# Decimal-safe JSON — Numeric(18,6) columns return Decimal objects
# which the default JSON encoder can't handle. This converts them to float.
import decimal
import json as _json
class DecimalEncoder(_json.JSONEncoder):
    def default(self, o):
        if isinstance(o, decimal.Decimal):
            return float(o)
        return super().default(o)

# Monkey-patch JSONResponse to use Decimal-safe encoder
from starlette.responses import JSONResponse as _OrigJSONResponse
_orig_render = _OrigJSONResponse.render
def _decimal_safe_render(self, content):
    return _json.dumps(
        content, ensure_ascii=False, allow_nan=False,
        indent=None, separators=(",", ":"), cls=DecimalEncoder
    ).encode("utf-8")
JSONResponse.render = _decimal_safe_render

@app.on_event("startup")
async def startup_event():
    import time
    # Re-install secret redaction now that uvicorn's loggers/handlers exist
    # (uvicorn.access is the one that logs request URLs incl. ?secret=...).
    _install_secret_redaction()
    from .database import engine, run_migrations
    from sqlalchemy import text
    for attempt in range(1, 6):
        try:
            with engine.connect() as conn:
                conn.execute(text("SELECT 1"))
            print(f"✅ DB connected on attempt {attempt}")
            break
        except Exception as e:
            print(f"⚠️ DB attempt {attempt} failed: {e}")
            if attempt < 5:
                time.sleep(3)

    # ── Connection pool warmup ─────────────────────────────────────
    # Diagnostic on 5 May 2026 showed the first query on a fresh
    # replica takes ~75ms while subsequent ones take ~5-10ms — that's
    # SQLAlchemy lazily acquiring Postgres connections. The first few
    # user requests to land on a cold replica pay this cost, which
    # adds visible latency on tab transitions.
    #
    # Pre-acquire connections matching pool_size (10) so the pool is warm
    # before the first user request arrives. Costs ~100-300ms of startup
    # time (replica isn't serving traffic yet anyway), saves ~50-200ms
    # off every cold-replica user request for the rest of the replica's
    # lifetime. Matches pool_size in app/database.py.
    try:
        warmup_conns = []
        for _ in range(10):
            c = engine.connect()
            c.execute(text("SELECT 1"))
            warmup_conns.append(c)
        for c in warmup_conns:
            c.close()
        print(f"✅ Connection pool warmed ({len(warmup_conns)} connections)")
    except Exception as e:
        print(f"⚠️ Pool warmup skipped: {e}")
    try:
        run_migrations()
        print("✅ Migrations complete")
    except Exception as e:
        print(f"⚠️ Migrations skipped: {e}")

    # ── One-time cleanup (Apr 2026): pause Tier-0 campaigns ──
    # Before today, the create-campaign endpoint had a `or 1` fallback that
    # let users with no Campaign Tier purchase silently create campaigns
    # treated as Tier 1 - bypassing the entire monetization model. This
    # cleanup pauses any active campaigns whose owner has no active tier
    # so they stop appearing in the watch rotation. Members will see a
    # "Paused - no Campaign Tier" badge with a CTA to purchase. Admin-owned
    # seed campaigns are skipped (admins effectively have all tiers).
    # Idempotent - re-running does nothing because already-paused campaigns
    # don't match the WHERE clause.
    try:
        from .database import SessionLocal, VideoCampaign, User, Grid
        from sqlalchemy import and_, or_
        cleanup_db = SessionLocal()
        try:
            # Find user IDs with at least one active grid (= has paid tier)
            from sqlalchemy import distinct
            paid_ids = {r[0] for r in cleanup_db.query(distinct(Grid.owner_id)).filter(
                Grid.is_complete == False
            ).all()}
            # Plus admins always count as paid
            admin_ids = {u.id for u in cleanup_db.query(User).filter(User.is_admin == True).all()}
            qualified_owners = paid_ids | admin_ids

            # Find active campaigns whose owner is NOT in the qualified set.
            # If qualified_owners is empty (extreme edge case: no one on the
            # platform has a tier), we want to pause ALL active campaigns.
            stuck_query = cleanup_db.query(VideoCampaign).filter(
                VideoCampaign.status == "active",
            )
            if qualified_owners:
                stuck_query = stuck_query.filter(
                    ~VideoCampaign.user_id.in_(qualified_owners)
                )
            stuck = stuck_query.all()

            paused_count = 0
            notified_users = set()
            for c in stuck:
                c.status = "paused_no_tier"
                paused_count += 1
                # Notify owner once (not once per campaign)
                if c.user_id not in notified_users:
                    try:
                        send_notification(cleanup_db, c.user_id, "campaign_paused", "⏸️",
                            "Your campaign is paused",
                            "You need an active Campaign Tier to keep your campaigns running. "
                            "Visit Campaign Tiers to purchase a tier and reactivate your campaign.")
                        notified_users.add(c.user_id)
                    except Exception:
                        # Notification failure doesn't block the pause itself
                        pass
            cleanup_db.commit()
            if paused_count > 0:
                print(f"✅ Paused {paused_count} Tier-0 campaign(s); notified {len(notified_users)} owner(s)")
            else:
                print("✅ No Tier-0 campaigns to pause")
        finally:
            cleanup_db.close()
    except Exception as e:
        print(f"⚠️ Tier-0 cleanup skipped: {e}")

    # ── Daily backup scheduler ──
    import asyncio, threading
    def _daily_backup_loop():
        """Run a database backup every 24 hours to Cloudflare R2."""
        import time as _time
        _time.sleep(60)  # Wait 60s after startup before first backup
        while True:
            try:
                from .db_backup import run_backup
                result = run_backup(skip_if_recent_hours=20)
                if result.get("success"):
                    print(f"✅ Daily backup: {result['file']} ({result['size_mb']}MB)")
                else:
                    print(f"⚠️ Backup failed: {result.get('error', 'unknown')}")
            except Exception as e:
                print(f"⚠️ Backup error: {e}")
            _time.sleep(86400)  # 24 hours

    backup_thread = threading.Thread(target=_daily_backup_loop, daemon=True)
    backup_thread.start()
    print("✅ Daily backup scheduler started")

    # ── In-process BSC scanner (Layer 3, 17 May 2026) ─────────────────
    # Removes the external-trigger dependency that left ~2-hour scan gaps
    # on launch night and lost SAP-00205's $14.54. Runs a scan every
    # BSC_INPROC_SCHEDULER_INTERVAL_SECONDS (default 30s) in a daemon
    # thread inside this replica.
    #
    # Multi-replica safety: Postgres advisory lock pg_try_advisory_lock(
    # BSC_SCAN_LOCK_ID) is acquired NON-BLOCKING before each scan.
    # If another replica is currently scanning, this replica skips the
    # tick silently — no double-scan, no cursor races. Lock auto-releases
    # at end of session (or function exit if using xact-scoped helper).
    #
    # The /cron/scan-bsc-payments endpoint stays live as a manual-trigger
    # backup. Disable the in-process scheduler with
    # BSC_INPROC_SCHEDULER_ENABLED=false if you ever need to revert.
    inproc_enabled = os.environ.get("BSC_INPROC_SCHEDULER_ENABLED", "true").lower() == "true"
    inproc_interval = int(os.environ.get("BSC_INPROC_SCHEDULER_INTERVAL_SECONDS", "30"))
    BSC_SCAN_LOCK_ID = 1885347291  # arbitrary 32-bit constant unique to this platform

    if not inproc_enabled:
        print("ℹ️ In-process BSC scanner DISABLED via BSC_INPROC_SCHEDULER_ENABLED")
    else:
        def _bsc_scanner_loop():
            import time as _time
            from .database import SessionLocal
            from sqlalchemy import text as _text
            # Wait 30s after boot before first tick — gives the rest of
            # startup (migrations, warmup, etc) time to settle so we don't
            # contend on the connection pool with cold-start traffic.
            _time.sleep(30)
            print(f"✅ In-process BSC scanner started (interval {inproc_interval}s)", flush=True)
            tick_count = 0
            # Log a quiet heartbeat every Nth tick even on idle scans, so
            # Railway logs always show the scanner is alive without spamming.
            # At 30s interval, every 60 ticks = every 30 minutes.
            HEARTBEAT_EVERY_N_TICKS = 60
            while True:
                tick_count += 1
                try:
                    result = _run_inproc_bsc_scan(SessionLocal, BSC_SCAN_LOCK_ID, _text)
                    # Logging policy:
                    #   - Always log exceptions / errors / unexpected result types
                    #   - Always log non-trivial activity (transfers, matches, orphans)
                    #   - Always log when a chunk fails (Layer-1 cursor-hold-back)
                    #   - Every Nth tick: short heartbeat so logs prove liveness
                    #   - Otherwise: silent
                    if not isinstance(result, dict):
                        print(f"[bsc-scan tick {tick_count}] unexpected result type: {type(result).__name__}", flush=True)
                    elif "error" in result:
                        print(f"[bsc-scan tick {tick_count}] ERROR: {result.get('error')}", flush=True)
                    elif "skipped" in result:
                        # lock_busy = another replica is scanning. Log only
                        # every Nth so we don't spam — it's the expected state.
                        if tick_count % HEARTBEAT_EVERY_N_TICKS == 0:
                            print(f"[bsc-scan tick {tick_count}] skipped: {result.get('skipped')} (heartbeat)", flush=True)
                    else:
                        interesting = (
                            result.get("transfers_seen", 0) > 0
                            or result.get("matched", 0) > 0
                            or result.get("orphans_added", 0) > 0
                            or len(result.get("failed_chunks", [])) > 0
                            or result.get("errors")
                        )
                        if interesting or tick_count % HEARTBEAT_EVERY_N_TICKS == 0:
                            tag = "" if interesting else " (heartbeat)"
                            print(
                                f"[bsc-scan tick {tick_count}] floor={result.get('scan_floor')} "
                                f"latest={result.get('latest_block')} "
                                f"transfers={result.get('transfers_seen', 0)} "
                                f"matched={result.get('matched', 0)} "
                                f"orphans={result.get('orphans_added', 0)} "
                                f"safe_cursor={result.get('safe_cursor', 0)} "
                                f"failed_chunks={len(result.get('failed_chunks', []))}{tag}",
                                flush=True,
                            )
                except Exception as e:
                    # NEVER let the loop die — log and continue. A killed
                    # loop would silently reintroduce the gap problem
                    # we're trying to fix.
                    import traceback
                    tb = traceback.format_exc()
                    try:
                        logger.error(f"[bsc-scan tick {tick_count}] iteration failed: {e}\n{tb}")
                    except Exception:
                        pass
                    print(f"[bsc-scan tick {tick_count}] EXCEPTION: {e}\n{tb}", flush=True)
                _time.sleep(inproc_interval)

        scanner_thread = threading.Thread(target=_bsc_scanner_loop, daemon=True, name="bsc-scanner")
        scanner_thread.start()
        print(f"✅ In-process BSC scanner scheduled (interval {inproc_interval}s, lock_id {BSC_SCAN_LOCK_ID})")

    # ── In-process security watchdog ──────────────────────────────────
    # Runs run_security_watch every 60s inside the always-on web process,
    # mirroring the BSC scanner (daemon thread + Postgres advisory lock for
    # multi-replica safety). THIS is what arms the synthetic-balance /
    # treasury-drain / admin-event alarms continuously — without it they
    # only fire on a manual /cron/security-watch hit. The /cron endpoint
    # stays as a manual backup. Kill switch: SECWATCH_INPROC_ENABLED=false.
    # The loop is wrapped so a single bad tick can never kill the watchdog.
    if os.environ.get("SECWATCH_INPROC_ENABLED", "true").lower() == "true":
        def _security_watch_loop():
            import time as _time
            from .database import SessionLocal
            from sqlalchemy import text as _text
            _time.sleep(45)  # let startup settle; stagger vs the BSC loop
            print("✅ In-process security watchdog started (interval 60s)", flush=True)
            SECWATCH_LOCK_ID = 1885347292  # unique 32-bit constant for this loop
            wtick = 0
            self_heal = False  # latched when a dead lock-holder is detected
            while True:
                wtick += 1
                try:
                    db = SessionLocal()
                    try:
                        got = db.execute(
                            _text("SELECT pg_try_advisory_lock(:k)"),
                            {"k": SECWATCH_LOCK_ID}).scalar()
                        # Stale-lock self-heal. The advisory lock is Postgres
                        # SESSION-scoped; behind a connection pooler it can be
                        # left held on a pooled server session if a process is
                        # killed mid-tick, so a restarted process gets `false`
                        # forever and never ticks. Guard: if we can't get the
                        # lock but NO worker has ticked in 150s, the holder is
                        # dead — latch self_heal and tick anyway. A live holder
                        # refreshes the heartbeat every ~60s, so a healthy peer
                        # never trips this; takeover only happens when the
                        # holder truly stopped. Cleared as soon as we reacquire.
                        if got:
                            self_heal = False
                        elif not self_heal:
                            try:
                                _lt = float(_secwatch_get(db, "secwatch_last_tick_ts", "0") or "0")
                            except (ValueError, TypeError):
                                _lt = 0.0
                            if (_time.time() - _lt) > 150:
                                self_heal = True
                                print("[secwatch] stale lock detected — self-heal takeover", flush=True)
                        if got or self_heal:
                            try:
                                res = run_security_watch(db)
                                # Heartbeat: stamp every live tick so
                                # /admin/secwatch-status can prove the daemon is
                                # actually ticking, not just alive on paper.
                                try:
                                    _secwatch_set(db, "secwatch_last_tick_ts", str(_time.time()))
                                except Exception:
                                    pass
                                if isinstance(res, dict) and res.get("events"):
                                    print(f"[secwatch tick {wtick}] {res.get('events')} "
                                          f"event(s) alerted={res.get('alerted')}", flush=True)
                                elif wtick % 30 == 0:
                                    print(f"[secwatch tick {wtick}] ok (heartbeat)", flush=True)
                            finally:
                                if got:
                                    db.execute(_text("SELECT pg_advisory_unlock(:k)"),
                                               {"k": SECWATCH_LOCK_ID})
                                db.commit()
                    finally:
                        db.close()
                except Exception as e:
                    import traceback as _tb
                    print(f"[secwatch tick {wtick}] EXCEPTION: {e}\n{_tb.format_exc()}", flush=True)
                _time.sleep(60)

        secwatch_thread = threading.Thread(target=_security_watch_loop, daemon=True, name="security-watch")
        secwatch_thread.start()
        print("✅ In-process security watchdog scheduled (interval 60s, lock_id 1885347292)")

templates = Jinja2Templates(directory="templates")
# Make Decimal values render cleanly in templates
templates.env.filters["money"] = lambda v: f"{float(v or 0):.2f}"
templates.env.finalize = lambda x: float(x) if isinstance(x, decimal.Decimal) else x
import json as _json
templates.env.filters["from_json"] = lambda s: _json.loads(s) if s else []

def _client_ip(request) -> str:
    """Real client IP behind Cloudflare. get_remote_address sees the
    Cloudflare edge IP — which would lump all users under one key and miss
    the real attacker. Prefer CF-Connecting-IP, then first X-Forwarded-For hop."""
    cf = request.headers.get("cf-connecting-ip")
    if cf:
        return cf.strip()
    xff = request.headers.get("x-forwarded-for")
    if xff:
        return xff.split(",")[0].strip()
    return get_remote_address(request)

limiter = Limiter(key_func=_client_ip)
app.state.limiter = limiter
app.add_exception_handler(RateLimitExceeded, _rate_limit_exceeded_handler)

@app.exception_handler(Exception)
async def global_exception_handler(request: Request, exc: Exception):
    """Catch unhandled exceptions and return JSON instead of HTML error pages."""
    import traceback
    logger.error(f"Unhandled error: {exc}\n{traceback.format_exc()}")
    # Do NOT return exc details to the client — error strings leak DB errors,
    # file paths, and SQL fragments that automated recon harvests. Full
    # detail is logged server-side above.
    return JSONResponse({"error": "Internal server error"}, status_code=500)

