@app.get("/api/account/purchases")
def api_account_purchases(user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """Member-facing 'Your Purchases & Holdings' data.

    Reads the SOURCE-OF-TRUTH tables directly (same tables the
    /admin/api/user-fulfillment diagnostic uses) so what a member sees is
    exactly what's real — no denormalised counters that can drift. Returns
    two things:

      holdings: what the member has active RIGHT NOW (membership, Profit Grid
                position, Creative Studio credit balance)
      history:  every purchase as a row (date, product, what it delivered,
                amount, status), merged across the scattered purchase tables
                (Payment for membership, GridPosition for campaign tiers,
                CreditPackPurchase for Nexus packs) and sorted newest-first.

    Built 28 May 2026 after the Daniela/cashflow case: a member couldn't tell
    what her three charges were because nothing in the member UI showed her
    purchases or holdings. This closes that gap. v1 covers membership +
    Campaign Tier + Nexus packs; courses/digital products can be added later.
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    from .database import (
        GridPosition, CreditPackPurchase, SuperSceneCredit, Payment,
        GRID_PACKAGES, GRID_TIER_NAMES,
    )

    # ── HOLDINGS: what's active right now ──
    # Membership
    is_founder = bool(getattr(user, "is_founding_member", False))
    locked = getattr(user, "membership_price_locked", None)
    membership_price = float(locked) if locked else (15.0 if is_founder else 20.0)
    membership = {
        "label": "Founder" if is_founder else ("Partner" if user.is_active else "Free"),
        "price": membership_price,
        "active": bool(user.is_active),
        "renews_at": user.membership_expires_at.isoformat() if getattr(user, "membership_expires_at", None) else None,
    }

    # Profit Grid — highest tier position they hold (Campaign Tier purchases)
    gpos = db.query(GridPosition).filter(GridPosition.member_id == user.id).all()
    grid_levels = sorted({g.grid_level for g in gpos if g.grid_level is not None})
    grid = {
        "has_position": len(gpos) > 0,
        "tier": (max(grid_levels) if grid_levels else None),
        "position_count": len(gpos),
    }

    # Creative Studio credits
    ssc = db.query(SuperSceneCredit).filter(SuperSceneCredit.user_id == user.id).first()
    credit_balance = int(ssc.balance) if ssc else 0

    holdings = {"membership": membership, "grid": grid, "credit_balance": credit_balance}

    # ── HISTORY: every purchase, merged + sorted newest-first ──
    history = []

    # Membership + balance payments (Payment rows where this user is the payer)
    for p in db.query(Payment).filter(Payment.from_user_id == user.id).all():
        ptype = (getattr(p, "payment_type", "") or "")
        if ptype.startswith("membership"):
            history.append({
                "date": p.created_at.isoformat() if p.created_at else None,
                "product": "Founder Membership" if is_founder else "Membership",
                "delivered": "Activated your membership account",
                "amount": float(getattr(p, "amount_usdt", 0) or 0),
                "status": "Delivered" if p.status in ("confirmed", "paid", "completed") else (p.status or "—"),
                "kind": "membership",
            })

    # Campaign Tier purchases — one row per distinct grid placement event.
    # GridPosition rows don't carry price; a Tier-N purchase is N*$... but the
    # ground-truth price for the buyer is the tier purchase amount. We surface
    # the placement as the deliverable; amount is the tier purchase price.
    # Group placements created in the same second = one purchase event.
    seen_grid_events = set()
    for g in sorted(gpos, key=lambda x: (x.created_at or datetime.min)):
        # bucket by created_at to the second to collapse the multi-row placement
        bucket = g.created_at.replace(microsecond=0).isoformat() if g.created_at else str(g.id)
        if bucket in seen_grid_events:
            continue
        seen_grid_events.add(bucket)
        tier = g.grid_level or 1
        tier_price = float(GRID_PACKAGES.get(tier, 0))
        tier_name = GRID_TIER_NAMES.get(tier, f"Tier {tier}")
        history.append({
            "date": g.created_at.isoformat() if g.created_at else None,
            "product": f"Campaign Tier {tier} — {tier_name} (Profit Grid)",
            "delivered": f"Placed you in the Profit Grid — Tier {tier} ({tier_name}) position active",
            "amount": tier_price,  # authoritative price from GRID_PACKAGES (NOT tier*20)
            "status": "Delivered",
            "kind": "campaign_tier",
        })

    # Nexus credit pack purchases
    for cp in db.query(CreditPackPurchase).filter(CreditPackPurchase.user_id == user.id).all():
        history.append({
            "date": cp.created_at.isoformat() if cp.created_at else None,
            "product": f"Credit Nexus — {(cp.pack_key or '').title()} Pack",
            "delivered": f"Added {cp.credits_awarded} Creative Studio credits to your account",
            "amount": float(cp.pack_price or 0),
            "status": "Delivered" if cp.status == "completed" else (cp.status or "—"),
            "kind": "nexus_pack",
        })

    # newest first
    history.sort(key=lambda r: (r["date"] or ""), reverse=True)

    return JSONResponse({"holdings": holdings, "history": history})


@app.get("/api/dashboard/goals")
def api_dashboard_goals(user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """Return personalised goal cards based on member's current situation."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    goals = []
    opportunities = []

    refs = db.query(User).filter(User.sponsor_id == user.id).count()
    balance = float(user.balance or 0)
    campaign_balance = float(user.campaign_balance or 0)

    # Self-funding is always measured against Basic membership ($20)
    # because that's the entry point we promote to new members
    membership_cost = 20
    base_commission = 10
    refs_needed = 2  # $20 / $10 = 2 referrals to break even
    if refs < refs_needed:
        remaining = refs_needed - refs
        pct = min(100, int(refs / refs_needed * 100)) if refs_needed > 0 else 0
        if refs == 0:
            goal_key = "shareLink"
            title = "Share your referral link to earn your first commission"
            desc = f"Every Basic referral earns you ${base_commission}/month. Just {refs_needed} referrals and your ${membership_cost} membership pays for itself."
        elif remaining == 1:
            goal_key = "1more"
            title = "1 more referral and your membership pays for itself"
            desc = f"You have {refs} referral{'s' if refs > 1 else ''} earning you ${refs * base_commission}/month. One more and your ${membership_cost} membership is fully covered."
        else:
            goal_key = "nmore"
            title = f"{remaining} more referrals until your membership is free"
            desc = f"You have {refs} referral{'s' if refs > 1 else ''} earning you ${refs * base_commission}/month. {remaining} more and your membership costs you nothing."
        goals.append({
            "type": "referral", "color": "#0ea5e9", "bg": "#ecfeff",
            "icon": "users", "title": title, "desc": desc,
            "goal_key": goal_key, "params": {"refs": refs, "needed": refs_needed, "remaining": remaining, "commission": base_commission, "cost": membership_cost, "earning": refs * base_commission},
            "progress": pct, "progress_label": f"{refs} of {refs_needed} referrals",
            "cta": "Share your link", "cta_link": "/affiliate",
        })
    elif refs >= refs_needed and refs < 10:
        # Already self-funding — push toward next milestone
        next_target = 10
        pct = min(100, int(refs / next_target * 100))
        monthly = refs * base_commission
        goals.append({
            "type": "referral", "color": "#0ea5e9", "bg": "#ecfeff",
            "icon": "users", "title": f"You're earning ${monthly}/month — next goal: 10 referrals",
            "desc": f"Your membership pays for itself and you're profiting ${monthly - membership_cost}/month. Hit 10 referrals for ${next_target * base_commission}/month.",
            "goal_key": "earning", "params": {"refs": refs, "needed": next_target, "monthly": monthly, "profit": monthly - membership_cost, "target": next_target * base_commission},
            "progress": pct, "progress_label": f"{refs} of {next_target} referrals",
            "cta": "Keep growing", "cta_link": "/affiliate",
        })

    # ── Goal: Grid completion ──
    active_grid = db.query(Grid).filter(
        Grid.owner_id == user.id, Grid.is_complete == False
    ).order_by(Grid.package_tier.desc()).first()
    if active_grid:
        filled = active_grid.positions_filled or 0
        from .database import GRID_COMPLETION_BONUS, GRID_TIER_NAMES, GRID_TOTAL
        total = active_grid.total_seats
        remaining = total - filled
        pct = min(100, int(filled / total * 100))
        bonus = completion_bonus_for(active_grid.total_seats, active_grid.package_price)
        tier_name = GRID_TIER_NAMES.get(active_grid.package_tier, f"Tier {active_grid.package_tier}")
        goals.append({
            "type": "grid", "color": "#8b5cf6", "bg": "#f5f3ff",
            "icon": "grid", "title": f"Grid {pct}% complete — ${bonus} bonus waiting",
            "desc": f"Your {tier_name} grid has {filled} of {total} positions filled. {remaining} more and you unlock the completion bonus.",
            "goal_key": "grid", "params": {"pct": pct, "bonus": bonus, "tierName": tier_name, "filled": filled, "total": total, "remaining": remaining},
            "progress": pct, "progress_label": f"{filled} of {total} positions",
            "ring": True,
            "cta": "View grid", "cta_link": "/income-grid",
        })

    # ── Goal: Withdrawal threshold ──
    if balance > 0 and balance < 10:
        remaining = 10 - balance
        pct = min(100, int(balance / 10 * 100))
        goals.append({
            "type": "withdrawal", "color": "#22c55e", "bg": "#f0fdf4",
            "icon": "wallet", "title": f"${remaining:.2f} more until you can withdraw",
            "goal_key": "withdraw", "params": {"remaining": f"{remaining:.2f}", "balance": f"{balance:.2f}"},
            "desc": f"Your affiliate wallet has ${balance:.2f}. The minimum withdrawal is $10. {'One more referral commission and you\'re there.' if remaining <= base_commission else 'Keep building your referrals to reach the threshold.'}",
            "progress": pct, "progress_label": f"${balance:.2f} of $10.00",
            "cta": "View wallet", "cta_link": "/wallet",
        })

    # ── Goal: Daily watch quota (always shown — changes state when complete) ──
    from datetime import date
    quota = db.query(WatchQuota).filter(WatchQuota.user_id == user.id).first()
    if quota:
        today_str = str(date.today())
        watched = quota.today_watched if quota.today_date == today_str else 0
        # daily_required can legitimately be 0 (admin/owner exemption) — use
        # an explicit None-check rather than `or 1` which would coerce 0 to 1.
        required = quota.daily_required if quota.daily_required is not None else 1
    else:
        required = 1
        watched  = 0

    if quota and required == 0:
        # Admin / owner exemption — no daily nag, no goal card at all
        pass
    elif quota:
        if watched >= required:
            goals.append({
                "type": "watch", "color": "#22c55e", "bg": "#f0fdf4",
                "icon": "check", "title": "Today's watch completed!",
                "goal_key": "watchDone", "params": {"required": required, "watched": watched},
                "desc": f"You've watched all {required} video{'s' if required > 1 else ''} today. You're qualified for campaign wallet withdrawals. Resets at midnight.",
                "progress": 100, "progress_label": f"{watched} of {required} watched today",
                "completed": True,
                "cta": "Watch more", "cta_link": "/watch",
            })
        else:
            pct = min(100, int(watched / required * 100)) if required > 0 else 0
            goals.append({
                "type": "watch", "color": "#f59e0b", "bg": "#fefce8",
                "icon": "zap", "title": "You haven't watched today's videos yet" if watched == 0 else f"{required - watched} more video{'s' if required - watched > 1 else ''} to complete today's watch",
                "goal_key": "watchStart" if watched == 0 else "watchNeed", "params": {"required": required, "watched": watched, "remaining": required - watched},
                "desc": f"Complete your daily watch to stay qualified for campaign wallet withdrawals. You need {required} video{'s' if required > 1 else ''} today.",
                "progress": pct, "progress_label": f"{watched} of {required} watched today",
                "cta": "Watch now", "cta_link": "/watch",
            })
    else:
        # No quota record yet — prompt them to start
        goals.append({
            "type": "watch", "color": "#f59e0b", "bg": "#fefce8",
            "icon": "zap", "title": "Start your daily watch",
            "goal_key": "watchStart", "params": {"required": 1, "watched": 0},
            "desc": "Watch a short video each day to stay qualified for campaign wallet withdrawals.",
            "progress": 0, "progress_label": "0 of 1 watched today",
            "cta": "Watch now", "cta_link": "/watch",
        })

    # ── Opportunities (features not yet used) ──

    # Creative Studio usage check
    from .database import SuperSceneVideo
    studio_count = db.query(SuperSceneVideo).filter(SuperSceneVideo.user_id == user.id).count()
    if studio_count == 0:
        opportunities.append({
            "type": "creative_studio", "color": "#ec4899", "bg": "#fdf2f8",
            "icon": "video", "title": "Try the Creative Studio",
            "desc": "You haven't created any AI content yet. Generate a video, image, or music track — it's included with your membership.",
            "cta": "Open Creative Studio", "cta_link": "/creative-studio",
        })

    # LinkHub check
    has_linkhub = db.query(db.query(LinkHubProfile).filter(LinkHubProfile.user_id == user.id).exists()).scalar()
    if not has_linkhub:
        opportunities.append({
            "type": "linkhub", "color": "#6366f1", "bg": "#eef2ff",
            "icon": "link", "title": "Build your LinkHub page",
            "desc": "Your LinkHub is empty. Set up your personal page with your links, offers, and referral — takes 2 minutes.",
            "cta": "Set up LinkHub", "cta_link": "/linkhub",
        })

    # Campaign tier check — if no active campaign tiers
    has_campaign = db.query(VideoCampaign).filter(
        VideoCampaign.user_id == user.id, VideoCampaign.status == "active"
    ).first()
    if not has_campaign and user.is_active:
        opportunities.append({
            "type": "campaign", "color": "#0d9488", "bg": "#f0fdfa",
            "icon": "target", "title": "Activate a campaign tier",
            "desc": "You don't have an active campaign tier yet. Campaign tiers unlock the full grid earning engine and get your video in front of members.",
            "cta": "View campaign tiers", "cta_link": "/campaign-tiers",
        })

    return {"goals": goals, "opportunities": opportunities}
