@app.get("/apple-touch-icon.png")
@app.get("/apple-touch-icon-precomposed.png")
def apple_touch_icon():
    """iOS looks for touch icon at root level."""
    from fastapi.responses import FileResponse
    from pathlib import Path
    icon_path = Path("static/icons/apple-touch-icon.png")
    if icon_path.exists():
        return FileResponse(str(icon_path), media_type="image/png")
    return FileResponse(str(Path("static/icons/icon-192.png")), media_type="image/png")


@app.get("/media/welcome-video")
def serve_welcome_video(request: Request):
    """Stream the explore-page welcome video with proper HTTP Range support.

    Background — bug found 10 May 2026 launch day:
        The 90-second tour video on /explore was a black screen on iOS Safari
        even after tapping play. Investigation found Cloudflare was caching
        the file at /static/images/explore-welcome.mp4 as immutable (1-year
        cache header from StaticFiles) and serving cached responses with
        '200 OK' instead of '206 Partial Content' for Range requests. iOS
        Safari sends Range:bytes=0-1 as a streaming probe and refuses to
        play any video where the server can't return 206. Black screen.

    The fix:
        - Re-encode the video to mobile-friendly 720p H.264 baseline (8MB
          vs the original 21MB, plays on every iOS made in the last 8 years).
        - Serve via this endpoint instead of /static/images/. FastAPI's
          FileResponse auto-handles Range correctly (returns 206 with
          Content-Range when requested).
        - Short Cache-Control (5 min) so Cloudflare doesn't latch onto a
          full-file response and serve it as 200 to subsequent Range probes.
        - Explicit Accept-Ranges header to advertise capability.

    Frontend uses /media/welcome-video instead of /static/images/explore-welcome.mp4
    so we don't disrupt anything else served from the static mount. The
    original .mp4 stays where it is for backwards compat.
    """
    from fastapi.responses import FileResponse
    from fastapi import HTTPException
    from pathlib import Path

    # Prefer the mobile-optimised re-encode if present, fall back to the
    # full-quality original. Both are committed in static/images/.
    mobile_path = Path("static/images/explore-welcome-mobile.mp4")
    full_path = Path("static/images/explore-welcome.mp4")
    video_path = mobile_path if mobile_path.exists() else full_path

    if not video_path.exists():
        raise HTTPException(status_code=404, detail="Welcome video not found")

    response = FileResponse(
        str(video_path),
        media_type="video/mp4",
        # FileResponse auto-handles Range. We just add the headers Cloudflare
        # needs to behave correctly on subsequent requests.
        headers={
            # 5-minute cache — long enough to absorb traffic spikes but short
            # enough that Cloudflare won't pin a non-Range response. Combined
            # with the Range-aware FileResponse, this gives Safari what it
            # expects on every fetch.
            "Cache-Control": "public, max-age=300, no-transform",
            # Explicitly advertise byte-range capability so clients don't
            # have to probe with a HEAD first.
            "Accept-Ranges": "bytes",
        },
    )
    return response


# Whitelist of tour video slugs. Anything not in this map returns 404 so
# the endpoint can't be abused to serve arbitrary files from static/.
_TOUR_VIDEO_SLUGS = {
    "dashboard":   "dashboard-tour.mp4",
    "how-you-earn": "how-you-earn-tour-v2.mp4",
    "watch-to-earn": "watch-to-earn-tour.mp4",
    "basic-tools": "basic-tools-tour.mp4",
    "pro-tools":   "pro-tools-tour.mp4",
    "wallet":      "wallet-tour.mp4",
}


@app.get("/media/tour-video/{slug}")
def serve_tour_video(slug: str, request: Request):
    """Stream a Platform Tour video with proper HTTP Range support.

    Same bug, same fix as serve_welcome_video above — applied to all 6
    tour videos this time. Reported 10 May 2026 launch day: all 6 tour
    videos black-screened on iOS Safari mobile even though the poster
    and play button rendered correctly. Root cause is Cloudflare
    caching the /static/downloads/tour-videos/*.mp4 files as immutable
    (StaticFiles sends Cache-Control: public, max-age=31536000) and
    serving the cached 200 OK response to iOS Safari's Range:bytes=0-1
    streaming probe instead of a 206 Partial Content. Safari refuses
    to play any video where the server can't honour Range. Black
    screen, no error, no console message.

    Routing the videos through this endpoint:
      - FastAPI FileResponse auto-handles Range -> 206 Partial Content
      - Short Cache-Control (5 min) so Cloudflare won't pin the
        non-Range full-file response
      - Explicit Accept-Ranges: bytes header advertises capability

    Frontend uses /media/tour-video/{slug} instead of
    /static/downloads/tour-videos/{slug}-tour.mp4. The original .mp4s
    stay where they are; the static path still works for downloads or
    any code that hasn't been migrated.
    """
    from fastapi.responses import FileResponse
    from fastapi import HTTPException
    from pathlib import Path

    filename = _TOUR_VIDEO_SLUGS.get(slug)
    if not filename:
        raise HTTPException(status_code=404, detail="Unknown tour video")

    video_path = Path("static/downloads/tour-videos") / filename
    if not video_path.exists():
        raise HTTPException(status_code=404, detail="Tour video not found")

    return FileResponse(
        str(video_path),
        media_type="video/mp4",
        headers={
            # 5-minute cache: long enough to absorb traffic spikes,
            # short enough that Cloudflare won't pin a non-Range
            # response. Combined with the Range-aware FileResponse
            # this gives iOS Safari what it expects on every fetch.
            "Cache-Control": "public, max-age=300, no-transform",
            "Accept-Ranges": "bytes",
        },
    )


