@app.get("/network")
@app.get("/api/dashboard")
def api_dashboard(request: Request, user: User = Depends(get_current_user),
                  db: Session = Depends(get_db)):
    """JSON dashboard data for React frontend. Cached for 60s per user."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    try:
        import time as _t
        t0 = _t.time()

        # Check cache first
        cache_key = f"dash:{user.id}:main"
        cached = cache_get(cache_key)
        if cached:
            logger.info(f"Dashboard API: cache HIT for user {user.id} ({_t.time()-t0:.3f}s)")
            return cached

        check_achievements(db, user)
        t1 = _t.time()
        ctx = get_dashboard_context(request, user, db)
        t2 = _t.time()
        # Strip non-serialisable items
        safe = {}
        for k, v in ctx.items():
            if k in ('request', 'user'):
                continue
            try:
                json.dumps(v)
                safe[k] = v
            except (TypeError, ValueError):
                safe[k] = str(v)
        t3 = _t.time()

        # Cache TTL: 30s. Originally 60s, dropped to 5s on 9 May 2026
        # because balance felt stale after payments/commissions when
        # cache_invalidate_user() was only wired up to notification
        # creation. As of 10 May the invalidator covers 26 commission/
        # balance write sites; raising to 30s is safe and dramatically
        # cuts DB load during the 12 May signup surge that was causing
        # 10-second timeouts on the React Dashboard. Kept slightly under
        # the per-helper TTL (60s) so a manually-triggered Dashboard
        # refresh after a commission has a real chance of pulling
        # post-invalidation data on its first hit.
        cache_set(cache_key, safe, ttl=30)

        logger.info(f"Dashboard API timing: achievements={t1-t0:.3f}s context={t2-t1:.3f}s serialize={t3-t2:.3f}s total={t3-t0:.3f}s")
        return safe
    except Exception as exc:
        import traceback
        logger.error(f"Dashboard API error for user {user.id}: {traceback.format_exc()}")
        return JSONResponse({"error": str(exc), "trace": traceback.format_exc()[-500:]}, status_code=500)


# ── Command Centre Layer 2: drill-down endpoints ─────────────────
# Returns lists of members in a given bucket, privacy-conscious by
# design — never exposes other members' earnings or financial data.
# Public profile fields only: username, display name, avatar, country,
# membership tier, signup date, last membership-payment date.
#
# Layer 1 returns counts via /api/dashboard. Layer 2 returns the actual
# members behind those counts so members can see who to follow up with.
# Layer 3 will add per-member actions (message, re-activate email).

def _direct_member_payload(u, last_paid_at):
    """Build a member row dict — privacy-conscious. No earnings, no email,
    no balance. Used by /api/command-centre/directs and grid/nexus too."""
    return {
        "id": u.id,
        "username": u.username,
        "display_name": u.first_name or u.username,
        "avatar_url": u.avatar_url or None,
        "country": u.country or None,
        "membership_tier": u.membership_tier or "free",
        "is_founding_member": bool(getattr(u, "is_founding_member", False)),
        "founding_spot_number": getattr(u, "founding_spot_number", None),
        "is_active": bool(u.is_active),
        "signed_up_at": u.created_at.isoformat() if u.created_at else None,
        "last_paid_at": last_paid_at.isoformat() if last_paid_at else None,
    }


@app.get("/api/command-centre/directs")
def api_command_centre_directs(
    request: Request,
    bucket: str = "active",
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """List of direct referrals filtered by bucket (active/lapsed/never_paid).

    Returns ONLY public profile fields + signup/last-paid dates.
    Never exposes earnings, balances, email addresses, or anything else
    that would let a sponsor see another member's financial activity.
    """
    from sqlalchemy import func
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    if bucket not in ("active", "lapsed", "never_paid"):
        return JSONResponse({"error": "Invalid bucket"}, status_code=400)

    # Base query: all direct referrals
    base = db.query(User).filter(User.sponsor_id == user.id)

    if bucket == "active":
        members = base.filter(User.is_active == True).order_by(User.created_at.desc()).all()
    else:
        # Both lapsed and never_paid are is_active=False; difference is
        # whether they have a confirmed membership Payment row.
        ever_paid_subq = db.query(Payment.from_user_id).filter(
            Payment.payment_type.like("membership%"),
            Payment.status.in_(["confirmed", "paid"]),
        )
        if bucket == "lapsed":
            members = base.filter(
                User.is_active == False,
                User.id.in_(ever_paid_subq),
            ).order_by(User.created_at.desc()).all()
        else:  # never_paid
            members = base.filter(
                User.is_active == False,
                ~User.id.in_(ever_paid_subq),
            ).order_by(User.created_at.desc()).all()

    # Look up last membership payment date per member (single query, then map)
    member_ids = [m.id for m in members]
    last_paid_map = {}
    if member_ids:
        rows = db.query(
            Payment.from_user_id,
            func.max(Payment.created_at),
        ).filter(
            Payment.from_user_id.in_(member_ids),
            Payment.payment_type.like("membership%"),
            Payment.status.in_(["confirmed", "paid"]),
        ).group_by(Payment.from_user_id).all()
        last_paid_map = {row[0]: row[1] for row in rows}

    return {
        "bucket": bucket,
        "count": len(members),
        "members": [_direct_member_payload(m, last_paid_map.get(m.id)) for m in members],
    }


@app.get("/admin/api/user-downline")
def admin_api_user_downline(
    user_id: int,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Diagnose a 'my team is missing' report. Shows the DB truth for a user's
    downline so we can tell a data problem (links/rows gone) from a display
    problem (Payment-table loss misbucketing, etc.).

    Returns the direct referrals (sponsor_id == user_id) with their active
    state and whether a confirmed membership Payment row exists for them
    (which is what the team page's lapsed/never_paid split relies on — and
    that table was hollowed in the restore), plus the full descendant counts.
    """
    _require_admin(user)
    from sqlalchemy import func as _func
    target = db.query(User).filter(User.id == user_id).first()
    if not target:
        return JSONResponse({"error": f"user {user_id} not found"}, status_code=404)

    directs = db.query(User).filter(User.sponsor_id == user_id).order_by(User.created_at.asc()).all()
    direct_ids = [d.id for d in directs]
    paid_ids = set()
    if direct_ids:
        for (uid,) in db.query(Payment.from_user_id).filter(
            Payment.from_user_id.in_(direct_ids),
            Payment.payment_type.like("membership%"),
            Payment.status.in_(["confirmed", "paid"]),
        ).distinct().all():
            paid_ids.add(uid)

    rows = [{
        "id": d.id,
        "username": d.username,
        "is_active": bool(d.is_active),
        "created_at": d.created_at.isoformat() if d.created_at else None,
        "has_membership_payment_row": d.id in paid_ids,
    } for d in directs]

    active_n = sum(1 for d in directs if d.is_active)
    try:
        desc = compute_descendant_counts(db, user_id)
    except Exception as e:
        desc = {"error": str(e)[:120]}

    return JSONResponse({
        "user": {"id": target.id, "username": target.username, "is_active": bool(target.is_active)},
        "direct_count_total": len(directs),
        "direct_active": active_n,
        "direct_inactive": len(directs) - active_n,
        "directs_with_membership_payment_row": len(paid_ids),
        "directs_missing_payment_row_but_inactive": sum(
            1 for d in directs if (not d.is_active) and d.id not in paid_ids),
        "descendant_counts": desc,
        "directs": rows,
    })


@app.get("/admin/api/sponsor-audit")
def admin_api_sponsor_audit(
    user_id: int,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Sponsor-link integrity audit. The signup path ALWAYS sets sponsor_id
    (referrer, else company fallback to SuperAdPro), so sponsor_id IS NULL is
    abnormal — a corruption signature. This reports:
      - the target user's sponsor fields + team counters vs actual direct count
        (counter >> actual = his downline links were lost), and
      - platform-wide scope: how many users have null sponsor_id, and of those
        how many still carry pass_up_sponsor_id (the recoverable source).
    """
    _require_admin(user)
    from sqlalchemy import func as _func
    t = db.query(User).filter(User.id == user_id).first()
    if not t:
        return JSONResponse({"error": f"user {user_id} not found"}, status_code=404)

    actual_directs = db.query(_func.count(User.id)).filter(User.sponsor_id == user_id).scalar() or 0
    target = {
        "id": t.id, "username": t.username, "is_active": bool(t.is_active),
        "sponsor_id": t.sponsor_id,
        "pass_up_sponsor_id": t.pass_up_sponsor_id,
        "personal_referrals_counter": t.personal_referrals,
        "total_team_counter": getattr(t, "total_team", None),
        "actual_direct_count_in_db": actual_directs,
        "team_links_lost": (getattr(t, "total_team", 0) or 0) > actual_directs,
    }

    total_users = db.query(_func.count(User.id)).scalar() or 0
    null_sponsor = db.query(_func.count(User.id)).filter(User.sponsor_id.is_(None)).scalar() or 0
    null_sponsor_recoverable = db.query(_func.count(User.id)).filter(
        User.sponsor_id.is_(None), User.pass_up_sponsor_id.isnot(None)).scalar() or 0
    null_both = db.query(_func.count(User.id)).filter(
        User.sponsor_id.is_(None), User.pass_up_sponsor_id.is_(None)).scalar() or 0

    sample = [{
        "id": u.id, "username": u.username, "is_active": bool(u.is_active),
        "pass_up_sponsor_id": u.pass_up_sponsor_id,
        "created_at": u.created_at.isoformat() if u.created_at else None,
    } for u in db.query(User).filter(User.sponsor_id.is_(None)).order_by(User.id.asc()).limit(20).all()]

    return JSONResponse({
        "target": target,
        "platform_scope": {
            "total_users": total_users,
            "null_sponsor_id": null_sponsor,
            "null_sponsor_but_has_passup_recoverable": null_sponsor_recoverable,
            "null_sponsor_and_null_passup_unrecoverable": null_both,
        },
        "null_sponsor_sample": sample,
        "note": ("sponsor_id should never be null (signup falls back to company). "
                 "null_sponsor_but_has_passup = rebuildable from pass_up_sponsor_id; "
                 "team_links_lost on target = his downline's sponsor_id was nulled."),
    })


@app.get("/admin/api/sponsor-recovery-scan")
def admin_api_sponsor_recovery_scan(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """How much of the wiped sponsor tree can be auto-recovered, and from where.
    Resolves each null-sponsor user (excluding the company root, id 1) against
    two surviving high-confidence sources, in priority order:
      1) pass_up_sponsor_id  (the permanent pass-up chain)
      2) surviving sponsor-commission rows: a row with from_user_id = the member
         and to_user_id = their sponsor (membership_sponsor / direct_sponsor).
         Rebuilt summary rows have from_user_id NULL so they can't pollute this.
    Read-only — reports coverage + a sample. No writes.
    """
    _require_admin(user)
    from sqlalchemy import func as _func
    null_users = db.query(User.id, User.username, User.pass_up_sponsor_id).filter(
        User.sponsor_id.is_(None), User.id != 1).all()
    null_ids = [u.id for u in null_users]
    passup = {u.id: u.pass_up_sponsor_id for u in null_users if u.pass_up_sponsor_id}

    comm_map = {}
    if null_ids:
        rows = db.query(Commission.from_user_id, Commission.to_user_id).filter(
            Commission.from_user_id.in_(null_ids),
            Commission.to_user_id.isnot(None),
            Commission.commission_type.in_(["membership_sponsor", "direct_sponsor"]),
        ).all()
        for frm, to in rows:
            if frm and to and frm not in comm_map:
                comm_map[frm] = to

    resolved, via_passup, via_commission, unresolved_ids = {}, 0, 0, []
    for u in null_users:
        if u.id in passup:
            resolved[u.id] = (passup[u.id], "passup"); via_passup += 1
        elif u.id in comm_map:
            resolved[u.id] = (comm_map[u.id], "commission"); via_commission += 1
        else:
            unresolved_ids.append(u.id)

    uname = {uid: un for uid, un, _ in [(u.id, u.username, None) for u in null_users]}
    sample_resolved = [{
        "user_id": uid, "username": uname.get(uid),
        "recovered_sponsor_id": sp, "source": src,
    } for uid, (sp, src) in list(resolved.items())[:15]]

    return JSONResponse({
        "total_null_sponsor_excl_root": len(null_users),
        "auto_recoverable_total": len(resolved),
        "via_passup": via_passup,
        "via_commission_records": via_commission,
        "needs_member_confirmation": len(unresolved_ids),
        "sample_recovered": sample_resolved,
        "sample_unresolved_ids": unresolved_ids[:15],
    })


@app.get("/admin/api/sponsor-recovery-notifications")
def admin_api_sponsor_recovery_notifications(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Recover the wiped sponsor tree from surviving 'team' join-notifications.

    On signup the platform notifies the sponsor: Notification(user_id=sponsor,
    type='team', title='<first_name> joined your team!', created_at≈signup time).
    If those rows survived, each maps sponsor -> joiner. We match the joiner back
    to a currently null-sponsor account by first name AND signup-timestamp
    proximity (the notification fires in the same request as the signup). A match
    is accepted only when it resolves to exactly one sponsor (no ambiguity).
    Read-only — reports coverage + sample. No writes.
    """
    _require_admin(user)
    from .database import Notification
    notifs = db.query(Notification.user_id, Notification.title, Notification.created_at).filter(
        Notification.type == "team").all()
    total_team_notifs = len(notifs)
    parsed = []
    for sponsor_uid, title, cat in notifs:
        nm = (title or "").split(" joined your team")[0].strip()
        if nm and cat:
            parsed.append((sponsor_uid, nm.lower(), cat))

    null_users = db.query(
        User.id, User.first_name, User.username, User.created_at, User.is_active
    ).filter(User.sponsor_id.is_(None), User.id != 1).all()

    WINDOW = 600  # seconds (10 min) — signup and its notification are near-simultaneous
    resolved, ambiguous_ids, no_name, active_resolved = {}, [], 0, 0
    for u in null_users:
        fn = (u.first_name or "").strip().lower()
        if not fn or not u.created_at:
            no_name += 1
            continue
        sponsors = set()
        for sp_uid, nm, cat in parsed:
            if nm == fn and abs((cat - u.created_at).total_seconds()) <= WINDOW:
                sponsors.add(sp_uid)
        if len(sponsors) == 1:
            sp = next(iter(sponsors))
            if sp != u.id:  # never self-sponsor
                resolved[u.id] = {"username": u.username, "first_name": u.first_name,
                                  "recovered_sponsor_id": sp, "is_active": bool(u.is_active)}
                if u.is_active:
                    active_resolved += 1
        elif len(sponsors) > 1:
            ambiguous_ids.append(u.id)

    return JSONResponse({
        "total_team_notifications_found": total_team_notifs,
        "null_sponsor_users": len(null_users),
        "recovered_via_notifications": len(resolved),
        "of_which_active": active_resolved,
        "ambiguous_multiple_candidates": len(ambiguous_ids),
        "null_users_without_first_name": no_name,
        "sample_recovered": list(resolved.values())[:20],
        "note": ("If total_team_notifications_found is ~0, the notifications were "
                 "wiped too and this source is dead. Otherwise these are name+time "
                 "matched sponsor links, accepted only when unambiguous."),
    })


@app.get("/admin/api/brevo-team-recovery")
def admin_api_brevo_team_recovery(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    sponsor_user_id: int = 1,
    email: str = "",
    max_pages: int = 10,
    per: int = 500,
):
    """Rebuild the sponsor tree from Brevo's transactional email logs (external,
    survived the wipe). On signup we email the sponsor "<first_name> just joined
    your SuperAdPro team!" via Brevo, so each logged email is recipient=sponsor,
    subject=referred first name, date≈signup. We map recipient email -> sponsor
    user, then match the referred first name + email date to a currently
    null-sponsor account, accepting only unambiguous matches. Read-only; reports
    coverage + the log date range (which reveals Brevo's retention window)."""
    _require_admin(user)
    import os as _os, httpx as _httpx
    from sqlalchemy import func as _func
    from collections import defaultdict as _dd
    from datetime import datetime as _dt

    api_key = _os.environ.get("BREVO_API_KEY", "")
    if not api_key:
        return JSONResponse({"error": "BREVO_API_KEY not configured in env"}, status_code=400)
    headers = {"api-key": api_key, "accept": "application/json"}
    base = "https://api.brevo.com/v3/smtp/emails"

    # /smtp/emails REQUIRES a filter (email/messageId/templateId). We filter by
    # RECIPIENT: every team-join email a sponsor received names someone who
    # joined under them. Default = company/owner (user 1) — the cohort you see
    # in your own inbox. ?sponsor_user_id=N recovers another sponsor's downline;
    # ?email= overrides the address.
    target = db.query(User).filter(User.id == sponsor_user_id).first()
    if not target:
        return JSONResponse({"error": f"sponsor_user_id {sponsor_user_id} not found"}, status_code=200)
    target_email = (email or target.email or "").strip()
    if not target_email:
        return JSONResponse({"error": f"no email on user {sponsor_user_id}; pass ?email="}, status_code=200)

    def _parse_dt(s):
        if not s:
            return None
        try:
            d = _dt.fromisoformat(s.replace("Z", "+00:00"))
            if d.tzinfo is not None:
                from datetime import timezone as _tz
                d = d.astimezone(_tz.utc).replace(tzinfo=None)
            return d
        except Exception:
            try:
                return _dt.strptime(s[:19], "%Y-%m-%dT%H:%M:%S")
            except Exception:
                return None

    import time as _time
    _t0 = _time.time()
    collected, total_seen, oldest, newest, hit_cap = [], 0, None, None, False
    first_status, first_sample = None, None
    offset, limit = 0, max(10, min(per, 500))
    try:
        with _httpx.Client(timeout=15) as client:
            for _pg in range(max_pages):
                if _time.time() - _t0 > 40:
                    hit_cap = True
                    break
                r = client.get(base, headers=headers,
                               params={"email": target_email, "limit": limit, "offset": offset, "sort": "desc"})
                if first_status is None:
                    first_status = r.status_code
                if r.status_code != 200:
                    return JSONResponse({"brevo_error_status": r.status_code,
                                         "brevo_body": r.text[:400]}, status_code=200)
                payload = r.json() or {}
                emails = payload.get("transactionalEmails", []) or []
                if first_sample is None and emails:
                    _s = emails[0]
                    first_sample = {"email": _s.get("email"), "subject": _s.get("subject"),
                                    "date": _s.get("date"), "keys": list(_s.keys())}
                if not emails:
                    break
                for e in emails:
                    total_seen += 1
                    dt = e.get("date") or ""
                    if dt:
                        if oldest is None or dt < oldest: oldest = dt
                        if newest is None or dt > newest: newest = dt
                    if "joined your SuperAdPro team" in (e.get("subject") or ""):
                        collected.append((e.get("email") or "", e.get("subject") or "", dt))
                if len(emails) < limit:
                    break
                offset += limit
    except Exception as e:
        return JSONResponse({"brevo_fetch_failed": f"{type(e).__name__}: {str(e)[:200]}",
                             "first_status": first_status}, status_code=200)

    all_users = db.query(User.id, User.first_name, User.username, User.created_at,
                         User.is_active, User.sponsor_id).all()
    by_fn = _dd(list)
    for u in all_users:
        if u.first_name:
            by_fn[u.first_name.strip().lower()].append(u)

    sponsor = target  # every email returned was received by this sponsor
    resolved, active_resolved, ambiguous, already_correct, conflict, not_found = {}, 0, 0, 0, 0, 0
    for recipient_email, subj, dt in collected:
        fn = subj.replace("\U0001f389", "").strip().split(" just joined")[0].strip().lower()
        cands = by_fn.get(fn, [])
        edt = _parse_dt(dt)
        near = [c for c in cands if c.created_at and edt and abs((c.created_at - edt).total_seconds()) <= 1800]
        pool = near or cands
        if len(pool) == 1:
            ref = pool[0]
            if ref.id == sponsor.id:
                continue
            if ref.sponsor_id == sponsor.id:
                already_correct += 1
            elif ref.sponsor_id is None:
                if ref.id not in resolved:
                    resolved[ref.id] = {"user_id": ref.id, "username": ref.username,
                                        "recovered_sponsor_id": sponsor.id,
                                        "sponsor_username": sponsor.username,
                                        "is_active": bool(ref.is_active)}
                    if ref.is_active:
                        active_resolved += 1
            else:
                conflict += 1  # already has a DIFFERENT sponsor — never overwrite
        elif len(pool) > 1:
            ambiguous += 1
        else:
            not_found += 1

    return JSONResponse({
        "transactional_emails_scanned": total_seen,
        "hit_page_or_time_cap": hit_cap,
        "brevo_first_status": first_status,
        "brevo_first_item_sample": first_sample,
        "brevo_log_date_range": {"oldest": oldest, "newest": newest},
        "queried_sponsor": {"user_id": target.id, "username": target.username, "email": target_email},
        "team_join_emails_found": len(collected),
        "recovered_under_this_sponsor": len(resolved),
        "of_which_active": active_resolved,
        "already_correct": already_correct,
        "ambiguous_same_name": ambiguous,
        "conflict_has_other_sponsor": conflict,
        "referred_not_found_in_db": not_found,
        "sample_recovered": list(resolved.values())[:25],
        "note": ("oldest date in brevo_log_date_range = Brevo's retention edge; "
                 "signups before that aren't in the logs. recovered links are "
                 "recipient(sponsor)->subject(referred), unambiguous matches only."),
    })


# ── Sponsor-tree mass recovery (batched Brevo sweep) ─────────────────────────
# /admin/api/brevo-team-recovery proves one sponsor's downline can be rebuilt
# from the team-join emails THEY received. This sweep runs that across every
# member who actually recruited (total_team>0 — a counter that SURVIVED the
# wipe), staging each unambiguous null->sponsor link into AppConfig so progress
# accumulates across taps. Dry by default; a separate 2FA apply writes the
# links, and ONLY where sponsor_id is currently NULL (never overwrites).
_SPONSOR_STAGE_KEY = "sponsor_recovery_staged"


def _sponsor_parse_dt(s):
    from datetime import datetime as _dt, timezone as _tz
    if not s:
        return None
    try:
        d = _dt.fromisoformat(s.replace("Z", "+00:00"))
        if d.tzinfo is not None:
            d = d.astimezone(_tz.utc).replace(tzinfo=None)
        return d
    except Exception:
        try:
            return _dt.strptime(s[:19], "%Y-%m-%dT%H:%M:%S")
        except Exception:
            return None


@app.get("/admin/api/sponsor-sweep")
def admin_api_sponsor_sweep(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    offset: int = 0,
    batch: int = 25,
    full: int = 0,
    reset: int = 0,
):
    """Batched dry-run sweep. Walks candidate sponsors (members with a downline,
    or ALL members if ?full=1), queries each one's Brevo inbox, and stages every
    unambiguous recoverable null->sponsor link into AppConfig. Resumable via
    ?offset=next_offset; returns next_offset until the list is exhausted. Writes
    NOTHING to member records — staging only. ?reset=1 clears the staged set."""
    _require_admin(user)
    import os as _os, httpx as _httpx, json as _json, time as _time
    from collections import defaultdict as _dd

    if reset:
        _secwatch_set(db, _SPONSOR_STAGE_KEY, "{}")
        db.commit()

    api_key = _os.environ.get("BREVO_API_KEY", "")
    if not api_key:
        return JSONResponse({"error": "BREVO_API_KEY not configured in env"}, status_code=400)
    headers = {"api-key": api_key, "accept": "application/json"}
    base = "https://api.brevo.com/v3/smtp/emails"

    # Candidate sponsors: members who actually recruited (total_team>0 or
    # personal_referrals>0 — both counters survived the wipe). ?full=1 flips to
    # the COMPLEMENT (members the recruiter pass skipped) to catch downlines
    # held by zero-counter sponsors — the two passes together cover everyone
    # exactly once.
    q = db.query(User.id, User.username, User.email).filter(
        User.email.isnot(None), User.email != "")
    if full:
        q = q.filter(~((User.total_team > 0) | (User.personal_referrals > 0)))
    else:
        q = q.filter((User.total_team > 0) | (User.personal_referrals > 0))
    candidates = q.order_by(User.id.asc()).all()
    total_candidates = len(candidates)
    window = candidates[offset:offset + max(1, batch)]

    # Name index over ALL users for matching referred first-names.
    all_users = db.query(User.id, User.first_name, User.username, User.created_at,
                         User.is_active, User.sponsor_id).all()
    by_fn = _dd(list)
    for u in all_users:
        if u.first_name:
            by_fn[u.first_name.strip().lower()].append(u)

    try:
        staged = _json.loads(_secwatch_get(db, _SPONSOR_STAGE_KEY, "{}") or "{}")
    except Exception:
        staged = {}

    _t0 = _time.time()
    processed, sponsors_with_links, new_links, stopped_early = 0, 0, 0, False
    next_offset = offset
    per_sponsor = []
    sponsors_errored = []
    try:
        with _httpx.Client(timeout=12) as client:
            for idx, cand in enumerate(window):
                if _time.time() - _t0 > 35:   # stay well under gateway timeout
                    stopped_early = True
                    break
                cemail = (cand.email or "").strip()
                if not cemail:
                    processed += 1
                    next_offset = offset + idx + 1
                    continue
                collected, off2, limit = [], 0, 500
                sponsor_err = None
                for _pg in range(4):
                    ok, r = False, None
                    for _attempt in range(2):   # one retry on rate-limit / transient
                        try:
                            r = client.get(base, headers=headers, params={
                                "email": cemail, "limit": limit, "offset": off2, "sort": "desc"})
                            if r.status_code == 200:
                                ok = True
                                break
                            sponsor_err = f"http_{r.status_code}"
                            if r.status_code in (429, 500, 502, 503, 504):
                                _time.sleep(1.0)
                                continue
                            break   # other non-200: do not retry
                        except Exception as _ex:
                            sponsor_err = type(_ex).__name__
                            _time.sleep(1.0)
                    if not ok:
                        break   # surfaced via sponsor_err below; not a silent zero
                    sponsor_err = None   # this page succeeded
                    emails = (r.json() or {}).get("transactionalEmails", []) or []
                    if not emails:
                        break
                    for e in emails:
                        if "joined your SuperAdPro team" in (e.get("subject") or ""):
                            collected.append((e.get("subject") or "", e.get("date") or ""))
                    if len(emails) < limit:
                        break
                    off2 += limit
                if sponsor_err:
                    sponsors_errored.append({"sponsor_id": cand.id,
                                             "sponsor_username": cand.username,
                                             "error": sponsor_err})
                _time.sleep(0.3)   # spacing to stay under Brevo's rate limit

                links_here = 0
                for subj, dt in collected:
                    fn = subj.replace("\U0001f389", "").strip().split(" just joined")[0].strip().lower()
                    cands_fn = by_fn.get(fn, [])
                    edt = _sponsor_parse_dt(dt)
                    near = [c for c in cands_fn if c.created_at and edt
                            and abs((c.created_at - edt).total_seconds()) <= 1800]
                    pool = near or cands_fn
                    if len(pool) != 1:
                        continue   # ambiguous -> leave for member-confirmation
                    ref = pool[0]
                    if ref.id == cand.id or ref.sponsor_id is not None:
                        continue   # skip self + anything already linked
                    key = str(ref.id)
                    if key not in staged:
                        staged[key] = {
                            "sponsor_id": cand.id,
                            "sponsor_username": cand.username,
                            "referred_username": ref.username,
                            "is_active": bool(ref.is_active),
                            "brevo_date": dt,
                            "applied": False,
                        }
                        new_links += 1
                        links_here += 1
                if links_here:
                    sponsors_with_links += 1
                    per_sponsor.append({"sponsor_id": cand.id,
                                        "sponsor_username": cand.username,
                                        "recovered": links_here})
                processed += 1
                next_offset = offset + idx + 1
    except Exception as e:
        return JSONResponse({"sweep_failed": f"{type(e).__name__}: {str(e)[:200]}"},
                            status_code=200)

    _secwatch_set(db, _SPONSOR_STAGE_KEY, _json.dumps(staged))
    db.commit()

    done = (next_offset >= total_candidates) and not stopped_early
    return JSONResponse({
        "candidate_pool": total_candidates,
        "candidate_mode": "non_recruiter_complement" if full else "recruiters_only(total_team>0)",
        "processed_this_batch": processed,
        "stopped_early_time_budget": stopped_early,
        "sponsors_with_recoverable_links_this_batch": sponsors_with_links,
        "new_links_staged_this_batch": new_links,
        "sponsors_errored_this_batch": len(sponsors_errored),
        "errored_sample": sponsors_errored[:25],
        "per_sponsor_this_batch": per_sponsor[:40],
        "cumulative_staged_total": len(staged),
        "cumulative_staged_active": sum(1 for v in staged.values() if v.get("is_active")),
        "next_offset": (None if done else next_offset),
        "sweep_complete": done,
        "note": ("Re-tap with ?offset=next_offset until sweep_complete=true. Then "
                 "review /admin/api/sponsor-sweep-review and apply with "
                 "/admin/api/sponsor-sweep-apply?code=YOUR_2FA. Nothing is written "
                 "to member records until you apply."),
    })


@app.get("/admin/api/sponsor-sweep-review")
def admin_api_sponsor_sweep_review(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    limit: int = 100,
):
    """Read-only view of everything staged, with a live sanity cross-check:
    how many staged targets are still NULL (will apply) vs already linked
    (will skip)."""
    _require_admin(user)
    import json as _json
    try:
        staged = _json.loads(_secwatch_get(db, _SPONSOR_STAGE_KEY, "{}") or "{}")
    except Exception:
        staged = {}
    if not staged:
        return JSONResponse({"staged_total": 0,
                             "note": "Nothing staged yet — run /admin/api/sponsor-sweep first."})
    ids = [int(k) for k in staged.keys()]
    cur = {u.id: u.sponsor_id for u in
           db.query(User.id, User.sponsor_id).filter(User.id.in_(ids)).all()}
    will_apply = sum(1 for k in staged if cur.get(int(k)) is None)
    by_sponsor = {}
    for v in staged.values():
        by_sponsor[v["sponsor_username"]] = by_sponsor.get(v["sponsor_username"], 0) + 1
    rows = sorted(staged.items(), key=lambda kv: kv[1]["sponsor_id"])
    sample = [{"referred_user_id": int(k), "referred_username": v["referred_username"],
               "sponsor_id": v["sponsor_id"], "sponsor_username": v["sponsor_username"],
               "is_active": v["is_active"],
               "state": ("NULL->will_apply" if cur.get(int(k)) is None else "already_linked->skip")}
              for k, v in rows][:limit]
    return JSONResponse({
        "staged_total": len(staged),
        "staged_active": sum(1 for v in staged.values() if v.get("is_active")),
        "will_apply_currently_null": will_apply,
        "will_skip_already_linked": len(staged) - will_apply,
        "sponsors_count": len(by_sponsor),
        "top_sponsors_by_recovered": sorted(by_sponsor.items(), key=lambda x: -x[1])[:25],
        "sample": sample,
    })


@app.get("/admin/api/sponsor-sweep-apply")
def admin_api_sponsor_sweep_apply(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    code: str = "",
    active_only: int = 0,
):
    """2FA-gated write. Sets User.sponsor_id from the staged set, ONLY where the
    member's sponsor_id is currently NULL (never overwrites an existing link).
    ?active_only=1 restricts to active members (commission-routing priority).
    Idempotent — applied entries are flagged and skipped on re-run."""
    _require_admin(user)
    import pyotp, json as _json
    if not getattr(user, "totp_secret", None):
        return JSONResponse({"error": "Admin has no 2FA configured"}, status_code=400)
    if not pyotp.TOTP(user.totp_secret).verify(code.strip(), valid_window=1):
        return JSONResponse({"error": "Invalid or missing 2FA code — pass ?code=NNNNNN"},
                            status_code=403)
    try:
        staged = _json.loads(_secwatch_get(db, _SPONSOR_STAGE_KEY, "{}") or "{}")
    except Exception:
        staged = {}
    if not staged:
        return JSONResponse({"error": "Nothing staged"}, status_code=400)

    applied, skipped_already, skipped_gone, skipped_inactive = 0, 0, 0, 0
    applied_sample = []
    for k, v in staged.items():
        if v.get("applied"):
            skipped_already += 1
            continue
        if active_only and not v.get("is_active"):
            skipped_inactive += 1
            continue
        ref = db.query(User).filter(User.id == int(k)).first()
        if not ref:
            skipped_gone += 1
            continue
        if ref.sponsor_id is not None:
            v["applied"] = True
            skipped_already += 1
            continue
        ref.sponsor_id = int(v["sponsor_id"])
        v["applied"] = True
        applied += 1
        if len(applied_sample) < 30:
            applied_sample.append({"referred_user_id": ref.id,
                                   "referred_username": ref.username,
                                   "sponsor_id": ref.sponsor_id,
                                   "sponsor_username": v["sponsor_username"]})
    _secwatch_set(db, _SPONSOR_STAGE_KEY, _json.dumps(staged))
    db.commit()
    return JSONResponse({
        "applied": applied,
        "skipped_already_linked_or_done": skipped_already,
        "skipped_user_gone": skipped_gone,
        "skipped_inactive": skipped_inactive,
        "active_only": bool(active_only),
        "applied_sample": applied_sample,
        "note": ("sponsor_id restored only where it was NULL. Surviving total_team/"
                 "personal_referrals counters left untouched (they're truth). "
                 "Re-run is safe — applied entries are skipped."),
    })


@app.get("/admin/api/set-sponsor")
def admin_api_set_sponsor(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    user_id: int = 0,
    sponsor_id: int = 0,
    code: str = "",
    force: int = 0,
):
    """2FA-gated manual sponsor set for the member-confirmation remainder. Sets
    User(user_id).sponsor_id = sponsor_id. By default only fills a NULL link;
    pass ?force=1 to overwrite an existing one (use sparingly — corrections).
    Guards against self-link and cycles (sponsor cannot sit in the member's own
    downline)."""
    _require_admin(user)
    import pyotp
    if not getattr(user, "totp_secret", None):
        return JSONResponse({"error": "Admin has no 2FA configured"}, status_code=400)
    if not pyotp.TOTP(user.totp_secret).verify(code.strip(), valid_window=1):
        return JSONResponse({"error": "Invalid or missing 2FA code — pass ?code=NNNNNN"},
                            status_code=403)
    if user_id <= 0 or sponsor_id <= 0:
        return JSONResponse({"error": "pass ?user_id=N&sponsor_id=M"}, status_code=400)
    if user_id == sponsor_id:
        return JSONResponse({"error": "a member cannot be their own sponsor"}, status_code=400)
    target = db.query(User).filter(User.id == user_id).first()
    sponsor = db.query(User).filter(User.id == sponsor_id).first()
    if not target:
        return JSONResponse({"error": f"user_id {user_id} not found"}, status_code=404)
    if not sponsor:
        return JSONResponse({"error": f"sponsor_id {sponsor_id} not found"}, status_code=404)
    if target.sponsor_id is not None and not force:
        return JSONResponse({"error": f"user {user_id} already linked to sponsor "
                             f"{target.sponsor_id}; pass ?force=1 to overwrite",
                             "current_sponsor_id": target.sponsor_id}, status_code=409)
    # Cycle guard: walk up from the proposed sponsor; must not reach user_id.
    hop, seen = sponsor.sponsor_id, {sponsor_id}
    for _ in range(25):
        if hop is None:
            break
        if hop == user_id:
            return JSONResponse({"error": "rejected — would create a sponsor cycle "
                                 f"(user {user_id} is an ancestor of {sponsor_id})"},
                                status_code=400)
        if hop in seen:
            break
        seen.add(hop)
        nxt = db.query(User.sponsor_id).filter(User.id == hop).first()
        hop = nxt[0] if nxt else None
    prev = target.sponsor_id
    target.sponsor_id = sponsor_id
    db.commit()
    return JSONResponse({
        "ok": True, "user_id": user_id, "username": target.username,
        "previous_sponsor_id": prev, "new_sponsor_id": sponsor_id,
        "sponsor_username": sponsor.username,
    })


@app.get("/admin/api/sponsor-residual-nulls")
def admin_api_sponsor_residual_nulls(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Lists every member still missing a sponsor_id after the Brevo sweep
    (excludes root user 1, whose null is correct). These are the pre-9-May
    signups outside Brevo's retention — the member-confirmation remainder.
    Ordered oldest-first (earliest founders) with the context needed to
    recognise/confirm them."""
    _require_admin(user)
    rows = (db.query(User.id, User.username, User.email, User.first_name,
                     User.created_at, User.is_active, User.total_team,
                     User.personal_referrals, User.founding_spot_number,
                     User.pass_up_sponsor_id)
            .filter(User.sponsor_id.is_(None), User.id != 1)
            .order_by(User.created_at.asc()).all())
    # Resolve pass-up lead usernames in one batch.
    pu_ids = [r.pass_up_sponsor_id for r in rows if r.pass_up_sponsor_id]
    pu_names = {}
    if pu_ids:
        pu_names = {u.id: u.username for u in
                    db.query(User.id, User.username).filter(User.id.in_(pu_ids)).all()}
    out = [{
        "user_id": r.id, "username": r.username, "first_name": r.first_name,
        "email": r.email, "is_active": bool(r.is_active),
        "created_at": r.created_at.isoformat() if r.created_at else None,
        "founding_spot": r.founding_spot_number,
        "total_team": r.total_team, "personal_referrals": r.personal_referrals,
        "passup_lead_id": r.pass_up_sponsor_id,
        "passup_lead_username": pu_names.get(r.pass_up_sponsor_id),
    } for r in rows]
    return JSONResponse({
        "residual_null_count": len(out),
        "active_count": sum(1 for r in out if r["is_active"]),
        "note": ("These need member-confirmation or owner knowledge — their "
                 "join emails predate Brevo's ~9-May retention edge. To set a "
                 "sponsor manually, use /admin/api/set-sponsor (2FA)."),
        "users": out,
    })


@app.get("/api/command-centre/grid-team")
def api_command_centre_grid_team(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Distinct members occupying positions in any of THIS user's grids.
    Privacy-conscious — public profile fields only, no earnings."""
    from sqlalchemy import func
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    # Distinct user IDs filling positions in this user's grids
    member_ids = [row[0] for row in db.query(GridPosition.member_id).join(
        Grid, GridPosition.grid_id == Grid.id
    ).filter(Grid.owner_id == user.id).distinct().all() if row[0]]

    if not member_ids:
        return {"count": 0, "members": []}

    members = db.query(User).filter(User.id.in_(member_ids)).order_by(User.created_at.desc()).all()

    # Last membership payment date per member
    last_paid_map = {}
    rows = db.query(
        Payment.from_user_id, func.max(Payment.created_at),
    ).filter(
        Payment.from_user_id.in_(member_ids),
        Payment.payment_type.like("membership%"),
        Payment.status.in_(["confirmed", "paid"]),
    ).group_by(Payment.from_user_id).all()
    last_paid_map = {row[0]: row[1] for row in rows}

    return {
        "count": len(members),
        "members": [_direct_member_payload(m, last_paid_map.get(m.id)) for m in members],
    }


@app.get("/api/command-centre/nexus-team")
def api_command_centre_nexus_team(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Distinct members in THIS user's credit matrix positions, excluding
    the owner themselves. Privacy-conscious — same shape as grid-team."""
    from sqlalchemy import func
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    # Distinct user IDs in this user's matrices, excluding the owner
    member_ids = [row[0] for row in db.query(CreditMatrixPosition.user_id).join(
        CreditMatrix, CreditMatrixPosition.matrix_id == CreditMatrix.id
    ).filter(
        CreditMatrix.owner_id == user.id,
        CreditMatrixPosition.user_id != user.id,
    ).distinct().all() if row[0]]

    if not member_ids:
        return {"count": 0, "members": []}

    members = db.query(User).filter(User.id.in_(member_ids)).order_by(User.created_at.desc()).all()

    last_paid_map = {}
    rows = db.query(
        Payment.from_user_id, func.max(Payment.created_at),
    ).filter(
        Payment.from_user_id.in_(member_ids),
        Payment.payment_type.like("membership%"),
        Payment.status.in_(["confirmed", "paid"]),
    ).group_by(Payment.from_user_id).all()
    last_paid_map = {row[0]: row[1] for row in rows}

    return {
        "count": len(members),
        "members": [_direct_member_payload(m, last_paid_map.get(m.id)) for m in members],
    }


