@app.post("/delete-campaign")
def delete_campaign(
    request: Request,
    campaign_id: int = Form(),
    db: Session = Depends(get_db),
    user: User  = Depends(get_current_user)
):
    if not user: return RedirectResponse(url="/?login=1", status_code=302)
    campaign = db.query(VideoCampaign).filter(
        VideoCampaign.id      == campaign_id,
        VideoCampaign.user_id == user.id  # ownership check
    ).first()
    if campaign:
        campaign.status = "deleted"
        db.commit()
    return RedirectResponse(url="/video-library", status_code=303)
@app.get("/api/video-library")
def api_video_library(request: Request,
                      db: Session = Depends(get_db),
                      user: User = Depends(get_current_user)):
    """JSON endpoint that serves the React VideoLibrary page.

    Ports the data shape that the (now-disabled) Jinja2 _old_video_library_DISABLED
    used to send to its template, but returns JSON for the React component to
    consume via apiGet('/api/video-library').

    Returns:
      - campaigns: list of VideoCampaign rows owned by this user, newest first,
        excluding soft-deleted entries
      - total_campaigns / active_campaigns / total_views: aggregate stats for
        the three big stat cards at the top of the page

    Created 16 May 2026 to fix a shipped-but-broken React page: when the
    library was migrated from Jinja2 to React, the page route was wired up
    (line 21433) but the matching JSON API was never created. apiGet on
    /api/video-library 404'd, the React component's silent .catch swallowed
    the error, and the empty-state UI rendered with a 'Create First' button —
    making it look like the user's just-uploaded campaign had vanished.
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    campaigns = db.query(VideoCampaign).filter(
        VideoCampaign.user_id == user.id,
        VideoCampaign.status != "deleted",
    ).order_by(VideoCampaign.created_at.desc()).all()

    # Aggregate stats for the three cards at the top of the page.
    # active_campaigns counts only campaigns currently delivering — pending,
    # paused_no_tier, and completed campaigns are excluded from the "active"
    # count so the user sees a true picture of what's currently working.
    total_views_delivered = sum((c.views_delivered or 0) for c in campaigns)
    active_count = sum(1 for c in campaigns if c.status == "active")

    return {
        "total_campaigns": len(campaigns),
        "active_campaigns": active_count,
        "total_views": total_views_delivered,
        "campaigns": [
            {
                "id": c.id,
                "title": c.title,
                "status": c.status,
                "platform": c.platform,
                "category": c.category,
                "video_url": c.video_url,
                "embed_url": c.embed_url,
                "views_target": c.views_target or 0,
                "views_delivered": c.views_delivered or 0,
                "target_country": c.target_country,
                "target_interests": c.target_interests,
            }
            for c in campaigns
        ],
    }


@app.delete("/api/campaigns/{campaign_id}")
def api_delete_campaign(campaign_id: int, request: Request,
                        db: Session = Depends(get_db),
                        user: User = Depends(get_current_user)):
    """Delete (soft) a video campaign. JSON API for React frontend."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    campaign = db.query(VideoCampaign).filter(
        VideoCampaign.id == campaign_id,
        VideoCampaign.user_id == user.id,
    ).first()
    if not campaign:
        return JSONResponse({"error": "Campaign not found"}, status_code=404)
    campaign.status = "deleted"
    db.commit()
    return {"success": True, "message": "Campaign deleted"}


@app.post("/admin/api/rotator-reenrol-founders")
def admin_api_rotator_reenrol_founders(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Re-run the founder-to-rotator auto-enrol on demand.

    Same logic as the boot-time migration in database.py — idempotent,
    only adds Founders not already in the queue, flips rotator_opted_in
    where currently FALSE. Lets us fix an empty queue without needing
    a redeploy. Admin only.
    """
    _require_admin(user)
    from sqlalchemy import text as _text
    try:
        rows = db.execute(_text("""
            SELECT u.id, u.username
              FROM users u
              LEFT JOIN rotator_queue rq ON rq.user_id = u.id
             WHERE u.is_active = TRUE
               AND u.is_founding_member = TRUE
               AND COALESCE(u.is_admin, FALSE) = FALSE
               AND rq.user_id IS NULL
             ORDER BY u.founding_spot_number NULLS LAST, u.id
        """)).fetchall()

        if not rows:
            existing = db.execute(_text(
                "SELECT COUNT(*) FROM rotator_queue"
            )).scalar() or 0
            return {
                "success": True,
                "enrolled": 0,
                "queue_size": existing,
                "message": f"No new enrolments needed. Queue already has {existing} member(s).",
            }

        mx = db.execute(_text(
            "SELECT COALESCE(MAX(queue_position), 0) FROM rotator_queue"
        )).scalar() or 0
        next_pos = mx + 1
        inserted = 0
        for r in rows:
            uid = r[0]
            try:
                db.execute(_text(
                    "INSERT INTO rotator_queue (user_id, queue_position, joined_at) "
                    "VALUES (:uid, :pos, NOW()) ON CONFLICT (user_id) DO NOTHING"
                ), {"uid": uid, "pos": next_pos})
                db.execute(_text(
                    "UPDATE users SET rotator_opted_in = TRUE WHERE id = :uid"
                ), {"uid": uid})
                inserted += 1
                next_pos += 1
            except Exception as e:
                logger.warning(f"rotator reenrol: user {uid} failed: {e}")
        db.commit()
        new_total = db.execute(_text("SELECT COUNT(*) FROM rotator_queue")).scalar() or 0
        return {
            "success": True,
            "enrolled": inserted,
            "queue_size": new_total,
            "message": f"Enrolled {inserted} Founder(s). Queue now has {new_total} member(s).",
        }
    except Exception as e:
        logger.exception(f"rotator reenrol endpoint failed: {e}")
        db.rollback()
        return JSONResponse(
            {"success": False, "error": str(e)},
            status_code=500,
        )


@app.get("/admin/api/diag-member-leads")
def admin_api_diag_member_leads(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Admin diagnostic: list the last 20 MemberLead rows in the table
    (any user), and the last 20 belonging to the calling admin. Also
    runs each of the five endpoints that MyLeads.jsx loads in parallel
    via Promise.all — if ANY of them errors, the .catch swallows the
    whole batch and the page shows zeros. This isolates which one.
    """
    _require_admin(user)
    from .database import MemberLead, EmailSequence, LeadList

    last_all = db.query(MemberLead).order_by(MemberLead.id.desc()).limit(20).all()
    mine = db.query(MemberLead).filter(MemberLead.user_id == user.id).order_by(MemberLead.id.desc()).limit(20).all()
    total_mine = db.query(MemberLead).filter(MemberLead.user_id == user.id).count()
    total_all = db.query(MemberLead).count()

    def row(l):
        return {
            "id": l.id, "user_id": l.user_id, "email": l.email,
            "source_funnel_id": l.source_funnel_id, "status": l.status,
            "emails_sent": l.emails_sent, "created_at": l.created_at.isoformat() if l.created_at else None,
        }

    # ── Probe each of the 5 endpoints MyLeads.jsx calls in parallel ──
    # Replicate each query inline so we can see which one raises.
    probes = {}

    # /api/leads — list leads
    try:
        leads = db.query(MemberLead).filter(MemberLead.user_id == user.id).limit(5).all()
        probes["api_leads"] = {"ok": True, "count": len(leads)}
    except Exception as e:
        probes["api_leads"] = {"ok": False, "error": str(e)[:300]}

    # /api/leads/sequences — list sequences
    try:
        seqs = db.query(EmailSequence).filter(EmailSequence.user_id == user.id).limit(5).all()
        probes["api_leads_sequences"] = {"ok": True, "count": len(seqs)}
    except Exception as e:
        probes["api_leads_sequences"] = {"ok": False, "error": str(e)[:300]}

    # /api/leads/lists — list lead lists
    try:
        lists = db.query(LeadList).filter(LeadList.user_id == user.id).limit(5).all()
        probes["api_leads_lists"] = {"ok": True, "count": len(lists)}
    except Exception as e:
        probes["api_leads_lists"] = {"ok": False, "error": str(e)[:300]}

    # /api/leads/stats — stats
    try:
        total = db.query(MemberLead).filter(MemberLead.user_id == user.id).count()
        hot = db.query(MemberLead).filter(MemberLead.user_id == user.id, MemberLead.is_hot == True).count()
        probes["api_leads_stats"] = {"ok": True, "total": total, "hot": hot}
    except Exception as e:
        probes["api_leads_stats"] = {"ok": False, "error": str(e)[:300]}

    # /api/leads/email-stats — email stats
    try:
        today = datetime.utcnow().strftime("%Y-%m-%d")
        sent = user.emails_sent_today or 0
        creds = user.email_credits or 0
        probes["api_leads_email_stats"] = {"ok": True, "sent_today": sent, "credits": creds}
    except Exception as e:
        probes["api_leads_email_stats"] = {"ok": False, "error": str(e)[:300]}

    return {
        "calling_admin_id": user.id,
        "total_rows_in_table": total_all,
        "total_rows_for_me": total_mine,
        "endpoint_probes": probes,
        "last_20_all": [row(l) for l in last_all],
        "last_20_mine": [row(l) for l in mine],
    }


@app.api_route("/admin/api/fix-broken-form-placeholders", methods=["GET", "POST"])
def admin_api_fix_broken_form_placeholders(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """One-shot DB cleanup: replace literal `{t('superPagesEditor.X')}`
    placeholder strings in funnel_pages with their resolved English
    text.

    Background: the buildHTML() function in both the production and
    labs SuperPagesEditor had a bug where i18n template syntax
    `{t('superPagesEditor.firstNamePlaceholder')}` was embedded inside
    a JS template literal, which doesn't evaluate t(). The literal
    Handlebars-style text got saved as the placeholder attribute on
    form inputs, showing up as raw template syntax on the public page.

    Editor fixed 18 May 2026; this endpoint repairs pages already
    saved with the bad data.

    Scans FunnelPage rows where content_json or html_export contains
    the broken pattern, regex-replaces with English fallback text,
    and saves. Idempotent — running twice is a no-op on the second
    pass because the broken pattern is gone after the first.

    Admin only. Returns count of pages updated.
    """
    _require_admin(user)
    from .database import FunnelPage
    import re as _re

    # Map of broken placeholder strings to English fallbacks.
    # Future locale-aware version would replace based on the page
    # owner's preferred language, but for now English is a safe
    # default — the bug shipped to all locales identically anyway.
    replacements = [
        (r"\{t\('superPagesEditor\.firstNamePlaceholder'\)\}", "Your name"),
        (r"\{t\('superPagesEditor\.emailPlaceholder'\)\}",     "Your email"),
        (r"\{t\('superPagesEditor\.phonePlaceholder'\)\}",     "Your phone"),
        # Double-quoted variants in case anyone hand-edited
        (r'\{t\("superPagesEditor\.firstNamePlaceholder"\)\}', "Your name"),
        (r'\{t\("superPagesEditor\.emailPlaceholder"\)\}',     "Your email"),
        (r'\{t\("superPagesEditor\.phonePlaceholder"\)\}',     "Your phone"),
    ]

    # FunnelPage stores the published HTML in gjs_html (what /p/{slug}
    # actually serves) and the GrapesJS editor state in gjs_components.
    # Older pages may also have content in sections_json. Scan all three
    # so we catch every place the broken placeholder string can live.
    pages = db.query(FunnelPage).all()
    updated = 0
    for p in pages:
        changed = False
        for col_name in ("gjs_html", "gjs_components", "gjs_styles", "sections_json"):
            current = getattr(p, col_name, None)
            if not current:
                continue
            new_val = current
            for pattern, fallback in replacements:
                new_val = _re.sub(pattern, fallback, new_val)
            if new_val != current:
                setattr(p, col_name, new_val)
                changed = True
        if changed:
            updated += 1

    db.commit()
    logger.info(f"Form-placeholder cleanup: updated {updated} of {len(pages)} pages")
    return {
        "success": True,
        "pages_scanned": len(pages),
        "pages_updated": updated,
    }


@app.api_route("/admin/api/backfill-lead-attribution", methods=["GET", "POST"])
def admin_api_backfill_lead_attribution(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """One-shot backfill: link existing active users to existing
    MemberLead rows by email match.

    Going forward, lead attribution is set automatically when a user
    activates Partner membership (via _attribute_lead_to_activation
    called from initialise_renewal_record). But that only covers NEW
    activations from the moment Commit B ships. This endpoint backfills
    historical data — for each currently-active user, find any
    MemberLead rows with matching email and attribute them.

    Idempotent: only sets rows where attribution_user_id IS NULL.
    Safe to run multiple times. Admin only.

    Returns: counts of users scanned, leads matched, errors.
    """
    _require_admin(user)
    from .database import MemberLead

    scanned = 0
    attributed = 0
    errors = 0

    # Process only active users — we don't attribute leads to free or
    # inactive users (they haven't 'converted' in any meaningful sense).
    active_users = db.query(User).filter(User.is_active == True).all()

    now = datetime.utcnow()
    for u in active_users:
        scanned += 1
        if not u.email:
            continue
        try:
            email_lc = u.email.strip().lower()
            matches = db.query(MemberLead).filter(
                MemberLead.email.ilike(email_lc),
                MemberLead.attribution_user_id.is_(None),
            ).all()
            for lead in matches:
                # Edge case: don't attribute a lead to the same user who
                # owns it (would happen if a member captured their own
                # email via their own form for testing — happens often).
                # That's not a conversion; that's the affiliate themselves.
                if lead.user_id == u.id:
                    continue
                lead.attribution_user_id = u.id
                lead.attribution_set_at = now
                if lead.status not in ("converted", "unsubscribed"):
                    lead.status = "converted"
                attributed += 1
        except Exception as e:
            logger.warning(f"backfill_lead_attribution: user {u.id} failed: {e}")
            errors += 1

    db.commit()
    logger.info(
        f"Lead attribution backfill: scanned={scanned} active users, "
        f"attributed={attributed} leads, errors={errors}"
    )
    return {
        "success": True,
        "users_scanned": scanned,
        "leads_attributed": attributed,
        "errors": errors,
    }


@app.get("/admin/api/campaign-binding-status")
@app.post("/admin/api/campaign-binding-status")
def admin_api_campaign_binding_status(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Phase 1 diagnostic: report current campaign binding state.

    Reports across the whole platform:
      - How many pages have default_list_id set vs NULL
      - How many MemberLead rows have list_id set vs NULL
      - Per-page summary: pages with their captured-lead count, current
        default_list_id, and whether they'd be touched by the backfill
      - Orphan leads: count by source_funnel_id where source page has
        no default_list_id

    Read-only. Safe to call any time. Admin only.

    Pair this with /admin/api/backfill-campaign-binding which actually
    runs the backfill (with a dry_run flag).
    """
    _require_admin(user)
    from .database import FunnelPage, MemberLead, LeadList
    from sqlalchemy import func as _func

    total_pages = db.query(_func.count(FunnelPage.id)).scalar() or 0
    pages_with_list = db.query(_func.count(FunnelPage.id)).filter(
        FunnelPage.default_list_id.isnot(None)
    ).scalar() or 0
    pages_without_list = total_pages - pages_with_list

    total_leads = db.query(_func.count(MemberLead.id)).scalar() or 0
    leads_with_list = db.query(_func.count(MemberLead.id)).filter(
        MemberLead.list_id.isnot(None)
    ).scalar() or 0
    leads_without_list = total_leads - leads_with_list

    total_lists = db.query(_func.count(LeadList.id)).scalar() or 0

    # Pages that have captured at least one lead — these are the ones
    # the backfill will care about. (Pages with zero leads don't need
    # a list yet; they can pick one when they capture their first.)
    pages_with_leads = db.query(
        FunnelPage.id, FunnelPage.user_id, FunnelPage.title,
        FunnelPage.default_list_id,
        _func.count(MemberLead.id).label("lead_count"),
    ).join(
        MemberLead, MemberLead.source_funnel_id == FunnelPage.id
    ).group_by(
        FunnelPage.id, FunnelPage.user_id, FunnelPage.title,
        FunnelPage.default_list_id
    ).order_by(_func.count(MemberLead.id).desc()).limit(50).all()

    page_summary = []
    backfill_would_create_lists = 0
    backfill_would_assign_leads = 0
    for p in pages_with_leads:
        action = "skip — already bound"
        if not p.default_list_id:
            action = f"create '<title> leads' list, assign {p.lead_count} leads"
            backfill_would_create_lists += 1
            backfill_would_assign_leads += int(p.lead_count or 0)
        page_summary.append({
            "page_id": p.id,
            "user_id": p.user_id,
            "title": p.title,
            "default_list_id": p.default_list_id,
            "captured_leads": int(p.lead_count or 0),
            "backfill_action": action,
        })

    return {
        "totals": {
            "pages": int(total_pages),
            "pages_with_default_list": int(pages_with_list),
            "pages_without_default_list": int(pages_without_list),
            "leads": int(total_leads),
            "leads_with_list_id": int(leads_with_list),
            "leads_without_list_id": int(leads_without_list),
            "lead_lists": int(total_lists),
        },
        "backfill_preview": {
            "lists_to_create": backfill_would_create_lists,
            "leads_to_assign": backfill_would_assign_leads,
            "note": "Run POST /admin/api/backfill-campaign-binding?dry_run=true to dry-run, or dry_run=false to execute.",
        },
        "pages_with_leads": page_summary,
    }


@app.get("/admin/api/backfill-campaign-binding")
@app.post("/admin/api/backfill-campaign-binding")
def admin_api_backfill_campaign_binding(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    dry_run: bool = True,
):
    """Phase 1 backfill: wire existing pages to lead lists.

    For every page that has captured at least one MemberLead but
    doesn't have default_list_id set:
      1. Create a new LeadList named '<page.title> leads' owned by
         page.user_id.
      2. Set page.default_list_id = new_list.id.
      3. Update every MemberLead with source_funnel_id == page.id
         AND list_id IS NULL to point at the new list.
      4. Update list.lead_count to match.

    Idempotent. Pages already bound to a list are skipped entirely.
    Pages with no captured leads are also skipped — they can pick a
    list when they capture their first.

    Default mode is DRY RUN: returns the plan without committing.
    Set ?dry_run=false (or POST with dry_run=false in query) to
    actually execute.

    Admin only. Safe to run multiple times.
    """
    _require_admin(user)
    from .database import FunnelPage, MemberLead, LeadList
    from sqlalchemy import func as _func

    actions = []
    lists_created = 0
    pages_bound = 0
    leads_assigned = 0
    errors = []

    # Find pages with captured leads and no default_list_id set
    candidates = db.query(
        FunnelPage.id, FunnelPage.user_id, FunnelPage.title,
        _func.count(MemberLead.id).label("lead_count"),
    ).join(
        MemberLead, MemberLead.source_funnel_id == FunnelPage.id
    ).filter(
        FunnelPage.default_list_id.is_(None),
    ).group_by(
        FunnelPage.id, FunnelPage.user_id, FunnelPage.title
    ).all()

    now = datetime.utcnow()
    for c in candidates:
        try:
            list_name = f"{(c.title or 'Untitled page').strip()[:80]} leads"
            actions.append({
                "page_id": c.id,
                "user_id": c.user_id,
                "page_title": c.title,
                "list_name_to_create": list_name,
                "leads_to_assign": int(c.lead_count or 0),
            })
            if dry_run:
                continue

            # ── Execute ──
            # Look for an existing list with the same name (idempotency
            # safety: if a previous backfill run partially succeeded, or
            # the user manually created a list with this exact name, we
            # reuse it rather than duplicating).
            existing = db.query(LeadList).filter(
                LeadList.user_id == c.user_id,
                LeadList.name == list_name,
            ).first()
            if existing:
                new_list = existing
            else:
                new_list = LeadList(
                    user_id=c.user_id,
                    name=list_name,
                    description=f"Auto-created by Phase 1 backfill for SuperPage '{c.title}'",
                    color="#0ea5e9",  # cobalt cyan
                    created_at=now,
                )
                db.add(new_list)
                db.flush()  # to get new_list.id
                lists_created += 1

            # Bind the page
            page = db.query(FunnelPage).filter(FunnelPage.id == c.id).first()
            if page and not page.default_list_id:
                page.default_list_id = new_list.id
                pages_bound += 1

            # Assign all unattached leads from this page to the new list
            assigned = db.query(MemberLead).filter(
                MemberLead.source_funnel_id == c.id,
                MemberLead.list_id.is_(None),
            ).update({"list_id": new_list.id}, synchronize_session=False)
            leads_assigned += int(assigned or 0)

            # Refresh list lead_count to match reality (covers both new
            # assignments and any leads that were already on this list)
            new_count = db.query(_func.count(MemberLead.id)).filter(
                MemberLead.list_id == new_list.id
            ).scalar() or 0
            new_list.lead_count = int(new_count)

        except Exception as e:
            errors.append({"page_id": c.id, "error": str(e)[:300]})
            logger.warning(f"backfill_campaign_binding: page {c.id} failed: {e}")

    if not dry_run and not errors:
        db.commit()
        logger.info(
            f"Phase 1 backfill: lists_created={lists_created}, "
            f"pages_bound={pages_bound}, leads_assigned={leads_assigned}"
        )
    elif errors and not dry_run:
        db.rollback()
        logger.error(f"Phase 1 backfill: rolled back due to errors: {errors}")

    return {
        "dry_run": dry_run,
        "committed": (not dry_run) and (not errors),
        "actions_planned": actions,
        "summary": {
            "candidate_pages": len(candidates),
            "lists_created": lists_created if not dry_run else len([a for a in actions]),
            "pages_bound": pages_bound if not dry_run else len([a for a in actions]),
            "leads_assigned": leads_assigned if not dry_run else sum(a["leads_to_assign"] for a in actions),
        },
        "errors": errors,
    }


@app.get("/admin/api/activation-funnel")
def admin_api_activation_funnel(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Admin diagnostic: how is the registered → activated funnel performing?

    Read-only. Answers the questions worth knowing about activation:
      1. What's the conversion rate overall (active / total)?
      2. How fresh are the inactive cohort? (recent = warm/recoverable;
         old = mostly lost). Bucketed by age since registration.
      3. For those who DID activate, how fast did they do it? (median
         time-to-activation tells you when an inactive member is past
         likely-to-convert window).
      4. Which sponsors convert their referrals best? (top sponsors by
         conversion rate, surfaces teaching/onboarding patterns).

    Built 28 May 2026 — investigation triggered by 'we have 382 registered
    members and 106 active members, what's that as a percentage?' The
    real insight is the AGE breakdown of the inactive pool, not the
    headline ratio.

    Excludes admin accounts (is_admin=true) from the cohort so the numbers
    reflect actual members.
    """
    _require_admin(user)
    from .database import Payment

    now = datetime.utcnow()

    # ── Cohort counts ──
    base_q = db.query(User).filter(User.is_admin == False)
    total = base_q.count()
    active = base_q.filter(User.is_active == True).count()
    inactive = total - active

    overall_conversion_pct = round((active / total * 100), 1) if total else 0.0

    # ── Age buckets of INACTIVE members (since registration) ──
    inactive_users = base_q.filter(User.is_active == False).all()
    inactive_buckets = {
        "last_24h": 0,
        "1_to_7d": 0,
        "7_to_30d": 0,
        "30_to_90d": 0,
        "over_90d": 0,
    }
    for u in inactive_users:
        if not u.created_at:
            continue
        age_days = (now - u.created_at).total_seconds() / 86400.0
        if age_days < 1:
            inactive_buckets["last_24h"] += 1
        elif age_days < 7:
            inactive_buckets["1_to_7d"] += 1
        elif age_days < 30:
            inactive_buckets["7_to_30d"] += 1
        elif age_days < 90:
            inactive_buckets["30_to_90d"] += 1
        else:
            inactive_buckets["over_90d"] += 1

    # Warm (recoverable, last 7d) vs cold (>30d, mostly lost)
    inactive_warm_7d = inactive_buckets["last_24h"] + inactive_buckets["1_to_7d"]
    inactive_cold_30d = inactive_buckets["30_to_90d"] + inactive_buckets["over_90d"]

    # ── Time-to-activation for those who DID activate ──
    active_users = base_q.filter(
        User.is_active == True,
        User.activated_at.isnot(None),
        User.created_at.isnot(None),
    ).all()
    ttd_hours = []
    activation_speed_buckets = {
        "same_day": 0,
        "1_to_3d": 0,
        "3_to_7d": 0,
        "7_to_30d": 0,
        "over_30d": 0,
    }
    for u in active_users:
        delta_h = (u.activated_at - u.created_at).total_seconds() / 3600.0
        if delta_h < 0:
            continue  # data weirdness, skip
        ttd_hours.append(delta_h)
        delta_d = delta_h / 24.0
        if delta_d < 1:
            activation_speed_buckets["same_day"] += 1
        elif delta_d < 3:
            activation_speed_buckets["1_to_3d"] += 1
        elif delta_d < 7:
            activation_speed_buckets["3_to_7d"] += 1
        elif delta_d < 30:
            activation_speed_buckets["7_to_30d"] += 1
        else:
            activation_speed_buckets["over_30d"] += 1

    # Median time-to-activation
    median_ttd_hours = None
    if ttd_hours:
        ttd_sorted = sorted(ttd_hours)
        n = len(ttd_sorted)
        median_ttd_hours = round(
            (ttd_sorted[n // 2] if n % 2 else (ttd_sorted[n // 2 - 1] + ttd_sorted[n // 2]) / 2),
            1
        )

    # ── Sponsor conversion patterns (top sponsors by referral count) ──
    # Build sponsor -> {referrals, activated} map. Only sponsors with >= 5
    # referrals (statistically meaningful), top 15 by referral count.
    sponsor_rows = db.execute(text("""
        SELECT
            sponsor_id,
            COUNT(*) as referrals,
            SUM(CASE WHEN is_active THEN 1 ELSE 0 END) as activated
        FROM users
        WHERE sponsor_id IS NOT NULL AND is_admin = false
        GROUP BY sponsor_id
        HAVING COUNT(*) >= 5
        ORDER BY COUNT(*) DESC
        LIMIT 15
    """)).fetchall()

    sponsor_ids = [r.sponsor_id for r in sponsor_rows]
    sponsor_users = {u.id: u for u in db.query(User).filter(User.id.in_(sponsor_ids)).all()} if sponsor_ids else {}

    top_sponsors = []
    for r in sponsor_rows:
        su = sponsor_users.get(r.sponsor_id)
        if not su:
            continue
        conv_pct = round((r.activated / r.referrals * 100), 1) if r.referrals else 0
        top_sponsors.append({
            "sponsor_id": r.sponsor_id,
            "username": su.username,
            "referrals": r.referrals,
            "activated": r.activated,
            "conversion_pct": conv_pct,
        })

    # ── Estimated MRR from active members ──
    # Read membership_price_locked for accuracy (Founders locked at $15,
    # Partners at $20). Falls back to is_founding_member -> $15 / else $20.
    mrr_total = 0.0
    founders_mrr = 0.0
    partners_mrr = 0.0
    for u in db.query(User).filter(User.is_admin == False, User.is_active == True).all():
        locked = getattr(u, "membership_price_locked", None)
        price = float(locked) if locked else (15.0 if getattr(u, "is_founding_member", False) else 20.0)
        mrr_total += price
        if getattr(u, "is_founding_member", False):
            founders_mrr += price
        else:
            partners_mrr += price

    return JSONResponse({
        "summary": {
            "total_registered": total,
            "active": active,
            "inactive": inactive,
            "conversion_pct": overall_conversion_pct,
            "median_time_to_activation_hours": median_ttd_hours,
            "estimated_mrr_usd": round(mrr_total, 2),
        },
        "inactive_cohort": {
            "by_age": inactive_buckets,
            "warm_last_7d": inactive_warm_7d,
            "cold_over_30d": inactive_cold_30d,
            "interpretation": (
                "Warm cohort (last 7d) is the recoverable pool — fresh registrations "
                "still in the conversion window. Cold cohort (>30d) is mostly lost "
                "and not worth re-engaging at scale."
            ),
        },
        "activation_speed": {
            "by_bucket": activation_speed_buckets,
            "median_hours": median_ttd_hours,
            "interpretation": (
                "If the median is <48h, anyone past 7 days who hasn't activated "
                "is unlikely to convert without targeted intervention."
            ),
        },
        "top_sponsors_by_referrals": top_sponsors,
        "mrr_breakdown": {
            "total_usd": round(mrr_total, 2),
            "from_founders_usd": round(founders_mrr, 2),
            "from_partners_usd": round(partners_mrr, 2),
            "explanation": (
                "MRR = Monthly Recurring Revenue. Sum of all active members' locked "
                "monthly membership prices. Excludes one-off purchases (Grid tiers, "
                "Nexus packs, etc) and crypto/admin accounts."
            ),
        },
    })


@app.get("/admin/api/grid-distribution")
def admin_api_grid_distribution(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Read-only transition diagnostic: how many grids are open and how many
    members sit in each, bucketed by fill level and tier.

    Grounds the 36 -> 16 seat transition decision in exact numbers.
    positions_filled is the operative seat count (it drives completion).
    A grid at >= 16 would complete immediately if converted to 16-seat;
    >16 carries (positions_filled - 16) overflow seats. Pure read — no
    mutation, no model change.
    """
    if not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)

    from .database import Grid, GridPosition, GRID_TIER_NAMES, GRID_PACKAGES
    NEW_SEATS = 16

    grids = db.query(Grid).all()
    open_grids = [g for g in grids if not g.is_complete]
    complete_grids = [g for g in grids if g.is_complete]

    def bucket(n):
        if n < NEW_SEATS:  return "under_16"
        if n == NEW_SEATS: return "at_16"
        if n < 36:         return "over_16_to_35"
        return "36_or_more_anomaly"

    # Live ledger truth per grid. positions_filled is a denormalised counter
    # and can drift above reality (e.g. a deleted account's GridPosition rows
    # are gone but the increments it made on upline grids were never rolled
    # back). Base the real analysis on actual placement rows; report the
    # counter + drift alongside so we can see the bug's footprint.
    from sqlalchemy import func as _f
    pos_counts = dict(
        db.query(GridPosition.grid_id, _f.count(GridPosition.id))
          .group_by(GridPosition.grid_id).all()
    )

    by_tier = {}
    past16 = []                # REAL placements >= 16 (the truth that matters)
    past16_by_counter = 0      # counter alone says >= 16 (for contrast)
    total_accrued_past16 = 0.0
    total_overflow_seats = 0
    drift_open = 0
    for g in open_grids:
        pf = int(g.positions_filled or 0)
        actual = int(pos_counts.get(g.id, 0))
        drift_open += (pf - actual)
        tier = g.package_tier
        t = by_tier.setdefault(tier, {
            "tier": tier, "name": GRID_TIER_NAMES.get(tier, "?"),
            "price": float(GRID_PACKAGES.get(tier, 0)),
            "open_grids": 0,
            "members_placed_actual": 0, "members_placed_counter": 0,
            "buckets_by_actual": {"under_16": 0, "at_16": 0, "over_16_to_35": 0, "36_or_more_anomaly": 0},
            "grids_really_past_16": 0, "accrued_in_those": 0.0,
        })
        t["open_grids"] += 1
        t["members_placed_actual"] += actual
        t["members_placed_counter"] += pf
        t["buckets_by_actual"][bucket(actual)] += 1
        if pf >= NEW_SEATS:
            past16_by_counter += 1
        if actual >= NEW_SEATS:
            acc = float(g.bonus_pool_accrued or 0)
            t["grids_really_past_16"] += 1
            t["accrued_in_those"] += acc
            total_accrued_past16 += acc
            total_overflow_seats += max(0, actual - NEW_SEATS)
            past16.append({
                "grid_id": g.id, "owner_id": g.owner_id, "tier": tier,
                "advance": g.advance_number,
                "positions_filled_counter": pf,
                "actual_placements": actual,
                "counter_drift": pf - actual,
                "overflow_over_16_real": max(0, actual - NEW_SEATS),
                "accrued": round(acc, 2),
            })

    for t in by_tier.values():
        t["accrued_in_those"] = round(t["accrued_in_those"], 2)

    drift_complete = sum(int(g.positions_filled or 0) - int(pos_counts.get(g.id, 0)) for g in complete_grids)
    open_actual = [int(pos_counts.get(g.id, 0)) for g in open_grids]
    counter_sum = sum(int(g.positions_filled or 0) for g in grids)
    actual_positions = db.query(GridPosition).count()

    return JSONResponse({
        "summary": {
            "total_grids": len(grids),
            "open_grids": len(open_grids),
            "complete_grids": len(complete_grids),
            "grids_REALLY_past_16_by_actual_placements": len(past16),
            "grids_past_16_by_counter_only": past16_by_counter,
            "total_overflow_seats_over_16_real": total_overflow_seats,
            "total_accrued_in_real_past16_grids": round(total_accrued_past16, 2),
            "avg_real_members_per_open_grid": round(sum(open_actual) / len(open_actual), 1) if open_actual else 0,
            "max_real_members_in_an_open_grid": max(open_actual) if open_actual else 0,
            "counter_integrity": {
                "sum_positions_filled": counter_sum,
                "actual_gridposition_rows": int(actual_positions),
                "total_drift": counter_sum - int(actual_positions),
                "drift_in_open_grids": drift_open,
                "drift_in_complete_grids": drift_complete,
            },
        },
        "by_tier": sorted(by_tier.values(), key=lambda x: x["tier"]),
        "grids_really_past_16": sorted(past16, key=lambda x: (-x["actual_placements"], x["tier"])),
    })


@app.get("/admin/api/user-fulfillment")
def admin_api_user_fulfillment(
    request: Request,
    user_id: int,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Admin diagnostic: PROVE exactly what a member did or didn't receive.

    Read-only. Given a user_id, reports the definitive fulfillment state by
    querying the source-of-truth tables directly — the answer to 'they were
    charged, but did they get the product?'

    Returns, for the user:
      grid_positions:        every GridPosition row (Campaign Tier placements)
      credit_pack_purchases: every CreditPackPurchase row (Nexus packs) with
                             pack_key/price/payment_ref/status
      superscene_credit_balance: raw SuperSceneCredit.balance (NOTE: may
                             include a 500-credit launch/founder SEED that is
                             NOT from any pack purchase — see boot migration
                             in database.py ~line 4048. So a non-zero balance
                             does NOT prove a pack was delivered; the
                             credit_pack_purchases list is the real proof.)
      recorded_payments:     Payment rows (what our ledger thinks it received)
      grid_commissions_from: Commissions FROM this user (would exist if a Grid
                             placement fired upline payouts — their absence is
                             corroborating proof no Grid purchase completed)

    Built 28 May 2026 after the Daniela/cashflow (user 350) case: two $20
    Stripe charges (campaign_tier + nexus_pack) SUCCEEDED at Stripe but left
    NO trace in our ledger — and no existing monitoring tool could read grid
    or credit state to confirm what she did/didn't receive. This endpoint
    closes that gap. Keep it long term.
    """
    _require_admin(user)
    from .database import (
        GridPosition, CreditPackPurchase, SuperSceneCredit, Payment, Commission, User as _User,
    )

    target = db.query(_User).filter(_User.id == user_id).first()
    if not target:
        return JSONResponse({"error": f"User {user_id} not found"}, status_code=404)

    # ── Grid positions (Campaign Tier placements) ──
    gpos = db.query(GridPosition).filter(GridPosition.member_id == user_id).all()
    grid_positions = [{
        "id": g.id, "grid_id": g.grid_id, "grid_level": g.grid_level,
        "position_num": g.position_num, "is_overspill": bool(g.is_overspill),
        "created_at": g.created_at.isoformat() if g.created_at else None,
    } for g in gpos]

    # ── Credit pack purchases (Nexus) ──
    packs = db.query(CreditPackPurchase).filter(CreditPackPurchase.user_id == user_id).all()
    credit_pack_purchases = [{
        "id": p.id, "pack_key": p.pack_key, "pack_price": float(p.pack_price),
        "credits_awarded": p.credits_awarded, "payment_method": p.payment_method,
        "payment_ref": p.payment_ref, "status": p.status,
        "created_at": p.created_at.isoformat() if p.created_at else None,
    } for p in packs]

    # ── Creative Studio credit balance (may include free seed — see docstring) ──
    ssc = db.query(SuperSceneCredit).filter(SuperSceneCredit.user_id == user_id).first()
    superscene_credit_balance = int(ssc.balance) if ssc else 0

    # ── Recorded payments (our ledger) ──
    pays = db.query(Payment).filter(Payment.from_user_id == user_id).order_by(Payment.created_at.desc()).all()
    recorded_payments = [{
        "id": p.id, "payment_type": getattr(p, "payment_type", None),
        "amount": float(getattr(p, "amount_usdt", 0) or 0),
        "status": p.status, "tx_hash": getattr(p, "tx_hash", None),
        "created_at": p.created_at.isoformat() if p.created_at else None,
    } for p in pays]

    # ── Commissions originating FROM this user (Grid/matrix payouts to upline) ──
    coms = db.query(Commission).filter(Commission.from_user_id == user_id).all()
    grid_commissions_from = [{
        "id": c.id, "to_user_id": c.to_user_id, "type": c.commission_type,
        "amount": float(c.amount_usdt or 0), "package_tier": c.package_tier,
        "status": c.status,
    } for c in coms]

    return JSONResponse({
        "user_id": user_id,
        "username": target.username,
        "email": target.email,
        "summary": {
            "has_grid_position": len(grid_positions) > 0,
            "has_credit_pack_purchase": len(credit_pack_purchases) > 0,
            "superscene_credit_balance": superscene_credit_balance,
            "recorded_payment_count": len(recorded_payments),
            "commissions_fired_from_user": len(grid_commissions_from),
        },
        "grid_positions": grid_positions,
        "credit_pack_purchases": credit_pack_purchases,
        "superscene_credit_balance": superscene_credit_balance,
        "recorded_payments": recorded_payments,
        "grid_commissions_from": grid_commissions_from,
    })


@app.get("/admin/api/gift-activation-check")
def admin_api_gift_activation_check(
    request: Request,
    user_ids: str,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Wipe-recovery: was a member activated via a CLAIMED gift voucher?

    The Free Gifting (Pay It Forward) system is the one off-rail activation
    route that IS recorded in our own DB — a GiftVoucher row with
    claimed_by_user_id set. lookup_user and user-fulfillment are both blind
    to gifts a member RECEIVED (they only see what a member bought/owns), so
    this endpoint closes that gap directly.

    For each user_id, returns every gift_voucher CLAIMED BY that user, with
    who gifted it, what it was (membership/tier), its dollar value, whether
    the gift was free (is_free_voucher) or paid-for (payment_method), and
    when it was claimed. An empty list RULES OUT the gift route for that
    member (so the remaining explanation is bank transfer / off-coin
    NOWPayments / genuine comp). Read-only.
    """
    _require_admin(user)
    from .database import GiftVoucher, User as _User

    try:
        ids = [int(x) for x in user_ids.split(",") if x.strip()]
    except ValueError:
        return JSONResponse({"error": "user_ids must be comma-separated integers"}, status_code=400)

    out = {}
    for uid in ids:
        target = db.query(_User).filter(_User.id == uid).first()
        if not target:
            out[uid] = {"error": "user not found"}
            continue
        vouchers = (
            db.query(GiftVoucher)
            .filter(GiftVoucher.claimed_by_user_id == uid)
            .order_by(GiftVoucher.claimed_at.desc())
            .all()
        )
        rows = []
        for v in vouchers:
            gifter = db.query(_User).filter(_User.id == v.gifter_user_id).first()
            rows.append({
                "voucher_id": v.id,
                "voucher_code": v.voucher_code,
                "gifter_user_id": v.gifter_user_id,
                "gifter_username": gifter.username if gifter else None,
                "gift_type": v.gift_type,
                "gift_value": float(v.gift_value) if v.gift_value is not None else None,
                "tier_num": v.tier_num,
                "is_free_voucher": bool(v.is_free_voucher),
                "payment_method": v.payment_method,
                "payment_ref": v.payment_ref,
                "status": v.status,
                "claimed_at": v.claimed_at.isoformat() if v.claimed_at else None,
                "created_at": v.created_at.isoformat() if v.created_at else None,
            })
        out[uid] = {
            "username": target.username,
            "email": target.email,
            "activated_at": target.activated_at.isoformat() if getattr(target, "activated_at", None) else None,
            "gift_activated": len(rows) > 0,
            "claimed_vouchers": rows,
        }

    return JSONResponse({"results": out})


@app.get("/admin/api/gateway-forensics")
def admin_api_gateway_forensics(
    request: Request,
    user_ids: str,
    np_days: int = 90,
    max_seconds: int = 70,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Wipe-recovery: find a member's payment in the GATEWAYS' OWN live APIs.

    Our mirror tables (stripe_charges, nowpayments_orders, walletconnect_*)
    were wiped 3 Jun; the gateways' APIs are the source of truth that
    survived. For each user_id this reports, side by side:
      db_mirror:   what our tables currently hold (StripeCharge / NowPayments /
                   WalletConnect / Payment rows for that user)
      stripe_live: Stripe Customer.list(email) -> Charge.list per customer
                   (catches card payments even if the wiped mirror lost them
                   or the charge wasn't attributed to the uid)
      nowpayments_live: payments whose order_id is SAP-<uid>, found by a full
                   paginated sweep of GET /v1/payment over the last np_days
                   (the backfill only processed hand-supplied ids, so any-coin
                   / mis-exported payments — like the worksmarter ETH case —
                   were never seen). Coin-agnostic, status-agnostic.

    Also returns np_sweep: every distinct SAP uid seen in the NOWPayments
    sweep, so other gap members who paid via NOWPayments surface in one pass.

    READ-ONLY. No writes, no 2FA. Pure forensic read of live APIs + our DB.
    """
    _require_admin(user)
    import re as _re, time as _time, httpx as _httpx
    from datetime import datetime as _dt, timedelta as _td
    from .database import (StripeCharge as _SC, NowPaymentsOrder as _NP,
                           WalletConnectPaymentOrder as _WC, Payment as _P, User as _U)

    try:
        ids = [int(x) for x in user_ids.split(",") if x.strip()]
    except ValueError:
        return JSONResponse({"error": "user_ids must be comma-separated integers"}, status_code=400)

    # ── NOWPayments live sweep (once, bucketed by uid) ──
    # The list-payments endpoint is PRIVATE: it needs a JWT bearer token from
    # POST /v1/auth (dashboard email+password), NOT the x-api-key. So we JWT
    # if NOWPAYMENTS_EMAIL/PASSWORD are present, else fall back to the key and
    # surface whatever status the API returns (never silently report zero).
    import os as _os
    np_by_uid, np_uids_seen, np_total, np_pages, np_err = {}, set(), 0, 0, None
    np_auth_mode = "none"
    try:
        from . import nowpayments_service as _nps
        if not _nps.is_configured():
            np_err = "nowpayments not configured in env"
        else:
            base = _nps.NOWPAYMENTS_API_BASE
            auth_headers = dict(_nps._api_headers())  # x-api-key
            np_auth_mode = "x-api-key"
            np_email = _os.environ.get("NOWPAYMENTS_EMAIL", "")
            np_pass = _os.environ.get("NOWPAYMENTS_PASSWORD", "")
            if np_email and np_pass:
                try:
                    ar = _httpx.post(f"{base}/auth",
                                     json={"email": np_email, "password": np_pass}, timeout=15)
                    if ar.status_code == 200 and (ar.json() or {}).get("token"):
                        auth_headers["Authorization"] = f"Bearer {ar.json()['token']}"
                        np_auth_mode = "jwt"
                    else:
                        np_err = f"auth http {ar.status_code}: {str(ar.text)[:100]}"
                except Exception as e:
                    np_err = f"auth exception {type(e).__name__}: {str(e)[:80]}"
            date_from = (_dt.utcnow() - _td(days=np_days)).strftime("%Y-%m-%d")
            date_to = (_dt.utcnow() + _td(days=1)).strftime("%Y-%m-%d")
            page = 0
            _t0 = _time.time()
            while np_err is None:
                if _time.time() - _t0 > max_seconds:
                    np_err = "time_budget_hit_partial_sweep"
                    break
                r = _httpx.get(
                    f"{base}/payment/?limit=500&page={page}"
                    f"&dateFrom={date_from}&dateTo={date_to}&sortBy=created_at&orderBy=asc",
                    headers=auth_headers, timeout=20,
                )
                if r.status_code != 200:
                    np_err = f"list http {r.status_code} (auth={np_auth_mode}): {str(r.text)[:120]}"
                    break
                j = r.json()
                rows = j.get("data") or []
                if not rows:
                    break
                np_pages += 1
                for p in rows:
                    np_total += 1
                    oid = str(p.get("order_id") or "")
                    m = _re.match(r"SAP-(\d+)", oid)
                    if not m:
                        continue
                    uid = int(m.group(1))
                    np_uids_seen.add(uid)
                    if uid in ids:
                        np_by_uid.setdefault(uid, []).append({
                            "payment_id": p.get("payment_id"),
                            "status": p.get("payment_status"),
                            "order_id": oid,
                            "order_description": p.get("order_description"),
                            "price_amount": p.get("price_amount"),
                            "price_currency": p.get("price_currency"),
                            "pay_currency": p.get("pay_currency"),
                            "actually_paid": p.get("actually_paid"),
                            "outcome_amount": p.get("outcome_amount"),
                            "created_at": p.get("created_at"),
                        })
                pages_count = j.get("pagesCount") or j.get("pages_count") or 1
                page += 1
                if page >= int(pages_count):
                    break
    except Exception as e:
        np_err = f"{type(e).__name__}: {str(e)[:80]}"

    # ── Per-user report ──
    out = {}
    for uid in ids:
        t = db.query(_U).filter(_U.id == uid).first()
        if not t:
            out[uid] = {"error": "user not found"}
            continue

        # our mirror tables
        sc = db.query(_SC).filter(_SC.user_id == uid).all()
        npo = db.query(_NP).filter(_NP.user_id == uid).all()
        wc = db.query(_WC).filter(_WC.user_id == uid).all()
        pay = db.query(_P).filter(_P.from_user_id == uid).all()
        db_mirror = {
            "stripe_charges": [{"charge_id": r.stripe_charge_id, "product": r.product,
                                "amount_cents": r.amount_cents, "kind": r.kind,
                                "created_at": r.created_at.isoformat() if r.created_at else None}
                               for r in sc],
            "nowpayments_orders": [{"id": r.id, "np_payment_id": r.np_payment_id,
                                    "product_key": r.product_key, "price_usd": float(r.price_usd or 0),
                                    "pay_currency": r.pay_currency, "status": r.status,
                                    "internal_order_id": r.internal_order_id} for r in npo],
            "walletconnect_orders": [{"id": r.id, "product_key": r.product_key,
                                      "unique_amount": float(r.unique_amount or 0), "status": r.status,
                                      "tx_hash": r.tx_hash} for r in wc],
            "payments": [{"id": r.id, "type": getattr(r, "payment_type", None),
                          "amount": float(getattr(r, "amount_usdt", 0) or 0),
                          "status": r.status, "tx_hash": getattr(r, "tx_hash", None)} for r in pay],
        }

        # stripe live by email
        stripe_live, stripe_err = [], None
        try:
            from . import stripe_service as _ss
            if not _ss.is_configured():
                stripe_err = "stripe not configured in env"
            else:
                _ss._ensure_sdk()
                import stripe as _stripe
                custs = _stripe.Customer.list(email=t.email, limit=10)
                for c in custs.data:
                    chs = _stripe.Charge.list(customer=c.id, limit=25)
                    for ch in chs.data:
                        stripe_live.append({
                            "charge_id": ch.id,
                            "customer_id": c.id,
                            "amount": (ch.amount or 0) / 100.0,
                            "currency": ch.currency,
                            "paid": bool(getattr(ch, "paid", False)),
                            "status": getattr(ch, "status", None),
                            "refunded": bool(getattr(ch, "refunded", False)),
                            "description": getattr(ch, "description", None),
                            "created": _dt.utcfromtimestamp(ch.created).isoformat() if getattr(ch, "created", None) else None,
                        })
        except Exception as e:
            stripe_err = f"{type(e).__name__}: {str(e)[:80]}"

        out[uid] = {
            "username": t.username,
            "email": t.email,
            "activated_at": t.activated_at.isoformat() if getattr(t, "activated_at", None) else None,
            "price_locked": float(t.membership_price_locked) if getattr(t, "membership_price_locked", None) else None,
            "db_mirror": db_mirror,
            "stripe_live": stripe_live,
            "stripe_error": stripe_err,
            "nowpayments_live": np_by_uid.get(uid, []),
            "verdict": (
                "STRIPE" if stripe_live else
                "NOWPAYMENTS" if np_by_uid.get(uid) else
                "no gateway record found (live)"
            ),
        }

    return JSONResponse({
        "results": out,
        "np_sweep": {
            "payments_seen": np_total,
            "pages_read": np_pages,
            "auth_mode": np_auth_mode,
            "distinct_uids_seen": sorted(np_uids_seen),
            "error": np_err,
        },
    })


@app.get("/admin/api/record-offrail-payment")
def admin_api_record_offrail_payment(
    request: Request,
    entries: str,
    apply: int = 0,
    code: str = "",
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Record-only audit rows for members who paid through a channel our rails
    don't auto-capture (bank transfer, off-coin NOWPayments) and were manually
    activated. Writes a Payment row tagged with the channel so the books read
    PAID, not comped.

    NO commissions, NO balances, NO entitlements — purely a ledger record of
    money that already arrived off-rail. Idempotent: each row gets a
    deterministic synthetic tx_hash OFFRAIL-<CHANNEL>-<uid>, so re-running
    skips anything already written.

    entries: comma-separated  uid:amount:channel[:date]
      e.g. 179:15:bank_transfer:2026-05-13,228:15:bank_transfer:2026-05-16
      date optional — falls back to the member's activated_at.

    apply=0 dry run (default). apply=1 requires ?code=NNNNNN (2FA).
    """
    _require_admin(user)
    import pyotp
    from datetime import datetime as _dt
    from .database import Payment as _P, User as _U

    parsed, errors = [], []
    for raw in (entries or "").split(","):
        raw = raw.strip()
        if not raw:
            continue
        parts = raw.split(":")
        if len(parts) < 3:
            errors.append({"entry": raw, "error": "expected uid:amount:channel[:date]"}); continue
        try:
            uid = int(parts[0]); amount = float(parts[1])
        except ValueError:
            errors.append({"entry": raw, "error": "uid/amount not numeric"}); continue
        channel = parts[2].strip().lower()
        date_str = parts[3].strip() if len(parts) >= 4 and parts[3].strip() else None
        parsed.append((uid, amount, channel, date_str, raw))

    will_apply = False
    if apply == 1:
        sec = getattr(user, "totp_secret", None)
        if not sec or not code or not pyotp.TOTP(sec).verify(code, valid_window=1):
            return JSONResponse({"error": "2FA required/invalid for apply"}, status_code=403)
        will_apply = True

    plan, written = [], 0
    for (uid, amount, channel, date_str, raw) in parsed:
        t = db.query(_U).filter(_U.id == uid).first()
        if not t:
            errors.append({"entry": raw, "error": "user not found"}); continue
        created = None
        if date_str:
            for fmt in ("%Y-%m-%dT%H:%M:%S", "%Y-%m-%d"):
                try:
                    created = _dt.strptime(date_str, fmt); break
                except ValueError:
                    pass
            if created is None:
                errors.append({"entry": raw, "error": f"bad date '{date_str}'"}); continue
        else:
            created = getattr(t, "activated_at", None) or _dt.utcnow()

        tx = f"OFFRAIL-{channel.upper()}-{uid}"
        existing = db.query(_P).filter(_P.tx_hash == tx).first()
        any_pay = db.query(_P).filter(_P.from_user_id == uid).count()
        row = {
            "user_id": uid, "username": t.username, "amount": amount,
            "channel": channel, "tx_hash": tx, "created_at": created.isoformat(),
            "already_recorded": existing is not None,
            "user_existing_payment_rows": any_pay,
        }
        if existing is not None:
            row["action"] = "skip (already present)"
        elif will_apply:
            db.add(_P(from_user_id=uid, to_user_id=None, amount_usdt=amount,
                      payment_type=channel, tx_hash=tx, status="confirmed",
                      created_at=created))
            written += 1
            row["action"] = "WRITTEN"
        else:
            row["action"] = "would write (dry run)"
        plan.append(row)

    if will_apply and written:
        db.commit()

    return JSONResponse({
        "mode": "APPLIED" if will_apply else "dry_run",
        "rows_written": written if will_apply else 0,
        "plan": plan,
        "errors": errors,
    })


@app.get("/admin/api/purchase-source-census")
def admin_api_purchase_source_census(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Wipe-recovery scoping: count every PURCHASE-REFERENCE source platform-wide
    so we know where recoverable tier/credit purchases actually live. For each
    surviving source, breaks down by product and gives the date range (which
    reveals the wipe boundary). Read-only; each source wrapped independently."""
    _require_admin(user)
    from sqlalchemy import func as _f
    from .database import (StripeCharge, WalletConnectPaymentOrder, NowPaymentsOrder,
                           Payment, Grid, GridPosition, SuperSceneCredit, Commission)
    out = {}

    def _census(label, model, group_col=None, status_col=None, date_col=None):
        try:
            total = db.query(_f.count()).select_from(model).scalar() or 0
            info = {"total_rows": total}
            if date_col is not None:
                mn = db.query(_f.min(date_col)).scalar()
                mx = db.query(_f.max(date_col)).scalar()
                info["oldest"] = mn.isoformat() if mn else None
                info["newest"] = mx.isoformat() if mx else None
            if group_col is not None:
                rows = db.query(group_col, _f.count()).group_by(group_col).all()
                info["by_product"] = {str(k): v for k, v in rows}
            if status_col is not None:
                rows = db.query(status_col, _f.count()).group_by(status_col).all()
                info["by_status"] = {str(k): v for k, v in rows}
            out[label] = info
        except Exception as e:
            out[label] = f"ERR {type(e).__name__}: {str(e)[:120]}"

    _census("stripe_charges", StripeCharge, group_col=StripeCharge.product, date_col=StripeCharge.created_at)
    _census("walletconnect_orders", WalletConnectPaymentOrder,
            group_col=WalletConnectPaymentOrder.product_type,
            status_col=WalletConnectPaymentOrder.status,
            date_col=WalletConnectPaymentOrder.created_at)
    _census("nowpayments_orders", NowPaymentsOrder,
            group_col=NowPaymentsOrder.product_type,
            status_col=NowPaymentsOrder.status,
            date_col=NowPaymentsOrder.created_at)
    _census("payments", Payment, group_col=Payment.payment_type, date_col=Payment.created_at)
    _census("grids", Grid, date_col=Grid.created_at)
    _census("grid_positions", GridPosition, date_col=GridPosition.created_at)
    _census("commissions", Commission, group_col=Commission.commission_type, date_col=Commission.created_at)

    # Legacy Polygon rail (retired) — may still hold 264-era purchase refs.
    try:
        from .database import CryptoPaymentOrder
        _census("crypto_orders_legacy_polygon", CryptoPaymentOrder, date_col=CryptoPaymentOrder.created_at)
    except Exception as e:
        out["crypto_orders_legacy_polygon"] = f"ERR {type(e).__name__}"

    # Creator-credit state
    try:
        rows = db.query(SuperSceneCredit).count()
        bal = db.query(_f.coalesce(_f.sum(SuperSceneCredit.balance), 0)).scalar() or 0
        nonzero = db.query(_f.count()).select_from(SuperSceneCredit).filter(SuperSceneCredit.balance > 0).scalar() or 0
        out["superscene_credits"] = {"rows": rows, "sum_balance": int(bal), "rows_with_balance": nonzero}
    except Exception as e:
        out["superscene_credits"] = f"ERR {type(e).__name__}"

    out["note"] = ("Where confirmed grid/campaign_tier and superscene/creative_credits "
                   "purchases appear with a sensible date range = the recoverable source. "
                   "An empty/short-range table = wiped (fall back to on-chain).")
    return JSONResponse(out)


@app.get("/admin/api/stripe-tier-credit-recovery")
def admin_api_stripe_tier_credit_recovery(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Phase 1 of tier/credit recovery: enumerate LIVE Stripe charges and read
    each one's metadata (product_kind / campaign_tier_id / superadpro_user_id —
    set at checkout via payment_intent_data, so it lands on the charge). Live
    API, not the 1-row local mirror, so webhook-missed charges are caught.

    Reports, for every PAID non-refunded charge, the exact (user, product, tier)
    it bought, then cross-checks current state (active grid? credit balance?) so
    we see precisely which Stripe-paid entitlements need restoring. Read-only."""
    _require_admin(user)
    from .database import Grid, SuperSceneCredit, User as _User
    try:
        from . import stripe_service as _ss
        if not _ss.is_configured():
            return JSONResponse({"error": "stripe not configured in env"}, status_code=200)
        _ss._ensure_sdk()
        import stripe as _stripe
        import time as _time
    except Exception as e:
        return JSONResponse({"error": f"stripe init failed: {type(e).__name__}"}, status_code=200)

    _t0 = _time.time()
    by_kind = {}
    tier_purchases, credit_purchases = [], []
    scanned, charges_read, hit_cap = 0, 0, False
    params = {"limit": 100, "type": "charge"}
    try:
        while True:
            if _time.time() - _t0 > 40:
                hit_cap = True
                break
            page = _stripe.BalanceTransaction.list(**params)
            for bt in page.data:
                scanned += 1
                src = getattr(bt, "source", None)
                if not src or not str(src).startswith("ch_"):
                    continue
                try:
                    ch = _stripe.Charge.retrieve(src)
                except Exception:
                    continue
                charges_read += 1
                md = (ch.metadata.to_dict() if getattr(ch, "metadata", None) else {})
                pk = md.get("product_kind") or "unknown"
                paid = bool(getattr(ch, "paid", False)) and getattr(ch, "status", "") == "succeeded"
                refunded = bool(getattr(ch, "refunded", False))
                by_kind[pk] = by_kind.get(pk, 0) + 1
                if not paid or refunded:
                    continue
                try:
                    uid = int(md.get("superadpro_user_id") or 0)
                except (TypeError, ValueError):
                    uid = 0
                amt = (ch.amount or 0) / 100.0
                created = ch.created
                if pk == "campaign_tier":
                    tier_purchases.append({"user_id": uid, "tier_id": md.get("campaign_tier_id"),
                                           "amount_usd": amt, "charge_id": ch.id, "created_ts": created})
                elif pk in ("creative_credits", "superscene", "nexus_pack"):
                    credit_purchases.append({"user_id": uid, "product_kind": pk,
                                             "pack": md.get("pack_key") or md.get("credit_pack"),
                                             "amount_usd": amt, "charge_id": ch.id, "created_ts": created})
            if getattr(page, "has_more", False) and page.data:
                params["starting_after"] = page.data[-1].id
            else:
                break
    except Exception as e:
        return JSONResponse({"stripe_enum_error": f"{type(e).__name__}: {str(e)[:200]}",
                             "balance_txns_scanned": scanned, "charges_read": charges_read,
                             "by_kind": by_kind}, status_code=200)

    # Cross-check current state for each Stripe-paid tier buyer.
    def _state(uid):
        if not uid:
            return {"valid_user": False}
        u = db.query(_User.id, _User.username, _User.is_active).filter(_User.id == uid).first()
        if not u:
            return {"valid_user": False}
        grids_inc = db.query(Grid).filter(Grid.owner_id == uid, Grid.is_complete == False).count()
        ssc = db.query(SuperSceneCredit).filter(SuperSceneCredit.user_id == uid).first()
        return {"valid_user": True, "username": u.username, "is_active": bool(u.is_active),
                "grids_incomplete_now": grids_inc,
                "credit_balance_now": int(ssc.balance) if ssc else 0}

    for t in tier_purchases:
        t.update(_state(t["user_id"]))
        t["needs_grid_restore"] = bool(t.get("valid_user") and t.get("grids_incomplete_now", 0) == 0)
    for c in credit_purchases:
        c.update(_state(c["user_id"]))

    return JSONResponse({
        "balance_txns_scanned": scanned,
        "charges_read": charges_read,
        "hit_time_cap": hit_cap,
        "charges_by_product_kind": by_kind,
        "campaign_tier_purchases_paid": tier_purchases,
        "tier_buyers_needing_grid_restore": sum(1 for t in tier_purchases if t.get("needs_grid_restore")),
        "credit_purchases_paid": credit_purchases,
        "note": ("Stripe-paid tiers/credits with exact user+tier from charge metadata. "
                 "needs_grid_restore=true means they paid via Stripe but have no active "
                 "grid now (wiped). Crypto-paid purchases are NOT here — those come from "
                 "the on-chain pass. Read-only; nothing restored yet."),
    })


def _run_reconciliation(db, max_seconds: int = 55, charge_cursor: str = ""):
    """Core cross-rail reconciliation. Settled-money truth (Stripe API +
    confirmed crypto orders + on-chain orphans) vs the internal DB mirror.
    Read-only — performs NO writes. Returns a dict. Factored out so a cron
    can reuse it. See /admin/api/reconcile for the HTTP surface."""
    from .database import (User as _U, StripeCharge, WalletConnectPaymentOrder,
                           NowPaymentsOrder, OnchainOrphanTransfer)
    from sqlalchemy import func as _f
    from datetime import datetime as _dt
    import time as _time

    rep = {"generated_at": _dt.utcnow().isoformat(), "read_only": True}

    # ── A. Internal mirror snapshot (what the DB currently believes) ──
    local_charge_ids = {r[0] for r in db.query(StripeCharge.stripe_charge_id)
                        .filter(StripeCharge.kind == "charge",
                                StripeCharge.stripe_charge_id.isnot(None)).all()}
    rep["internal_mirror"] = {
        "stripe_charge_rows": len(local_charge_ids),
        "wc_confirmed_rows": db.query(_f.count(WalletConnectPaymentOrder.id))
            .filter(WalletConnectPaymentOrder.status == "confirmed").scalar() or 0,
        "np_confirmed_rows": db.query(_f.count(NowPaymentsOrder.id))
            .filter(NowPaymentsOrder.status.in_(["confirmed", "finished"])).scalar() or 0,
    }

    # ── B. Crypto truth (confirmed orders, straight from DB) ──
    def _order_summary(rows, amount_attr):
        total = 0.0
        users = set()
        by_product = {}
        for r in rows:
            amt = float(getattr(r, amount_attr, 0) or 0)
            total += amt
            if r.user_id:
                users.add(r.user_id)
            pk = getattr(r, "product_type", None) or "unknown"
            by_product[pk] = round(by_product.get(pk, 0.0) + amt, 2)
        return {"count": len(rows), "usd": round(total, 2),
                "distinct_users": len(users), "by_product": by_product}

    rep["walletconnect"] = _order_summary(
        db.query(WalletConnectPaymentOrder).filter(
            WalletConnectPaymentOrder.status == "confirmed").all(), "base_amount")
    rep["nowpayments"] = _order_summary(
        db.query(NowPaymentsOrder).filter(
            NowPaymentsOrder.status.in_(["confirmed", "finished"])).all(), "price_usd")

    # ── C. On-chain orphans (USDT that arrived but matched no order) ──
    orphans = db.query(OnchainOrphanTransfer).filter(
        OnchainOrphanTransfer.resolved == False).all()  # noqa: E712
    rep["orphan_transfers"] = {
        "unresolved_count": len(orphans),
        "unresolved_usd": round(sum(float(o.amount_usdt or 0) for o in orphans), 2),
        "sample": [{"tx_hash": o.tx_hash, "from_address": o.from_address,
                    "usd": float(o.amount_usdt or 0),
                    "likely_rounded": bool(o.likely_rounded_amount)}
                   for o in orphans[:15]],
    }

    # ── D. Stripe truth (LIVE API — catches webhook-missed charges) ──
    stripe_rep = {"configured": False}
    try:
        from . import stripe_service as _ss
        if not _ss.is_configured():
            stripe_rep = {"configured": False,
                          "note": ("Stripe not configured in this environment "
                                   "(STRIPE_SECRET_KEY / price IDs missing). Run from a "
                                   "deploy that holds the key — the live app does.")}
        else:
            _ss._ensure_sdk()
            import stripe as _stripe

            # D1. Subscriptions = recurring paying members (fast, authoritative)
            sub_total = 0
            sub_by_status = {}
            sub_by_price = {}
            active_customers = set()
            sub_capped = False
            sparams = {"status": "all", "limit": 100}
            t_sub = _time.time()
            while True:
                if _time.time() - t_sub > 20:
                    sub_capped = True
                    break
                spage = _stripe.Subscription.list(**sparams)
                for s in spage.data:
                    sub_total += 1
                    st = getattr(s, "status", "unknown")
                    sub_by_status[st] = sub_by_status.get(st, 0) + 1
                    if st in ("active", "trialing", "past_due"):
                        cust = getattr(s, "customer", None)
                        if cust:
                            active_customers.add(cust)
                        try:
                            items = getattr(s, "items", None)
                            pid = items.data[0].price.id if (items and items.data) else "unknown"
                        except Exception:
                            pid = "unknown"
                        sub_by_price[pid] = sub_by_price.get(pid, 0) + 1
                if getattr(spage, "has_more", False) and spage.data:
                    sparams["starting_after"] = spage.data[-1].id
                else:
                    break
            matched_sub_users = 0
            if active_customers:
                matched_sub_users = db.query(_f.count(_U.id)).filter(
                    _U.stripe_customer_id.in_(list(active_customers))).scalar() or 0

            # D2. Walk charges → revenue by product, distinct buyers, recording gap
            by_kind = {}
            rev_by_kind = {}
            paying_users = set()
            scanned = charges_read = 0
            missing_sample = []
            missing_usd = 0.0
            cap_hit = False
            resume = ""
            walk_err = None
            cparams = {"limit": 100, "type": "charge"}
            if charge_cursor:
                cparams["starting_after"] = charge_cursor
            t_ch = _time.time()
            try:
                while True:
                    if _time.time() - t_ch > max_seconds:
                        cap_hit = True
                        break
                    page = _stripe.BalanceTransaction.list(**cparams)
                    for bt in page.data:
                        scanned += 1
                        src = getattr(bt, "source", None)
                        if not src or not str(src).startswith("ch_"):
                            continue
                        try:
                            ch = _stripe.Charge.retrieve(src)
                        except Exception:
                            continue
                        charges_read += 1
                        paid = bool(getattr(ch, "paid", False)) and getattr(ch, "status", "") == "succeeded"
                        if not paid or bool(getattr(ch, "refunded", False)):
                            continue
                        md = (ch.metadata.to_dict() if getattr(ch, "metadata", None) else {})
                        pk = md.get("product_kind") or "unknown"
                        amt = (ch.amount or 0) / 100.0
                        by_kind[pk] = by_kind.get(pk, 0) + 1
                        rev_by_kind[pk] = round(rev_by_kind.get(pk, 0.0) + amt, 2)
                        try:
                            uid = int(md.get("superadpro_user_id") or 0)
                        except (TypeError, ValueError):
                            uid = 0
                        if uid:
                            paying_users.add(uid)
                        if ch.id not in local_charge_ids:
                            missing_usd += amt
                            if len(missing_sample) < 25:
                                missing_sample.append({"charge_id": ch.id, "user_id": uid,
                                                       "product": pk, "usd": round(amt, 2)})
                    if getattr(page, "has_more", False) and page.data:
                        resume = page.data[-1].id
                        cparams["starting_after"] = resume
                    else:
                        resume = ""
                        break
            except Exception as e:
                walk_err = f"{type(e).__name__}: {str(e)[:200]}"

            stripe_rep = {
                "configured": True,
                "active_subscriptions": {
                    "total_subscriptions_seen": sub_total,
                    "by_status": sub_by_status,
                    "active_or_billing": sum(sub_by_status.get(k, 0)
                                             for k in ("active", "trialing", "past_due")),
                    "distinct_paying_customers": len(active_customers),
                    "matched_to_local_users": int(matched_sub_users),
                    "by_price_id": sub_by_price,
                    "scan_capped": sub_capped,
                },
                "one_time_charges": {
                    "balance_txns_scanned": scanned,
                    "charges_read": charges_read,
                    "by_product_kind": by_kind,
                    "revenue_usd_by_product": rev_by_kind,
                    "total_paid_usd": round(sum(rev_by_kind.values()), 2),
                    "distinct_paying_users": len(paying_users),
                    "time_capped": cap_hit,
                    "resume_cursor": resume if cap_hit else "",
                    "walk_error": walk_err,
                },
                "recording_gap": {
                    "paid_charges_missing_from_mirror": len(missing_sample),
                    "missing_usd_seen_so_far": round(missing_usd, 2),
                    "complete": (not cap_hit and walk_err is None),
                    "sample": missing_sample,
                    "note": ("Charges present in Stripe but absent from the local "
                             "stripe_charges table = the webhook-miss recording leak. "
                             "These are what a backfill would write. If time_capped, "
                             "re-run with charge_cursor=resume_cursor to continue."),
                },
            }
    except Exception as e:
        stripe_rep = {"configured": False, "error": f"{type(e).__name__}: {str(e)[:200]}"}
    rep["stripe"] = stripe_rep

    # ── E. Headline summary ──
    s_subs = (stripe_rep.get("active_subscriptions") or {}) if stripe_rep.get("configured") else {}
    s_charges = (stripe_rep.get("one_time_charges") or {}) if stripe_rep.get("configured") else {}
    rep["summary"] = {
        "stripe_active_paying_members": s_subs.get("active_or_billing") if stripe_rep.get("configured") else None,
        "stripe_one_time_revenue_usd": s_charges.get("total_paid_usd") if stripe_rep.get("configured") else None,
        "crypto_confirmed_revenue_usd": round(rep["walletconnect"]["usd"] + rep["nowpayments"]["usd"], 2),
        "crypto_confirmed_buyers": rep["walletconnect"]["distinct_users"] + rep["nowpayments"]["distinct_users"],
        "stripe_charges_missing_from_db_usd": (stripe_rep.get("recording_gap") or {}).get("missing_usd_seen_so_far") if stripe_rep.get("configured") else None,
        "orphan_unmatched_usd": rep["orphan_transfers"]["unresolved_usd"],
        "verdict": ("Real paying base = Stripe active_or_billing subscriptions + distinct "
                    "crypto buyers (rails may overlap; treat as upper bound until de-duped by "
                    "user_id). Recording leak = stripe_charges_missing + orphan transfers. "
                    "Crypto buyer counts are per-rail distinct, not yet de-duped across rails."),
    }
    return rep


@app.get("/admin/api/reconcile")
def admin_api_reconcile(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    max_seconds: int = 55,
    charge_cursor: str = "",
):
    """Authoritative cross-rail reconciliation (READ-ONLY, no mutations).

    Settled-money truth — Stripe live API (subscriptions + charges), confirmed
    WalletConnect/NOWPayments orders, and on-chain orphan transfers — diffed
    against the internal DB mirror. Answers, in one pass:
      • how many REAL paying members / how much REAL revenue exists, and
      • where the DB disagrees (Stripe charges that never reached stripe_charges
        = the webhook-miss leak; on-chain transfers that matched no order).

    Stripe charge-walk is time-capped (per-charge API reads are slow). If
    time_capped=true, re-run with charge_cursor=<resume_cursor> to continue.
    Nothing is written — backfill is a separate, dry-run-gated step."""
    _require_admin(user)
    try:
        return JSONResponse(_run_reconciliation(db, max_seconds=max_seconds, charge_cursor=charge_cursor))
    except Exception as e:
        return JSONResponse({"error": f"{type(e).__name__}: {str(e)[:300]}"}, status_code=200)


@app.get("/admin/api/nowpayments-enrich")
def admin_api_nowpayments_enrich(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    ids: str = "",
):
    """Resolve a batch of NOWPayments payment IDs (from the dashboard CSV export)
    to (user, product, tier) via the per-payment API, which returns the
    order_description the CSV omits. order_id encodes the user (SAP-<user>-<n>);
    order_description names the product ('Campaign Tier 1 — Starter'). Always
    echoes the raw description so the classification can be verified, not
    trusted blind. Read-only."""
    _require_admin(user)
    import re as _re, time as _time
    from .database import Grid, SuperSceneCredit, User as _User
    try:
        from . import nowpayments_service as _np
        if not _np.is_configured():
            return JSONResponse({"error": "nowpayments not configured in env"}, status_code=200)
    except Exception as e:
        return JSONResponse({"error": f"np init failed: {type(e).__name__}"}, status_code=200)

    id_list = [i.strip() for i in (ids or "").split(",") if i.strip()]
    if not id_list:
        return JSONResponse({"error": "pass ?ids=comma,separated,payment_ids"}, status_code=400)

    def _classify(desc):
        d = (desc or "").lower()
        m = _re.search(r"tier\s*(\d+)", d)
        if "campaign tier" in d or (m and "grid" in d) or m and "tier" in d and "credit" not in d and "nexus" not in d:
            return ("campaign_tier", int(m.group(1)) if m else None)
        if "superscene" in d or "creative" in d or "studio credit" in d:
            return ("creative_credits", None)
        if "nexus" in d or "credit pack" in d or "credit matrix" in d:
            return ("nexus_pack", None)
        if "founder" in d or "partner" in d or "membership" in d:
            return ("membership", None)
        return ("unknown", None)

    def _uid_from_order(oid):
        m = _re.match(r"SAP-(\d+)-", oid or "")
        return int(m.group(1)) if m else 0

    _t0 = _time.time()
    resolved, errors = [], []
    for pid in id_list:
        if _time.time() - _t0 > 50:
            errors.append({"payment_id": pid, "error": "time_budget_hit_remaining_skipped"})
            break
        try:
            data = _np.get_payment_status(pid)
        except Exception as e:
            errors.append({"payment_id": pid, "error": type(e).__name__})
            continue
        if not isinstance(data, dict) or data.get("error"):
            errors.append({"payment_id": pid, "error": str(data)[:100]})
            continue
        oid = data.get("order_id") or ""
        desc = data.get("order_description") or ""
        uid = _uid_from_order(oid)
        kind, tier = _classify(desc)
        resolved.append({
            "payment_id": pid, "order_id": oid, "user_id": uid,
            "raw_description": desc, "product_kind": kind, "tier": tier,
            "price_usd": data.get("price_amount"),
            "actually_paid": data.get("actually_paid"),
            "pay_currency": data.get("pay_currency"),
            "status": data.get("payment_status"),
        })

    # Cross-check current state per distinct user in the tier/credit set.
    uids = sorted({r["user_id"] for r in resolved
                   if r["user_id"] and r["product_kind"] in ("campaign_tier", "creative_credits", "nexus_pack")})
    state = {}
    for uid in uids:
        u = db.query(_User.id, _User.username, _User.is_active).filter(_User.id == uid).first()
        if not u:
            state[uid] = {"valid_user": False}
            continue
        grids_inc = db.query(Grid).filter(Grid.owner_id == uid, Grid.is_complete == False).count()
        ssc = db.query(SuperSceneCredit).filter(SuperSceneCredit.user_id == uid).first()
        state[uid] = {"valid_user": True, "username": u.username, "is_active": bool(u.is_active),
                      "grids_incomplete_now": grids_inc,
                      "credit_balance_now": int(ssc.balance) if ssc else 0}

    tiers = [r for r in resolved if r["product_kind"] == "campaign_tier"]
    credits = [r for r in resolved if r["product_kind"] == "creative_credits"]
    nexus = [r for r in resolved if r["product_kind"] == "nexus_pack"]
    membership = [r for r in resolved if r["product_kind"] == "membership"]
    unknown = [r for r in resolved if r["product_kind"] == "unknown"]
    return JSONResponse({
        "requested": len(id_list), "resolved": len(resolved), "errors": errors[:20],
        "summary": {"campaign_tier": len(tiers), "creative_credits": len(credits),
                    "nexus_pack": len(nexus), "membership": len(membership), "unknown": len(unknown)},
        "campaign_tier_purchases": tiers,
        "creative_credit_purchases": credits,
        "nexus_pack_purchases": nexus,
        "unknown_descriptions": unknown,
        "current_state_by_user": {str(k): v for k, v in state.items()},
        "note": ("raw_description is echoed for every row — verify the product_kind/tier "
                 "classification against it before we restore anything. membership rows "
                 "are listed only in summary (not part of tier/credit recovery)."),
    })


@app.get("/admin/api/tier-grid-restore")
def admin_api_tier_grid_restore(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    pairs: str = "",
    apply: int = 0,
    code: str = "",
):
    """Restore wiped campaign-tier grids from VERIFIED paid purchases (Stripe +
    NOWPayments). pairs = comma-separated user:tier (e.g. '264:1,264:2'). Uses
    get_or_create_active_grid, which creates ONLY the Grid row (active-tier
    state) and NEVER fires commissions — process_tier_purchase is the one that
    pays upline, and those commissions were already earned and rebuilt, so
    re-firing would double-pay. Dry-run by default; ?apply=1&code=2FA writes.
    Idempotent (skips a tier the member already has an active grid for)."""
    _require_admin(user)
    from .grid import get_or_create_active_grid
    from .database import Grid, User as _User, GRID_PACKAGES as _PKG
    import pyotp

    items = []
    for tok in (pairs or "").split(","):
        tok = tok.strip()
        if not tok or ":" not in tok:
            continue
        u, t = tok.split(":", 1)
        try:
            items.append((int(u), int(t)))
        except ValueError:
            continue
    if not items:
        return JSONResponse({"error": "pass ?pairs=user:tier,user:tier"}, status_code=400)
    items = sorted(set(items), key=lambda x: (x[0], x[1]))  # tier asc per user

    plan = []
    for uid, tier in items:
        if tier not in _PKG:
            plan.append({"user_id": uid, "tier": tier, "action": "skip_invalid_tier"})
            continue
        u = db.query(_User.id, _User.username, _User.is_active).filter(_User.id == uid).first()
        if not u:
            plan.append({"user_id": uid, "tier": tier, "action": "skip_user_gone"})
            continue
        exists = db.query(Grid).filter(Grid.owner_id == uid, Grid.package_tier == tier,
                                       Grid.is_complete == False).first()
        plan.append({"user_id": uid, "username": u.username, "tier": tier,
                     "is_active": bool(u.is_active),
                     "action": "already_has_grid" if exists else "will_create"})

    to_create = [p for p in plan if p["action"] == "will_create"]

    if not apply:
        return JSONResponse({
            "mode": "dry_run", "pairs_in": len(items),
            "will_create": len(to_create),
            "already_has_grid": sum(1 for p in plan if p["action"] == "already_has_grid"),
            "skipped": sum(1 for p in plan if str(p["action"]).startswith("skip")),
            "plan": plan,
            "note": ("Dry-run — nothing written. ?apply=1&code=YOUR_2FA to create. "
                     "Grid rows only; no commissions fired."),
        })

    if not getattr(user, "totp_secret", None):
        return JSONResponse({"error": "Admin has no 2FA configured"}, status_code=400)
    if not pyotp.TOTP(user.totp_secret).verify(code.strip(), valid_window=1):
        return JSONResponse({"error": "Invalid or missing 2FA code — pass ?code=NNNNNN"},
                            status_code=403)

    created = []
    for p in to_create:
        try:
            g = get_or_create_active_grid(db, p["user_id"], p["tier"])
            created.append({"user_id": p["user_id"], "username": p.get("username"),
                            "tier": p["tier"], "grid_id": g.id})
        except Exception as e:
            created.append({"user_id": p["user_id"], "tier": p["tier"],
                            "error": f"{type(e).__name__}: {str(e)[:120]}"})
    return JSONResponse({
        "mode": "applied",
        "created": len([c for c in created if c.get("grid_id")]),
        "errors": len([c for c in created if c.get("error")]),
        "results": created,
        "note": ("Active grids restored (no commissions fired). Tier reads active; "
                 "downline active-network counts recompute on next read (60s cache)."),
    })


@app.get("/admin/api/nexus-credit-restore")
def admin_api_nexus_credit_restore(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    pairs: str = "",
    apply: int = 0,
    code: str = "",
):
    """Restore wiped credit balances from VERIFIED paid Nexus/credit purchases.
    pairs = comma-separated user:credits (e.g. '264:100,157:350'). Adds to
    superscene_credits.balance directly (the spendable 'creator credits'
    balance) — NEVER calls purchase_credit_pack, which fires the 20% sponsor
    commission. Used-credit history was wiped so this restores GROSS purchased;
    current balance is 0 for all wiped accounts. Dry-run by default; ?apply=1&
    code=2FA writes."""
    _require_admin(user)
    from .database import SuperSceneCredit, User as _User
    import pyotp

    items = []
    for tok in (pairs or "").split(","):
        tok = tok.strip()
        if not tok or ":" not in tok:
            continue
        u, c = tok.split(":", 1)
        try:
            items.append((int(u), int(c)))
        except ValueError:
            continue
    if not items:
        return JSONResponse({"error": "pass ?pairs=user:credits,user:credits"}, status_code=400)
    items = sorted(set(items), key=lambda x: x[0])

    plan = []
    for uid, credits in items:
        u = db.query(_User.id, _User.username, _User.is_active).filter(_User.id == uid).first()
        if not u:
            plan.append({"user_id": uid, "credits": credits, "action": "skip_user_gone"})
            continue
        ssc = db.query(SuperSceneCredit).filter(SuperSceneCredit.user_id == uid).first()
        cur = int(ssc.balance) if ssc else 0
        plan.append({"user_id": uid, "username": u.username, "credits_to_add": credits,
                     "current_balance": cur, "resulting_balance": cur + credits,
                     "action": "will_restore"})

    to_do = [p for p in plan if p["action"] == "will_restore"]
    if not apply:
        return JSONResponse({
            "mode": "dry_run", "pairs_in": len(items), "will_restore": len(to_do),
            "skipped": sum(1 for p in plan if str(p["action"]).startswith("skip")),
            "total_credits_to_add": sum(p.get("credits_to_add", 0) for p in to_do),
            "plan": plan,
            "note": ("Dry-run — nothing written. ?apply=1&code=YOUR_2FA to restore. "
                     "Adds to superscene_credits.balance; no commissions fired."),
        })

    if not getattr(user, "totp_secret", None):
        return JSONResponse({"error": "Admin has no 2FA configured"}, status_code=400)
    if not pyotp.TOTP(user.totp_secret).verify(code.strip(), valid_window=1):
        return JSONResponse({"error": "Invalid or missing 2FA code — pass ?code=NNNNNN"},
                            status_code=403)

    done = []
    for p in to_do:
        uid, credits = p["user_id"], p["credits_to_add"]
        ssc = db.query(SuperSceneCredit).filter(SuperSceneCredit.user_id == uid).first()
        if ssc:
            ssc.balance = int(ssc.balance or 0) + credits
            newbal = ssc.balance
        else:
            db.add(SuperSceneCredit(user_id=uid, balance=credits))
            newbal = credits
        done.append({"user_id": uid, "username": p.get("username"),
                     "added": credits, "new_balance": newbal})
    db.commit()
    return JSONResponse({
        "mode": "applied", "restored": len(done),
        "total_credits_added": sum(d["added"] for d in done),
        "results": done,
        "note": "Credit balances restored (no commissions fired).",
    })


@app.get("/admin/api/stripe-charge-inspect")
def admin_api_stripe_charge_inspect(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    charge_id: str = "",
):
    """Retrieve one live Stripe charge and dump its full current metadata,
    description, amount and refund state — to confirm exactly what a charge was
    for (e.g. a nexus pack later converted to a campaign tier). Read-only."""
    _require_admin(user)
    from .database import User as _User
    if not charge_id:
        return JSONResponse({"error": "pass ?charge_id=ch_..."}, status_code=400)
    try:
        from . import stripe_service as _ss
        if not _ss.is_configured():
            return JSONResponse({"error": "stripe not configured"}, status_code=200)
        _ss._ensure_sdk()
        import stripe as _stripe
        ch = _stripe.Charge.retrieve(charge_id)
    except Exception as e:
        return JSONResponse({"error": f"{type(e).__name__}: {str(e)[:200]}"}, status_code=200)
    md = (ch.metadata.to_dict() if getattr(ch, "metadata", None) else {})
    uid = 0
    try:
        uid = int(md.get("superadpro_user_id") or 0)
    except (TypeError, ValueError):
        uid = 0
    uname = None
    if uid:
        u = db.query(_User.username).filter(_User.id == uid).first()
        uname = u.username if u else None
    return JSONResponse({
        "charge_id": charge_id,
        "amount_usd": (ch.amount or 0) / 100.0,
        "status": getattr(ch, "status", None),
        "paid": bool(getattr(ch, "paid", False)),
        "refunded": bool(getattr(ch, "refunded", False)),
        "amount_refunded_usd": (getattr(ch, "amount_refunded", 0) or 0) / 100.0,
        "description": getattr(ch, "description", None),
        "metadata": md,
        "resolved_user_id": uid,
        "resolved_username": uname,
        "created_ts": getattr(ch, "created", None),
    })


@app.get("/admin/api/reroute-purchase-commission")
def admin_api_reroute_purchase_commission(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    buyer_id: int = 451,
    tier: int = 1,
    apply: int = 0,
    code: str = "",
):
    """Re-route the affiliate commissions for a tier purchase that company-
    absorbed because the buyer's sponsor link was null at purchase time
    (wipe-timing artifact). Now that the chain is restored, this credits the
    commissions through the live compensation plan exactly as the purchase
    should have at the time.

    Uses the REAL engine (_pay_direct_sponsor + _pay_unilevel_chain) for both
    the preview (run inside a savepoint that's rolled back) and the apply —
    no duplicated commission logic. The original company-absorb rows are
    marked 'reversed' for ledger hygiene (they credited no balance). Idempotent
    via source_event_id. Dry-run by default; ?apply=1&code=YOUR_2FA writes.
    """
    _require_admin(user)
    from .database import (User as _U, Commission, GRID_PACKAGES as _PKG,
                           DIRECT_PCT as _D, PER_LEVEL_PCT as _L)
    from .grid import _pay_direct_sponsor, _pay_unilevel_chain
    import pyotp

    if tier not in _PKG:
        return JSONResponse({"error": f"unknown tier {tier}"}, status_code=400)
    buyer = db.query(_U).filter(_U.id == buyer_id).first()
    if not buyer:
        return JSONResponse({"error": f"buyer {buyer_id} not found"}, status_code=404)
    if not buyer.sponsor_id:
        return JSONResponse({"error": f"buyer {buyer_id} still has no sponsor — "
                             "nothing to re-route; restore the sponsor link first"},
                            status_code=400)

    price = float(_PKG[tier])
    event_id = f"reroute-{buyer_id}-grid{tier}"

    # Idempotency: refuse if a re-route for this purchase already exists
    prior = db.query(Commission).filter(Commission.source_event_id == event_id).count()
    if prior:
        return JSONResponse({"error": "already re-routed for this purchase",
                             "event_id": event_id, "existing_rows": prior},
                            status_code=409)

    # The original misrouted company-absorb rows for this buyer's purchase
    orig = db.query(Commission).filter(
        Commission.from_user_id == buyer_id,
        Commission.to_user_id.is_(None),
        Commission.status == "platform",
        Commission.commission_type.in_(["direct_sponsor", "uni_level"]),
    ).all()
    orig_view = [{"id": c.id, "type": c.commission_type, "amount": float(c.amount_usdt or 0),
                  "notes": c.notes} for c in orig]
    orig_total = round(sum(float(c.amount_usdt or 0) for c in orig), 2)

    def _summarise(rows):
        by_recipient = {}
        company = 0.0
        for c in rows:
            amt = float(c.amount_usdt or 0)
            if c.to_user_id is None:
                company += amt
            else:
                by_recipient.setdefault(c.to_user_id, 0.0)
                by_recipient[c.to_user_id] += amt
        uname = {r.id: r.username for r in db.query(_U.id, _U.username).all()}
        credits = [{"user_id": uid, "username": uname.get(uid), "amount": round(v, 2)}
                   for uid, v in sorted(by_recipient.items(), key=lambda kv: -kv[1])]
        return credits, round(company, 2)

    # ── PREVIEW via savepoint (real engine, rolled back) ──
    if not apply:
        sp = db.begin_nested()
        try:
            _pay_direct_sponsor(db, buyer, price, tier, source_event_id=event_id)
            _pay_unilevel_chain(db, buyer, price, tier, source_event_id=event_id)
            db.flush()
            would = db.query(Commission).filter(Commission.source_event_id == event_id).all()
            credits, company = _summarise(would)
            member_total = round(sum(c["amount"] for c in credits if c["user_id"] != 1), 2)
        finally:
            sp.rollback()
        return JSONResponse({
            "mode": "dry_run", "buyer_id": buyer_id, "username": buyer.username,
            "tier": tier, "package_price": price,
            "would_reverse": {"rows": orig_view, "total_to_company_now": orig_total},
            "would_credit": credits,
            "company_keeps_after": company,
            "member_total_credited": member_total,
            "event_id": event_id,
            "note": ("Preview generated by running the live engine in a rolled-back "
                     "savepoint — nothing written. Apply marks the original rows "
                     "'reversed' and re-fires the engine for real. ?apply=1&code=YOUR_2FA."),
        })

    # ── APPLY ──
    if not getattr(user, "totp_secret", None):
        return JSONResponse({"error": "Admin has no 2FA configured"}, status_code=400)
    if not pyotp.TOTP(user.totp_secret).verify((code or "").strip(), valid_window=1):
        return JSONResponse({"error": "Invalid or missing 2FA code — pass ?code=NNNNNN"},
                            status_code=403)

    for c in orig:
        c.status = "reversed"
        c.notes = (c.notes or "") + f" | reversed: superseded by {event_id} (good-faith re-route per live comp plan)"
    db.flush()
    _pay_direct_sponsor(db, buyer, price, tier, source_event_id=event_id)
    _pay_unilevel_chain(db, buyer, price, tier, source_event_id=event_id)
    db.commit()

    new_rows = db.query(Commission).filter(Commission.source_event_id == event_id).all()
    credits, company = _summarise(new_rows)
    member_total = round(sum(c["amount"] for c in credits if c["user_id"] != 1), 2)
    return JSONResponse({
        "mode": "APPLIED", "buyer_id": buyer_id, "username": buyer.username,
        "tier": tier, "package_price": price,
        "reversed_rows": [c["id"] for c in orig_view], "reversed_total": orig_total,
        "credited": credits, "company_keeps_after": company,
        "member_total_credited": member_total, "event_id": event_id,
        "note": "Commissions re-routed through the live comp plan. Engine-credited "
                "campaign_balance/total_earned/grid_earnings/level_earnings + paid rows.",
    })


@app.get("/admin/api/grid-owner-status")
def admin_api_grid_owner_status(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Read-only health check for two things:
      1. Every grid owner's active/qualified status (via the live
         _user_is_qualified engine function) — surfaces any owner who
         bought a tier but isn't showing qualified to earn (e.g. all grids
         completed and the next advance never spawned).
      2. The watch-to-earn engine — active campaigns, whether watches are
         being recorded, and the daily-quota / commissions-paused state.
    """
    _require_admin(user)
    from .database import (User as _U, Grid, VideoCampaign, VideoWatch, WatchQuota)
    from .grid import _user_is_qualified
    from sqlalchemy import func as _f
    from datetime import datetime as _dt, timedelta as _td

    now = _dt.utcnow()

    # ── Grid owners (anyone who owns a purchased grid) ──
    owner_rows = db.query(Grid.owner_id, _f.max(Grid.package_tier)).filter(
        Grid.owner_purchased == True).group_by(Grid.owner_id).all()  # noqa: E712
    uname = {r.id: r.username for r in db.query(_U.id, _U.username).all()}
    is_active = {r.id: bool(r.is_active) for r in db.query(_U.id, _U.is_active).all()}
    is_admin = {r.id: bool(r.is_admin) for r in db.query(_U.id, _U.is_admin).all()}

    # active (incomplete) grid count per owner
    active_grid_owners = {r[0] for r in db.query(Grid.owner_id).filter(
        Grid.is_complete == False).distinct().all()}  # noqa: E712
    # active/grace campaign owners
    camp_owners = {r[0] for r in db.query(VideoCampaign.user_id).filter(
        VideoCampaign.status.in_(["active", "paused"]),
        VideoCampaign.is_completed == False).distinct().all()}  # noqa: E712
    quotas = {q.user_id: q for q in db.query(WatchQuota).all()}

    owners = []
    not_qualified = []
    paused = []
    for oid, max_tier in owner_rows:
        if oid not in uname:
            continue
        qualified = _user_is_qualified(db, oid, 1)
        q = quotas.get(oid)
        rec = {
            "user_id": oid, "username": uname.get(oid),
            "membership_active": is_active.get(oid, False),
            "owns_tier": int(max_tier or 0),
            "qualified_to_earn": bool(qualified),
            "has_active_grid": oid in active_grid_owners,
            "has_active_campaign": oid in camp_owners,
            "commissions_paused": (bool(q.commissions_paused) if q else None),
            "today_watched": (int(q.today_watched or 0) if q else None),
            "daily_required": (int(q.daily_required or 0) if q else None),
            "consecutive_missed": (int(q.consecutive_missed or 0) if q else None),
        }
        owners.append(rec)
        if is_active.get(oid) and (max_tier or 0) > 0 and not qualified:
            not_qualified.append({"user_id": oid, "username": uname.get(oid),
                                  "owns_tier": int(max_tier or 0),
                                  "has_active_grid": oid in active_grid_owners,
                                  "has_active_campaign": oid in camp_owners})
        if q and q.commissions_paused:
            paused.append({"user_id": oid, "username": uname.get(oid),
                           "consecutive_missed": int(q.consecutive_missed or 0)})

    owners.sort(key=lambda r: (-r["owns_tier"], r["user_id"]))

    # ── Watch-to-earn engine health ──
    watches_24h = db.query(_f.count(VideoWatch.id)).filter(
        VideoWatch.is_complete == True, VideoWatch.watched_at >= now - _td(hours=24)).scalar()  # noqa: E712
    watches_7d = db.query(_f.count(VideoWatch.id)).filter(
        VideoWatch.is_complete == True, VideoWatch.watched_at >= now - _td(days=7)).scalar()  # noqa: E712
    active_campaigns = db.query(_f.count(VideoCampaign.id)).filter(
        VideoCampaign.status == "active", VideoCampaign.is_completed == False).scalar()  # noqa: E712
    completed_campaigns = db.query(_f.count(VideoCampaign.id)).filter(
        VideoCampaign.is_completed == True).scalar()
    in_grace = db.query(_f.count(VideoCampaign.id)).filter(
        VideoCampaign.is_completed == True, VideoCampaign.grace_expires_at != None,
        VideoCampaign.grace_expires_at > now).scalar()  # noqa: E711
    total_quotas = db.query(_f.count(WatchQuota.id)).scalar()
    paused_quotas = db.query(_f.count(WatchQuota.id)).filter(
        WatchQuota.commissions_paused == True).scalar()  # noqa: E712

    return JSONResponse({
        "grid_owners": {
            "total": len(owners),
            "qualified": sum(1 for o in owners if o["qualified_to_earn"]),
            "not_qualified_but_owns_tier": not_qualified,
            "commissions_paused": paused,
            "detail": owners,
        },
        "watch_to_earn": {
            "active_campaigns": int(active_campaigns or 0),
            "completed_campaigns": int(completed_campaigns or 0),
            "campaigns_in_grace": int(in_grace or 0),
            "watches_completed_last_24h": int(watches_24h or 0),
            "watches_completed_last_7d": int(watches_7d or 0),
            "watch_quota_rows": int(total_quotas or 0),
            "members_with_commissions_paused": int(paused_quotas or 0),
        },
        "note": ("qualified_to_earn uses the live _user_is_qualified engine fn "
                 "(active grid at tier>=1, OR active/grace campaign, OR admin). "
                 "not_qualified_but_owns_tier flags any active member who bought a "
                 "tier but isn't currently qualified — the thing to fix. Low watch "
                 "counts are expected if the platform has been in maintenance."),
    })


@app.get("/admin/api/solvency-snapshot")
def admin_api_solvency_snapshot(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Read-only solvency picture: total member withdrawable liability
    (affiliate balance + campaign_balance) vs treasury. Attacker accounts
    (670,673,674) excluded. Company root (user 1) broken out separately so
    'what we owe members' is clean. Treasury on-chain balance is reported
    separately (fetched off-server) — this endpoint is the liability side.
    """
    _require_admin(user)
    from .database import User as _U
    from decimal import Decimal as _D

    ATTACKERS = {670, 673, 674}
    rows = db.query(_U.id, _U.username, _U.balance, _U.campaign_balance,
                    _U.total_earned, _U.is_admin, _U.is_active).all()

    def f(x): return float(x or 0)

    member_bal = member_camp = 0.0
    admin_bal = admin_camp = 0.0
    holders = []
    for r in rows:
        if r.id in ATTACKERS:
            continue
        b = f(r.balance); c = f(r.campaign_balance)
        if r.is_admin or r.id == 1:
            admin_bal += b; admin_camp += c
            continue
        member_bal += b; member_camp += c
        if (b + c) > 0:
            holders.append({"user_id": r.id, "username": r.username,
                            "balance": round(b, 2), "campaign_balance": round(c, 2),
                            "withdrawable": round(b + c, 2)})

    holders.sort(key=lambda h: -h["withdrawable"])
    member_liability = round(member_bal + member_camp, 2)

    return JSONResponse({
        "member_withdrawable_liability": member_liability,
        "_breakdown": {
            "affiliate_balance_total": round(member_bal, 2),
            "campaign_balance_total": round(member_camp, 2),
        },
        "company_root_user1": {
            "balance": round(admin_bal, 2),
            "campaign_balance": round(admin_camp, 2),
            "total": round(admin_bal + admin_camp, 2),
            "note": "Company's own retained share — not a liability to members.",
        },
        "members_with_positive_balance": len(holders),
        "top_holders": holders[:25],
        "attackers_excluded": sorted(ATTACKERS),
        "note": ("Liability = what the platform owes members if all withdrew. "
                 "Compare against treasury on-chain USDT + cold storage to size "
                 "the float needed before lifting the withdrawal freeze."),
    })


@app.get("/admin/api/qualification-timing-check")
def admin_api_qualification_timing_check(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """DEFINITIVE PROOF for the back-credit question: were the recovered buyers'
    commissions legitimately escrowed to the company because the upline wasn't
    yet qualified at purchase time, or were they genuinely owed (counter wiped)?

    Uses REAL purchase timestamps from Steve's Stripe + NOWPayments exports
    (embedded below, authoritative) joined against live genealogy. For every
    buyer purchase, walks the upline chain and asks: at the instant this buyer
    paid, had the upline already bought a tier >= the buyer's tier?
      - YES  -> the upline was qualified, commission was owed (counts to 'owed')
      - NO   -> escrowed and absorbed by the company (counts to 'company')
    Then compares each upline's qualified-at-time OWED total against their
    surviving counter. If counter ~= owed (and the gap to 'expected' is the
    company-escrowed portion), the counters are CORRECT and the back-credit
    would overpay. Read-only.
    """
    _require_admin(user)
    from .database import User as _U, GRID_PACKAGES as _PKG, DIRECT_PCT as _D, PER_LEVEL_PCT as _L, UNILEVEL_DEPTH as _DEPTH
    from collections import defaultdict as _dd
    from datetime import datetime as _dt

    BUYERS = {451: [1], 527: [1], 440: [1], 287: [1], 319: [1], 627: [1], 151: [1, 2], 449: [1], 504: [1], 285: [1], 550: [1], 183: [1, 2], 252: [1], 521: [1], 378: [1], 517: [1], 532: [1], 510: [1], 355: [1], 469: [1], 219: [1], 492: [1], 489: [1], 482: [1], 354: [1], 473: [1], 424: [1], 455: [1], 324: [1], 432: [1], 189: [1], 420: [1], 268: [1], 191: [1], 349: [1, 2], 427: [1], 412: [1], 408: [1], 398: [1], 397: [1], 350: [1], 386: [1], 389: [1], 323: [1], 224: [1], 491: [1], 329: [1], 522: [1], 343: [1, 2], 264: [1, 2], 393: [1], 385: [1], 382: [1], 367: [1], 158: [1], 307: [1], 211: [1], 154: [1], 202: [1], 204: [1], 194: [1], 177: [1], 157: [1, 2], 166: [1], 165: [1], 163: [1], 161: [1], 160: [1], 159: [1]}
    TS = {'451_1': '2026-06-07T19:00:58', '527_1': '2026-06-03T04:25:22', '440_1': '2026-06-02T19:56:01', '287_1': '2026-06-02T18:35:36', '319_1': '2026-06-01T19:36:40', '627_1': '2026-06-01T17:51:02', '151_2': '2026-05-31T06:37:06', '151_1': '2026-05-30T21:43:45', '449_1': '2026-05-31T00:05:36', '504_1': '2026-05-30T21:27:25', '285_1': '2026-05-29T00:03:41', '550_1': '2026-05-28T23:40:10', '183_2': '2026-05-28T18:54:46', '183_1': '2026-05-28T18:43:45', '252_1': '2026-05-28T18:36:22', '521_1': '2026-05-28T14:48:30', '378_1': '2026-05-28T14:35:14', '517_1': '2026-05-28T12:53:04', '532_1': '2026-05-28T09:58:31', '510_1': '2026-05-28T00:38:12', '355_1': '2026-05-27T21:56:45', '469_1': '2026-05-27T18:43:03', '219_1': '2026-05-27T16:45:41', '492_1': '2026-05-27T16:37:15', '489_1': '2026-05-27T16:03:51', '482_1': '2026-05-27T12:41:49', '354_1': '2026-05-27T08:30:57', '473_1': '2026-05-27T07:30:24', '424_1': '2026-05-26T22:33:02', '455_1': '2026-05-26T22:11:30', '324_1': '2026-05-26T19:57:14', '432_1': '2026-05-26T13:29:58', '189_1': '2026-05-26T13:14:07', '420_1': '2026-05-26T10:35:57', '268_1': '2026-05-26T09:37:42', '191_1': '2026-05-26T06:48:24', '349_2': '2026-05-26T06:14:04', '349_1': '2026-05-25T12:54:10', '427_1': '2026-05-26T04:27:43', '412_1': '2026-05-25T22:28:52', '408_1': '2026-05-25T21:30:39', '398_1': '2026-05-25T18:39:06', '397_1': '2026-05-25T18:22:56', '350_1': '2026-05-25T16:52:15', '386_1': '2026-05-25T14:59:46', '389_1': '2026-05-25T14:39:45', '323_1': '2026-05-24T14:03:19', '224_1': '2026-05-18T08:22:00', '491_1': '2026-05-28T21:07:00', '329_1': '2026-05-27T06:56:00', '522_1': '2026-05-28T08:39:00', '343_2': '2026-05-26T06:42:00', '343_1': '2026-05-22T22:22:00', '264_2': '2026-05-26T06:36:00', '264_1': '2026-05-15T16:10:00', '393_1': '2026-05-25T21:58:00', '385_1': '2026-05-25T11:31:00', '382_1': '2026-05-25T09:23:00', '367_1': '2026-05-24T11:00:00', '158_1': '2026-05-20T14:45:00', '307_1': '2026-05-20T04:32:00', '211_1': '2026-05-17T20:37:00', '154_1': '2026-05-16T21:17:00', '202_1': '2026-05-12T14:46:00', '204_1': '2026-05-12T13:33:00', '194_1': '2026-05-12T12:22:00', '177_1': '2026-05-11T23:08:00', '157_2': '2026-05-11T02:12:00', '157_1': '2026-05-11T01:35:00', '166_1': '2026-05-06T14:13:00', '165_1': '2026-05-06T13:24:00', '163_1': '2026-04-29T15:09:00', '161_1': '2026-04-28T16:17:00', '160_1': '2026-04-28T13:51:00', '159_1': '2026-04-28T13:17:00'}

    def buy_ts(uid, t):
        v = TS.get(str(uid) + "_" + str(t))
        return _dt.fromisoformat(v) if v else None
    def qual_ts(uid, t):
        # earliest date uid owned a tier >= t (admin always qualified)
        best = None
        for tt in range(t, 4):
            v = TS.get(str(uid) + "_" + str(tt))
            if v:
                d = _dt.fromisoformat(v)
                if best is None or d < best:
                    best = d
        return best

    rows = db.query(_U.id, _U.sponsor_id, _U.username, _U.is_admin,
                    _U.grid_earnings, _U.level_earnings).all()
    sponsor_of = {r.id: r.sponsor_id for r in rows}
    is_admin = {r.id: bool(r.is_admin) for r in rows}
    uname = {r.id: r.username for r in rows}
    act_grid = {r.id: float(r.grid_earnings or 0) for r in rows}
    act_level = {r.id: float(r.level_earnings or 0) for r in rows}

    exp_g = _dd(float); owed_g = _dd(float); comp_g = _dd(float)
    exp_l = _dd(float); owed_l = _dd(float); comp_l = _dd(float)
    detail = _dd(list)  # per direct-sponsor: list of (buyer, buyer_ts, qualified_bool)

    for buyer, tiers in BUYERS.items():
        for t in tiers:
            price = float(_PKG.get(t, 0))
            bts = buy_ts(buyer, t)
            cur = buyer; seen = set()
            for lvl in range(1, _DEPTH + 1):
                sp = sponsor_of.get(cur)
                if not sp or sp in seen:
                    break
                seen.add(sp)
                # qualified-at-time?
                if is_admin.get(sp, False):
                    q = True
                else:
                    qts = qual_ts(sp, t)
                    q = bool(qts and bts and qts <= bts)
                # level (unilevel) stream — every level incl. direct
                exp_l[sp] += round(price * _L, 2)
                (owed_l if q else comp_l)[sp] += round(price * _L, 2)
                # grid (direct) stream — only level 1 (direct sponsor)
                if lvl == 1:
                    exp_g[sp] += round(price * _D, 2)
                    (owed_g if q else comp_g)[sp] += round(price * _D, 2)
                    detail[sp].append({
                        "buyer": buyer, "buyer_user": uname.get(buyer),
                        "tier": t,
                        "buyer_bought": bts.isoformat() if bts else None,
                        "sponsor_qualified": (qual_ts(sp, t).isoformat() if qual_ts(sp, t) else None),
                        "qualified_at_purchase": q,
                        "direct_amount": round(price * _D, 2),
                        "routed_to": ("upline" if q else "company"),
                    })
                cur = sp

    # focus on the 13 credited uplines
    CREDIT = [343,151,432,349,264,350,473,307,482,177,191,504,157]
    out = []
    for x in CREDIT:
        out.append({
            "user_id": x, "username": uname.get(x),
            "counter_grid": round(act_grid.get(x,0),2),
            "owed_grid_at_time": round(owed_g[x],2),
            "company_grid_escrowed": round(comp_g[x],2),
            "expected_grid_naive": round(exp_g[x],2),
            "counter_level": round(act_level.get(x,0),2),
            "owed_level_at_time": round(owed_l[x],2),
            "company_level_escrowed": round(comp_l[x],2),
            "expected_level_naive": round(exp_l[x],2),
            "direct_detail": detail[x],
        })

    tot = {
        "owed_grid_at_time": round(sum(owed_g[x] for x in CREDIT),2),
        "company_grid_escrowed": round(sum(comp_g[x] for x in CREDIT),2),
        "expected_grid_naive": round(sum(exp_g[x] for x in CREDIT),2),
        "counter_grid": round(sum(act_grid.get(x,0) for x in CREDIT),2),
        "owed_level_at_time": round(sum(owed_l[x] for x in CREDIT),2),
        "company_level_escrowed": round(sum(comp_l[x] for x in CREDIT),2),
        "expected_level_naive": round(sum(exp_l[x] for x in CREDIT),2),
        "counter_level": round(sum(act_level.get(x,0) for x in CREDIT),2),
    }
    return JSONResponse({
        "verdict_note": ("If counter_grid ~= owed_grid_at_time for each upline, the "
                         "surviving counters are CORRECT and the 'gap' to expected_naive "
                         "is company-escrowed money (sponsor not yet qualified when the "
                         "buyer paid). In that case the back-credit OVERPAYS and must NOT "
                         "be applied."),
        "totals_across_credited_uplines": tot,
        "per_upline": out,
    })


@app.get("/admin/api/grid-backcredit")
def admin_api_grid_backcredit(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    apply: int = 0,
    code: str = "",
    min_credit: float = 1.0,
):
    """Restore the grid/unilevel commissions the recovered buyers owed their
    uplines but that were never credited (the prior earnings reconstruction
    only knew 28 of the ~63 buyers). Uses the SAME expected computation as
    /admin/api/earnings-reconciliation (mirrors grid.py: 0.40 direct to the
    direct sponsor, 0.0625 to each of 8 unilevel levels incl. the direct
    sponsor, qualified = owns purchased tier>=t or admin).

    Credit per member = max(0, expected - actual) for the grid stream and the
    level stream independently — CAPPED at the matrix-implied amount, so a
    member can never be pushed above what the rebuilt positions justify
    (no double-pay on the original 28 buyers' already-credited commissions).
    Admin/company (user 1) is excluded (its deltas are company-absorb, not
    owed). Members already at/above expected (e.g. a commission from a since-
    deleted downline buyer) are left untouched.

    On apply: credits campaign_balance + total_earned + grid_earnings/
    level_earnings, and writes one audit Commission row per stream
    (type grid_reconstruction_backcredit, status paid). No email, no bonus.
    Dry-run default; ?apply=1&code=YOUR_2FA writes.
    """
    _require_admin(user)
    from .database import (User as _User, Grid, Commission,
                           GRID_PACKAGES as _PKG,
                           DIRECT_PCT as _D, PER_LEVEL_PCT as _L,
                           UNILEVEL_DEPTH as _DEPTH)
    from collections import defaultdict as _dd
    from decimal import Decimal as _Dec
    from datetime import datetime as _dt
    import pyotp

    urows = db.query(_User.id, _User.sponsor_id, _User.username, _User.is_admin).all()
    sponsor_of = {r.id: r.sponsor_id for r in urows}
    is_admin = {r.id: bool(r.is_admin) for r in urows}
    uname = {r.id: r.username for r in urows}

    buyer_tiers = _dd(set); owns_max = _dd(int)
    for g in db.query(Grid).filter(Grid.owner_purchased == True).all():  # noqa: E712
        buyer_tiers[g.owner_id].add(g.package_tier)
        if g.package_tier > owns_max[g.owner_id]:
            owns_max[g.owner_id] = g.package_tier

    def qualified(x, t):
        return is_admin.get(x, False) or owns_max.get(x, 0) >= t

    exp_grid = _dd(float); exp_level = _dd(float)
    for B, tiers in buyer_tiers.items():
        for t in tiers:
            price = float(_PKG.get(t, 0))
            cur = B; seen = set()
            for lvl in range(1, _DEPTH + 1):
                sp = sponsor_of.get(cur)
                if not sp or sp in seen: break
                seen.add(sp)
                if qualified(sp, t):
                    exp_level[sp] += round(price * _L, 2)
                    if lvl == 1:
                        exp_grid[sp] += round(price * _D, 2)
                cur = sp

    will_apply = False
    if apply == 1:
        sec = getattr(user, "totp_secret", None)
        if not sec or not code or not pyotp.TOTP(sec).verify(code, valid_window=1):
            return JSONResponse({"error": "2FA required/invalid for apply"}, status_code=403)
        will_apply = True

    rows = []
    tot_grid = tot_level = 0.0
    targets = set(list(exp_grid.keys()) + list(exp_level.keys()))
    for x in sorted(targets):
        if is_admin.get(x, False):
            continue  # company root excluded
        u = db.query(_User).filter(_User.id == x).first()
        if not u:
            continue
        ag = float(getattr(u, "grid_earnings", 0) or 0)
        al = float(getattr(u, "level_earnings", 0) or 0)
        owe_g = round(max(0.0, round(exp_grid[x], 2) - ag), 2)
        owe_l = round(max(0.0, round(exp_level[x], 2) - al), 2)
        if (owe_g + owe_l) < min_credit:
            continue
        tot_grid += owe_g; tot_level += owe_l
        rows.append({"user_id": x, "username": uname.get(x),
                     "grid_owed": owe_g, "level_owed": owe_l,
                     "total_owed": round(owe_g + owe_l, 2),
                     "grid_before": round(ag, 2), "level_before": round(al, 2)})
        if will_apply:
            credit = _Dec(str(owe_g + owe_l))
            u.campaign_balance = _Dec(str(u.campaign_balance or 0)) + credit
            u.total_earned     = _Dec(str(u.total_earned or 0)) + credit
            if owe_g > 0:
                u.grid_earnings = _Dec(str(u.grid_earnings or 0)) + _Dec(str(owe_g))
                db.add(Commission(from_user_id=None, to_user_id=x, amount_usdt=owe_g,
                                  commission_type="grid_reconstruction_backcredit",
                                  status="paid", paid_at=_dt.utcnow(),
                                  notes="Back-credit: direct-sponsor commissions from recovered buyers (post-wipe reconstruction)"))
            if owe_l > 0:
                u.level_earnings = _Dec(str(u.level_earnings or 0)) + _Dec(str(owe_l))
                db.add(Commission(from_user_id=None, to_user_id=x, amount_usdt=owe_l,
                                  commission_type="grid_reconstruction_backcredit",
                                  status="paid", paid_at=_dt.utcnow(),
                                  notes="Back-credit: unilevel commissions from recovered buyers (post-wipe reconstruction)"))
            db.flush()
    if will_apply:
        db.commit()

    rows.sort(key=lambda r: -r["total_owed"])
    return JSONResponse({
        "mode": "APPLIED" if will_apply else "dry_run",
        "members_credited" if will_apply else "members_to_credit": len(rows),
        "total_grid_owed": round(tot_grid, 2),
        "total_level_owed": round(tot_level, 2),
        "total_owed": round(tot_grid + tot_level, 2),
        "min_credit": min_credit,
        "credits": rows,
        "note": ("Credits campaign_balance + total_earned + grid/level_earnings by "
                 "max(0, expected-actual) per stream — capped at the matrix-implied "
                 "amount so the original 28 buyers' commissions are never double-paid. "
                 "Company root (user 1) excluded. Audit Commission rows written per "
                 "stream. ?apply=1&code=YOUR_2FA. This increases recorded member "
                 "liability by total_owed — restores true pre-hack earnings."),
    })


@app.get("/admin/api/earnings-reconciliation")
def admin_api_earnings_reconciliation(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    min_delta: float = 1.0,
):
    """Read-only cross-validation of the SURVIVING per-user earnings counters
    against what the now-rebuilt grid positions + genealogy imply under the
    locked comp plan. The counters (grid_earnings / level_earnings /
    bonus_earnings) are User columns that survived the relational wipe; this
    confirms the rebuilt matrix is consistent with them.

    Mirrors grid.py exactly:
      direct   = price * DIRECT_PCT (0.40) to the buyer's DIRECT sponsor, if qualified
      unilevel = price * PER_LEVEL_PCT (0.0625) to each of UNILEVEL_DEPTH (8)
                 sponsor-chain levels (level 1 = the direct sponsor as well), if qualified
      bonus    = price * GRID_TOTAL * BONUS_POOL_PCT per COMPLETED grid owned
      qualified(X,t) = X owns a purchased grid at tier >= t (or is admin)

    Buyer set + completions read from live grids (post-rebuild); genealogy from
    users.sponsor_id. Expected is the fully-qualified steady-state figure; real
    escrow/grace, time-ordered qualification, repurchases and the deleted-buyer
    gap produce small deltas, so only |delta| >= min_delta (default $1) is
    flagged. Admin/company (user 1) follows different absorb rules and is
    expected to diverge. No writes."""
    _require_admin(user)
    from .database import (User as _User, Grid,
                           GRID_PACKAGES as _PKG, GRID_TOTAL as _TOTAL,
                           DIRECT_PCT as _D, PER_LEVEL_PCT as _L,
                           UNILEVEL_DEPTH as _DEPTH, BONUS_POOL_PCT as _BP,
                           bonus_pct_for as _bpf)
    from collections import defaultdict as _dd

    urows = db.query(_User.id, _User.sponsor_id, _User.username, _User.is_admin,
                     _User.grid_earnings, _User.level_earnings, _User.bonus_earnings).all()
    sponsor_of = {r.id: r.sponsor_id for r in urows}
    is_admin = {r.id: bool(r.is_admin) for r in urows}
    uname = {r.id: r.username for r in urows}
    act = {r.id: {"grid": float(r.grid_earnings or 0), "level": float(r.level_earnings or 0),
                  "bonus": float(r.bonus_earnings or 0)} for r in urows}

    buyer_tiers = _dd(set); owns_max = _dd(int)
    for g in db.query(Grid).filter(Grid.owner_purchased == True).all():  # noqa: E712
        buyer_tiers[g.owner_id].add(g.package_tier)
        if g.package_tier > owns_max[g.owner_id]:
            owns_max[g.owner_id] = g.package_tier

    def qualified(x, t):
        return is_admin.get(x, False) or owns_max.get(x, 0) >= t

    exp_grid = _dd(float); exp_level = _dd(float)
    for B, tiers in buyer_tiers.items():
        for t in tiers:
            price = float(_PKG.get(t, 0))
            cur = B; seen = set()
            for lvl in range(1, _DEPTH + 1):
                sp = sponsor_of.get(cur)
                if not sp or sp in seen: break
                seen.add(sp)
                if qualified(sp, t):
                    exp_level[sp] += round(price * _L, 2)
                    if lvl == 1:
                        exp_grid[sp] += round(price * _D, 2)
                cur = sp

    exp_bonus = _dd(float)
    for g in db.query(Grid).filter(Grid.is_complete == True).all():  # noqa: E712
        exp_bonus[g.owner_id] += round(float(_PKG.get(g.package_tier, 0)) * g.total_seats * _bpf(g.total_seats), 2)

    owners = set(list(exp_grid) + list(exp_level) + list(exp_bonus) +
                 [u for u, v in act.items() if v["grid"] or v["level"] or v["bonus"]])
    tot = {"eg": 0.0, "ag": 0.0, "el": 0.0, "al": 0.0, "eb": 0.0, "ab": 0.0}
    rows = []
    for x in owners:
        eg, el, eb = round(exp_grid[x], 2), round(exp_level[x], 2), round(exp_bonus[x], 2)
        ag, al, ab = round(act.get(x, {}).get("grid", 0.0), 2), round(act.get(x, {}).get("level", 0.0), 2), round(act.get(x, {}).get("bonus", 0.0), 2)
        tot["eg"] += eg; tot["ag"] += ag; tot["el"] += el; tot["al"] += al; tot["eb"] += eb; tot["ab"] += ab
        dg, dl, dbn = round(ag - eg, 2), round(al - el, 2), round(ab - eb, 2)
        if max(abs(dg), abs(dl), abs(dbn)) >= min_delta:
            rows.append({"user_id": x, "username": uname.get(x), "is_admin": is_admin.get(x, False),
                         "grid_expected": eg, "grid_actual": ag, "grid_delta": dg,
                         "level_expected": el, "level_actual": al, "level_delta": dl,
                         "bonus_expected": eb, "bonus_actual": ab, "bonus_delta": dbn})
    rows.sort(key=lambda r: -(abs(r["grid_delta"]) + abs(r["level_delta"]) + abs(r["bonus_delta"])))

    return JSONResponse({
        "mode": "read_only",
        "comp_plan": {"direct_pct": _D, "per_level_pct": _L, "unilevel_depth": _DEPTH, "bonus_pool_pct": _BP},
        "totals": {
            "grid_expected": round(tot["eg"], 2), "grid_actual": round(tot["ag"], 2), "grid_delta": round(tot["ag"] - tot["eg"], 2),
            "level_expected": round(tot["el"], 2), "level_actual": round(tot["al"], 2), "level_delta": round(tot["al"] - tot["el"], 2),
            "bonus_expected": round(tot["eb"], 2), "bonus_actual": round(tot["ab"], 2), "bonus_delta": round(tot["ab"] - tot["eb"], 2),
        },
        "flagged_count": len(rows),
        "min_delta": min_delta,
        "flagged_owners": rows,
        "note": ("delta = actual(survived counter) - expected(from rebuilt positions). "
                 "Near-zero across the board = positions and earnings agree. Positive "
                 "deltas can be legit (membership/Nexus/course streams don't touch these "
                 "grid counters; escrow later claimed). Negative deltas = counter below "
                 "what the matrix implies (possible under-credit to investigate). user 1 "
                 "(admin/company) diverges by design."),
    })


@app.get("/admin/api/grid-full-rebuild")
def admin_api_grid_full_rebuild(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    apply: int = 0,
    code: str = "",
):
    """Authoritative grid-position rebuild from the FULL Stripe+NOWPayments
    verified buyer set (69 tier-1, 6 tier-2, 1 tier-3), reconstructed from
    Steve's own processor exports after the post-breach relational wipe.

    Additive + silent + idempotent:
      - seats each EXISTING buyer in every upline's grid at the tier, in
        purchase-time order, ONLY where not already seated (preserves live and
        previously-reconstructed positions; safe to re-run)
      - composes the real engine primitives (get_or_create_active_grid +
        _next_slot) so advance roll-over and slot order match live exactly
      - when a grid reaches GRID_TOTAL it is completed SILENTLY: is_complete=True,
        bonus_pool_accrued set to policy target, bonus_paid=True (so the boot
        top-up migration can NEVER re-pay it). NO completion bonus, NO commission,
        NO email -- historical bonuses were already paid/restored. Completions are
        listed for separate audit.
      - buyers whose user record no longer exists (deleted early test/churn
        accounts) are skipped and reported
      - sets owner_purchased=True on each real buyer's own grid
    Dry-run default; ?apply=1&code=YOUR_2FA writes.
    """
    _require_admin(user)
    from .database import (Grid, GridPosition, User as _User,
                           GRID_PACKAGES as _PKG, GRID_TOTAL as _TOTAL)
    from .grid import get_or_create_active_grid as _goc, _next_slot, _policy_bonus_target
    from datetime import datetime as _dt
    from decimal import Decimal as _Dec
    from collections import defaultdict as _dd
    import pyotp

    BUYERS = {451: [1], 527: [1], 440: [1], 287: [1], 319: [1], 627: [1], 151: [1, 2], 449: [1], 504: [1], 285: [1], 550: [1], 183: [1, 2, 3], 252: [1], 521: [1], 378: [1], 517: [1], 532: [1], 510: [1], 355: [1], 469: [1], 219: [1], 492: [1], 489: [1], 482: [1], 354: [1], 473: [1], 424: [1], 455: [1], 324: [1], 432: [1], 189: [1], 420: [1], 268: [1], 191: [1], 349: [1, 2], 427: [1], 412: [1], 408: [1], 398: [1], 397: [1], 350: [1], 386: [1], 389: [1], 323: [1], 224: [1], 491: [1], 329: [1], 522: [1], 343: [1, 2], 264: [1, 2], 393: [1], 385: [1], 382: [1], 367: [1], 158: [1], 307: [1], 211: [1], 154: [1], 202: [1], 204: [1], 194: [1], 177: [1], 157: [1, 2], 166: [1], 165: [1], 163: [1], 161: [1], 160: [1], 159: [1]}
    TS = {'451_1': '2026-06-07T19:00:58', '527_1': '2026-06-03T04:25:22', '440_1': '2026-06-02T19:56:01', '287_1': '2026-06-02T18:35:36', '319_1': '2026-06-01T19:36:40', '627_1': '2026-06-01T17:51:02', '151_2': '2026-05-31T06:37:06', '151_1': '2026-05-30T21:43:45', '449_1': '2026-05-31T00:05:36', '504_1': '2026-05-30T21:27:25', '285_1': '2026-05-29T00:03:41', '550_1': '2026-05-28T23:40:10', '183_2': '2026-05-28T18:54:46', '183_1': '2026-05-28T18:43:45', '252_1': '2026-05-28T18:36:22', '521_1': '2026-05-28T14:48:30', '378_1': '2026-05-28T14:35:14', '517_1': '2026-05-28T12:53:04', '532_1': '2026-05-28T09:58:31', '510_1': '2026-05-28T00:38:12', '355_1': '2026-05-27T21:56:45', '469_1': '2026-05-27T18:43:03', '219_1': '2026-05-27T16:45:41', '492_1': '2026-05-27T16:37:15', '489_1': '2026-05-27T16:03:51', '482_1': '2026-05-27T12:41:49', '354_1': '2026-05-27T08:30:57', '473_1': '2026-05-27T07:30:24', '424_1': '2026-05-26T22:33:02', '455_1': '2026-05-26T22:11:30', '324_1': '2026-05-26T19:57:14', '432_1': '2026-05-26T13:29:58', '189_1': '2026-05-26T13:14:07', '420_1': '2026-05-26T10:35:57', '268_1': '2026-05-26T09:37:42', '191_1': '2026-05-26T06:48:24', '349_2': '2026-05-26T06:14:04', '349_1': '2026-05-25T12:54:10', '427_1': '2026-05-26T04:27:43', '412_1': '2026-05-25T22:28:52', '408_1': '2026-05-25T21:30:39', '398_1': '2026-05-25T18:39:06', '397_1': '2026-05-25T18:22:56', '350_1': '2026-05-25T16:52:15', '386_1': '2026-05-25T14:59:46', '389_1': '2026-05-25T14:39:45', '323_1': '2026-05-24T14:03:19', '224_1': '2026-05-18T08:22:00', '491_1': '2026-05-28T21:07:00', '329_1': '2026-05-27T06:56:00', '522_1': '2026-05-28T08:39:00', '343_2': '2026-05-26T06:42:00', '343_1': '2026-05-22T22:22:00', '264_2': '2026-05-26T06:36:00', '264_1': '2026-05-15T16:10:00', '393_1': '2026-05-25T21:58:00', '385_1': '2026-05-25T11:31:00', '382_1': '2026-05-25T09:23:00', '367_1': '2026-05-24T11:00:00', '158_1': '2026-05-20T14:45:00', '307_1': '2026-05-20T04:32:00', '211_1': '2026-05-17T20:37:00', '154_1': '2026-05-16T21:17:00', '202_1': '2026-05-12T14:46:00', '204_1': '2026-05-12T13:33:00', '194_1': '2026-05-12T12:22:00', '177_1': '2026-05-11T23:08:00', '157_2': '2026-05-11T02:12:00', '157_1': '2026-05-11T01:35:00', '166_1': '2026-05-06T14:13:00', '165_1': '2026-05-06T13:24:00', '163_1': '2026-04-29T15:09:00', '161_1': '2026-04-28T16:17:00', '160_1': '2026-04-28T13:51:00', '159_1': '2026-04-28T13:17:00', '183_3': '2026-05-28T18:54:46'}

    urows = db.query(_User.id, _User.sponsor_id, _User.created_at).all()
    sponsor_of = {r.id: r.sponsor_id for r in urows}
    created_of = {r.id: r.created_at for r in urows}
    exists = set(sponsor_of.keys())

    def ev_ts(uid, tier):
        k = "%s_%s" % (uid, tier)
        if k in TS:
            try: return _dt.fromisoformat(TS[k])
            except Exception: pass
        return created_of.get(uid) or _dt(2026, 5, 15)

    # ordered purchase events; skip buyers whose user record is gone
    events = []
    skipped = []
    for uid, tiers in BUYERS.items():
        if uid not in exists:
            skipped.append(uid); continue
        for t in tiers:
            events.append((ev_ts(uid, t), uid, t))
    events.sort(key=lambda x: x[0])

    def chain(uid):
        out = []; cur = uid; seen = set()
        while True:
            sp = sponsor_of.get(cur)
            if not sp or sp in seen: break
            seen.add(sp)
            if sp != uid: out.append(sp)
            cur = sp
        return out

    # existing seating snapshot: (owner_id, tier, buyer_id)
    existing = set()
    cur_owner_fill = _dd(lambda: _dd(int))   # owner -> tier -> current seat count
    for gp, g in (db.query(GridPosition, Grid)
                  .join(Grid, GridPosition.grid_id == Grid.id).all()):
        existing.add((g.owner_id, g.package_tier, gp.member_id))
        cur_owner_fill[g.owner_id][g.package_tier] += 1

    add_fill = _dd(lambda: _dd(int))         # owner -> tier -> seats this rebuild adds
    to_add = []                               # (owner, tier, buyer) ordered
    for ts, uid, tier in events:
        for owner in chain(uid):
            if owner not in exists: continue
            if owner == 1: continue   # company root: already restored at counter
            #                           level (2 completed tier-1 advances + bonuses
            #                           via grid-root-restore). Row-seating it would
            #                           stack onto those counters AND can't reach a
            #                           clean 72 anyway (6 deleted accounts + repurchases),
            #                           so it is intentionally preserved as-is.
            key = (owner, tier, uid)
            if key in existing: continue
            existing.add(key)
            add_fill[owner][tier] += 1
            to_add.append((owner, tier, uid))

    # projection per owner+tier
    owners = sorted(set(list(add_fill.keys()) + [o for o in cur_owner_fill]))
    def proj(owner, tier):
        cur = cur_owner_fill[owner][tier]; add = add_fill[owner][tier]
        tot = cur + add
        return cur, add, tot, (tot // _TOTAL), (tot % _TOTAL)

    # ---- APPLY gate ----
    will_apply = False
    if apply == 1:
        sec = getattr(user, "totp_secret", None)
        if not sec or not code or not pyotp.TOTP(sec).verify(code, valid_window=1):
            return JSONResponse({"error": "2FA required/invalid for apply"}, status_code=403)
        will_apply = True

    completions = []
    if will_apply:
        # set owner_purchased on each existing buyer's own grid
        for uid, tiers in BUYERS.items():
            if uid not in exists: continue
            for t in tiers:
                og = _goc(db, uid, t)
                if not og.owner_purchased:
                    og.owner_purchased = True
        db.flush()
        # seat additions in order, composing real primitives, silent completion
        for owner, tier, buyer in to_add:
            grid = _goc(db, owner, tier)
            lvl, pos = _next_slot(db, grid)
            if lvl is None:
                grid.is_complete = True
                grid.bonus_pool_accrued = _Dec(str(_policy_bonus_target(tier)))
                grid.bonus_paid = True
                completions.append({"owner": owner, "tier": tier, "grid_id": grid.id})
                db.flush()
                grid = _goc(db, owner, tier)
                lvl, pos = _next_slot(db, grid)
            db.add(GridPosition(grid_id=grid.id, member_id=buyer,
                                grid_level=lvl, position_num=pos, is_overspill=True))
            grid.positions_filled = (grid.positions_filled or 0) + 1
            grid.revenue_total = _Dec(str(grid.revenue_total or 0)) + _Dec(str(_PKG[tier]))
            if grid.positions_filled >= grid.total_seats and not grid.is_complete:
                grid.is_complete = True
                grid.bonus_pool_accrued = _Dec(str(_policy_bonus_target(tier, grid.total_seats)))
                grid.bonus_paid = True
                completions.append({"owner": owner, "tier": tier, "grid_id": grid.id})
            db.flush()
        db.commit()

    # ---- report ----
    u1 = proj(1, 1)
    report_owners = []
    for owner in owners:
        for tier in (1, 2, 3):
            if add_fill[owner][tier] or cur_owner_fill[owner][tier]:
                cur, add, tot, adv, part = proj(owner, tier)
                if add:  # only show owners we change
                    report_owners.append({"owner": owner, "tier": tier,
                        "current_seats": cur, "added": add, "projected_total": tot,
                        "completed_advances": adv, "partial_fill": part})
    report_owners.sort(key=lambda r: -r["added"])

    return JSONResponse({
        "mode": "APPLIED" if will_apply else "dry_run",
        "buyers_in_set": len(BUYERS),
        "skipped_nonexistent_buyers": sorted(skipped),
        "total_seats_to_add": len(to_add),
        "owners_touched": len(set(o for o, _, _ in to_add)),
        "completions_during_rebuild": completions if will_apply else "n/a (dry-run)",
        "owner_1_root_grid": ("EXCLUDED / preserved as restored — your 2 completed "
                              "tier-1 advances (72 seats, bonuses already paid) and "
                              "tier-2 stand at the counter level. Not row-seated: "
                              "6 deleted accounts + repurchases make a clean 72 "
                              "unrecoverable from existing members, and seating would "
                              "double-count the restored advances."),
        "owners_changed": report_owners,
        "note": ("Dry-run mutates nothing. Apply seats every missing existing buyer "
                 "(EXCLUDING company root owner 1) additively in purchase order, "
                 "silently completing grids (pool=target + bonus_paid=True so the boot "
                 "top-up migration cannot re-pay; no bonus/commission/email), and flags "
                 "completions for audit. ?apply=1&code=YOUR_2FA"),
    })


@app.get("/admin/api/grid-position-replay")
def admin_api_grid_position_replay(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    apply: int = 0,
    code: str = "",
    depth_cap: int = 0,
):
    """Reconstruct the wiped GridPosition matrix by DETERMINISTIC, NON-DESTRUCTIVE
    replay of verified historical tier purchases.

    Placement is deterministic: a buyer seats in EVERY upline grid at the tier
    (sponsor chain), slots fill levels 1..6 six-per-level in fill order. The only
    input deciding the matrix is purchase ORDER, and fill COUNT (progress toward
    bonus) is order-independent — so progress rebuilds exactly even where a
    timestamp is approximate; order only affects cosmetic slot layout.

    LIVE-SAFE: the platform is open and new purchases (e.g. 451 stevenh, who
    bought tier 1 post-reopen) already created correct grids/positions/commissions
    via the live flow. So this NEVER deletes or blind-resets. It:
      1. Pre-loads existing GridPositions (live + any survivors) so it is fully
         idempotent — a buyer already seated in a grid is skipped.
      2. Seats each verified historical buyer in their upline grids ONLY where
         not already present, at the next open slot after existing seats.
      3. Sets owner_purchased=True on real buyers' own grids (also corrects the
         flag tier-grid-restore left False).
      4. Recomputes positions_filled / revenue_total / bonus_pool_accrued for
         every grid FROM ITS ACTUAL ROWS (the platform's denormalised-counter
         doctrine), correcting stale survivor counters. is_complete is left
         untouched. No commissions, bonuses, or emails fire.

    Checksum: reconstructed final (live+historical) filled*price vs the grid's
    surviving revenue_total counter. real_mismatches = a SURVIVING counter that
    still disagrees; no_surviving_baseline = grids with no counter to check
    (benign). The recompute makes counters match actual rows on apply regardless.

    With 33 historical buyers + GRID_TOTAL=36 no grid completes; a >=36 fill is
    flagged, not auto-advanced. Dry-run default; ?apply=1&code=YOUR_2FA writes.
    ?depth_cap=N bounds the upline walk (0 = unbounded, mirrors _spillover_fill)."""
    _require_admin(user)
    from .database import (Grid, GridPosition, User as _User,
                           GRID_PACKAGES as _PKG, GRID_TOTAL as _TOTAL,
                           GRID_WIDTH as _W, BONUS_POOL_PCT as _BPCT,
                           bonus_pct_for as _bpf)
    from .grid import _policy_bonus_target
    from datetime import datetime as _dt
    from decimal import Decimal as _Dec
    from collections import defaultdict as _dd
    import pyotp

    # ── Verified HISTORICAL tier buyers (Stripe + NOWPayments, prior session).
    #    451 (stevenh) is deliberately EXCLUDED — his tier-1 was a live
    #    post-reopen purchase, already placed by the live flow. ──
    TIER_BUYERS = {154:[1],157:[1,2],158:[1],177:[1],183:[1,2,3],191:[1],194:[1],
        202:[1],211:[1],219:[1],224:[1],264:[1,2],268:[1],287:[1],307:[1],323:[1],
        329:[1],343:[1,2],367:[1],382:[1],385:[1],393:[1],408:[1],432:[1],469:[1],
        491:[1],522:[1],532:[1]}
    NP_TS = {(154,1):"2026-05-16T21:17:00",(157,1):"2026-05-11T01:35:00",
        (157,2):"2026-05-11T02:12:00",(158,1):"2026-05-20T14:45:00",
        (177,1):"2026-05-11T23:08:00",(194,1):"2026-05-12T12:22:00",
        (202,1):"2026-05-12T14:46:00",(211,1):"2026-05-17T20:37:00",
        (224,1):"2026-05-18T08:22:00",(264,1):"2026-05-15T16:10:00",
        (264,2):"2026-05-26T06:36:00",(307,1):"2026-05-20T04:32:00",
        (329,1):"2026-05-27T06:56:00",(343,1):"2026-05-22T22:22:00",
        (343,2):"2026-05-26T06:42:00",(367,1):"2026-05-24T11:00:00",
        (382,1):"2026-05-25T09:23:00",(385,1):"2026-05-25T11:31:00",
        (393,1):"2026-05-25T21:58:00",(491,1):"2026-05-28T21:07:00",
        (522,1):"2026-05-28T08:39:00"}

    urows = db.query(_User.id, _User.sponsor_id, _User.created_at, _User.username).all()
    sponsor_of = {r.id: r.sponsor_id for r in urows}
    created_of = {r.id: r.created_at for r in urows}
    uname_of   = {r.id: r.username for r in urows}

    def _order_key(buyer, tier):
        iso = NP_TS.get((buyer, tier))
        if iso:
            try: return _dt.fromisoformat(iso)
            except Exception: pass
        return created_of.get(buyer) or _dt(2099, 1, 1)

    events = []
    for buyer, tiers in TIER_BUYERS.items():
        for tier in tiers:
            events.append((buyer, tier))
    events.sort(key=lambda bt: (_order_key(*bt), bt[1]))

    # ── Pre-load existing positions (live + survivors) → idempotency baseline ──
    grids = db.query(Grid.id, Grid.owner_id, Grid.package_tier).all()
    grid_meta = {g.id: (g.owner_id, g.package_tier) for g in grids}
    fill   = _dd(int)              # (owner,tier) -> seats already present
    seated = set()                 # (owner,tier,member)
    for gp in db.query(GridPosition.grid_id, GridPosition.member_id).all():
        meta = grid_meta.get(gp.grid_id)
        if not meta:
            continue
        owner, tier = meta
        fill[(owner, tier)] += 1
        seated.add((owner, tier, gp.member_id))
    preexisting_total = sum(fill.values())

    # ── Replay historical buyers ADDITIVELY (skip already-seated) ──
    new_seats = []                 # (owner,tier,member) to insert
    own_grids = set(events)
    overfull = set()
    for buyer, tier in events:
        if tier not in _PKG:
            continue
        cur, seen, steps = buyer, set(), 0
        while True:
            anc = sponsor_of.get(cur)
            if not anc or anc in seen:
                break
            seen.add(anc)
            if anc != buyer and (anc, tier, buyer) not in seated:
                if fill[(anc, tier)] >= _TOTAL:
                    overfull.add((anc, tier))
                else:
                    new_seats.append((anc, tier, buyer))
                    seated.add((anc, tier, buyer))
                    fill[(anc, tier)] += 1
            cur = anc
            steps += 1
            if depth_cap and steps >= depth_cap:
                break

    # ── Checksum vs surviving revenue_total ──
    surviving_rev = _dd(_Dec)
    for g in db.query(Grid.owner_id, Grid.package_tier, Grid.revenue_total).all():
        surviving_rev[(g.owner_id, g.package_tier)] += _Dec(str(g.revenue_total or 0))
    checks, mismatches, no_baseline = [], [], []
    for (owner, tier) in sorted(set(fill.keys()) | set(surviving_rev.keys()) | own_grids):
        final_seats = fill.get((owner, tier), 0)
        recon_rev = _Dec(str(_PKG.get(tier, 0))) * final_seats
        surv = surviving_rev.get((owner, tier), _Dec(0))
        if surv == 0 and final_seats == 0:
            continue
        if recon_rev == surv:        status = "match"
        elif final_seats == 0:       status = "surviving_only_no_buyers"
        elif surv == 0:              status = "no_surviving_baseline"
        elif recon_rev > surv:       status = "reconstructed_exceeds_surviving"
        else:                        status = "reconstructed_below_surviving"
        row = {"owner_id": owner, "username": uname_of.get(owner), "tier": tier,
               "final_seats": final_seats, "final_revenue": float(recon_rev),
               "surviving_revenue": float(surv), "status": status}
        checks.append(row)
        if status in ("reconstructed_below_surviving", "reconstructed_exceeds_surviving"):
            mismatches.append(row)
        elif status == "no_surviving_baseline":
            no_baseline.append(row)

    fill_summary = sorted([{"owner_id": o, "username": uname_of.get(o), "tier": t, "seats": n}
                           for (o, t), n in fill.items() if n > 0],
                          key=lambda x: (-x["seats"], x["owner_id"]))

    if not apply:
        return JSONResponse({
            "mode": "dry_run",
            "historical_placement_events": len(events),
            "preexisting_positions_live_or_survivor": preexisting_total,
            "new_positions_to_add": len(new_seats),
            "final_total_positions": preexisting_total + len(new_seats),
            "own_grids_flagged_purchased": len(own_grids),
            "overfull_grids_need_advance_review": sorted([f"{o}:{t}" for o, t in overfull]),
            "checksum": {"compared": len(checks), "real_mismatches": len(mismatches),
                         "no_surviving_baseline_benign": len(no_baseline),
                         "mismatch_detail": mismatches[:40]},
            "fill_summary_top": fill_summary[:40],
            "note": ("Dry-run — nothing written. ADDITIVE + idempotent: live purchases "
                     "(e.g. 451) are preserved, only missing historical seats are added, "
                     "and every grid's counters are recomputed from its actual rows. "
                     "real_mismatches that are owner_id 1 = stale company-root counter the "
                     "recompute will correct. ?apply=1&code=YOUR_2FA to write. No "
                     "commissions/bonuses/emails."),
        })

    # ── APPLY (2FA-gated, non-destructive) ──
    if not getattr(user, "totp_secret", None):
        return JSONResponse({"error": "Admin has no 2FA configured"}, status_code=400)
    if not pyotp.TOTP(user.totp_secret).verify(code.strip(), valid_window=1):
        return JSONResponse({"error": "Invalid or missing 2FA code — pass ?code=NNNNNN"}, status_code=403)

    # resolve/create one active grid per (owner,tier); set owner_purchased on buyers
    grid_id_of, slot_counter = {}, _dd(int)
    def _grid_for(owner, tier):
        if (owner, tier) in grid_id_of:
            return grid_id_of[(owner, tier)]
        g = (db.query(Grid).filter(Grid.owner_id == owner, Grid.package_tier == tier,
                                   Grid.is_complete == False)
             .order_by(Grid.advance_number.asc(), Grid.id.asc()).first())
        if not g:
            g = Grid(owner_id=owner, package_tier=tier, package_price=_PKG.get(tier, 0),
                     advance_number=1, positions_filled=0, revenue_total=0,
                     bonus_pool_accrued=0, is_complete=False, owner_purchased=False)
            db.add(g); db.flush()
        grid_id_of[(owner, tier)] = g.id
        # seed slot counter from actual current rows in this grid
        slot_counter[(owner, tier)] = db.query(GridPosition).filter(
            GridPosition.grid_id == g.id).count()
        return g.id

    # mark real buyers' own grids purchased
    for (owner, tier) in own_grids:
        gid = _grid_for(owner, tier)
        gobj = db.query(Grid).filter(Grid.id == gid).first()
        if gobj and not gobj.owner_purchased:
            gobj.owner_purchased = True

    # insert new historical seats at the next open slot (after existing live seats)
    inserted = 0
    for owner, tier, member in new_seats:
        gid = _grid_for(owner, tier)
        idx = slot_counter[(owner, tier)]
        db.add(GridPosition(grid_id=gid, member_id=member,
                            grid_level=idx // _W + 1, position_num=idx % _W + 1,
                            is_overspill=True))
        slot_counter[(owner, tier)] += 1
        inserted += 1
    db.flush()

    # recompute denormalised counters from ACTUAL rows for every grid (doctrine)
    recomputed = 0
    for g in db.query(Grid).all():
        cnt = db.query(GridPosition).filter(GridPosition.grid_id == g.id).count()
        price = _Dec(str(_PKG.get(g.package_tier, 0)))
        g.positions_filled = cnt
        g.revenue_total = price * cnt
        target = _Dec(str(_policy_bonus_target(g.package_tier, g.total_seats)))
        accrued = (price * cnt) * _Dec(str(_bpf(g.total_seats)))
        g.bonus_pool_accrued = min(target, accrued) if target > 0 else accrued
        recomputed += 1
    db.commit()

    return JSONResponse({
        "mode": "applied",
        "new_positions_inserted": inserted,
        "preexisting_positions_preserved": preexisting_total,
        "grids_counters_recomputed": recomputed,
        "own_grids_marked_purchased": len(own_grids),
        "note": ("Grid matrix reconstructed non-destructively. Live purchases preserved; "
                 "missing historical seats added; all grid counters recomputed from actual "
                 "rows. No commissions, bonuses, or emails fired. Active-network counts "
                 "recompute on next read (60s cache)."),
    })


@app.get("/admin/api/campaign-tier-restore")
def admin_api_campaign_tier_restore(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    apply: int = 0,
    code: str = "",
    max_seconds: int = 55,
    grant: str = "",
):
    """Fix 'tier active but can't create a video campaign'.

    grant="158:1,205:2" lets the operator restore members they personally
    confirm paid but whose purchase left NO machine record (wiped order, not in
    Stripe, no grid-earnings signal). Format is user_id:tier. Still 2FA-gated.

    Campaign creation is gated by get_user_highest_tier() = the member's highest
    ACTIVE (incomplete) grid. The breach wiped grids; recovery could only rebuild
    them for purchases recorded in the DB — and most weren't (Stripe never wrote
    stripe_charges; crypto fell to orphans). So members who really paid for a
    tier have no grid -> tier resolves to 0 -> campaign creation blocked, and the
    boot cleanup paused the campaigns they already had.

    This determines each member's paid tier from settled-money truth (Stripe
    campaign_tier charges + confirmed WalletConnect grid orders), finds those
    with NO active grid, and (on apply) creates their owner grid at that tier and
    reactivates their paused_no_tier campaigns. NO commissions/bonuses fire —
    those already paid at original purchase. Mirrors the grid-root-restore
    direct-creation pattern.

    apply=0 (default) = READ-ONLY dry run. apply=1 requires ?code=NNNNNN (2FA)."""
    _require_admin(user)
    from .database import (Grid, VideoCampaign, User as _U,
                           GRID_PACKAGES as _PKG, WalletConnectPaymentOrder)
    from datetime import datetime as _dt
    import time as _time, re as _re

    _price_to_tier = {}
    for _t, _p in (_PKG or {}).items():
        try:
            _price_to_tier[round(float(_p), 2)] = _t
        except Exception:
            pass

    paid_tier = {}   # uid -> highest paid campaign tier
    evidence = {}    # uid -> evidence strings

    def _bump(uid, tier, ev):
        if not uid or not tier:
            return
        if tier > paid_tier.get(uid, 0):
            paid_tier[uid] = tier
        evidence.setdefault(uid, []).append(ev)

    # ── Crypto: confirmed WalletConnect grid orders ──
    try:
        for o in db.query(WalletConnectPaymentOrder).filter(
                WalletConnectPaymentOrder.status == "confirmed",
                WalletConnectPaymentOrder.product_type == "grid").all():
            m = _re.search(r"(\d+)", o.product_key or "")
            tier = int(m.group(1)) if m else _price_to_tier.get(round(float(o.base_amount or 0), 2), 0)
            _bump(o.user_id, tier, f"WC #{o.id} {o.product_key} (${float(o.base_amount or 0):.2f})")
    except Exception:
        pass

    # ── Stripe: campaign_tier charges (live API truth) ──
    stripe_note = None
    try:
        from . import stripe_service as _ss
        if _ss.is_configured():
            _ss._ensure_sdk()
            import stripe as _stripe
            cparams = {"limit": 100, "type": "charge"}
            t0 = _time.time(); capped = False
            while True:
                if _time.time() - t0 > max_seconds:
                    capped = True
                    break
                page = _stripe.BalanceTransaction.list(**cparams)
                for bt in page.data:
                    src = getattr(bt, "source", None)
                    if not src or not str(src).startswith("ch_"):
                        continue
                    try:
                        ch = _stripe.Charge.retrieve(src)
                    except Exception:
                        continue
                    if not (bool(getattr(ch, "paid", False)) and getattr(ch, "status", "") == "succeeded"):
                        continue
                    if bool(getattr(ch, "refunded", False)):
                        continue
                    md = (ch.metadata.to_dict() if getattr(ch, "metadata", None) else {})
                    if (md.get("product_kind") or "") != "campaign_tier":
                        continue
                    try:
                        uid = int(md.get("superadpro_user_id") or 0)
                    except (TypeError, ValueError):
                        uid = 0
                    try:
                        tier = int(md.get("campaign_tier_id") or 0)
                    except (TypeError, ValueError):
                        tier = 0
                    if not tier:
                        tier = _price_to_tier.get(round((ch.amount or 0) / 100.0, 2), 0)
                    _bump(uid, tier, f"Stripe {ch.id} tier {tier} (${(ch.amount or 0)/100.0:.2f})")
                if getattr(page, "has_more", False) and page.data:
                    cparams["starting_after"] = page.data[-1].id
                else:
                    break
            if capped:
                stripe_note = "Stripe charge walk hit the time cap — re-run; some tier buyers may be missing."
        else:
            stripe_note = "Stripe not configured in this environment (can't read card-paid tiers here)."
    except Exception as e:
        stripe_note = f"Stripe walk error: {type(e).__name__}: {str(e)[:160]}"

    # ── Build target set: paid-tier buyers (auto) + operator grants (manual) ──
    targets = {}      # uid -> {"tier", "source", "evidence"}
    for uid, tier in paid_tier.items():
        targets[uid] = {"tier": tier, "source": "auto_settled_money",
                        "evidence": evidence.get(uid, [])[:6]}

    manual_errors = []
    if grant:
        for pair in grant.split(","):
            pair = pair.strip()
            if not pair:
                continue
            try:
                uid_s, tier_s = pair.split(":")
                guid, gtier = int(uid_s), int(tier_s)
            except (ValueError, TypeError):
                manual_errors.append(f"bad pair '{pair}' — use user_id:tier")
                continue
            if gtier not in (_PKG or {}):
                manual_errors.append(f"user {guid}: invalid tier {gtier} (must be 1-8)")
                continue
            if guid in targets:
                continue  # already covered by auto-detection
            targets[guid] = {"tier": gtier, "source": "manual_operator",
                             "evidence": ["operator-confirmed (no surviving machine record)"]}

    # ── Assess what each target needs: create grid / mark purchased / reactivate ──
    def _assess(uid):
        u = db.query(_U.id, _U.username, _U.is_active).filter(_U.id == uid).first()
        if not u:
            return None
        grid = (db.query(Grid).filter(Grid.owner_id == uid, Grid.is_complete == False)
                .order_by(Grid.package_tier.desc(), Grid.id.asc()).first())
        paused = db.query(VideoCampaign.id, VideoCampaign.title).filter(
            VideoCampaign.user_id == uid,
            VideoCampaign.status == "paused_no_tier").all()
        actions = []
        if grid is None:
            actions.append("create_grid")
        elif not grid.owner_purchased:
            actions.append("mark_owner_purchased")
        if paused:
            actions.append("reactivate_campaigns")
        return {
            "username": u.username, "is_active": bool(u.is_active),
            "current_grid": (None if grid is None else
                             {"tier": grid.package_tier, "owner_purchased": bool(grid.owner_purchased)}),
            "paused_campaigns": [{"id": c.id, "title": c.title} for c in paused],
            "actions": actions,
        }

    candidates = []
    for uid, meta in targets.items():
        st = _assess(uid)
        if st is None:
            if meta["source"] == "manual_operator":
                manual_errors.append(f"user {uid}: not found")
            continue
        if not st["actions"]:
            continue  # already fully fine — nothing to do
        candidates.append({
            "user_id": uid, "username": st["username"], "is_active": st["is_active"],
            "restore_tier": meta["tier"], "tier_price": float((_PKG or {}).get(meta["tier"], 0)),
            "source": meta["source"], "evidence": meta["evidence"],
            "current_grid": st["current_grid"], "actions": st["actions"],
            "campaigns_to_reactivate": st["paused_campaigns"],
        })
    candidates.sort(key=lambda c: (-c["restore_tier"], c["user_id"]))

    base = {
        "generated_at": _dt.utcnow().isoformat(),
        "stripe_note": stripe_note,
        "paid_tier_buyers_found": len(paid_tier),
        "members_needing_fix": len(candidates),
        "manual_grant_errors": manual_errors,
        "campaigns_that_would_reactivate": sum(len(c["campaigns_to_reactivate"]) for c in candidates),
        "candidates": candidates,
    }

    if not apply:
        base["mode"] = "dry_run"
        base["note"] = ("READ-ONLY preview — nothing written. Per member, the planned actions: "
                        "create_grid (no grid at all), mark_owner_purchased (grid exists but "
                        "isn't flagged as a genuine purchase), reactivate_campaigns (campaigns "
                        "stuck in paused_no_tier despite a valid grid — the 'No Tier' badge). "
                        "Re-run with apply=1&code=NNNNNN (2FA) to apply. NO commissions/bonuses fire.")
        return JSONResponse(base)

    # ── APPLY (2FA-gated) ──
    if not getattr(user, "totp_secret", None):
        return JSONResponse({"error": "Admin has no 2FA configured"}, status_code=400)
    import pyotp
    if not code or not pyotp.TOTP(user.totp_secret).verify(code.strip(), valid_window=1):
        return JSONResponse({"error": "Invalid or missing 2FA code — pass ?apply=1&code=NNNNNN"}, status_code=403)

    grids_created = 0
    grids_marked_purchased = 0
    campaigns_reactivated = 0
    details = []
    for c in candidates:
        uid = c["user_id"]
        tier = c["restore_tier"]
        did = []
        grid = (db.query(Grid).filter(Grid.owner_id == uid, Grid.is_complete == False)
                .order_by(Grid.package_tier.desc(), Grid.id.asc()).first())
        if grid is None:
            grid = Grid(owner_id=uid, package_tier=tier, package_price=(_PKG or {}).get(tier, 0),
                        advance_number=1, positions_filled=0, revenue_total=0,
                        bonus_pool_accrued=0, is_complete=False, owner_purchased=True)
            db.add(grid)
            db.flush()
            grids_created += 1
            did.append(f"created Tier-{tier} grid")
        elif not grid.owner_purchased:
            grid.owner_purchased = True
            grids_marked_purchased += 1
            did.append(f"marked existing Tier-{grid.package_tier} grid as purchased")
        n = db.query(VideoCampaign).filter(
            VideoCampaign.user_id == uid,
            VideoCampaign.status == "paused_no_tier").update(
            {VideoCampaign.status: "active"}, synchronize_session=False)
        if n:
            campaigns_reactivated += int(n)
            did.append(f"reactivated {int(n)} campaign(s)")
        details.append({"user_id": uid, "username": c["username"], "did": did})
    db.commit()
    base.update({
        "mode": "applied",
        "grids_created": grids_created,
        "grids_marked_purchased": grids_marked_purchased,
        "campaigns_reactivated": campaigns_reactivated,
        "applied_detail": details,
        "note": ("Done. Grids created where missing, existing grids flagged as genuine "
                 "purchases, paused_no_tier campaigns reactivated. No commissions/bonuses "
                 "fired. Affected members' campaigns are live again and the 'No Tier' badge clears."),
    })
    return JSONResponse(base)


@app.get("/admin/api/reactivate-stuck-campaigns")
def admin_api_reactivate_stuck_campaigns(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    apply: int = 0,
    code: str = "",
):
    """One-shot sweep: reactivate every campaign frozen at paused_no_tier whose
    owner currently holds a genuine (owner_purchased) active grid.

    Root cause: the boot cleanup only ever PAUSES campaigns (active -> paused_no_tier)
    for owners with no active grid; it never un-pauses. After the breach wiped grids
    and they were later restored, those campaigns stayed frozen showing the 'No Tier'
    badge. This clears the whole backlog in one pass while respecting each member's
    tier campaign-limit (won't push anyone over their cap). Campaigns whose owner has
    NO genuine grid are left paused and reported under still_blocked (restore their
    tier first via /admin/api/campaign-tier-restore). NO commissions/bonuses fire.

    apply=0 (default) = READ-ONLY dry run. apply=1 requires ?code=NNNNNN (2FA)."""
    _require_admin(user)
    from .database import (Grid, VideoCampaign, User as _U,
                           CAMPAIGN_TIER_FEATURES as _FEAT)
    from datetime import datetime as _dt
    from collections import defaultdict

    # genuine active tier owners -> their highest purchased, still-incomplete tier
    owner_tier = {}
    for oid, ptier in db.query(Grid.owner_id, Grid.package_tier).filter(
            Grid.owner_purchased == True, Grid.is_complete == False).all():  # noqa: E712
        owner_tier[oid] = max(owner_tier.get(oid, 0), ptier or 0)

    paused = db.query(VideoCampaign.id, VideoCampaign.title, VideoCampaign.user_id).filter(
        VideoCampaign.status == "paused_no_tier").order_by(VideoCampaign.id.asc()).all()

    uname = {u.id: u.username for u in db.query(_U.id, _U.username).filter(
        _U.id.in_([c.user_id for c in paused] or [0])).all()}

    by_owner = defaultdict(list)
    for c in paused:
        by_owner[c.user_id].append(c)

    to_fix, still_blocked, capped = [], [], []
    for uid, camps in by_owner.items():
        tier = owner_tier.get(uid, 0)
        base_row = lambda c: {"campaign_id": c.id, "title": c.title,
                              "user_id": uid, "username": uname.get(uid)}
        if tier <= 0:
            still_blocked.extend(base_row(c) for c in camps)
            continue
        maxc = _FEAT.get(tier, _FEAT[1])["max_campaigns"]
        active_now = db.query(VideoCampaign).filter(
            VideoCampaign.user_id == uid, VideoCampaign.status == "active").count()
        slots = max(0, maxc - active_now)
        for i, c in enumerate(camps):
            if i < slots:
                to_fix.append(base_row(c))
            else:
                capped.append({**base_row(c), "tier": tier, "max_campaigns": maxc,
                               "already_active": active_now})

    base = {
        "generated_at": _dt.utcnow().isoformat(),
        "paused_no_tier_total": len(paused),
        "would_reactivate": len(to_fix),
        "still_blocked_need_grid": len(still_blocked),
        "capped_by_tier_limit": len(capped),
        "to_reactivate": to_fix,
        "still_blocked": still_blocked,
        "capped": capped,
    }

    if not apply:
        base["mode"] = "dry_run"
        base["note"] = ("READ-ONLY. to_reactivate = owner has a genuine purchased grid and a "
                        "free campaign slot; these flip to active on apply. still_blocked = "
                        "owner has no purchased grid (restore tier first via "
                        "/admin/api/campaign-tier-restore?grant=UID:TIER). capped = owner is "
                        "already at their tier's active-campaign limit; they must upgrade or "
                        "pause another. Re-run with apply=1&code=NNNNNN (2FA). NO commissions fire.")
        return JSONResponse(base)

    if not getattr(user, "totp_secret", None):
        return JSONResponse({"error": "Admin has no 2FA configured"}, status_code=400)
    import pyotp
    if not code or not pyotp.TOTP(user.totp_secret).verify(code.strip(), valid_window=1):
        return JSONResponse({"error": "Invalid or missing 2FA code — pass ?apply=1&code=NNNNNN"}, status_code=403)

    ids = [r["campaign_id"] for r in to_fix]
    n = 0
    if ids:
        n = db.query(VideoCampaign).filter(
            VideoCampaign.id.in_(ids),
            VideoCampaign.status == "paused_no_tier").update(
            {VideoCampaign.status: "active"}, synchronize_session=False)
        db.commit()
    base.update({
        "mode": "applied",
        "campaigns_reactivated": int(n or 0),
        "note": ("Done. Every eligible paused_no_tier campaign is active again; the 'No Tier' "
                 "badge clears on refresh. still_blocked members still need their tier restored; "
                 "capped members are at their limit. No commissions fired."),
    })
    return JSONResponse(base)


@app.get("/admin/api/ownership-snapshot")
def admin_api_ownership_snapshot(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    fmt: str = "summary",   # summary | full | csv
):
    """Master record: every registered member, what they own, and who sponsored
    them. Assembled from the live source tables (User.sponsor_id, Grid,
    CreditPackPurchase, membership flags) and cross-checked against all three
    payment rails (Stripe, NOWPayments, WalletConnect). Read-only.

    fmt=summary (default): headline counts + provability gaps (members who own a
        product but have NO payment-rail record) + members with no sponsor.
    fmt=full: full per-member JSON array.
    fmt=csv: downloadable CSV, one row per member — the off-platform backup you
        keep (open in Sheets/Excel)."""
    _require_admin(user)
    from .database import (User as _U, Grid, CreditPackPurchase, StripeCharge,
                           WalletConnectPaymentOrder, NowPaymentsOrder, Payment)
    from sqlalchemy import func as _f
    from datetime import datetime as _dt
    from collections import defaultdict

    users = db.query(
        _U.id, _U.username, _U.email, _U.sponsor_id, _U.pass_up_sponsor_id,
        _U.is_active, _U.is_founding_member, _U.membership_tier,
        _U.membership_price_locked, _U.membership_expires_at,
        _U.membership_billing, _U.stripe_subscription_id, _U.payment_method,
    ).all()
    uname = {u.id: u.username for u in users}

    grids_by_owner = defaultdict(list)
    for g in db.query(Grid.owner_id, Grid.package_tier, Grid.owner_purchased,
                      Grid.is_complete).all():
        grids_by_owner[g.owner_id].append(
            {"tier": g.package_tier, "owner_purchased": bool(g.owner_purchased),
             "is_complete": bool(g.is_complete)})

    packs_by_user = defaultdict(list)
    for p in db.query(CreditPackPurchase.user_id, CreditPackPurchase.pack_key,
                      CreditPackPurchase.credits_awarded, CreditPackPurchase.status).all():
        packs_by_user[p.user_id].append(
            {"pack": p.pack_key, "credits": p.credits_awarded, "status": p.status})

    def _cmap(rows):
        return {r[0]: r[1] for r in rows}
    sc_cnt = _cmap(db.query(StripeCharge.user_id, _f.count(StripeCharge.id))
                   .group_by(StripeCharge.user_id).all())
    wc_cnt = _cmap(db.query(WalletConnectPaymentOrder.user_id, _f.count(WalletConnectPaymentOrder.id))
                   .filter(WalletConnectPaymentOrder.status == "confirmed")
                   .group_by(WalletConnectPaymentOrder.user_id).all())
    np_cnt = _cmap(db.query(NowPaymentsOrder.user_id, _f.count(NowPaymentsOrder.id))
                   .filter(NowPaymentsOrder.status.in_(["confirmed", "finished"]))
                   .group_by(NowPaymentsOrder.user_id).all())
    pay_cnt = _cmap(db.query(Payment.from_user_id, _f.count(Payment.id))
                    .filter(Payment.status == "confirmed")
                    .group_by(Payment.from_user_id).all())

    members = []
    for u in users:
        grids = grids_by_owner.get(u.id, [])
        owned_tiers = sorted({g["tier"] for g in grids if g["owner_purchased"]})
        packs = packs_by_user.get(u.id, [])
        rail = {"stripe": sc_cnt.get(u.id, 0), "nowpayments": np_cnt.get(u.id, 0),
                "walletconnect": wc_cnt.get(u.id, 0), "payments_tbl": pay_cnt.get(u.id, 0)}
        owns_product = bool(owned_tiers) or bool(packs) or bool(u.is_active)
        has_rail = any(rail.values())
        members.append({
            "user_id": u.id, "username": u.username, "email": u.email,
            "sponsor_id": u.sponsor_id, "sponsor_username": uname.get(u.sponsor_id),
            "pass_up_sponsor_id": u.pass_up_sponsor_id,
            "is_active": bool(u.is_active), "is_founding_member": bool(u.is_founding_member),
            "membership_tier": u.membership_tier,
            "price_locked": (float(u.membership_price_locked)
                             if u.membership_price_locked is not None else None),
            "membership_expires_at": (u.membership_expires_at.isoformat()
                                      if u.membership_expires_at else None),
            "membership_billing": u.membership_billing,
            "has_stripe_sub": bool(u.stripe_subscription_id),
            "payment_method": u.payment_method,
            "tiers_owned": owned_tiers, "credit_packs": packs, "rail_records": rail,
            "owns_product": owns_product,
            "payment_record_present": (has_rail if owns_product else None),
        })

    if fmt == "csv":
        import csv, io
        buf = io.StringIO()
        w = csv.writer(buf)
        w.writerow(["user_id", "username", "email", "sponsor_id", "sponsor_username",
                    "pass_up_sponsor_id", "is_active", "is_founding_member", "membership_tier",
                    "price_locked", "membership_expires_at", "membership_billing", "has_stripe_sub",
                    "payment_method", "tiers_owned", "credit_packs", "stripe_recs",
                    "nowpayments_recs", "walletconnect_recs", "payments_tbl_recs",
                    "owns_product", "payment_record_present"])
        for m in members:
            w.writerow([
                m["user_id"], m["username"], m["email"], m["sponsor_id"], m["sponsor_username"] or "",
                m["pass_up_sponsor_id"] or "", m["is_active"], m["is_founding_member"],
                m["membership_tier"], "" if m["price_locked"] is None else m["price_locked"],
                m["membership_expires_at"] or "", m["membership_billing"] or "", m["has_stripe_sub"],
                m["payment_method"] or "", ";".join(str(t) for t in m["tiers_owned"]),
                ";".join(f'{p["pack"]}({p["credits"]},{p["status"]})' for p in m["credit_packs"]),
                m["rail_records"]["stripe"], m["rail_records"]["nowpayments"],
                m["rail_records"]["walletconnect"], m["rail_records"]["payments_tbl"],
                m["owns_product"], "" if m["payment_record_present"] is None else m["payment_record_present"],
            ])
        from fastapi.responses import Response as _Resp
        return _Resp(content=buf.getvalue(), media_type="text/csv",
                     headers={"Content-Disposition": "attachment; filename=ownership-snapshot.csv"})

    no_sponsor = [{"user_id": m["user_id"], "username": m["username"]}
                  for m in members if not m["sponsor_id"]]
    gaps = [{"user_id": m["user_id"], "username": m["username"], "tiers_owned": m["tiers_owned"],
             "is_active": m["is_active"], "credit_packs": [p["pack"] for p in m["credit_packs"]]}
            for m in members if m["owns_product"] and not any(m["rail_records"].values())]

    summary = {
        "generated_at": _dt.utcnow().isoformat(),
        "members_total": len(members),
        "members_active": sum(1 for m in members if m["is_active"]),
        "tier_owners": sum(1 for m in members if m["tiers_owned"]),
        "credit_pack_owners": sum(1 for m in members if m["credit_packs"]),
        "members_without_sponsor": len(no_sponsor),
        "provability_gaps_count": len(gaps),
        "note": ("provability_gaps = members who OWN a product (active membership, a purchased "
                 "tier, or a credit pack) but have ZERO record on any of the three payment rails "
                 "— holdings whose money-in record was wiped and needs backfilling. Load "
                 "?fmt=csv for the full downloadable master record (one row per member: ownership "
                 "+ sponsor) — that file is your off-platform backup. ?fmt=full for JSON."),
        "members_without_sponsor_sample": no_sponsor[:50],
        "provability_gaps_sample": gaps[:50],
    }
    if fmt == "full":
        summary["members"] = members
    return JSONResponse(summary)


@app.get("/admin/api/stripe-charge-backfill")
def admin_api_stripe_charge_backfill(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    apply: int = 0,
    code: str = "",
    max_seconds: int = 45,
    charge_cursor: str = "",
):
    """Rebuild the stripe_charges audit trail from Stripe's live ledger — the
    record-only backfill for the webhook-miss recording leak.

    Walks every settled, non-refunded Stripe charge (same proven BalanceTransaction
    walk as stripe-tier-credit-recovery), resolves the buyer — metadata
    superadpro_user_id first, then charge.customer -> User.stripe_customer_id for
    the membership invoice charges that carry no charge-level metadata — and the
    product, then writes the missing StripeCharge rows with their REAL ch_/pi_ ids
    so the books match settled money and future reconcile diffs work.

    RECORD-ONLY: writes audit rows only. Fires NO commissions, grants NO
    entitlements, touches NO balances. Idempotent — skips any charge already in
    stripe_charges by charge_id. Never writes a row it can't attribute to a user.

    apply=0 (default) = READ-ONLY dry run. apply=1 requires ?code=NNNNNN (2FA).
    If time_capped, re-run with ?charge_cursor=<resume_cursor> to continue."""
    _require_admin(user)
    from .database import StripeCharge, User as _U
    from datetime import datetime as _dt
    try:
        from . import stripe_service as _ss
        if not _ss.is_configured():
            return JSONResponse({"error": "stripe not configured in env"}, status_code=200)
        _ss._ensure_sdk()
        import stripe as _stripe
        import time as _time
    except Exception as e:
        return JSONResponse({"error": f"stripe init failed: {type(e).__name__}"}, status_code=200)

    existing_ids = {r[0] for r in db.query(StripeCharge.stripe_charge_id)
                    .filter(StripeCharge.stripe_charge_id.isnot(None)).all()}

    def _resolve_product(pk, u):
        if pk and pk != "unknown":
            return pk
        if u is not None and getattr(u, "stripe_subscription_id", None):
            return "founder_renewal" if getattr(u, "is_founding_member", False) else "membership_renewal"
        if u is not None:
            return "membership"
        return "unknown"

    to_write, skipped_exists, unattributed = [], [], []
    scanned = charges_read = 0
    hit_cap = False
    resume_cursor = ""
    _t0 = _time.time()
    params = {"limit": 100}
    if charge_cursor:
        params["starting_after"] = charge_cursor
    try:
        while True:
            if _time.time() - _t0 > max_seconds:
                hit_cap = True
                break
            page = _stripe.Charge.list(**params)
            for ch in page.data:
                scanned += 1
                charges_read += 1
                paid = bool(getattr(ch, "paid", False)) and getattr(ch, "status", "") == "succeeded"
                refunded = bool(getattr(ch, "refunded", False))
                if not paid or refunded:
                    continue
                if ch.id in existing_ids:
                    skipped_exists.append(ch.id)
                    continue
                md = (ch.metadata.to_dict() if getattr(ch, "metadata", None) else {})
                pk = md.get("product_kind") or "unknown"
                try:
                    uid = int(md.get("superadpro_user_id") or 0)
                except (TypeError, ValueError):
                    uid = 0
                u = db.query(_U).filter(_U.id == uid).first() if uid else None
                if u is None:
                    cust = getattr(ch, "customer", None)
                    if cust:
                        u = db.query(_U).filter(_U.stripe_customer_id == str(cust)).first()
                if u is None:
                    # Subscription-renewal charges often carry no charge-level
                    # metadata, and the 3-Jun breach wiped many stripe_customer_id
                    # values — so the two paths above miss them. The live truth we
                    # DO still hold is User.stripe_subscription_id, so bridge the
                    # charge -> invoice -> subscription -> user. This is what
                    # recovers the active Stripe subscribers (has_stripe_sub=true)
                    # that showed zero stripe rail records.
                    inv_id = getattr(ch, "invoice", None)
                    if inv_id:
                        try:
                            _inv = _stripe.Invoice.retrieve(str(inv_id))
                            _sub = getattr(_inv, "subscription", None)
                            if _sub:
                                u = db.query(_U).filter(
                                    _U.stripe_subscription_id == str(_sub)).first()
                        except Exception:
                            pass
                amt_cents = int(ch.amount or 0)
                if u is None:
                    unattributed.append({"charge_id": ch.id, "usd": amt_cents / 100.0,
                                         "customer": str(getattr(ch, "customer", "") or ""),
                                         "metadata_product": pk})
                    continue
                product = _resolve_product(pk, u)
                to_write.append({
                    "charge_id": ch.id,
                    "payment_intent": getattr(ch, "payment_intent", None),
                    "user_id": u.id, "username": u.username,
                    "product": product, "usd": amt_cents / 100.0, "amount_cents": amt_cents,
                    "currency": getattr(ch, "currency", "usd") or "usd",
                    "created_ts": int(getattr(ch, "created", 0) or 0),
                    "sub_id": (getattr(u, "stripe_subscription_id", None)
                               if product in ("membership", "membership_renewal", "founder_renewal") else None),
                })
            if getattr(page, "has_more", False) and page.data:
                params["starting_after"] = page.data[-1].id
                resume_cursor = page.data[-1].id
            else:
                break
    except Exception as e:
        return JSONResponse({"stripe_enum_error": f"{type(e).__name__}: {str(e)[:200]}",
                             "balance_txns_scanned": scanned, "charges_read": charges_read},
                            status_code=200)

    base = {
        "generated_at": _dt.utcnow().isoformat(),
        "balance_txns_scanned": scanned,
        "charges_read": charges_read,
        "time_capped": hit_cap,
        "resume_cursor": resume_cursor if hit_cap else "",
        "rows_to_write": len(to_write),
        "already_present": len(skipped_exists),
        "unattributed": len(unattributed),
        "to_write": to_write,
        "unattributed_sample": unattributed[:30],
    }

    if not apply:
        base["mode"] = "dry_run"
        base["note"] = ("READ-ONLY. to_write = settled Stripe charges absent from stripe_charges, "
                        "resolved to a user (by metadata or stripe_customer_id) — written as "
                        "record-only audit rows with their real ch_/pi_ ids. already_present = "
                        "skipped (idempotent). unattributed = couldn't map to a user — NOT written, "
                        "needs manual attribution. RECORD-ONLY: no commissions, entitlements, or "
                        "balances. Re-run with apply=1&code=NNNNNN to write; if time_capped, re-run "
                        "with charge_cursor=resume_cursor.")
        return JSONResponse(base)

    if not getattr(user, "totp_secret", None):
        return JSONResponse({"error": "Admin has no 2FA configured"}, status_code=400)
    import pyotp
    if not code or not pyotp.TOTP(user.totp_secret).verify(code.strip(), valid_window=1):
        return JSONResponse({"error": "Invalid or missing 2FA code — pass ?apply=1&code=NNNNNN"}, status_code=403)

    written = 0
    for r in to_write:
        try:
            cshare, refundable = _ss.calculate_refundable(r["product"], r["amount_cents"])
        except Exception:
            cshare, refundable = 0, 0
        db.add(StripeCharge(
            user_id=r["user_id"],
            stripe_charge_id=r["charge_id"],
            stripe_payment_intent_id=r["payment_intent"],
            stripe_subscription_id=r["sub_id"],
            kind="charge",
            product=r["product"],
            amount_cents=r["amount_cents"],
            currency=r["currency"],
            company_share_cents=cshare,
            refundable_cents=refundable,
            description=f"Backfilled from Stripe live API {_dt.utcnow().date().isoformat()} (webhook-miss recovery)",
            created_at=(_dt.utcfromtimestamp(r["created_ts"]) if r["created_ts"] else _dt.utcnow()),
        ))
        written += 1
    db.commit()
    base.update({
        "mode": "applied",
        "rows_written": written,
        "note": ("Done. Record-only audit rows written with real charge ids. No commissions, "
                 "entitlements, or balances touched. Re-run the dry run to confirm rows_to_write "
                 "drops to 0 (use charge_cursor if it was time_capped)."),
    })
    return JSONResponse(base)


@app.get("/admin/api/orphan-attribution")
def admin_api_orphan_attribution(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    apply: int = 0,
    code: str = "",
    grant: str = "",   # operator manual: "txhash:user_id,txhash:user_id"
):
    """Attribute unmatched on-chain treasury transfers (OnchainOrphanTransfer) to
    members and record them — the crypto-rail half of the recovery.

    These are real USDT receipts to the treasury that arrived without matching a
    live WalletConnect order (sent directly / after the order expired / a wiped
    order). The inflow is already on record (the orphan row); this resolves WHO
    sent it and writes a Payment so the books attribute it.

    Auto-match (high confidence): orphan amount == a WalletConnect order's
    unique_amount (cent-unique by design) -> that order's user + product.
    Everything else is a worklist grouped by sender wallet with a product guess,
    for manual attribution via grant="txhash:uid,..." (e.g. after asking the
    member which wallet they paid from).

    RECORD-ONLY: writes a Payment row + marks the orphan resolved. Fires NO
    commissions, grants NO entitlements (members already hold them from the
    rebuild), touches NO balances. Idempotent (Payment.tx_hash unique + resolved
    flag). apply=0 dry run; apply=1 requires ?code=NNNNNN (2FA)."""
    _require_admin(user)
    from .database import (OnchainOrphanTransfer as _O, WalletConnectPaymentOrder as _WC,
                           Payment as _P, User as _U)
    from datetime import datetime as _dt
    from collections import defaultdict

    orphans = db.query(_O).filter(_O.resolved == False).all()  # noqa: E712

    # index WC orders by cent-rounded unique_amount -> users (high-confidence key)
    amt_index = defaultdict(list)
    for o in db.query(_WC.id, _WC.user_id, _WC.product_type, _WC.product_key,
                      _WC.unique_amount, _WC.status).all():
        if o.unique_amount is None:
            continue
        amt_index[round(float(o.unique_amount), 2)].append(
            {"user_id": o.user_id, "product_type": o.product_type,
             "product_key": o.product_key, "order_id": o.id, "status": o.status})

    def _product_guess(usd):
        u = round(usd)
        return {15: "membership (founder $15)", 20: "membership ($20) or campaign tier 1",
                50: "campaign tier 2", 100: "tier 3 / nexus pack", 200: "campaign tier 4",
                400: "campaign tier 5", 600: "campaign tier 6", 800: "campaign tier 7",
                1000: "campaign tier 8"}.get(u, "unknown")

    uname = {u.id: u.username for u in db.query(_U.id, _U.username).all()}

    manual = {}
    for pair in (grant or "").split(","):
        pair = pair.strip()
        if not pair:
            continue
        try:
            tx, uid = pair.rsplit(":", 1)
            manual[tx.strip()] = int(uid)
        except (ValueError, TypeError):
            pass

    high, worklist = [], []
    for orp in orphans:
        usd = float(orp.amount_usdt or 0)
        row = {"tx_hash": orp.tx_hash, "from_address": orp.from_address,
               "usd": round(usd, 2), "seen_at": orp.seen_at.isoformat() if orp.seen_at else None}
        matched_uid, matched = None, None
        if orp.tx_hash in manual:
            matched_uid, matched = manual[orp.tx_hash], {"via": "operator_grant"}
        else:
            cands = amt_index.get(round(usd, 2), [])
            uids = {c["user_id"] for c in cands}
            if len(uids) == 1:
                c = cands[0]
                matched_uid = c["user_id"]
                matched = {"via": f"wc_order#{c['order_id']} ({c['status']})",
                           "product_type": c["product_type"], "product_key": c["product_key"]}
        if matched_uid:
            row.update({"user_id": matched_uid, "username": uname.get(matched_uid), "match": matched})
            high.append(row)
        else:
            row["product_guess"] = _product_guess(usd)
            worklist.append(row)

    by_addr = defaultdict(lambda: {"count": 0, "usd": 0.0, "txs": []})
    for w in worklist:
        g = by_addr[w["from_address"]]
        g["count"] += 1
        g["usd"] = round(g["usd"] + w["usd"], 2)
        g["txs"].append({"tx_hash": w["tx_hash"], "usd": w["usd"],
                         "seen_at": w["seen_at"], "product_guess": w["product_guess"]})
    worklist_by_sender = sorted(({"from_address": a, **v} for a, v in by_addr.items()),
                                key=lambda x: -x["usd"])

    base = {
        "generated_at": _dt.utcnow().isoformat(),
        "unresolved_orphans": len(orphans),
        "auto_matched": len(high),
        "auto_matched_usd": round(sum(h["usd"] for h in high), 2),
        "needs_manual": len(worklist),
        "needs_manual_usd": round(sum(w["usd"] for w in worklist), 2),
        "to_attribute": high,
        "worklist_by_sender": worklist_by_sender,
    }

    if not apply:
        base["mode"] = "dry_run"
        base["note"] = ("READ-ONLY. to_attribute = orphan amount matched a WalletConnect order's "
                        "unique_amount (or your grant) -> recorded to that user on apply. "
                        "worklist_by_sender = no order match; grouped by sender wallet with a "
                        "product guess, for manual attribution via grant=\"txhash:userid,...\" "
                        "(ask the member which wallet they paid from). RECORD-ONLY: writes a "
                        "Payment + marks the orphan resolved; no commissions/entitlements/balances. "
                        "apply=1&code=NNNNNN to write.")
        return JSONResponse(base)

    if not getattr(user, "totp_secret", None):
        return JSONResponse({"error": "Admin has no 2FA configured"}, status_code=400)
    import pyotp
    if not code or not pyotp.TOTP(user.totp_secret).verify(code.strip(), valid_window=1):
        return JSONResponse({"error": "Invalid or missing 2FA code — pass ?apply=1&code=NNNNNN"}, status_code=403)

    written = 0
    for h in high:
        orp = db.query(_O).filter(_O.tx_hash == h["tx_hash"], _O.resolved == False).first()  # noqa: E712
        if not orp:
            continue
        mt = h.get("match") or {}
        if db.query(_P).filter(_P.tx_hash == h["tx_hash"]).first():
            orp.resolved = True
            orp.resolution_note = "Payment already existed for tx; marked resolved (recovery)"
            orp.resolved_at = _dt.utcnow()
            orp.resolved_by_user_id = h["user_id"]
            continue
        ptype = f"onchain_{mt['product_type']}" if mt.get("product_type") else "onchain_attributed"
        db.add(_P(from_user_id=h["user_id"], to_user_id=None, amount_usdt=h["usd"],
                  payment_type=ptype, tx_hash=h["tx_hash"], status="confirmed",
                  created_at=orp.seen_at or _dt.utcnow()))
        orp.resolved = True
        orp.resolution_note = f"Attributed to user {h['user_id']} via {mt.get('via', 'match')} (recovery backfill)"
        orp.resolved_at = _dt.utcnow()
        orp.resolved_by_user_id = h["user_id"]
        written += 1
    db.commit()
    base.update({
        "mode": "applied",
        "payments_written": written,
        "note": ("Done. Record-only Payment rows written for attributed orphans + those orphans "
                 "marked resolved. No commissions/entitlements/balances. Re-run dry run; "
                 "worklist_by_sender shows what still needs grant=txhash:uid."),
    })
    return JSONResponse(base)


@app.get("/admin/api/onchain-historical-reconcile")
def admin_api_onchain_historical_reconcile(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    apply: int = 0,
    code: str = "",
    user_ids: str = "196,181,290,205,325,365,374,352,228,351",
    pre_min: int = 30,
    post_min: int = 5,
    amount_tol: float = 1.0,
    max_seconds: int = 90,
):
    """Reconstruct breach-wiped direct-WalletConnect membership payments by reading
    the treasury's on-chain USDT inbound history around each member's activation.

    The 3-Jun breach wiped the WalletConnectPaymentOrder rows (tx_hash + from_address)
    for members who paid by direct WC, so those members show ZERO record on any rail
    despite being active payers. Their payment is still permanently on-chain: a USDT
    transfer to the treasury landing seconds-to-minutes before their activation. For
    each target member this scans treasury inbound USDT in a tight window around
    activated_at, drops anything already attributed (Payment / WC order / orphan), and
    matches the unattributed transfer closest in time before activation whose amount
    ~= the membership price the member pays (founders pay $15).

    RECORD-ONLY: writes a Payment(status=confirmed, payment_type=onchain_membership)
    with the REAL tx_hash. Fires NO commissions, grants NO entitlements (members
    already hold their membership), touches NO balances. Idempotent (Payment.tx_hash
    is unique + we re-check before insert).

    Reads BSC via BSC_RPC_URL (the Alchemy endpoint already in Railway) with an
    adaptive getLogs span that backs off on 'limit exceeded'. apply=0 (default) =
    READ-ONLY dry run; apply=1 requires ?code=NNNNNN (2FA). If time_capped, re-run
    with the remaining ids in user_ids (dry run is idempotent; apply dedups by tx)."""
    _require_admin(user)
    from .database import (Payment as _P, WalletConnectPaymentOrder as _WC,
                           OnchainOrphanTransfer as _O, User as _U)
    from datetime import datetime as _dt, timezone as _tz
    import time as _time
    try:
        from .walletconnect_payments import _get_treasury_transfers_single_provider as _scan
        from .withdrawals import BSC_RPC_URL
        import urllib.request as _urlreq, json as _json
    except Exception as e:
        return JSONResponse({"error": f"bsc init failed: {type(e).__name__}: {e}"}, status_code=200)

    try:
        ids = [int(x) for x in user_ids.split(",") if x.strip()]
    except ValueError:
        return JSONResponse({"error": "user_ids must be comma-separated integers"}, status_code=200)

    # Raw JSON-RPC for block lookups — bypasses web3's PoA extraData header
    # validation (BSC is proof-of-authority; web3.eth.get_block raises
    # ExtraDataLengthError without the PoA middleware). getLogs goes through the
    # scanner's _scan, which doesn't parse headers, so it's unaffected.
    def _rpc(method, params, timeout=20):
        body = _json.dumps({"jsonrpc": "2.0", "id": 1, "method": method, "params": params}).encode()
        req = _urlreq.Request(BSC_RPC_URL, data=body, headers={"Content-Type": "application/json"})
        with _urlreq.urlopen(req, timeout=timeout) as r:
            out = _json.loads(r.read())
        if "result" not in out:
            raise RuntimeError(f"rpc {method} error: {str(out.get('error'))[:120]}")
        return out["result"]

    try:
        head = int(_rpc("eth_blockNumber", []), 16)
    except Exception as e:
        return JSONResponse({"error": f"BSC RPC unreachable via BSC_RPC_URL: {type(e).__name__}: {str(e)[:120]}"}, status_code=200)

    # already-attributed tx hashes across every rail that records one
    attributed = set()
    for (h,) in db.query(_P.tx_hash).filter(_P.tx_hash.isnot(None)).all():
        attributed.add(str(h).lower())
    for (h,) in db.query(_WC.tx_hash).filter(_WC.tx_hash.isnot(None)).all():
        attributed.add(str(h).lower())
    for (h,) in db.query(_O.tx_hash).filter(_O.tx_hash.isnot(None)).all():
        attributed.add(str(h).lower())

    # memoised block-timestamp lookups (BSC has no native ts->block)
    _bts = {}
    def blk_ts(n):
        n = int(n)
        if n not in _bts:
            _bts[n] = int(_rpc("eth_getBlockByNumber", [hex(n), False])["timestamp"], 16)
        return _bts[n]

    try:
        head_ts = blk_ts(head)
        _samp = max(1, head - 5_000_000)
        avg_bt = max(0.1, (head_ts - blk_ts(_samp)) / max(1, (head - _samp)))
    except Exception as e:
        return JSONResponse({"error": f"block calibration failed: {type(e).__name__}: {str(e)[:120]}"}, status_code=200)

    def block_at(ts_target):
        est = int(head - (head_ts - ts_target) / avg_bt)
        lo = max(1, est - 150_000)
        hi = min(head, est + 150_000)
        guard = 0
        while lo > 1 and blk_ts(lo) > ts_target and guard < 60:
            lo = max(1, lo - 150_000); guard += 1
        while hi < head and blk_ts(hi) < ts_target and guard < 120:
            hi = min(head, hi + 150_000); guard += 1
        while lo < hi:
            mid = (lo + hi) // 2
            if blk_ts(mid) < ts_target:
                lo = mid + 1
            else:
                hi = mid
        return lo

    # adaptive getLogs over a block range; learns the max span this RPC serves
    span_state = {"span": 1000}
    def scan_range(b0, b1):
        out, cur, guard = [], int(b0), 0
        b1 = int(b1)
        while cur <= b1 and guard < 5000:
            guard += 1
            span = span_state["span"]
            top = min(cur + span, b1)
            try:
                out.extend(_scan(BSC_RPC_URL, cur, top))
                cur = top + 1
            except Exception as ex:
                msg = str(ex).lower()
                if span > 5 and any(k in msg for k in ("limit", "range", "many", "exceed", "too large")):
                    span_state["span"] = max(5, span // 2)
                    continue
                if span <= 5:
                    cur += 1  # smallest span still failing — skip one block, keep going
                    continue
                raise
        return out

    results, unresolved, processed = [], [], []
    t0 = _time.time()
    for uid in ids:
        if _time.time() - t0 > max_seconds:
            break
        u = db.query(_U).filter(_U.id == uid).first()
        if not u:
            unresolved.append({"user_id": uid, "reason": "user not found"}); continue
        if not u.activated_at:
            unresolved.append({"user_id": uid, "username": u.username, "reason": "no activated_at"}); continue
        processed.append(uid)
        try:
            price = float(u.membership_price_locked) if u.membership_price_locked else (15.0 if u.is_founding_member else 20.0)
        except (TypeError, ValueError):
            price = 15.0 if u.is_founding_member else 20.0
        act = u.activated_at
        act_ts = int(act.replace(tzinfo=_tz.utc).timestamp()) if act.tzinfo is None else int(act.timestamp())
        try:
            b_lo = block_at(act_ts - pre_min * 60)
            b_hi = block_at(act_ts + post_min * 60)
            transfers = scan_range(b_lo, b_hi)
        except Exception as ex:
            unresolved.append({"user_id": uid, "username": u.username, "reason": f"scan failed: {type(ex).__name__}: {str(ex)[:80]}"})
            continue
        cands = []
        for t in transfers:
            th = str(t["tx_hash"]).lower()
            if th in attributed:
                continue
            amt = float(t["amount_usdt"])
            if abs(amt - price) > amount_tol:
                continue
            try:
                bts = blk_ts(int(t["block_number"]))
            except Exception:
                bts = act_ts
            cands.append({"tx_hash": t["tx_hash"], "from_address": t["from_address"],
                          "amount_usdt": amt, "block_number": int(t["block_number"]),
                          "block_ts": bts, "secs_before_activation": act_ts - bts})
        cands.sort(key=lambda c: abs(c["secs_before_activation"]))
        if not cands:
            unresolved.append({"user_id": uid, "username": u.username, "price": price,
                               "scanned_blocks": [b_lo, b_hi],
                               "reason": "no unattributed ~price transfer in window"})
            continue
        best = cands[0]
        attributed.add(str(best["tx_hash"]).lower())  # prevent double-assign within this run
        results.append({
            "user_id": uid, "username": u.username, "price": price,
            "tx_hash": best["tx_hash"], "from_address": best["from_address"],
            "amount_usdt": round(best["amount_usdt"], 4),
            "block_number": best["block_number"],
            "paid_at": _dt.utcfromtimestamp(best["block_ts"]).isoformat(),
            "paid_ts": best["block_ts"],
            "secs_before_activation": best["secs_before_activation"],
            "product": "onchain_membership",
            "other_candidates_in_window": len(cands) - 1,
        })

    base = {
        "generated_at": _dt.utcnow().isoformat(),
        "targets": ids,
        "processed": processed,
        "time_capped": (_time.time() - t0 > max_seconds),
        "matched": len(results),
        "unresolved": len(unresolved),
        "getlogs_span_used": span_state["span"],
        "to_write": results,
        "unresolved_detail": unresolved,
    }

    if not apply:
        base["mode"] = "dry_run"
        base["note"] = ("READ-ONLY. Reads the treasury's on-chain USDT inbound around each "
                        "member's activation via BSC_RPC_URL. to_write = an unattributed transfer "
                        "(~membership price) landing just before activation -> the breach-wiped "
                        "direct-WC payment. unresolved = no matching transfer found in window "
                        "(widen pre_min / amount_tol, or the member was genuinely comped). "
                        "RECORD-ONLY on apply: writes Payment(status=confirmed) with the real "
                        "tx_hash; NO commissions/entitlements/balances. apply=1&code=NNNNNN to "
                        "write. If time_capped, re-run with the remaining user_ids.")
        return JSONResponse(base)

    if not getattr(user, "totp_secret", None):
        return JSONResponse({"error": "Admin has no 2FA configured"}, status_code=400)
    import pyotp
    if not code or not pyotp.TOTP(user.totp_secret).verify(code.strip(), valid_window=1):
        return JSONResponse({"error": "Invalid or missing 2FA code — pass ?apply=1&code=NNNNNN"}, status_code=403)

    written = 0
    for r in results:
        if db.query(_P).filter(_P.tx_hash == r["tx_hash"]).first():
            continue
        db.add(_P(from_user_id=r["user_id"], to_user_id=None,
                  amount_usdt=r["amount_usdt"], payment_type=r["product"],
                  tx_hash=r["tx_hash"], status="confirmed",
                  created_at=_dt.utcfromtimestamp(r["paid_ts"])))
        written += 1
    db.commit()
    base.update({
        "mode": "applied",
        "payments_written": written,
        "note": ("Done. Record-only Payment rows written with real on-chain tx hashes. No "
                 "commissions/entitlements/balances touched. Re-run the dry run to confirm "
                 "matched transfers now show as attributed (they'll drop out)."),
    })
    return JSONResponse(base)


@app.get("/admin/api/treasury-scan")
def admin_api_treasury_scan(
    request: Request,
    after: str,
    before: str,
    max_seconds: int = 70,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """READ-ONLY forensic: list every USDT inbound to the treasury between two
    timestamps, flagging which are already attributed and which are orphaned.

    Used to recover breach-wiped direct payments whose order row no longer
    exists: scan a tight window around a member's signup/activation and look
    for an UNATTRIBUTED ~price transfer — that's their lost payment. Keep the
    window tight (a few hours) so the getLogs scan stays cheap.

    after / before: ISO timestamps (e.g. 2026-05-25T04:00:00). No writes.
    """
    _require_admin(user)
    from .database import (Payment as _P, WalletConnectPaymentOrder as _WC,
                           OnchainOrphanTransfer as _O)
    from datetime import datetime as _dt, timezone as _tz
    import time as _time
    try:
        from .walletconnect_payments import _get_treasury_transfers_single_provider as _scan
        from .withdrawals import BSC_RPC_URL
        import urllib.request as _urlreq, json as _json
    except Exception as e:
        return JSONResponse({"error": f"bsc init failed: {type(e).__name__}: {e}"}, status_code=200)

    def _parse(ts):
        ts = ts.strip().replace("Z", "")
        for fmt in ("%Y-%m-%dT%H:%M:%S", "%Y-%m-%dT%H:%M", "%Y-%m-%d %H:%M:%S", "%Y-%m-%d"):
            try:
                return int(_dt.strptime(ts, fmt).replace(tzinfo=_tz.utc).timestamp())
            except ValueError:
                pass
        return None
    ts_after, ts_before = _parse(after), _parse(before)
    if ts_after is None or ts_before is None:
        return JSONResponse({"error": "after/before must be ISO e.g. 2026-05-25T04:00:00"}, status_code=400)
    if ts_before <= ts_after:
        return JSONResponse({"error": "before must be after after"}, status_code=400)

    def _rpc(method, params, timeout=20):
        body = _json.dumps({"jsonrpc": "2.0", "id": 1, "method": method, "params": params}).encode()
        req = _urlreq.Request(BSC_RPC_URL, data=body, headers={"Content-Type": "application/json"})
        with _urlreq.urlopen(req, timeout=timeout) as r:
            out = _json.loads(r.read())
        if "result" not in out:
            raise RuntimeError(f"rpc {method} error: {str(out.get('error'))[:120]}")
        return out["result"]

    try:
        head = int(_rpc("eth_blockNumber", []), 16)
    except Exception as e:
        return JSONResponse({"error": f"BSC RPC unreachable: {type(e).__name__}: {str(e)[:120]}"}, status_code=200)

    _bts = {}
    def blk_ts(n):
        n = int(n)
        if n not in _bts:
            _bts[n] = int(_rpc("eth_getBlockByNumber", [hex(n), False])["timestamp"], 16)
        return _bts[n]

    try:
        head_ts = blk_ts(head)
        _samp = max(1, head - 5_000_000)
        avg_bt = max(0.1, (head_ts - blk_ts(_samp)) / max(1, (head - _samp)))
    except Exception as e:
        return JSONResponse({"error": f"block calibration failed: {type(e).__name__}: {str(e)[:120]}"}, status_code=200)

    def block_at(ts_target):
        est = int(head - (head_ts - ts_target) / avg_bt)
        lo = max(1, est - 150_000); hi = min(head, est + 150_000); guard = 0
        while lo > 1 and blk_ts(lo) > ts_target and guard < 60:
            lo = max(1, lo - 150_000); guard += 1
        while hi < head and blk_ts(hi) < ts_target and guard < 120:
            hi = min(head, hi + 150_000); guard += 1
        while lo < hi:
            mid = (lo + hi) // 2
            if blk_ts(mid) < ts_target:
                lo = mid + 1
            else:
                hi = mid
        return lo

    span_state = {"span": 1000}
    def scan_range(b0, b1):
        out, cur, guard = [], int(b0), 0
        b1 = int(b1)
        while cur <= b1 and guard < 5000:
            guard += 1
            span = span_state["span"]
            top = min(cur + span, b1)
            try:
                out.extend(_scan(BSC_RPC_URL, cur, top)); cur = top + 1
            except Exception as ex:
                msg = str(ex).lower()
                if span > 5 and any(k in msg for k in ("limit", "range", "many", "exceed", "too large")):
                    span_state["span"] = max(5, span // 2); continue
                if span <= 5:
                    cur += 1; continue
                raise
        return out

    # attribution maps
    pay_tx = {str(h).lower(): (pt or "payment") for (h, pt) in
              db.query(_P.tx_hash, _P.payment_type).filter(_P.tx_hash.isnot(None)).all()}
    wc_tx = {str(h).lower(): uid for (h, uid) in
             db.query(_WC.tx_hash, _WC.user_id).filter(_WC.tx_hash.isnot(None)).all()}
    orph_tx = {str(r.tx_hash).lower(): r for r in
               db.query(_O).filter(_O.tx_hash.isnot(None)).all()}

    t0 = _time.time()
    try:
        b_lo = block_at(ts_after); b_hi = block_at(ts_before)
        transfers = scan_range(b_lo, b_hi)
    except Exception as ex:
        return JSONResponse({"error": f"scan failed: {type(ex).__name__}: {str(ex)[:120]}"}, status_code=200)

    rows, unattributed = [], 0
    for t in transfers:
        th = str(t["tx_hash"]).lower()
        try:
            bts = blk_ts(int(t["block_number"]))
        except Exception:
            bts = None
        if th in pay_tx:
            attr = f"payment:{pay_tx[th]}"
        elif th in wc_tx:
            attr = f"wc_order:user_{wc_tx[th]}"
        elif th in orph_tx:
            o = orph_tx[th]
            attr = f"orphan:{'resolved' if o.resolved else 'unresolved'}" + (
                f":user_{o.resolved_by_user_id}" if o.resolved_by_user_id else "")
        else:
            attr = "UNATTRIBUTED"; unattributed += 1
        rows.append({
            "tx_hash": t["tx_hash"], "from_address": t["from_address"],
            "amount_usdt": round(float(t["amount_usdt"]), 4),
            "block_number": int(t["block_number"]),
            "ts": _dt.utcfromtimestamp(bts).isoformat() if bts else None,
            "attributed": attr,
        })
    rows.sort(key=lambda r: r["ts"] or "")

    return JSONResponse({
        "window": {"after": after, "before": before},
        "blocks_scanned": [b_lo, b_hi],
        "getlogs_span_used": span_state["span"],
        "time_capped": (_time.time() - t0 > max_seconds),
        "transfers_found": len(rows),
        "unattributed_count": unattributed,
        "transfers": rows,
    })


@app.get("/admin/api/activations-near")
def admin_api_activations_near(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    ts: str = "",
    back_min: int = 5,
    fwd_min: int = 30,
):
    """READ-ONLY. List members whose activated_at falls in [ts - back_min, ts + fwd_min],
    checking EVERY payment rail (Payment / StripeCharge / NowPaymentsOrder) so the one
    with no surviving record stands out.

    Purpose: map an UNATTRIBUTED on-chain treasury transfer (surfaced by treasury-scan)
    back to the member who sent it. A breach-wiped direct-WalletConnect payer activates
    seconds-to-minutes AFTER their USDT lands, so the member activating just after the
    transfer's timestamp with no payment on any rail is the owner. Feed that user_id to
    /admin/api/onchain-historical-reconcile to record the wiped payment. Also reusable
    for breach-wiped campaign-tier payments (anchor on GridPosition.created_at)."""
    _require_admin(user)
    from .database import (Payment as _P, StripeCharge as _SC,
                           NowPaymentsOrder as _NP, User as _U)
    from datetime import datetime as _dt, timezone as _tz, timedelta as _td
    if not ts:
        return JSONResponse({"error": "ts required (ISO, e.g. 2026-05-15T16:08:30Z)"}, status_code=200)
    try:
        anchor = _dt.fromisoformat(ts.replace("Z", "+00:00")).astimezone(_tz.utc).replace(tzinfo=None)
    except ValueError:
        return JSONResponse({"error": "ts not ISO-parseable (use e.g. 2026-05-15T16:08:30Z)"}, status_code=200)
    lo = anchor - _td(minutes=back_min)
    hi = anchor + _td(minutes=fwd_min)
    members = (db.query(_U)
               .filter(_U.activated_at.isnot(None),
                       _U.activated_at >= lo, _U.activated_at <= hi)
               .order_by(_U.activated_at.asc()).all())
    out = []
    for m in members:
        try:
            price = float(m.membership_price_locked) if m.membership_price_locked else (15.0 if m.is_founding_member else 20.0)
        except (TypeError, ValueError):
            price = 15.0 if m.is_founding_member else 20.0
        pays = db.query(_P).filter(_P.from_user_id == m.id).all()
        pay_types = [p.payment_type for p in pays]
        stripe_n = db.query(_SC).filter(_SC.user_id == m.id).count()
        # NOWPayments: only count orders that actually settled (order existence != payment)
        np_paid = (db.query(_NP)
                   .filter(_NP.user_id == m.id,
                           _NP.status.in_(["confirmed", "finished", "partially_paid"]))
                   .count())
        has_any_rail = bool(pays) or stripe_n > 0 or np_paid > 0
        out.append({
            "user_id": m.id,
            "username": m.username,
            "is_founding_member": bool(m.is_founding_member),
            "price": price,
            "activated_at": m.activated_at.isoformat(),
            "secs_after_anchor": int((m.activated_at - anchor).total_seconds()),
            "payment_rows": len(pays),
            "payment_types": pay_types,
            "stripe_charges": stripe_n,
            "nowpayments_settled": np_paid,
            "has_any_rail_record": has_any_rail,
        })
    return JSONResponse({
        "anchor_ts": anchor.isoformat(),
        "window": [lo.isoformat(), hi.isoformat()],
        "member_count": len(out),
        "members": out,
        "note": ("READ-ONLY. Members activated in the window, with payment presence on every "
                 "rail. has_any_rail_record=false activating just after an UNATTRIBUTED treasury "
                 "transfer = the breach-wiped direct-WC payer who owns it. Feed that user_id to "
                 "/admin/api/onchain-historical-reconcile to record it."),
    })


@app.get("/admin/api/wallet-trace")
def admin_api_wallet_trace(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    address: str = "",
    days: int = 180,
    from_block: int = 0,
    max_seconds: int = 60,
):
    """READ-ONLY. Trace every USDT payment a given wallet sent to the treasury, and
    name the member behind it.

    Used to attribute an UNATTRIBUTED treasury transfer whose sender we know but
    whose owner we don't (e.g. a breach-wiped RENEWAL — no fresh activation to match
    on time, so activations-near can't find them). A member usually pays from the
    same wallet every time, so if ANY transfer from this wallet is already attributed
    (Payment / WalletConnect order / resolved orphan), that record names the wallet's
    owner — and therefore the owner of the unattributed transfer too.

    Topic-filtered eth_getLogs (Transfer, from=address, to=treasury) — doubly indexed,
    so it returns only this wallet's payments and stays cheap over a wide range.
    Reads BSC via BSC_RPC_URL. apply has no meaning here (pure read)."""
    _require_admin(user)
    from .database import (Payment as _P, WalletConnectPaymentOrder as _WC,
                           OnchainOrphanTransfer as _O, User as _U)
    from datetime import datetime as _dt
    import time as _time, urllib.request as _urlreq, json as _json
    try:
        from .walletconnect_payments import (TRANSFER_EVENT_TOPIC, USDT_CONTRACT_BSC,
                                              TREASURY_ADDRESS_BSC, raw_to_usdt_bsc)
        from .withdrawals import BSC_RPC_URL
    except Exception as e:
        return JSONResponse({"error": f"bsc init failed: {type(e).__name__}: {e}"}, status_code=200)

    addr = (address or "").strip().lower()
    if not (addr.startswith("0x") and len(addr) == 42):
        return JSONResponse({"error": "address required (0x + 40 hex)"}, status_code=200)

    def _rpc(method, params, timeout=25):
        body = _json.dumps({"jsonrpc": "2.0", "id": 1, "method": method, "params": params}).encode()
        req = _urlreq.Request(BSC_RPC_URL, data=body, headers={"Content-Type": "application/json"})
        with _urlreq.urlopen(req, timeout=timeout) as r:
            out = _json.loads(r.read())
        if "result" not in out:
            raise RuntimeError(f"rpc {method} error: {str(out.get('error'))[:120]}")
        return out["result"]

    try:
        head = int(_rpc("eth_blockNumber", []), 16)
    except Exception as e:
        return JSONResponse({"error": f"BSC RPC unreachable: {type(e).__name__}: {str(e)[:120]}"}, status_code=200)

    # BSC ~0.75s/block -> ~115200 blocks/day. Floor the scan unless caller pins from_block.
    lo = int(from_block) if from_block else max(1, head - int(days * 115200))

    # tx_hash -> attribution, across every rail that stores one
    attrib = {}
    uname = {u.id: u.username for u in db.query(_U.id, _U.username).all()}
    for p in db.query(_P.tx_hash, _P.from_user_id, _P.payment_type).filter(_P.tx_hash.isnot(None)).all():
        attrib[str(p.tx_hash).lower()] = {"via": "payment", "user_id": p.from_user_id,
                                          "username": uname.get(p.from_user_id), "detail": p.payment_type}
    for w in db.query(_WC.tx_hash, _WC.user_id, _WC.product_type).filter(_WC.tx_hash.isnot(None)).all():
        attrib.setdefault(str(w.tx_hash).lower(), {"via": "wc_order", "user_id": w.user_id,
                                                   "username": uname.get(w.user_id), "detail": w.product_type})
    for o in db.query(_O.tx_hash, _O.resolved_by_user_id, _O.resolved).filter(_O.tx_hash.isnot(None)).all():
        attrib.setdefault(str(o.tx_hash).lower(), {"via": "orphan",
                                                   "user_id": o.resolved_by_user_id,
                                                   "username": uname.get(o.resolved_by_user_id),
                                                   "detail": f"resolved={bool(o.resolved)}"})

    from_padded = "0x" + addr[2:].zfill(64)
    treasury_padded = "0x" + TREASURY_ADDRESS_BSC[2:].lower().zfill(64)
    usdt = USDT_CONTRACT_BSC if USDT_CONTRACT_BSC.startswith("0x") else "0x" + USDT_CONTRACT_BSC

    span = 500_000  # doubly-indexed filter returns near-zero rows -> wide span is fine
    cur, t0 = lo, _time.time()
    raw_logs, capped = [], False
    while cur <= head:
        if _time.time() - t0 > max_seconds:
            capped = True
            break
        top = min(cur + span, head)
        try:
            logs = _rpc("eth_getLogs", [{
                "fromBlock": hex(cur), "toBlock": hex(top), "address": usdt,
                "topics": [TRANSFER_EVENT_TOPIC, from_padded, treasury_padded],
            }])
            raw_logs.extend(logs)
            cur = top + 1
        except Exception as ex:
            msg = str(ex).lower()
            if span > 2000 and any(k in msg for k in ("limit", "range", "many", "exceed", "large", "response")):
                span = max(2000, span // 2)
                continue
            return JSONResponse({"error": f"getLogs failed: {type(ex).__name__}: {str(ex)[:120]}",
                                 "at_block": cur, "span": span}, status_code=200)

    _bts = {}
    def blk_ts(n):
        n = int(n)
        if n not in _bts:
            try:
                _bts[n] = int(_rpc("eth_getBlockByNumber", [hex(n), False])["timestamp"], 16)
            except Exception:
                _bts[n] = 0
        return _bts[n]

    transfers, attributed_users = [], {}
    for lg in raw_logs:
        try:
            txh = lg.get("transactionHash")
            txh = (txh.hex() if hasattr(txh, "hex") else str(txh)).lower()
            if not txh.startswith("0x"):
                txh = "0x" + txh
            bn = int(lg.get("blockNumber"), 16) if isinstance(lg.get("blockNumber"), str) else int(lg.get("blockNumber"))
            data = lg.get("data", "0x0")
            amt = float(raw_to_usdt_bsc(int(data, 16)))
            a = attrib.get(txh)
            ts = blk_ts(bn)
            row = {"tx_hash": txh, "amount_usdt": round(amt, 4), "block_number": bn,
                   "ts": _dt.utcfromtimestamp(ts).isoformat() if ts else None,
                   "attributed": a or "UNATTRIBUTED"}
            transfers.append(row)
            if a and a.get("user_id"):
                k = a["user_id"]
                attributed_users.setdefault(k, {"user_id": k, "username": a.get("username"), "count": 0})
                attributed_users[k]["count"] += 1
        except Exception:
            continue
    transfers.sort(key=lambda r: r["block_number"])

    return JSONResponse({
        "wallet": addr,
        "scanned_blocks": [lo, head],
        "time_capped": capped,
        "getlogs_span_used": span,
        "transfers_found": len(transfers),
        "transfers": transfers,
        "attributed_owners": list(attributed_users.values()),
        "note": ("READ-ONLY. transfers = every USDT payment this wallet sent the treasury in range. "
                 "attributed_owners = members an already-recorded transfer from this wallet points to "
                 "— the wallet's owner, hence the owner of any UNATTRIBUTED transfer from it. If empty "
                 "and time_capped, re-run with &from_block= an earlier block to scan further back. "
                 "If empty and not capped, this wallet has no other recorded treasury payment "
                 "(can't be named from chain alone)."),
    })


@app.get("/admin/api/nowpayments-backfill")
def admin_api_nowpayments_backfill(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    ids: str = "",
    apply: int = 0,
    code: str = "",
    max_seconds: int = 50,
):
    """Backfill the NOWPayments rail from settled dashboard payments, and resolve
    the matching on-chain treasury orphans in the same pass.

    NOWPayments forwards each member's crypto payment to the treasury, so a
    settled NOWPayments payment shows up on-chain as an unmatched OnchainOrphan
    transfer (the scanner can't tie a NOWPayments payout to a WC order). The
    dashboard Order ID encodes the member (SAP-<uid>-<n>) and the API gives the
    product + settled outcome amount. So per settled payment id we:
      - write the canonical NowPaymentsOrder record (user + product + amount), and
      - mark the orphan whose amount matches the outcome as resolved + attributed
        to that member (no separate Payment row -> no double counting).

    Pass ?ids=<comma-separated settled payment ids> (from the dashboard export).
    RECORD-ONLY: writes order rows + resolves orphans. NO commissions,
    entitlements, or balances. Idempotent (skips orders already present by
    np_payment_id; skips already-resolved orphans). Re-run to continue if
    time-capped. apply=0 dry run; apply=1 requires ?code=NNNNNN (2FA)."""
    _require_admin(user)
    import re as _re, time as _time
    from datetime import datetime as _dt
    from .database import NowPaymentsOrder as _NP, OnchainOrphanTransfer as _O, User as _U
    try:
        from . import nowpayments_service as _np
        if not _np.is_configured():
            return JSONResponse({"error": "nowpayments not configured in env"}, status_code=200)
    except Exception as e:
        return JSONResponse({"error": f"np init failed: {type(e).__name__}"}, status_code=200)

    id_list = [i.strip() for i in (ids or "").split(",") if i.strip()]
    if not id_list:
        return JSONResponse({"error": "pass ?ids=comma,separated,payment_ids"}, status_code=400)

    def _product(desc, price):
        d = (desc or "").lower(); p = round(price or 0)
        if "campaign tier" in d or "grid" in d or ("tier" in d and "credit" not in d and "nexus" not in d):
            tier = {20: 1, 50: 2, 100: 3, 200: 4, 400: 5, 600: 6, 800: 7, 1000: 8}.get(p)
            return ("grid", f"grid_{tier}" if tier else "grid")
        if "nexus" in d or "credit pack" in d or "credit matrix" in d:
            return ("nexus", "nexus_pack")
        if "superscene" in d or "creative" in d or "studio" in d:
            return ("superscene", "superscene")
        if "founder" in d or p == 15:
            return ("membership", "founder")
        if "partner" in d or "membership" in d or p == 20:
            return ("membership", "partner")
        return ("unknown", "unknown")

    uname = {u.id: u.username for u in db.query(_U.id, _U.username).all()}
    existing_np = {r[0] for r in db.query(_NP.np_payment_id).filter(_NP.np_payment_id.isnot(None)).all()}

    plan, errors = [], []
    _t0 = _time.time()
    for pid in id_list:
        if _time.time() - _t0 > max_seconds:
            errors.append({"payment_id": pid, "error": "time_budget_hit_remaining_skipped"})
            break
        try:
            data = _np.get_payment_status(int(pid))
        except Exception as e:
            errors.append({"payment_id": pid, "error": type(e).__name__}); continue
        if not isinstance(data, dict) or data.get("error"):
            errors.append({"payment_id": pid, "error": str(data)[:80]}); continue
        oid = data.get("order_id") or ""
        m = _re.match(r"SAP-(\d+)-", oid)
        uid = int(m.group(1)) if m else 0
        status = (data.get("payment_status") or "").lower()
        price = float(data.get("price_amount") or 0)
        outcome = float(data.get("outcome_amount") or data.get("actually_paid") or 0)
        ptype, pkey = _product(data.get("order_description"), price)
        already = int(pid) in existing_np
        # find a matching unresolved orphan by settled amount
        orphan = None
        if outcome > 0:
            cands = db.query(_O).filter(_O.resolved == False).all()  # noqa: E712
            best, bestd = None, 0.05
            for o in cands:
                d = abs(float(o.amount_usdt or 0) - outcome)
                if d < bestd:
                    best, bestd = o, d
            orphan = best
        plan.append({
            "payment_id": pid, "user_id": uid, "username": uname.get(uid),
            "product_type": ptype, "product_key": pkey, "price_usd": price,
            "outcome_usdt": round(outcome, 6), "status": status,
            "order_action": "skip_exists" if already else "write_np_order",
            "orphan_match": (orphan.tx_hash if orphan else None),
            "orphan_usd": (round(float(orphan.amount_usdt), 2) if orphan else None),
            "_orphan_id": (orphan.id if orphan else None),
            "_valid_user": bool(uid and uname.get(uid)),
        })

    base = {
        "generated_at": _dt.utcnow().isoformat(),
        "ids_requested": len(id_list),
        "processed": len(plan),
        "np_orders_to_write": sum(1 for p in plan if p["order_action"] == "write_np_order" and p["_valid_user"]),
        "orphans_to_resolve": sum(1 for p in plan if p["orphan_match"] and p["_valid_user"]),
        "errors": errors,
        "plan": plan,
    }

    if not apply:
        base["mode"] = "dry_run"
        base["note"] = ("READ-ONLY. Per settled NOWPayments payment: write_np_order records the "
                        "canonical NowPaymentsOrder (user from Order ID, product from description); "
                        "orphan_match is the treasury transfer whose amount equals the settled "
                        "outcome — it gets marked resolved + attributed on apply. RECORD-ONLY: no "
                        "commissions/entitlements/balances. Re-run with apply=1&code=NNNNNN; "
                        "re-run again to continue if time-capped (idempotent).")
        return JSONResponse(base)

    if not getattr(user, "totp_secret", None):
        return JSONResponse({"error": "Admin has no 2FA configured"}, status_code=400)
    import pyotp
    if not code or not pyotp.TOTP(user.totp_secret).verify(code.strip(), valid_window=1):
        return JSONResponse({"error": "Invalid or missing 2FA code — pass ?apply=1&code=NNNNNN"}, status_code=403)

    np_written = orphans_resolved = 0
    for p in plan:
        if not p["_valid_user"]:
            continue
        if p["order_action"] == "write_np_order":
            db.add(_NP(user_id=p["user_id"], product_type=p["product_type"], product_key=p["product_key"],
                       price_usd=p["price_usd"], np_payment_id=int(p["payment_id"]),
                       internal_order_id=f"SAP-{p['user_id']}", outcome_amount=p["outcome_usdt"],
                       outcome_currency="usdtbsc", pay_currency="usdtbsc",
                       status=("confirmed" if p["status"] in ("finished", "confirmed") else p["status"]),
                       confirmed_at=_dt.utcnow()))
            np_written += 1
        if p["_orphan_id"]:
            orp = db.query(_O).filter(_O.id == p["_orphan_id"], _O.resolved == False).first()  # noqa: E712
            if orp:
                orp.resolved = True
                orp.resolved_by_user_id = p["user_id"]
                orp.resolved_at = _dt.utcnow()
                orp.resolution_note = (f"NOWPayments payment {p['payment_id']} for user {p['user_id']} "
                                       f"({p['product_type']}/{p['product_key']}, ${p['price_usd']:.0f}) — recovery backfill")
                orphans_resolved += 1
    db.commit()
    base.update({
        "mode": "applied",
        "np_orders_written": np_written,
        "orphans_resolved": orphans_resolved,
        "note": ("Done. NOWPayments order records written + matching treasury orphans resolved and "
                 "attributed. No commissions/entitlements/balances. Re-run dry run to confirm; "
                 "re-run apply if it was time-capped (idempotent)."),
    })
    return JSONResponse(base)


@app.get("/admin/api/grid-root-restore")
def admin_api_grid_root_restore(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    apply: int = 0,
    code: str = "",
    empty_active_all_tiers: int = 1,
):
    """Correct the company-root (user 1) grid after grid-position-replay.

    User 1 had completed advances pre-hack (e.g. 2 on T1, bonuses paid — seen as
    'Advances: 2' + surviving revenue) whose per-seat detail is unrecoverable (44
    of ~72 seats lost: deleted accounts, pre-Brevo-window). The replay treated
    every grid as a fresh advance-1 and seated reconstructable descendant-buyers
    into user 1's ACTIVE grid, manufacturing false progress toward a phantom
    completion bonus. Those buyers historically filled user 1's COMPLETED
    advances and remain correctly seated in their real intermediate uplines.

    This removes the reconstructed positions from user-1-owned grids and restores
    the pre-hack shape: completed advances marked done (full seats, bonus_paid),
    active grids emptied. Members' seats elsewhere are untouched; no commissions
    or bonuses fire. Dry-run dumps the real grid rows first.

    empty_active_all_tiers=1 (default) empties every active user-1 grid (T1/T2/T3);
    set 0 to only touch grids whose tier had a completed advance."""
    _require_admin(user)
    from .database import (Grid, GridPosition, GRID_PACKAGES as _PKG,
                           GRID_TOTAL as _TOTAL)
    from .grid import _policy_bonus_target
    from decimal import Decimal as _Dec
    import pyotp
    ROOT = 1

    grids = (db.query(Grid).filter(Grid.owner_id == ROOT)
             .order_by(Grid.package_tier, Grid.advance_number).all())
    tiers_with_completion = {g.package_tier for g in grids if g.is_complete}

    dump, total_remove = [], 0
    for g in grids:
        cnt = db.query(GridPosition).filter(GridPosition.grid_id == g.id).count()
        if g.is_complete:
            plan = "restore_complete_full"
        elif empty_active_all_tiers or g.package_tier in tiers_with_completion:
            plan = "empty_active"
        else:
            plan = "leave_as_is"
        if plan != "leave_as_is":
            total_remove += cnt
        dump.append({"grid_id": g.id, "tier": g.package_tier, "advance": g.advance_number,
                     "is_complete": bool(g.is_complete),
                     "positions_filled_counter": g.positions_filled,
                     "actual_position_rows": cnt,
                     "revenue_total": float(g.revenue_total or 0), "plan": plan})

    if not apply:
        return JSONResponse({
            "mode": "dry_run", "root_user": ROOT,
            "tiers_with_completed_advances": sorted(tiers_with_completion),
            "grids": dump,
            "positions_to_remove_from_root_grids": total_remove,
            "note": ("Dry-run. Apply: completed advances -> full 36 seats + bonus_paid "
                     "(counter consistency; bonus already paid historically); active grids "
                     "-> emptied (the reconstructed seats belong to your completed advances; "
                     "members keep their seats in their real uplines). Result matches pre-hack: "
                     "completed advances done, current grid empty. ?apply=1&code=YOUR_2FA. "
                     "?empty_active_all_tiers=0 to only touch tiers that had a completed advance."),
        })

    if not getattr(user, "totp_secret", None):
        return JSONResponse({"error": "Admin has no 2FA configured"}, status_code=400)
    if not pyotp.TOTP(user.totp_secret).verify(code.strip(), valid_window=1):
        return JSONResponse({"error": "Invalid or missing 2FA code — pass ?code=NNNNNN"}, status_code=403)

    removed = 0
    for d in dump:
        if d["plan"] == "leave_as_is":
            continue
        removed += db.query(GridPosition).filter(
            GridPosition.grid_id == d["grid_id"]).delete(synchronize_session=False)
    db.flush()

    fixed = 0
    for g in grids:
        match = next((d for d in dump if d["grid_id"] == g.id), None)
        if not match or match["plan"] == "leave_as_is":
            continue
        price = _Dec(str(_PKG.get(g.package_tier, 0)))
        if g.is_complete:
            g.positions_filled = g.total_seats
            g.revenue_total = price * g.total_seats
            g.bonus_pool_accrued = _Dec(str(_policy_bonus_target(g.package_tier, g.total_seats)))
            g.bonus_paid = True
        else:
            g.positions_filled = 0
            g.revenue_total = 0
            g.bonus_pool_accrued = 0
        fixed += 1
    db.commit()

    return JSONResponse({
        "mode": "applied", "positions_removed": removed, "grids_fixed": fixed,
        "note": ("User-1 grids restored to pre-hack shape: completed advances done, active "
                 "grids empty. Members' seats in their own uplines untouched. No false "
                 "progress, no phantom-bonus risk. No commissions or bonuses fired."),
    })


@app.get("/admin/api/missing-tier-owners")
def admin_api_missing_tier_owners(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Read-only. Identify wiped campaign-tier (grid) buyers by the one signal
    the wipe could not touch and that no other product can forge: survived
    per-user grid earnings.

    Verified in grid.py: User.grid_earnings and User.level_earnings are
    incremented ONLY inside the grid commission functions (_pay_direct_sponsor,
    _pay_unilevel_chain, spillover fill, completion bonus). Membership, Nexus
    credit_matrix, PIF and course commissions credit different counters. And
    per _user_is_qualified, a member can only RECEIVE a grid/level commission if
    they own an active (purchased) Grid at that tier. Therefore:
        grid_earnings>0 OR level_earnings>0 OR bonus_earnings>0
        => the member owned a grid tier, regardless of payment rail.

    This lists such members who currently have NO owner_purchased Grid — i.e.
    real tier buyers whose Grid row was wiped (overwhelmingly the BSC/
    WalletConnect rail, whose order records are gone). Earnings only catch
    buyers who earned (had a downline purchase); pure leaf buyers who never
    earned are surfaced as a reconciliation residual, not named here.
    No writes."""
    _require_admin(user)
    from .database import User as _User, Grid, GridPosition, VideoCampaign
    from sqlalchemy import or_ as _or

    def _f2(v):
        try: return float(v or 0)
        except Exception: return 0.0

    # current real owners (owner_purchased), by tier
    owned = {}
    for g in db.query(Grid).filter(Grid.owner_purchased == True).all():  # noqa: E712
        owned.setdefault(g.owner_id, set()).add(g.package_tier)

    # video campaign tier per user (independent qualification + tier hint)
    vc_tier = {}
    for vc in db.query(VideoCampaign).all():
        vc_tier[vc.user_id] = max(vc_tier.get(vc.user_id, 0), (vc.campaign_tier if vc.campaign_tier is not None else 1))

    earners = db.query(_User).filter(
        _User.is_admin == False,  # noqa: E712
        _or(_User.grid_earnings > 0, _User.level_earnings > 0, _User.bonus_earnings > 0),
    ).all()

    missing, already = [], []
    for u in earners:
        rec = {
            "user_id": u.id, "username": u.username,
            "grid_earnings": _f2(getattr(u, "grid_earnings", 0)),
            "level_earnings": _f2(getattr(u, "level_earnings", 0)),
            "bonus_earnings": _f2(getattr(u, "bonus_earnings", 0)),
            "total_earned": _f2(getattr(u, "total_earned", 0)),
            "sponsor_id": getattr(u, "sponsor_id", None),
            "has_video_campaign": u.id in vc_tier,
            "vc_tier": vc_tier.get(u.id),
            "has_wallet": bool((getattr(u, "wallet_address", None) or "").strip()),
            "seated_positions": db.query(GridPosition).filter(GridPosition.member_id == u.id).count(),
        }
        if u.id in owned:
            rec["owns_tiers"] = sorted(owned[u.id])
            already.append(rec)
        else:
            rec["inferred_tier"] = vc_tier.get(u.id, 1)
            missing.append(rec)

    missing.sort(key=lambda r: -(r["grid_earnings"] + r["level_earnings"] + r["bonus_earnings"]))

    miss_by_tier = {}
    for r in missing:
        miss_by_tier[r["inferred_tier"]] = miss_by_tier.get(r["inferred_tier"], 0) + 1
    cur_t1 = sum(1 for ts in owned.values() if 1 in ts)
    cur_t2 = sum(1 for ts in owned.values() if 2 in ts)
    cur_t3 = sum(1 for ts in owned.values() if 3 in ts)

    return JSONResponse({
        "earners_total": len(earners),
        "already_owner_purchased": len(already),
        "missing_owner_count": len(missing),
        "missing_by_inferred_tier": miss_by_tier,
        "current_owner_purchased": {"tier1": cur_t1, "tier2": cur_t2, "tier3": cur_t3},
        "reconciliation": {
            "survived_user1_tier1_seats": 72,
            "current_t1_owners_plus_missing_t1": cur_t1 + miss_by_tier.get(1, 0),
            "note": ("If current_t1_owners_plus_missing_t1 lands at/near 72, the named "
                     "missing owners ARE the wiped tier-1 buyers. A residual below 72 = "
                     "leaf buyers who earned nothing (close via member self-ID)."),
        },
        "missing_owners": missing,
    })


@app.get("/admin/api/tier-buyer-census")
def admin_api_tier_buyer_census(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Read-only census of every surviving data source that records a
    campaign-grid (tier) purchase. After the relational-layer wipe we need to
    know which source can rebuild the FULL buyer set — the surviving user-1
    grid counter says ~72 tier-1 buyers existed but only 28 were rebuilt from
    Stripe+NOWPayments, so the WalletConnect/BSC self-custody buyers are
    missing. This dump tells us whether their canonical records (confirmed WC
    grid orders) survived, or whether we must reconstruct from on-chain
    treasury inflows. Aggregate counts + histograms + date ranges only. No PII,
    no writes."""
    _require_admin(user)
    from .database import (Payment, VideoCampaign, Grid,
                           WalletConnectPaymentOrder, OnchainOrphanTransfer,
                           StripeCharge, User as _User)
    from sqlalchemy import func as _f
    out = {}

    # --- WalletConnect self-custody orders (the suspected-wiped crypto rail) ---
    wc_total = db.query(WalletConnectPaymentOrder).count()
    wc_by = (db.query(WalletConnectPaymentOrder.status,
                      WalletConnectPaymentOrder.product_type,
                      _f.count(WalletConnectPaymentOrder.id))
             .group_by(WalletConnectPaymentOrder.status,
                       WalletConnectPaymentOrder.product_type).all())
    wc_grid_confirmed = (db.query(WalletConnectPaymentOrder)
                         .filter(WalletConnectPaymentOrder.status == "confirmed",
                                 WalletConnectPaymentOrder.product_type == "grid")
                         .order_by(WalletConnectPaymentOrder.confirmed_at.asc()).all())
    wc_dates = db.query(_f.min(WalletConnectPaymentOrder.created_at),
                        _f.max(WalletConnectPaymentOrder.created_at)).first()
    out["walletconnect_orders"] = {
        "total": wc_total,
        "by_status_product": [{"status": s, "product_type": p, "count": c} for (s, p, c) in wc_by],
        "confirmed_grid_count": len(wc_grid_confirmed),
        "confirmed_grid_orders": [
            {"user_id": o.user_id, "product_key": o.product_key,
             "base_amount": float(o.base_amount or 0),
             "confirmed_at": o.confirmed_at.isoformat() if o.confirmed_at else None}
            for o in wc_grid_confirmed],
        "created_at_min": wc_dates[0].isoformat() if wc_dates and wc_dates[0] else None,
        "created_at_max": wc_dates[1].isoformat() if wc_dates and wc_dates[1] else None,
    }

    # --- Orphan treasury transfers (unmatched on-chain inflows) ---
    orph_total = db.query(OnchainOrphanTransfer).count()
    orph_unresolved = db.query(OnchainOrphanTransfer).filter(OnchainOrphanTransfer.resolved == False).count()
    orph_dates = db.query(_f.min(OnchainOrphanTransfer.seen_at), _f.max(OnchainOrphanTransfer.seen_at)).first()
    out["orphan_transfers"] = {
        "total": orph_total, "unresolved": orph_unresolved,
        "seen_at_min": orph_dates[0].isoformat() if orph_dates and orph_dates[0] else None,
        "seen_at_max": orph_dates[1].isoformat() if orph_dates and orph_dates[1] else None,
    }

    # --- VideoCampaign rows (rail-independent tier-ownership signal) ---
    vc_total = db.query(VideoCampaign).count()
    vc_distinct_users = db.query(VideoCampaign.user_id).distinct().count()
    vc_by_tier = (db.query(VideoCampaign.campaign_tier, _f.count(VideoCampaign.id))
                  .group_by(VideoCampaign.campaign_tier).order_by(VideoCampaign.campaign_tier).all())
    vc_dates = db.query(_f.min(VideoCampaign.created_at), _f.max(VideoCampaign.created_at)).first()
    out["video_campaigns"] = {
        "total": vc_total, "distinct_users": vc_distinct_users,
        "by_campaign_tier": [{"tier": t, "count": c} for (t, c) in vc_by_tier],
        "created_at_min": vc_dates[0].isoformat() if vc_dates and vc_dates[0] else None,
        "created_at_max": vc_dates[1].isoformat() if vc_dates and vc_dates[1] else None,
    }

    # --- payments table (generic incoming) ---
    pay_total = db.query(Payment).count()
    pay_by = (db.query(Payment.payment_type, Payment.status, _f.count(Payment.id))
              .group_by(Payment.payment_type, Payment.status).all())
    out["payments"] = {
        "total": pay_total,
        "by_type_status": [{"payment_type": pt, "status": st, "count": c} for (pt, st, c) in pay_by],
    }

    # --- stripe_charges (campaign_tier = the Stripe-rail tier buys we DID capture) ---
    sc_total = db.query(StripeCharge).count()
    sc_tier = (db.query(StripeCharge.kind, _f.count(StripeCharge.id))
               .filter(StripeCharge.product == "campaign_tier")
               .group_by(StripeCharge.kind).all())
    out["stripe_charges"] = {
        "total": sc_total,
        "campaign_tier_by_kind": [{"kind": k, "count": c} for (k, c) in sc_tier],
    }

    # --- users with a stored wallet_address (needed for on-chain attribution) ---
    users_total = db.query(_User).count()
    users_with_wallet = db.query(_User).filter(_User.wallet_address.isnot(None),
                                               _User.wallet_address != "").count()
    out["users"] = {"total": users_total, "with_wallet_address": users_with_wallet}

    # --- grids actually present (owner_purchased = real tier owners after rebuild) ---
    grids_total = db.query(Grid).count()
    grid_owner_purchased = (db.query(Grid.package_tier, _f.count(Grid.id))
                            .filter(Grid.owner_purchased == True)
                            .group_by(Grid.package_tier).order_by(Grid.package_tier).all())
    out["grids"] = {
        "total": grids_total,
        "owner_purchased_by_tier": [{"tier": t, "count": c} for (t, c) in grid_owner_purchased],
    }

    out["_note"] = ("Decision key: if walletconnect_orders.confirmed_grid_count is "
                    "substantial, those rows ARE the missing crypto tier buyers "
                    "(user_id + tier, directly). If ~0, the WC grid rows were wiped and we "
                    "reconstruct from orphan_transfers + on-chain treasury scan, "
                    "attributing via users.with_wallet_address.")

    return JSONResponse(out)


@app.get("/admin/api/grid-root-audit")
def admin_api_grid_root_audit(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    target_user_id: int = 1,
    hours: int = 72,
):
    """Read-only ground-truth dump for diagnosing an unexpected wallet credit.

    Returns the target user's actual wallet/earnings fields (incl. campaign_balance,
    which lookup_user does NOT expose), the full bonus state of their grids, and
    every Commission row touching them in the window — so an unexplained
    campaign_balance change can be traced to its exact source and reversed
    precisely. No writes."""
    _require_admin(user)
    from .database import Grid, GridPosition, Commission, User as _User
    from datetime import datetime as _dt, timedelta as _td
    from sqlalchemy import or_ as _or

    t = db.query(_User).filter(_User.id == target_user_id).first()
    if not t:
        return JSONResponse({"error": f"user {target_user_id} not found"}, status_code=404)

    wallet = {
        "campaign_balance": float(getattr(t, "campaign_balance", 0) or 0),
        "balance": float(getattr(t, "balance", 0) or 0),
        "total_earned": float(getattr(t, "total_earned", 0) or 0),
        "bonus_earnings": float(getattr(t, "bonus_earnings", 0) or 0),
        "grid_earnings": float(getattr(t, "grid_earnings", 0) or 0),
        "level_earnings": float(getattr(t, "level_earnings", 0) or 0),
    }

    grids = (db.query(Grid).filter(Grid.owner_id == target_user_id)
             .order_by(Grid.package_tier, Grid.advance_number).all())
    grid_rows = []
    for g in grids:
        cnt = db.query(GridPosition).filter(GridPosition.grid_id == g.id).count()
        grid_rows.append({
            "grid_id": g.id, "tier": g.package_tier, "advance": g.advance_number,
            "is_complete": bool(g.is_complete), "bonus_paid": bool(g.bonus_paid),
            "bonus_rolled_over": bool(getattr(g, "bonus_rolled_over", False)),
            "bonus_pool_accrued": float(g.bonus_pool_accrued or 0),
            "positions_filled": g.positions_filled, "actual_rows": cnt,
            "completed_at": g.completed_at.isoformat() if g.completed_at else None,
        })

    since = _dt.utcnow() - _td(hours=hours)
    coms = (db.query(Commission)
            .filter(_or(Commission.to_user_id == target_user_id,
                        Commission.from_user_id == target_user_id))
            .filter(Commission.created_at >= since)
            .order_by(Commission.created_at.desc()).all())
    com_rows = [{
        "id": c.id, "type": c.commission_type, "amount": float(c.amount_usdt or 0),
        "from": c.from_user_id, "to": c.to_user_id, "status": c.status,
        "grid_id": getattr(c, "grid_id", None),
        "created_at": c.created_at.isoformat() if c.created_at else None,
        "paid_at": c.paid_at.isoformat() if c.paid_at else None,
        "notes": (c.notes or "")[:120],
    } for c in coms]
    grid_bonus_to_user = [c for c in com_rows
                          if c["type"] in ("grid_completion_bonus", "grid_completion_bonus_topup")
                          and c["to"] == target_user_id]

    return JSONResponse({
        "target_user_id": target_user_id, "username": t.username,
        "wallet": wallet,
        "grids": grid_rows,
        "commissions_window_hours": hours,
        "commissions_touching_user": com_rows,
        "grid_completion_bonuses_to_user_in_window": grid_bonus_to_user,
        "note": ("Read-only. campaign_balance is the grid/campaign wallet (grid completion "
                 "bonuses land here). A grid_completion_bonus Commission row + matching "
                 "campaign_balance/bonus_earnings/total_earned bump = a real payout; its "
                 "absence means any reported figure is grid-state-derived, not a credit."),
    })


@app.get("/admin/api/spawn-missing-advances")
def admin_api_spawn_missing_advances(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    apply: int = 0,
    code: str = "",
):
    """Repair: spawn the next-advance grid for every COMPLETED grid that has no
    successor at the same (owner, tier).

    Root cause: breach-recovery reconstructed grid completions from surviving
    counters WITHOUT running _complete_grid(), the only path that auto-spawns the
    next advance. Result: completed grids with no successor, so /api/grid-visualiser
    (which loads only is_complete=False) renders that tier EMPTY even though seats
    and bonus are intact (e.g. user 264 'success' tier 1).

    Recreates ONLY the missing successor Grid row, mirroring _complete_grid:
    advance_number+1; carry bonus_pool_accrued solely when the completed grid
    rolled its bonus over unpaid. Writes NO balances and NO commissions — bonuses
    are already paid/reconstructed. Pure additive + idempotent (skips a (owner,tier)
    that still has any incomplete grid, or where the successor already exists).
    Dry-run default; apply=1&code=NNNNNN to write."""
    _require_admin(user)
    from .database import Grid as _G, User as _U
    from decimal import Decimal as _Dec

    do_apply = bool(apply) and bool((code or "").strip())
    if do_apply:
        _require_admin_2fa(user, code)

    grids = db.query(_G).all()
    existing_adv = {(g.owner_id, g.package_tier, g.advance_number) for g in grids}
    by_key = {}
    for g in grids:
        by_key.setdefault((g.owner_id, g.package_tier), []).append(g)
    uname = {u.id: u.username for u in db.query(_U.id, _U.username).all()}

    to_spawn = []
    for (owner_id, tier), gl in by_key.items():
        # If this (owner,tier) has ANY incomplete grid, the visualiser already
        # has something to show — no missing successor.
        if any(not g.is_complete for g in gl):
            continue
        top = max(gl, key=lambda g: g.advance_number)
        if (owner_id, tier, top.advance_number + 1) in existing_adv:
            continue
        rolled = bool(getattr(top, "bonus_rolled_over", False)) and not bool(getattr(top, "bonus_paid", False))
        to_spawn.append({
            "owner_id": owner_id, "username": uname.get(owner_id), "tier": tier,
            "completed_advance": top.advance_number, "completed_grid_id": top.id,
            "new_advance_number": top.advance_number + 1,
            "carry_bonus_pool": (float(top.bonus_pool_accrued or 0) if rolled else 0.0),
            "completed_bonus_paid": bool(getattr(top, "bonus_paid", False)),
        })
    to_spawn.sort(key=lambda s: (s["tier"], s["owner_id"]))

    report = {
        "dry_run": not do_apply,
        "completed_tiers_missing_successor": len(to_spawn),
        "to_spawn": to_spawn,
    }
    if not do_apply:
        report["note"] = ("READ-ONLY. Each entry = a (member, tier) whose grids are ALL complete with "
                          "no next advance, so the grid page renders that tier empty. Apply spawns the "
                          "missing successor grid (advance+1) ONLY — no balances, commissions, or bonuses. "
                          "Idempotent. Add &apply=1&code=NNNNNN to write.")
        return JSONResponse(report)

    spawned = 0
    for s in to_spawn:
        if db.query(_G).filter(_G.owner_id == s["owner_id"], _G.package_tier == s["tier"],
                               _G.advance_number == s["new_advance_number"]).first():
            continue
        done = db.query(_G).filter(_G.id == s["completed_grid_id"]).first()
        ng = _G(owner_id=s["owner_id"], package_tier=s["tier"],
                package_price=(done.package_price if done else None),
                advance_number=s["new_advance_number"])
        if s["carry_bonus_pool"] > 0:
            ng.bonus_pool_accrued = _Dec(str(s["carry_bonus_pool"]))
        db.add(ng)
        spawned += 1
    db.commit()
    report["spawned"] = spawned
    report["note"] = f"Applied. Spawned {spawned} missing advance grid(s). No balances/commissions touched."
    return JSONResponse(report)


@app.get("/admin/api/grid-occupants-reconstruct")
def admin_api_grid_occupants_reconstruct(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    owner_id: int = 1,
    tier: int = 1,
    depth_cap: int = 0,
):
    """READ-ONLY reconstruction of who occupies an owner's grid at a tier, derived
    from tier PURCHASES + the sponsor chain (not the wiped GridPosition rows).

    Placement is deterministic: a tier buyer seats in EVERY upline grid at that
    tier, in purchase-time order. So the occupants of owner_id's grid = every
    verified tier buyer (a member who owns an owner_purchased grid at this tier)
    whose sponsor chain reaches owner_id, ordered by their purchase time, mapped
    36-per-advance. This rebuilds the company-root board (grids the reconstruction
    pass left at counter level) from surviving data.

    Honest about gaps: identifiable_occupants vs counter_seats_claimed. A positive
    unmapped_gap = seats the surviving counter claims that can't be tied to a
    current member — deleted accounts (removed in the breach), repurchases, or a
    counter that was itself reconstructed. Writes nothing."""
    _require_admin(user)
    from .database import Grid as _G, GridPosition as _GP, User as _U, GRID_TOTAL as _TOTAL
    from datetime import datetime as _dt

    urows = db.query(_U.id, _U.sponsor_id, _U.username, _U.created_at).all()
    sponsor_of = {r.id: r.sponsor_id for r in urows}
    uname = {r.id: r.username for r in urows}
    ucreated = {r.id: r.created_at for r in urows}

    def _reaches(b):
        cur, seen, steps = b, set(), 0
        while True:
            anc = sponsor_of.get(cur)
            if anc is None or anc in seen:
                return False
            seen.add(anc)
            if anc == owner_id:
                return True
            cur = anc
            steps += 1
            if depth_cap and steps >= depth_cap:
                return False

    # Verified tier buyers = owners of an owner_purchased grid at this tier.
    buyer_grids = db.query(_G).filter(_G.package_tier == tier, _G.owner_purchased == True).all()
    occ = []
    for g in buyer_grids:
        b = g.owner_id
        if b == owner_id:
            continue
        if _reaches(b):
            ts = g.created_at or ucreated.get(b)
            occ.append({"member_id": b, "sap_id": "SAP-" + str(b).zfill(5),
                        "username": uname.get(b),
                        "purchase_ts": ts.isoformat() if ts else None, "_ts": ts})
    occ.sort(key=lambda o: o["_ts"] or _dt(2099, 1, 1))
    for i, o in enumerate(occ):
        o["advance"] = i // _TOTAL + 1
        o["seat"] = i % _TOTAL + 1
        o.pop("_ts", None)

    owner_grids = db.query(_G).filter(_G.owner_id == owner_id, _G.package_tier == tier).order_by(_G.advance_number).all()
    counter_seats = sum(int(g.positions_filled or 0) for g in owner_grids)
    completed_adv = sum(1 for g in owner_grids if g.is_complete)
    live_rows = (db.query(_GP).join(_G, _GP.grid_id == _G.id)
                 .filter(_G.owner_id == owner_id, _G.package_tier == tier).count())

    return JSONResponse({
        "owner_id": owner_id, "owner_username": uname.get(owner_id), "tier": tier,
        "counter_seats_claimed": counter_seats,
        "completed_advances_claimed": completed_adv,
        "live_seat_rows_present": live_rows,
        "identifiable_occupants": len(occ),
        "unmapped_gap": max(0, counter_seats - len(occ)),
        "occupants": occ,
        "note": ("READ-ONLY. occupants = verified tier buyers whose sponsor chain reaches "
                 "this owner, in purchase order, mapped 36/advance. identifiable_occupants vs "
                 "counter_seats_claimed: a positive unmapped_gap = seats the counter claims "
                 "that no current member backs (deleted accounts, repurchases, or a counter "
                 "that was itself reconstructed). live_seat_rows_present = surviving "
                 "GridPosition rows (0 for the breach-wiped company root)."),
    })


@app.get("/admin/api/missed-commission-audit")
def admin_api_missed_commission_audit(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    user_id: int = 0,
    since: str = "",
):
    """READ-ONLY. Quantify campaign-tier commissions a member MISSED while
    unqualified — e.g. a breach-wiped tier purchase left them with no active tier,
    so their 40%/6.25% on downline tier purchases was company-absorbed.

    _pay_direct_sponsor / _pay_unilevel_chain stamp every absorb row with a note
    naming the skipped recipient ('Sponsor {id} unqualified' / 'upline {id}
    unqualified … company absorb'). This sums those for `user_id` since `since` —
    what they'd have earned had they been live from that date. Also reports downline
    size so a possible missed grid completion can be judged. No writes.

    Caveat: only events PROCESSED live carry the naming note; pre-3-June rows
    reconstructed from counters may not, so treat the figure as a verified floor."""
    _require_admin(user)
    from .database import Commission as _C, User as _U
    from datetime import datetime as _dt
    from sqlalchemy import or_ as _or

    target = db.query(_U).filter(_U.id == user_id).first()
    if not target:
        return JSONResponse({"error": f"user {user_id} not found"}, status_code=200)
    try:
        since_dt = _dt.fromisoformat(since) if since else _dt(2026, 5, 25)
    except Exception:
        return JSONResponse({"error": f"bad since '{since}' (use YYYY-MM-DD)"}, status_code=200)

    uname = {u.id: u.username for u in db.query(_U.id, _U.username).all()}

    rows = (db.query(_C)
            .filter(_C.to_user_id.is_(None),
                    _C.created_at >= since_dt,
                    _or(_C.notes.like(f"%upline {user_id} unqualified%"),
                        _C.notes.like(f"%Sponsor {user_id} unqualified%")))
            .order_by(_C.created_at.asc()).all())
    missed, total_direct, total_uni = [], 0.0, 0.0
    for c in rows:
        amt = float(c.amount_usdt or 0)
        if c.commission_type == "direct_sponsor":
            total_direct += amt
        else:
            total_uni += amt
        missed.append({
            "commission_id": c.id, "type": c.commission_type, "amount": round(amt, 4),
            "from_buyer": c.from_user_id, "buyer_username": uname.get(c.from_user_id),
            "package_tier": getattr(c, "package_tier", None),
            "created_at": c.created_at.isoformat() if c.created_at else None,
            "note": (c.notes or "")[:160],
        })

    direct_dl = db.query(_U.id).filter(_U.sponsor_id == user_id).count()
    level_ids, frontier, depth, total_dl = {user_id}, [user_id], 0, 0
    while frontier and depth < 8:
        kids = [r[0] for r in db.query(_U.id).filter(_U.sponsor_id.in_(frontier)).all() if r[0] not in level_ids]
        for k in kids:
            level_ids.add(k)
        total_dl += len(kids)
        frontier, depth = kids, depth + 1

    return JSONResponse({
        "user_id": user_id, "username": target.username, "since": since_dt.isoformat(),
        "missed_commission_count": len(missed),
        "missed_direct_40pct": round(total_direct, 2),
        "missed_unilevel_625pct": round(total_uni, 2),
        "missed_total": round(total_direct + total_uni, 2),
        "direct_downline": direct_dl,
        "downline_within_8_levels": total_dl,
        "missed_detail": missed,
        "note": ("READ-ONLY. missed_total = campaign-tier commissions company-absorbed because "
                 "this member was unqualified when a downline member bought a tier — what they'd "
                 "have earned had they been live from `since`. Only live-processed events carry the "
                 "naming note, so treat as a verified floor (pre-3-June reconstructed rows may lack "
                 "detail). A missed grid COMPLETION bonus is only possible if 36+ tier buyers fell "
                 "in their downline — judge via the downline counts."),
    })


@app.get("/admin/api/grid-cutoff")
def admin_grid_cutoff(
    apply: int = 0,
    code: str = "",
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Cut-off: settle + retire every legacy 36-seat grid in one controlled op.

    Catches BOTH genuinely-incomplete legacy grids AND grids an earlier
    migration force-flipped to is_complete=True without real fills (the
    Kurt/Katarina phantom-completion set that stranded owners out of
    Watch-to-Earn via get_user_highest_tier). Selection gates on REAL
    GridPosition rows < total_seats, so a falsely-completed grid is included
    and a genuinely-full grid (real rows >= total_seats) is excluded.

    DRY-RUN by default (apply=0): returns per-grid detail (real seats, real
    revenue, current vs honest pool) + totals, no writes. APPLY (apply=1 + TOTP
    ?code=NNNNNN) settles each grid's GENUINELY-EARNED bonus = REAL rows x tier
    price x 10% (NOT positions_filled, which can be drifted; NOT the 26-May
    topped bonus_pool_accrued), credits the owner's withdrawable balance, heals
    the stored pool + counter to honest values, retires the grid
    (is_complete=True + retired_at=now), then EAGERLY mints the fresh 16-seat
    replacement so Watch-to-Earn access returns immediately.

    Money mutation -> 2FA-gated apply (dry-run doctrine). Idempotent: only
    grids with retired_at IS NULL are processed, so a re-run never
    double-settles. Settle+retire is one commit -> all-or-nothing; the eager
    re-grid runs after and is itself idempotent. 12 Jun 2026 (extended 13 Jun).
    """
    _require_admin(user)
    from .database import (Grid, GridPosition as _GP, User as _User, NEW_GRID_SEATS,
                           LEGACY_BONUS_POOL_PCT, GRID_PACKAGES)
    from .grid import _record_commission, get_or_create_active_grid
    from sqlalchemy import func as _func
    from datetime import datetime as _dt

    RATE = float(LEGACY_BONUS_POOL_PCT)  # 0.10 — legacy grids keep the old rate

    # Candidate legacy (non-16-seat), not-yet-retired grids. We deliberately do
    # NOT filter on is_complete: an earlier migration force-flipped grids to
    # is_complete=True without real fills, which the old is_complete==False
    # filter skipped -> owners stranded (Watch-to-Earn locked, phantom $72 pool).
    # Gate on ACTUAL GridPosition rows instead: a falsely-completed grid is
    # caught, a genuinely-full grid (rows >= total_seats) is correctly excluded.
    candidate_grids = (db.query(Grid)
             .filter(_func.coalesce(Grid.total_seats, 36) != NEW_GRID_SEATS,
                     Grid.retired_at == None)
             .all())
    cand_ids = [g.id for g in candidate_grids]
    row_counts = {}
    if cand_ids:
        for gid, cnt in (db.query(_GP.grid_id, _func.count(_GP.id))
                           .filter(_GP.grid_id.in_(cand_ids))
                           .group_by(_GP.grid_id).all()):
            row_counts[gid] = int(cnt)
    grids = [g for g in candidate_grids
             if row_counts.get(g.id, 0) < int(g.total_seats or 36)]

    owner_ids = list({g.owner_id for g in grids}) or [0]
    uname = {u.id: u.username for u in
             db.query(_User).filter(_User.id.in_(owner_ids)).all()}

    plan = []          # (grid, earned, seats)  -- seats = REAL rows
    per_tier = {}
    detail = []
    for g in grids:
        seats = int(row_counts.get(g.id, 0))   # REAL GridPosition rows -- drift-proof
        price = float(GRID_PACKAGES.get(g.package_tier, float(g.package_price or 0)))
        earned = round(seats * price * RATE, 2)
        plan.append((g, earned, seats))
        detail.append({
            "grid_id": g.id, "owner_id": g.owner_id,
            "username": uname.get(g.owner_id),
            "tier": g.package_tier, "advance": g.advance_number,
            "real_seats": seats,
            "real_revenue": round(seats * price, 2),
            "current_pool": float(g.bonus_pool_accrued or 0),
            "honest_settle": earned,
            "was_falsely_complete": bool(g.is_complete),
            "counter_was": int(g.positions_filled or 0),
        })
        pt = per_tier.setdefault(g.package_tier,
                                 {"tier": g.package_tier, "grids": 0,
                                  "seats_filled": 0, "settle_usd": 0.0})
        pt["grids"] += 1
        pt["seats_filled"] += seats
        pt["settle_usd"] = round(pt["settle_usd"] + earned, 2)

    total_settle = round(sum(e for _, e, _ in plan), 2)
    members = len({g.owner_id for g, _, _ in plan})

    falsely_complete = sum(1 for d in detail if d["was_falsely_complete"])
    out = {
        "mode": "APPLY" if apply == 1 else "DRY-RUN",
        "legacy_grids_to_retire": len(plan),
        "falsely_complete_included": falsely_complete,
        "distinct_members": members,
        "total_settle_usd": total_settle,
        "settle_wallet": "balance (withdrawable affiliate wallet)",
        "rate": RATE,
        "by_tier": sorted(per_tier.values(),
                          key=lambda r: (r["tier"] is None,
                                         r["tier"] if r["tier"] is not None else -1)),
        "detail": sorted(detail, key=lambda d: (-d["real_seats"], d["grid_id"])),
        "note": ("Settle = REAL GridPosition rows x tier price x 10% (genuinely earned from "
                 "actual seat-fills; NOT positions_filled, which can be drifted; NOT the "
                 "26-May topped bonus_pool_accrued). Credits owner withdrawable balance, heals "
                 "the stored pool + counter to honest values, retires the grid "
                 "(is_complete=True + retired_at), then EAGERLY mints the fresh 16-seat "
                 "replacement so Watch-to-Earn returns immediately. Idempotent on "
                 "retired_at IS NULL. Qualification waived given trivial per-member amounts."),
    }

    if apply != 1:
        out["next"] = "Review the per-grid detail + total, then re-call with &apply=1&code=YOUR_TOTP to execute."
        return JSONResponse(out, status_code=200,
                            headers={"Cache-Control": "no-store, no-cache, max-age=0"})

    # ---- APPLY (2FA-gated) ----
    _require_admin_2fa(user, code)

    now = _dt.utcnow()
    retired = 0
    settled_usd = 0.0
    retire_targets = set()   # (owner_id, package_tier) to re-grid after commit
    for g, earned, seats in plan:
        owner = db.query(_User).filter(_User.id == g.owner_id).first()
        if owner and earned > 0:
            owner.balance        = decimal.Decimal(str(owner.balance or 0)) + decimal.Decimal(str(earned))
            owner.total_earned   = decimal.Decimal(str(owner.total_earned or 0)) + decimal.Decimal(str(earned))
            owner.bonus_earnings = decimal.Decimal(str(owner.bonus_earnings or 0)) + decimal.Decimal(str(earned))
            _record_commission(
                db, g.owner_id, g.owner_id, earned, "grid_completion_bonus",
                f"Cut-off settle: {seats} REAL filled seats x tier {g.package_tier} price x 10% "
                f"= ${earned:.2f} (legacy 36-seat grid retired)",
                g.package_tier,
            )
            db.add(owner)
        # Heal stored pool + counter to honest values, then retire (paid so no
        # sweeper re-pays). positions_filled is reset to REAL rows so any drift
        # (e.g. counter=36 / rows=0) cannot mis-settle on a re-run.
        g.bonus_pool_accrued = decimal.Decimal(str(earned))
        g.positions_filled   = seats
        g.is_complete = True
        g.bonus_paid  = True
        g.owner_paid  = True
        g.retired_at  = now
        db.add(g)
        retire_targets.add((g.owner_id, g.package_tier))
        retired += 1
        settled_usd = round(settled_usd + earned, 2)

    db.commit()   # all-or-nothing settle + retire

    # Eager re-grid: mint the fresh 16-seat replacement so owners aren't left
    # gridless (and Watch-to-Earn-locked) waiting for 'next activity'. Idempotent:
    # only mints where the owner has no incomplete grid at that tier.
    minted = 0
    for owner_id, tier in retire_targets:
        has_incomplete = db.query(Grid).filter(
            Grid.owner_id == owner_id, Grid.package_tier == tier,
            Grid.is_complete == False).count()
        if has_incomplete == 0:
            get_or_create_active_grid(db, owner_id, tier)
            minted += 1

    out["mode"] = "APPLIED"
    out["grids_retired"] = retired
    out["total_settled_usd"] = settled_usd
    out["replacement_grids_minted"] = minted
    return JSONResponse(out, status_code=200,
                        headers={"Cache-Control": "no-store, no-cache, max-age=0"})


@app.get("/admin/api/grid-integrity-audit")
def admin_api_grid_integrity_audit(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """READ-ONLY full-platform grid + seat integrity scan across EVERY grid.

    Commission scans (commission_anomalies / unqualified_commissions) are blind to
    display defects because those defects move no money. This surfaces exactly the
    failure modes the breach recovery could have left:

      - orphaned_seat_grids: a GridPosition.member_id points to a user row that no
        longer exists (e.g. a member deleted in the breach). /api/grid-visualiser
        does `if not member: continue`, so the seat is SKIPPED and the grid renders
        short/empty -> the 'Tier 2 shows no one / inactive' symptom.
      - counter_drift_grids: grid.positions_filled disagrees with the real
        GridPosition row count.
      - completion_mismatch_grids: is_complete=True on a grid with < GRID_TOTAL real
        rows (a reconstructed completion), or is_complete=False with >= GRID_TOTAL.
      - completed_no_successor_grids: a completed grid with no next-advance grid at
        the same (owner, tier) and no other incomplete grid there -> tier renders
        empty (the spawn-missing-advances set).

    No writes. This is the true blast radius across all grids."""
    _require_admin(user)
    from .database import Grid as _G, GridPosition as _GP, User as _U, GRID_TOTAL as _TOTAL
    from collections import defaultdict as _dd

    user_ids = {r[0] for r in db.query(_U.id).all()}
    uname = {u.id: u.username for u in db.query(_U.id, _U.username).all()}

    grids = db.query(_G).all()
    existing_adv = {(g.owner_id, g.package_tier, g.advance_number) for g in grids}
    has_incomplete = _dd(bool)
    for g in grids:
        if not g.is_complete:
            has_incomplete[(g.owner_id, g.package_tier)] = True

    pos = db.query(_GP.grid_id, _GP.member_id).all()
    by_grid = _dd(list)
    for gid, mid in pos:
        by_grid[gid].append(mid)

    orphaned, drift, completion_mismatch, missing_succ = [], [], [], []
    for g in grids:
        members = by_grid.get(g.id, [])
        actual = len(members)
        resolvable = sum(1 for m in members if m in user_ids)
        orphans = actual - resolvable
        counter = int(g.positions_filled or 0)
        rec = {
            "grid_id": g.id, "owner_id": g.owner_id, "username": uname.get(g.owner_id),
            "tier": g.package_tier, "advance": g.advance_number,
            "is_complete": bool(g.is_complete),
            "counter_filled": counter, "actual_rows": actual,
            "resolvable_rows": resolvable, "orphaned_rows": orphans,
            "total_seats": int(g.total_seats or 0),
            "retired_at": g.retired_at.isoformat() if g.retired_at else None,
            "bonus_paid": bool(g.bonus_paid),
            "bonus_pool": float(g.bonus_pool_accrued or 0),
            "owner_purchased": bool(g.owner_purchased),
        }
        if orphans > 0:
            orphaned.append(rec)
        if counter != actual:
            drift.append(rec)
        if (g.is_complete and actual < g.total_seats) or ((not g.is_complete) and actual >= g.total_seats):
            completion_mismatch.append(rec)
        if (g.is_complete
                and (g.owner_id, g.package_tier, g.advance_number + 1) not in existing_adv
                and not has_incomplete[(g.owner_id, g.package_tier)]):
            missing_succ.append(rec)

    affected_grid_ids = {r["grid_id"] for r in (orphaned + drift + completion_mismatch + missing_succ)}
    return JSONResponse({
        "grids_total": len(grids),
        "positions_total": len(pos),
        "grid_total_seats": _TOTAL,
        "affected_grids_count": len(affected_grid_ids),
        "orphaned_seat_grids": {"count": len(orphaned), "detail": orphaned},
        "counter_drift_grids": {"count": len(drift), "detail": drift},
        "completion_mismatch_grids": {"count": len(completion_mismatch), "detail": completion_mismatch},
        "completed_no_successor_grids": {"count": len(missing_succ), "detail": missing_succ},
        "note": ("READ-ONLY. orphaned_seat_grids => seats whose member_id points to a deleted "
                 "user; the visualiser skips them so the grid shows short/empty (the Tier-2 "
                 "'no one / inactive' symptom). counter_drift => positions_filled disagrees with "
                 "real rows. completion_mismatch => is_complete inconsistent with real row count. "
                 "completed_no_successor => the missing-advance set. affected_grids_count is the "
                 "true display blast radius; commissions are separately verified clean."),
    })


@app.get("/admin/api/grid-settlement-truth")
def admin_grid_settlement_truth(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """READ-ONLY truth reconciliation of the 12-Jun legacy grid cut-off.

    For every legacy grid owner, per tier: the HONEST completion bonus owed
    (real GridPosition rows x tier price x 10%) set against what was actually
    PAID (Commission grid_completion_bonus, status=paid), plus the status of
    the phantom top-ups, owner_purchased, and whether an active successor grid
    exists. Proves who was settled correctly, whether any phantom money is
    still live, and who is genuinely missing a successor grid (the WTE lockout).
    No writes."""
    _require_admin(user)
    from .database import (Grid, GridPosition as _GP, User as _User, Commission,
                           GRID_PACKAGES, NEW_GRID_SEATS, LEGACY_BONUS_POOL_PCT)
    from sqlalchemy import func as _func
    RATE = float(LEGACY_BONUS_POOL_PCT)

    # Completed legacy grids = the settled set we reconcile.
    grids = (db.query(Grid)
             .filter(_func.coalesce(Grid.total_seats, 36) != NEW_GRID_SEATS,
                     Grid.is_complete == True)  # noqa: E712
             .all())
    gids = [g.id for g in grids]
    rows = {}
    if gids:
        for gid, cnt in (db.query(_GP.grid_id, _func.count(_GP.id))
                         .filter(_GP.grid_id.in_(gids))
                         .group_by(_GP.grid_id).all()):
            rows[gid] = int(cnt)

    # Active (incomplete) grids per (owner,tier) = a live successor exists.
    active = set()
    for oid, tier in (db.query(Grid.owner_id, Grid.package_tier)
                      .filter(Grid.is_complete == False).all()):  # noqa: E712
        active.add((oid, tier))

    # Completion commissions grouped by (recipient, tier, type, status).
    comm = {}
    for to_uid, tier, ctype, status, total in (
        db.query(Commission.to_user_id, Commission.package_tier,
                 Commission.commission_type, Commission.status,
                 _func.coalesce(_func.sum(Commission.amount_usdt), 0))
        .filter(Commission.commission_type.in_(
            ["grid_completion_bonus", "grid_completion_bonus_topup"]))
        .group_by(Commission.to_user_id, Commission.package_tier,
                  Commission.commission_type, Commission.status).all()):
        comm[(to_uid, tier, ctype, status)] = float(total or 0)

    unames = {u.id: u.username for u in db.query(_User.id, _User.username).all()}

    groups = {}
    for g in grids:
        key = (g.owner_id, g.package_tier)
        gp = groups.setdefault(key, {"grids": [], "seats": 0, "owner_purchased": False})
        gp["grids"].append({
            "grid_id": g.id, "advance": g.advance_number,
            "real_seats": rows.get(g.id, 0),
            "retired_at": g.retired_at.isoformat() if g.retired_at else None,
            "owner_purchased": bool(g.owner_purchased),
            "bonus_pool_stored": float(g.bonus_pool_accrued or 0),
        })
        gp["seats"] += rows.get(g.id, 0)
        if g.owner_purchased:
            gp["owner_purchased"] = True

    out_rows = []
    tot_expected = tot_paid = tot_topup_live = 0.0
    n_correct = n_under = n_over = n_need_succ = 0
    for (owner, tier), gp in groups.items():
        price = float(GRID_PACKAGES.get(tier, 0))
        expected = round(gp["seats"] * price * RATE, 2)
        paid = comm.get((owner, tier, "grid_completion_bonus", "paid"), 0.0)
        topup_reversed = comm.get((owner, tier, "grid_completion_bonus_topup", "reversed"), 0.0)
        topup_live = comm.get((owner, tier, "grid_completion_bonus_topup", "paid"), 0.0)
        delta = round(paid - expected, 2)
        has_succ = (owner, tier) in active
        needs_succ = gp["owner_purchased"] and not has_succ
        settlement = ("correct" if abs(delta) < 0.01 else
                      ("UNDERPAID" if delta < 0 else "OVERPAID"))
        tot_expected += expected; tot_paid += paid; tot_topup_live += topup_live
        if settlement == "correct": n_correct += 1
        elif settlement == "UNDERPAID": n_under += 1
        else: n_over += 1
        if needs_succ: n_need_succ += 1
        out_rows.append({
            "owner_id": owner, "username": unames.get(owner), "tier": tier,
            "real_seats": gp["seats"], "owner_purchased": gp["owner_purchased"],
            "honest_expected_usd": expected, "actually_paid_usd": round(paid, 2),
            "delta_usd": delta, "settlement": settlement,
            "phantom_topup_reversed_usd": round(topup_reversed, 2),
            "phantom_topup_STILL_LIVE_usd": round(topup_live, 2),
            "has_active_successor": has_succ, "needs_successor": needs_succ,
            "grids": gp["grids"],
        })

    out_rows.sort(key=lambda r: (r["settlement"] == "correct", -r["real_seats"]))
    return JSONResponse({
        "read_only": True, "rate": RATE,
        "owner_tier_groups": len(out_rows),
        "settled_correct": n_correct, "underpaid": n_under, "overpaid": n_over,
        "need_successor_grid": n_need_succ,
        "totals": {
            "honest_expected_usd": round(tot_expected, 2),
            "actually_paid_usd": round(tot_paid, 2),
            "net_delta_usd": round(tot_paid - tot_expected, 2),
            "phantom_topup_still_live_usd": round(tot_topup_live, 2),
        },
        "detail": out_rows,
        "note": ("honest_expected = real GridPosition rows x tier price x 10%. "
                 "actually_paid = paid grid_completion_bonus for owner+tier. delta ~0 = "
                 "settled correctly. phantom_topup_STILL_LIVE must be 0 (all reversed). "
                 "needs_successor = owner_purchased grid, completed, no active grid at that "
                 "tier = the Watch-to-Earn lockout. READ-ONLY, no writes."),
    })


@app.get("/admin/api/wte-successor-mint")
def admin_wte_successor_mint(
    apply: str = "",
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Members who genuinely purchased a campaign tier (owner_purchased grid)
    but have NO active (incomplete) grid at that tier are locked out of
    Watch-to-Earn: get_user_highest_tier returns -1, so /api/watch returns
    locked. The 12-Jun cut-off retired their legacy grids without minting the
    16-seat successor. This mints the missing successor per purchased tier so
    the member's tier is active again and WTE unlocks.

    Empty 16-seat grids only — NO money, NO commissions. Idempotent:
    get_or_create_active_grid returns an existing active grid rather than
    duplicating. Dry-run by default; pass ?apply=yes to mint.
    """
    _require_admin(user)
    from .database import Grid, User as _User
    from .grid import get_or_create_active_grid
    do_apply = apply.lower() in ("yes", "1", "true")

    by_owner = {}
    for g in db.query(Grid).all():
        by_owner.setdefault(g.owner_id, []).append(g)
    unames = {u.id: u.username for u in db.query(_User.id, _User.username).all()}

    rows, minted_rows = [], []
    n_locked = total_need = minted_count = 0
    for owner_id, gl in by_owner.items():
        purchased = sorted({g.package_tier for g in gl if g.owner_purchased})
        if not purchased:
            continue  # never genuinely bought a tier
        active = sorted({g.package_tier for g in gl if not g.is_complete})
        highest_active = max(active) if active else -1
        wte_locked = highest_active < 0
        need = [t for t in purchased if t not in active]
        if wte_locked:
            n_locked += 1
        total_need += len(need)
        row = {
            "user_id": owner_id, "username": unames.get(owner_id),
            "purchased_tiers": purchased, "active_tiers": active,
            "highest_active_tier": highest_active, "wte_locked": wte_locked,
            "tiers_needing_successor": need,
        }
        if do_apply and need:
            made = []
            for t in need:
                try:
                    g = get_or_create_active_grid(db, owner_id, t)
                    made.append({"tier": t, "grid_id": g.id,
                                 "advance": g.advance_number, "total_seats": g.total_seats})
                    minted_count += 1
                except Exception as e:
                    made.append({"tier": t, "error": str(e)})
            row["minted"] = made
            minted_rows.append({"user_id": owner_id, "username": unames.get(owner_id), "made": made})
        if need or wte_locked:
            rows.append(row)

    rows.sort(key=lambda r: (not r["wte_locked"], r["user_id"]))
    return JSONResponse({
        "read_only": not do_apply,
        "mode": "APPLIED" if do_apply else "dry-run",
        "paid_tier_members_needing_fix": len(rows),
        "wte_locked_count": n_locked,
        "successor_grids_needed": total_need,
        "minted_count": minted_count if do_apply else 0,
        "detail": rows,
        "note": ("wte_locked = no active grid at any tier -> /api/watch locked. "
                 "tiers_needing_successor = a purchased tier with no active grid. "
                 "Apply mints one empty 16-seat successor per needed tier "
                 "(get_or_create_active_grid, idempotent). No money, no commissions. "
                 "Pass ?apply=yes to execute."),
    })


@app.get("/admin/api/sponsor-integrity")
def admin_sponsor_integrity(
    focus_ids: str = "177,157",
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """READ-ONLY sponsor-chain integrity trace.

    admin_delete_user hard-deletes a user and NULLs sponsor_id on every downline
    member who had them as sponsor; a NULL sponsor renders in the referral UI as
    'under SuperAdPro' (root). This surfaces the damage:
      - orphaned_accounts: live non-admin users with sponsor_id NULL (the
        'now under you' victims of a deleted sponsor), with founding/active/
        created so legitimate paying members stand out from organic free signups.
      - counter_drift: users whose personal_referrals counter != real count of
        direct children (delta>0 = a child was deleted out from under them).
      - focus: the current direct downline of each focus_id vs its counter.
    No writes."""
    _require_admin(user)
    from .database import User as _U
    from sqlalchemy import func as _func

    child_counts = dict(
        db.query(_U.sponsor_id, _func.count(_U.id))
        .filter(_U.sponsor_id.isnot(None))
        .group_by(_U.sponsor_id).all()
    )

    def _u(u):
        return {"id": u.id, "username": u.username, "is_active": bool(u.is_active),
                "is_founding": bool(getattr(u, "is_founding_member", False)),
                "sponsor_id": u.sponsor_id,
                "pass_up_sponsor_id": getattr(u, "pass_up_sponsor_id", None),
                "personal_referrals": u.personal_referrals or 0,
                "actual_children": child_counts.get(u.id, 0),
                "created_at": u.created_at.isoformat() if getattr(u, "created_at", None) else None}

    orphans = (db.query(_U)
               .filter(_U.sponsor_id.is_(None), _U.id != 1, _U.is_admin == False)  # noqa: E711,E712
               .all())
    # founding/active first (most likely real victims), then by recency
    orphans.sort(key=lambda u: (not bool(getattr(u, "is_founding_member", False)),
                                not bool(u.is_active),
                                -(u.id or 0)))

    drift = []
    for u in db.query(_U).filter(_U.is_admin == False).all():  # noqa: E712
        actual = child_counts.get(u.id, 0)
        counter = u.personal_referrals or 0
        if actual != counter:
            drift.append({"id": u.id, "username": u.username,
                          "personal_referrals_counter": counter,
                          "actual_children": actual, "delta": counter - actual})

    focus = {}
    for fid in [int(x) for x in focus_ids.split(",") if x.strip().isdigit()]:
        owner = db.query(_U).filter(_U.id == fid).first()
        if not owner:
            focus[fid] = {"error": "not found"}
            continue
        kids = db.query(_U).filter(_U.sponsor_id == fid).order_by(_U.created_at.asc()).all()
        focus[fid] = {
            "username": owner.username, "sponsor_id": owner.sponsor_id,
            "personal_referrals_counter": owner.personal_referrals or 0,
            "actual_direct_children": len(kids),
            "children": [_u(k) for k in kids],
        }

    return JSONResponse({
        "read_only": True,
        "orphaned_count": len(orphans),
        "orphaned_founding_active_count": sum(
            1 for o in orphans if getattr(o, "is_founding_member", False) and o.is_active),
        "orphaned_accounts": [_u(o) for o in orphans],
        "counter_drift_count": len(drift),
        "counter_drift": sorted(drift, key=lambda d: d["delta"], reverse=True),
        "focus": focus,
        "note": ("orphaned = sponsor_id NULL (renders as 'under SuperAdPro'); founding+active "
                 "orphans are the likely real victims of a deleted upline. counter_drift delta>0 "
                 "= personal_referrals exceeds real children (a child was deleted). READ-ONLY."),
    })


@app.get("/admin/api/sponsor-relink")
def admin_sponsor_relink(
    apply: str = "",
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Restore the true sponsor for members whose sponsor_id was reset to NULL or
    to 1 (root). Reconstructs the real sponsor from the surviving Commission
    ledger: a member's sponsor-relationship commissions (membership_sponsor,
    direct_sponsor, etc.) fire from_user=member -> to_user=sponsor, so the
    recipient names the real sponsor even though sponsor_id was later corrupted.

    Only relinks where the ledger unambiguously names a different, valid,
    non-root sponsor. Members whose sponsor commissions genuinely went to user 1,
    or who have no sponsor commission at all (true direct signups), are left
    untouched. Dry-run by default; ?apply=yes writes sponsor_id only (the
    personal_referrals counters are broken platform-wide and need a separate
    recompute, so they are deliberately not touched here)."""
    _require_admin(user)
    from .database import User as _U, Commission as _C
    do_apply = apply.lower() in ("yes", "1", "true")
    SPONSOR_TYPES = ["membership_sponsor", "gift_membership_sponsor",
                     "membership_renewal", "direct_sponsor",
                     "direct_referral", "direct_sale"]

    valid_ids = {r.id for r in db.query(_U.id).all()}
    unames = {u.id: u.username for u in db.query(_U.id, _U.username).all()}

    candidates = (db.query(_U)
                  .filter(_U.id != 1, _U.is_admin == False,  # noqa: E712
                          (_U.sponsor_id.is_(None)) | (_U.sponsor_id == 1))
                  .all())

    rows = []
    n_relink = applied = 0
    for u in candidates:
        comms = (db.query(_C)
                 .filter(_C.from_user_id == u.id,
                         _C.commission_type.in_(SPONSOR_TYPES),
                         _C.to_user_id.isnot(None), _C.to_user_id != 1)
                 .order_by(_C.created_at.asc()).all())
        recipients = []
        for c in comms:
            if c.to_user_id not in recipients:
                recipients.append(c.to_user_id)
        orig = recipients[0] if recipients else None
        evidence = (f"{comms[0].commission_type} #{comms[0].id}" if comms else None)
        determinable = (orig is not None and orig in valid_ids and orig != u.id)
        needs = determinable and orig != u.sponsor_id
        action = ("RELINK" if needs else
                  ("already_correct" if (determinable and orig == u.sponsor_id)
                   else "undetermined_leave"))
        row = {
            "user_id": u.id, "username": u.username,
            "current_sponsor_id": u.sponsor_id,
            "reconstructed_sponsor_id": orig,
            "reconstructed_sponsor": unames.get(orig) if orig else None,
            "evidence": evidence,
            "recipient_conflict": recipients if len(recipients) > 1 else None,
            "action": action,
        }
        if needs:
            n_relink += 1
            if do_apply:
                u.sponsor_id = orig
                applied += 1
                row["applied"] = True
        if action != "already_correct":
            rows.append(row)
    if do_apply:
        db.commit()

    rows.sort(key=lambda r: (r["action"] != "RELINK", r["user_id"] or 0))
    return JSONResponse({
        "read_only": not do_apply,
        "mode": "APPLIED" if do_apply else "dry-run",
        "candidates_scanned": len(candidates),
        "relink_needed": n_relink,
        "relinked": applied if do_apply else 0,
        "detail": rows,
        "note": ("reconstructed_sponsor = recipient of the member's sponsor-relationship "
                 "commissions (from_user=member -> to_user=sponsor), which survived the "
                 "breach. RELINK = sponsor_id is NULL/1 but the ledger names a different "
                 "valid sponsor. undetermined_leave = no sponsor commission (true direct "
                 "signup or unrecoverable), left untouched. recipient_conflict flags the "
                 "rare >1-named-sponsor case. ?apply=yes writes sponsor_id only."),
    })


@app.get("/admin/api/sponsor-signals")
def admin_sponsor_signals(
    ids: str = "",
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Read-only forensic dump of every surviving sponsor signal for specific
    members, so we can see what the breach left behind before attempting any
    relink. For each id: current sponsor_id, pass_up_sponsor_id (the permanent
    pass-up chain), and the commission-ledger linkage both ways (rows authored
    BY this member name their sponsor in to_user_id; rows naming this member as
    recipient give context). Post-breach rebuilt commission rows carry
    from_user_id NULL, so a zero comm_from_count means the per-member linkage
    was lost in the rebuild and the ledger cannot name this member's sponsor."""
    _require_admin(user)
    from .database import User as _U, Commission as _C
    try:
        id_list = [int(x) for x in ids.split(",") if x.strip()]
    except ValueError:
        return JSONResponse({"error": "ids must be comma-separated integers"},
                            status_code=400)
    unames = {u.id: u.username for u in db.query(_U.id, _U.username).all()}
    out = []
    for uid in id_list:
        u = db.query(_U).filter(_U.id == uid).first()
        if not u:
            out.append({"user_id": uid, "error": "not found"})
            continue
        from_rows = (db.query(_C.commission_type, _C.to_user_id)
                     .filter(_C.from_user_id == uid).all())
        sponsor_named = {}
        for ct, to in from_rows:
            if to and to != 1:
                sponsor_named.setdefault(to, set()).add(ct)
        to_count = db.query(_C).filter(_C.to_user_id == uid).count()
        out.append({
            "user_id": uid, "username": u.username,
            "sponsor_id": u.sponsor_id,
            "pass_up_sponsor_id": u.pass_up_sponsor_id,
            "pass_up_username": unames.get(u.pass_up_sponsor_id),
            "comm_from_count": len(from_rows),
            "sponsor_named_by_ledger": {
                f"{k} ({unames.get(k)})": sorted(v) for k, v in sponsor_named.items()},
            "comm_to_count": to_count,
        })
    return JSONResponse({"read_only": True, "detail": out})


@app.get("/admin/api/backup-inspect")
def admin_backup_inspect(
    file: str = "",
    ids: str = "",
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Read-only: load a specific R2 backup and report the sponsor tree AS STORED
    IN THAT BACKUP, to find whether any surviving backup predates the sponsor
    corruption. Reports an aggregate health signal (how many users in the backup
    have a real, non-root sponsor) vs live, plus exact sponsor_id /
    pass_up_sponsor_id for specific ids. Compare the earliest vs latest backup to
    pinpoint when sponsor_id flipped to 1. No writes."""
    _require_admin(user)
    from .db_backup import load_backup, list_backups
    from .database import User as _U
    if not file:
        return JSONResponse({"error": "pass ?file=<name> (see /admin/api/backups)",
                             "available": list_backups()})
    payload = load_backup(file)
    if "error" in payload:
        return JSONResponse(payload, status_code=400)
    users = payload.get("tables", {}).get("users", [])
    if isinstance(users, dict) and "_error" in users:
        return JSONResponse({"error": f"users table not captured: {users['_error']}"},
                            status_code=400)
    total = len(users)
    real = sum(1 for u in users if u.get("sponsor_id") not in (None, 1))
    root = sum(1 for u in users if u.get("sponsor_id") == 1)
    nul = sum(1 for u in users if u.get("sponsor_id") is None)
    by_id = {u.get("id"): u for u in users}

    try:
        id_list = [int(x) for x in ids.split(",") if x.strip()]
    except ValueError:
        id_list = []
    detail = []
    for uid in id_list:
        bu = by_id.get(uid)
        if not bu:
            detail.append({"user_id": uid, "in_backup": False})
            continue
        detail.append({
            "user_id": uid, "username": bu.get("username"),
            "backup_sponsor_id": bu.get("sponsor_id"),
            "backup_pass_up_sponsor_id": bu.get("pass_up_sponsor_id"),
        })

    live_total = db.query(_U).count()
    live_real = db.query(_U).filter(_U.sponsor_id.isnot(None), _U.sponsor_id != 1).count()
    live_root = db.query(_U).filter(_U.sponsor_id == 1).count()
    live_nul = db.query(_U).filter(_U.sponsor_id.is_(None)).count()

    return JSONResponse({
        "read_only": True,
        "backup_file": file,
        "backup_timestamp": payload.get("meta", {}).get("timestamp"),
        "backup_users_total": total,
        "backup_sponsor_breakdown": {"real_non_root": real, "root_1": root, "null": nul},
        "live_sponsor_breakdown": {"total": live_total, "real_non_root": live_real,
                                   "root_1": live_root, "null": live_nul},
        "ids_detail": detail,
        "note": ("If backup real_non_root is much HIGHER than live real_non_root, this "
                 "backup predates the corruption and the true tree is recoverable from it. "
                 "If ids show backup_sponsor_id = the real sponsor (e.g. 330->177) while "
                 "live is 1, this backup holds the truth."),
    })


@app.get("/admin/api/grid-topup-reversal")
def admin_api_grid_topup_reversal(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    since_iso: str = "2026-06-07T22:00:00",
    apply: int = 0,
    code: str = "",
    restore_pools: int = 0,
):
    """Reverse erroneous grid_completion_bonus_topup credits caused this session.

    grid-position-replay recomputed bonus_pool_accrued from actual (wiped) rows,
    zeroing every COMPLETED grid's pool. The boot migration migrate_grid_bonus_pools
    (Pass 2) then read those as '$0 paid vs target' and credited owners the
    'shortfall' (campaign_balance + total_earned + bonus_earnings) plus a
    grid_completion_bonus_topup commission — a double-pay, since those bonuses were
    already paid historically.

    This reverses every grid_completion_bonus_topup created at/after since_iso
    (the session window — the legitimate pre-session May topup is excluded):
    deducts the amount from the recipient's three credited fields and marks the
    commission status='reversed' (row kept so the migration's notes-LIKE
    idempotency guard still blocks a re-fire). It ALSO restores every completed
    grid's bonus_pool_accrued to its policy target so no future deploy re-triggers
    Pass 2. Dry-run by default; ?apply=1&code=YOUR_2FA writes."""
    _require_admin(user)
    from .database import Commission, User as _User, Grid
    from datetime import datetime as _dt
    from decimal import Decimal as _Dec
    import pyotp

    TARGETS = {1: 72.0, 2: 180.0, 3: 360.0, 4: 720.0,
               5: 1440.0, 6: 2160.0, 7: 2880.0, 8: 3600.0}
    try:
        since = _dt.fromisoformat(since_iso)
    except Exception:
        return JSONResponse({"error": f"bad since_iso: {since_iso}"}, status_code=400)

    topups = (db.query(Commission)
              .filter(Commission.commission_type == "grid_completion_bonus_topup",
                      Commission.created_at >= since,
                      Commission.status != "reversed")
              .order_by(Commission.created_at.asc()).all())

    rev_plan = []
    for c in topups:
        u = db.query(_User).filter(_User.id == c.to_user_id).first()
        cur_cb = float(getattr(u, "campaign_balance", 0) or 0) if u else None
        amt = float(c.amount_usdt or 0)
        rev_plan.append({
            "commission_id": c.id, "user_id": c.to_user_id,
            "username": u.username if u else None, "amount": amt,
            "created_at": c.created_at.isoformat() if c.created_at else None,
            "current_campaign_balance": cur_cb,
            "campaign_balance_after": (round(cur_cb - amt, 2) if cur_cb is not None else None),
            "would_go_negative": (cur_cb is not None and cur_cb - amt < 0),
            "notes": (c.notes or "")[:90],
        })

    completed = db.query(Grid).filter(Grid.is_complete == True).all() if restore_pools else []
    pool_fixes = []
    for g in completed:
        target = TARGETS.get(int(g.package_tier))
        if target is None:
            continue
        if float(g.bonus_pool_accrued or 0) < target - 0.01:
            pool_fixes.append({"grid_id": g.id, "owner_id": g.owner_id, "tier": g.package_tier,
                               "advance": g.advance_number,
                               "pool_now": float(g.bonus_pool_accrued or 0), "restore_to": target})

    if not apply:
        return JSONResponse({
            "mode": "dry_run", "since_iso": since_iso,
            "erroneous_topups_found": len(rev_plan),
            "total_to_reverse_usd": round(sum(r["amount"] for r in rev_plan), 2),
            "any_would_go_negative": any(r["would_go_negative"] for r in rev_plan),
            "reversals": rev_plan,
            "completed_grids_pool_to_restore": len(pool_fixes),
            "pool_restore_detail": pool_fixes,
            "note": ("Dry-run — nothing written. Apply deducts each topup from the "
                     "recipient's campaign_balance/total_earned/bonus_earnings, marks the "
                     "commission reversed (row kept for idempotency), and restores completed "
                     "grids' pools to target so no future deploy re-triggers this. "
                     "?apply=1&code=YOUR_2FA. Verify the topup set is only this session's "
                     "(the legit May topup must NOT appear)."),
        })

    if not getattr(user, "totp_secret", None):
        return JSONResponse({"error": "Admin has no 2FA configured"}, status_code=400)
    if not pyotp.TOTP(user.totp_secret).verify(code.strip(), valid_window=1):
        return JSONResponse({"error": "Invalid or missing 2FA code — pass ?code=NNNNNN"}, status_code=403)

    reversed_n, reversed_usd = 0, 0.0
    for c in topups:
        u = db.query(_User).filter(_User.id == c.to_user_id).first()
        if not u:
            continue
        amt = _Dec(str(c.amount_usdt or 0))
        u.campaign_balance = _Dec(str(u.campaign_balance or 0)) - amt
        u.total_earned     = _Dec(str(u.total_earned or 0))     - amt
        u.bonus_earnings   = _Dec(str(u.bonus_earnings or 0))   - amt
        c.status = "reversed"
        c.notes = (c.notes or "") + " | REVERSED: erroneous session topup from replay-zeroed pool."
        reversed_n += 1
        reversed_usd += float(amt)

    restored = 0
    for g in completed:
        target = TARGETS.get(int(g.package_tier))
        if target is None:
            continue
        if float(g.bonus_pool_accrued or 0) < target - 0.01:
            g.bonus_pool_accrued = _Dec(str(target))
            restored += 1
    db.commit()

    return JSONResponse({
        "mode": "applied", "topups_reversed": reversed_n,
        "total_reversed_usd": round(reversed_usd, 2),
        "completed_grid_pools_restored": restored,
        "note": ("Erroneous session topups reversed (campaign_balance/total_earned/"
                 "bonus_earnings restored); commission rows kept as 'reversed' for "
                 "idempotency; completed-grid pools restored to target. No legitimate "
                 "historical topup touched."),
    })


@app.get("/admin/api/withdrawal-drain-audit")
def admin_api_withdrawal_drain_audit(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Read-only diagnosis of the TREASURY DRAIN SIGNAL watchdog alert.

    The alert fires on unexplained = (baseline_treasury - current_treasury)
    - (current_paid_wd_total - baseline_paid_wd_total). A treasury that fell $0
    with a NEGATIVE newly_paid (paid-withdrawal total dropped) produces a phantom
    'drain' equal to that drop — no USDT actually left. This dumps the secwatch
    baselines, the live treasury read, the current paid-withdrawal total, and
    every withdrawal row with its timestamps, so the drop can be traced to the
    exact records and time. No writes."""
    _require_admin(user)
    from .database import Withdrawal
    from sqlalchemy import func as _f

    base_treasury = _secwatch_get(db, "secwatch_treasury_usdt", "")
    base_paid_wd  = _secwatch_get(db, "secwatch_paid_wd_total", "")
    last_tick     = _secwatch_get(db, "secwatch_last_tick_ts", "")

    cur_paid_total = float(db.query(_f.coalesce(_f.sum(Withdrawal.amount_usdt), 0))
                           .filter(Withdrawal.status == "paid").scalar() or 0)
    cur_paid_count = db.query(Withdrawal).filter(Withdrawal.status == "paid").count()

    cur_treasury = None
    try:
        from .walletconnect_payments import health_check as _bsc_health
        cur_treasury = _bsc_health().get("treasury_usdt")
    except Exception as e:
        cur_treasury = f"read_failed: {e}"

    by_status = dict(db.query(Withdrawal.status, _f.count(Withdrawal.id))
                     .group_by(Withdrawal.status).all())

    rows = (db.query(Withdrawal)
            .order_by(Withdrawal.processed_at.desc().nullslast(),
                      Withdrawal.requested_at.desc()).limit(60).all())
    wd = [{
        "id": w.id, "user_id": w.user_id, "amount_usdt": float(w.amount_usdt or 0),
        "status": w.status, "network": w.network, "wallet_type": w.wallet_type,
        "tx_hash": (w.tx_hash or "")[:24],
        "requested_at": w.requested_at.isoformat() if w.requested_at else None,
        "processed_at": w.processed_at.isoformat() if w.processed_at else None,
        "notes": (w.notes or "")[:80],
    } for w in rows]

    baseline_minus_current = None
    try:
        baseline_minus_current = round(float(base_paid_wd) - cur_paid_total, 2)
    except Exception:
        pass

    return JSONResponse({
        "secwatch_baselines": {
            "treasury_usdt": base_treasury, "paid_wd_total": base_paid_wd,
            "last_tick_ts": last_tick,
        },
        "live_now": {
            "treasury_usdt": cur_treasury,
            "paid_withdrawal_total": round(cur_paid_total, 2),
            "paid_withdrawal_count": cur_paid_count,
        },
        "baseline_paid_wd_minus_current": baseline_minus_current,
        "withdrawals_by_status": {k: v for k, v in by_status.items()},
        "recent_withdrawals": wd,
        "note": ("If baseline_paid_wd_minus_current is positive, the paid-withdrawal "
                 "total dropped by that amount since the baseline (records removed / "
                 "status-changed / amounts reduced) — which is what the watchdog read as "
                 "a 'drain' even though treasury_usdt did not fall. The watchdog "
                 "re-baselines each successful tick, so the alert is one-time, not "
                 "ongoing. Cross-check withdrawal processed_at timestamps against the "
                 "alert time (2026-06-07T19:08:43Z) to identify the cause."),
    })


@app.get("/admin/api/seat-member")
def admin_api_seat_member(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    member_id: int = 451,
    tier: int = 1,
    apply: int = 0,
    code: str = "",
    include_root: int = 0,
):
    """Seat one member into their upline grids for a tier they bought — the
    placement the live flow should have made but didn't.

    Use case: 451 (stevenh) bought tier 1 post-reopen while his sponsor_id was
    still null (mid sponsor-recovery), so _spillover_fill walked an empty chain
    and seated him nowhere. With the tree now restored (451 -> 432 -> 349 -> ...),
    this walks his sponsor chain and seats him in each ancestor's ACTIVE grid at
    the tier, at the next open slot, idempotently (skips any grid where he is
    already seated). It marks the member's OWN grid owner_purchased=True.

    Surgical and safe: positions only — NO commissions fire (his were already
    paid at purchase). It recomputes positions_filled/revenue_total/bonus_pool
    ONLY for the active grids it touches, and NEVER touches a completed grid's
    bonus pool (the mistake that triggered the retroactive-topup cascade).
    Dry-run by default; ?apply=1&code=YOUR_2FA writes."""
    _require_admin(user)
    from .database import (Grid, GridPosition, User as _User,
                           GRID_PACKAGES as _PKG, GRID_TOTAL as _TOTAL,
                           GRID_WIDTH as _W, BONUS_POOL_PCT as _BPCT,
                           bonus_pct_for as _bpf)
    from .grid import _policy_bonus_target
    from decimal import Decimal as _Dec
    import pyotp

    if tier not in _PKG:
        return JSONResponse({"error": f"unknown tier {tier}"}, status_code=400)
    m = db.query(_User).filter(_User.id == member_id).first()
    if not m:
        return JSONResponse({"error": f"member {member_id} not found"}, status_code=404)

    sponsor_of = {r.id: r.sponsor_id for r in db.query(_User.id, _User.sponsor_id).all()}
    uname_of   = {r.id: r.username for r in db.query(_User.id, _User.username).all()}
    is_admin_of = {r.id: bool(r.is_admin) for r in db.query(_User.id, _User.is_admin).all()}

    def _active_grid(owner):
        return (db.query(Grid).filter(Grid.owner_id == owner, Grid.package_tier == tier,
                                      Grid.is_complete == False)
                .order_by(Grid.advance_number.asc(), Grid.id.asc()).first())

    # walk the member's upline chain
    chain, seen, cur = [], set(), member_id
    while True:
        anc = sponsor_of.get(cur)
        if not anc or anc in seen:
            break
        seen.add(anc)
        chain.append(anc)
        cur = anc

    # The company/admin root grid is managed separately (grid-root-restore) and
    # was deliberately excluded from buyer seating in the full rebuild. Stay
    # consistent: don't seat into an admin root unless explicitly asked.
    if not include_root:
        chain = [a for a in chain if not is_admin_of.get(a, False)]

    plan = []
    for anc in chain:
        g = _active_grid(anc)
        already = False
        slot_idx = 0
        if g:
            already = db.query(GridPosition).filter(
                GridPosition.grid_id == g.id, GridPosition.member_id == member_id).count() > 0
            slot_idx = db.query(GridPosition).filter(GridPosition.grid_id == g.id).count()
        plan.append({
            "upline_id": anc, "username": uname_of.get(anc),
            "grid_id": g.id if g else None,
            "grid_will_be_created": g is None,
            "already_seated": already,
            "seat_at_level": (slot_idx // _W + 1) if not already else None,
            "seat_at_position": (slot_idx % _W + 1) if not already else None,
        })
    to_seat = [p for p in plan if not p["already_seated"]]

    own = _active_grid(member_id)
    own_state = {"grid_id": own.id if own else None,
                 "owner_purchased_now": bool(own.owner_purchased) if own else None,
                 "will_set_owner_purchased": bool(own and not own.owner_purchased)}

    if not apply:
        return JSONResponse({
            "mode": "dry_run", "member_id": member_id,
            "member_username": uname_of.get(member_id), "tier": tier,
            "upline_chain": [{"id": a, "username": uname_of.get(a)} for a in chain],
            "seats_to_add": len(to_seat),
            "placement_plan": plan,
            "own_grid": own_state,
            "note": ("Dry-run — nothing written. Apply seats the member in each upline's "
                     "active grid (skipping any where already seated), sets the member's own "
                     "grid owner_purchased=True, and recomputes ONLY the touched active grids' "
                     "counters from actual rows. No commissions fire. Completed grids are "
                     "never touched. ?apply=1&code=YOUR_2FA."),
        })

    if not getattr(user, "totp_secret", None):
        return JSONResponse({"error": "Admin has no 2FA configured"}, status_code=400)
    if not pyotp.TOTP(user.totp_secret).verify(code.strip(), valid_window=1):
        return JSONResponse({"error": "Invalid or missing 2FA code — pass ?code=NNNNNN"}, status_code=403)

    touched_grids = set()
    seated = 0
    for anc in chain:
        g = _active_grid(anc)
        if not g:
            g = Grid(owner_id=anc, package_tier=tier, package_price=_PKG.get(tier, 0),
                     advance_number=1, positions_filled=0, revenue_total=0,
                     bonus_pool_accrued=0, is_complete=False, owner_purchased=False)
            db.add(g); db.flush()
        if db.query(GridPosition).filter(GridPosition.grid_id == g.id,
                                         GridPosition.member_id == member_id).count() == 0:
            idx = db.query(GridPosition).filter(GridPosition.grid_id == g.id).count()
            db.add(GridPosition(grid_id=g.id, member_id=member_id,
                                grid_level=idx // _W + 1, position_num=idx % _W + 1,
                                is_overspill=True))
            seated += 1
        touched_grids.add(g.id)

    own = _active_grid(member_id)
    if own and not own.owner_purchased:
        own.owner_purchased = True
        touched_grids.add(own.id)
    db.flush()

    # recompute ONLY the touched ACTIVE grids from actual rows (never completed)
    for gid in touched_grids:
        g = db.query(Grid).filter(Grid.id == gid).first()
        if not g or g.is_complete:
            continue
        cnt = db.query(GridPosition).filter(GridPosition.grid_id == gid).count()
        price = _Dec(str(_PKG.get(g.package_tier, 0)))
        g.positions_filled = cnt
        g.revenue_total = price * cnt
        target = _Dec(str(_policy_bonus_target(g.package_tier, g.total_seats)))
        accrued = (price * cnt) * _Dec(str(_bpf(g.total_seats)))
        g.bonus_pool_accrued = min(target, accrued) if target > 0 else accrued
    db.commit()

    return JSONResponse({
        "mode": "applied", "member_id": member_id, "tier": tier,
        "seats_added": seated, "grids_touched": len(touched_grids),
        "note": ("Member seated into upline grids; own grid marked purchased. No "
                 "commissions fired; no completed grid touched."),
    })


@app.get("/admin/api/member-entitlement")
def admin_api_member_entitlement(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    user_id: int = 0,
):
    """Wipe-recovery foundation: for one member, read every PAYMENT-TRUTH source
    that lives OUTSIDE the wiped Payment/Grid/credit tables — Stripe charges,
    WalletConnect (BSC) orders, NOWPayments orders — and compare against their
    current entitlement state (grids, credits). Tells us exactly what a member
    PAID FOR vs what they currently HAVE, which is the basis for restoring
    campaign tiers and creator credits without inventing value.

    Read-only. Each source is wrapped independently so a missing/wiped table
    degrades gracefully instead of failing the whole report."""
    _require_admin(user)
    from .database import (StripeCharge, WalletConnectPaymentOrder, NowPaymentsOrder,
                           Grid, GridPosition, SuperSceneCredit, User as _User)
    target = db.query(_User).filter(_User.id == user_id).first()
    if not target:
        return JSONResponse({"error": f"User {user_id} not found"}, status_code=404)

    out = {"user_id": user_id, "username": target.username,
           "is_active": bool(target.is_active),
           "membership_tier": getattr(target, "membership_tier", None),
           "is_founding_member": bool(getattr(target, "is_founding_member", False)),
           "founding_spot": getattr(target, "founding_spot_number", None),
           "wallet_address": getattr(target, "wallet_address", None),
           "created_at": target.created_at.isoformat() if target.created_at else None}

    # ── PAID TRUTH (survives outside the wiped tables) ──
    try:
        sc = db.query(StripeCharge).filter(StripeCharge.user_id == user_id).order_by(
            StripeCharge.created_at.asc()).all()
        out["stripe_charges"] = [{
            "product": c.product, "kind": c.kind,
            "amount_usd": round((c.amount_cents or 0) / 100.0, 2),
            "created_at": c.created_at.isoformat() if c.created_at else None,
        } for c in sc]
    except Exception as e:
        out["stripe_charges"] = f"ERR {type(e).__name__}"

    try:
        wc = db.query(WalletConnectPaymentOrder).filter(
            WalletConnectPaymentOrder.user_id == user_id).order_by(
            WalletConnectPaymentOrder.created_at.asc()).all()
        out["walletconnect_orders"] = [{
            "product_type": o.product_type, "product_key": o.product_key,
            "amount_usd": float(o.base_amount or 0), "status": o.status,
            "tx_hash": o.tx_hash,
            "confirmed_at": o.confirmed_at.isoformat() if o.confirmed_at else None,
            "created_at": o.created_at.isoformat() if o.created_at else None,
        } for o in wc]
    except Exception as e:
        out["walletconnect_orders"] = f"ERR {type(e).__name__}"

    try:
        npo = db.query(NowPaymentsOrder).filter(
            NowPaymentsOrder.user_id == user_id).order_by(
            NowPaymentsOrder.created_at.asc()).all()
        out["nowpayments_orders"] = [{
            "product_type": o.product_type, "product_key": o.product_key,
            "amount_usd": float(o.price_usd or 0), "status": o.status,
            "confirmed_at": o.confirmed_at.isoformat() if o.confirmed_at else None,
            "created_at": o.created_at.isoformat() if o.created_at else None,
        } for o in npo]
    except Exception as e:
        out["nowpayments_orders"] = f"ERR {type(e).__name__}"

    # ── CURRENT STATE (what they have now, post-wipe) ──
    try:
        out["grids_owned"] = db.query(Grid).filter(Grid.owner_id == user_id).count()
        out["grids_incomplete"] = db.query(Grid).filter(
            Grid.owner_id == user_id, Grid.is_complete == False).count()
        out["grid_positions_held"] = db.query(GridPosition).filter(
            GridPosition.member_id == user_id).count()
    except Exception as e:
        out["grid_state"] = f"ERR {type(e).__name__}"
    try:
        ssc = db.query(SuperSceneCredit).filter(SuperSceneCredit.user_id == user_id).first()
        out["creator_credit_balance"] = int(ssc.balance) if ssc else 0
    except Exception as e:
        out["creator_credit_balance"] = f"ERR {type(e).__name__}"
    out["campaign_balance"] = float(getattr(target, "campaign_balance", 0) or 0)
    out["grid_earnings"] = float(getattr(target, "grid_earnings", 0) or 0)
    out["total_earned"] = float(getattr(target, "total_earned", 0) or 0)

    # ── ENTITLEMENT DERIVATION (what paid truth says they should have) ──
    def _confirmed(rows):
        if not isinstance(rows, list):
            return []
        return rows
    paid_tier, paid_credits, paid_nexus = [], [], []
    for o in _confirmed(out.get("walletconnect_orders")) + _confirmed(out.get("nowpayments_orders")):
        if o.get("status") in ("confirmed", "finished"):
            pt = (o.get("product_type") or "").lower()
            if pt == "grid":
                paid_tier.append(o)
            elif pt == "superscene":
                paid_credits.append(o)
            elif pt == "nexus":
                paid_nexus.append(o)
    for c in _confirmed(out.get("stripe_charges")):
        if c.get("kind") == "charge":
            p = (c.get("product") or "").lower()
            if p == "campaign_tier":
                paid_tier.append(c)
            elif p == "creative_credits":
                paid_credits.append(c)
            elif p == "nexus_pack":
                paid_nexus.append(c)
    out["entitlement_summary"] = {
        "paid_for_campaign_tier": len(paid_tier) > 0,
        "campaign_tier_purchases": paid_tier,
        "credit_pack_purchases": paid_credits,
        "nexus_pack_purchases": paid_nexus,
        "has_active_grid_now": out.get("grids_incomplete", 0) > 0 if isinstance(out.get("grids_incomplete"), int) else None,
        "credit_balance_now": out.get("creator_credit_balance"),
    }
    out["note"] = ("Paid truth = stripe_charges + confirmed walletconnect/nowpayments "
                   "orders (these live outside the wiped Payment/Grid/credit tables). "
                   "Gap between entitlement_summary and current state = what to restore.")
    return JSONResponse(out)


@app.get("/admin/api/stripe-reconciliation")
def admin_api_stripe_reconciliation(
    request: Request,
    days: int = 7,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Admin diagnostic: cross-check every Stripe charge in the last N days
    against the corresponding platform fulfillment row.

    For each StripeCharge row (kind='charge', amount_cents > 0), verify the
    product was actually delivered:

      product='founder_signup'      → User.is_active = True
      product='membership_signup'   → User.is_active = True
      product='founder_renewal'     → User.is_active = True AND
                                       User.membership_expires_at >= charge time
      product='membership_renewal'  → User.is_active = True AND
                                       User.membership_expires_at >= charge time
      product='campaign_tier'       → GridPosition exists for user, created
                                       within 10 min of charge timestamp, OR
                                       a manual_recovery_user{N}_grid* Payment
                                       row exists from after the charge.
      product='nexus_pack'          → CreditPackPurchase row exists with
                                       payment_ref containing the Stripe
                                       session_id and status='completed'
      product='pif_voucher'         → GiftVoucher row exists with payment_ref
                                       containing the Stripe session_id

    Built 29 May 2026 in response to the Michell Gustavsson case where a
    $20 succeeded Stripe charge looked suspicious in lookup_user but turned
    out to be a Nexus pack that DID fulfill correctly. The lesson was that
    no single tool gave us a 'did every Stripe charge in the last week
    actually deliver a product' view. This endpoint provides that.

    Read-only. Returns matched (sampled), mismatched (full list — these are
    the real problems), and any charges with unknown product kinds.

    Bounded: days is capped at 90 to avoid runaway queries. Default 7.

    Returns 200 with structured JSON. mismatched_count > 0 is the signal to
    investigate — those are charges where the customer paid but our DB
    has no evidence we delivered the product.
    """
    _require_admin(user)
    from .database import (
        StripeCharge, GridPosition, CreditPackPurchase,
        GiftVoucher, Payment, User as _User,
    )
    from datetime import datetime, timedelta

    if days < 1:
        days = 1
    if days > 90:
        days = 90

    since = datetime.utcnow() - timedelta(days=days)

    # Only positive-amount charges. Refunds (amount_cents < 0) and chargebacks
    # aren't fulfillment events to check.
    charges = (
        db.query(StripeCharge)
        .filter(
            StripeCharge.created_at >= since,
            StripeCharge.kind == "charge",
            StripeCharge.amount_cents > 0,
        )
        .order_by(StripeCharge.created_at.desc())
        .all()
    )

    matched = []
    mismatched = []
    unknown = []

    # Window for time-based fulfillment matching. Webhooks normally process
    # in sub-second; 10 min is a generous buffer that still attributes
    # correctly. Looking backwards by 2 min handles edge case where the
    # fulfillment row's clock is slightly ahead of the charge's.
    WINDOW_BEFORE = timedelta(minutes=2)
    WINDOW_AFTER = timedelta(minutes=10)

    for ch in charges:
        win_start = ch.created_at - WINDOW_BEFORE
        win_end = ch.created_at + WINDOW_AFTER

        ok = None
        detail = {}

        target = db.query(_User).filter(_User.id == ch.user_id).first()

        if ch.product in ("founder_signup", "membership_signup"):
            ok = bool(target and target.is_active)
            detail = {
                "check": "user_active_after_signup",
                "user_active": bool(target.is_active) if target else False,
                "activated_at": target.activated_at.isoformat() if target and target.activated_at else None,
            }

        elif ch.product in ("founder_renewal", "membership_renewal"):
            expires = target.membership_expires_at if target else None
            ok = bool(
                target and target.is_active
                and expires and expires >= ch.created_at
            )
            detail = {
                "check": "user_active_and_expiry_covers_charge_time",
                "user_active": bool(target.is_active) if target else False,
                "expires_at": expires.isoformat() if expires else None,
                "charge_time": ch.created_at.isoformat() if ch.created_at else None,
            }

        elif ch.product == "campaign_tier":
            # GridPosition created in the window (any one is enough — a tier
            # purchase walks up the sponsor chain creating multiple rows).
            gpos = (
                db.query(GridPosition)
                .filter(
                    GridPosition.member_id == ch.user_id,
                    GridPosition.created_at >= win_start,
                    GridPosition.created_at <= win_end,
                )
                .first()
            )
            # Manual recovery fallback (an admin granted Tier post-hoc).
            recovery = (
                db.query(Payment)
                .filter(
                    Payment.from_user_id == ch.user_id,
                    Payment.tx_hash.like(f"manual_recovery_user{ch.user_id}_grid%"),
                    Payment.status == "confirmed",
                    Payment.created_at >= ch.created_at,
                )
                .first()
            )
            ok = bool(gpos) or bool(recovery)
            detail = {
                "check": "grid_position_in_window_or_manual_recovery",
                "grid_position_id": gpos.id if gpos else None,
                "grid_position_created_at": gpos.created_at.isoformat() if gpos and gpos.created_at else None,
                "manual_recovery_payment_id": recovery.id if recovery else None,
                "manual_recovery_tx_hash": recovery.tx_hash if recovery else None,
            }

        elif ch.product == "nexus_pack":
            # Match by session_id in payment_ref (the writer uses
            # payment_ref=f"stripe_{session_id}"). Fall back to time window
            # if session_id is null on the charge.
            pack = None
            if ch.stripe_session_id:
                pack = (
                    db.query(CreditPackPurchase)
                    .filter(
                        CreditPackPurchase.user_id == ch.user_id,
                        CreditPackPurchase.payment_ref.like(f"%{ch.stripe_session_id}%"),
                    )
                    .first()
                )
            if not pack:
                pack = (
                    db.query(CreditPackPurchase)
                    .filter(
                        CreditPackPurchase.user_id == ch.user_id,
                        CreditPackPurchase.created_at >= win_start,
                        CreditPackPurchase.created_at <= win_end,
                        CreditPackPurchase.payment_method == "stripe",
                    )
                    .first()
                )
            ok = bool(pack) and (pack.status == "completed")
            detail = {
                "check": "credit_pack_purchase_completed",
                "pack_id": pack.id if pack else None,
                "pack_status": pack.status if pack else None,
                "pack_key": pack.pack_key if pack else None,
                "match_method": (
                    "session_id" if pack and ch.stripe_session_id and ch.stripe_session_id in (pack.payment_ref or "")
                    else "time_window" if pack else "none"
                ),
            }

        elif ch.product == "pif_voucher":
            voucher = None
            if ch.stripe_session_id:
                voucher = (
                    db.query(GiftVoucher)
                    .filter(
                        GiftVoucher.gifter_user_id == ch.user_id,
                        GiftVoucher.payment_ref.like(f"%{ch.stripe_session_id}%"),
                    )
                    .first()
                )
            if not voucher:
                voucher = (
                    db.query(GiftVoucher)
                    .filter(
                        GiftVoucher.gifter_user_id == ch.user_id,
                        GiftVoucher.created_at >= win_start,
                        GiftVoucher.created_at <= win_end,
                    )
                    .first()
                )
            ok = bool(voucher)
            detail = {
                "check": "gift_voucher_created",
                "voucher_id": voucher.id if voucher else None,
                "voucher_code": voucher.voucher_code if voucher else None,
                "voucher_status": voucher.status if voucher else None,
            }

        else:
            # Unknown product type — don't blow up, just flag.
            detail = {"check": "unknown_product"}

        row = {
            "charge_id": ch.id,
            "user_id": ch.user_id,
            "username": target.username if target else None,
            "email": target.email if target else None,
            "product": ch.product,
            "amount_cents": ch.amount_cents,
            "stripe_session_id": ch.stripe_session_id,
            "stripe_payment_intent_id": ch.stripe_payment_intent_id,
            "stripe_subscription_id": ch.stripe_subscription_id,
            "created_at": ch.created_at.isoformat() if ch.created_at else None,
            "fulfillment": detail,
        }

        if ok is True:
            matched.append(row)
        elif ok is False:
            mismatched.append(row)
        else:
            unknown.append(row)

    # Group mismatched by product so it's easier to scan
    mismatched_by_product = {}
    for r in mismatched:
        mismatched_by_product.setdefault(r["product"], []).append(r)

    return JSONResponse({
        "since": since.isoformat() + "Z",
        "days": days,
        "total_charges_checked": len(charges),
        "matched_count": len(matched),
        "mismatched_count": len(mismatched),
        "unknown_count": len(unknown),
        "mismatched_by_product_summary": {
            k: len(v) for k, v in mismatched_by_product.items()
        },
        "mismatched": mismatched,
        "unknown": unknown,
        "matched_sample": matched[:5],
    })


@app.get("/admin/api/stripe-phantom-charges")
def admin_api_stripe_phantom_charges(
    request: Request,
    dry_run: bool = True,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Find (and optionally remove) phantom duplicate charge rows created by
    the pre-1-Jun-2026 invoice.paid bug: a subscription's FIRST invoice was
    mislabelled membership_renewal/founder_renewal and written as a second
    charge row alongside the real *_signup row from checkout.session.completed,
    inflating revenue.

    A phantom is a *_renewal charge whose stripe_subscription_id also has a
    *_signup charge for the same user created within 5 minutes — i.e. a
    'renewal' that landed seconds after signup. Real renewals are a month+ later.

    Read-only by default. Navigate ?dry_run=false to actually delete the
    phantom rows. Browser-navigable, admin auth only.
    """
    _require_admin(user)
    from datetime import timedelta as _td

    renewals = (
        db.query(StripeCharge)
        .filter(
            StripeCharge.kind == "charge",
            StripeCharge.product.in_(["membership_renewal", "founder_renewal"]),
            StripeCharge.stripe_subscription_id.isnot(None),
        )
        .order_by(StripeCharge.created_at.asc())
        .all()
    )

    phantoms = []
    for r in renewals:
        signup = (
            db.query(StripeCharge)
            .filter(
                StripeCharge.kind == "charge",
                StripeCharge.product.in_(["membership_signup", "founder_signup"]),
                StripeCharge.stripe_subscription_id == r.stripe_subscription_id,
                StripeCharge.user_id == r.user_id,
            )
            .order_by(StripeCharge.created_at.asc())
            .first()
        )
        if not signup or not signup.created_at or not r.created_at:
            continue
        gap = abs((r.created_at - signup.created_at).total_seconds())
        if gap <= 300:  # renewal within 5 min of signup = phantom first-invoice
            phantoms.append({
                "phantom_charge_id": r.id,
                "user_id": r.user_id,
                "subscription_id": r.stripe_subscription_id,
                "phantom_product": r.product,
                "phantom_amount_usd": round((r.amount_cents or 0) / 100, 2),
                "phantom_created_at": r.created_at.isoformat(),
                "paired_signup_charge_id": signup.id,
                "signup_created_at": signup.created_at.isoformat(),
                "gap_seconds": round(gap, 1),
            })

    phantom_total_usd = round(sum(p["phantom_amount_usd"] for p in phantoms), 2)

    deleted = 0
    if not dry_run and phantoms:
        ids = [p["phantom_charge_id"] for p in phantoms]
        deleted = (
            db.query(StripeCharge)
            .filter(StripeCharge.id.in_(ids))
            .delete(synchronize_session=False)
        )
        db.commit()

    return JSONResponse({
        "dry_run": dry_run,
        "phantom_count": len(phantoms),
        "phantom_total_usd_removed_from_revenue": phantom_total_usd,
        "deleted_rows": deleted,
        "phantoms": phantoms,
        "note": (
            "Dry run — navigate ?dry_run=false to delete these rows."
            if dry_run else
            f"Deleted {deleted} phantom charge row(s). Revenue figures will drop "
            f"by ${phantom_total_usd} (correcting the double-count)."
        ),
    })


@app.get("/admin/api/rotator-state")
def admin_api_rotator_state(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Admin diagnostic: full rotator queue introspection.

    Returns:
      queue: every row in rotator_queue with the joined user details
        (queue_position, user_id, username, is_active, rotator_opted_in,
        is_admin, is_founding_member, last_assigned_at)
      eligible_pick: who would be picked next given the current filters
      recent_assignments: last 20 rotator-assigned signups with sponsors
      diagnostics: counts that explain queue state at a glance

    Built 16 May 2026 in response to Steve reporting that /start signups
    were landing on the house account — needed visibility to diagnose
    whether the queue was empty, had ineligible rows, or had a picker
    bug. Keep this endpoint long term; rotator state should always be
    inspectable.
    """
    _require_admin(user)
    from sqlalchemy import text as _text

    queue_rows = db.execute(_text("""
        SELECT rq.queue_position, rq.user_id, u.username,
               u.is_active, u.rotator_opted_in, u.is_admin,
               u.is_founding_member, u.founding_spot_number,
               rq.joined_at, rq.last_assigned_at
          FROM rotator_queue rq
          JOIN users u ON u.id = rq.user_id
         ORDER BY rq.queue_position ASC
    """)).fetchall()
    queue = [{
        "queue_position": r[0],
        "user_id": r[1],
        "username": r[2],
        "is_active": bool(r[3]),
        "rotator_opted_in": bool(r[4]),
        "is_admin": bool(r[5]),
        "is_founding_member": bool(r[6]),
        "founding_spot_number": r[7],
        "joined_at": r[8].isoformat() if r[8] else None,
        "last_assigned_at": r[9].isoformat() if r[9] else None,
        "eligible_for_pick": bool(r[3]) and bool(r[4]),
    } for r in queue_rows]

    eligible_pick_row = db.execute(_text(
        "SELECT rq.user_id, u.username "
        "  FROM rotator_queue rq "
        "  JOIN users u ON u.id = rq.user_id "
        " WHERE u.is_active = true "
        "   AND u.rotator_opted_in = true "
        " ORDER BY rq.queue_position ASC "
        " LIMIT 1"
    )).fetchone()
    eligible_pick = None
    if eligible_pick_row:
        eligible_pick = {"user_id": eligible_pick_row[0], "username": eligible_pick_row[1]}

    recent_rows = db.execute(_text("""
        SELECT ra.id, ra.signup_user_id, su.username AS signup_username,
               ra.assigned_sponsor_id, sp.username AS sponsor_username,
               ra.funnel_source, ra.assigned_at
          FROM rotator_assignments ra
          LEFT JOIN users su ON su.id = ra.signup_user_id
          LEFT JOIN users sp ON sp.id = ra.assigned_sponsor_id
         ORDER BY ra.id DESC
         LIMIT 20
    """)).fetchall()
    recent_assignments = [{
        "id": r[0],
        "signup_user_id": r[1],
        "signup_username": r[2],
        "assigned_sponsor_id": r[3],
        "assigned_sponsor_username": r[4],
        "funnel_source": r[5],
        "assigned_at": r[6].isoformat() if r[6] else None,
    } for r in recent_rows]

    total_in_queue = len(queue)
    eligible_count = sum(1 for q in queue if q["eligible_for_pick"])
    opted_in_users = db.execute(_text(
        "SELECT COUNT(*) FROM users WHERE rotator_opted_in = true"
    )).scalar() or 0
    active_founders = db.execute(_text(
        "SELECT COUNT(*) FROM users "
        " WHERE is_active = true "
        "   AND is_founding_member = true "
        "   AND COALESCE(is_admin, FALSE) = FALSE"
    )).scalar() or 0

    return {
        "diagnostics": {
            "total_in_queue": total_in_queue,
            "eligible_for_pick_now": eligible_count,
            "opted_in_users_total": opted_in_users,
            "active_non_admin_founders": active_founders,
            "queue_works": eligible_pick is not None,
        },
        "next_pick_would_be": eligible_pick,
        "queue": queue,
        "recent_assignments": recent_assignments,
    }


def _enrol_user_to_rotator(db: Session, user_id: int) -> bool:
    """Add a user to the rotator queue at the back, flip rotator_opted_in=TRUE.

    Idempotent: if the user is already in rotator_queue, no-op. If they're
    already opted in, no-op. Safe to call from any code path that creates
    or activates a Founder — the caller doesn't need to check whether
    the user is already enrolled.

    Returns True if a new row was inserted, False if the user was already
    in the queue.

    Concurrency: queue_position is computed as MAX+1 inside this call. Two
    simultaneous Founder activations could theoretically race and produce
    duplicate positions, but rotator_queue.user_id is UNIQUE so the second
    INSERT would fail (caught by ON CONFLICT DO NOTHING). The picker
    sorts by queue_position ASC and tolerates duplicate positions —
    worst case is one extra signup landing on the same Founder before
    they rotate. Not worth the cost of a serialised lock for what's at
    most one or two activations per minute in real load.
    """
    from sqlalchemy import text as _text
    try:
        max_pos_row = db.execute(_text(
            "SELECT COALESCE(MAX(queue_position), 0) FROM rotator_queue"
        )).fetchone()
        new_pos = (max_pos_row[0] or 0) + 1
        result = db.execute(_text(
            "INSERT INTO rotator_queue (user_id, queue_position, joined_at) "
            "VALUES (:uid, :pos, NOW()) ON CONFLICT (user_id) DO NOTHING"
        ), {"uid": user_id, "pos": new_pos})
        db.execute(_text(
            "UPDATE users SET rotator_opted_in = TRUE "
            "WHERE id = :uid AND COALESCE(rotator_opted_in, FALSE) = FALSE"
        ), {"uid": user_id})
        inserted = bool(getattr(result, 'rowcount', 0))
        if inserted:
            logger.info(f"rotator: enrolled user_id={user_id} at queue_position={new_pos}")
        return inserted
    except Exception as e:
        logger.warning(f"rotator: enrol failed for user_id={user_id}: {e}")
        return False


def _pick_next_rotator_sponsor(db: Session):
    """Return the user_id at the front of the rotator queue, atomically
    moving them to the back. Returns None if queue is empty.

    Concurrency-safe via pg_advisory_xact_lock — same pattern the
    founding-spot claim uses. Two simultaneous /start signups will
    serialize on this lock, so each one gets a distinct rotator
    sponsor rather than both stealing whoever was at position 1.

    Filters: only active members with rotator_opted_in=true AND
    membership is not lapsed AND user is not suspended. Stale queue
    rows (member opted out / went inactive / was deleted) are skipped
    by the join, not by a separate cleanup pass.
    """
    from sqlalchemy import text as _text
    # Serialize all rotator picks against each other. Arbitrary 64-bit
    # key — different from founding-spot lock (7423957) to avoid
    # serializing /start against unrelated founding claims.
    db.execute(_text("SELECT pg_advisory_xact_lock(8742193)"))
    row = db.execute(_text(
        "SELECT rq.user_id "
        "FROM rotator_queue rq "
        "JOIN users u ON u.id = rq.user_id "
        "WHERE u.is_active = true "
        "  AND u.rotator_opted_in = true "
        "ORDER BY rq.queue_position ASC "
        "LIMIT 1"
    )).fetchone()
    if not row:
        return None
    picked_user_id = row[0]
    # Move them to the back of the queue
    max_pos_row = db.execute(_text(
        "SELECT COALESCE(MAX(queue_position), 0) FROM rotator_queue"
    )).fetchone()
    new_pos = (max_pos_row[0] or 0) + 1
    db.execute(_text(
        "UPDATE rotator_queue SET queue_position = :pos WHERE user_id = :uid"
    ), {"pos": new_pos, "uid": picked_user_id})
    return picked_user_id


@app.get("/api/start/next-sponsor")
def api_start_next_sponsor(request: Request, db: Session = Depends(get_db)):
    """Return the username of the Founder currently at the front of the
    rotator queue, WITHOUT advancing the queue. Used by the registration
    page (when via=start) to display "Your sponsor: <name>" so the prospect
    sees who they'll be matched with.

    Public — no auth. Returns only a username, no PII. Reading is a pure
    SELECT so this endpoint can be hit by anyone without affecting rotator
    state. The actual queue advance still happens at form submission via
    _pick_next_rotator_sponsor in the /api/register handler.

    Cached 10s by Cloudflare since most page-views happen in clusters
    around an ad campaign launch and we don't need second-level precision.
    """
    from sqlalchemy import text as _text
    try:
        row = db.execute(_text(
            "SELECT u.username "
            "FROM rotator_queue rq "
            "JOIN users u ON u.id = rq.user_id "
            "WHERE u.is_active = true "
            "  AND u.rotator_opted_in = true "
            "ORDER BY rq.queue_position ASC "
            "LIMIT 1"
        )).fetchone()
        username = row[0] if row else None
    except Exception:
        username = None
    return JSONResponse(
        {"username": username},
        headers={"Cache-Control": "public, max-age=10"},
    )


@app.post("/api/start/peek-next-sponsor")
def api_start_peek_next_sponsor(
    request: Request,
    db: Session = Depends(get_db),
):
    """Advance the rotator queue by one and return the picked Founder's
    username. PUBLIC — no auth required.

    Called from the /start CTA click handler. Steve's design: every
    click of 'Claim your Founder spot' shows a different Founder's
    name on the register page. Each call here advances the queue.

    Because this endpoint advances the queue, the register flow that
    follows must use the explicit ref it returns rather than calling
    the rotator a second time on submit. Frontend passes ?ref=<name>
    via the URL; backend register handler uses that explicit ref.

    Returns:
      { sponsor_username: <str>, queue_size: <int> } on success
      { sponsor_username: 'SuperAdPro', queue_size: 0, fallback: true }
        if the queue is empty (so the page still works gracefully)

    Concurrency: _pick_next_rotator_sponsor uses pg_advisory_xact_lock,
    so two simultaneous clicks each get a distinct Founder, not the
    same one.
    """
    try:
        picked_id = _pick_next_rotator_sponsor(db)
        if not picked_id:
            db.commit()
            return {
                "sponsor_username": "SuperAdPro",
                "queue_size": 0,
                "fallback": True,
            }
        # Look up the username for the picked id
        from sqlalchemy import text as _text
        row = db.execute(_text(
            "SELECT username FROM users WHERE id = :id"
        ), {"id": picked_id}).fetchone()
        sponsor_username = row[0] if row else "SuperAdPro"
        # Count remaining queue size for diagnostics
        qsize = db.execute(_text(
            "SELECT COUNT(*) FROM rotator_queue"
        )).scalar() or 0
        db.commit()
        logger.info(
            f"rotator peek: served '{sponsor_username}' (user_id={picked_id}) "
            f"to /start CTA click — queue advanced"
        )
        return {
            "sponsor_username": sponsor_username,
            "queue_size": qsize,
            "fallback": False,
        }
    except Exception as e:
        logger.exception(f"peek-next-sponsor failed: {e}")
        db.rollback()
        # Don't break the page — fall back to house account.
        return {
            "sponsor_username": "SuperAdPro",
            "queue_size": 0,
            "fallback": True,
            "error": str(e),
        }


@app.get("/api/start/stats")
def api_start_stats(request: Request, db: Session = Depends(get_db)):
    """Live platform stats for the /start hero. PUBLIC — no auth.

    Returns total_members and founding_remaining so the hero counter
    can animate from 0 to the real value, and the founding-dots grid
    can render the accurate lit/dim ratio.

    Cached implicitly by Cloudflare for 30s via Cache-Control header
    since this fires on every public landing-page hit and these
    numbers change slowly. Set ttl=0 if a live test needs immediate
    propagation.
    """
    try:
        total_members = db.query(User).filter(User.is_active == True).count()  # noqa: E712
    except Exception:
        total_members = 138  # fallback to a known-good number rather than failing the page
    try:
        founding_claimed = db.query(User).filter(
            User.is_founding_member == True  # noqa: E712
        ).count()
        founding_remaining = max(0, 100 - founding_claimed)
    except Exception:
        founding_remaining = 77

    return JSONResponse(
        {
            "total_members": total_members,
            "founding_remaining": founding_remaining,
        },
        headers={"Cache-Control": "public, max-age=30"},
    )


# ── Fast Start Hero (17 May 2026) ─────────────────────────────────────
# Dashboard hero that prompts paid Partners to activate Grid Tier 1.
# Three endpoints power the React surface:
#   GET  /api/fast-start/state — current state machine + live stats
#   POST /api/fast-start/press — record click, transition to "in progress"
#   POST /api/fast-start/hide  — × dismiss, transition to permanent-hidden
# The hero is auto-hidden when a user activates grid_1 (side-effect lives
# in _nowpayments_activate_product).

@app.get("/api/fast-start/state")
def api_fast_start_state(
    request: Request,
    db: Session = Depends(get_db),
    user: User = Depends(get_current_user),
):
    """Returns the dashboard hero state + live stats.

    Response shape:
      {
        "state": "hero" | "continue" | "hidden",
        "username": "...",
        "next_position": "SAP-00148",          # what they'd claim if they bought now
        "activated_last_24h": 7,
        "activated_last_hour": 1,
        "has_grid_position": false             # belt-and-braces: hero never shown to users who do
      }

    State derivation:
      - has_grid_position OR hidden_at set  → "hidden"
      - pressed_at set, hidden_at null      → "continue"
      - otherwise                            → "hero"

    Auth required. Anonymous users get 401.
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    from .database import Grid, GridPosition

    # Gating rule: hero only renders for paid Partners.
    # Free users (is_active=False) have nothing meaningful to do with
    # "Activate Grid" — they need to buy Partner membership ($20/mo)
    # first, which is a separate funnel entirely. The hero's headline
    # "Activate for $20" would be misleading for them since $20 buys
    # them Partner, not a Grid Tier 1 (that's an additional $20).
    # Force "hidden" so the dashboard renders without the hero, leaving
    # the existing Founding Partner banner / hero carousel to do the
    # membership conversion job.
    if not user.is_active:
        return JSONResponse({
            "state": "hidden",
            "username": user.username,
            "has_grid_position": False,
        })

    # Defensive: belt-and-braces check that the user doesn't already own
    # a Grid Tier 1. If they do, force "hidden" regardless of column
    # state — protects against stale fast_start_hidden_at NULL on users
    # who activated grid_1 before this feature shipped.
    has_t1_grid = db.query(Grid.id).filter(
        Grid.owner_id == user.id,
        Grid.package_tier == 1,
    ).first() is not None

    if has_t1_grid or user.fast_start_hidden_at is not None:
        state = "hidden"
    elif user.fast_start_pressed_at is not None:
        state = "continue"
    else:
        state = "hero"

    # Live stats — only compute if we're going to render something
    if state == "hidden":
        return JSONResponse({
            "state": "hidden",
            "username": user.username,
            "has_grid_position": has_t1_grid,
        })

    # next_position — the SAP-#### they'd be assigned if they bought right now.
    # Defined as 'count of distinct Grid Tier 1 owners + 1' since each user
    # who activates T1 gets their own Grid row, and the SAP-#### sequence
    # tracks the activation order. Falls back gracefully on any DB error.
    try:
        existing_t1_owners = db.query(Grid.owner_id).filter(
            Grid.package_tier == 1
        ).distinct().count()
        next_position = f"SAP-{(existing_t1_owners + 1):05d}"
    except Exception:
        next_position = None

    # Activated last 24h / 1h — count of distinct users whose T1 grid
    # was created in those windows. Grid.created_at fires at the exact
    # moment process_tier_purchase calls get_or_create_active_grid.
    now = datetime.utcnow()
    try:
        activated_24h = db.query(Grid.owner_id).filter(
            Grid.package_tier == 1,
            Grid.created_at >= now - timedelta(hours=24),
        ).distinct().count()
    except Exception:
        activated_24h = 0
    try:
        activated_1h = db.query(Grid.owner_id).filter(
            Grid.package_tier == 1,
            Grid.created_at >= now - timedelta(hours=1),
        ).distinct().count()
    except Exception:
        activated_1h = 0

    return JSONResponse({
        "state": state,
        "username": user.username,
        "next_position": next_position,
        "activated_last_24h": activated_24h,
        "activated_last_hour": activated_1h,
        "has_grid_position": has_t1_grid,
    })


@app.post("/api/fast-start/press")
def api_fast_start_press(
    request: Request,
    db: Session = Depends(get_db),
    user: User = Depends(get_current_user),
):
    """Record that the user clicked 'Activate Grid'. Sets
    fast_start_pressed_at if not already set so subsequent dashboard
    visits show the degraded "Continue activation →" state.

    Idempotent: if pressed_at is already set, no-op. If hidden_at is
    set we still no-op — they've already moved past this surface.

    Returns the same shape as /api/fast-start/state for convenience
    (so the frontend doesn't have to make two calls).
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    if user.fast_start_pressed_at is None and user.fast_start_hidden_at is None:
        user.fast_start_pressed_at = datetime.utcnow()
        db.add(user)
        try:
            db.commit()
        except Exception as e:
            logger.error(f"fast_start press persist failed for user {user.id}: {e}")
            db.rollback()
    # Return current state — re-read so the response reflects the write
    return api_fast_start_state(request, db, user)


@app.post("/api/fast-start/hide")
def api_fast_start_hide(
    request: Request,
    db: Session = Depends(get_db),
    user: User = Depends(get_current_user),
):
    """× dismiss the degraded continue-card permanently.

    Sets fast_start_hidden_at if not already set. From this point the
    hero never renders on this user's dashboard (until/unless they
    activate Grid Tier 1, which also lands here via the activation
    handler).
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    if user.fast_start_hidden_at is None:
        user.fast_start_hidden_at = datetime.utcnow()
        db.add(user)
        try:
            db.commit()
        except Exception as e:
            logger.error(f"fast_start hide persist failed for user {user.id}: {e}")
            db.rollback()
    return api_fast_start_state(request, db, user)


@app.get("/api/watch/preview/{campaign_id}")
def api_watch_preview(campaign_id: int, request: Request,
                      db: Session = Depends(get_db),
                      user: User = Depends(get_current_user)):
    """Owner-preview of a single campaign in the Watch player chrome.

    Returns the same video shape /api/watch returns inside its videos[] array,
    wrapped in a payload the React Watch page can render in 'preview' mode.

    Permissions:
      - Campaign owner (user_id == requester) can preview their own ad
      - Admins can preview any campaign
      - Everyone else gets 404 (not 403, to avoid leaking existence)

    Preview mode characteristics (enforced by the React page reading
    is_preview=True in the response):
      - No 30s timer, no 'Mark as watched' button
      - Never hits /api/watch/complete, so no VideoWatch row is written
      - No quota tick, no earnings, no rotation involvement
      - views_delivered is NOT incremented (owner can't accidentally burn
        their own ad budget by previewing)

    Created 16 May 2026 to replace the broken 'View' button on the React
    My Campaigns page, which was sending owners to the raw YouTube URL in
    a new tab — leaking viewers off platform and skipping the actual Watch
    chrome the owner wanted to preview.
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    campaign = db.query(VideoCampaign).filter(
        VideoCampaign.id == campaign_id,
        VideoCampaign.status != "deleted",
    ).first()
    if not campaign:
        return JSONResponse({"error": "Campaign not found"}, status_code=404)
    # Owner OR admin only. Anyone else gets 404 (deliberate — don't reveal
    # that the campaign exists to non-owners).
    is_owner = campaign.user_id == user.id
    is_admin = bool(getattr(user, "is_admin", False))
    if not (is_owner or is_admin):
        return JSONResponse({"error": "Campaign not found"}, status_code=404)
    return {
        "is_preview": True,
        "video": {
            "id": campaign.id,
            "title": campaign.title,
            "platform": campaign.platform or "youtube",
            "category": campaign.category or "General",
            "embed_url": campaign.embed_url,
            "cta_url": campaign.cta_url or None,
            "is_watched": False,
            "seconds_remaining": 0,
            "is_resumed": False,
        },
    }


