# ─────────────────────────────────────────────────────────────────
#  Test account cleanup — diagnostic + safe deletion
# ─────────────────────────────────────────────────────────────────
# Pre-launch goal: identify likely test accounts so the admin can
# review and remove them, without inflating the leaderboard or
# leaving cruft in production data. Deletion itself goes through
# admin_delete_user (existing endpoint with proper 41-model cascade).
#
# This diagnostic endpoint is READ-ONLY. It returns candidates with
# a "test score" (combination of soft signals) and a cascade-impact
# preview so the admin sees exactly what will be deleted before
# pulling the trigger.
#
# Soft signals used (no single one is definitive):
#   - Username matches test patterns (test*, demo*, qa*, dummy*, fake*)
#   - Email never verified
#   - Zero balance + zero total_earned + zero total_withdrawn
#   - No commissions earned or paid
#   - No purchases (NowPaymentsOrder, CryptoPaymentOrder, course/credit-matrix)
#   - No active grid
#   - Created in close succession to other test-pattern accounts
#
# Score 0–7. Admin's judgement on what threshold to act on. The
# endpoint deliberately does NOT auto-delete anything.
@app.get("/admin/api/users/cleanup-candidates")
def admin_users_cleanup_candidates(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    min_score: int = 3,
):
    """List likely-test accounts with cascade-impact preview. Read-only.

    Query params:
      min_score (int, default 3) — only return candidates scoring >= N
                                    soft signals. Tighten to 5+ for
                                    near-certain test accounts; loosen
                                    to 1 to see everything that could
                                    plausibly be one.

    Returns one row per candidate with:
      - basic identity (id, username, email, created_at)
      - the score breakdown (which signals fired)
      - cascade impact (counts of FK references that would be
        deleted/nulled if admin_delete_user is called)
      - blockers (admin / has-balance / is-self) that would prevent
        deletion outright

    The admin uses this to review the list, then deletes individuals
    via DELETE /admin/api/user/{user_id} which already exists and
    handles the proper 41-model cascade with sponsor counter
    decrements + downline orphaning.
    """
    _require_admin(user)
    import re as _re
    from sqlalchemy import or_, func as _func
    from .database import (
        Commission, Payment, Withdrawal, NowPaymentsOrder,
        CryptoPaymentOrder, CoursePurchase, Grid, VideoCampaign,
    )

    # Test-pattern username regex. Conservative — only flags accounts
    # whose usernames clearly look like throwaway test data. Real users
    # named "Tess" or "Demo" won't match because we anchor at start.
    test_username_re = _re.compile(
        r"^(test|demo|qa|dummy|fake|debug|sample|tmp|temp)[\d_]*$",
        _re.IGNORECASE,
    )

    candidates = []
    # Pull all non-admin, non-self users. Small enough at launch (~13)
    # that scanning all of them is fine. Add LIMIT if this grows.
    all_users = db.query(User).filter(
        User.is_admin == False,
        User.id != user.id,
    ).order_by(User.id.asc()).all()

    for u in all_users:
        signals = []
        score = 0

        # Signal 1: Username matches test pattern
        if u.username and test_username_re.match(u.username):
            signals.append("username_test_pattern")
            score += 2  # strong signal — weight 2

        # Signal 2: Email never verified (if your model tracks this)
        if hasattr(u, "email_verified") and not getattr(u, "email_verified", True):
            signals.append("email_not_verified")
            score += 1

        # Signal 3: No balance, no earnings, no withdrawals
        bal = float(u.balance or 0)
        earned = float(u.total_earned or 0)
        withdrawn = compute_total_withdrawn(db, u.id)
        if bal == 0 and earned == 0 and withdrawn == 0:
            signals.append("zero_financial_activity")
            score += 1

        # Signal 4: No commissions either earned or attributed-to-buyer
        comms_to = db.query(Commission).filter(Commission.to_user_id == u.id).count()
        comms_from = db.query(Commission).filter(Commission.from_user_id == u.id).count()
        if comms_to == 0 and comms_from == 0:
            signals.append("no_commissions")
            score += 1

        # Signal 5: No purchases of any kind
        np_count = db.query(NowPaymentsOrder).filter(NowPaymentsOrder.user_id == u.id).count()
        cp_count = db.query(CryptoPaymentOrder).filter(CryptoPaymentOrder.user_id == u.id).count()
        course_count = db.query(CoursePurchase).filter(CoursePurchase.user_id == u.id).count()
        if (np_count + cp_count + course_count) == 0:
            signals.append("no_purchases")
            score += 1

        # Signal 6: No active grid
        grid_count = db.query(Grid).filter(Grid.owner_id == u.id).count()
        if grid_count == 0:
            signals.append("no_grid")
            score += 1

        if score < min_score:
            continue

        # Cascade impact preview — how many rows would be touched if
        # admin_delete_user is called. Helps the admin spot accounts
        # that have unexpected ties (e.g. they "look like" test data
        # but actually have downstream activity that shouldn't be
        # deleted).
        downline_count = db.query(User).filter(User.sponsor_id == u.id).count()
        notif_count = 0
        try:
            from .database import Notification
            notif_count = db.query(Notification).filter(Notification.user_id == u.id).count()
        except Exception:
            pass

        # Blockers — conditions that would cause admin_delete_user to
        # 400-reject. Surface them in the preview so the admin doesn't
        # try to delete and bounce.
        blockers = []
        if bal > 0:
            blockers.append(f"balance > 0 (${bal:.2f}) — withdraw or zero first")
        if u.is_admin:
            blockers.append("is_admin (cannot delete admin accounts)")
        if u.id == user.id:
            blockers.append("is_self (cannot delete your own account)")

        candidates.append({
            "id": u.id,
            "username": u.username,
            "email": u.email,
            "first_name": u.first_name,
            "is_active": bool(u.is_active),
            "membership_tier": u.membership_tier or "free",
            "balance_usd": bal,
            "total_earned_usd": earned,
            "total_withdrawn_usd": withdrawn,
            "personal_referrals_stored": u.personal_referrals or 0,
            "personal_referrals_live": db.query(User).filter(User.sponsor_id == u.id).count(),
            "sponsor_id": u.sponsor_id,
            "created_at": u.created_at.isoformat() if u.created_at else None,
            "score": score,
            "signals": signals,
            "cascade_preview": {
                "commissions_to_user":   comms_to,
                "commissions_from_user": comms_from,
                "nowpayments_orders":    np_count,
                "crypto_orders":         cp_count,
                "course_purchases":      course_count,
                "grids":                 grid_count,
                "downline_users_to_orphan": downline_count,
                "notifications":         notif_count,
            },
            "blockers": blockers,
            "delete_url": f"/admin/api/user/{u.id}",
            "delete_method": "DELETE",
        })

    # Sort by score desc, then by id asc — highest-confidence
    # candidates first, oldest first within same score.
    candidates.sort(key=lambda c: (-c["score"], c["id"]))

    return {
        "total_users_scanned": len(all_users),
        "min_score_threshold": min_score,
        "candidate_count": len(candidates),
        "candidates": candidates,
        "instructions": (
            "Review each candidate. To delete, send DELETE to delete_url. "
            "The existing admin_delete_user endpoint cascades through 41 "
            "FK-related tables, decrements your sponsor counters, and "
            "orphans (nulls sponsor_id on) any users who had this person "
            "as their sponsor. Blockers must be cleared first. "
            "Recommendation: start with score >= 5 candidates, work down."
        ),
    }


@app.delete("/admin/api/user/{user_id}")
def admin_delete_user(user_id: int, user: User = Depends(get_current_user),
                      db: Session = Depends(get_db)):
    """Admin: permanently delete a user and all their data."""
    _require_admin(user)
    target = db.query(User).filter(User.id == user_id).first()
    if not target:
        return JSONResponse({"error": "User not found"}, status_code=404)
    if target.is_admin:
        return JSONResponse({"error": "Cannot delete admin accounts"}, status_code=400)
    if target.id == user.id:
        return JSONResponse({"error": "Cannot delete your own account"}, status_code=400)
    if float(target.balance or 0) > 0:
        return JSONResponse({"error": f"User has ${target.balance} balance — withdraw or zero first"}, status_code=400)

    from .database import (
        MemberLead, EmailSequence, EmailSendLog, LeadList,
        CoPilotBriefing, AIUsageQuota, NurtureSequence,
        VideoWatch, WatchQuota, FunnelLead, FunnelEvent,
        LinkHubLink, LinkHubClick, ProSellerMessage, Prospect,
        SuperSellerCampaign
    )

    from .database import (
        # All 41 models with FK to users - verified from database.py
        MembershipRenewal, PasswordResetToken, NurtureSequence,
        VideoWatch, WatchQuota, VideoCampaign,
        Grid, GridPosition,
        FunnelPage, FunnelLead, FunnelEvent,
        ShortLink, LinkRotator,
        LinkHubProfile, LinkHubLink,
        MemberLead, LeadList, EmailSequence, EmailSendLog,
        CoPilotBriefing, AIUsageQuota,
        Commission, Payment, Withdrawal, P2PTransfer,
        Notification, Achievement,
        CoursePurchase, CourseCommission, CourseProgress, CoursePassUpTracker,
        MemberCourse, MemberCoursePurchase,
        DigitalProduct, DigitalProductPurchase, DigitalProductReview, DigitalProductAffiliate,
        ProSellerMessage, Prospect, SuperSellerCampaign,
    )
    from .database import LinkHubClick, MemberCourseLesson, MemberCourseChapter

    username = target.username
    try:
        # ── LAYER 0: Decrement sponsor counters ──
        if target.sponsor_id:
            sponsor = db.query(User).filter(User.id == target.sponsor_id).first()
            if sponsor:
                sponsor.personal_referrals = max(0, (sponsor.personal_referrals or 0) - 1)
                sponsor.total_team = max(0, (sponsor.total_team or 0) - 1)
                db.flush()

        # Null out sponsor references to prevent orphaned downline
        # Members who had this user as their sponsor keep their account but lose the upline link
        db.query(User).filter(User.sponsor_id == user_id).update(
            {"sponsor_id": None}, synchronize_session=False
        )
        db.query(User).filter(User.pass_up_sponsor_id == user_id).update(
            {"pass_up_sponsor_id": None}, synchronize_session=False
        )

        # ── LAYER 1: Deepest grandchildren (reference child tables, not users directly) ──

        # EmailSendLog → references member_leads and email_sequences
        lead_ids = [r.id for r in db.query(MemberLead).filter(MemberLead.user_id == user_id).all()]
        if lead_ids:
            db.query(EmailSendLog).filter(EmailSendLog.lead_id.in_(lead_ids)).delete(synchronize_session=False)

        # LinkHubClick → references linkhub_links and linkhub_profiles
        profile = db.query(LinkHubProfile).filter(LinkHubProfile.user_id == user_id).first()
        if profile:
            db.query(LinkHubClick).filter(LinkHubClick.profile_id == profile.id).delete()

        # LinkHubLink → references linkhub_profiles
        db.query(LinkHubLink).filter(LinkHubLink.user_id == user_id).delete()

        # GridPosition → references grids
        # Two cases to handle:
        # 1) Positions IN this user's own grids (grids they own) — drop them along with the grids
        # 2) Positions WHERE this user is the placed member (someone else's grid via spillover)
        #    These have FK grid_positions.member_id → users.id and would block the user delete
        #    if not removed first. Bug surfaced 6 May 2026 — admin tried to delete a test user
        #    who had been placed in someone else's grid via spillover and got a FK violation.
        grid_ids = [r.id for r in db.query(Grid).filter(Grid.owner_id == user_id).all()]
        if grid_ids:
            db.query(GridPosition).filter(GridPosition.grid_id.in_(grid_ids)).delete(synchronize_session=False)
        # Also delete positions where THIS user is the placed member
        db.query(GridPosition).filter(GridPosition.member_id == user_id).delete(synchronize_session=False)

        # CourseCommission → references course_purchases
        purchase_ids = [r.id for r in db.query(CoursePurchase).filter(CoursePurchase.user_id == user_id).all()]
        if purchase_ids:
            db.query(CourseCommission).filter(CourseCommission.purchase_id.in_(purchase_ids)).delete(synchronize_session=False)

        # (Legacy MemberCourse/MemberCoursePurchase deletions removed —
        # creator-uploaded courses feature has been retired in favour of
        # the official 3-tier Course Academy. Tables left in place for
        # historical data integrity; no longer written to.)

        # DigitalProduct children
        product_ids = [r.id for r in db.query(DigitalProduct).filter(DigitalProduct.creator_id == user_id).all()]
        if product_ids:
            db.query(DigitalProductPurchase).filter(DigitalProductPurchase.product_id.in_(product_ids)).delete(synchronize_session=False)
            db.query(DigitalProductReview).filter(DigitalProductReview.product_id.in_(product_ids)).delete(synchronize_session=False)
            db.query(DigitalProductAffiliate).filter(DigitalProductAffiliate.product_id.in_(product_ids)).delete(synchronize_session=False)

        # FunnelEvent, FunnelLead → references funnel_pages
        # MemberLead.source_funnel_id also references funnel_pages — null out
        # so FK doesn't block the funnel_pages deletion below. The member_leads
        # rows themselves get deleted later (they have user_id = user_id too).
        funnel_ids = [r.id for r in db.query(FunnelPage).filter(FunnelPage.user_id == user_id).all()]
        if funnel_ids:
            from sqlalchemy import text as _sql_text_net
            db.execute(_sql_text_net("UPDATE member_leads SET source_funnel_id = NULL WHERE source_funnel_id = ANY(:ids)"), {"ids": funnel_ids})
            db.query(FunnelEvent).filter(FunnelEvent.page_id.in_(funnel_ids)).delete(synchronize_session=False)
            db.query(FunnelLead).filter(FunnelLead.page_id.in_(funnel_ids)).delete(synchronize_session=False)

        # ProSellerMessage → references prospects
        prospect_ids = [r.id for r in db.query(Prospect).filter(Prospect.user_id == user_id).all()]
        if prospect_ids:
            db.query(ProSellerMessage).filter(ProSellerMessage.prospect_id.in_(prospect_ids)).delete(synchronize_session=False)

        # VideoWatch has user_id directly — delete all watches BY this user
        db.query(VideoWatch).filter(VideoWatch.user_id == user_id).delete()

        # ── LAYER 2: Direct children of users (all verified field names) ──
        db.query(MembershipRenewal).filter(MembershipRenewal.user_id == user_id).delete()
        db.query(PasswordResetToken).filter(PasswordResetToken.user_id == user_id).delete()
        db.query(NurtureSequence).filter(NurtureSequence.user_id == user_id).delete()
        db.query(WatchQuota).filter(WatchQuota.user_id == user_id).delete()
        db.query(VideoCampaign).filter(VideoCampaign.user_id == user_id).delete()
        db.query(Grid).filter(Grid.owner_id == user_id).delete()
        db.query(FunnelPage).filter(FunnelPage.user_id == user_id).delete()
        db.query(ShortLink).filter(ShortLink.user_id == user_id).delete()
        db.query(LinkRotator).filter(LinkRotator.user_id == user_id).delete()
        db.query(LinkHubProfile).filter(LinkHubProfile.user_id == user_id).delete()
        db.query(MemberLead).filter(MemberLead.user_id == user_id).delete()
        db.query(LeadList).filter(LeadList.user_id == user_id).delete()
        db.query(EmailSequence).filter(EmailSequence.user_id == user_id).delete()
        db.query(CoPilotBriefing).filter(CoPilotBriefing.user_id == user_id).delete()
        db.query(AIUsageQuota).filter(AIUsageQuota.user_id == user_id).delete()
        db.query(Commission).filter((Commission.from_user_id == user_id) | (Commission.to_user_id == user_id)).delete()
        db.query(Payment).filter((Payment.from_user_id == user_id) | (Payment.to_user_id == user_id)).delete()
        db.query(Withdrawal).filter(Withdrawal.user_id == user_id).delete()
        db.query(P2PTransfer).filter((P2PTransfer.from_user_id == user_id) | (P2PTransfer.to_user_id == user_id)).delete()
        db.query(Notification).filter(Notification.user_id == user_id).delete()
        db.query(Achievement).filter(Achievement.user_id == user_id).delete()
        db.query(CoursePurchase).filter(CoursePurchase.user_id == user_id).delete()
        db.query(CourseProgress).filter(CourseProgress.user_id == user_id).delete()
        db.query(CoursePassUpTracker).filter(CoursePassUpTracker.user_id == user_id).delete()
        db.query(MemberCourse).filter(MemberCourse.creator_id == user_id).delete()
        db.query(DigitalProduct).filter(DigitalProduct.creator_id == user_id).delete()
        db.query(DigitalProductPurchase).filter(DigitalProductPurchase.buyer_id == user_id).delete()
        db.query(DigitalProductAffiliate).filter(DigitalProductAffiliate.user_id == user_id).delete()
        db.query(Prospect).filter((Prospect.user_id == user_id) | (Prospect.converted_user_id == user_id)).delete()
        db.query(SuperSellerCampaign).filter(SuperSellerCampaign.user_id == user_id).delete()

        # ── LAYER 2b: Credit Matrix & SuperScene tables ──
        from .database import (
            SuperSceneCredit, CreditMatrix, CreditMatrixPosition,
            CreditMatrixCommission, CreditPackPurchase, NowPaymentsOrder,
        )
        # Credit matrix positions where this user appears (in anyone's matrix)
        db.query(CreditMatrixCommission).filter(
            (CreditMatrixCommission.earner_id == user_id) | (CreditMatrixCommission.from_user_id == user_id)
        ).delete(synchronize_session=False)
        # Positions in any matrix
        db.query(CreditMatrixPosition).filter(CreditMatrixPosition.user_id == user_id).delete(synchronize_session=False)
        # Matrices owned by this user — first delete their positions, then the matrix
        owned_matrix_ids = [m.id for m in db.query(CreditMatrix).filter(CreditMatrix.owner_id == user_id).all()]
        if owned_matrix_ids:
            db.query(CreditMatrixCommission).filter(CreditMatrixCommission.matrix_id.in_(owned_matrix_ids)).delete(synchronize_session=False)
            db.query(CreditMatrixPosition).filter(CreditMatrixPosition.matrix_id.in_(owned_matrix_ids)).delete(synchronize_session=False)
            db.query(CreditMatrix).filter(CreditMatrix.id.in_(owned_matrix_ids)).delete(synchronize_session=False)
        db.query(CreditPackPurchase).filter(CreditPackPurchase.user_id == user_id).delete(synchronize_session=False)
        db.query(SuperSceneCredit).filter(SuperSceneCredit.user_id == user_id).delete(synchronize_session=False)
        # NOWPayments orders
        try:
            db.query(NowPaymentsOrder).filter(NowPaymentsOrder.user_id == user_id).delete(synchronize_session=False)
        except Exception:
            pass
        # Team messages
        from sqlalchemy import text as _text
        try:
            db.execute(_text("DELETE FROM team_messages WHERE from_user_id = :uid OR to_user_id = :uid"), {"uid": user_id})
        except Exception:
            pass
        # Presentations
        try:
            db.execute(_text("DELETE FROM presentations WHERE user_id = :uid"), {"uid": user_id})
        except Exception:
            pass

        # ── LAYER 2c: Runtime FK introspection (the catch-all) ──
        # The hand-maintained cascade above gets stale every time we add
        # a new table with FK to users (it missed GiftVoucher on 11 May
        # 2026 — caused this bug). Rather than maintain the list by hand,
        # ask Postgres what FKs exist on the users table and clean each
        # one automatically. This makes the cascade future-proof: any new
        # FK-to-users column added later just works.
        #
        # Strategy per column:
        #   - NOT NULL column → DELETE the rows (can't null them, and
        #     leaving them would block the user delete)
        #   - Nullable column → SET to NULL (preserves the related row's
        #     historical context)
        try:
            fk_rows = db.execute(_text("""
                SELECT
                    tc.table_name      AS child_table,
                    kcu.column_name    AS child_column,
                    col.is_nullable    AS is_nullable
                FROM information_schema.table_constraints tc
                JOIN information_schema.key_column_usage kcu
                    ON tc.constraint_name = kcu.constraint_name
                    AND tc.table_schema = kcu.table_schema
                JOIN information_schema.constraint_column_usage ccu
                    ON ccu.constraint_name = tc.constraint_name
                    AND ccu.table_schema = tc.table_schema
                JOIN information_schema.columns col
                    ON col.table_name = kcu.table_name
                    AND col.column_name = kcu.column_name
                    AND col.table_schema = kcu.table_schema
                WHERE tc.constraint_type = 'FOREIGN KEY'
                    AND ccu.table_name = 'users'
                    AND ccu.column_name = 'id'
                    AND tc.table_schema = 'public'
                    AND tc.table_name != 'users'   -- skip self-references (sponsor_id, handled above)
            """)).fetchall()

            for child_table, child_column, is_nullable in fk_rows:
                try:
                    if is_nullable == 'YES':
                        # Preserve the row, null out the reference
                        db.execute(
                            _text(f'UPDATE "{child_table}" SET "{child_column}" = NULL WHERE "{child_column}" = :uid'),
                            {"uid": user_id}
                        )
                    else:
                        # Can't null a NOT NULL column — delete the rows
                        db.execute(
                            _text(f'DELETE FROM "{child_table}" WHERE "{child_column}" = :uid'),
                            {"uid": user_id}
                        )
                    db.flush()  # surface FK errors here, per-table, not at the end
                except Exception as fk_exc:
                    # Per-table error aborts the postgres transaction. Log it
                    # and re-raise so the outer except handles cleanup. The
                    # admin will see exactly which table failed and can dig in.
                    logger.warning(
                        f"FK cascade: failed to clean {child_table}.{child_column} "
                        f"for user {user_id}: {fk_exc}"
                    )
                    raise
        except Exception as introspect_exc:
            logger.warning(f"FK introspection failed for user {user_id}: {introspect_exc}")
            # If introspection itself failed, fall through and try the
            # final delete anyway — it may still succeed if the hand
            # cascade above caught everything.

        # ── LAYER 3: Finally delete the user ──
        db.delete(target)
        db.commit()
        return {"ok": True, "message": f"User {username} deleted successfully"}
    except Exception as e:
        db.rollback()
        return JSONResponse({"error": str(e)}, status_code=500)
