# ════════════════════════════════════════════════════════════════════════
# WalletConnect / Self-custody BSC payment endpoints (Stage 2, 6 May 2026)
# ────────────────────────────────────────────────────────────────────────
# Three public endpoints + one admin endpoint replacing the NOWPayments
# inbound rail. Member checkout flow:
#
#   1. Frontend calls POST /api/onchain/create-intent with the product
#   2. Backend creates a pending WalletConnectPaymentOrder with a
#      cent-unique amount (e.g. $19.97), responds with order_id +
#      treasury_address + unique_amount + expires_at
#   3. Frontend opens Reown AppKit, member signs USDT-BEP-20 transfer
#      for unique_amount to treasury from their own wallet
#   4. Frontend polls GET /api/onchain/order/{id} every ~4s until
#      status='confirmed' (or 'expired' / 'cancelled')
#   5. Cron /cron/scan-bsc-payments (30s) reads BSC USDT Transfers,
#      matches by amount, marks confirmed, runs activation handler
#
# Parallel-runs alongside NOWPayments redirect for ~2 weeks before
# the legacy rail is retired.
# ════════════════════════════════════════════════════════════════════════

@app.post("/api/onchain/create-intent")
async def onchain_create_intent(request: Request,
                                 user: User = Depends(get_current_user),
                                 db: Session = Depends(get_db)):
    """Create a pending WalletConnectPaymentOrder.

    Body: {product_type, product_key, product_meta?: object}
    Returns 200 with order details on success, 400 on known errors.
    """
    if not user:
        return JSONResponse({"error": "Authentication required"}, status_code=401)
    # ── Maintenance gate (hard only — soft = withdrawals only) ──
    if is_hard_maintenance(db):
        return JSONResponse({"error": _MAINTENANCE_MESSAGE}, status_code=503)

    try:
        body = await request.json()
    except Exception:
        return JSONResponse({"error": "Invalid JSON body"}, status_code=400)

    product_type = (body.get("product_type") or "").strip()
    product_key = (body.get("product_key") or "").strip()
    product_meta = body.get("product_meta") or None
    from_address = (body.get("from_address") or "").strip().lower()

    if not product_type or not product_key:
        return JSONResponse(
            {"error": "product_type and product_key are required"},
            status_code=400,
        )

    from .walletconnect_payments import (
        create_payment_intent,
        TREASURY_ADDRESS_BSC,
        USDT_CONTRACT_BSC,
        BSC_CHAIN_ID,
    )

    # Treasury self-pay guard. If the connected wallet IS the treasury
    # wallet, refuse the intent — sending USDT from the treasury to
    # itself wastes gas, can't be matched by the watcher (the matcher
    # filters out treasury self-transfers), and is almost certainly a
    # mistake (treasury imported into a member's MetaMask, or admin
    # testing on the wrong account). Bug history: Steve hit this on
    # 6 May testing — connected the treasury wallet to /credit-nexus,
    # MetaMask showed self→self transfer, transaction was a no-op.
    #
    # Only enforced when the frontend supplies from_address. Older
    # clients that don't send it bypass the guard (the watcher's
    # treasury-self-transfer filter is the backstop). Frontend updated
    # 7 May 2026 to always send the connected address.
    if from_address and from_address == TREASURY_ADDRESS_BSC.lower():
        return JSONResponse(
            {
                "error": (
                    "You're connected with the treasury wallet — please connect "
                    "with a different wallet to make a payment. The treasury "
                    "wallet is for receiving payments, not making them."
                ),
                "code": "treasury_self_pay",
            },
            status_code=400,
        )

    result = create_payment_intent(
        db=db,
        user_id=user.id,
        product_type=product_type,
        product_key=product_key,
        product_meta=product_meta,
    )

    # Error responses
    if isinstance(result, dict):
        err = result.get("error")
        if err == "unknown_product":
            return JSONResponse(
                {"error": "Unknown product", "code": "unknown_product"},
                status_code=400,
            )
        if err == "course_not_ready":
            return JSONResponse(
                {"error": "Course payments not yet available — coming soon",
                 "code": "course_not_ready"},
                status_code=503,
            )
        if err == "collision":
            return JSONResponse(
                {"error": "High demand right now — please try again in a moment",
                 "code": "collision"},
                status_code=503,
            )
        if err == "membership_required":
            return JSONResponse(
                {"error": "Active membership required to purchase Campaign Tiers",
                 "code": "membership_required"},
                status_code=403,
            )
        if err == "tier_sequence_violation":
            req = result.get("required_tier", "the prior tier")
            return JSONResponse(
                {"error": (f"You must purchase Tier {req} before this one. "
                           f"Campaign Tiers are purchased in order — buy Tier "
                           f"{req} first."),
                 "code": "tier_sequence_violation",
                 "required_tier": req},
                status_code=400,
            )
        return JSONResponse(
            {"error": "Could not create payment intent"},
            status_code=500,
        )

    # Success — `result` is a WalletConnectPaymentOrder
    order = result
    return {
        "order_id": order.id,
        "product_type": order.product_type,
        "product_key": order.product_key,
        "base_amount": str(order.base_amount),
        "unique_amount": str(order.unique_amount),
        "treasury_address": TREASURY_ADDRESS_BSC,
        "usdt_contract": USDT_CONTRACT_BSC,
        "chain_id": BSC_CHAIN_ID,
        "chain_name": "BSC",
        "token_decimals": 18,
        "expires_at": order.expires_at.isoformat() + "Z",
        "status": order.status,
    }


@app.get("/api/onchain/order/{order_id}")
async def onchain_order_status(order_id: int,
                                user: User = Depends(get_current_user),
                                db: Session = Depends(get_db)):
    """Check the status of an onchain order. Used by the frontend to
    poll until status='confirmed' (or 'expired')."""
    if not user:
        return JSONResponse({"error": "Authentication required"}, status_code=401)

    from .database import WalletConnectPaymentOrder
    order = db.query(WalletConnectPaymentOrder).filter(
        WalletConnectPaymentOrder.id == order_id,
    ).first()
    if not order:
        return JSONResponse({"error": "Order not found"}, status_code=404)
    # Members can only see their own orders; admin can see any
    if order.user_id != user.id and not getattr(user, "is_admin", False):
        return JSONResponse({"error": "Forbidden"}, status_code=403)

    return {
        "order_id": order.id,
        "status": order.status,
        "product_type": order.product_type,
        "product_key": order.product_key,
        "base_amount": str(order.base_amount),
        "unique_amount": str(order.unique_amount),
        "tx_hash": order.tx_hash,
        "from_address": order.from_address,
        "block_number": order.block_number,
        "expires_at": order.expires_at.isoformat() + "Z" if order.expires_at else None,
        "confirmed_at": order.confirmed_at.isoformat() + "Z" if order.confirmed_at else None,
    }


# ── Self-healing scan-gap recovery (12 Jun 2026) ──────────────────────
# When the scan floor is forced to skip ahead of the cursor — the cursor fell
# more than MAX_SCAN_BLOCKS_PER_RUN behind the chain head (an extended lag or
# wedge) — the skipped blocks were previously dropped SILENTLY: never scanned,
# never orphaned, any payment in them lost until a manual on-chain reconcile.
# That is what stranded SAP-00352's $50 grid_2. These helpers turn that silent
# loss into self-healing recovery: the skipped range is enqueued into the
# failed-chunk retry queue the scanner already re-scans every run (so any
# payments get matched/orphaned automatically, often the same tick), and an
# alert email fires. Bounded so a very long outage can't flood the retry table.
GAP_AUTORECOVER_MAX_BLOCKS = 10000  # ~75 min at ~0.45s/block; older = alert only


def _send_scan_gap_alert(gap_lo, gap_hi, recover_lo, total_blocks, older_unrecovered, chunks_enqueued):
    """Best-effort email when the scanner skipped a gap (floor cap exceeded).
    Never raises into the scan loop — caller wraps in try/except."""
    from .email_utils import send_email
    older_note = (
        f"<div style='margin-top:8px;color:#b45309;'><strong>Older portion:</strong> "
        f"{older_unrecovered} block(s) below {recover_lo} are beyond the auto-recover "
        f"window — run <code>/admin/api/treasury-scan</code> over that range and "
        f"reconcile any unattributed transfers via <code>/admin/api/reconcile-wc-order</code>.</div>"
        if older_unrecovered > 0 else ""
    )
    subject = f"BSC scanner skipped a gap — {total_blocks} blocks [{gap_lo}-{gap_hi}]"
    html_body = f"""
    <div style="font-family:Helvetica Neue,Arial,sans-serif;max-width:600px;margin:0 auto;padding:24px;">
      <h2 style="color:#dc2626;margin:0 0 16px;">BSC scanner skipped a block gap</h2>
      <p style="font-size:14px;line-height:1.6;color:#334155;">
        The scan cursor fell more than the catch-up cap behind the chain head, so the
        scanner had to skip a range of blocks. Any payment that landed in this range
        would otherwise have been missed. The recent portion has been queued for
        automatic re-scan and recovery — activations should land over the next few
        minutes with no action needed.
      </p>
      <div style="background:#f1f5f9;border-radius:10px;padding:16px;margin:16px 0;font-family:'JetBrains Mono',monospace;font-size:13px;">
        <div><strong>Skipped range:</strong> {gap_lo} &rarr; {gap_hi} ({total_blocks} blocks)</div>
        <div><strong>Auto-recovering:</strong> {recover_lo} &rarr; {gap_hi} ({chunks_enqueued} chunks queued for retry)</div>
        {older_note}
      </div>
      <p style="font-size:13px;color:#475569;line-height:1.6;">
        The failed-chunk retry pass re-scans the queued range every run and
        matches/orphans any transfers found. No manual step is needed for the
        auto-recovering portion.
      </p>
    </div>
    """
    send_email(to_email="stevelawsonmarketing@gmail.com", subject=subject, html_body=html_body)


def _enqueue_skipped_gap(db, gap_lo, gap_hi):
    """The scan floor skipped [gap_lo, gap_hi] because the cursor fell past the
    catch-up cap. Enqueue the most-recent slice into the failed-chunk retry
    queue in GETLOGS_WINDOW_BLOCKS-sized chunks so the existing retry pass
    recovers any payments, then alert. Bounded by GAP_AUTORECOVER_MAX_BLOCKS so
    a long outage can't flood the table; the older remainder is alert-only.

    Idempotent: record_failed_chunk upserts on (from_block, to_block), so a
    re-run over the same gap won't duplicate rows. Returns the chunk count.
    """
    from .walletconnect_payments import record_failed_chunk, GETLOGS_WINDOW_BLOCKS
    if gap_hi < gap_lo:
        return 0
    total = gap_hi - gap_lo + 1
    recover_lo = max(gap_lo, gap_hi - GAP_AUTORECOVER_MAX_BLOCKS + 1)
    chunks_enqueued = 0
    b = recover_lo
    while b <= gap_hi:
        chunk_hi = min(b + GETLOGS_WINDOW_BLOCKS - 1, gap_hi)
        try:
            record_failed_chunk(db, b, chunk_hi, "skipped_gap_cap_exceeded")
            chunks_enqueued += 1
        except Exception as e:
            logger.error(f"_enqueue_skipped_gap: record_failed_chunk {b}-{chunk_hi} failed: {e}")
        b = chunk_hi + 1
    try:
        db.commit()
    except Exception as e:
        logger.error(f"_enqueue_skipped_gap: commit failed: {e}")
        db.rollback()
    older_unrecovered = recover_lo - gap_lo
    logger.warning(
        f"inproc_bsc_scan: SCAN GAP {total} blocks [{gap_lo}-{gap_hi}] skipped by floor "
        f"cap; queued {chunks_enqueued} chunk(s) from {recover_lo} for retry; "
        f"{older_unrecovered} older block(s) need manual treasury-scan"
    )
    # Only email when part of the gap is OLDER than the auto-recover window and
    # so genuinely needs manual action (treasury-scan + reconcile). Routine
    # within-window gaps are fully self-healing — the retry pass re-scans them
    # and matches/orphans any payment automatically — so they are logged above
    # (full visibility in logs) but NOT emailed. This stops the every-few-minutes
    # inbox flood while preserving the alert for the rare case that needs a human.
    if older_unrecovered > 0:
        try:
            _send_scan_gap_alert(gap_lo, gap_hi, recover_lo, total, older_unrecovered, chunks_enqueued)
        except Exception as e:
            logger.error(f"_enqueue_skipped_gap: alert failed: {e}")
    return chunks_enqueued


def _send_bsc_scan_failure_alert(from_block, to_block, attempt_count, first_seen_at, last_error):
    """Fire an email alert when a BSC scan chunk has failed ESCALATE_AT_ATTEMPTS
    times in a row. Sent once per chunk (alerted_at gate in caller prevents
    repeat alerts). Recipient: stevelawsonmarketing@gmail.com (ops alert
    inbox, same as the daily-briefing cron).

    Failure mode: keep the alert best-effort. If email infrastructure is
    down we MUST NOT fail the scan loop. Caller wraps in try/except.

    Added 24 May 2026 alongside the failed-chunk persistence work — the
    Matt incident showed we had no visibility when chunks silently failed
    repeatedly; an email is the cheapest way to get human eyes on it.
    """
    from .email_utils import send_email
    elapsed_min = "?"
    try:
        elapsed_min = int((datetime.utcnow() - first_seen_at).total_seconds() / 60)
    except Exception:
        pass
    subject = f"⚠️  BSC scan chunk stuck — blocks {from_block}–{to_block} ({attempt_count} attempts)"
    html_body = f"""
    <div style="font-family:Helvetica Neue,Arial,sans-serif;max-width:600px;margin:0 auto;padding:24px;">
      <h2 style="color:#dc2626;margin:0 0 16px;">BSC scanner chunk failing repeatedly</h2>
      <p style="font-size:14px;line-height:1.6;color:#334155;">
        A WalletConnect scan chunk has failed across all redundant RPC providers
        for <strong>{attempt_count} consecutive attempts</strong> (first seen
        ~{elapsed_min} minutes ago). If a member's payment landed in this block
        range, their activation is currently stuck.
      </p>
      <div style="background:#f1f5f9;border-radius:10px;padding:16px;margin:16px 0;font-family:'JetBrains Mono',monospace;font-size:13px;">
        <div><strong>Range:</strong> {from_block} → {to_block}</div>
        <div><strong>Attempts:</strong> {attempt_count} (escalation at {ESCALATE_AT_ATTEMPTS}, abandon at {GIVE_UP_AT_ATTEMPTS})</div>
        <div><strong>First seen:</strong> {first_seen_at}</div>
        <div style="margin-top:8px;color:#64748b;word-break:break-all;"><strong>Last error:</strong> {(last_error or '')[:400]}</div>
      </div>
      <p style="font-size:13px;color:#475569;line-height:1.6;">
        <strong>Next steps:</strong> if this persists, check BSC RPC health for
        the configured providers. Failed chunks can be inspected at
        <code>SELECT * FROM bsc_scan_failed_chunks WHERE status='pending' ORDER BY attempt_count DESC</code>.
        If a stuck payment is reported, recover it via
        <code>/admin/api/manual-confirm-walletconnect-order?order_id=X&amp;tx_hash=0x...</code>.
      </p>
    </div>
    """
    send_email(
        to_email="stevelawsonmarketing@gmail.com",
        subject=subject,
        html_body=html_body,
    )


@app.post("/cron/scan-bsc-payments")
async def cron_scan_bsc_payments(request: Request, db: Session = Depends(get_db)):
    """Watcher cron — runs every 30s.

    1. Sweep expired pending orders → status='expired'
    2. Compute scan_floor_block from oldest still-pending order's age
    3. Read BSC USDT Transfer events to treasury (paginated 10-block chunks)
    4. For each transfer:
       - match_incoming_transfer → if matched, write Payment row +
         call _nowpayments_activate_product (reused activation handler)
       - if no match, persist as OnchainOrphanTransfer for support reconciliation

    Protected by CRON_SECRET in Authorization header (any prefix accepted,
    matching existing cron pattern).
    """
    auth = request.headers.get("Authorization", "")
    secret = os.environ.get("CRON_SECRET", "")
    if not secret or not auth.endswith(secret):
        return JSONResponse({"error": "Forbidden"}, status_code=403)

    from .database import (
        WalletConnectPaymentOrder, OnchainOrphanTransfer,
    )
    from .walletconnect_payments import (
        expire_stale_orders,
        match_incoming_transfer,
        scan_treasury_transfers_with_cursor,
        get_treasury_transfers_in_range_redundant,
        estimate_scan_floor_block,
        set_scan_cursor,
        is_likely_rounded_amount,
        get_pending_failed_chunks,
        record_failed_chunk,
        mark_chunk_resolved,
        mark_chunk_abandoned,
        mark_chunk_alerted,
        ESCALATE_AT_ATTEMPTS,
        GIVE_UP_AT_ATTEMPTS,
        _get_web3_bsc,
    )
    import json as _json
    import uuid

    stats = {
        "expired": 0,
        "scan_floor": 0,
        "latest_block": 0,
        "scanned_blocks": 0,
        "transfers_seen": 0,
        "matched": 0,
        "activated": 0,
        "orphans_added": 0,
        "errors": [],
        "failed_chunks": [],          # NEW failures this run: [[from, to, err], ...]
        "retry_chunks_seen": 0,       # Persisted failed chunks attempted this run
        "retry_chunks_resolved": 0,   # Of those, how many succeeded this run
        "retry_chunks_abandoned": 0,  # Of those, how many exceeded GIVE_UP and were abandoned
        "alerts_fired": 0,            # How many alerts fired this run
        "reconcile_orders_checked": 0,    # Stuck-order reconciler stats
        "reconcile_transfers_found": 0,
        "safe_cursor": 0,             # highest block the cursor was actually advanced to
    }

    # 1. Expire stale pending orders FIRST so a late-arriving payment
    #    can't match against a pending row that should have expired.
    try:
        stats["expired"] = expire_stale_orders(db)
    except Exception as e:
        logger.error(f"cron_scan_bsc_payments: expire_stale_orders failed: {e}")
        stats["errors"].append(f"expire: {e}")

    # 2. Compute scan floor from persisted cursor (changed 7 May 2026 from
    #    "oldest pending order age" — see estimate_scan_floor_block docstring).
    try:
        # Floor-calc latest-block read MUST fail over on rate-limit, not only on
        # connection failure. _get_web3_bsc() fails over only when the primary is
        # UNREACHABLE; a connected-but-throttled Alchemy free tier returns a w3
        # whose .eth.block_number then throws 429 / quota — which aborted the
        # WHOLE cron at the 503 below, before the (already redundant) transfer
        # scan ever ran. Net effect: full crypto-rail stall — zero confirmations,
        # valid on-time payments left completely unseen (e.g. a $50 grid_2 paid
        # 14s after order creation, never matched, order then expired). The fix:
        # call_bsc_rpc_with_failover retries the block read across the public BSC
        # dataseed fallbacks, so a throttled primary can no longer blind the cron.
        from .withdrawals import call_bsc_rpc_with_failover
        latest_block = call_bsc_rpc_with_failover("eth.block_number")
        scan_floor = estimate_scan_floor_block(db, latest_block)
        stats["latest_block"] = latest_block
        stats["scan_floor"] = scan_floor
        stats["scanned_blocks"] = max(latest_block - scan_floor + 1, 0)
    except Exception as e:
        logger.error(f"cron_scan_bsc_payments: floor calc failed: {e}")
        return JSONResponse(
            {"error": f"BSC RPC unavailable: {e}", "stats": stats},
            status_code=503,
        )

    # 2a. Retry previously-failed chunks FIRST (added 24 May 2026).
    #     The cursor-stall mechanism already retries chunks from the
    #     CURRENT run, but failures persisted in bsc_scan_failed_chunks
    #     might be from any prior run — including ones where the cursor
    #     advanced because OTHER chunks succeeded after the failed one.
    #     This pass guarantees those orphaned failed ranges are retried
    #     across cron lifetimes.
    retry_transfers: list = []
    try:
        pending_chunks = get_pending_failed_chunks(db, limit=200)
        stats["retry_chunks_seen"] = len(pending_chunks)
        for (fb, tb) in pending_chunks:
            chunk_txs, providers_ok, last_err = get_treasury_transfers_in_range_redundant(fb, tb)
            if providers_ok > 0:
                # Success this attempt — mark resolved and merge transfers
                # into the main processing list. Transfers will go through
                # the same match/orphan logic below as fresh scan results.
                retry_transfers.extend(chunk_txs)
                if mark_chunk_resolved(db, fb, tb):
                    stats["retry_chunks_resolved"] += 1
                    logger.info(
                        f"cron_scan_bsc_payments: failed chunk {fb}-{tb} RESOLVED "
                        f"({len(chunk_txs)} transfers recovered)"
                    )
            else:
                # Still failing — increment attempt count and decide escalation
                err_msg = str(last_err) if last_err else "all providers errored"
                outcome = record_failed_chunk(db, fb, tb, err_msg)
                if outcome["should_abandon"]:
                    mark_chunk_abandoned(db, fb, tb)
                    stats["retry_chunks_abandoned"] += 1
                    logger.error(
                        f"cron_scan_bsc_payments: chunk {fb}-{tb} ABANDONED after "
                        f"{outcome['attempt_count']} failed attempts — "
                        f"manual reconciliation needed"
                    )
                elif outcome["should_alert"]:
                    mark_chunk_alerted(db, fb, tb)
                    stats["alerts_fired"] += 1
                    logger.warning(
                        f"cron_scan_bsc_payments: chunk {fb}-{tb} ESCALATION — "
                        f"{outcome['attempt_count']} consecutive failures, "
                        f"first seen {outcome['first_seen_at']}"
                    )
                    # Best-effort email alert. Failures here MUST NOT break
                    # the scan — wrap in try/except and log.
                    try:
                        _send_bsc_scan_failure_alert(
                            fb, tb, outcome["attempt_count"],
                            outcome["first_seen_at"], err_msg,
                        )
                    except Exception as alert_err:
                        logger.error(f"BSC alert email failed for chunk {fb}-{tb}: {alert_err}")
        db.commit()
    except Exception as e:
        logger.error(f"cron_scan_bsc_payments: retry pass failed: {e}")
        stats["errors"].append(f"retry_pass: {e}")
        db.rollback()

    # 3. Paginated scan with chunk-failure tracking — the MAIN scan from
    #    cursor forward. Returns the safe cursor (highest block that's
    #    part of an unbroken chain of successful chunks from the floor).
    #    Now uses SCAN_REDUNDANCY=3 parallel providers per chunk so a
    #    single-provider index miss doesn't lose transfers (24 May 2026 fix).
    try:
        transfers, safe_cursor, failed_chunks = scan_treasury_transfers_with_cursor(scan_floor)
        stats["transfers_seen"] = len(transfers) + len(retry_transfers)
        stats["safe_cursor"] = safe_cursor
        stats["failed_chunks"] = [[f, t, err[:200]] for f, t, err in failed_chunks]
        # Persist new failures for cross-run retry (the durability fix).
        for fb, tb, err_msg in failed_chunks:
            try:
                outcome = record_failed_chunk(db, fb, tb, err_msg)
                if outcome["should_abandon"]:
                    mark_chunk_abandoned(db, fb, tb)
                elif outcome["should_alert"]:
                    mark_chunk_alerted(db, fb, tb)
                    stats["alerts_fired"] += 1
                    try:
                        _send_bsc_scan_failure_alert(
                            fb, tb, outcome["attempt_count"],
                            outcome["first_seen_at"], err_msg,
                        )
                    except Exception as alert_err:
                        logger.error(f"BSC alert email failed for new chunk {fb}-{tb}: {alert_err}")
            except Exception as e:
                logger.error(f"cron_scan_bsc_payments: record_failed_chunk failed for {fb}-{tb}: {e}")
        if failed_chunks:
            db.commit()
            logger.warning(
                f"cron_scan_bsc_payments: {len(failed_chunks)} chunk(s) failed; "
                f"cursor will hold at block {safe_cursor} so they retry next run. "
                f"failed_ranges={[(f,t) for f,t,_ in failed_chunks[:5]]}{'...' if len(failed_chunks) > 5 else ''}"
            )
        # Merge retry transfers into the main list for downstream match/orphan.
        # Order doesn't matter — match is by tx_hash exact equality and
        # orphan persist is idempotent on tx_hash.
        transfers = list(transfers) + retry_transfers
    except Exception as e:
        logger.error(f"cron_scan_bsc_payments: scan failed: {e}")
        stats["errors"].append(f"scan: {e}")
        transfers = list(retry_transfers)  # at least process retry hits
        safe_cursor = -1
        failed_chunks = []

    # 3a. Stuck-order reconciliation pass (added 24 May 2026).
    #     Last line of defence: for pending orders aged >2 min that the
    #     main scan did NOT pick up (all providers happened to return
    #     empty for the relevant chunk — rare but possible), independently
    #     scan a recent block window and try to match by amount equality.
    #     Any matches merge into `transfers` and flow through the normal
    #     match → activate path below.
    try:
        from .walletconnect_payments import reconcile_stuck_orders
        recon = reconcile_stuck_orders(db, latest_block)
        stats["reconcile_orders_checked"] = recon["orders_checked"]
        stats["reconcile_transfers_found"] = recon["transfers_found"]
        if recon["transfers"]:
            transfers = list(transfers) + recon["transfers"]
            stats["transfers_seen"] += len(recon["transfers"])
            logger.warning(
                f"cron_scan_bsc_payments: reconciler RECOVERED "
                f"{len(recon['transfers'])} transfer(s) the main scan missed "
                f"({recon['orders_checked']} pending orders checked)"
            )
    except Exception as e:
        logger.error(f"cron_scan_bsc_payments: reconcile pass failed: {e}")
        stats["errors"].append(f"reconcile: {e}")

    # 4. Match each transfer; persist orphans for the rest
    for tx in transfers:
        try:
            matched_order = match_incoming_transfer(db, tx)
        except Exception as e:
            logger.error(f"cron_scan_bsc_payments: match failed for tx {tx.get('tx_hash')}: {e}")
            stats["errors"].append(f"match {tx.get('tx_hash','?')[:12]}: {e}")
            continue

        if matched_order:
            # ── Activate the product ──
            try:
                # Load buyer
                buyer = db.query(User).filter(User.id == matched_order.user_id).first()
                if not buyer:
                    logger.error(
                        f"cron_scan_bsc_payments: buyer {matched_order.user_id} "
                        f"missing for matched order {matched_order.id}"
                    )
                    stats["errors"].append(f"buyer_missing: order {matched_order.id}")
                    continue

                # Idempotent Payment row — reuse if a prior activation
                # already wrote it (e.g. cron retry after partial failure)
                tx_ref = f"wc_{matched_order.tx_hash}" if matched_order.tx_hash else f"wc_{uuid.uuid4().hex[:12]}"
                existing_payment = db.query(Payment).filter(Payment.tx_hash == tx_ref).first()
                if not existing_payment:
                    payment = Payment(
                        from_user_id=buyer.id,
                        to_user_id=None,
                        amount_usdt=matched_order.unique_amount,
                        payment_type=f"walletconnect_{matched_order.product_type}",
                        tx_hash=tx_ref,
                        status="confirmed",
                    )
                    db.add(payment)
                    db.flush()

                # Reuse the canonical activation handler — same logic
                # NOWPayments IPN runs, ensuring rail-equivalent fulfilment
                meta = _json.loads(matched_order.product_meta) if matched_order.product_meta else {}

                # _nowpayments_activate_product reads order.price_usd for
                # the SuperScene rail. Our model uses base_amount; alias
                # it on the in-memory instance so the shared activator
                # can read it without a code-path fork.
                if not hasattr(matched_order, "price_usd") or matched_order.price_usd is None:
                    try:
                        matched_order.price_usd = matched_order.base_amount
                    except Exception:
                        # SQLAlchemy InstrumentedAttribute — set as runtime attr
                        object.__setattr__(matched_order, "price_usd", matched_order.base_amount)

                _nowpayments_activate_product(db, buyer, matched_order, meta)
                db.commit()

                stats["matched"] += 1
                stats["activated"] += 1
                logger.info(
                    f"cron_scan_bsc_payments: ACTIVATED order {matched_order.id} "
                    f"user={buyer.id} {matched_order.product_type}/{matched_order.product_key} "
                    f"tx={matched_order.tx_hash}"
                )
            except Exception as e:
                logger.error(
                    f"cron_scan_bsc_payments: activation failed for order "
                    f"{matched_order.id}: {e}"
                )
                stats["errors"].append(f"activate {matched_order.id}: {e}")
                db.rollback()
                # The match itself was rolled back too. The next cron run
                # will re-see the same on-chain transfer and re-attempt.
                # tx_hash idempotency check in match_incoming_transfer
                # only fires once a match has been committed; rollback
                # means it wasn't, so retry is safe.
        else:
            # ── Persist as orphan ──
            try:
                tx_hash = tx.get("tx_hash")
                # Idempotency #1: skip if we've already confirmed an order
                # for this tx_hash. match_incoming_transfer returns None
                # in two cases — "already processed" and "no match".
                # Without this check, every cron re-scan would attempt to
                # file every already-confirmed payment as a fresh orphan.
                already_confirmed = db.query(WalletConnectPaymentOrder).filter(
                    WalletConnectPaymentOrder.tx_hash == tx_hash
                ).first()
                if already_confirmed:
                    continue

                # Idempotency #2: skip if we've already filed this orphan
                existing_orphan = db.query(OnchainOrphanTransfer).filter(
                    OnchainOrphanTransfer.tx_hash == tx_hash
                ).first()
                if existing_orphan:
                    continue

                orphan = OnchainOrphanTransfer(
                    tx_hash=tx_hash,
                    from_address=(tx.get("from_address") or "").lower(),
                    amount_usdt=tx.get("amount_usdt"),
                    block_number=tx.get("block_number"),
                    likely_rounded_amount=is_likely_rounded_amount(tx.get("amount_usdt")),
                )
                db.add(orphan)
                db.commit()
                stats["orphans_added"] += 1
                logger.info(
                    f"cron_scan_bsc_payments: orphan transfer recorded — "
                    f"tx={tx_hash[:12]}... amount=${tx.get('amount_usdt')} "
                    f"rounded_flag={orphan.likely_rounded_amount}"
                )
            except Exception as e:
                logger.error(f"cron_scan_bsc_payments: orphan persist failed: {e}")
                stats["errors"].append(f"orphan {tx.get('tx_hash','?')[:12]}: {e}")
                db.rollback()

    # 5. Persist scan cursor — advance ONLY to safe_cursor (the highest
    #    block in the unbroken chain of successful chunks from the floor).
    #    If any chunk between floor and latest_block failed, safe_cursor
    #    is < latest_block, and the next run will retry the failed range.
    #
    #    The previous version advanced to latest_block whenever stats["errors"]
    #    was empty — but inner-loop chunk failures didn't add to stats["errors"]
    #    (they only logged), so cursor silently skipped over failed chunks.
    #    This was the bug that lost SAP-00205's $14.54 at block 98459311 on
    #    15 May 2026.
    try:
        if safe_cursor > 0:
            current_cursor = None
            try:
                from .walletconnect_payments import get_scan_cursor
                current_cursor = get_scan_cursor(db)
            except Exception:
                pass
            # Only advance — never move cursor backwards
            if current_cursor is None or safe_cursor > current_cursor:
                set_scan_cursor(db, safe_cursor)
                db.commit()
                if failed_chunks:
                    logger.info(
                        f"cron_scan_bsc_payments: cursor → {safe_cursor} "
                        f"(held back from {stats['latest_block']} due to "
                        f"{len(failed_chunks)} failed chunk(s) — retry next run)"
                    )
        elif safe_cursor == -1:
            # Sentinel from scan function: floor calc itself failed.
            # Do not touch the cursor.
            logger.warning(
                "cron_scan_bsc_payments: not advancing cursor — "
                "scan_treasury_transfers couldn't read latest block"
            )
    except Exception as e:
        logger.error(f"cron_scan_bsc_payments: cursor persist failed: {e}")
        stats["errors"].append(f"cursor: {e}")
        db.rollback()

    return stats


def _run_inproc_bsc_scan(SessionLocal, lock_id, sql_text):
    """One iteration of the in-process BSC scanner (Layer 3, 17 May 2026).

    Called from a daemon thread on each interval tick. Acquires a
    Postgres advisory lock so only ONE replica runs the scan at a time
    — multiple Railway replicas all running the scheduler is safe; they
    coordinate via the DB lock and the losers skip silently.

    Mirrors the cron handler's logic but without the FastAPI request /
    auth machinery, since this runs inside the process. The HTTP cron
    endpoint stays live as a manual-trigger backup.

    Args:
        SessionLocal: SQLAlchemy session factory (from .database)
        lock_id:      int32 constant for pg_try_advisory_lock — same
                      across all replicas, different from any other
                      lock IDs the platform uses
        sql_text:     sqlalchemy.text — passed in to avoid re-importing

    Returns: dict of scan stats (same shape as cron handler), or
             {"skipped": "lock_busy"} if another replica is scanning.
    """
    from .database import (
        WalletConnectPaymentOrder, OnchainOrphanTransfer, Payment, User
    )
    from .walletconnect_payments import (
        expire_stale_orders,
        match_incoming_transfer,
        scan_treasury_transfers_with_cursor,
        get_treasury_transfers_in_range_redundant,
        reconcile_stuck_orders,
        estimate_scan_floor_block,
        set_scan_cursor,
        get_scan_cursor,
        get_pending_failed_chunks,
        record_failed_chunk,
        mark_chunk_resolved,
        mark_chunk_abandoned,
        mark_chunk_alerted,
        ESCALATE_AT_ATTEMPTS,
        GIVE_UP_AT_ATTEMPTS,
        is_likely_rounded_amount,
    )
    from app.withdrawals import call_bsc_rpc_with_failover
    import json as _json
    import uuid

    db = SessionLocal()
    lock_held = False
    try:
        # Try to acquire the advisory lock. pg_try_advisory_lock returns
        # bool — TRUE if we got it, FALSE if another replica already has it.
        # NON-BLOCKING: this returns immediately. The lock is held for the
        # duration of this DB session and released when we close it below.
        got_lock = db.execute(
            sql_text("SELECT pg_try_advisory_lock(:lid)"),
            {"lid": lock_id},
        ).scalar()
        if not got_lock:
            # Another replica is currently scanning. Skip silently.
            return {"skipped": "lock_busy"}
        lock_held = True

        stats = {
            "expired": 0,
            "scan_floor": 0,
            "latest_block": 0,
            "scanned_blocks": 0,
            "transfers_seen": 0,
            "matched": 0,
            "activated": 0,
            "orphans_added": 0,
            "errors": [],
            "failed_chunks": [],
            "retry_chunks_seen": 0,
            "retry_chunks_resolved": 0,
            "retry_chunks_abandoned": 0,
            "alerts_fired": 0,
            "reconcile_orders_checked": 0,
            "reconcile_transfers_found": 0,
            "safe_cursor": 0,
        }

        # 1. Expire stale pending orders first
        try:
            stats["expired"] = expire_stale_orders(db)
        except Exception as e:
            logger.error(f"inproc_bsc_scan: expire_stale_orders failed: {e}")
            stats["errors"].append(f"expire: {e}")

        # 2. Compute scan floor
        try:
            latest_block = call_bsc_rpc_with_failover("eth.block_number")
            scan_floor = estimate_scan_floor_block(db, latest_block)
            stats["latest_block"] = latest_block
            stats["scan_floor"] = scan_floor
            stats["scanned_blocks"] = max(latest_block - scan_floor + 1, 0)
            # GAP GUARD (12 Jun 2026): if the floor was forced ahead of the
            # cursor (cursor fell > MAX_SCAN_BLOCKS_PER_RUN behind head), the
            # skipped blocks would be SILENTLY lost — never scanned, never
            # orphaned. Enqueue them into the failed-chunk retry queue (re-scanned
            # this same tick and after) so any payments in them recover
            # automatically, and alert. Only fires on a >cap lag, so a normal
            # deploy restart (well under the cap) never trips it.
            _prior_cursor = get_scan_cursor(db)
            if _prior_cursor is not None and (_prior_cursor + 1) < scan_floor:
                try:
                    _queued = _enqueue_skipped_gap(db, _prior_cursor + 1, scan_floor - 1)
                    stats["gap_blocks_skipped"] = scan_floor - 1 - _prior_cursor
                    stats["gap_chunks_queued"] = _queued
                except Exception as _ge:
                    logger.error(f"inproc_bsc_scan: gap enqueue failed: {_ge}")
                    stats["errors"].append(f"gap_enqueue: {_ge}")
        except Exception as e:
            logger.error(f"inproc_bsc_scan: floor calc failed: {e}")
            return {"error": f"BSC RPC unavailable: {e}", "stats": stats}

        # 2a. Retry previously-failed chunks (24 May 2026 — cross-run retry).
        retry_transfers: list = []
        try:
            pending_chunks = get_pending_failed_chunks(db, limit=200)
            stats["retry_chunks_seen"] = len(pending_chunks)
            for (fb, tb) in pending_chunks:
                chunk_txs, providers_ok, last_err = get_treasury_transfers_in_range_redundant(fb, tb)
                if providers_ok > 0:
                    retry_transfers.extend(chunk_txs)
                    if mark_chunk_resolved(db, fb, tb):
                        stats["retry_chunks_resolved"] += 1
                        logger.info(
                            f"inproc_bsc_scan: failed chunk {fb}-{tb} RESOLVED "
                            f"({len(chunk_txs)} transfers recovered)"
                        )
                else:
                    err_msg = str(last_err) if last_err else "all providers errored"
                    outcome = record_failed_chunk(db, fb, tb, err_msg)
                    if outcome["should_abandon"]:
                        mark_chunk_abandoned(db, fb, tb)
                        stats["retry_chunks_abandoned"] += 1
                    elif outcome["should_alert"]:
                        mark_chunk_alerted(db, fb, tb)
                        stats["alerts_fired"] += 1
                        try:
                            _send_bsc_scan_failure_alert(
                                fb, tb, outcome["attempt_count"],
                                outcome["first_seen_at"], err_msg,
                            )
                        except Exception as alert_err:
                            logger.error(f"inproc alert email failed for chunk {fb}-{tb}: {alert_err}")
            db.commit()
        except Exception as e:
            logger.error(f"inproc_bsc_scan: retry pass failed: {e}")
            stats["errors"].append(f"retry_pass: {e}")
            db.rollback()

        # 3. Paginated scan with safe_cursor tracking — now redundant per-chunk
        try:
            transfers, safe_cursor, failed_chunks = scan_treasury_transfers_with_cursor(scan_floor)
            stats["transfers_seen"] = len(transfers) + len(retry_transfers)
            stats["safe_cursor"] = safe_cursor
            stats["failed_chunks"] = [[f, t, err[:200]] for f, t, err in failed_chunks]
            for fb, tb, err_msg in failed_chunks:
                try:
                    outcome = record_failed_chunk(db, fb, tb, err_msg)
                    if outcome["should_abandon"]:
                        mark_chunk_abandoned(db, fb, tb)
                    elif outcome["should_alert"]:
                        mark_chunk_alerted(db, fb, tb)
                        stats["alerts_fired"] += 1
                        try:
                            _send_bsc_scan_failure_alert(
                                fb, tb, outcome["attempt_count"],
                                outcome["first_seen_at"], err_msg,
                            )
                        except Exception as alert_err:
                            logger.error(f"inproc alert email failed for new chunk {fb}-{tb}: {alert_err}")
                except Exception as e:
                    logger.error(f"inproc_bsc_scan: record_failed_chunk failed for {fb}-{tb}: {e}")
            if failed_chunks:
                db.commit()
                logger.warning(
                    f"inproc_bsc_scan: {len(failed_chunks)} chunk(s) failed; "
                    f"cursor will hold at block {safe_cursor}"
                )
            transfers = list(transfers) + retry_transfers
        except Exception as e:
            logger.error(f"inproc_bsc_scan: scan failed: {e}")
            stats["errors"].append(f"scan: {e}")
            transfers = list(retry_transfers)
            safe_cursor = -1
            failed_chunks = []

        # 3a. Stuck-order reconciliation pass (24 May 2026)
        try:
            recon = reconcile_stuck_orders(db, latest_block)
            stats["reconcile_orders_checked"] = recon["orders_checked"]
            stats["reconcile_transfers_found"] = recon["transfers_found"]
            if recon["transfers"]:
                transfers = list(transfers) + recon["transfers"]
                stats["transfers_seen"] += len(recon["transfers"])
                logger.warning(
                    f"inproc_bsc_scan: reconciler RECOVERED "
                    f"{len(recon['transfers'])} transfer(s) the main scan missed"
                )
        except Exception as e:
            logger.error(f"inproc_bsc_scan: reconcile pass failed: {e}")
            stats["errors"].append(f"reconcile: {e}")

        # 4. Match each transfer; orphan-file the rest. Reuse the
        #    canonical NOWPayments activator on match for parity with
        #    the HTTP cron path.
        for tx in transfers:
            try:
                matched_order = match_incoming_transfer(db, tx)
            except Exception as e:
                logger.error(f"inproc_bsc_scan: match failed for tx {tx.get('tx_hash')}: {e}")
                stats["errors"].append(f"match {tx.get('tx_hash','?')[:12]}: {e}")
                continue

            if matched_order:
                try:
                    buyer = db.query(User).filter(User.id == matched_order.user_id).first()
                    if not buyer:
                        stats["errors"].append(f"buyer_missing: order {matched_order.id}")
                        continue

                    tx_ref = f"wc_{matched_order.tx_hash}" if matched_order.tx_hash else f"wc_{uuid.uuid4().hex[:12]}"
                    existing_payment = db.query(Payment).filter(Payment.tx_hash == tx_ref).first()
                    if not existing_payment:
                        payment = Payment(
                            from_user_id=buyer.id,
                            to_user_id=None,
                            amount_usdt=matched_order.unique_amount,
                            payment_type=f"walletconnect_{matched_order.product_type}",
                            tx_hash=tx_ref,
                            status="confirmed",
                        )
                        db.add(payment)
                        db.flush()

                    meta = _json.loads(matched_order.product_meta) if matched_order.product_meta else {}
                    if not hasattr(matched_order, "price_usd") or matched_order.price_usd is None:
                        try:
                            matched_order.price_usd = matched_order.base_amount
                        except Exception:
                            object.__setattr__(matched_order, "price_usd", matched_order.base_amount)

                    _nowpayments_activate_product(db, buyer, matched_order, meta)
                    db.commit()

                    stats["matched"] += 1
                    stats["activated"] += 1
                    logger.info(
                        f"inproc_bsc_scan: ACTIVATED order {matched_order.id} "
                        f"user={buyer.id} {matched_order.product_type}/"
                        f"{matched_order.product_key} tx={matched_order.tx_hash}"
                    )
                except Exception as e:
                    logger.error(f"inproc_bsc_scan: activation failed for order {matched_order.id}: {e}")
                    stats["errors"].append(f"activate {matched_order.id}: {e}")
                    db.rollback()
            else:
                try:
                    tx_hash = tx.get("tx_hash")
                    already_confirmed = db.query(WalletConnectPaymentOrder).filter(
                        WalletConnectPaymentOrder.tx_hash == tx_hash
                    ).first()
                    if already_confirmed:
                        continue
                    existing_orphan = db.query(OnchainOrphanTransfer).filter(
                        OnchainOrphanTransfer.tx_hash == tx_hash
                    ).first()
                    if existing_orphan:
                        continue
                    orphan = OnchainOrphanTransfer(
                        tx_hash=tx_hash,
                        from_address=(tx.get("from_address") or "").lower(),
                        amount_usdt=tx.get("amount_usdt"),
                        block_number=tx.get("block_number"),
                        likely_rounded_amount=is_likely_rounded_amount(tx.get("amount_usdt")),
                    )
                    db.add(orphan)
                    db.commit()
                    stats["orphans_added"] += 1
                    logger.info(
                        f"inproc_bsc_scan: orphan filed tx={tx_hash[:12]}... "
                        f"amount=${tx.get('amount_usdt')}"
                    )
                except Exception as e:
                    logger.error(f"inproc_bsc_scan: orphan persist failed: {e}")
                    stats["errors"].append(f"orphan {tx.get('tx_hash','?')[:12]}: {e}")
                    db.rollback()

        # 5. Persist cursor — safe_cursor logic same as cron
        try:
            if safe_cursor > 0:
                current_cursor = None
                try:
                    current_cursor = get_scan_cursor(db)
                except Exception:
                    pass
                if current_cursor is None or safe_cursor > current_cursor:
                    set_scan_cursor(db, safe_cursor)
                    db.commit()
        except Exception as e:
            logger.error(f"inproc_bsc_scan: cursor persist failed: {e}")
            stats["errors"].append(f"cursor: {e}")
            db.rollback()

        # Heartbeat log: only on a successful, non-trivial scan, to keep
        # logs quiet during idle periods. The cron equivalent doesn't log
        # heartbeat either — both rely on errors/matches/orphans to surface.
        if stats["transfers_seen"] > 0 or stats["matched"] > 0 or stats["orphans_added"] > 0:
            logger.info(
                f"inproc_bsc_scan tick: floor={stats['scan_floor']} "
                f"latest={stats['latest_block']} transfers={stats['transfers_seen']} "
                f"matched={stats['matched']} orphans={stats['orphans_added']} "
                f"safe_cursor={stats['safe_cursor']}"
            )

        return stats
    finally:
        if lock_held:
            try:
                db.execute(sql_text("SELECT pg_advisory_unlock(:lid)"), {"lid": lock_id})
                db.commit()
            except Exception as e:
                logger.warning(f"inproc_bsc_scan: advisory_unlock failed: {e}")
        try:
            db.close()
        except Exception:
            pass


# ─────────────────────────────────────────────────────────────────────────────
# Stripe payment rail
# ─────────────────────────────────────────────────────────────────────────────
# Re-introduced 23 May 2026 alongside the existing crypto rail. Members
# can now sign up by card OR by USDT on BSC. Two payment_method values
# on User: "crypto" (existing flow) and "stripe" (this flow).
#
# Stripe handles renewals natively — we don't run a cron for Stripe
# subscriptions. We listen to webhooks and update local state when
# Stripe tells us something happened.
#
# Refund policy (Steve, 23 May 2026): partial-refund-only. We refund
# the company's share of each payment (after commissions). Commissions
# are already paid out to wallets / on-chain and can't be reclaimed.
# 7-day window from payment, then no refunds. Stripe Checkout surfaces
# a link to /refund-policy at the moment of payment so the terms are
# explicit before card details are entered.
#
# Founder cap (Steve, 23 May 2026): the 100-Founder cap is shared
# across crypto + Stripe. _activate_membership() already enforces this
# via the FOUNDING_LOCK_KEY advisory lock — no special handling needed
# here as long as we pass tier='founding' when the member chose the
# Founder price.
# ─────────────────────────────────────────────────────────────────────────────

from app import stripe_service as _stripe

@app.get("/api/stripe/status")
async def stripe_status(user: User = Depends(get_current_user)):
    """Diagnostic endpoint — returns whether Stripe is configured + this user's
    Stripe state. Used by frontend to decide whether to show the 'Pay by card'
    option on signup. Returns 200 always; .configured tells the truth."""
    if not user:
        # Unauthenticated probe — just report whether the integration is
        # configured server-side. Useful for monitoring / health checks.
        return {"configured": _stripe.is_configured(), "authenticated": False}
    return {
        "configured": _stripe.is_configured(),
        "authenticated": True,
        "has_subscription": bool(user.stripe_subscription_id),
        "stripe_customer_id": user.stripe_customer_id,
        "payment_method": user.payment_method or "crypto",
        "refund_eligible_until": user.stripe_refund_eligible_until.isoformat() + "Z" if user.stripe_refund_eligible_until else None,
    }


@app.post("/api/stripe/checkout/membership")
async def stripe_checkout_membership(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Create a Stripe Checkout session for membership signup.

    Body (JSON):
      tier:    'partner' or 'founding' (default 'partner')
               If 'founding' is requested but the 100-spot cap is full,
               this endpoint falls back to 'partner' silently. The actual
               founder assignment happens in _activate_membership() on
               webhook receipt so the cap is enforced consistently across
               crypto + Stripe.
      billing: 'monthly' or 'annual' (default 'monthly')  -- added 27 May 2026
               Annual maps to $150/yr Founder or $200/yr Partner. Stripe
               Price IDs come from STRIPE_FOUNDER_ANNUAL_PRICE_ID and
               STRIPE_PARTNER_ANNUAL_PRICE_ID env vars; if either is
               missing, returns 400 with "no_price_for_tier".

    Returns:
      { checkout_url, session_id }
    """
    if not _stripe.is_configured():
        return JSONResponse({"error": "stripe_not_configured"}, status_code=503)

    body = await request.json()
    tier = (body.get("tier") or "partner").lower()
    billing = (body.get("billing") or "monthly").lower()
    if billing not in ("monthly", "annual", "yearly", "year"):
        billing = "monthly"

    if tier in ("founder", "founding"):
        # Check the founder cap before sending the member to Stripe with a
        # $15 price — if the cap is full, send them to the $20 Partner
        # checkout instead and surface the change in metadata so the
        # frontend can show a friendly notice.
        current_founders = db.execute(text(
            "SELECT COUNT(*) AS cnt FROM users WHERE is_founding_member = TRUE"
        )).fetchone()
        if current_founders and current_founders.cnt >= 100:
            tier = "partner"
        # ALSO check the deadline — if the Founder offer has closed by
        # deadline (not just count), fall back to partner pricing the
        # same way. Keeps the time cap consistent across crypto + Stripe.
        elif not _founder_offer_still_open(db):
            tier = "partner"

    price_id = _stripe.get_price_id_for_tier(tier, billing=billing)
    if not price_id:
        return JSONResponse({
            "error": "no_price_for_tier",
            "tier": tier,
            "billing": billing,
            "detail": f"No Stripe Price configured for {tier} ({billing}). Check STRIPE_*_PRICE_ID env vars.",
        }, status_code=400)

    try:
        result = _stripe.create_checkout_session(
            user=user,
            db_session=db,
            product_kind="founder_signup" if tier in ("founder", "founding") else "membership_signup",
            price_id=price_id,
            success_path="/payment-success",
            cancel_path="/partner-payment",
            extra_metadata={"tier_requested": tier, "billing": billing},
        )
        return result
    except Exception as e:
        logger.exception(f"stripe_checkout_membership failed for user {user.id}")
        return JSONResponse({"error": "checkout_create_failed", "detail": str(e)}, status_code=500)


@app.post("/api/stripe/checkout/campaign-tier")
async def stripe_checkout_campaign_tier(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Create a one-time Stripe Checkout session for a Campaign Tier purchase.

    Body (JSON):
      tier_id: 1-8 (Starter $20 through Champion $1000)

    Membership-gated: members must be active partners to buy campaign
    tiers (matches the existing crypto rail rule). One-time payment mode
    on the Stripe side — not a subscription.

    Returns:
      { checkout_url, session_id }
    """
    if not _stripe.is_configured():
        return JSONResponse({"error": "stripe_not_configured"}, status_code=503)
    if not user:
        return JSONResponse({"error": "auth_required"}, status_code=401)
    # Campaign tiers are gated to active partners (membership active).
    # Mirrors the crypto rail check in /api/nowpayments/create-invoice
    # and the various other entry points.
    if not user.is_active:
        return JSONResponse({"error": "membership_required", "detail": "Campaign Tiers are available to active members only."}, status_code=403)

    body = await request.json()
    try:
        tier_id = int(body.get("tier_id") or 0)
    except (TypeError, ValueError):
        tier_id = 0
    price_usd = GRID_PACKAGES.get(tier_id)
    if not price_usd:
        return JSONResponse({"error": "invalid_tier", "detail": f"tier_id must be 1-8, got {tier_id}"}, status_code=400)

    amount_cents = int(round(float(price_usd) * 100))
    try:
        result = _stripe.create_checkout_session(
            user=user,
            db_session=db,
            product_kind="campaign_tier",
            amount_cents=amount_cents,
            success_path=f"/campaign-tiers?activated=tier_{tier_id}",
            cancel_path=f"/activate-tier/{tier_id}",
            extra_metadata={"campaign_tier_id": str(tier_id)},
        )
        return result
    except Exception as e:
        logger.exception(f"stripe_checkout_campaign_tier failed for user {user.id} tier {tier_id}")
        return JSONResponse({"error": "checkout_create_failed", "detail": str(e)}, status_code=500)


@app.post("/api/stripe/checkout/launchpad")
async def stripe_checkout_launchpad(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Create a one-time $10 Stripe Checkout session for the Launchpad
    (grid tier 0) — the entry rung for FREE (non-member) users.

    Unlike campaign tiers (active-member only), Launchpad sits BEFORE
    membership: a free user pays $10, gets the tier-0 grid + comp-plan
    qualification (can_earn True), but NO tools and NO tiers 1-8 until they
    activate full membership. One-time payment mode. Price is sourced from
    GRID_PACKAGES[0] so it stays single-source with every other rail.

    Returns: { checkout_url, session_id }
    """
    if not _stripe.is_configured():
        return JSONResponse({"error": "stripe_not_configured"}, status_code=503)
    if not user:
        return JSONResponse({"error": "auth_required"}, status_code=401)
    # Full members already have tier access — Launchpad is the free-user ramp.
    if user.is_active:
        return JSONResponse({"error": "already_active", "detail": "You already have full membership — Launchpad is the free-user entry rung."}, status_code=400)
    # Already on Launchpad — don't sell a second tier-0 entry.
    if (getattr(user, "membership_tier", None) or "free") == "launchpad":
        return JSONResponse({"error": "already_launchpad", "detail": "You're already on Launchpad."}, status_code=400)

    price_usd = GRID_PACKAGES.get(0)
    if not price_usd:
        return JSONResponse({"error": "launchpad_unavailable"}, status_code=503)
    amount_cents = int(round(float(price_usd) * 100))
    try:
        result = _stripe.create_checkout_session(
            user=user,
            db_session=db,
            product_kind="launchpad",
            amount_cents=amount_cents,
            success_path="/dashboard?launchpad=activated",
            cancel_path="/dashboard",
        )
        return result
    except Exception as e:
        logger.exception(f"stripe_checkout_launchpad failed for user {user.id}")
        return JSONResponse({"error": "checkout_create_failed", "detail": str(e)}, status_code=500)


@app.post("/api/stripe/checkout/nexus-pack")
async def stripe_checkout_nexus_pack(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Create a one-time Stripe Checkout session for a Credit Nexus pack.

    Body (JSON):
      pack_key: 'starter' | 'builder' | 'pro' | 'advanced' | 'elite' | 'premium' | 'executive' | 'ultimate'

    Membership-gated: only active members can purchase Nexus packs
    (matches the crypto rail rule).

    Returns:
      { checkout_url, session_id }
    """
    if not _stripe.is_configured():
        return JSONResponse({"error": "stripe_not_configured"}, status_code=503)
    if not user:
        return JSONResponse({"error": "auth_required"}, status_code=401)
    if not user.is_active:
        return JSONResponse({"error": "membership_required", "detail": "Credit Nexus packs are available to active members only."}, status_code=403)

    body = await request.json()
    pack_key = (body.get("pack_key") or "").lower().strip()
    pack = CREDIT_PACKS.get(pack_key)
    if not pack:
        return JSONResponse({"error": "invalid_pack", "detail": f"Unknown pack '{pack_key}'. Valid: {list(CREDIT_PACKS.keys())}"}, status_code=400)

    amount_cents = int(round(float(pack["price"]) * 100))
    try:
        result = _stripe.create_checkout_session(
            user=user,
            db_session=db,
            product_kind="nexus_pack",
            amount_cents=amount_cents,
            success_path=f"/my-credits?activated={pack_key}",
            cancel_path="/my-credits",
            extra_metadata={"nexus_pack_key": pack_key},
        )
        return result
    except Exception as e:
        logger.exception(f"stripe_checkout_nexus_pack failed for user {user.id} pack {pack_key}")
        return JSONResponse({"error": "checkout_create_failed", "detail": str(e)}, status_code=500)


@app.post("/api/stripe/checkout/pif-voucher")
async def stripe_checkout_pif_voucher(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Create a one-time Stripe Checkout session for a Pay It Forward
    gift voucher ($20 flat).

    Body (JSON):
      recipient_name:   optional, max 100 chars, surfaces on the
                        recipient's claim page
      personal_message: optional, max 500 chars, ditto

    Membership-gated: only active members can buy gift vouchers
    (matches crypto + wallet rails — see /api/pay-it-forward/create).
    Also enforces the 10-active-voucher rate limit.

    Returns:
      { checkout_url, session_id }

    Webhook then creates the GiftVoucher row in 'available' state via
    the pif_voucher case in _stripe_handle_checkout_completed. The
    voucher gets a payment_ref of stripe_{session_id} so it's
    traceable back to the original charge.

    Added 26 May 2026 — third and final payment rail for PIF, closing
    parity with membership + nexus pack flows which already had Stripe
    available alongside crypto.
    """
    if not _stripe.is_configured():
        return JSONResponse({"error": "stripe_not_configured"}, status_code=503)
    if not user:
        return JSONResponse({"error": "auth_required"}, status_code=401)
    if not user.is_active and not user.is_admin:
        return JSONResponse(
            {"error": "membership_required",
             "detail": "You must be an active member to gift a membership."},
            status_code=403,
        )

    # Same 10-active-voucher rate limit as the wallet/crypto rails
    from .database import GiftVoucher
    active_count = db.query(GiftVoucher).filter(
        GiftVoucher.gifter_user_id == user.id,
        GiftVoucher.status == "available",
    ).count()
    if active_count >= 10:
        return JSONResponse(
            {"error": "limit_reached",
             "detail": "Maximum 10 unclaimed vouchers at a time. Wait for some to be claimed."},
            status_code=429,
        )

    body = await request.json()
    recipient_name = (body.get("recipient_name") or "").strip()[:100]
    personal_message = (body.get("personal_message") or "").strip()[:500]

    try:
        result = _stripe.create_checkout_session(
            user=user,
            db_session=db,
            product_kind="pif_voucher",
            amount_cents=2000,  # $20 flat
            success_path="/pay-it-forward?paid=1&via=stripe",
            cancel_path="/pay-it-forward",
            extra_metadata={
                "pif_recipient_name": recipient_name,
                "pif_personal_message": personal_message,
            },
        )
        return result
    except Exception as e:
        logger.exception(f"stripe_checkout_pif_voucher failed for user {user.id}")
        return JSONResponse({"error": "checkout_create_failed", "detail": str(e)}, status_code=500)


