@app.post("/api/stripe/webhook")
async def stripe_webhook(request: Request, db: Session = Depends(get_db)):
    """Stripe webhook receiver.

    Verifies the signature, then dispatches to the right handler based on
    event type. Returns 200 on success, 400 on invalid signature (causes
    Stripe to retry).

    Events handled (subscribe these in Stripe Dashboard → Developers → Webhooks):
      - checkout.session.completed   → activate membership / mark one-time paid
      - invoice.paid                 → log renewal payment, extend membership
      - invoice.payment_failed       → log + send notification (Stripe retries)
      - customer.subscription.deleted → mark membership as ended
      - charge.dispute.created       → CHARGEBACK — suspend member immediately
      - charge.refunded              → log refund (kept for audit)
    """
    payload = await request.body()
    signature = request.headers.get("stripe-signature", "")

    try:
        event_obj = _stripe.verify_and_parse_webhook(payload, signature)
    except Exception as e:
        logger.warning(f"Stripe webhook signature verification failed: {e}")
        return JSONResponse({"error": "invalid_signature"}, status_code=400)

    # 23 May 2026: convert Stripe SDK object to plain dict so all downstream
    # handlers work with native Python types. Stripe StripeObject supports
    # .get() dict-style but nested objects can be StripeObject too which
    # subtly breaks some assumptions. .to_dict_recursive() returns a fully
    # native dict tree.
    try:
        if hasattr(event_obj, "to_dict_recursive"):
            event = event_obj.to_dict_recursive()
        elif hasattr(event_obj, "to_dict"):
            event = event_obj.to_dict()
        else:
            event = dict(event_obj)
    except Exception as e:
        logger.exception("Failed to convert Stripe event to dict")
        return JSONResponse({"received": True, "convert_error": str(e)}, status_code=200)

    event_type = event.get("type", "")
    obj = event.get("data", {}).get("object", {})
    logger.info(f"Stripe webhook received: {event_type} (id={event.get('id')})")

    try:
        if event_type == "checkout.session.completed":
            _stripe_handle_checkout_completed(db, obj, event)
        elif event_type == "invoice.paid":
            _stripe_handle_invoice_paid(db, obj, event)
        elif event_type == "invoice.payment_failed":
            _stripe_handle_invoice_failed(db, obj, event)
        elif event_type == "customer.subscription.deleted":
            _stripe_handle_subscription_deleted(db, obj, event)
        elif event_type == "charge.dispute.created":
            _stripe_handle_dispute_created(db, obj, event)
        elif event_type == "charge.refunded":
            _stripe_handle_charge_refunded(db, obj, event)
        else:
            # We received an event we don't handle — that's fine, just log.
            logger.info(f"Stripe webhook: unhandled event type {event_type}")
        return {"received": True}
    except Exception as e:
        # Webhook handler crashed. Return 200 to Stripe so they don't
        # retry (the failure is on our side and a retry won't fix it),
        # but ALERT the founder so a paying member doesn't sit stuck
        # waiting for us to notice. Bug caught 26 May 2026: Sylvia +
        # Mary both stuck for hours because the handler crashed (founder
        # spot collision), webhook returned 200, no human knew until
        # they messaged in.
        import traceback as _traceback
        tb = _traceback.format_exc()
        logger.exception(f"Stripe webhook handler crashed for {event_type}")
        # Best-effort alert email to the founder. Wrapped in its own
        # try/except so an email failure can't compound the original
        # crash. Includes the event type, event id, and a truncated
        # traceback so we can diagnose without needing Railway logs.
        try:
            from .email_utils import send_email, SITE_URL as _SITE_URL
            alert_to = os.environ.get("ADMIN_ALERT_EMAIL", "stevelawsonmarketing@gmail.com")
            event_id = event.get("id", "unknown")
            obj_data = event.get("data", {}).get("object", {}) or {}
            customer_email = (obj_data.get("customer_email")
                              or obj_data.get("receipt_email") or "unknown")
            metadata = obj_data.get("metadata") or {}
            sap_user_id = metadata.get("superadpro_user_id", "unknown")
            html = (
                f'<div style="font-family:Sora,sans-serif;max-width:600px;'
                f'margin:0 auto;padding:24px;background:#fff">'
                f'<h2 style="color:#dc2626;margin:0 0 12px">'
                f'⚠️ Stripe webhook crashed</h2>'
                f'<p style="color:#475569;font-size:14px;line-height:1.6">'
                f'A Stripe webhook reached the platform but the handler '
                f'failed. The customer may be charged but not activated. '
                f'Investigate immediately.</p>'
                f'<table style="width:100%;border-collapse:collapse;'
                f'background:#f8fafc;border-radius:10px;padding:16px;'
                f'margin:16px 0">'
                f'<tr><td style="padding:6px 12px;color:#64748b;font-size:13px">Event type</td>'
                f'<td style="padding:6px 12px;color:#0f172a;font-weight:600;font-family:monospace">{event_type}</td></tr>'
                f'<tr><td style="padding:6px 12px;color:#64748b;font-size:13px">Event ID</td>'
                f'<td style="padding:6px 12px;color:#0f172a;font-family:monospace;font-size:12px">{event_id}</td></tr>'
                f'<tr><td style="padding:6px 12px;color:#64748b;font-size:13px">Customer email</td>'
                f'<td style="padding:6px 12px;color:#0f172a">{customer_email}</td></tr>'
                f'<tr><td style="padding:6px 12px;color:#64748b;font-size:13px">SuperAdPro user_id</td>'
                f'<td style="padding:6px 12px;color:#0f172a">{sap_user_id}</td></tr>'
                f'<tr><td style="padding:6px 12px;color:#64748b;font-size:13px;vertical-align:top">Error</td>'
                f'<td style="padding:6px 12px;color:#dc2626;font-family:monospace;font-size:12px;word-break:break-word">{str(e)[:1000]}</td></tr>'
                f'</table>'
                f'<p style="color:#475569;font-size:13px;margin:16px 0 8px">Next steps:</p>'
                f'<ol style="color:#475569;font-size:13px;line-height:1.7">'
                f'<li>Run <code>/admin/stripe-user-debug?user_id={sap_user_id}</code></li>'
                f'<li>Verify in Stripe Dashboard the charge succeeded</li>'
                f'<li>Run <code>/admin/stripe-recover-user/{sap_user_id}?tier=founding&amount_cents=1500</code> (or tier=partner&amount_cents=2000)</li>'
                f'</ol>'
                f'<details style="margin-top:16px"><summary style="cursor:pointer;color:#64748b;font-size:12px">Full traceback</summary>'
                f'<pre style="font-size:10px;background:#0f172a;color:#cbd5e1;padding:12px;border-radius:8px;overflow-x:auto">{tb[:3000]}</pre>'
                f'</details>'
                f'</div>'
            )
            send_email(
                alert_to,
                f"⚠️ SuperAdPro Stripe webhook crashed: {event_type}",
                html,
                f"Stripe webhook crashed. Event: {event_type} (id: {event_id}). "
                f"Customer: {customer_email}, user_id: {sap_user_id}. "
                f"Error: {str(e)[:500]}",
            )
        except Exception as alert_err:
            logger.exception(f"Failed to send Stripe webhook crash alert: {alert_err}")
        return {"received": True, "handler_error": str(e), "handler_error_type": type(e).__name__}


def _stripe_handle_checkout_completed(db, session, event):
    """The member has just finished paying at Stripe Checkout.
    For subscription mode: activate the membership.
    For payment mode: mark the one-time product as paid (custom domain, etc.)."""
    metadata = session.get("metadata", {}) or {}
    user_id = int(metadata.get("superadpro_user_id", 0))
    if not user_id:
        logger.warning(f"Stripe checkout.session.completed without user_id: {session.get('id')}")
        return
    user = db.query(User).filter(User.id == user_id).first()
    if not user:
        logger.warning(f"Stripe checkout for unknown user {user_id}")
        return

    # ── Per-user activation lock (added 27 May 2026, late evening) ──────
    # See full explanation in _stripe_handle_invoice_paid. Both handlers
    # must acquire the same per-user advisory lock to serialise concurrent
    # webhook deliveries that hit different Railway replicas. The is_active
    # check below is correct logic but not atomic without this lock.
    db.execute(text("SELECT pg_advisory_xact_lock(:k)"),
               {"k": 6101000000 + user.id})
    db.refresh(user)

    product_kind = metadata.get("product_kind", "membership_signup")
    mode = session.get("mode", "")
    amount_cents = int(session.get("amount_total") or 0)
    company_share, refundable = _stripe.calculate_refundable(product_kind, amount_cents)

    # Persist charge row for audit
    charge = StripeCharge(
        user_id=user.id,
        stripe_session_id=session.get("id"),
        stripe_payment_intent_id=session.get("payment_intent"),
        stripe_subscription_id=session.get("subscription"),
        kind="charge",
        product=product_kind,
        amount_cents=amount_cents,
        currency=session.get("currency", "usd"),
        company_share_cents=company_share,
        refundable_cents=refundable,
        description=f"Checkout completed: {product_kind}",
        raw_event_json=str(event)[:50000],  # truncate to keep row size sane
    )
    db.add(charge)
    db.flush()

    # Refund window opens for 7 days from this payment
    user.stripe_refund_eligible_until = _stripe.refund_window_expiry()
    user.payment_method = "stripe"

    if mode == "subscription":
        # Membership signup or upgrade
        user.stripe_subscription_id = session.get("subscription")
        tier_requested = metadata.get("tier_requested", "partner")
        tier_for_activation = "founding" if tier_requested in ("founder", "founding") else "partner"
        # 27 May 2026: read billing cadence from metadata too. We pass
        # 'billing' in extra_metadata at checkout-creation; if absent
        # default monthly. _activate_membership(billing="annual") sets
        # 365-day expiry and 10× sponsor commission.
        billing_from_metadata = (metadata.get("billing") or "monthly").lower()
        if billing_from_metadata not in ("monthly", "annual", "yearly", "year"):
            billing_from_metadata = "monthly"
        billing_for_activation = "annual" if billing_from_metadata in ("annual", "yearly", "year") else "monthly"

        # ── Double-fire guard (26 May 2026) ────────────────────────────
        # Both webhook events can fire for a single signup (Stripe sends
        # them both as normal flow). If invoice.paid arrived FIRST and the
        # self-healing branch in _stripe_handle_invoice_paid already
        # activated the user, this checkout-completed handler must not
        # re-activate or it pays the sponsor commission a second time.
        # Bug caught 26 May via daily-briefing audit:
        #   starthere paid TWICE for earnwithdarius signup ($10 each,
        #   commissions 601 'stripe-invoice-recovery' + 603 'stripe',
        #   500ms apart). starthere kept the duplicate $10; company short $10.
        if user.is_active:
            logger.info(
                f"Stripe checkout.session.completed for already-active user "
                f"{user.id} ({user.username}) — invoice.paid self-healing "
                f"path likely arrived first. Skipping duplicate activation; "
                f"charge row recorded above for audit."
            )
            db.commit()
            return

        try:
            # Idempotency key: use the Stripe subscription_id (which is
            # the SAME for both checkout.session.completed and invoice.paid
            # events covering this signup) rather than event.id (which
            # differs per webhook). Both webhook handlers compute the same
            # source_event_id, so the partial unique index blocks the
            # second one even if they hit different replicas.
            sub_id = session.get("subscription")
            idem_key = f"stripe_sub:{sub_id}" if sub_id else None
            _activate_membership(
                db=db,
                user=user,
                tier=tier_for_activation,
                source="stripe",
                subscription_id=sub_id,
                is_upgrade=False,
                billing=billing_for_activation,
                source_event_id=idem_key,
            )
            logger.info(f"Stripe membership activated for user {user.id} tier={tier_for_activation} billing={billing_for_activation}")
        except Exception as e:
            logger.exception(f"_activate_membership failed during Stripe webhook for user {user.id}")
    elif mode == "payment":
        # One-time payment (Campaign Tier, Credit Nexus pack, custom domain).
        # Dispatch based on product_kind from session metadata.
        logger.info(f"Stripe one-time payment received: user={user.id} product={product_kind} amount={amount_cents}")

        # ── ROOT-CAUSE GUARD (31 May 2026) ─────────────────────────────────
        # Activation must ONLY run on a real, completed, LIVE payment. Without
        # this, test-mode (cs_test_) checkout sessions and live sessions that
        # never actually paid (payment_status != 'paid') were running
        # process_tier_purchase — activating grids + paying up-chain commissions
        # with NO money in. Forensic: 44 campaign_tier charges / $1000, ZERO
        # live-verified; ~40 grids activated free; ~$687 phantom commissions.
        #   - payment_status must be 'paid' (form-completed-but-unpaid sessions
        #     report 'unpaid'/'no_payment_required')
        #   - the event must be livemode (test-mode events never touch production)
        _pay_status = (session.get("payment_status") or "").lower()
        _livemode = bool(event.get("livemode", session.get("livemode", False)))
        if _pay_status != "paid" or not _livemode:
            logger.error(
                f"Stripe one-time payment NOT activated — guard tripped. "
                f"user={user.id} product={product_kind} payment_status={_pay_status!r} "
                f"livemode={_livemode} session={session.get('id')}. "
                f"(Refusing to activate without a real, paid, live charge.)"
            )
            # Record nothing as activated; return cleanly so Stripe doesn't retry.
            db.commit()
            return

        if product_kind == "campaign_tier":
            # Activate the purchased campaign tier — reuses the exact same
            # logic the crypto rail uses (process_tier_purchase handles
            # grid placement, sponsor commission, completion bonus pool,
            # rotator enrolment if applicable, fast-start hero hide).
            try:
                tier_id_str = metadata.get("campaign_tier_id", "0")
                tier_id = int(tier_id_str)
                from .grid import process_tier_purchase
                result = process_tier_purchase(
                    db=db, buyer_id=user.id, package_tier=tier_id,
                    source_event_id=f"stripe_{session.get('id')}",
                )
                if result.get("success"):
                    # ── Authoritative grid Payment row (31 May 2026 systemic fix) ──
                    # The crypto rails leave a TRUSTED confirmed artifact: their
                    # order row (WalletConnectOrder / NowPaymentsOrder / Crypto-
                    # PaymentOrder) flips to status='confirmed' only after on-chain
                    # verification, and the reconciliation engine reads that as
                    # top-priority proof of payment. Stripe tier purchases used to
                    # leave ONLY a StripeCharge row — and that row is written for
                    # AUDIT *before* the payment_status/livemode guard above, so it
                    # exists even for test-mode (cs_test_) and incomplete live
                    # sessions. It is therefore NOT trustworthy on its own, which is
                    # exactly what blinded the engine to card-paid tiers (caught
                    # 31 May 2026: >=9 real card-payers wrongly flagged 'unpaid',
                    # commissions voided then fully restored).
                    #
                    # We now write a CONFIRMED grid Payment row HERE — past the
                    # guard — so it is created ONLY for real, settled, live money,
                    # exactly parallel to a confirmed crypto order. This gives the
                    # engine a first-class trusted signal that needs no per-run live
                    # Stripe API re-verification.
                    #   payment_type 'stripe_grid_{tier}' is read by the engine's
                    #     confirmed_payment branch via an ADDITIVE TIER-EXACT clause
                    #     (== f"stripe_grid_{tier}"). Deliberately does NOT match the
                    #     broad LIKE 'grid_%' wildcard, so a tier-1 Stripe payment
                    #     marks ONLY the tier-1 grid paid — never a spillover-created
                    #     higher-tier grid. This mirrors how the crypto rails match
                    #     tier-specifically (order.product_key == f"grid_{tier}").
                    #   tx_hash 'stripe_grid_{session_id}' is unique => idempotent on
                    #     webhook re-delivery (check-then-add below). The commission
                    #     side is independently replay-guarded by source_event_id in
                    #     process_tier_purchase, so a redelivery double-writes neither.
                    try:
                        _grid_tx = f"stripe_grid_{session.get('id')}"
                        _exists = db.query(Payment).filter(Payment.tx_hash == _grid_tx).first()
                        if not _exists:
                            db.add(Payment(
                                from_user_id=user.id,
                                to_user_id=None,
                                amount_usdt=round(amount_cents / 100.0, 2),
                                payment_type=f"stripe_grid_{tier_id}",
                                tx_hash=_grid_tx,
                                status="confirmed",
                            ))
                            db.flush()
                            logger.info(
                                f"Stripe grid Payment row written: user={user.id} "
                                f"tier={tier_id} tx={_grid_tx} amount=${amount_cents/100:.2f}"
                            )
                    except Exception:
                        # Activation already succeeded; a failed audit-row write must
                        # not crash the webhook (Stripe would retry and risk a double
                        # activation). Log loudly — this is a reconciliation gap, not
                        # a money error.
                        logger.exception(
                            f"Failed to write Stripe grid Payment row for user "
                            f"{user.id} tier {tier_id} — activation succeeded, "
                            f"engine will fall back to live StripeCharge verification."
                        )
                    # Hide fast-start hero on grid activation (mirrors crypto rail logic)
                    try:
                        if user.fast_start_hidden_at is None:
                            user.fast_start_hidden_at = datetime.utcnow()
                            db.add(user)
                    except Exception:
                        pass
                    logger.info(f"Stripe campaign tier activated: user={user.id} tier={tier_id}")
                else:
                    logger.error(f"Stripe campaign tier activation failed: user={user.id} tier={tier_id} err={result.get('error')}")
            except Exception as e:
                logger.exception(f"campaign_tier activation crashed for user {user.id}")

        elif product_kind == "nexus_pack":
            # Purchase the Credit Nexus pack — reuses purchase_credit_pack
            # which handles matrix placement, all 3 commission types (direct,
            # spillover, completion bonus), and credit awards.
            try:
                pack_key = metadata.get("nexus_pack_key", "")
                from .credit_matrix import purchase_credit_pack
                result = purchase_credit_pack(
                    db, user, pack_key,
                    payment_ref=f"stripe_{session.get('id')}",
                    payment_method="stripe",
                )
                if result.get("success"):
                    logger.info(f"Stripe Nexus pack purchased: user={user.id} pack={pack_key} credits={result.get('credits_awarded')}")
                else:
                    logger.error(f"Stripe Nexus pack failed: user={user.id} pack={pack_key} err={result.get('error')}")
            except Exception as e:
                logger.exception(f"nexus_pack activation crashed for user {user.id}")

        elif product_kind == "pif_voucher":
            # Pay It Forward gift voucher — creates a GiftVoucher row in
            # 'available' state. Mirrors the NOWPayments / WalletConnect
            # PIF activation logic (see app/main.py search for
            # "Pay It Forward voucher" — same chain-depth + parent
            # lookup pattern, same code-generation retry loop). The
            # only difference is the payment_ref, which here is
            # stripe_{session_id} so audit trail traces back to the
            # exact Stripe charge.
            try:
                from .database import GiftVoucher
                # Find the buyer's claimed voucher (if any) to compute
                # chain depth — matches the wallet + crypto rails
                received = db.query(GiftVoucher).filter(
                    GiftVoucher.claimed_by_user_id == user.id
                ).first()
                parent_id = received.id if received else None
                chain_depth = (received.pif_chain_depth + 1) if received else 1

                # Generate unique code (same algorithm + 10-try retry)
                code = None
                for _ in range(10):
                    candidate = _generate_voucher_code()
                    existing = db.query(GiftVoucher).filter(
                        GiftVoucher.voucher_code == candidate
                    ).first()
                    if not existing:
                        code = candidate
                        break
                if not code:
                    logger.error(
                        f"PIF Stripe activation: could not generate unique "
                        f"voucher code for user {user.id} session {session.get('id')}"
                    )
                    return

                voucher = GiftVoucher(
                    gifter_user_id=user.id,
                    voucher_code=code,
                    gift_type="membership",
                    gift_value=20,
                    recipient_name=(metadata.get("pif_recipient_name") or "")[:100] or None,
                    personal_message=(metadata.get("pif_personal_message") or "")[:500] or None,
                    is_free_voucher=False,
                    payment_method="stripe",
                    payment_ref=f"stripe_{session.get('id')}",
                    status="available",
                    pif_chain_depth=chain_depth,
                    parent_voucher_id=parent_id,
                )
                db.add(voucher)
                logger.info(
                    f"Stripe PIF voucher created: user={user.id} code={code} "
                    f"chain_depth={chain_depth}"
                )
            except Exception as e:
                logger.exception(f"pif_voucher activation crashed for user {user.id}")

        elif product_kind == "launchpad":
            # $10 Launchpad = grid tier 0 for a FREE (non-member) user. Grants
            # the tier-0 grid + comp-plan qualification through the SAME engine
            # the crypto rail uses (process_tier_purchase, tier 0), and tags
            # membership_tier='launchpad' so can_earn() flips True while
            # is_pro() stays False (tools + tiers 1-8 stay locked until full
            # membership). Mirrors the WalletConnect/BSC rail's
            # _nowpayments_activate_product launchpad logic exactly.
            try:
                from .grid import process_tier_purchase
                result = process_tier_purchase(
                    db=db, buyer_id=user.id, package_tier=0,
                    source_event_id=f"stripe_{session.get('id')}",
                )
                if result.get("success"):
                    # Promote a free user UP to launchpad — idempotent, and
                    # never downgrades an active member or an existing
                    # launchpad/founding/partner tier.
                    if not user.is_active and (getattr(user, "membership_tier", None) or "free") == "free":
                        user.membership_tier = "launchpad"
                        db.add(user)
                        logger.info(f"Stripe Launchpad: user={user.id} tagged membership_tier='launchpad'")
                    # Trusted confirmed Payment row — written PAST the
                    # paid+livemode guard, exactly parallel to the campaign_tier
                    # rail, so the reconciliation engine sees real settled money
                    # for tier 0. tx_hash is unique per session => idempotent on
                    # webhook re-delivery; commission side is replay-guarded by
                    # source_event_id inside process_tier_purchase.
                    try:
                        _lp_tx = f"stripe_grid_{session.get('id')}"
                        if not db.query(Payment).filter(Payment.tx_hash == _lp_tx).first():
                            db.add(Payment(
                                from_user_id=user.id,
                                to_user_id=None,
                                amount_usdt=round(amount_cents / 100.0, 2),
                                payment_type="stripe_grid_0",
                                tx_hash=_lp_tx,
                                status="confirmed",
                            ))
                            db.flush()
                            logger.info(
                                f"Stripe Launchpad Payment row written: user={user.id} "
                                f"tx={_lp_tx} amount=${amount_cents/100:.2f}"
                            )
                    except Exception:
                        logger.exception(
                            f"Failed to write Stripe Launchpad Payment row for user "
                            f"{user.id} — activation succeeded, engine will fall back "
                            f"to live StripeCharge verification."
                        )
                    # Hide fast-start hero on grid activation (mirror crypto rail)
                    try:
                        if user.fast_start_hidden_at is None:
                            user.fast_start_hidden_at = datetime.utcnow()
                            db.add(user)
                    except Exception:
                        pass
                    logger.info(f"Stripe Launchpad activated: user={user.id} tier=0")
                else:
                    logger.error(f"Stripe Launchpad activation failed: user={user.id} err={result.get('error')}")
            except Exception:
                logger.exception(f"launchpad activation crashed for user {user.id}")

        # Other one-time products (custom_domain etc.) ship later — log only.

    db.commit()


def _stripe_handle_invoice_paid(db, invoice, event):
    """A subscription invoice was paid.

    Two cases this handler covers:
      (a) Renewal — user is already active, we just log the charge and
          extend the membership window.
      (b) Self-healing activation — user is NOT active but the invoice
          has billing_reason='subscription_create' and metadata pointing
          at one of our users. This means checkout.session.completed
          fired into the void (a legacy/disabled webhook endpoint, a
          duplicate registration, or Stripe simply not firing it) and
          this is the first time our backend sees the payment.
          Activate them from here instead of losing the activation.

    Discovered 25 May 2026 — case (b) was caught because jerrygoff paid
    $15 Founder subscription, invoice.paid arrived with 200 OK to our
    webhook, but checkout.session.completed never reached us, leaving
    them charged-but-inactive. Self-healing here means a future
    occurrence (regardless of root cause) doesn't strand a paying member.
    """
    customer_id = invoice.get("customer")
    if not customer_id:
        return
    user = db.query(User).filter(User.stripe_customer_id == customer_id).first()
    if not user:
        logger.warning(f"Stripe invoice.paid for unknown customer {customer_id}")
        return

    # ── Per-user activation lock (added 27 May 2026, late evening) ──────
    # Concurrent webhook races: when checkout.session.completed and
    # invoice.paid arrive within ~350ms of each other (real case caught
    # for user dprose55420 -> ourfreedom sponsor commission), they hit
    # different Railway replicas. Both read user.is_active=False at the
    # same instant, both run the self-healing activation, both pay the
    # sponsor commission. Result: duplicate $10 commission paid out.
    #
    # The is_user_inactive check below is correct logic but not atomic
    # against concurrent transactions. pg_advisory_xact_lock with a
    # per-user key serialises both webhook paths — one waits, the other
    # commits and releases on transaction end, the waiter then reads the
    # post-commit state (user IS active, skips self-healing).
    #
    # Lock key derivation: 6101000000 + user.id keeps it in a dedicated
    # namespace from other locks (Founder lock is 7423957, rotator lock
    # is 8742193, BSC scanner is 1885347291). 6.1 billion fits in int64.
    db.execute(text("SELECT pg_advisory_xact_lock(:k)"),
               {"k": 6101000000 + user.id})
    # After acquiring the lock, RE-READ the user to get the post-commit
    # state from any peer transaction that activated us moments ago.
    db.refresh(user)

    amount_cents = int(invoice.get("amount_paid") or 0)
    if amount_cents <= 0:
        # $0 invoice (trial / coupon) — nothing to log
        return

    # 23 May 2026: API version 2026-04-22.dahlia restructured invoice fields.
    # subscription is no longer at top level — it's at
    # parent.subscription_details.subscription. payment_intent similarly
    # moved. Read both old and new locations for forward/backward compat.
    subscription_id = invoice.get("subscription")
    if not subscription_id:
        parent = invoice.get("parent") or {}
        sub_details = parent.get("subscription_details") or {}
        subscription_id = sub_details.get("subscription")
    payment_intent_id = invoice.get("payment_intent")
    if not payment_intent_id:
        # Newer API versions don't expose payment_intent here. Acceptable —
        # we still capture the subscription_id for audit chain.
        pass

    # ── Self-healing activation branch ────────────────────────────────
    # Detect "this is the user's first invoice and they're not yet active"
    # via billing_reason='subscription_create' on the invoice. Metadata
    # on the invoice (and on parent.subscription_details.metadata)
    # carries the tier_requested and superadpro_user_id we set at
    # checkout creation, so we have everything needed to call
    # _activate_membership directly.
    billing_reason = invoice.get("billing_reason", "")
    is_subscription_create = (billing_reason == "subscription_create")
    is_user_inactive = (not bool(user.is_active))

    if is_subscription_create and is_user_inactive:
        # Pull tier from metadata. Two locations to check (Stripe wraps it
        # both on the invoice and on the subscription parent).
        metadata = {}
        try:
            parent = invoice.get("parent") or {}
            sub_details = parent.get("subscription_details") or {}
            metadata = sub_details.get("metadata") or {}
        except Exception:
            metadata = {}
        # Fallback: also check line item metadata
        if not metadata:
            try:
                lines = (invoice.get("lines") or {}).get("data") or []
                if lines:
                    metadata = lines[0].get("metadata") or {}
            except Exception:
                pass

        tier_requested = metadata.get("tier_requested", "partner")
        tier_for_activation = "founding" if tier_requested in ("founder", "founding") else "partner"
        # 27 May 2026: read billing cadence from metadata too. Without this
        # an annual Stripe checkout that fell into the self-healing path
        # would be activated as monthly — wrong expiry, wrong commission,
        # member charged for a year but only credited for a month.
        billing_from_metadata = (metadata.get("billing") or "monthly").lower()
        if billing_from_metadata not in ("monthly", "annual", "yearly", "year"):
            billing_from_metadata = "monthly"
        billing_for_activation = "annual" if billing_from_metadata in ("annual", "yearly", "year") else "monthly"
        try:
            # Idempotency key: same scheme as checkout-completed —
            # subscription_id is the shared identifier between both
            # webhook events for this signup.
            idem_key = f"stripe_sub:{subscription_id}" if subscription_id else None
            _activate_membership(
                db=db,
                user=user,
                tier=tier_for_activation,
                source="stripe-invoice-recovery",  # so we can audit later
                subscription_id=subscription_id,
                is_upgrade=False,
                billing=billing_for_activation,
                source_event_id=idem_key,
            )
            logger.warning(
                f"Self-healed Stripe activation via invoice.paid for user {user.id} "
                f"({user.username}) — checkout.session.completed didn't arrive. "
                f"Activated as tier={tier_for_activation} billing={billing_for_activation} "
                f"via subscription {subscription_id}"
            )
            # Re-read user.is_founding_member after activation so the product_kind
            # tag below reflects the new state, not the old free-tier state.
            db.flush()
        except Exception:
            logger.exception(
                f"Self-healing _activate_membership failed for user {user.id} "
                f"on invoice.paid — manual intervention needed"
            )
        # We may also need to mark refund window + payment_method
        user.stripe_refund_eligible_until = _stripe.refund_window_expiry()
        user.payment_method = "stripe"

        # Write the SIGNUP charge row here. Normally checkout.session.completed
        # writes it, but in this self-healing path that event was missed, so
        # this is the only place the signup payment gets recorded. (The shared
        # charge block below now only fires for subscription_cycle renewals,
        # so without this a self-healed signup would record zero revenue.)
        db.flush()
        signup_product = "founder_signup" if user.is_founding_member else "membership_signup"
        _sc_share, _sc_refundable = _stripe.calculate_refundable(signup_product, amount_cents)
        db.add(StripeCharge(
            user_id=user.id,
            stripe_payment_intent_id=payment_intent_id,
            stripe_subscription_id=subscription_id,
            kind="charge",
            product=signup_product,
            amount_cents=amount_cents,
            currency=invoice.get("currency", "usd"),
            company_share_cents=_sc_share,
            refundable_cents=_sc_refundable,
            description=f"Invoice paid (self-healed signup, {billing_reason or 'unknown'})",
            raw_event_json=str(event)[:50000],
        ))

    # ── Charge row (renewal invoices ONLY) ────────────────────────────
    # CRITICAL: the FIRST invoice of a subscription (billing_reason=
    # 'subscription_create') IS the signup payment, which
    # checkout.session.completed already recorded as a membership_signup /
    # founder_signup charge row. invoice.paid must NOT write a second charge
    # row for it, or the same $20 is counted twice and revenue is inflated.
    #
    # PRIOR BUG (found 1 Jun 2026): the product label was chosen from
    # `is_subscription_create and is_user_inactive`. On a normal signup,
    # checkout.session.completed activates the user BEFORE invoice.paid
    # arrives ~2s later, so is_user_inactive was False → the first invoice
    # was mislabelled 'membership_renewal' and written as a duplicate charge.
    # joyhealey (user 627) had a $20 signup (charge 184) + a phantom $20
    # 'renewal' 2s later (charge 185) on the same sub — making real $80
    # display as $100. Commission side was already correctly gated on
    # billing_reason=='subscription_cycle', so no double commission was paid;
    # this was a revenue-counting bug only.
    #
    # FIX: gate the charge row on billing_reason alone. Only write a charge
    # for a TRUE recurring cycle. subscription_create is owned by checkout.
    is_true_renewal_cycle = (billing_reason == "subscription_cycle")
    if is_true_renewal_cycle:
        product_kind = "founder_renewal" if user.is_founding_member else "membership_renewal"
        company_share, refundable = _stripe.calculate_refundable(product_kind, amount_cents)

        charge = StripeCharge(
            user_id=user.id,
            stripe_payment_intent_id=payment_intent_id,
            stripe_subscription_id=subscription_id,
            kind="charge",
            product=product_kind,
            amount_cents=amount_cents,
            currency=invoice.get("currency", "usd"),
            company_share_cents=company_share,
            refundable_cents=refundable,
            description=f"Invoice paid ({billing_reason or 'unknown'})",
            raw_event_json=str(event)[:50000],
        )
        db.add(charge)
    else:
        logger.info(
            f"invoice.paid for user {user.id} billing_reason={billing_reason!r} "
            f"— no renewal charge row written (signup invoice is owned by "
            f"checkout.session.completed; only subscription_cycle writes a charge)."
        )

    # ── Extend membership_expires_at — Stripe is the source of truth ───
    # 26 May 2026 root-cause fix.
    #
    # PRIOR BUG: read invoice.period_end. Per Stripe docs, that field is
    # "End of the usage period during which invoice items were added to
    # this invoice" — i.e. the lookback period for revenue recognition.
    # On a fresh subscription's first invoice (billing_reason=
    # subscription_create) there is NO prior usage period, so
    # invoice.period_end equals the subscription create timestamp. On
    # renewals it equals the end of the period JUST ELAPSED. Either way
    # it is NOT the date the new paid period ends. Writing it to
    # membership_expires_at made every Stripe-rail signup land with an
    # expiry seconds before or equal to activated_at — corrupting 15 of
    # the 16 expired-but-active rows surfaced by member_composition on
    # 26 May.
    #
    # FIX: read line_item.period.end on the subscription line item. This
    # is the END of the service period the invoice paid for — i.e. when
    # the new paid window terminates. For a fresh monthly sub this is
    # subscription_create + 1 month; for a renewal it is the just-paid
    # period's end. Both correct.
    #
    # Fallback chain: line item period → invoice.period_end + interval
    # (last resort, assumes monthly) → leave existing value (don't write
    # a value worse than nothing).
    _expires_source = None
    _expires_value = None
    try:
        _lines = (invoice.get("lines") or {}).get("data") or []
        # The subscription line item carries the service-period dates.
        # On a sub_create invoice there is one line item; on prorated
        # upgrades there can be multiple. Take the LAST line item whose
        # period.end is the furthest in the future — that's the one
        # representing the new paid window.
        _candidate_ends = []
        for _li in _lines:
            _period = _li.get("period") or {}
            _end = _period.get("end")
            if _end:
                _candidate_ends.append(int(_end))
        if _candidate_ends:
            _expires_value = datetime.utcfromtimestamp(max(_candidate_ends))
            _expires_source = "line_item.period.end"
    except Exception as e:
        logger.warning(f"Stripe invoice line-item period read failed for user {user.id}: {e}")

    if _expires_value is None:
        # Defensive fallback: invoice.period_end + monthly interval.
        # On a sub_create invoice period_end == subscription start, so
        # +31 days gives the right answer. On a renewal period_end ==
        # end of just-elapsed period, so +31 days gives the next period
        # end. Only used if line items are unavailable.
        _legacy_pe = invoice.get("period_end")
        if _legacy_pe:
            _expires_value = datetime.utcfromtimestamp(int(_legacy_pe)) + timedelta(days=31)
            _expires_source = "invoice.period_end+31d (fallback)"

    if _expires_value is not None:
        # Invariant guard: refuse to write an expiry earlier than the
        # activation timestamp. Catches any future class of webhook-
        # field-misread bug at the moment it would corrupt state.
        _activated = user.activated_at or datetime.utcnow()
        if _expires_value < _activated:
            logger.error(
                f"Stripe invoice expiry guard tripped for user {user.id} "
                f"({user.username}): would have written expires_at="
                f"{_expires_value.isoformat()} which is BEFORE activated_at="
                f"{_activated.isoformat()}. Source={_expires_source}. "
                f"Skipping write — review the invoice payload."
            )
        else:
            user.membership_expires_at = _expires_value
            logger.info(
                f"Stripe invoice extended membership for user {user.id} "
                f"to {_expires_value.isoformat()} (source={_expires_source})"
            )

    user.stripe_refund_eligible_until = _stripe.refund_window_expiry()

    # ── Recurring-renewal sponsor commission (28 May 2026 — bug fix) ───────
    # PRIOR BUG: this handler extended membership_expires_at on a renewal but
    # never paid the sponsor. Stripe card renewals therefore paid sponsors
    # NOTHING, while the wallet rail (process_auto_renewals) paid correctly —
    # a silent rail divergence. The dead _stripe_renew_membership function
    # existed to do this but was never wired in (and wrote status='pending',
    # invisible to the paid-only earnings model).
    #
    # FIX: route through the shared pay_renewal_commission engine — the same
    # function the wallet cron now calls. Founder → sponsor $10 / company $5;
    # Partner → sponsor $10 / company $10; per renewal, forever (Steve, spec).
    #
    # Gate: only a TRUE recurring cycle (billing_reason='subscription_cycle')
    # on an already-active member. The first invoice (subscription_create) is
    # the signup — _activate_membership already paid that sponsor commission,
    # so we must NOT pay again here. Annual members are excluded: they paid
    # the $100 annual sponsor commission up front and don't renew monthly.
    #
    # Idempotency: period_key 'renewal:{user_id}:{YYYY-MM}' — the same scheme
    # the wallet rail uses, so a Stripe retry OR a cross-rail collision in the
    # same month pays the sponsor exactly once (uniq_commission_event index).
    is_recurring_renewal = (billing_reason == "subscription_cycle")
    is_annual_member = (getattr(user, "membership_billing", "monthly") == "annual")
    if is_recurring_renewal and user.is_active and not is_annual_member:
        try:
            period_key = f"renewal:{user.id}:{datetime.utcnow().strftime('%Y-%m')}"
            paid = pay_renewal_commission(db, user, period_key=period_key, rail="stripe")
            logger.info(
                f"Stripe renewal commission processed for user {user.id} "
                f"({user.username}) — sponsor paid=${paid}, period={period_key}"
            )
        except Exception:
            # Never let a commission failure strand the renewal/expiry write.
            # Log loudly — the integrity cron will surface an unpaid renewal.
            logger.exception(
                f"Stripe renewal commission FAILED for user {user.id} "
                f"({user.username}) — expiry was still extended; needs manual review"
            )

    db.commit()
    logger.info(f"Stripe invoice processed for user {user.id} amount=${amount_cents/100} reason={billing_reason}")


def _stripe_handle_invoice_failed(db, invoice, event):
    """A subscription invoice failed to charge. Stripe will retry (default
    3 attempts over 7 days). We log it; on the final failure (handled by
    subscription_deleted) we mark the membership ended."""
    customer_id = invoice.get("customer")
    if not customer_id:
        return
    user = db.query(User).filter(User.stripe_customer_id == customer_id).first()
    if not user:
        return
    logger.warning(f"Stripe payment failed for user {user.id} — Stripe will retry")
    # TODO: send notification email so member can update their card before
    # the grace period expires. Hook into the existing email infrastructure
    # in a follow-up.


def _stripe_handle_subscription_deleted(db, subscription, event):
    """The subscription is ended — either member cancelled, or Stripe gave
    up after retry exhaustion. Mark membership lapsed."""
    customer_id = subscription.get("customer")
    if not customer_id:
        return
    user = db.query(User).filter(User.stripe_customer_id == customer_id).first()
    if not user:
        return
    user.stripe_subscription_id = None
    # Don't clear payment_method — they may re-subscribe via Stripe later.
    # membership_expires_at stays at its current value; the existing
    # 'has_active_membership' check (membership_expires_at > now) naturally
    # lapses them when that time arrives.
    db.commit()
    logger.info(f"Stripe subscription ended for user {user.id}")


def _stripe_handle_dispute_created(db, dispute, event):
    """A chargeback has been initiated. Per Steve's policy (23 May 2026):
    immediate account suspension. Member loses access to the platform until
    we manually re-enable. The chargeback itself goes through Stripe's
    standard process — we don't fight it here, but we DO lock the account
    so the disputed member can't keep using the service while the dispute
    is in flight."""
    charge_id = dispute.get("charge")
    amount_cents = int(dispute.get("amount", 0))

    # Find the user via the charge
    user = None
    if charge_id:
        existing_charge = db.query(StripeCharge).filter(StripeCharge.stripe_charge_id == charge_id).first()
        if existing_charge:
            user = db.query(User).filter(User.id == existing_charge.user_id).first()
    if not user:
        # Fall back to looking up via customer if charge isn't in our DB yet
        cust_id = dispute.get("customer") or (event.get("data", {}).get("object", {}).get("customer"))
        if cust_id:
            user = db.query(User).filter(User.stripe_customer_id == cust_id).first()
    if not user:
        logger.error(f"Chargeback received but user not found: dispute={dispute.get('id')}")
        return

    # Log the chargeback
    charge = StripeCharge(
        user_id=user.id,
        stripe_charge_id=charge_id,
        kind="chargeback",
        product="chargeback",
        amount_cents=-amount_cents,
        currency=dispute.get("currency", "usd"),
        description=f"Chargeback initiated: {dispute.get('reason', 'unknown')}",
        raw_event_json=str(event)[:50000],
    )
    db.add(charge)

    # Suspend the account. We use membership_expires_at=now() so existing
    # 'has_active_membership' checks immediately return False. If they
    # also have a Stripe subscription, cancel it so future renewals stop.
    user.membership_expires_at = datetime.utcnow()
    if user.stripe_subscription_id:
        try:
            _stripe.cancel_subscription_immediately(user.stripe_subscription_id)
        except Exception:
            logger.exception(f"Failed to cancel Stripe sub during chargeback for user {user.id}")
        user.stripe_subscription_id = None

    db.commit()
    logger.critical(f"CHARGEBACK: user {user.id} ({user.username}) account suspended. amount=${amount_cents/100} reason={dispute.get('reason')}")


def _stripe_handle_charge_refunded(db, charge, event):
    """A refund was processed (either by us via the refund endpoint, or
    manually in Stripe Dashboard). Log it for audit."""
    user = None
    charge_id = charge.get("id")
    if charge_id:
        existing = db.query(StripeCharge).filter(StripeCharge.stripe_charge_id == charge_id).first()
        if existing:
            user = db.query(User).filter(User.id == existing.user_id).first()
    if not user:
        cust_id = charge.get("customer")
        if cust_id:
            user = db.query(User).filter(User.stripe_customer_id == cust_id).first()
    if not user:
        return

    amount_refunded = int(charge.get("amount_refunded", 0))
    refund_row = StripeCharge(
        user_id=user.id,
        stripe_charge_id=charge_id,
        kind="refund",
        product="refund",
        amount_cents=-amount_refunded,
        currency=charge.get("currency", "usd"),
        description=f"Refund processed",
        raw_event_json=str(event)[:50000],
    )
    db.add(refund_row)
    db.commit()


@app.post("/api/stripe/refund-request")
async def stripe_refund_request(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Member-initiated refund request.

    Validates against the 7-day window + the partial-refund cap (only the
    company's share is refundable; commissions already paid out cannot be
    reclaimed).

    Body (JSON):
      reason: free-text reason (stored, sent to support if needed)
      charge_id: optional specific stripe_charge_id to refund. Defaults
                 to the most recent charge.

    Returns:
      { ok, refund_amount_cents, refund_id } on success
      { ok: false, error: <reason> } on failure
    """
    if not _stripe.is_configured():
        return JSONResponse({"error": "stripe_not_configured"}, status_code=503)
    if not user.stripe_refund_eligible_until or user.stripe_refund_eligible_until < datetime.utcnow():
        return JSONResponse({"ok": False, "error": "refund_window_expired"}, status_code=400)

    body = await request.json()
    reason = body.get("reason", "requested_by_customer")
    target_charge_id = body.get("charge_id")

    # Find the charge to refund
    q = db.query(StripeCharge).filter(
        StripeCharge.user_id == user.id,
        StripeCharge.kind == "charge",
        StripeCharge.refundable_cents > 0,
    ).order_by(StripeCharge.created_at.desc())
    if target_charge_id:
        q = q.filter(StripeCharge.stripe_charge_id == target_charge_id)
    charge_row = q.first()
    if not charge_row:
        return JSONResponse({"ok": False, "error": "no_refundable_charge"}, status_code=400)

    # Compute remaining refundable amount (subtract previous refunds for this charge)
    previous_refunds = db.query(StripeCharge).filter(
        StripeCharge.user_id == user.id,
        StripeCharge.stripe_charge_id == charge_row.stripe_charge_id,
        StripeCharge.kind == "refund",
    ).all()
    already_refunded = sum(-r.amount_cents for r in previous_refunds)  # refunds stored negative
    remaining = max(0, charge_row.refundable_cents - already_refunded)
    if remaining <= 0:
        return JSONResponse({"ok": False, "error": "already_fully_refunded"}, status_code=400)

    # Process the refund via Stripe
    target_charge_id_for_stripe = charge_row.stripe_charge_id or charge_row.stripe_payment_intent_id
    if not target_charge_id_for_stripe:
        return JSONResponse({"ok": False, "error": "no_charge_id_on_record"}, status_code=400)
    try:
        result = _stripe.refund_charge(
            charge_id=charge_row.stripe_charge_id,
            amount_cents=remaining,
            reason="requested_by_customer",
        )
        # The refund webhook will fire and log the StripeCharge row.
        # We don't double-log here.
        logger.info(f"Refund issued: user={user.id} amount=${remaining/100} reason='{reason}'")
        return {
            "ok": True,
            "refund_amount_cents": remaining,
            "refund_id": result.get("refund_id"),
            "note": "Refund processed. Card statement will reflect within 5-10 business days.",
        }
    except Exception as e:
        logger.exception(f"Refund failed for user {user.id}")
        return JSONResponse({"ok": False, "error": "refund_failed", "detail": str(e)}, status_code=500)


