@app.get("/api/funnels/load/{page_id}")
def funnel_load_gjs(page_id: int, request: Request, user: User = Depends(get_current_user),
                    db: Session = Depends(get_db)):
    """Load GrapesJS editor data for a page."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    if not is_pro(user):
        return JSONResponse({"error": "SuperPages is a Pro feature. Upgrade to access."}, status_code=403)
    page = db.query(FunnelPage).filter(FunnelPage.id == page_id, FunnelPage.user_id == user.id).first()
    if not page:
        return JSONResponse({"error": "Page not found"}, status_code=404)
    import json

    # ── Campaign wiring (added 20 May 2026) ──
    # Resolve list + sequence names alongside their IDs so the editor's
    # in-page "Campaign wiring" button can show the current binding
    # without an extra round-trip. Previously the editor had no idea
    # which list a published page was bound to — only the Funnels gallery
    # showed that. Surfacing it inside the editor means users can change
    # the list mid-edit (Steve, 20 May 2026: "we should have the include
    # list function inside the editor rather than the modal that pops up
    # first incase we want to change our minds").
    from .database import LeadList, EmailSequence
    list_name = None
    seq_title = None
    seq_num_emails = None
    if page.default_list_id:
        lst = db.query(LeadList).filter(LeadList.id == page.default_list_id).first()
        if lst:
            list_name = lst.name
    if page.capture_sequence_id:
        seq = db.query(EmailSequence).filter(EmailSequence.id == page.capture_sequence_id).first()
        if seq:
            seq_title = seq.title or "Sequence"
            seq_num_emails = int(seq.num_emails or 0)

    return JSONResponse({
        "id": page.id,
        "title": page.title,
        "slug": page.slug,
        "template_type": page.template_type,
        "status": page.status,
        "gjs_components": json.loads(page.gjs_components) if page.gjs_components else [],
        "gjs_styles": json.loads(page.gjs_styles) if page.gjs_styles else [],
        "gjs_html": page.gjs_html or "",
        "gjs_css": page.gjs_css or "",
        "updated_at": page.updated_at.isoformat() if page.updated_at else None,
        # Wiring fields — null when nothing bound (the page captures leads
        # but doesn't route them anywhere yet).
        "default_list_id": page.default_list_id,
        "default_list_name": list_name,
        "capture_sequence_id": page.capture_sequence_id,
        "capture_sequence_title": seq_title,
        "capture_sequence_num_emails": seq_num_emails,
    })


def _apply_campaign_binding(db, user, page, body):
    """Phase 1 (Campaign Hub): apply list + sequence binding to a page.

    Reads three optional fields from the request body and writes the
    appropriate FK on the FunnelPage:
      default_list_id          → bind to existing LeadList by ID
      create_new_list_name     → auto-create a list with this name + bind
      capture_sequence_id      → bind to existing EmailSequence by ID

    Each field is independent and idempotent. Ownership checked — the
    user can only bind to their own lists/sequences. If a list with the
    create_new_list_name already exists for this user, it's reused
    rather than duplicated.

    Used by /api/funnels/save and /api/funnels/from-template so both
    page-create paths share identical binding behaviour.

    Caller is responsible for db.commit() — this only mutates the
    session state.
    """
    from .database import LeadList, EmailSequence

    # ── default_list_id ──
    if "default_list_id" in body:
        new_list_id = body.get("default_list_id")
        if new_list_id:
            try:
                lst = db.query(LeadList).filter(
                    LeadList.id == int(new_list_id),
                    LeadList.user_id == user.id,
                ).first()
                if lst:
                    page.default_list_id = lst.id
            except (TypeError, ValueError):
                pass
        else:
            page.default_list_id = None

    # ── create_new_list_name ──
    if "create_new_list_name" in body:
        new_name = (body.get("create_new_list_name") or "").strip()
        if new_name and len(new_name) <= 100:
            existing = db.query(LeadList).filter(
                LeadList.user_id == user.id,
                LeadList.name == new_name,
            ).first()
            if existing:
                page.default_list_id = existing.id
            else:
                new_list = LeadList(
                    user_id=user.id,
                    name=new_name,
                    description=f"Auto-created for SuperPage '{page.title or 'Untitled'}'",
                    color="#0ea5e9",
                    created_at=datetime.utcnow(),
                )
                db.add(new_list)
                db.flush()
                page.default_list_id = new_list.id

    # ── capture_sequence_id ──
    if "capture_sequence_id" in body:
        new_seq_id = body.get("capture_sequence_id")
        if new_seq_id:
            try:
                seq = db.query(EmailSequence).filter(
                    EmailSequence.id == int(new_seq_id),
                    EmailSequence.user_id == user.id,
                ).first()
                if seq:
                    page.capture_sequence_id = seq.id
            except (TypeError, ValueError):
                pass
        else:
            page.capture_sequence_id = None


@app.post("/api/funnels/save")
async def funnel_save(request: Request, user: User = Depends(get_current_user),
                      db: Session = Depends(get_db)):
    from fastapi.responses import JSONResponse
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    if not is_pro(user):
        return JSONResponse({"error": "SuperPages is a Pro feature. Upgrade to access."}, status_code=403)
    try:
        body = await request.json()
    except Exception:
        return JSONResponse({"error": "Invalid request"}, status_code=400)

    # Payload size guard — reject excessively large pages (5MB limit)
    import json as _json
    if len(_json.dumps(body)) > 5 * 1024 * 1024:
        return JSONResponse({"error": "Page content too large. Try removing some sections."}, status_code=413)

    page_id = body.get("id")
    if page_id:
        page = db.query(FunnelPage).filter(FunnelPage.id == page_id, FunnelPage.user_id == user.id).first()
        if not page:
            return JSONResponse({"error": "Page not found"}, status_code=404)
        # Optimistic locking: reject if page was modified by another tab/session
        client_updated = body.get("updated_at")
        if client_updated and page.updated_at:
            from datetime import datetime
            try:
                client_ts = datetime.fromisoformat(client_updated.replace("Z", "+00:00")).replace(tzinfo=None)
                server_ts = page.updated_at
                if abs((server_ts - client_ts).total_seconds()) > 2:
                    return JSONResponse({
                        "error": "This page was modified in another tab or session. Please reload to get the latest version.",
                        "conflict": True,
                        "server_updated_at": page.updated_at.isoformat()
                    }, status_code=409)
            except (ValueError, TypeError):
                pass  # If timestamp parsing fails, allow the save
    else:
        page = FunnelPage(user_id=user.id)
        db.add(page)

    # Generate slug from title + username. Original logic only ran when
    # page.slug was empty AND it was a new page — but Steve found pages
    # in his gallery with empty slugs (20 May 2026), suggesting some
    # legacy path saved pages without slugs OR the if-not check has
    # been silently skipping over null slugs that should have been
    # regenerated. Belt-and-braces: ensure every saved page has a slug,
    # regenerating only when one is genuinely missing (so we don't
    # break working slugs that members have shared).
    import re
    title = body.get("title", "My Page").strip()
    if not page.slug:
        page.slug = generate_unique_slug(db, user.username, title, exclude_page_id=page.id)

    page.title = title

    # Only update fields that are explicitly included in the payload
    # This prevents the canvas editor (which only sends id/title/gjs_html/gjs_css/status)
    # from wiping fields set by the AI generator or other editors
    if "template_type" in body: page.template_type = body["template_type"]
    if "headline" in body: page.headline = body["headline"]
    if "subheadline" in body: page.subheadline = body["subheadline"]
    if "body_copy" in body: page.body_copy = body["body_copy"]
    if "cta_text" in body: page.cta_text = body["cta_text"]
    if "cta_url" in body: page.cta_url = body["cta_url"]
    if "video_url" in body: page.video_url = body["video_url"]
    if "image_url" in body: page.image_url = body["image_url"]
    if "color_scheme" in body: page.color_scheme = body["color_scheme"]
    if "accent_color" in body: page.accent_color = body["accent_color"]
    if "custom_bg" in body: page.custom_bg = body["custom_bg"]
    if "status" in body: page.status = body["status"]
    if "funnel_name" in body: page.funnel_name = body["funnel_name"]
    if "font_family" in body: page.font_family = body["font_family"]
    if "meta_description" in body: page.meta_description = body["meta_description"]

    # Custom slug — allow user to rename their page URL
    custom_slug = body.get("custom_slug", "").strip().lower()
    if custom_slug:
        import re
        custom_slug = re.sub(r'[^a-z0-9-]', '-', custom_slug).strip('-')
        custom_slug = re.sub(r'-+', '-', custom_slug)[:80]
        if custom_slug:
            new_slug = f"{user.username}/{custom_slug}"
            if new_slug != page.slug:
                existing = db.query(FunnelPage).filter(FunnelPage.slug == new_slug, FunnelPage.id != page.id).first()
                if existing:
                    return JSONResponse({"error": f"The URL '{custom_slug}' is already taken. Choose a different name."}, status_code=409)
                page.slug = new_slug

    # Section-based content
    import json
    sections = body.get("sections")
    if sections is not None:
        page.sections_json = json.dumps(sections)

    # GrapesJS visual editor data
    gjs_components = body.get("gjs_components")
    if gjs_components is not None:
        page.gjs_components = json.dumps(gjs_components) if isinstance(gjs_components, (list, dict)) else gjs_components
    gjs_styles = body.get("gjs_styles")
    if gjs_styles is not None:
        page.gjs_styles = json.dumps(gjs_styles) if isinstance(gjs_styles, (list, dict)) else gjs_styles
    gjs_html = body.get("gjs_html")
    if gjs_html is not None:
        # Strip script tags, inline event handlers, and javascript: URLs to
        # prevent XSS. The React editor's exportHTML adds onsubmit="return true"
        # to forms, which gets stripped here — that's fine, the published
        # template (funnel-render.html) re-wires forms with its own submit
        # handler. Members generally don't write raw HTML, but template
        # imports / embed blocks could carry hostile markup.
        #
        # 14 May 2026: tightened the regex set to catch handlers the prior
        # version missed: unquoted handlers (onclick=alert(1)) and handlers
        # with mismatched quotes inside attribute values.
        import re
        gjs_html = re.sub(r'<script\b[^>]*>[\s\S]*?</script>', '', gjs_html, flags=re.IGNORECASE)
        # Inline handlers: on* = "..." | '...' | unquoted-until-space-or->
        gjs_html = re.sub(r'\bon[a-z]+\s*=\s*"[^"]*"', '', gjs_html, flags=re.IGNORECASE)
        gjs_html = re.sub(r"\bon[a-z]+\s*=\s*'[^']*'", '', gjs_html, flags=re.IGNORECASE)
        gjs_html = re.sub(r'\bon[a-z]+\s*=\s*[^\s>]+', '', gjs_html, flags=re.IGNORECASE)
        # javascript: URLs inside href/src
        gjs_html = re.sub(r'((?:href|src)\s*=\s*["\']?)\s*javascript:[^"\'\s>]*', r'\1#', gjs_html, flags=re.IGNORECASE)
        page.gjs_html = gjs_html
    gjs_css = body.get("gjs_css")
    if gjs_css is not None:
        # gjs_css from the React editor is a JSON blob like:
        # '{"els":[...],"canvasBg":"#ffffff","canvasBgImage":"..."}'
        # We keep storing it so the editor can rehydrate on reload, but we
        # ALSO extract canvasBg/canvasBgImage and write them to the proper
        # color_scheme + custom_bg columns so the published page renderer
        # (templates/funnel-render.html) shows the right background.
        #
        # Bug history: prior to 14 May 2026 the published template emitted
        # this entire JSON blob inside a <style> tag, which (1) ignored the
        # member's chosen background entirely and (2) was an XSS vector if
        # a member typed </style><script> in any text field. The published
        # page would render on the legacy color_scheme default ('dark' = deep
        # blue), so members designing on a white canvas saw their content
        # publish onto a dark background with light text becoming invisible.
        page.gjs_css = gjs_css
        try:
            import json as _gjson
            css_data = _gjson.loads(gjs_css) if isinstance(gjs_css, str) else gjs_css
            if isinstance(css_data, dict):
                canvas_bg = css_data.get("canvasBg")
                canvas_bg_image = css_data.get("canvasBgImage")
                # Only update color_scheme/custom_bg if the editor actually
                # provided a canvasBg — older saves with no canvasBg shouldn't
                # have their existing color_scheme wiped.
                if canvas_bg:
                    page.color_scheme = "custom"
                    page.custom_bg = canvas_bg
                if canvas_bg_image:
                    # Store the bg image in og_image_url fallback if no other
                    # field — actually no, we don't have a bg image column.
                    # We'll surface this via the template reading gjs_css JSON
                    # too. Leave it parked for now; the template fix below
                    # handles it.
                    pass
        except (ValueError, TypeError):
            # Non-JSON gjs_css (legacy GrapesJS used to put real CSS here) —
            # leave it alone, the template-side fix will handle both shapes.
            pass

    # ── Phase 1 (Campaign Hub): campaign binding ──
    # Accepts default_list_id, create_new_list_name, capture_sequence_id.
    # Shared with /api/funnels/from-template via _apply_campaign_binding.
    _apply_campaign_binding(db, user, page, body)

    db.commit()
    db.refresh(page)

    return JSONResponse({
        "success": True,
        "id": page.id,
        "slug": page.slug,
        "status": page.status,
        "preview_url": f"/p/{page.slug}",
        "updated_at": page.updated_at.isoformat() if page.updated_at else None,
    })
@app.post("/admin/api/funnels/migrate-canvas-bg")
def admin_migrate_canvas_bg(request: Request, user: User = Depends(get_current_user),
                            db: Session = Depends(get_db)):
    """One-shot migration: repair pages where canvasBg lived inside gjs_css JSON.

    Walks every FunnelPage with a JSON-shaped gjs_css, parses it, and writes
    canvasBg → color_scheme='custom' + custom_bg, so the published renderer
    honours the member's chosen background instead of falling back to the
    legacy 'dark' default.

    Idempotent. Skips pages where color_scheme is already 'custom' AND
    custom_bg matches what we'd write — so it's safe to re-run.

    Admin only. Returns counts so we can verify after the run.
    """
    if not user or not getattr(user, "is_admin", False):
        return JSONResponse({"error": "Admin only"}, status_code=403)

    import json as _mig_json
    pages = db.query(FunnelPage).filter(FunnelPage.gjs_css.isnot(None)).all()
    repaired = 0
    skipped_already_fixed = 0
    skipped_no_canvas_bg = 0
    skipped_non_json = 0
    errors = []

    for p in pages:
        raw = (p.gjs_css or "").strip()
        if not raw or not raw.startswith("{"):
            skipped_non_json += 1
            continue
        try:
            data = _mig_json.loads(raw)
        except (ValueError, TypeError):
            errors.append({"page_id": p.id, "slug": p.slug, "error": "invalid JSON"})
            continue
        if not isinstance(data, dict):
            skipped_non_json += 1
            continue
        canvas_bg = data.get("canvasBg")
        if not canvas_bg:
            skipped_no_canvas_bg += 1
            continue
        # Idempotency check: skip if already set correctly
        if p.color_scheme == "custom" and p.custom_bg == canvas_bg:
            skipped_already_fixed += 1
            continue
        p.color_scheme = "custom"
        p.custom_bg = canvas_bg
        repaired += 1

    db.commit()
    return JSONResponse({
        "ok": True,
        "total_pages_scanned": len(pages),
        "repaired": repaired,
        "skipped_already_fixed": skipped_already_fixed,
        "skipped_no_canvas_bg": skipped_no_canvas_bg,
        "skipped_non_json": skipped_non_json,
        "errors": errors,
    })


@app.post("/api/funnels/upload-image")
async def funnel_upload_image(file: UploadFile = File(...), user: User = Depends(get_current_user),
                               db: Session = Depends(get_db)):
    """Upload an image for use in funnel pages. Returns the public URL."""
    from fastapi.responses import JSONResponse
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    if not is_pro(user):
        return JSONResponse({"error": "SuperPages is a Pro feature. Upgrade to access."}, status_code=403)

    # Validate file type
    allowed_types = {"image/jpeg", "image/png", "image/gif", "image/webp", "image/svg+xml"}
    if file.content_type not in allowed_types:
        return JSONResponse({"error": "Only JPEG, PNG, GIF, WebP and SVG images are allowed."}, status_code=400)

    # Read and check size (max 5MB)
    contents = await file.read()
    if len(contents) > 5 * 1024 * 1024:
        return JSONResponse({"error": "Image too large. Maximum size is 5MB."}, status_code=400)

    import uuid, os
    ext = os.path.splitext(file.filename or "image.jpg")[1].lower().lstrip(".")
    if ext not in {"jpg", "jpeg", "png", "gif", "webp", "svg"}:
        ext = "jpg"

    # Auto-optimise: resize >1920px wide, convert to WebP (25-35% smaller),
    # strip EXIF metadata. Best-effort — pass-through on any failure so
    # uploads never break. SVG/GIF skipped (vector / animated). Audit C-M-1.
    from app.image_optimise import optimise_image
    contents, ext, content_type_after = optimise_image(contents, ext)
    file_content_type = content_type_after

    # Try R2 first, fall back to local storage
    from app.r2_storage import r2_available, upload_image
    if r2_available():
        url = upload_image(contents, "funnel-images", ext, file_content_type)
    else:
        upload_dir = os.path.join(os.path.dirname(os.path.dirname(__file__)), "static", "uploads")
        os.makedirs(upload_dir, exist_ok=True)
        filename = f"{user.id}_{uuid.uuid4().hex[:12]}.{ext}"
        filepath = os.path.join(upload_dir, filename)
        with open(filepath, "wb") as f:
            f.write(contents)
        url = f"/static/uploads/{filename}"

    return JSONResponse({"success": True, "url": url})
