@app.post("/api/funnels/generate-copy")
async def funnel_generate_copy(request: Request, user: User = Depends(get_current_user),
                                db: Session = Depends(get_db)):
    """AI generates landing page copy based on member's brief."""
    from fastapi.responses import JSONResponse
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    rl = check_and_increment_ai_quota(db, user.id, "campaign_studio")
    if not rl["allowed"]:
        return JSONResponse({"error": f"Daily AI limit reached. Resets in {rl['resets_in']}."}, status_code=429)

    try:
        body = await request.json()
    except Exception:
        return JSONResponse({"error": "Invalid request"}, status_code=400)

    template_type = body.get("template_type", "opportunity")
    niche = body.get("niche", "online income")
    offer = body.get("offer", "")
    audience = body.get("audience", "")
    tone = body.get("tone", "professional and exciting")

    type_prompts = {
        "opportunity": "an opportunity/income presentation landing page. The visitor should feel excited about a real opportunity and want to learn more. Include social proof elements and urgency.",
        "optin": "a lead capture / opt-in page. The visitor should want to enter their email to receive something valuable. Focus on the free value proposition and what they'll learn.",
        "bridge": "a bridge page. This is a personal story/recommendation page that builds trust before sending the visitor to the main offer. Write in first person, be authentic and relatable.",
        "webinar": "a webinar/event registration page. Create urgency around a live event, highlight what they'll learn, and emphasise limited spots or time-sensitivity.",
        "thankyou": "a thank you / confirmation page. Confirm their action, build excitement for what's coming next, and include a secondary CTA or next step.",
    }

    page_context = type_prompts.get(template_type, type_prompts["opportunity"])

    prompt = f"""You are an expert direct-response copywriter specialising in affiliate marketing and network marketing landing pages.

Create compelling copy for {page_context}

BRIEF:
- Niche: {niche}
- Offer: {offer if offer else "an online income opportunity"}
- Target audience: {audience if audience else "people looking to earn extra income online"}
- Tone: {tone}

Respond ONLY with a JSON object (no markdown, no backticks) containing:
{{
  "headline": "A powerful, attention-grabbing headline (max 12 words)",
  "subheadline": "A supporting line that builds on the headline (max 25 words)",
  "body_copy": "3-5 bullet points separated by newlines, each starting with ✓. Focus on benefits and outcomes, not features.",
  "cta_text": "Action-oriented button text (3-5 words)"
}}

Make every word count. Use power words. Create genuine curiosity and desire. Avoid hype — be compelling but believable."""

    try:
        import json
        from .grok_service import ai_text_generate
        text = (await ai_text_generate(prompt=prompt, max_tokens=800, temperature=0.7)).strip()
        # Strip markdown fences if present
        if text.startswith("```"):
            text = text.split("\n", 1)[1] if "\n" in text else text[3:]
        if text.endswith("```"):
            text = text[:-3]
        data = json.loads(text)
        return JSONResponse(data)
    except Exception as e:
        logger.error(f"Funnel AI copy error: {e}")
        return JSONResponse({
            "headline": f"Your {niche.title()} Success Starts Here",
            "subheadline": "The proven system for building real income online",
            "body_copy": "✓ Step-by-step training included\n✓ No experience required\n✓ Proven results from real people\n✓ Full support and community\n✓ Start today risk-free",
            "cta_text": "Get Started Now",
        })
@app.post("/api/funnels/from-template")
async def funnel_from_template(request: Request, user: User = Depends(get_current_user),
                                db: Session = Depends(get_db)):
    """Create a funnel page from a pre-built niche template."""
    if not user: return {"error": "Not logged in"}
    if not is_pro(user):
        return JSONResponse({"error": "SuperPages is a Pro feature. Upgrade to access."}, status_code=403)
    body = await request.json()
    niche = body.get("niche", "affiliate-marketing")
    import json, random, string, re as _re

    # ── NEW: SuperPages template builder (React editor format) ──
    from app.template_builder import build_template, BUILDERS
    if niche in BUILDERS:
        tpl_data = build_template(niche, getattr(user, 'username', 'demo'))
        TEMPLATE_TITLES = {
            'lead-capture': 'Lead Capture Page',
            'video-sales': 'Video Sales Letter',
            'product-offer': 'Product Offer Page',
            'network-opportunity': 'Business Opportunity',
            'webinar-registration': 'Webinar Registration',
            'coaching-program': 'Coaching Program',
            'digital-product': 'Digital Product Page',
            'affiliate-income': 'Affiliate Funnel',
            'thank-you': 'Thank You Page',
        }
        title = TEMPLATE_TITLES.get(niche, 'New Page')
        page = FunnelPage(
            user_id=user.id,
            title=title,
            headline=title,
            template_type="landing",
            status="draft",
            gjs_css=json.dumps(tpl_data),
        )
        db.add(page)
        db.flush()
        page.slug = generate_unique_slug(db, user.username, title)

        # ── Phase 1: apply campaign binding from the modal payload ──
        # Same three fields as /api/funnels/save: default_list_id (use
        # existing), create_new_list_name (auto-create), capture_sequence_id
        # (use existing). The modal sends one or none per field.
        _apply_campaign_binding(db, user, page, body)

        db.commit()
        return {"success": True, "id": page.id, "edit_url": f"/pro/funnel/{page.id}/edit"}

    # If we get here the niche key didn't match BUILDERS. Old niche keys
    # (forex/crypto/affiliate-marketing/etc.) were removed 26 May 2026 along
    # with their dead NICHE_TEMPLATES/STATS/STEPS fallback block — the
    # frontend only sends BUILDERS keys (lead-capture, video-sales, etc.),
    # so this branch is defensive only.
    return JSONResponse(
        {"error": "unknown_template", "detail": f"Template '{niche}' not recognised. Available templates: {sorted(BUILDERS.keys())}"},
        status_code=400,
    )
@app.post("/api/funnels/delete/{page_id}")
def funnel_delete(page_id: int, user: User = Depends(get_current_user),
                  db: Session = Depends(get_db)):
    from fastapi.responses import JSONResponse
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    if not is_pro(user):
        return JSONResponse({"error": "SuperPages is a Pro feature. Upgrade to access."}, status_code=403)
    page = db.query(FunnelPage).filter(FunnelPage.id == page_id, FunnelPage.user_id == user.id).first()
    if not page:
        return JSONResponse({"error": "Page not found"}, status_code=404)
    try:
        from sqlalchemy import text
        # Clear any next_page_id references pointing to this page
        db.query(FunnelPage).filter(FunnelPage.next_page_id == page_id).update({"next_page_id": None})
        # Null out source_funnel_id on CRM leads captured via this page —
        # we keep the leads, just detach them from the deleted page.
        db.execute(text("UPDATE member_leads SET source_funnel_id = NULL WHERE source_funnel_id = :pid"), {"pid": page_id})
        # Delete related funnel analytics leads (separate table — ephemeral data)
        db.execute(text("DELETE FROM funnel_leads WHERE page_id = :pid"), {"pid": page_id})
        # Delete related analytics events
        db.execute(text("DELETE FROM funnel_events WHERE page_id = :pid"), {"pid": page_id})
        # Delete A/B variant if exists
        db.query(FunnelPage).filter(FunnelPage.ab_variant_of == page_id).delete()
        # Now delete the page
        db.delete(page)
        db.commit()
        return JSONResponse({"success": True})
    except Exception as e:
        db.rollback()
        logger.error(f"Funnel delete error for page_id={page_id}: {e}")
        return JSONResponse({"error": "Delete failed. Please try again or contact support."}, status_code=500)
# ── Phase 2: Lead Capture API ──────────────────────────────
@app.post("/api/leads/capture")
async def capture_lead(request: Request, db: Session = Depends(get_db)):
    from fastapi.responses import JSONResponse
    try:
        body = await request.json()
    except Exception:
        return JSONResponse({"error": "Invalid request"}, status_code=400)
    page_id = body.get("page_id")
    email = body.get("email", "").strip().lower()
    if not page_id or not email:
        return JSONResponse({"error": "page_id and email required"}, status_code=400)
    # Basic email format validation — prevents junk leads, bounce-prone Brevo sends,
    # and inflated leads_captured counts from bot/form-spam.
    import re as _re_email
    if len(email) > 254 or not _re_email.match(r"^[^@\s]+@[^@\s]+\.[^@\s]+$", email):
        return JSONResponse({"error": "Please enter a valid email address"}, status_code=400)
    page = db.query(FunnelPage).filter(FunnelPage.id == page_id).first()
    if not page:
        return JSONResponse({"error": "Page not found"}, status_code=404)
    referrer = request.headers.get("referer", "")
    source = "direct"
    for s in ["facebook", "instagram", "twitter", "youtube", "google", "tiktok", "linkedin"]:
        if s in referrer.lower():
            source = s
            break
    ua = request.headers.get("user-agent", "").lower()
    device = "mobile" if any(d in ua for d in ["mobile", "android", "iphone"]) else "desktop"
    lead = FunnelLead(page_id=page.id, user_id=page.user_id, name=body.get("name", "").strip(),
        email=email, phone=body.get("phone", "").strip(), source=source,
        ip_address=request.client.host if request.client else None)
    db.add(lead)
    event = FunnelEvent(page_id=page.id, user_id=page.user_id, event_type="optin",
        referrer=referrer, device=device, ip_address=request.client.host if request.client else None)
    db.add(event)

    # ── Increment the denormalised leads_captured counter ──
    # Some legacy UI surfaces read page.leads_captured directly rather
    # than computing from MemberLead rows. Keep this in sync on every
    # capture so those surfaces show the right number. The live
    # /api/funnels endpoint uses MemberLead aggregates regardless, so
    # this is belt-and-braces. Missing increment was a latent bug
    # (existed before today's work but never surfaced because nobody
    # checked legacy lead counts vs live counts). Added 18 May 2026.
    page.leads_captured = (page.leads_captured or 0) + 1

    # ── Commit the core lead data FIRST ──
    # Two-phase commit: get the FunnelLead + FunnelEvent saved before
    # attempting the CRM / autoresponder side-effects. Previously the
    # CRM sync ran in the same transaction, so any inner SQL error
    # (e.g. missing column on a pre-existing table with SKIP_MIGRATIONS=
    # true) poisoned the transaction and rolled back the lead itself.
    # The user saw 'Submitting...' freeze. Fixed 18 May 2026.
    try:
        db.commit()
    except Exception as e:
        db.rollback()
        logger.error(f"Lead capture commit failed for page {page.id}: {e}")
        return JSONResponse(
            {"error": "Failed to save your details. Please try again."},
            status_code=500,
        )

    # ── Auto-add to CRM (MemberLead) for autoresponder ──
    # Wrapped in its own transaction so CRM failures don't lose the
    # lead. Any error inside this block rolls back the CRM-only work
    # and we still return success to the user.
    try:
        existing_crm = db.query(MemberLead).filter(
            MemberLead.user_id == page.user_id, MemberLead.email == email.lower()
        ).first()
        if not existing_crm:
            # Phase 1 (Campaign Hub): set list_id from the page's binding.
            # page.default_list_id is set when the user creates the page
            # via the campaign-setup modal (or by the Phase 1 backfill for
            # pre-existing pages). NULL is fine — the lead just lands
            # unbound and the user can move it via SuperLeads.
            crm_lead = MemberLead(
                user_id=page.user_id, email=email.lower(),
                name=body.get("name", "").strip(),
                source_funnel_id=page.id,
                source_url=f"/p/{page.slug}" if page.slug else "SuperPage",
                status="new",
                list_id=page.default_list_id,
            )
            db.add(crm_lead)

            # ── Sequence assignment ──
            # Page-level binding wins. If page.capture_sequence_id is set
            # (chosen by the user in the campaign-setup modal at create
            # time), use that. Otherwise fall back to the legacy
            # "most-recent active sequence" heuristic for backward compat
            # with pages built before Phase 1. Going forward, every new
            # page will have capture_sequence_id explicitly set or
            # explicitly None (= "no sequence").
            from .database import EmailSequence
            default_seq = None
            if page.capture_sequence_id:
                default_seq = db.query(EmailSequence).filter(
                    EmailSequence.id == page.capture_sequence_id,
                    EmailSequence.user_id == page.user_id,
                    EmailSequence.is_active == True,
                ).first()
            if not default_seq:
                default_seq = db.query(EmailSequence).filter(
                    EmailSequence.user_id == page.user_id, EmailSequence.is_active == True
                ).order_by(EmailSequence.created_at.desc()).first()
            if default_seq:
                crm_lead.email_sequence_id = default_seq.id
                crm_lead.status = "nurturing"

            # Send first email in sequence if Brevo is configured
            if default_seq:
                try:
                    import json as _j_auto
                    emails_list = _j_auto.loads(default_seq.emails_json or "[]")
                    if emails_list:
                        from .brevo_service import send_email as brevo_send, wrap_email_html
                        first_email = emails_list[0]
                        owner = db.query(User).filter(User.id == page.user_id).first()
                        member_name = (owner.first_name or owner.username) if owner else "SuperAdPro"
                        wrapped = wrap_email_html(first_email.get("body_html", ""), member_name)
                        # Capture Brevo's messageId from the send response so the
                        # /webhook/brevo handler can match incoming open/click
                        # events back to this EmailSendLog row. Without this,
                        # autoresponder-driven opens/clicks silently undercount
                        # because the webhook lookup by brevo_message_id finds
                        # nothing and no-ops. Fixed 18 May 2026.
                        send_result = await brevo_send(
                            email, body.get("name", ""),
                            first_email.get("subject", "Welcome!"), wrapped,
                        )
                        brevo_msg_id = (send_result or {}).get("message_id", "") if isinstance(send_result, dict) else ""
                        crm_lead.emails_sent = 1
                        from .database import EmailSendLog
                        log = EmailSendLog(
                            lead_id=crm_lead.id,
                            sequence_id=default_seq.id,
                            email_index=0,
                            brevo_message_id=brevo_msg_id or None,
                            status="sent",
                        )
                        db.add(log)
                except Exception as e:
                    # Email-send-specific failure (Brevo API, missing
                    # column on email_send_log etc.). Don't rollback —
                    # we still want the MemberLead saved.
                    db.rollback()
                    logger.warning(f"[AutoResponder] First email send error: {e}")
                    # Re-add the CRM lead without the email_sent counter
                    # since rollback wiped it. The lead matters more
                    # than the immediate send — cron will retry.
                    # Phase 1: preserve list_id binding on the recovered
                    # lead too — otherwise a Brevo glitch silently breaks
                    # the page's campaign wiring for that lead.
                    try:
                        db.add(MemberLead(
                            user_id=page.user_id, email=email.lower(),
                            name=body.get("name", "").strip(),
                            source_funnel_id=page.id,
                            source_url=f"/p/{page.slug}" if page.slug else "SuperPage",
                            status="nurturing" if default_seq else "new",
                            email_sequence_id=default_seq.id if default_seq else None,
                            list_id=page.default_list_id,
                        ))
                        db.commit()
                    except Exception as e2:
                        db.rollback()
                        logger.warning(f"[CRM] Lead re-save after email error failed: {e2}")
        # Commit CRM side-effects (only reached if no email error)
        try:
            db.commit()
            # ── Phase 1: bump lead_count on the bound list ──
            # Stored counter on LeadList. Used by the lists UI as a
            # fast display. We refresh from a COUNT(*) query rather
            # than +1 to stay accurate even if multiple captures
            # raced or if the recovery path also fired. Cheap query,
            # bounded by user's lead count on this one list.
            if page.default_list_id:
                from .database import LeadList
                from sqlalchemy import func as _func_lc
                lst = db.query(LeadList).filter(
                    LeadList.id == page.default_list_id
                ).first()
                if lst:
                    new_count = db.query(_func_lc.count(MemberLead.id)).filter(
                        MemberLead.list_id == page.default_list_id
                    ).scalar() or 0
                    lst.lead_count = int(new_count)
                    db.commit()
        except Exception as e:
            db.rollback()
            logger.warning(f"[CRM] Lead sync commit failed: {e}")
    except Exception as e:
        # Outer CRM block — most likely missing column on member_leads
        # (attribution_*) when SKIP_MIGRATIONS=true. Rollback the
        # poisoned session so we can still respond cleanly.
        db.rollback()
        logger.warning(f"[CRM] Lead sync error (rolled back): {e}")

    redirect_url = None
    if page.next_page_id:
        next_pg = db.query(FunnelPage).filter(FunnelPage.id == page.next_page_id).first()
        if next_pg:
            redirect_url = f"/p/{next_pg.slug}"
    return JSONResponse({"success": True, "redirect": redirect_url})


# ────────────────────────────────────────────────────────────────────────
# Share Code system (commit 1: schema + generate)
# ────────────────────────────────────────────────────────────────────────
# Lets a member generate a portable SAP-XXXX-XXXX code that snapshots
# the visual/content fields of one of their FunnelPages. The code's
# payload contains everything needed to recreate the page in another
# member's drafts on import — but deliberately excludes ownership,
# stats, slug, and binding (default_list_id, capture_sequence_id).
# The importer wires their own list/sequence via the Phase 1 modal.
#
# Spec locked 18 May 2026:
#   - Page-only (no list, no sequence carried)
#   - No attribution shown anywhere
#   - Auto-rewrite of /r/{username} and ?ref={username} happens at
#     IMPORT time, not snapshot time — keeps the payload neutral and
#     lets us improve the rewriter without re-issuing codes.
#   - Asset URLs left as-is in payload; copy-on-import handled by
#     the import endpoint (commit 2).
# ────────────────────────────────────────────────────────────────────────

# Fields on FunnelPage we DO carry across in a v1 snapshot. Anything
# not in this set is deliberately excluded — ownership, slug, stats,
# bindings, A/B variant pointers, attribution metadata. Adding a new
# visual/content field to FunnelPage means adding it here too.
SHARE_CODE_V1_FIELDS = (
    "title",
    "template_type",
    "headline",
    "subheadline",
    "body_copy",
    "cta_text",
    "cta_url",
    "video_url",
    "image_url",
    "sections_json",
    "color_scheme",
    "accent_color",
    "custom_bg",
    "font_family",
    "custom_css",
    "gjs_components",
    "gjs_styles",
    "gjs_html",
    "gjs_css",
    "meta_description",
    "og_image_url",
    "has_capture_form",
    "capture_form_heading",
    "capture_form_subtext",
)


def _build_share_payload(page: FunnelPage) -> dict:
    """Return the v1 snapshot dict for a FunnelPage.

    Versioned via top-level "v" key so importers stay forward-compatible
    when SHARE_CODE_V1_FIELDS grows. Unknown fields are ignored on
    import; missing fields fall back to FunnelPage defaults.
    """
    snapshot = {field: getattr(page, field, None) for field in SHARE_CODE_V1_FIELDS}
    return {"v": 1, "page": snapshot}


def _generate_unique_share_code(db: Session) -> str:
    """Generate a SAP-XXXX-XXXX code that doesn't collide with an existing one.

    Uses an unambiguous alphabet (no 0/O/1/I) so codes are safe to read
    aloud and type. 8 chars across two groups → 32^8 ≈ 1.1 trillion
    keyspace; collisions effectively impossible at our scale, but we
    still check.
    """
    import secrets
    alphabet = "ABCDEFGHJKLMNPQRSTUVWXYZ23456789"  # no 0/O/1/I
    for _ in range(8):
        a = "".join(secrets.choice(alphabet) for _ in range(4))
        b = "".join(secrets.choice(alphabet) for _ in range(4))
        code = f"SAP-{a}-{b}"
        if not db.query(ShareCode).filter(ShareCode.code == code).first():
            return code
    # Astronomically unlikely; raise rather than loop forever.
    raise RuntimeError("Could not generate unique share code after 8 attempts")


@app.post("/api/share-codes/generate")
async def share_code_generate(request: Request, user: User = Depends(get_current_user),
                              db: Session = Depends(get_db)):
    """Generate a SAP-XXXX-XXXX share code for one of the user's pages.

    Body: {"page_id": <int>}
    Returns: {"code": "SAP-XXXX-XXXX", "created_at": "..."}
    """
    from fastapi.responses import JSONResponse
    import json as _json
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    if not is_pro(user):
        return JSONResponse({"error": "Sharing pages is a Pro feature."}, status_code=403)
    try:
        body = await request.json()
    except Exception:
        return JSONResponse({"error": "Invalid request"}, status_code=400)

    page_id = body.get("page_id")
    if not page_id:
        return JSONResponse({"error": "page_id required"}, status_code=400)

    page = db.query(FunnelPage).filter(
        FunnelPage.id == page_id,
        FunnelPage.user_id == user.id,
    ).first()
    if not page:
        return JSONResponse({"error": "Page not found"}, status_code=404)

    payload = _build_share_payload(page)
    code = _generate_unique_share_code(db)

    share = ShareCode(
        code=code,
        owner_user_id=user.id,
        source_page_id=page.id,
        payload_json=_json.dumps(payload),
        is_public=False,
        uses_count=0,
    )
    db.add(share)
    db.commit()
    db.refresh(share)

    return JSONResponse({
        "code": share.code,
        "created_at": share.created_at.isoformat() if share.created_at else None,
    })


@app.get("/api/share-codes/my")
def share_code_list_mine(user: User = Depends(get_current_user),
                         db: Session = Depends(get_db)):
    """List share codes the current user has generated.

    Returns the 50 most recent. Used by the Funnels dashboard to show
    a user which of their pages they've already shared.
    """
    from fastapi.responses import JSONResponse
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    rows = (db.query(ShareCode)
              .filter(ShareCode.owner_user_id == user.id)
              .order_by(ShareCode.created_at.desc())
              .limit(50)
              .all())
    return JSONResponse({"codes": [{
        "code": r.code,
        "source_page_id": r.source_page_id,
        "uses_count": r.uses_count,
        "is_public": r.is_public,
        "created_at": r.created_at.isoformat() if r.created_at else None,
    } for r in rows]})


# ── Share Code commit 2: import + ref-link rewriting ──
# When a user pastes a SAP-XXXX-XXXX code, we look it up, rebuild a
# fresh draft FunnelPage owned by them, run the rewriter to swap any
# /r/{username} and ?ref={username} occurrences to their own ref, and
# flag anything we couldn't safely rewrite so they can review.
#
# Asset handling decision (deliberately deferred): we leave external
# image/video URLs as-is in v1. Our R2 buckets are public and stable
# so the imported page just keeps referencing the original asset. If
# this causes problems (asset deletion, abuse, hotlinking concerns)
# we add a copy-on-import pass in a future commit. Network marketers
# typically replace shared imagery with their own brand anyway, so
# the link-back to the original is short-lived in practice.

import re as _re

# Patterns the rewriter recognises. Anything that doesn't match these
# is left alone but flagged in the import receipt as "review this
# link — we couldn't safely rewrite it."
#   /r/USERNAME            — referral landing path
#   ?ref=USERNAME          — query-string ref
#   &ref=USERNAME          — query-string ref (not first param)
# Usernames are alphanumeric + underscore on SuperAdPro (see User
# model). We rewrite case-insensitively but preserve the original
# casing semantics by always emitting lowercase (which is what the
# router expects).
_REF_PATH_RE  = _re.compile(r"/r/([A-Za-z0-9_]+)")
_REF_QUERY_RE = _re.compile(r"([?&])ref=([A-Za-z0-9_]+)", _re.IGNORECASE)


def _rewrite_referral_links(text_blob: str, new_username: str):
    """Rewrite referral occurrences in arbitrary text/HTML/JSON.

    Returns (rewritten_text, rewrite_count). We don't try to be smart
    about whose ref it was — every match becomes new_username. That's
    correct: if the original author's ref leaked into a CTA, the
    importer wants their own ref there, full stop.
    """
    if not text_blob or not new_username:
        return text_blob, 0
    count = 0

    def _sub_path(m):
        nonlocal count
        count += 1
        return f"/r/{new_username}"

    def _sub_query(m):
        nonlocal count
        count += 1
        return f"{m.group(1)}ref={new_username}"

    rewritten = _REF_PATH_RE.sub(_sub_path, text_blob)
    rewritten = _REF_QUERY_RE.sub(_sub_query, rewritten)
    return rewritten, count


# Fields on the v1 snapshot that may contain referral links and so
# get passed through the rewriter. Anything else (template_type,
# color_scheme, etc.) is structural and never holds URLs.
_REWRITE_TARGET_FIELDS = (
    "headline", "subheadline", "body_copy",
    "cta_url", "video_url", "image_url",
    "sections_json", "gjs_components", "gjs_html", "custom_css",
    "meta_description", "og_image_url",
    "capture_form_heading", "capture_form_subtext",
)


# ── Share-code XSS hardening (audit XSS-1, 24 May 2026) ───────────────
#
# Background: share codes are essentially "this member's page, copy/pasted
# to another member's account as a fresh draft". The receiving member
# trusts the sender — but visitors to the imported, republished page
# trust NEITHER party. A malicious sharer could craft an element with
# <img src=x onerror="..."> inside el.txt, generate a share code, and
# weaponise any importer's page against THEIR visitors.
#
# The funnel-render template renders `{{ page.gjs_html|safe }}`, and the
# editor Canvas renders most types via dangerouslySetInnerHTML on el.txt —
# both bypass framework-level escaping by design (members legitimately
# embed HTML in their own pages). Sanitisation MUST happen at the trust
# boundary, which is the import endpoint.
#
# Strategy: bleach.clean() on every field that ends up as HTML in the
# render path. Two surfaces to clean:
#   1. The page-level HTML blob (gjs_html, gjs_css, custom_css, copy
#      fields) — straight bleach pass with a permissive page-builder
#      allowlist.
#   2. The element JSON (sections_json) — walk the JSON, sanitise every
#      el.txt and structured-prop string field, write it back.
#
# Permissive but safe: members embed images, links, styled spans, lists,
# headings, etc. inside their copy. Tags/attrs members legitimately use
# stay. Everything dangerous (script, iframe-outside-allowlist, event
# handlers, javascript: URLs, expression() CSS) is stripped.

# Tags allowed in page-builder HTML. Permissive — members write rich
# content. iframes are allowed but their src is checked at canvas/export
# time via sanitizeEmbed; bleach passes the iframe through, sanitizeEmbed
# enforces the host allowlist. (Belt + braces.)
_PAGE_BUILDER_ALLOWED_TAGS = [
    "p", "br", "hr", "span", "div",
    "h1", "h2", "h3", "h4", "h5", "h6",
    "strong", "em", "b", "i", "u", "s",
    "a", "img",
    "ul", "ol", "li",
    "blockquote", "code", "pre",
    "table", "thead", "tbody", "tr", "td", "th",
    "iframe",  # host-restricted at render time by sanitizeEmbed
]

# Attributes allowed per tag. style is allowed broadly because the
# editor builds inline styles for everything — but bleach also strips
# unsafe CSS expressions (url(javascript:), expression(), etc) via the
# css_sanitizer below.
_PAGE_BUILDER_ALLOWED_ATTRS = {
    "*":      ["class", "style", "id", "data-sp-submit", "data-sap-dismissible",
               "data-el-type", "data-has-font", "data-redirect", "data-success-message"],
    "a":      ["href", "target", "rel"],
    "img":    ["src", "alt", "width", "height", "loading"],
    "iframe": ["src", "width", "height", "allowfullscreen", "allow",
               "frameborder", "title", "data-sp-facade"],
}

# Allowed URL schemes on href / src. http(s), mailto, tel, fragments,
# and relative paths. Anything else (javascript:, data:, vbscript:,
# file:) gets the attribute stripped entirely.
_PAGE_BUILDER_ALLOWED_PROTOCOLS = ["http", "https", "mailto", "tel"]


def _sanitize_html_field(raw):
    """Bleach-clean a single HTML string with the page-builder allowlist.
    Returns sanitised string, or '' for non-string input.

    Two-tier strategy:
      Tier 1 — full bleach.clean with CSSSanitizer (requires tinycss2).
               Strips dangerous CSS like url(javascript:) and expression().
      Tier 2 — bleach.clean WITHOUT css_sanitizer if tinycss2 isn't
               available. Style attributes pass through unsanitised but
               the rest of the allowlist still applies. Render-time
               sanitizeEmbed.js handles the residual CSS edges.

    Last resort: strip everything if bleach itself raises — fail closed
    rather than emit unsanitised content.
    """
    if not raw or not isinstance(raw, str):
        return raw if raw is None else ""

    # Tier 1: full sanitiser with CSS protection
    try:
        from bleach.css_sanitizer import CSSSanitizer
        css = CSSSanitizer(allowed_css_properties=[
            # Layout
            "display", "position", "top", "left", "right", "bottom", "z-index",
            "width", "height", "max-width", "max-height", "min-width", "min-height",
            "margin", "margin-top", "margin-right", "margin-bottom", "margin-left",
            "padding", "padding-top", "padding-right", "padding-bottom", "padding-left",
            "box-sizing", "overflow", "overflow-x", "overflow-y",
            # Flex / grid
            "flex", "flex-direction", "flex-wrap", "justify-content", "align-items",
            "align-self", "align-content", "gap", "row-gap", "column-gap",
            "grid", "grid-template-columns", "grid-template-rows", "grid-column",
            "grid-row", "grid-area", "grid-gap",
            # Typography
            "font-family", "font-size", "font-weight", "font-style", "line-height",
            "letter-spacing", "text-align", "text-transform", "text-decoration",
            "color", "white-space", "word-wrap", "word-break", "overflow-wrap",
            # Background / border / shadow
            "background", "background-color", "background-image", "background-size",
            "background-position", "background-repeat", "background-attachment",
            "border", "border-top", "border-right", "border-bottom", "border-left",
            "border-color", "border-style", "border-width", "border-radius",
            "box-shadow", "outline",
            # Visual
            "opacity", "transform", "transition", "filter", "cursor",
            "visibility", "pointer-events", "user-select", "list-style",
        ])
        return bleach.clean(
            raw,
            tags=_PAGE_BUILDER_ALLOWED_TAGS,
            attributes=_PAGE_BUILDER_ALLOWED_ATTRS,
            protocols=_PAGE_BUILDER_ALLOWED_PROTOCOLS,
            css_sanitizer=css,
            strip=True,
            strip_comments=True,
        )
    except ImportError:
        # Tier 2: tinycss2 not installed → CSS sanitiser unavailable.
        # Fall through to no-css-sanitiser cleaning. Style attribute
        # values pass through unfiltered at the bleach layer; the
        # render-time sanitizeEmbed and the URL-scheme filter catch
        # the high-impact attacks. Log so ops sees it.
        logger.warning(
            "_sanitize_html_field: tinycss2 not installed — CSS sanitiser "
            "unavailable, falling back to tag/attr cleaning without CSS filter. "
            "Add tinycss2 to requirements.txt to enable full CSS sanitisation."
        )
    except Exception as e:
        logger.error(f"_sanitize_html_field: CSS sanitiser setup failed: {e}")

    # Tier 2 path — bleach.clean with allowlist, no css_sanitizer
    try:
        return bleach.clean(
            raw,
            tags=_PAGE_BUILDER_ALLOWED_TAGS,
            attributes=_PAGE_BUILDER_ALLOWED_ATTRS,
            protocols=_PAGE_BUILDER_ALLOWED_PROTOCOLS,
            strip=True,
            strip_comments=True,
        )
    except Exception as e:
        # Last resort: fail closed by escaping everything.
        logger.error(f"_sanitize_html_field: bleach.clean failed entirely: {e}")
        return bleach.clean(raw, tags=[], strip=True)


def _sanitize_sections_json(raw):
    """Walk a sections_json string (the React editor's els array as JSON)
    and bleach-clean every text-bearing field on every element.

    The structure is documented as `{"els": [{txt, type, s, _faqQ, ...}, ...]}`
    plus other top-level keys (canvasBg, canvasBgImage, deviceVisibility, etc).

    We deliberately preserve the outer JSON shape and ONLY modify the
    values that get rendered as HTML. Other fields (numbers, IDs, style
    keys, type strings) pass through unchanged.

    Fields cleaned per element (any that exist):
      txt — the main HTML content (Tiptap output, button label, etc)
      _quote, _author — review/testimonial structured fields
      _faqQuestion, _faqAnswer — FAQ structured fields
      _statLabel — stat block label
      _iconHeading, _iconDescription — icontext fields
      _separatorSymbol — separator centre text
      _logos[].text — logostrip per-logo label
      _formHeading, _formSubtitle, _formGdprText, _formBtnText,
        _formSuccessMsg — form copy fields
      _embedCode — embed HTML (already passes through sanitizeEmbed
        on render but we double-sanitise on import for defence in depth)

    Returns the re-serialised JSON string. On any error, returns the
    original input — render-time sanitisation still applies.
    """
    if not raw or not isinstance(raw, str):
        return raw if raw is None else ""
    try:
        import json as _json
        data = _json.loads(raw)
    except Exception:
        # Not JSON — could be legacy format. Pass through unchanged
        # (it won't be rendered as HTML via gjs_html either).
        return raw

    HTML_TEXT_FIELDS = (
        "txt",
        "_quote", "_author",
        "_faqQuestion", "_faqAnswer",
        "_statLabel",
        "_iconHeading", "_iconDescription",
        "_separatorSymbol",
        "_formHeading", "_formSubtitle", "_formGdprText",
        "_formBtnText", "_formSuccessMsg",
        "_embedCode",
    )

    try:
        if isinstance(data, dict) and isinstance(data.get("els"), list):
            for el in data["els"]:
                if not isinstance(el, dict):
                    continue
                for field in HTML_TEXT_FIELDS:
                    val = el.get(field)
                    if isinstance(val, str) and val:
                        el[field] = _sanitize_html_field(val)
                # Logostrip: per-logo text labels
                logos = el.get("_logos")
                if isinstance(logos, list):
                    for logo in logos:
                        if isinstance(logo, dict):
                            txt = logo.get("text")
                            if isinstance(txt, str) and txt:
                                logo["text"] = _sanitize_html_field(txt)
                            # Logo image URLs are also member-controlled —
                            # block javascript: and data: schemes here.
                            img = logo.get("img")
                            if isinstance(img, str) and img:
                                stripped = img.strip().lower()
                                if stripped.startswith(("javascript:", "vbscript:", "data:text/html")):
                                    logo["img"] = ""
        return _json.dumps(data, separators=(",", ":"), ensure_ascii=False)
    except Exception as e:
        logger.error(f"_sanitize_sections_json: walk failed: {e}")
        return raw


def _sanitize_share_code_snapshot(snap):
    """Mutate `snap` in place: bleach-clean every field that ends up
    rendered as HTML on the published page or in the editor canvas.

    Called by share_code_import BEFORE the snapshot is written to the
    importer's new FunnelPage. Defence boundary: the importer trusts
    the sender, but visitors trust neither — so we clean at this seam.

    Safe-to-mutate fields:
      gjs_html, gjs_css, custom_css — page-level HTML/CSS blobs
      headline, subheadline, body_copy — copy fields rendered as HTML
      capture_form_heading, capture_form_subtext — opt-in modal copy
      meta_description — emitted in <meta>, plain-text but still
        deserves angle-bracket escape
      sections_json — element array, sanitised via _sanitize_sections_json
      gjs_components — legacy GrapesJS components (rare in modern shares)

    URL fields (cta_url, video_url, image_url, og_image_url) get
    a scheme check: javascript:/vbscript:/data:text/html replaced with ''.
    Other fields (title, template_type, color_scheme, font_family) are
    structural / enum-like and pass through unchanged.
    """
    if not isinstance(snap, dict):
        return snap

    # HTML / CSS blob fields — full bleach pass
    for field in ("gjs_html", "gjs_css", "custom_css",
                  "headline", "subheadline", "body_copy",
                  "capture_form_heading", "capture_form_subtext",
                  "gjs_components"):
        if field in snap and isinstance(snap[field], str):
            snap[field] = _sanitize_html_field(snap[field])

    # Element JSON — walk-and-clean
    if "sections_json" in snap and isinstance(snap["sections_json"], str):
        snap["sections_json"] = _sanitize_sections_json(snap["sections_json"])

    # Plain-text meta — strip any HTML entirely (no formatting allowed)
    if "meta_description" in snap and isinstance(snap["meta_description"], str):
        snap["meta_description"] = bleach.clean(snap["meta_description"], tags=[], strip=True)

    # URL fields — scheme-check; clear dangerous schemes
    DANGEROUS_URL_RE = _re.compile(r"^\s*(javascript|vbscript|file|data:text/html)", _re.IGNORECASE)
    for field in ("cta_url", "video_url", "image_url", "og_image_url"):
        if field in snap and isinstance(snap[field], str) and snap[field]:
            if DANGEROUS_URL_RE.match(snap[field]):
                snap[field] = ""

    return snap


@app.post("/api/share-codes/import")
async def share_code_import(request: Request, user: User = Depends(get_current_user),
                            db: Session = Depends(get_db)):
    """Import a SAP-XXXX-XXXX code as a fresh draft FunnelPage.

    Body: {"code": "SAP-XXXX-XXXX"}
    Returns: {
      "success": True,
      "page_id": <int>,
      "edit_url": "/pro/funnel/<id>/edit",
      "ref_rewrites": <int>,           # how many ref links we swapped
      "warnings": [ ... ],             # any soft issues for the user
    }

    Spec: the new page is owned by the importer, status=draft, with
    no list/sequence binding. The importer wires their campaign via
    the existing Phase 1 modal flow on first publish. We deliberately
    do NOT expose the owner_user_id of the code anywhere in the
    response — the spec mandates zero attribution to importers.
    """
    from fastapi.responses import JSONResponse
    import json as _json
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    if not is_pro(user):
        return JSONResponse({"error": "Importing pages is a Pro feature."}, status_code=403)
    try:
        body = await request.json()
    except Exception:
        return JSONResponse({"error": "Invalid request"}, status_code=400)

    raw_code = (body.get("code") or "").strip().upper()
    if not raw_code:
        return JSONResponse({"error": "code required"}, status_code=400)

    # Normalise: accept with or without dashes, with or without SAP-
    # prefix variants. We store as SAP-XXXX-XXXX.
    cleaned = _re.sub(r"[^A-Z0-9]", "", raw_code)
    if cleaned.startswith("SAP"):
        cleaned = cleaned[3:]
    if len(cleaned) != 8:
        return JSONResponse({"error": "That code doesn't look right. Expected format: SAP-XXXX-XXXX"}, status_code=400)
    normalised = f"SAP-{cleaned[:4]}-{cleaned[4:]}"

    share = db.query(ShareCode).filter(ShareCode.code == normalised).first()
    if not share:
        return JSONResponse({"error": "Code not found. Double-check the code with whoever sent it."}, status_code=404)

    # Expiry guard (future-proofing — no codes expire today)
    if share.expires_at and share.expires_at < datetime.utcnow():
        return JSONResponse({"error": "This code has expired."}, status_code=410)

    try:
        payload = _json.loads(share.payload_json)
    except Exception:
        return JSONResponse({"error": "This code's data is corrupted. Ask the sender to regenerate it."}, status_code=500)

    if payload.get("v") != 1:
        return JSONResponse({"error": f"Unsupported share-code version: {payload.get('v')}. Update needed."}, status_code=400)

    snap = payload.get("page") or {}
    title = (snap.get("title") or "Imported page").strip() or "Imported page"

    # XSS sanitisation pass (audit XSS-1, 24 May 2026). MUST run before
    # any other field manipulation — clean content gets the rewriter
    # next, then lands in the DB. Without this, a malicious sharer could
    # craft <img src=x onerror=...> in any element's txt, generate a
    # share code, and pwn every visitor to the importer's republished
    # page. See _sanitize_share_code_snapshot for the field-by-field
    # rationale.
    try:
        _sanitize_share_code_snapshot(snap)
    except Exception as _e:
        logger.error(f"share_code_import: sanitisation pass raised — failing closed: {_e}")
        return JSONResponse({"error": "Could not safely import this code. The sender may need to regenerate it."}, status_code=500)

    # Run the rewriter across every text-bearing field. We sum the
    # rewrite counts to report in the response. The rewriter is safe
    # to run on JSON-encoded blobs (sections_json, gjs_components) —
    # it operates on the raw string so escape sequences stay intact.
    rewrite_total = 0
    for field in _REWRITE_TARGET_FIELDS:
        original = snap.get(field)
        if not original or not isinstance(original, str):
            continue
        rewritten, n = _rewrite_referral_links(original, user.username or "")
        if n:
            snap[field] = rewritten
            rewrite_total += n

    # Build the new page. Status forced to draft so the user reviews
    # before publishing — never auto-publish someone else's content
    # under the importer's name.
    new_page = FunnelPage(user_id=user.id, status="draft")
    for field in SHARE_CODE_V1_FIELDS:
        if field in snap:
            setattr(new_page, field, snap[field])
    new_page.title = title
    new_page.slug = generate_unique_slug(db, user.username or f"user{user.id}", title)
    # Explicitly zero stats so we never inherit the source page's
    # numbers. Defaults on the model handle this for fresh inserts
    # but we set them defensively in case future migrations change
    # column defaults.
    new_page.views = 0
    new_page.clicks = 0
    new_page.leads_captured = 0
    # No binding inherited — campaign wiring is the importer's call.
    new_page.default_list_id = None
    new_page.capture_sequence_id = None
    # Don't flag imports as AI-generated — they may have been, in the
    # original author's account, but on the importer's dashboard the
    # AI badge would mislead.
    new_page.is_ai_generated = False
    new_page.ai_niche = None
    new_page.ai_audience = None
    new_page.ai_story = None
    new_page.ai_tone = None
    db.add(new_page)

    # Track usage on the share code.
    share.uses_count = (share.uses_count or 0) + 1

    db.commit()
    db.refresh(new_page)

    warnings = []
    # If there were 0 rewrites AND the original had something that
    # looked like a URL in a CTA, flag it. Cheap heuristic — better
    # to over-flag than miss a stranger's monetised link.
    if rewrite_total == 0:
        cta = (snap.get("cta_url") or "")
        if cta and ("/r/" in cta or "ref=" in cta.lower() or "affiliate" in cta.lower()):
            warnings.append("The CTA link contained referral-looking text we couldn't safely rewrite. Review the Edit page before publishing.")

    return JSONResponse({
        "success": True,
        "page_id": new_page.id,
        "edit_url": f"/pro/funnel/{new_page.id}/edit",
        "ref_rewrites": rewrite_total,
        "warnings": warnings,
    })


@app.post("/api/funnels/sequence")
async def funnel_set_sequence(request: Request, user: User = Depends(get_current_user),
                               db: Session = Depends(get_db)):
    from fastapi.responses import JSONResponse
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    try:
        body = await request.json()
    except Exception:
        return JSONResponse({"error": "Invalid request"}, status_code=400)
    funnel_name = body.get("funnel_name", "").strip()
    page_ids = body.get("page_ids", [])
    if not funnel_name or not page_ids:
        return JSONResponse({"error": "funnel_name and page_ids required"}, status_code=400)
    pages = db.query(FunnelPage).filter(FunnelPage.id.in_(page_ids), FunnelPage.user_id == user.id).all()
    page_map = {p.id: p for p in pages}
    for i, pid in enumerate(page_ids):
        pg = page_map.get(pid)
        if not pg:
            continue
        pg.funnel_name = funnel_name
        pg.funnel_order = i
        pg.next_page_id = page_ids[i + 1] if i + 1 < len(page_ids) else None
    db.commit()
    return JSONResponse({"success": True, "funnel_name": funnel_name, "pages": len(page_ids)})
