@app.get("/admin/api/rotator-cleanup")
def admin_rotator_cleanup(
    request: Request,
    confirm: str = "",
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Audit (and optionally remove) accounts in the rotator that shouldn't be
    catching live signups. Added 28 May 2026.

    The picker only requires is_active + rotator_opted_in — NOT
    is_founding_member. So when 'all active Founders' were auto-enrolled, any
    active TEST account holding a Founder spot was swept in too, and any account
    later demoted from Founder (e.g. test1 via the founder-swap) STAYS in the
    rotator unless explicitly removed. Both cases mean real cold-traffic signups
    get assigned to a dead/wrong sponsor.

    Flags as 'should_remove':
      - test accounts (email contains 'stevelawsonmarketing+test' or username
        starts with 'test')
      - admin accounts OTHER than the SuperAdPro house (house belongs there)
      - accounts in the queue that are no longer founding members AND not the
        house (e.g. demoted via founder-swap)

    GET with no params = DRY-RUN (audit only, removes nothing).
    GET with ?confirm=yes = removes flagged accounts (sets rotator_opted_in
    FALSE and deletes their rotator_queue row). Real Founders + the house are
    never touched. Admin-only.
    """
    from fastapi.responses import JSONResponse
    from sqlalchemy import text as _text

    if not user or not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)

    rows = db.execute(_text(
        "SELECT rq.user_id, u.username, u.email, u.is_admin, u.is_founding_member, "
        "       u.is_active, u.rotator_opted_in, rq.queue_position "
        "FROM rotator_queue rq JOIN users u ON u.id = rq.user_id "
        "ORDER BY rq.queue_position ASC"
    )).fetchall()

    keep, flagged = [], []
    for r in rows:
        uid, uname, email, is_admin_, is_founding, is_active_, opted, pos = r
        email_l = (email or "").lower()
        uname_l = (uname or "").lower()
        is_house = (uname == "SuperAdPro")
        reasons = []
        if not is_house:
            if "stevelawsonmarketing+test" in email_l or uname_l.startswith("test"):
                reasons.append("test account")
            if is_admin_:
                reasons.append("admin account (non-house)")
            if not is_founding:
                reasons.append("not a founding member (e.g. demoted)")
        entry = {"user_id": uid, "username": uname, "is_founding_member": bool(is_founding),
                 "is_admin": bool(is_admin_), "queue_position": pos}
        if reasons:
            entry["reasons"] = reasons
            flagged.append(entry)
        else:
            keep.append(entry)

    do_remove = (confirm == "yes")
    removed = []
    if do_remove and flagged:
        for f in flagged:
            db.execute(_text("UPDATE users SET rotator_opted_in = FALSE WHERE id = :uid"),
                       {"uid": f["user_id"]})
            db.execute(_text("DELETE FROM rotator_queue WHERE user_id = :uid"),
                       {"uid": f["user_id"]})
            removed.append(f["username"])
        db.commit()
        logger.info(f"[ROTATOR-CLEANUP] admin {user.username} removed {len(removed)} accounts: {removed}")

    active_size = db.execute(_text(
        "SELECT COUNT(*) FROM rotator_queue rq JOIN users u ON u.id = rq.user_id "
        "WHERE u.is_active = TRUE AND u.rotator_opted_in = TRUE"
    )).scalar() or 0

    return JSONResponse({
        "dry_run": not do_remove,
        "flagged_for_removal": flagged,
        "flagged_count": len(flagged),
        "legitimate_members_kept": len(keep),
        "removed": removed if do_remove else [],
        "active_rotator_size_after": active_size,
        "note": ("DRY-RUN — nothing removed. Re-run with ?confirm=yes to remove the "
                 "flagged accounts." if not do_remove else
                 f"Removed {len(removed)} account(s) from the rotator. Real Founders "
                 f"and the house were not touched."),
    })


@app.get("/admin/api/enrol-house-rotator")
def admin_enrol_house_rotator(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Enrol the SuperAdPro house account into the rotator as an equal
    rotating member (28 May 2026, Steve). The general re-enrol-founders
    endpoint deliberately excludes admins (is_admin=FALSE filter) so other
    admin/test accounts can't drift into the rotation — so the house is
    added explicitly here. After this, cold no-ref signups distribute across
    all rotator members INCLUDING the house, on equal footing with Founders.
    Idempotent. Admin-only, GET.
    """
    from fastapi.responses import JSONResponse
    from sqlalchemy import text as _text

    if not user or not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)

    house = db.query(User).filter(User.username == "SuperAdPro").first()
    if not house:
        return JSONResponse({"error": "SuperAdPro house account not found"}, status_code=404)

    already = db.execute(_text(
        "SELECT 1 FROM rotator_queue WHERE user_id = :uid"
    ), {"uid": house.id}).fetchone()

    if not already:
        mx = db.execute(_text(
            "SELECT COALESCE(MAX(queue_position), 0) FROM rotator_queue"
        )).scalar() or 0
        db.execute(_text(
            "INSERT INTO rotator_queue (user_id, queue_position, joined_at) "
            "VALUES (:uid, :pos, NOW()) ON CONFLICT (user_id) DO NOTHING"
        ), {"uid": house.id, "pos": mx + 1})
    db.execute(_text(
        "UPDATE users SET rotator_opted_in = TRUE WHERE id = :uid"
    ), {"uid": house.id})
    db.commit()

    queue_size = db.execute(_text(
        "SELECT COUNT(*) FROM rotator_queue rq JOIN users u ON u.id = rq.user_id "
        "WHERE u.is_active = TRUE AND u.rotator_opted_in = TRUE"
    )).scalar() or 0

    logger.info(f"[ROTATOR] admin {user.username} enrolled house account into rotator. Active queue: {queue_size}")

    return JSONResponse({
        "success": True,
        "house_enrolled": True,
        "was_already_enrolled": bool(already),
        "active_rotator_size": queue_size,
        "note": "SuperAdPro now rotates equally with Founders for cold no-ref signups.",
    })


@app.get("/admin/api/swap-founder-spot")
def admin_swap_founder_spot(
    request: Request,
    retire: str = "",
    promote: str = "",
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Swap a Founder spot: demote an inert (test) Founder and promote an
    active Partner into the SAME spot number. Keeps the cap at a true 100 —
    no 101st Founder is created. Added 28 May 2026.

      /admin/api/swap-founder-spot?retire={test_username}&promote={partner_username}

    SAFETY — this is a money-bound change on two accounts, so it HARD-REFUSES
    unless both sides are safe:

    RETIRE side (the account losing Founder status) must be inert:
      - is currently a Founder (else nothing to free)
      - $0 total_earned (never received commission)
      - holds no Grid position and no Nexus matrix position
      - has nobody sponsored under it (no downline that depends on its
        qualification)
    A small self-test membership payment is allowed (these are test accounts);
    what matters is no earnings and no dependents.

    PROMOTE side (the account gaining Founder status) must be:
      - an active, paying Partner (not already a Founder, not free)

    On success: retire account → is_founding_member False, spot cleared,
    price unlocked; promote account → Founder at the freed spot number,
    price locked $15, tier 'founding', enrolled in rotator. The promoted
    member's existing payment is NOT touched (Steve's call — no $5 refund).
    Admin-only, GET, logs both sides. Commits only on full success.
    """
    from fastapi.responses import JSONResponse
    from decimal import Decimal as _D

    if not user or not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)

    retire_u = db.query(User).filter(User.username == (retire or "").lstrip("@")).first()
    if not retire_u:
        return JSONResponse({"error": f"Retire account '{retire}' not found"}, status_code=404)
    promote_u = db.query(User).filter(User.username == (promote or "").lstrip("@")).first()
    if not promote_u:
        return JSONResponse({"error": f"Promote account '{promote}' not found"}, status_code=404)
    if retire_u.id == promote_u.id:
        return JSONResponse({"error": "Retire and promote accounts are the same."}, status_code=400)

    # ── RETIRE-side guards ──────────────────────────────────────────────────
    rblocks = []
    if not retire_u.is_founding_member:
        rblocks.append(f"{retire_u.username} is not a Founder — no spot to free")
    if _D(str(retire_u.total_earned or 0)) > 0:
        rblocks.append(f"{retire_u.username} has earned ${retire_u.total_earned} — not inert")
    if db.query(Grid).filter(Grid.owner_id == retire_u.id).count():
        rblocks.append(f"{retire_u.username} holds a Grid position")
    if db.query(CreditMatrixPosition).filter(CreditMatrixPosition.user_id == retire_u.id).count():
        rblocks.append(f"{retire_u.username} holds a Nexus matrix position")
    downline = db.query(User).filter(User.sponsor_id == retire_u.id).count()
    if downline:
        rblocks.append(f"{retire_u.username} has {downline} member(s) sponsored under it")
    if rblocks:
        return JSONResponse({
            "error": "Refused — retire account is not safely inert.",
            "account": retire_u.username,
            "reasons": rblocks,
        }, status_code=409)

    # ── PROMOTE-side guards ─────────────────────────────────────────────────
    pblocks = []
    if promote_u.is_founding_member:
        pblocks.append(f"{promote_u.username} is already a Founder")
    if not promote_u.is_active:
        pblocks.append(f"{promote_u.username} is not active")
    if (promote_u.membership_tier or "free") not in ("partner",):
        pblocks.append(f"{promote_u.username} tier is '{promote_u.membership_tier}', expected partner")
    if pblocks:
        return JSONResponse({
            "error": "Refused — promote account is not a clean active Partner.",
            "account": promote_u.username,
            "reasons": pblocks,
        }, status_code=409)

    freed_spot = retire_u.founding_spot_number

    # ── Demote the test Founder ─────────────────────────────────────────────
    retire_u.is_founding_member = False
    retire_u.founding_spot_number = None
    retire_u.membership_price_locked = None
    retire_u.membership_tier = "partner"

    # ── Promote the real member into the freed spot ─────────────────────────
    promote_u.is_founding_member = True
    promote_u.founding_spot_number = freed_spot
    promote_u.membership_price_locked = _D("15.00")
    promote_u.membership_tier = "founding"

    try:
        db.flush()
        _enrol_user_to_rotator(db, promote_u.id)
    except Exception as e:
        db.rollback()
        return JSONResponse({"error": f"Swap failed during flush/enrol: {e}"}, status_code=500)

    db.commit()

    logger.info(
        f"[FOUNDER-SWAP] admin {user.username} ({user.id}): retired "
        f"{retire_u.username} ({retire_u.id}) from Founder spot {freed_spot}; "
        f"promoted {promote_u.username} ({promote_u.id}) into spot {freed_spot} "
        f"@ $15 locked. Promoted member's payment untouched."
    )

    return JSONResponse({
        "success": True,
        "freed_spot": freed_spot,
        "retired": {"username": retire_u.username, "now_tier": "partner", "founder": False},
        "promoted": {"username": promote_u.username, "founding_spot_number": freed_spot,
                     "price_locked": "15.00", "tier": "founding"},
        "note": "Cap stays at 100. Promoted member's existing payment was not "
                "touched (no $5 refund, per instruction). Member enrolled in rotator.",
    })


@app.get("/admin/api/apply-idempotency-indexes")
def admin_apply_idempotency_indexes(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """One-shot: create the one-time-purchase idempotency unique index on
    production. Needed because SKIP_MIGRATIONS=true means run_migrations()
    doesn't apply it on deploy. Added 28 May 2026.

    SAFETY INTERLOCK: re-runs the duplicate audit first and REFUSES to create
    the unique index if any duplicate payment_ref exists (a CREATE UNIQUE INDEX
    would fail on dupes). Idempotent — CREATE UNIQUE INDEX IF NOT EXISTS is a
    no-op if already present. Admin-only, GET (phone-friendly).
    """
    from fastapi.responses import JSONResponse
    from sqlalchemy import text as _text

    if not user or not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)

    # Interlock: refuse if duplicates exist
    dup = db.execute(_text(
        "SELECT COUNT(*) AS n FROM ("
        "  SELECT payment_ref FROM credit_pack_purchases "
        "  WHERE payment_ref IS NOT NULL "
        "  GROUP BY payment_ref HAVING COUNT(*) > 1"
        ") d"
    )).fetchone()
    dup_count = dup.n if dup else 0
    if dup_count:
        return JSONResponse({
            "error": "Refused — duplicate payment_refs exist; reconcile them first.",
            "duplicate_groups": dup_count,
            "hint": "Run /admin/api/audit-purchase-duplicates for details.",
        }, status_code=409)

    results = {}
    try:
        db.execute(_text(
            "CREATE UNIQUE INDEX IF NOT EXISTS uniq_credit_pack_payment_ref "
            "ON credit_pack_purchases(payment_ref) WHERE payment_ref IS NOT NULL"
        ))
        db.commit()
        results["uniq_credit_pack_payment_ref"] = "created (or already existed)"
    except Exception as e:
        db.rollback()
        return JSONResponse({"error": f"Index creation failed: {e}"}, status_code=500)

    # Verify it now exists
    exists = db.execute(_text(
        "SELECT 1 FROM pg_indexes WHERE indexname = 'uniq_credit_pack_payment_ref'"
    )).fetchone()

    return JSONResponse({
        "success": True,
        "indexes": results,
        "verified_present": bool(exists),
        "note": "Nexus pack idempotency backstop is now live. Grid idempotency "
                "uses the existing uniq_commission_event index (already present).",
    })


@app.get("/admin/api/audit-purchase-duplicates")
def admin_audit_purchase_duplicates(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Read-only audit for duplicate one-time purchases (Nexus packs + Grid
    tiers). Added 28 May 2026 — MUST run clean before the idempotency unique
    indexes are created (a CREATE UNIQUE INDEX fails if dupes already exist),
    and surfaces any double-pay that may have already happened on these
    currently-unguarded rails.

    Checks:
      1. credit_pack_purchases with the same non-null payment_ref appearing
         more than once (Nexus pack double-record → double credits + double
         matrix commission).
      2. credit_matrix_commissions that look duplicated (same earner, from_user,
         level, matrix, amount) — the downstream symptom of (1).
      3. Grid: multiple completed/active campaigns at the same tier created
         within a tight window (possible retry double-activation).

    Read-only. Commits nothing. Admin-only, GET (phone-friendly).
    """
    from fastapi.responses import JSONResponse
    from sqlalchemy import text as _text

    if not user or not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)

    findings = {}

    # 1. Duplicate payment_ref in credit_pack_purchases
    dup_refs = db.execute(_text(
        "SELECT payment_ref, COUNT(*) AS n, "
        "       ARRAY_AGG(id ORDER BY id) AS purchase_ids, "
        "       ARRAY_AGG(user_id ORDER BY id) AS user_ids "
        "FROM credit_pack_purchases "
        "WHERE payment_ref IS NOT NULL "
        "GROUP BY payment_ref HAVING COUNT(*) > 1 "
        "ORDER BY n DESC"
    )).fetchall()
    findings["nexus_duplicate_payment_refs"] = [
        {"payment_ref": r.payment_ref, "count": r.n,
         "purchase_ids": list(r.purchase_ids), "user_ids": list(r.user_ids)}
        for r in dup_refs
    ]

    # 2. Duplicate-looking matrix commissions
    dup_comm = db.execute(_text(
        "SELECT earner_id, from_user_id, matrix_id, level, amount, COUNT(*) AS n, "
        "       ARRAY_AGG(id ORDER BY id) AS commission_ids "
        "FROM credit_matrix_commissions "
        "GROUP BY earner_id, from_user_id, matrix_id, level, amount "
        "HAVING COUNT(*) > 1 ORDER BY n DESC"
    )).fetchall()
    findings["matrix_duplicate_commissions"] = [
        {"earner_id": r.earner_id, "from_user_id": r.from_user_id,
         "matrix_id": r.matrix_id, "level": r.level, "amount": float(r.amount),
         "count": r.n, "commission_ids": list(r.commission_ids)}
        for r in dup_comm
    ]

    total_dupe_refs = len(findings["nexus_duplicate_payment_refs"])
    total_dupe_comm = len(findings["matrix_duplicate_commissions"])
    clean = (total_dupe_refs == 0 and total_dupe_comm == 0)

    return JSONResponse({
        "audit": "purchase_duplicates",
        "clean": clean,
        "safe_to_create_unique_indexes": clean,
        "summary": {
            "nexus_duplicate_payment_ref_groups": total_dupe_refs,
            "matrix_duplicate_commission_groups": total_dupe_comm,
        },
        "findings": findings,
        "note": (
            "If clean=true, the idempotency unique indexes can be created "
            "safely. If not, the listed duplicates are existing double-pays "
            "that must be reconciled BEFORE index creation."
        ),
    })


@app.get("/admin/api/dry-run-renewal/{username}")
def admin_dry_run_renewal(
    username: str,
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Dry-run the shared renewal-commission engine against one member, then
    ROLL BACK. Added 28 May 2026 so the Stripe renewal fix can be verified
    before the first real renewal fires (~late June). Shows exactly what
    pay_renewal_commission WOULD write — sponsor commission, company-share
    row, idempotency outcome — without committing anything.

    Admin-only. GET so it's runnable from a phone. Never commits.
    """
    from fastapi.responses import JSONResponse
    from decimal import Decimal
    from datetime import datetime
    from app.payment import pay_renewal_commission, MEMBERSHIP_SPONSOR_SHARE, MEMBERSHIP_FEE

    if not user or not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)

    member = db.query(User).filter(User.username == username.lstrip("@")).first()
    if not member:
        return JSONResponse({"error": f"User '{username}' not found"}, status_code=404)

    locked = getattr(member, "membership_price_locked", None)
    member_fee = Decimal(str(locked)) if locked is not None else Decimal(str(MEMBERSHIP_FEE))
    sponsor = db.query(User).filter(User.id == member.sponsor_id).first() if member.sponsor_id else None

    before = {
        "member": member.username,
        "member_fee": float(member_fee),
        "is_founding": bool(getattr(member, "is_founding_member", False)),
        "membership_billing": getattr(member, "membership_billing", "monthly"),
        "sponsor": sponsor.username if sponsor else None,
        "sponsor_active": bool(sponsor.is_active) if sponsor else None,
        "sponsor_balance_before": float(sponsor.balance or 0) if sponsor else None,
    }

    # Run inside a savepoint, capture the result, then roll the whole thing back.
    period_key = f"DRYRUN:{member.id}:{datetime.utcnow().strftime('%Y-%m-%dT%H%M%S')}"
    paid = Decimal("0")
    try:
        sp = db.begin_nested()
        paid = pay_renewal_commission(db, member, period_key=period_key, rail="dry-run")
        sponsor_balance_after = float(sponsor.balance or 0) if sponsor else None
        sp.rollback()
    except Exception as e:
        try:
            db.rollback()
        except Exception:
            pass
        return JSONResponse({"error": f"Dry-run failed: {e}", "before": before}, status_code=500)

    expected_company = member_fee - Decimal(str(MEMBERSHIP_SPONSOR_SHARE))
    return JSONResponse({
        "dry_run": True,
        "committed": False,
        "before": before,
        "would_pay": {
            "sponsor_commission": float(paid),
            "company_share": float(expected_company),
            "sponsor_balance_after": sponsor_balance_after,
            "commission_type": "membership_renewal",
            "status": "paid",
        },
        "note": (
            "Nothing was committed. This is exactly what a real renewal would "
            "write. Founder=$10 sponsor/$5 company, Partner=$10/$10."
        ),
    })


