def send_notification(db: Session, user_id: int, type: str, icon: str, title: str, message: str, link: str = None, translation_key: str = None):
    """Create a notification for a user. Also invalidates their dashboard cache.

    If translation_key is provided, the frontend will translate the title/
    message at display time using the user's locale. The literal title and
    message values are still required (used as the English fallback for
    older clients and for any i18n cache miss)."""
    notif = Notification(
        user_id=user_id, type=type, icon=icon,
        title=title, message=message, link=link,
        translation_key=translation_key,
    )
    db.add(notif)
    # Invalidate dashboard cache so next load shows fresh data. Covers all
    # four user-keyed prefixes (dash/descendants/withdrawn/earnings) since
    # the broader fix on 10 May 2026 — previously only dash:.
    cache_invalidate_user(user_id)
    # Leaderboard invalidation — any notification type that signals a
    # commission/balance change affects the leaderboard's earnings ranking.
    # Previously only "commission" was covered, missing "gift_claimed",
    # "withdrawal", and "matrix_*" types that all involve real money flow.
    if type in ("commission", "gift_claimed", "withdrawal"):
        cache_invalidate_leaderboard()
@app.get("/api/notifications")
def get_notifications(user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """Get recent notifications for current user."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    notifs = db.query(Notification).filter(
        Notification.user_id == user.id
    ).order_by(Notification.created_at.desc()).limit(20).all()
    unread = db.query(Notification).filter(
        Notification.user_id == user.id, Notification.is_read == False
    ).count()
    return JSONResponse({
        "notifications": [{
            "id": n.id,
            "type": n.type,
            "icon": n.icon,
            "title": n.title,
            "message": n.message,
            "link": n.link,
            "is_read": n.is_read,
            "translation_key": n.translation_key,
            "created_at": n.created_at.isoformat() if n.created_at else None,
        } for n in notifs],
        "unread_count": unread,
    })
@app.post("/api/notifications/read-beacon")
async def mark_notifications_read_beacon(request: Request, db: Session = Depends(get_db)):
    """Mark all notifications as read via sendBeacon (no JSON body)."""
    user = get_current_user(request, db)
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    db.query(Notification).filter(
        Notification.user_id == user.id, Notification.is_read == False
    ).update({Notification.is_read: True}, synchronize_session=False)
    db.commit()
    return JSONResponse({"ok": True})
@app.post("/api/notifications/read")
async def mark_notifications_read(request: Request, user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """Mark notifications as read."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    body = await request.json()
    ids = body.get("ids", [])
    if ids:
        db.query(Notification).filter(
            Notification.user_id == user.id, Notification.id.in_(ids)
        ).update({Notification.is_read: True}, synchronize_session=False)
    else:
        # Mark all as read
        db.query(Notification).filter(
            Notification.user_id == user.id, Notification.is_read == False
        ).update({Notification.is_read: True}, synchronize_session=False)
    db.commit()
    return JSONResponse({"ok": True})
