@app.get("/admin/grid-audit")
def admin_grid_audit(
    user: User = Depends(get_current_user),
    owner_username: str = "master",
    tier: int = 1,
    db: Session = Depends(get_db)
):
    """
    Full audit of a grid — shows positions, commissions, balances.
    
    Usage: /admin/grid-audit?secret=$ADMIN_SECRET&owner_username=master&tier=1
    """
    _require_admin(user)

    owner = db.query(User).filter(User.username == owner_username).first()
    if not owner:
        return JSONResponse({"error": f"User '{owner_username}' not found"}, status_code=404)

    grids = db.query(Grid).filter(
        Grid.owner_id == owner.id,
        Grid.package_tier == tier,
    ).order_by(Grid.advance_number).all()

    audit = []
    for g in grids:
        positions = db.query(GridPosition).filter(GridPosition.grid_id == g.id).order_by(
            GridPosition.grid_level, GridPosition.position_num
        ).all()

        commissions = db.query(Commission).filter(Commission.grid_id == g.id).all()

        level_breakdown = {}
        for lvl in range(1, 9):
            level_positions = [p for p in positions if p.grid_level == lvl]
            level_breakdown[f"level_{lvl}"] = {
                "filled": len(level_positions),
                "capacity": 8,
                "members": [p.member_id for p in level_positions],
            }

        commission_summary = {}
        for c in commissions:
            ct = c.commission_type
            if ct not in commission_summary:
                commission_summary[ct] = {"count": 0, "total": 0.0}
            commission_summary[ct]["count"] += 1
            commission_summary[ct]["total"] += float(c.amount_usdt or 0)

        audit.append({
            "grid_id": g.id,
            "advance": g.advance_number,
            "filled": g.positions_filled,
            "is_complete": g.is_complete,
            "revenue_total": float(g.revenue_total or 0),
            "levels": level_breakdown,
            "commission_summary": commission_summary,
        })

    return {
        "owner": owner_username,
        "tier": tier,
        "price": GRID_PACKAGES.get(tier),
        "owner_balances": {
            "balance": float(owner.balance or 0),
            "total_earned": float(owner.total_earned or 0),
            "grid_earnings": float(owner.grid_earnings or 0),
            "level_earnings": float(owner.level_earnings or 0),
        },
        "grids": audit,
    }


@app.get("/admin/grid-cleanup-audit")
def admin_grid_cleanup_audit(
    user: User = Depends(get_current_user),
    ids: str = "667,668,669,670,673,674",
    db: Session = Depends(get_db),
):
    """
    READ-ONLY footprint of suspected synthetic / attacker accounts in the grid.

    For each suspect user_id it reports:
      - grids they OWN (phantom grids spawned by the voided package buys)
      - grid POSITIONS they hold inside OTHER members' grids (matrix pollution)
      - commission rows from/to them, grouped by status (so we can see what's
        already been reversed vs what's still live on real members' balances)
      - whether any of their positions sit inside the founder's (user 1) grids

    No writes whatsoever — pure diagnostics so we can decide exactly what to
    clean before touching anything. Phone-friendly HTML; ?format=json available.
    Usage: /admin/grid-cleanup-audit?ids=667,668,669,670,673,674
    """
    _require_admin(user)
    import html as _h

    FOUNDER_ID = 1
    try:
        synth_ids = [int(x) for x in ids.split(",") if x.strip().isdigit()]
    except Exception:
        synth_ids = []
    if not synth_ids:
        return HTMLResponse("<p>No valid ids. Use ?ids=667,670,673…</p>", status_code=400)

    suspects = db.query(User).filter(User.id.in_(synth_ids)).all()
    suspect_map = {u.id: u for u in suspects}

    owned_grids = db.query(Grid).filter(Grid.owner_id.in_(synth_ids)).order_by(
        Grid.owner_id, Grid.package_tier, Grid.advance_number).all()

    held = db.query(GridPosition).filter(GridPosition.member_id.in_(synth_ids)).order_by(
        GridPosition.grid_id, GridPosition.grid_level, GridPosition.position_num).all()

    held_grid_ids = sorted({p.grid_id for p in held})
    grids_by_id = {}
    if held_grid_ids:
        for g in db.query(Grid).filter(Grid.id.in_(held_grid_ids)).all():
            grids_by_id[g.id] = g
    owner_ids_needed = sorted({g.owner_id for g in grids_by_id.values()})
    owner_names = {}
    if owner_ids_needed:
        for u in db.query(User).filter(User.id.in_(owner_ids_needed)).all():
            owner_names[u.id] = u.username or f"#{u.id}"

    comms_from = db.query(Commission).filter(Commission.from_user_id.in_(synth_ids)).all()
    comms_to = db.query(Commission).filter(Commission.to_user_id.in_(synth_ids)).all()

    def breakdown(rows):
        out = {}
        for c in rows:
            st = c.status or "unknown"
            d = out.setdefault(st, {"count": 0, "total": 0.0})
            d["count"] += 1
            d["total"] += float(c.amount_usdt or 0)
        return out

    from_bd, to_bd = breakdown(comms_from), breakdown(comms_to)

    # positions held by suspects that sit inside grids owned by NON-suspects
    in_real = [p for p in held if grids_by_id.get(p.grid_id) and grids_by_id[p.grid_id].owner_id not in synth_ids]
    in_founder = [p for p in held if grids_by_id.get(p.grid_id) and grids_by_id[p.grid_id].owner_id == FOUNDER_ID]
    # phantom commissions FROM suspects to others that are NOT reversed = still live on books
    def _is_live(st):
        # statuses are suffixed, e.g. 'reversed_incident_20260603' — match by substring
        return not any(k in (st or "").lower() for k in ("revers", "void", "fail", "refund"))
    live_from = sum(d["total"] for st, d in from_bd.items() if _is_live(st))

    payload = {
        "summary": {
            "owned_grids": len(owned_grids),
            "positions_held_total": len(held),
            "positions_in_real_members_grids": len(in_real),
            "positions_in_founder_grids": len(in_founder),
            "live_phantom_commission_from_suspects_usd": round(live_from, 2),
        },
    }

    # ---- render HTML ----
    s = payload["summary"]
    verdict_clean = (s["owned_grids"] == 0 and s["positions_held_total"] == 0 and s["live_phantom_commission_from_suspects_usd"] == 0)
    verdict = ("✅ No residual grid footprint — these accounts hold no grids, no positions, and no live commissions."
               if verdict_clean else
               "⚠️ Residual grid footprint found — see below. Nothing has been changed; this is read-only.")

    def chip(label, val, warn=False):
        bg = "#fef2f2" if warn and val else "#f0f9ff"
        bd = "#fecaca" if warn and val else "#bae6fd"
        col = "#b91c1c" if warn and val else "#0c4a6e"
        return (f"<div style='flex:1;min-width:130px;background:{bg};border:1px solid {bd};"
                f"border-radius:10px;padding:12px 14px;'><div style='font-size:12px;color:#64748b;"
                f"text-transform:uppercase;letter-spacing:.5px;'>{_h.escape(label)}</div>"
                f"<div style='font-size:22px;font-weight:700;color:{col};'>{val}</div></div>")

    rows = []
    rows.append("<tr><th>id</th><th>username</th><th>active</th><th>balance</th></tr>")
    for u in suspects:
        rows.append(f"<tr><td>{u.id}</td><td>{_h.escape(u.username or '')}</td>"
                    f"<td>{'yes' if u.is_active else 'no'}</td><td>${float(u.balance or 0):.2f}</td></tr>")
    suspects_tbl = "".join(rows)

    if owned_grids:
        g_rows = ["<tr><th>grid</th><th>owner</th><th>tier</th><th>adv</th><th>filled</th><th>complete</th><th>owner_bought</th><th>revenue</th></tr>"]
        for g in owned_grids:
            g_rows.append(f"<tr><td>{g.id}</td><td>{g.owner_id}</td><td>{g.package_tier}</td>"
                          f"<td>{g.advance_number}</td><td>{g.positions_filled}</td>"
                          f"<td>{'yes' if g.is_complete else 'no'}</td>"
                          f"<td>{'yes' if g.owner_purchased else 'no'}</td>"
                          f"<td>${float(g.revenue_total or 0):.2f}</td></tr>")
        owned_tbl = "<table>" + "".join(g_rows) + "</table>"
    else:
        owned_tbl = "<p style='color:#15803d'>None — these accounts own no grids.</p>"

    if held:
        p_rows = ["<tr><th>pos</th><th>grid</th><th>grid owner</th><th>tier</th><th>lvl</th><th>seat</th><th>seat holder</th></tr>"]
        for p in held:
            g = grids_by_id.get(p.grid_id)
            ownid = g.owner_id if g else None
            oname = owner_names.get(ownid, f"#{ownid}") if ownid is not None else "?"
            flag = ""
            if ownid == FOUNDER_ID:
                flag = " style='background:#fef2f2'"
            elif ownid is not None and ownid not in synth_ids:
                flag = " style='background:#fffbeb'"
            p_rows.append(f"<tr{flag}><td>{p.id}</td><td>{p.grid_id}</td><td>{_h.escape(str(oname))} (#{ownid})</td>"
                          f"<td>{g.package_tier if g else '?'}</td><td>{p.grid_level}</td>"
                          f"<td>{p.position_num}</td><td>#{p.member_id}</td></tr>")
        held_tbl = "<table>" + "".join(p_rows) + "</table>"
        held_tbl += ("<p style='font-size:13px;color:#64748b'>Pink rows sit inside the founder's grid; "
                     "amber rows sit inside another real member's grid. These are the positions that would "
                     "move if the accounts were removed — clean them deliberately, don't hard-delete.</p>")
    else:
        held_tbl = "<p style='color:#15803d'>None — these accounts occupy no positions in any grid.</p>"

    def comm_tbl(bd, title):
        if not bd:
            return f"<p style='color:#15803d'>{title}: none.</p>"
        r = [f"<tr><th>status</th><th>count</th><th>total</th></tr>"]
        for st, d in sorted(bd.items()):
            warn = _is_live(st)
            style = " style='color:#b91c1c;font-weight:600'" if warn else " style='color:#15803d'"
            r.append(f"<tr><td{style}>{_h.escape(st)}</td><td>{d['count']}</td><td>${d['total']:.2f}</td></tr>")
        return f"<p style='font-weight:600;margin:14px 0 4px'>{title}</p><table>" + "".join(r) + "</table>"

    html_out = f"""<!doctype html><html><head><meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Grid Cleanup Audit</title>
<style>
body{{font-family:-apple-system,Segoe UI,Roboto,sans-serif;margin:0;padding:18px;background:#f4f5f7;color:#0f172a;}}
h1{{font-size:20px;margin:0 0 4px}} h2{{font-size:15px;margin:22px 0 8px;color:#1e3a8a}}
.sub{{color:#64748b;font-size:13px;margin-bottom:16px}}
.verdict{{padding:14px 16px;border-radius:10px;font-weight:600;margin-bottom:16px;
 background:{'#f0fdf4' if verdict_clean else '#fffbeb'};border:1px solid {'#86efac' if verdict_clean else '#fde68a'};
 color:{'#15803d' if verdict_clean else '#92400e'}}}
.chips{{display:flex;flex-wrap:wrap;gap:10px;margin-bottom:8px}}
table{{width:100%;border-collapse:collapse;font-size:13px;background:#fff;border-radius:8px;overflow:hidden;margin:6px 0 4px}}
th,td{{text-align:left;padding:8px 10px;border-bottom:1px solid #eef1f5}}
th{{background:#f8fafc;color:#475569;font-size:11px;text-transform:uppercase;letter-spacing:.4px}}
</style></head><body>
<h1>Grid Cleanup Audit — synthetic account footprint</h1>
<div class="sub">Read-only. Suspect IDs: {_h.escape(', '.join(str(i) for i in synth_ids))} · generated {datetime.utcnow().strftime('%Y-%m-%d %H:%M')} UTC</div>
<div class="verdict">{verdict}</div>
<div class="chips">
{chip('Grids owned', s['owned_grids'], warn=True)}
{chip('Positions held', s['positions_held_total'], warn=True)}
{chip('In real grids', s['positions_in_real_members_grids'], warn=True)}
{chip('In YOUR grid', s['positions_in_founder_grids'], warn=True)}
{chip('Live phantom $', f"${s['live_phantom_commission_from_suspects_usd']:.2f}", warn=True)}
</div>
<h2>Suspect accounts</h2><table>{suspects_tbl}</table>
<h2>Grids OWNED by suspects</h2>{owned_tbl}
<h2>Positions HELD by suspects (matrix pollution)</h2>{held_tbl}
<h2>Commissions</h2>
{comm_tbl(from_bd, 'FROM suspects → paid to others (phantom payouts; non-reversed = still live)')}
{comm_tbl(to_bd, 'TO suspects (money the synthetic accounts earned)')}
</body></html>"""

    return HTMLResponse(html_out)


@app.get("/admin/owner-grids")
def admin_owner_grids(
    user: User = Depends(get_current_user),
    owner: str = "SuperAdPro",
    db: Session = Depends(get_db),
):
    """
    READ-ONLY: every grid an owner holds across ALL tiers, with completion
    flags straight from the DB. Diagnoses 'my completed-grid stats vanished':
    /api/grid-visualiser computes completed_advances PER TIER, so a completion
    in tier X is invisible while the page is showing tier Y (it defaults to T1).
    This lists all tiers at once, plus the owner's stored earning fields and
    their commission ledger grouped by type+status. No writes.
    Usage: /admin/owner-grids?owner=SuperAdPro
    """
    _require_admin(user)
    import html as _h

    o = db.query(User).filter(User.username == owner).first()
    if not o and owner.strip().isdigit():
        o = db.query(User).filter(User.id == int(owner)).first()
    if not o:
        return HTMLResponse(f"<p>Owner '{_h.escape(owner)}' not found.</p>", status_code=404)

    grids = db.query(Grid).filter(Grid.owner_id == o.id).order_by(
        Grid.package_tier, Grid.advance_number).all()

    per_tier = {}
    for g in grids:
        d = per_tier.setdefault(g.package_tier, {"total": 0, "complete": 0})
        d["total"] += 1
        if g.is_complete:
            d["complete"] += 1
    total_complete = sum(d["complete"] for d in per_tier.values())
    complete_tiers = sorted(t for t, d in per_tier.items() if d["complete"] > 0)

    comms = db.query(Commission).filter(Commission.to_user_id == o.id).all()
    by_ts = {}
    for c in comms:
        key = (c.commission_type or "?", c.status or "?")
        d = by_ts.setdefault(key, {"count": 0, "total": 0.0})
        d["count"] += 1
        d["total"] += float(c.amount_usdt or 0)

    bal = float(getattr(o, "balance", 0) or 0)
    cb = float(getattr(o, "campaign_balance", 0) or 0)
    tot = float(getattr(o, "total_earned", 0) or 0)
    ge = float(getattr(o, "grid_earnings", 0) or 0)
    le = float(getattr(o, "level_earnings", 0) or 0)

    # Live PAID ledger sums by type (status containing revers/void/fail excluded)
    def _paid_sum(types):
        s = 0.0
        for c in comms:
            st = (c.status or "").lower()
            if any(k in st for k in ("revers", "void", "fail", "refund")):
                continue
            if (c.commission_type or "") in types:
                s += float(c.amount_usdt or 0)
        return s
    ledger_direct = _paid_sum({"direct_sponsor"})
    ledger_uni = _paid_sum({"uni_level"})
    ledger_bonus = _paid_sum({"grid_completion_bonus", "grid_completion_bonus_topup"})
    ledger_grid_total = ledger_direct + ledger_uni + ledger_bonus
    # reconciliation: counters vs ledger
    recon = [
        ("grid_earnings (direct 40%)", ge, ledger_direct, "direct_sponsor"),
        ("level_earnings (uni-level)", le, ledger_uni, "uni_level"),
    ]
    recon_drift = any(abs(stored - led) > 0.01 for _, stored, led, _ in recon)

    if total_complete > 0:
        verdict = (f"✅ {total_complete} completed grid(s) found in the DB, in tier(s) "
                   f"{', '.join('T'+str(t) for t in complete_tiers)}. The data is intact — "
                   f"the grid page defaults to T1, so select that tier tab to see these stats.")
        vclean = True
    else:
        verdict = ("⚠️ No grids flagged is_complete=True for this owner in any tier. "
                   "If you expected completions, the records themselves are missing — not just hidden by the tier view.")
        vclean = False

    def esc(x):
        return _h.escape(str(x))

    pt_rows = ["<tr><th>tier</th><th>grids</th><th>completed</th></tr>"]
    for t in sorted(per_tier.keys()):
        d = per_tier[t]
        hl = " style='background:#f0fdf4'" if d["complete"] > 0 else ""
        pt_rows.append(f"<tr{hl}><td>T{t}</td><td>{d['total']}</td><td>{d['complete']}</td></tr>")
    pt_tbl = "<table>" + "".join(pt_rows) + "</table>" if per_tier else "<p>No grids owned.</p>"

    g_rows = ["<tr><th>grid</th><th>tier</th><th>adv</th><th>filled</th><th>complete</th><th>revenue</th><th>completed_at</th></tr>"]
    for g in grids:
        hl = " style='background:#f0fdf4'" if g.is_complete else ""
        cat = g.completed_at.strftime('%Y-%m-%d') if getattr(g, "completed_at", None) else "—"
        g_rows.append(f"<tr{hl}><td>{g.id}</td><td>T{g.package_tier}</td><td>{g.advance_number}</td>"
                      f"<td>{g.positions_filled}</td><td>{'YES' if g.is_complete else 'no'}</td>"
                      f"<td>${float(g.revenue_total or 0):.2f}</td><td>{cat}</td></tr>")
    g_tbl = "<table>" + "".join(g_rows) + "</table>" if grids else "<p>No grids owned.</p>"

    c_rows = ["<tr><th>type</th><th>status</th><th>count</th><th>total</th></tr>"]
    for (ct, st), d in sorted(by_ts.items()):
        warn = not any(k in st.lower() for k in ("revers", "void", "fail", "refund"))
        col = "#0f172a" if warn else "#15803d"
        c_rows.append(f"<tr><td>{esc(ct)}</td><td style='color:{col}'>{esc(st)}</td>"
                      f"<td>{d['count']}</td><td>${d['total']:.2f}</td></tr>")
    c_tbl = "<table>" + "".join(c_rows) + "</table>" if by_ts else "<p>No commissions recorded to this owner.</p>"

    r_rows = ["<tr><th>counter</th><th>stored value</th><th>live paid ledger</th><th>match?</th></tr>"]
    for label, stored, led, _t in recon:
        ok = abs(stored - led) <= 0.01
        mark = "✅" if ok else "⚠️ diff $%.2f" % (stored - led)
        hl = "" if ok else " style='background:#fffbeb'"
        r_rows.append(f"<tr{hl}><td>{esc(label)}</td><td>${stored:.2f}</td><td>${led:.2f}</td><td>{mark}</td></tr>")
    recon_tbl = "<table>" + "".join(r_rows) + "</table>"
    recon_note = ("" if not recon_drift else
                  "<p style='font-size:13px;color:#92400e'>The stored earnings counters that feed your "
                  "displayed stats don't match the actual paid commission rows. These counters are lifetime "
                  "<em>stats</em> — your withdrawable wallets (affiliate ${:.2f} / campaign ${:.2f}) are separate "
                  "— so this is a display-accuracy issue, not a balance leak. A reconcile from the ledger fixes "
                  "the displayed figures.</p>".format(bal, cb))

    html_out = f"""<!doctype html><html><head><meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Owner Grids</title>
<style>
body{{font-family:-apple-system,Segoe UI,Roboto,sans-serif;margin:0;padding:18px;background:#f4f5f7;color:#0f172a}}
h1{{font-size:20px;margin:0 0 4px}} h2{{font-size:15px;margin:22px 0 8px;color:#1e3a8a}}
.sub{{color:#64748b;font-size:13px;margin-bottom:16px}}
.verdict{{padding:14px 16px;border-radius:10px;font-weight:600;margin-bottom:16px;
 background:{'#f0fdf4' if vclean else '#fffbeb'};border:1px solid {'#86efac' if vclean else '#fde68a'};
 color:{'#15803d' if vclean else '#92400e'}}}
.chips{{display:flex;flex-wrap:wrap;gap:10px;margin-bottom:8px}}
.chip{{flex:1;min-width:120px;background:#f0f9ff;border:1px solid #bae6fd;border-radius:10px;padding:12px 14px}}
.chip .l{{font-size:12px;color:#64748b;text-transform:uppercase;letter-spacing:.5px}}
.chip .v{{font-size:20px;font-weight:700;color:#0c4a6e}}
table{{width:100%;border-collapse:collapse;font-size:13px;background:#fff;border-radius:8px;overflow:hidden;margin:6px 0}}
th,td{{text-align:left;padding:8px 10px;border-bottom:1px solid #eef1f5}}
th{{background:#f8fafc;color:#475569;font-size:11px;text-transform:uppercase;letter-spacing:.4px}}
</style></head><body>
<h1>Owner Grids — {esc(o.username)} (#{o.id})</h1>
<div class="sub">Read-only · generated {datetime.utcnow().strftime('%Y-%m-%d %H:%M')} UTC</div>
<div class="verdict">{verdict}</div>
<div class="chips">
<div class="chip"><div class="l">Completed grids</div><div class="v">{total_complete}</div></div>
<div class="chip"><div class="l">Balance (affiliate)</div><div class="v">${bal:.2f}</div></div>
<div class="chip"><div class="l">Campaign wallet</div><div class="v">${cb:.2f}</div></div>
<div class="chip"><div class="l">Total earned</div><div class="v">${tot:.2f}</div></div>
<div class="chip"><div class="l">Grid earnings</div><div class="v">${ge:.2f}</div></div>
<div class="chip"><div class="l">Level earnings</div><div class="v">${le:.2f}</div></div>
</div>
<h2>Per-tier summary</h2>{pt_tbl}
<h2>Counters vs live ledger (what feeds your displayed earnings)</h2>{recon_tbl}{recon_note}
<h2>All grids (green = completed)</h2>{g_tbl}
<h2>Commissions credited to this owner (by type + status)</h2>{c_tbl}
</body></html>"""

    return HTMLResponse(html_out)


@app.get("/admin/earnings-reconcile")
def admin_earnings_reconcile(
    user: User = Depends(get_current_user),
    limit: int = 40,
    apply: int = 0,
    code: str = "",
    db: Session = Depends(get_db),
):
    """
    Counter vs live-ledger earnings reconciliation.

    - GET (default): READ-ONLY dry-run. Compares every user's denormalised
      counters (total_earned / grid_earnings / level_earnings) against the
      live paid ledger and reports platform-wide drift. No writes.
    - ?apply=1 (no code): shows the same impact + the instruction to add a
      2FA code. Still no writes.
    - ?apply=1&code=NNNNNN: 2FA-gated. Recomputes the three counters from the
      live paid ledger for every drifted user. Touches ONLY the stat counters
      — never balance / campaign_balance / any money field — so it cannot move
      money; worst case is a corrected stat. Idempotent.

    Scope: users with a non-zero counter (the overstated/stale cases). A user
    with zero counters but real ledger earnings is not in scope here.
    Usage: /admin/earnings-reconcile   then   ?apply=1&code=NNNNNN
    """
    _require_admin(user)
    import html as _h
    import decimal as _dec
    from sqlalchemy import func as _f

    want_apply = bool(apply)
    do_apply = want_apply and bool((code or "").strip())
    if do_apply:
        _require_admin_2fa(user, code)   # raises on missing/invalid code

    def _ledger(uid):
        led = compute_user_earnings(db, uid)
        direct = float(db.query(_f.coalesce(_f.sum(Commission.amount_usdt), 0)).filter(
            Commission.to_user_id == uid, Commission.status == 'paid',
            Commission.commission_type == 'direct_sponsor').scalar() or 0)
        uni = float(db.query(_f.coalesce(_f.sum(Commission.amount_usdt), 0)).filter(
            Commission.to_user_id == uid, Commission.status == 'paid',
            Commission.commission_type == 'uni_level').scalar() or 0)
        return float(led["total_earned"]), direct, uni

    users = db.query(User).filter(
        (User.total_earned > 0) | (User.grid_earnings > 0) | (User.level_earnings > 0)
    ).all()

    rows = []
    n_drift = 0
    sum_counter = 0.0
    sum_ledger = 0.0
    applied = 0
    for u in users:
        l_tot, l_direct, l_uni = _ledger(u.id)
        c_tot = float(u.total_earned or 0)
        c_grid = float(u.grid_earnings or 0)
        c_lvl = float(u.level_earnings or 0)
        sum_counter += c_tot
        sum_ledger += l_tot
        drift = c_tot - l_tot
        is_drift = (abs(drift) > 0.01 or abs(c_grid - l_direct) > 0.01 or abs(c_lvl - l_uni) > 0.01)
        if is_drift:
            n_drift += 1
            rows.append({
                "id": u.id, "username": u.username or "",
                "c_tot": c_tot, "l_tot": l_tot, "drift": drift,
                "c_grid": c_grid, "l_grid": l_direct,
                "c_lvl": c_lvl, "l_lvl": l_uni,
            })
            if do_apply:
                u.total_earned = _dec.Decimal(str(round(l_tot, 2)))
                u.grid_earnings = _dec.Decimal(str(round(l_direct, 2)))
                u.level_earnings = _dec.Decimal(str(round(l_uni, 2)))
                applied += 1
                try:
                    cache_invalidate_user(u.id)
                except Exception:
                    pass

    if do_apply:
        db.commit()

    rows.sort(key=lambda r: abs(r["drift"]), reverse=True)
    shown = rows[:max(1, limit)]
    total_drift = sum_counter - sum_ledger

    def esc(x):
        return _h.escape(str(x))

    if applied:
        banner = (f"<div style='padding:14px 16px;border-radius:10px;font-weight:600;margin-bottom:16px;"
                  f"background:#f0fdf4;border:1px solid #86efac;color:#15803d'>✅ Applied — reconciled "
                  f"{applied} user(s)' counters to live-ledger truth. Stat counters only; no balances touched.</div>")
    elif want_apply:
        banner = (f"<div style='padding:14px 16px;border-radius:10px;font-weight:600;margin-bottom:16px;"
                  f"background:#fffbeb;border:1px solid #fde68a;color:#92400e'>Preview only — no writes yet. "
                  f"Append <b>&amp;code=NNNNNN</b> (your authenticator code) to apply.</div>")
    else:
        banner = ""

    tr = ["<tr><th>id</th><th>user</th><th>counter total</th><th>ledger total</th><th>drift</th>"
          "<th>grid c→l</th><th>level c→l</th></tr>"]
    for r in shown:
        hl = " style='background:#fffbeb'" if abs(r["drift"]) > 0.01 else ""
        tr.append(f"<tr{hl}><td>{r['id']}</td><td>{esc(r['username'])}</td>"
                  f"<td>${r['c_tot']:.2f}</td><td>${r['l_tot']:.2f}</td>"
                  f"<td><b>{'+' if r['drift']>=0 else ''}{r['drift']:.2f}</b></td>"
                  f"<td>${r['c_grid']:.2f}→${r['l_grid']:.2f}</td>"
                  f"<td>${r['c_lvl']:.2f}→${r['l_lvl']:.2f}</td></tr>")
    tbl = "<table>" + "".join(tr) + "</table>" if shown else "<p style='color:#15803d'>No drift — counters already match the ledger.</p>"

    title = "Earnings Reconcile — applied" if applied else "Earnings Reconcile — dry-run (read-only)"
    html_out = f"""<!doctype html><html><head><meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1"><title>Earnings Reconcile</title>
<style>
body{{font-family:-apple-system,Segoe UI,Roboto,sans-serif;margin:0;padding:18px;background:#f4f5f7;color:#0f172a}}
h1{{font-size:20px;margin:0 0 4px}} .sub{{color:#64748b;font-size:13px;margin-bottom:16px}}
.chips{{display:flex;flex-wrap:wrap;gap:10px;margin-bottom:16px}}
.chip{{flex:1;min-width:120px;background:#f0f9ff;border:1px solid #bae6fd;border-radius:10px;padding:12px 14px}}
.chip .l{{font-size:12px;color:#64748b;text-transform:uppercase;letter-spacing:.5px}}
.chip .v{{font-size:20px;font-weight:700;color:#0c4a6e}}
table{{width:100%;border-collapse:collapse;font-size:13px;background:#fff;border-radius:8px;overflow:hidden}}
th,td{{text-align:left;padding:8px 10px;border-bottom:1px solid #eef1f5}}
th{{background:#f8fafc;color:#475569;font-size:11px;text-transform:uppercase;letter-spacing:.4px}}
.note{{font-size:13px;color:#64748b;margin-top:12px}}
</style></head><body>
<h1>{title}</h1>
<div class="sub">Counter vs live ledger (compute_user_earnings) · generated {datetime.utcnow().strftime('%Y-%m-%d %H:%M')} UTC</div>
{banner}
<div class="chips">
<div class="chip"><div class="l">Users w/ counters &gt; 0</div><div class="v">{len(users)}</div></div>
<div class="chip"><div class="l">Users with drift</div><div class="v">{n_drift}</div></div>
<div class="chip"><div class="l">Σ counters</div><div class="v">${sum_counter:.2f}</div></div>
<div class="chip"><div class="l">Σ ledger</div><div class="v">${sum_ledger:.2f}</div></div>
<div class="chip"><div class="l">Σ drift</div><div class="v">${total_drift:.2f}</div></div>
</div>
<p class="note">Positive drift = counter overstates the ledger (stale-counter pattern). "grid c→l" / "level c→l" show current counter → ledger value. Showing top {len(shown)} by drift size.</p>
{tbl}
</body></html>"""
    return HTMLResponse(html_out)


@app.get("/admin/commission-census")
def admin_commission_census(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """
    READ-ONLY census of the commission ledger. Groups the Commission table by
    (commission_type, status) with row counts and summed amounts, and reports
    the companion CreditMatrixCommission / CourseCommission tables. Tells us
    whether the grid commission rows (direct_sponsor / uni_level) actually
    exist in the ledger at all, or were deleted / never written — which decides
    whether the counters or the ledger is closer to truth. No writes.
    """
    _require_admin(user)
    import html as _h
    from sqlalchemy import func as _f

    grp = (db.query(Commission.commission_type, Commission.status,
                     _f.count(Commission.id), _f.coalesce(_f.sum(Commission.amount_usdt), 0))
             .group_by(Commission.commission_type, Commission.status)
             .all())
    total_rows = sum(int(r[2]) for r in grp)
    total_sum = sum(float(r[3] or 0) for r in grp)

    # companion tables
    try:
        cm_rows = int(db.query(_f.count(CreditMatrixCommission.id)).scalar() or 0)
        cm_sum = float(db.query(_f.coalesce(_f.sum(CreditMatrixCommission.amount), 0)).scalar() or 0)
    except Exception:
        cm_rows, cm_sum = -1, 0.0
    try:
        cc_rows = int(db.query(_f.count(CourseCommission.id)).scalar() or 0)
        cc_sum = float(db.query(_f.coalesce(_f.sum(CourseCommission.amount), 0)).scalar() or 0)
    except Exception:
        cc_rows, cc_sum = -1, 0.0

    def esc(x):
        return _h.escape(str(x))

    grp_sorted = sorted(grp, key=lambda r: float(r[3] or 0), reverse=True)
    tr = ["<tr><th>commission_type</th><th>status</th><th>rows</th><th>sum</th></tr>"]
    for ct, st, cnt, amt in grp_sorted:
        tr.append(f"<tr><td>{esc(ct)}</td><td>{esc(st)}</td><td>{int(cnt)}</td><td>${float(amt or 0):.2f}</td></tr>")
    tbl = "<table>" + "".join(tr) + "</table>" if grp else "<p style='color:#b91c1c;font-weight:600'>The commissions table is EMPTY.</p>"

    html_out = f"""<!doctype html><html><head><meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1"><title>Commission Census</title>
<style>
body{{font-family:-apple-system,Segoe UI,Roboto,sans-serif;margin:0;padding:18px;background:#f4f5f7;color:#0f172a}}
h1{{font-size:20px;margin:0 0 4px}} h2{{font-size:15px;margin:22px 0 8px;color:#1e3a8a}}
.sub{{color:#64748b;font-size:13px;margin-bottom:16px}}
.chips{{display:flex;flex-wrap:wrap;gap:10px;margin-bottom:16px}}
.chip{{flex:1;min-width:130px;background:#f0f9ff;border:1px solid #bae6fd;border-radius:10px;padding:12px 14px}}
.chip .l{{font-size:12px;color:#64748b;text-transform:uppercase;letter-spacing:.5px}}
.chip .v{{font-size:20px;font-weight:700;color:#0c4a6e}}
table{{width:100%;border-collapse:collapse;font-size:13px;background:#fff;border-radius:8px;overflow:hidden}}
th,td{{text-align:left;padding:8px 10px;border-bottom:1px solid #eef1f5}}
th{{background:#f8fafc;color:#475569;font-size:11px;text-transform:uppercase;letter-spacing:.4px}}
</style></head><body>
<h1>Commission Ledger Census</h1>
<div class="sub">Read-only · what actually lives in the commissions table · {datetime.utcnow().strftime('%Y-%m-%d %H:%M')} UTC</div>
<div class="chips">
<div class="chip"><div class="l">Commission rows</div><div class="v">{total_rows}</div></div>
<div class="chip"><div class="l">Σ commissions</div><div class="v">${total_sum:.2f}</div></div>
<div class="chip"><div class="l">CreditMatrix rows</div><div class="v">{cm_rows}</div></div>
<div class="chip"><div class="l">Σ CreditMatrix</div><div class="v">${cm_sum:.2f}</div></div>
<div class="chip"><div class="l">Course rows</div><div class="v">{cc_rows}</div></div>
<div class="chip"><div class="l">Σ Course</div><div class="v">${cc_sum:.2f}</div></div>
</div>
<h2>commissions — by type &amp; status</h2>{tbl}
</body></html>"""
    return HTMLResponse(html_out)


@app.get("/admin/grid-commission-rebuild")
def admin_grid_commission_rebuild(
    user: User = Depends(get_current_user),
    limit: int = 40,
    db: Session = Depends(get_db),
):
    """
    READ-ONLY reconstruction preview for the missing grid commission rows.

    Replays the locked comp plan over every real GridPosition fill:
      buyer = position.member_id, price = GRID_PACKAGES[grid.package_tier]
      direct 40% -> buyer's sponsor
      uni-level 6.25% -> each of 8 uplines in the buyer's sponsor chain
    Then compares the reconstructed per-user totals against the stored
    counters (grid_earnings = direct, level_earnings = uni) AND against the
    campaign wallet (the real money). If reconstruction ≈ counters ≈ wallet,
    the rebuild is trustworthy. No writes — this only previews.

    Note: ignores time-of-purchase qualification/escrow, so reconstruction is
    the GROSS comp-plan ideal; actuals (counters) may be lower where an upline
    was unqualified and the slot escrowed/expired. The gap is informative.
    """
    _require_admin(user)
    import html as _h
    from .database import GRID_PACKAGES, DIRECT_PCT, PER_LEVEL_PCT, UNILEVEL_DEPTH

    # Prefetch: grid tier by id, and user sponsor/counter maps (avoid N+1).
    grid_tier = {g.id: g.package_tier for g in db.query(Grid.id, Grid.package_tier).all()}
    sponsor_of = {}
    counters = {}
    for u in db.query(User.id, User.sponsor_id, User.username, User.grid_earnings,
                      User.level_earnings, User.campaign_balance).all():
        sponsor_of[u.id] = u.sponsor_id
        counters[u.id] = {
            "username": u.username or "",
            "grid": float(u.grid_earnings or 0),
            "level": float(u.level_earnings or 0),
            "campaign": float(u.campaign_balance or 0),
        }

    recon_direct = {}
    recon_uni = {}
    positions = 0
    for gp in db.query(GridPosition.member_id, GridPosition.grid_id).all():
        tier = grid_tier.get(gp.grid_id)
        if tier is None:
            continue
        price = float(GRID_PACKAGES.get(tier, 0) or 0)
        if price <= 0:
            continue
        positions += 1
        buyer = gp.member_id
        # direct 40% -> buyer's sponsor
        sp = sponsor_of.get(buyer)
        if sp:
            recon_direct[sp] = recon_direct.get(sp, 0.0) + round(price * DIRECT_PCT, 2)
        # uni-level 6.25% up the buyer's sponsor chain, 8 levels
        per_level = round(price * PER_LEVEL_PCT, 2)
        cur = buyer
        seen = {buyer}
        for _lvl in range(UNILEVEL_DEPTH):
            up = sponsor_of.get(cur)
            if not up or up in seen:
                break
            recon_uni[up] = recon_uni.get(up, 0.0) + per_level
            seen.add(up)
            cur = up

    # Per-user comparison
    uids = set(recon_direct) | set(recon_uni) | {uid for uid, c in counters.items()
                                                 if c["grid"] > 0 or c["level"] > 0}
    rows = []
    sums = {"rd": 0.0, "ru": 0.0, "cg": 0.0, "cl": 0.0, "cw": 0.0}
    for uid in uids:
        c = counters.get(uid, {"username": "", "grid": 0, "level": 0, "campaign": 0})
        rd = round(recon_direct.get(uid, 0.0), 2)
        ru = round(recon_uni.get(uid, 0.0), 2)
        rows.append({
            "id": uid, "username": c["username"],
            "rd": rd, "cg": c["grid"], "ru": ru, "cl": c["level"],
            "rtot": round(rd + ru, 2), "cw": c["campaign"],
        })
        sums["rd"] += rd; sums["ru"] += ru
        sums["cg"] += c["grid"]; sums["cl"] += c["level"]; sums["cw"] += c["campaign"]

    rows.sort(key=lambda r: r["rtot"] + r["cg"] + r["cl"], reverse=True)
    shown = rows[:max(1, limit)]

    def esc(x):
        return _h.escape(str(x))

    tr = ["<tr><th>id</th><th>user</th><th>recon direct</th><th>counter grid</th>"
          "<th>recon uni</th><th>counter level</th><th>recon total</th><th>campaign wallet</th></tr>"]
    for r in shown:
        dmark = "" if abs(r["rd"] - r["cg"]) <= 0.5 else " style='background:#fffbeb'"
        tr.append(f"<tr><td>{r['id']}</td><td>{esc(r['username'])}</td>"
                  f"<td{dmark}>${r['rd']:.2f}</td><td>${r['cg']:.2f}</td>"
                  f"<td>${r['ru']:.2f}</td><td>${r['cl']:.2f}</td>"
                  f"<td><b>${r['rtot']:.2f}</b></td><td>${r['cw']:.2f}</td></tr>")
    tbl = "<table>" + "".join(tr) + "</table>"

    html_out = f"""<!doctype html><html><head><meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1"><title>Grid Commission Rebuild (preview)</title>
<style>
body{{font-family:-apple-system,Segoe UI,Roboto,sans-serif;margin:0;padding:18px;background:#f4f5f7;color:#0f172a}}
h1{{font-size:20px;margin:0 0 4px}} .sub{{color:#64748b;font-size:13px;margin-bottom:16px}}
.chips{{display:flex;flex-wrap:wrap;gap:10px;margin-bottom:8px}}
.chip{{flex:1;min-width:120px;background:#f0f9ff;border:1px solid #bae6fd;border-radius:10px;padding:12px 14px}}
.chip .l{{font-size:12px;color:#64748b;text-transform:uppercase;letter-spacing:.5px}}
.chip .v{{font-size:18px;font-weight:700;color:#0c4a6e}}
table{{width:100%;border-collapse:collapse;font-size:13px;background:#fff;border-radius:8px;overflow:hidden}}
th,td{{text-align:left;padding:8px 10px;border-bottom:1px solid #eef1f5}}
th{{background:#f8fafc;color:#475569;font-size:11px;text-transform:uppercase;letter-spacing:.4px}}
.note{{font-size:13px;color:#64748b;margin:12px 0}}
</style></head><body>
<h1>Grid Commission Rebuild — reconstruction preview (read-only)</h1>
<div class="sub">Comp-plan replay over {positions} grid fills · {datetime.utcnow().strftime('%Y-%m-%d %H:%M')} UTC</div>
<div class="chips">
<div class="chip"><div class="l">Σ recon direct</div><div class="v">${sums['rd']:.2f}</div></div>
<div class="chip"><div class="l">Σ counter grid</div><div class="v">${sums['cg']:.2f}</div></div>
<div class="chip"><div class="l">Σ recon uni</div><div class="v">${sums['ru']:.2f}</div></div>
<div class="chip"><div class="l">Σ counter level</div><div class="v">${sums['cl']:.2f}</div></div>
<div class="chip"><div class="l">Σ recon (d+u)</div><div class="v">${sums['rd']+sums['ru']:.2f}</div></div>
<div class="chip"><div class="l">Σ campaign wallets</div><div class="v">${sums['cw']:.2f}</div></div>
</div>
<p class="note">If <b>Σ recon (d+u) ≈ Σ counters (grid+level) ≈ Σ campaign wallets</b>, the three sources agree and the rebuild is trustworthy. Amber direct cells = reconstruction differs from the counter by &gt;$0.50 (likely qualification/escrow at purchase time). Showing top {len(shown)}.</p>
{tbl}
</body></html>"""
    return HTMLResponse(html_out)


@app.get("/admin/data-census")
def admin_data_census(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """
    READ-ONLY row-count census across the financial / event tables, to see
    exactly which detail records survived and which are empty. Diagnoses the
    'counters retained, event rows gone' pattern found in commissions and
    grid positions. No writes.
    """
    _require_admin(user)
    import html as _h
    from sqlalchemy import func as _f

    targets = [
        ("User", "User"), ("Grid", "Grid"), ("GridPosition", "GridPosition"),
        ("Commission", "Commission"), ("PendingCommission", "PendingCommission"),
        ("Payment", "Payment"), ("Withdrawal", "Withdrawal"),
        ("CreditMatrix", "CreditMatrix"), ("CreditMatrixPosition", "CreditMatrixPosition"),
        ("CreditMatrixCommission", "CreditMatrixCommission"),
        ("CourseCommission", "CourseCommission"), ("CoursePurchase", "CoursePurchase"),
        ("MembershipRenewal", "MembershipRenewal"),
        ("WalletConnectPaymentOrder", "WalletConnectPaymentOrder"),
        ("NowPaymentsOrder", "NowPaymentsOrder"),
        ("VideoCampaign", "VideoCampaign"),
    ]
    g = globals()
    rows = []
    for label, modelname in targets:
        model = g.get(modelname)
        if model is None:
            rows.append((label, "—", "model not in scope"))
            continue
        try:
            cnt = int(db.query(_f.count()).select_from(model).scalar() or 0)
            rows.append((label, str(cnt), ""))
        except Exception as e:
            rows.append((label, "ERR", str(e)[:60]))

    def esc(x):
        return _h.escape(str(x))

    tr = ["<tr><th>table</th><th>rows</th><th>note</th></tr>"]
    for label, cnt, note in rows:
        hl = " style='background:#fffbeb'" if cnt == "0" else ""
        tr.append(f"<tr{hl}><td>{esc(label)}</td><td><b>{esc(cnt)}</b></td><td style='color:#64748b'>{esc(note)}</td></tr>")
    tbl = "<table>" + "".join(tr) + "</table>"

    html_out = f"""<!doctype html><html><head><meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1"><title>Data Census</title>
<style>
body{{font-family:-apple-system,Segoe UI,Roboto,sans-serif;margin:0;padding:18px;background:#f4f5f7;color:#0f172a}}
h1{{font-size:20px;margin:0 0 4px}} .sub{{color:#64748b;font-size:13px;margin-bottom:16px}}
table{{width:100%;border-collapse:collapse;font-size:14px;background:#fff;border-radius:8px;overflow:hidden}}
th,td{{text-align:left;padding:9px 12px;border-bottom:1px solid #eef1f5}}
th{{background:#f8fafc;color:#475569;font-size:11px;text-transform:uppercase;letter-spacing:.4px}}
</style></head><body>
<h1>Data Census — financial / event tables</h1>
<div class="sub">Read-only row counts · {datetime.utcnow().strftime('%Y-%m-%d %H:%M')} UTC · amber = empty</div>
{tbl}
</body></html>"""
    return HTMLResponse(html_out)


@app.get("/admin/rebuild-grid-ledger")
def admin_rebuild_grid_ledger(
    user: User = Depends(get_current_user),
    limit: int = 50,
    apply: int = 0,
    code: str = "",
    db: Session = Depends(get_db),
):
    """
    Materialise the grid-commission stream into the ledger from the surviving
    counters (the per-event detail was lost; counters are the validated truth).

    For each member with grid_earnings/level_earnings > 0, writes ONE summary
    Commission row per stream:
        direct_sponsor = grid_earnings,  uni_level = level_earnings
    status='paid', from_user_id=None, marked in notes + source_event_id as a
    reconstruction so it's identifiable/reversible. Idempotent — re-running
    skips members who already have their rebuild rows. Touches only the
    commission LEDGER (adds audit rows); never touches balances or counters.

    Excludes the known synthetic/test accounts. The membership/$10-sponsor
    stream and the founder-account turnover residual are handled separately.

    - GET: read-only dry-run (what would be written).
    - ?apply=1&code=NNNNNN: 2FA-gated write.
    """
    _require_admin(user)
    import html as _h

    MARKER = "ledger_rebuild_20260607"
    SYNTHETIC = {667, 668, 669, 670, 673, 674}

    want_apply = bool(apply)
    do_apply = want_apply and bool((code or "").strip())
    if do_apply:
        _require_admin_2fa(user, code)

    members = db.query(User).filter(
        (User.grid_earnings > 0) | (User.level_earnings > 0)
    ).all()

    rows = []
    n_rows = 0
    sum_direct = 0.0
    sum_uni = 0.0
    written = 0
    skipped = 0
    for u in members:
        if u.id in SYNTHETIC:
            continue
        ge = float(u.grid_earnings or 0)
        le = float(u.level_earnings or 0)
        planned = []
        if ge > 0:
            planned.append(("direct_sponsor", round(ge, 2)))
        if le > 0:
            planned.append(("uni_level", round(le, 2)))
        if not planned:
            continue
        rows.append({"id": u.id, "username": u.username or "", "direct": ge, "uni": le})
        sum_direct += ge
        sum_uni += le
        n_rows += len(planned)
        if do_apply:
            for ctype, amt in planned:
                sev = f"{MARKER}:{u.id}:{ctype}"
                exists = db.query(Commission.id).filter(Commission.source_event_id == sev).first()
                if exists:
                    skipped += 1
                    continue
                db.add(Commission(
                    from_user_id=None,
                    to_user_id=u.id,
                    grid_id=None,
                    amount_usdt=amt,
                    commission_type=ctype,
                    package_tier=None,
                    status="paid",
                    notes=("RECONSTRUCTED from surviving counter — original per-event "
                           "detail lost before 2026-06-07; counter-validated against "
                           "campaign wallet. See ledger rebuild."),
                    paid_at=datetime.utcnow(),
                    source_event_id=sev,
                ))
                written += 1
            try:
                cache_invalidate_user(u.id)
            except Exception:
                pass

    if do_apply:
        db.commit()

    rows.sort(key=lambda r: (r["direct"] + r["uni"]), reverse=True)
    shown = rows[:max(1, limit)]

    def esc(x):
        return _h.escape(str(x))

    if written or (do_apply):
        banner = (f"<div style='padding:14px 16px;border-radius:10px;font-weight:600;margin-bottom:16px;"
                  f"background:#f0fdf4;border:1px solid #86efac;color:#15803d'>✅ Applied — wrote {written} "
                  f"reconstructed commission row(s), skipped {skipped} already-present. Ledger only; no "
                  f"balances or counters touched.</div>")
    elif want_apply:
        banner = (f"<div style='padding:14px 16px;border-radius:10px;font-weight:600;margin-bottom:16px;"
                  f"background:#fffbeb;border:1px solid #fde68a;color:#92400e'>Preview only — no writes. "
                  f"Append <b>&amp;code=NNNNNN</b> to write the rows.</div>")
    else:
        banner = ""

    tr = ["<tr><th>id</th><th>user</th><th>direct_sponsor</th><th>uni_level</th><th>row total</th></tr>"]
    for r in shown:
        tr.append(f"<tr><td>{r['id']}</td><td>{esc(r['username'])}</td>"
                  f"<td>${r['direct']:.2f}</td><td>${r['uni']:.2f}</td>"
                  f"<td><b>${r['direct']+r['uni']:.2f}</b></td></tr>")
    tbl = "<table>" + "".join(tr) + "</table>"

    html_out = f"""<!doctype html><html><head><meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1"><title>Rebuild Grid Ledger</title>
<style>
body{{font-family:-apple-system,Segoe UI,Roboto,sans-serif;margin:0;padding:18px;background:#f4f5f7;color:#0f172a}}
h1{{font-size:20px;margin:0 0 4px}} .sub{{color:#64748b;font-size:13px;margin-bottom:16px}}
.chips{{display:flex;flex-wrap:wrap;gap:10px;margin-bottom:16px}}
.chip{{flex:1;min-width:120px;background:#f0f9ff;border:1px solid #bae6fd;border-radius:10px;padding:12px 14px}}
.chip .l{{font-size:12px;color:#64748b;text-transform:uppercase;letter-spacing:.5px}}
.chip .v{{font-size:20px;font-weight:700;color:#0c4a6e}}
table{{width:100%;border-collapse:collapse;font-size:13px;background:#fff;border-radius:8px;overflow:hidden}}
th,td{{text-align:left;padding:8px 10px;border-bottom:1px solid #eef1f5}}
th{{background:#f8fafc;color:#475569;font-size:11px;text-transform:uppercase;letter-spacing:.4px}}
.note{{font-size:13px;color:#64748b;margin:12px 0}}
</style></head><body>
<h1>Rebuild Grid Ledger — {'applied' if written else 'dry-run (read-only)'}</h1>
<div class="sub">Materialise grid_earnings→direct_sponsor, level_earnings→uni_level · {datetime.utcnow().strftime('%Y-%m-%d %H:%M')} UTC</div>
{banner}
<div class="chips">
<div class="chip"><div class="l">Members</div><div class="v">{len(rows)}</div></div>
<div class="chip"><div class="l">Rows to write</div><div class="v">{n_rows}</div></div>
<div class="chip"><div class="l">Σ direct_sponsor</div><div class="v">${sum_direct:.2f}</div></div>
<div class="chip"><div class="l">Σ uni_level</div><div class="v">${sum_uni:.2f}</div></div>
<div class="chip"><div class="l">Σ total</div><div class="v">${sum_direct+sum_uni:.2f}</div></div>
</div>
<p class="note">Excludes synthetic/test accounts. Completion bonuses already in the ledger. Membership/$10-sponsor stream and the founder-account residual handled separately. Showing top {len(shown)}.</p>
{tbl}
</body></html>"""
    return HTMLResponse(html_out)


@app.get("/admin/earnings-decompose")
def admin_earnings_decompose(
    user: User = Depends(get_current_user),
    limit: int = 60,
    db: Session = Depends(get_db),
):
    """
    Read-only. Decompose every earner's total_earned against ALL counter
    fields, then reconstruct the membership stream from real sponsor→
    active-paid-referral data ($10 monthly / $100 annual per the locked
    FLAT_SPONSOR_COMMISSION). Surfaces, per user:

        total_earned  vs  (grid+level+bonus+upline+course+marketplace)
        => membership_implied (the residual the counters can't explain)
        vs membership_reconstructed (real referrals × locked share)
        => divergence  (implied − reconstructed; large +ve = turnover/inflation)

    Sorted by |divergence| so the founder-account turnover surfaces first.
    No writes.
    """
    _require_admin(user)
    import html as _h

    earners = db.query(User).filter(User.total_earned > 0).all()

    rows = []
    tot_te = tot_acc = tot_impl = tot_recon = 0.0
    for u in earners:
        te = float(u.total_earned or 0)
        grid = float(u.grid_earnings or 0)
        level = float(u.level_earnings or 0)
        bonus = float(u.bonus_earnings or 0)
        upline = float(u.upline_earnings or 0)
        course = float(u.course_earnings or 0)
        mkt = float(u.marketplace_earnings or 0)
        accounted = grid + level + bonus + upline + course + mkt
        implied = round(te - accounted, 2)

        # reconstruct membership from real referral activations
        refs = db.query(User).filter(
            User.sponsor_id == u.id,
            User.is_active == True,  # noqa: E712
            User.membership_tier != "free",
        ).all()
        n_month = sum(1 for r in refs if (r.membership_billing or "monthly") != "annual")
        n_annual = sum(1 for r in refs if (r.membership_billing or "monthly") == "annual")
        recon = round(10.0 * n_month + 100.0 * n_annual, 2)

        divergence = round(implied - recon, 2)
        bal = float(u.balance or 0)
        wd = float(u.total_withdrawn or 0)

        rows.append({
            "id": u.id, "u": u.username or "", "te": te, "grid": grid, "level": level,
            "bonus": bonus, "upline": upline, "course": course, "mkt": mkt,
            "impl": implied, "nref": len(refs), "recon": recon, "div": divergence,
            "bal": bal, "wd": wd,
        })
        tot_te += te
        tot_acc += accounted
        tot_impl += implied
        tot_recon += recon

    rows.sort(key=lambda r: abs(r["div"]), reverse=True)
    shown = rows[:max(1, limit)]

    def esc(x):
        return _h.escape(str(x))

    def fmt(v):
        return f"${v:.2f}" if v else "·"

    tr = ["<tr><th>id</th><th>user</th><th>total_earned</th><th>grid</th><th>level</th>"
          "<th>bonus</th><th>upline</th><th>course</th><th>mkt</th><th>mem_implied</th>"
          "<th>refs</th><th>mem_recon</th><th>divergence</th><th>aff_bal</th><th>withdrawn</th></tr>"]
    for r in shown:
        dcol = "#dc2626" if abs(r["div"]) >= 20 else ("#d97706" if abs(r["div"]) >= 5 else "#16a34a")
        tr.append(
            f"<tr><td>{r['id']}</td><td>{esc(r['u'])}</td><td><b>{fmt(r['te'])}</b></td>"
            f"<td>{fmt(r['grid'])}</td><td>{fmt(r['level'])}</td><td>{fmt(r['bonus'])}</td>"
            f"<td>{fmt(r['upline'])}</td><td>{fmt(r['course'])}</td><td>{fmt(r['mkt'])}</td>"
            f"<td>{fmt(r['impl'])}</td><td>{r['nref']}</td><td>{fmt(r['recon'])}</td>"
            f"<td style='color:{dcol};font-weight:700'>{r['div']:+.2f}</td>"
            f"<td>{fmt(r['bal'])}</td><td>{fmt(r['wd'])}</td></tr>")
    tbl = "<table>" + "".join(tr) + "</table>"

    html_out = f"""<!doctype html><html><head><meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1"><title>Earnings Decompose</title>
<style>
body{{font-family:-apple-system,Segoe UI,Roboto,sans-serif;margin:0;padding:18px;background:#f4f5f7;color:#0f172a}}
h1{{font-size:20px;margin:0 0 4px}} .sub{{color:#64748b;font-size:13px;margin-bottom:16px}}
.chips{{display:flex;flex-wrap:wrap;gap:10px;margin-bottom:16px}}
.chip{{flex:1;min-width:130px;background:#f0f9ff;border:1px solid #bae6fd;border-radius:10px;padding:12px 14px}}
.chip .l{{font-size:12px;color:#64748b;text-transform:uppercase;letter-spacing:.5px}}
.chip .v{{font-size:20px;font-weight:700;color:#0c4a6e}}
table{{width:100%;border-collapse:collapse;font-size:12px;background:#fff;border-radius:8px;overflow:hidden}}
th,td{{text-align:right;padding:6px 8px;border-bottom:1px solid #eef1f5;white-space:nowrap}}
th:nth-child(2),td:nth-child(2){{text-align:left}}
th{{background:#f8fafc;color:#475569;font-size:10px;text-transform:uppercase;letter-spacing:.3px}}
.note{{font-size:13px;color:#64748b;margin:12px 0;line-height:1.5}}
.wrap{{overflow-x:auto}}
</style></head><body>
<h1>Earnings Decompose — read-only</h1>
<div class="sub">total_earned vs all counters → membership implied vs reconstructed · {datetime.utcnow().strftime('%Y-%m-%d %H:%M')} UTC</div>
<div class="chips">
<div class="chip"><div class="l">Earners</div><div class="v">{len(rows)}</div></div>
<div class="chip"><div class="l">Σ total_earned</div><div class="v">${tot_te:.2f}</div></div>
<div class="chip"><div class="l">Σ counter-accounted</div><div class="v">${tot_acc:.2f}</div></div>
<div class="chip"><div class="l">Σ mem_implied</div><div class="v">${tot_impl:.2f}</div></div>
<div class="chip"><div class="l">Σ mem_reconstructed</div><div class="v">${tot_recon:.2f}</div></div>
<div class="chip"><div class="l">Σ divergence</div><div class="v">${tot_impl-tot_recon:.2f}</div></div>
</div>
<p class="note"><b>mem_implied</b> = total_earned − (grid+level+bonus+upline+course+marketplace). <b>mem_recon</b> = $10×monthly + $100×annual active paid direct referrals. <b>divergence</b> = implied − recon: green ≈ matches (real), amber small gap, <span style="color:#dc2626">red ≥ $20</span> = unexplained inflation/turnover. Sorted by |divergence|.</p>
<div class="wrap">{tbl}</div>
</body></html>"""
    return HTMLResponse(html_out)


@app.get("/admin/withdrawal-reconcile")
def admin_withdrawal_reconcile(
    user: User = Depends(get_current_user),
    limit: int = 60,
    db: Session = Depends(get_db),
):
    """
    Read-only. Reconcile the per-user total_withdrawn COUNTER against the
    authoritative Withdrawal table (status='paid' = on-chain confirmed, real
    USDT out). Separates two very different problems:

      - counter_drift  = total_withdrawn − paid_actual
            (≠0 → the counter is wrong; NOT a money problem)
      - real_overdraw  = paid_actual − total_earned  (when > 0)
            (real USDT left the treasury beyond what the account legitimately
             earned → this is the solvency gap / breach-escape signal)

    No writes.
    """
    _require_admin(user)
    import html as _h

    # users that have either a counter or any withdrawal row
    uids = set()
    for (uid,) in db.query(User.id).filter(User.total_withdrawn > 0).all():
        uids.add(uid)
    for (uid,) in db.query(Withdrawal.user_id).distinct().all():
        if uid:
            uids.add(uid)

    rows = []
    tot_counter = tot_paid = tot_pending = tot_overdraw = 0.0
    for uid in uids:
        u = db.query(User).get(uid)
        if not u:
            continue
        counter = float(u.total_withdrawn or 0)
        te = float(u.total_earned or 0)
        # full status breakdown so 'completed' (legacy success) and failed/
        # refunded rows are all visible — no blind spot.
        srows = db.query(
            Withdrawal.status, func.count(Withdrawal.id),
            func.coalesce(func.sum(Withdrawal.amount_usdt), 0),
        ).filter(Withdrawal.user_id == uid).group_by(Withdrawal.status).all()
        smap = {(s or "?"): (int(c), float(a or 0)) for s, c, a in srows}
        real_out = sum(a for s, (c, a) in smap.items() if s in ("paid", "completed"))
        pending = sum(a for s, (c, a) in smap.items()
                      if s in ("pending", "processing", "awaiting_approval"))
        status_str = "; ".join(f"{s}×{c} ${a:.2f}" for s, (c, a) in sorted(smap.items())) or "—"
        paid = real_out
        drift = round(counter - paid, 2)
        overdraw = round(paid - te, 2)
        rows.append({
            "id": uid, "u": u.username or "", "te": te, "counter": counter,
            "paid": paid, "pending": pending, "drift": drift, "over": overdraw,
            "status": status_str,
        })
        tot_counter += counter
        tot_paid += paid
        tot_pending += pending
        if overdraw > 0:
            tot_overdraw += overdraw

    rows.sort(key=lambda r: r["over"], reverse=True)
    shown = rows[:max(1, limit)]

    def esc(x):
        return _h.escape(str(x))

    def fmt(v):
        return f"${v:.2f}" if v else "·"

    tr = ["<tr><th>id</th><th>user</th><th>total_earned</th><th>counter (total_withdrawn)</th>"
          "<th>real_out (paid+completed)</th><th>pending</th><th>counter_drift</th>"
          "<th>real_overdraw</th><th>withdrawal rows by status</th></tr>"]
    for r in shown:
        ocol = "#dc2626" if r["over"] > 0.5 else "#94a3b8"
        dcol = "#d97706" if abs(r["drift"]) > 0.5 else "#94a3b8"
        tr.append(
            f"<tr><td>{r['id']}</td><td>{esc(r['u'])}</td><td>{fmt(r['te'])}</td>"
            f"<td>{fmt(r['counter'])}</td><td><b>{fmt(r['paid'])}</b></td><td>{fmt(r['pending'])}</td>"
            f"<td style='color:{dcol}'>{r['drift']:+.2f}</td>"
            f"<td style='color:{ocol};font-weight:700'>{r['over']:+.2f}</td>"
            f"<td style='text-align:left;font-size:11px;color:#475569'>{esc(r['status'])}</td></tr>")
    tbl = "<table>" + "".join(tr) + "</table>"

    html_out = f"""<!doctype html><html><head><meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1"><title>Withdrawal Reconcile</title>
<style>
body{{font-family:-apple-system,Segoe UI,Roboto,sans-serif;margin:0;padding:18px;background:#f4f5f7;color:#0f172a}}
h1{{font-size:20px;margin:0 0 4px}} .sub{{color:#64748b;font-size:13px;margin-bottom:16px}}
.chips{{display:flex;flex-wrap:wrap;gap:10px;margin-bottom:16px}}
.chip{{flex:1;min-width:130px;background:#fef2f2;border:1px solid #fecaca;border-radius:10px;padding:12px 14px}}
.chip.ok{{background:#f0f9ff;border-color:#bae6fd}}
.chip .l{{font-size:12px;color:#64748b;text-transform:uppercase;letter-spacing:.5px}}
.chip .v{{font-size:20px;font-weight:700;color:#0c4a6e}}
table{{width:100%;border-collapse:collapse;font-size:12px;background:#fff;border-radius:8px;overflow:hidden}}
th,td{{text-align:right;padding:6px 9px;border-bottom:1px solid #eef1f5;white-space:nowrap}}
th:nth-child(2),td:nth-child(2){{text-align:left}}
th{{background:#f8fafc;color:#475569;font-size:10px;text-transform:uppercase;letter-spacing:.3px}}
.note{{font-size:13px;color:#64748b;margin:12px 0;line-height:1.5}}
.wrap{{overflow-x:auto}}
</style></head><body>
<h1>Withdrawal Reconcile — read-only</h1>
<div class="sub">total_withdrawn counter vs paid Withdrawal rows (real USDT out) · {datetime.utcnow().strftime('%Y-%m-%d %H:%M')} UTC</div>
<div class="chips">
<div class="chip ok"><div class="l">Σ counter</div><div class="v">${tot_counter:.2f}</div></div>
<div class="chip ok"><div class="l">Σ paid_actual (real out)</div><div class="v">${tot_paid:.2f}</div></div>
<div class="chip ok"><div class="l">Σ pending</div><div class="v">${tot_pending:.2f}</div></div>
<div class="chip"><div class="l">Σ counter drift</div><div class="v">${tot_counter-tot_paid:.2f}</div></div>
<div class="chip"><div class="l">Σ real overdraw</div><div class="v">${tot_overdraw:.2f}</div></div>
</div>
<p class="note"><b>counter_drift</b> = total_withdrawn − paid_actual (≠0 means the counter is wrong, not the money). <b>real_overdraw</b> = paid_actual − total_earned when positive: <span style="color:#dc2626">real USDT that left the treasury beyond legitimate earnings</span> — this column summed is the true solvency gap. Sorted by real_overdraw.</p>
<div class="wrap">{tbl}</div>
</body></html>"""
    return HTMLResponse(html_out)


@app.get("/admin/rebuild-bonus-ledger")
def admin_rebuild_bonus_ledger(
    user: User = Depends(get_current_user),
    apply: int = 0,
    code: str = "",
    db: Session = Depends(get_db),
):
    """
    Materialise the grid-completion-bonus stream gap. The grid-stream rebuild
    handled direct_sponsor + uni_level but NOT the completion bonus; only the
    owner account's $144 bonus was ever in the ledger. richard1980 ($72),
    success ($72) etc. carry bonus_earnings on the counter with no ledger row,
    so compute_user_earnings under-reports them.

    For each owner with bonus_earnings > 0, writes a grid_completion_bonus row
    for the GAP (bonus_earnings − existing ledger bonus of both
    grid_completion_bonus + grid_completion_bonus_topup), so it can never
    double-count an owner who already has bonus rows (e.g. the owner account's
    $144 → gap $0 → skipped). Idempotent via source_event_id; ledger only.

    - GET: dry-run.  ?apply=1&code=NNNNNN: 2FA-gated write.
    """
    _require_admin(user)
    import html as _h

    MARKER = "ledger_rebuild_20260607"
    SYNTHETIC = {667, 668, 669, 670, 673, 674}
    BONUS_TYPES = ["grid_completion_bonus", "grid_completion_bonus_topup"]

    want_apply = bool(apply)
    do_apply = want_apply and bool((code or "").strip())
    if do_apply:
        _require_admin_2fa(user, code)

    owners = db.query(User).filter(User.bonus_earnings > 0).all()

    rows = []
    written = skipped = 0
    sum_gap = 0.0
    for u in owners:
        if u.id in SYNTHETIC:
            continue
        counter = float(u.bonus_earnings or 0)
        existing = float(db.query(func.coalesce(func.sum(Commission.amount_usdt), 0)).filter(
            Commission.to_user_id == u.id,
            Commission.status == "paid",
            Commission.commission_type.in_(BONUS_TYPES),
        ).scalar() or 0)
        gap = round(counter - existing, 2)
        rows.append({"id": u.id, "u": u.username or "", "counter": counter,
                     "existing": existing, "gap": gap})
        if gap > 0.01:
            sum_gap += gap
            if do_apply:
                sev = f"{MARKER}:{u.id}:bonus"
                if db.query(Commission.id).filter(Commission.source_event_id == sev).first():
                    skipped += 1
                    continue
                db.add(Commission(
                    from_user_id=None, to_user_id=u.id, grid_id=None,
                    amount_usdt=gap, commission_type="grid_completion_bonus",
                    package_tier=None, status="paid",
                    notes=("RECONSTRUCTED completion-bonus gap from surviving "
                           "bonus_earnings counter — original per-event detail lost "
                           "before 2026-06-07. Gap = counter − existing ledger bonus."),
                    paid_at=datetime.utcnow(), source_event_id=sev,
                ))
                written += 1
                try:
                    cache_invalidate_user(u.id)
                except Exception:
                    pass
    if do_apply:
        db.commit()

    rows.sort(key=lambda r: r["gap"], reverse=True)

    def esc(x):
        return _h.escape(str(x))

    if written or do_apply:
        banner = (f"<div style='padding:14px 16px;border-radius:10px;font-weight:600;margin-bottom:16px;"
                  f"background:#f0fdf4;border:1px solid #86efac;color:#15803d'>✅ Applied — wrote {written} "
                  f"bonus row(s), skipped {skipped}. Ledger only.</div>")
    elif want_apply:
        banner = (f"<div style='padding:14px 16px;border-radius:10px;font-weight:600;margin-bottom:16px;"
                  f"background:#fffbeb;border:1px solid #fde68a;color:#92400e'>Preview only — append "
                  f"<b>&amp;code=NNNNNN</b> to write.</div>")
    else:
        banner = ""

    tr = ["<tr><th>id</th><th>user</th><th>bonus_earnings</th><th>in ledger</th><th>gap to write</th></tr>"]
    for r in rows:
        gcol = "#16a34a" if r["gap"] > 0.01 else "#94a3b8"
        tr.append(f"<tr><td>{r['id']}</td><td>{esc(r['u'])}</td><td>${r['counter']:.2f}</td>"
                  f"<td>${r['existing']:.2f}</td>"
                  f"<td style='color:{gcol};font-weight:700'>${r['gap']:.2f}</td></tr>")
    tbl = "<table>" + "".join(tr) + "</table>"

    html_out = f"""<!doctype html><html><head><meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1"><title>Rebuild Bonus Ledger</title>
<style>
body{{font-family:-apple-system,Segoe UI,Roboto,sans-serif;margin:0;padding:18px;background:#f4f5f7;color:#0f172a}}
h1{{font-size:20px;margin:0 0 4px}} .sub{{color:#64748b;font-size:13px;margin-bottom:16px}}
.chips{{display:flex;gap:10px;margin-bottom:16px}}
.chip{{flex:1;background:#f0f9ff;border:1px solid #bae6fd;border-radius:10px;padding:12px 14px}}
.chip .l{{font-size:12px;color:#64748b;text-transform:uppercase}} .chip .v{{font-size:20px;font-weight:700;color:#0c4a6e}}
table{{width:100%;border-collapse:collapse;font-size:13px;background:#fff;border-radius:8px;overflow:hidden}}
th,td{{text-align:left;padding:8px 10px;border-bottom:1px solid #eef1f5}}
th{{background:#f8fafc;color:#475569;font-size:11px;text-transform:uppercase}}
</style></head><body>
<h1>Rebuild Bonus Ledger — {'applied' if written else 'dry-run'}</h1>
<div class="sub">grid_completion_bonus gap (counter − existing) · {datetime.utcnow().strftime('%Y-%m-%d %H:%M')} UTC</div>
{banner}
<div class="chips">
<div class="chip"><div class="l">Owners</div><div class="v">{len(rows)}</div></div>
<div class="chip"><div class="l">Σ gap to write</div><div class="v">${sum_gap:.2f}</div></div>
</div>
{tbl}
</body></html>"""
    return HTMLResponse(html_out)


@app.get("/admin/fix-withdrawn-counter")
def admin_fix_withdrawn_counter(
    user: User = Depends(get_current_user),
    apply: int = 0,
    code: str = "",
    db: Session = Depends(get_db),
):
    """
    Correct the total_withdrawn COUNTER to equal real on-chain withdrawals
    (status in paid/completed). The reconcile proved $941.74 of counter drift
    on six legit accounts whose total_withdrawn claims withdrawals with ZERO
    backing Withdrawal rows — bad data, no money. This sets the counter to
    truth. Accounts already reconciled (owner, attackers) are untouched.
    Counter-only — never touches balance, total_earned, or any money field.

    - GET: dry-run.  ?apply=1&code=NNNNNN: 2FA-gated write.
    """
    _require_admin(user)
    import html as _h

    want_apply = bool(apply)
    do_apply = want_apply and bool((code or "").strip())
    if do_apply:
        _require_admin_2fa(user, code)

    uids = set()
    for (uid,) in db.query(User.id).filter(User.total_withdrawn > 0).all():
        uids.add(uid)

    rows = []
    fixed = 0
    sum_removed = 0.0
    for uid in uids:
        u = db.query(User).get(uid)
        if not u:
            continue
        counter = float(u.total_withdrawn or 0)
        real_out = float(db.query(func.coalesce(func.sum(Withdrawal.amount_usdt), 0)).filter(
            Withdrawal.user_id == uid,
            Withdrawal.status.in_(["paid", "completed"])).scalar() or 0)
        delta = round(counter - real_out, 2)
        if abs(delta) <= 0.01:
            continue
        rows.append({"id": uid, "u": u.username or "", "from": counter,
                     "to": real_out, "delta": delta})
        sum_removed += delta
        if do_apply:
            u.total_withdrawn = real_out
            fixed += 1
            try:
                cache_invalidate_user(uid)
            except Exception:
                pass
    if do_apply:
        db.commit()

    rows.sort(key=lambda r: abs(r["delta"]), reverse=True)

    def esc(x):
        return _h.escape(str(x))

    if fixed or do_apply:
        banner = (f"<div style='padding:14px 16px;border-radius:10px;font-weight:600;margin-bottom:16px;"
                  f"background:#f0fdf4;border:1px solid #86efac;color:#15803d'>✅ Applied — corrected {fixed} "
                  f"counter(s), removed ${sum_removed:.2f} of phantom withdrawn. No money touched.</div>")
    elif want_apply:
        banner = (f"<div style='padding:14px 16px;border-radius:10px;font-weight:600;margin-bottom:16px;"
                  f"background:#fffbeb;border:1px solid #fde68a;color:#92400e'>Preview only — append "
                  f"<b>&amp;code=NNNNNN</b> to write.</div>")
    else:
        banner = ""

    tr = ["<tr><th>id</th><th>user</th><th>counter now</th><th>real paid</th><th>phantom removed</th></tr>"]
    for r in rows:
        tr.append(f"<tr><td>{r['id']}</td><td>{esc(r['u'])}</td><td>${r['from']:.2f}</td>"
                  f"<td><b>${r['to']:.2f}</b></td>"
                  f"<td style='color:#dc2626;font-weight:700'>−${r['delta']:.2f}</td></tr>")
    tbl = "<table>" + "".join(tr) + "</table>"

    html_out = f"""<!doctype html><html><head><meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1"><title>Fix Withdrawn Counter</title>
<style>
body{{font-family:-apple-system,Segoe UI,Roboto,sans-serif;margin:0;padding:18px;background:#f4f5f7;color:#0f172a}}
h1{{font-size:20px;margin:0 0 4px}} .sub{{color:#64748b;font-size:13px;margin-bottom:16px}}
.chips{{display:flex;gap:10px;margin-bottom:16px}}
.chip{{flex:1;background:#f0f9ff;border:1px solid #bae6fd;border-radius:10px;padding:12px 14px}}
.chip .l{{font-size:12px;color:#64748b;text-transform:uppercase}} .chip .v{{font-size:20px;font-weight:700;color:#0c4a6e}}
table{{width:100%;border-collapse:collapse;font-size:13px;background:#fff;border-radius:8px;overflow:hidden}}
th,td{{text-align:left;padding:8px 10px;border-bottom:1px solid #eef1f5}}
th{{background:#f8fafc;color:#475569;font-size:11px;text-transform:uppercase}}
</style></head><body>
<h1>Fix Withdrawn Counter — {'applied' if fixed else 'dry-run'}</h1>
<div class="sub">total_withdrawn → real paid (paid+completed) · {datetime.utcnow().strftime('%Y-%m-%d %H:%M')} UTC</div>
{banner}
<div class="chips">
<div class="chip"><div class="l">Accounts to fix</div><div class="v">{len(rows)}</div></div>
<div class="chip"><div class="l">Σ phantom removed</div><div class="v">${sum_removed:.2f}</div></div>
</div>
{tbl}
</body></html>"""
    return HTMLResponse(html_out)


@app.get("/admin/rebuild-membership-ledger")
def admin_rebuild_membership_ledger(
    user: User = Depends(get_current_user),
    limit: int = 60,
    apply: int = 0,
    code: str = "",
    db: Session = Depends(get_db),
):
    """
    Final rebuild stream: materialise the membership residual. Each real
    earner's membership earnings = total_earned − (grid+level+bonus+upline+
    course+marketplace counters), which is the surviving known-good value
    (post the 31-May restore). Membership has no dedicated counter, so it
    lives as this residual. Writes a membership_sponsor reconstructed row for
    the GAP (residual − existing ledger membership) so it can't double-count
    any membership rows already present. Idempotent, ledger only, synthetic
    accounts excluded.

    - GET: dry-run.  ?apply=1&code=NNNNNN: 2FA-gated write.
    """
    _require_admin(user)
    import html as _h

    MARKER = "ledger_rebuild_20260607"
    SYNTHETIC = {667, 668, 669, 670, 673, 674}
    MEM_TYPES = ["membership", "membership_renewal", "membership_sponsor",
                 "Membership Sponsor", "gift_membership_sponsor"]

    want_apply = bool(apply)
    do_apply = want_apply and bool((code or "").strip())
    if do_apply:
        _require_admin_2fa(user, code)

    earners = db.query(User).filter(User.total_earned > 0).all()

    rows = []
    written = skipped = 0
    sum_gap = 0.0
    for u in earners:
        if u.id in SYNTHETIC:
            continue
        te = float(u.total_earned or 0)
        accounted = (float(u.grid_earnings or 0) + float(u.level_earnings or 0)
                     + float(u.bonus_earnings or 0) + float(u.upline_earnings or 0)
                     + float(u.course_earnings or 0) + float(u.marketplace_earnings or 0))
        residual = round(te - accounted, 2)
        existing = float(db.query(func.coalesce(func.sum(Commission.amount_usdt), 0)).filter(
            Commission.to_user_id == u.id,
            Commission.status == "paid",
            Commission.commission_type.in_(MEM_TYPES),
        ).scalar() or 0)
        gap = round(residual - existing, 2)
        if residual <= 0.01 and existing <= 0.01:
            continue
        rows.append({"id": u.id, "u": u.username or "", "residual": residual,
                     "existing": existing, "gap": gap})
        if gap > 0.01:
            sum_gap += gap
            if do_apply:
                sev = f"{MARKER}:{u.id}:membership"
                if db.query(Commission.id).filter(Commission.source_event_id == sev).first():
                    skipped += 1
                    continue
                db.add(Commission(
                    from_user_id=None, to_user_id=u.id, grid_id=None,
                    amount_usdt=gap, commission_type="membership_sponsor",
                    package_tier=0, status="paid",
                    notes=("RECONSTRUCTED membership residual from surviving "
                           "known-good counter (total_earned − grid/level/bonus) — "
                           "per-event detail lost before 2026-06-07 (post 31-May restore)."),
                    paid_at=datetime.utcnow(), source_event_id=sev,
                ))
                written += 1
                try:
                    cache_invalidate_user(u.id)
                except Exception:
                    pass
    if do_apply:
        db.commit()

    rows.sort(key=lambda r: r["gap"], reverse=True)
    shown = rows[:max(1, limit)]

    def esc(x):
        return _h.escape(str(x))

    if written or do_apply:
        banner = (f"<div style='padding:14px 16px;border-radius:10px;font-weight:600;margin-bottom:16px;"
                  f"background:#f0fdf4;border:1px solid #86efac;color:#15803d'>✅ Applied — wrote {written} "
                  f"membership row(s), skipped {skipped}. Ledger only.</div>")
    elif want_apply:
        banner = (f"<div style='padding:14px 16px;border-radius:10px;font-weight:600;margin-bottom:16px;"
                  f"background:#fffbeb;border:1px solid #fde68a;color:#92400e'>Preview only — append "
                  f"<b>&amp;code=NNNNNN</b> to write.</div>")
    else:
        banner = ""

    tr = ["<tr><th>id</th><th>user</th><th>membership residual</th><th>already in ledger</th><th>gap to write</th></tr>"]
    for r in shown:
        gcol = "#16a34a" if r["gap"] > 0.01 else "#94a3b8"
        tr.append(f"<tr><td>{r['id']}</td><td>{esc(r['u'])}</td><td>${r['residual']:.2f}</td>"
                  f"<td>${r['existing']:.2f}</td>"
                  f"<td style='color:{gcol};font-weight:700'>${r['gap']:.2f}</td></tr>")
    tbl = "<table>" + "".join(tr) + "</table>"

    html_out = f"""<!doctype html><html><head><meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1"><title>Rebuild Membership Ledger</title>
<style>
body{{font-family:-apple-system,Segoe UI,Roboto,sans-serif;margin:0;padding:18px;background:#f4f5f7;color:#0f172a}}
h1{{font-size:20px;margin:0 0 4px}} .sub{{color:#64748b;font-size:13px;margin-bottom:16px}}
.chips{{display:flex;gap:10px;margin-bottom:16px}}
.chip{{flex:1;background:#f0f9ff;border:1px solid #bae6fd;border-radius:10px;padding:12px 14px}}
.chip .l{{font-size:12px;color:#64748b;text-transform:uppercase}} .chip .v{{font-size:20px;font-weight:700;color:#0c4a6e}}
table{{width:100%;border-collapse:collapse;font-size:13px;background:#fff;border-radius:8px;overflow:hidden}}
th,td{{text-align:left;padding:8px 10px;border-bottom:1px solid #eef1f5}}
th{{background:#f8fafc;color:#475569;font-size:11px;text-transform:uppercase}}
</style></head><body>
<h1>Rebuild Membership Ledger — {'applied' if written else 'dry-run'}</h1>
<div class="sub">membership residual (total_earned − counters) → membership_sponsor · {datetime.utcnow().strftime('%Y-%m-%d %H:%M')} UTC</div>
{banner}
<div class="chips">
<div class="chip"><div class="l">Earners</div><div class="v">{len(rows)}</div></div>
<div class="chip"><div class="l">Σ gap to write</div><div class="v">${sum_gap:.2f}</div></div>
</div>
{tbl}
</body></html>"""
    return HTMLResponse(html_out)


@app.get("/admin/restore-backup")
def admin_restore_backup(
    user: User = Depends(get_current_user),
    file: str = "",
    table: str = "",
    apply: int = 0,
    code: str = "",
):
    """
    Insert-missing restore of ONE table from an R2 backup. Safe by design: only
    rows whose primary key is absent from the live table get inserted
    (ON CONFLICT DO NOTHING) — surviving rows are never overwritten or deleted.

    - GET with no file/table: lists available backups + usage.
    - GET ?file=...&table=...: dry-run (rows in backup, live now, would insert).
    - GET ?file=...&table=...&apply=1&code=NNNNNN: 2FA-gated write.
    """
    _require_admin(user)
    from .db_backup import restore_table, list_backups

    do_apply = bool(apply) and bool((code or "").strip())
    if do_apply:
        _require_admin_2fa(user, code)

    if not file or not table:
        return JSONResponse({
            "usage": "Dry-run: /admin/restore-backup?file=<backup.json.gz>&table=<name>  |  "
                     "Apply: add &apply=1&code=NNNNNN (2FA). Insert-missing only — never overwrites.",
            "available_backups": list_backups(),
        })

    return JSONResponse(restore_table(file, table, do_apply=do_apply))


@app.get("/admin/restamp-rebuild-rows")
def admin_restamp_rebuild_rows(
    user: User = Depends(get_current_user),
    apply: int = 0,
    code: str = "",
    db: Session = Depends(get_db),
):
    """
    Backdate tonight's reconstructed commission rows (source_event_id LIKE
    'ledger_rebuild_20260607%') from 'now' to the 31-May known-good date.
    They were stamped at insertion time, which makes lifetime-aggregate
    historical earnings look like today's activity — tripping the 24h
    unqualified-commission and financial_sanity windows. Sets created_at and
    paid_at to 2026-05-31 so the ledger reflects when the earnings actually
    belong. Earnings totals are unaffected (compute_user_earnings filters by
    status, not date). Dry-run default; 2FA-gated apply.
    """
    _require_admin(user)
    from datetime import datetime as _dt

    want_apply = bool(apply)
    do_apply = want_apply and bool((code or "").strip())
    if do_apply:
        _require_admin_2fa(user, code)

    target = _dt(2026, 5, 31, 0, 0, 0)
    rows = (db.query(Commission)
            .filter(Commission.source_event_id.like("ledger_rebuild_20260607%"))
            .all())

    n = len(rows)
    total = round(sum(float(r.amount_usdt or 0) for r in rows), 2)
    by_type = {}
    for r in rows:
        by_type[r.commission_type] = by_type.get(r.commission_type, 0) + 1

    updated = 0
    if do_apply:
        for r in rows:
            r.created_at = target
            r.paid_at = target
            updated += 1
        db.commit()

    return JSONResponse({
        "matched": n,
        "total_usd": total,
        "by_type": by_type,
        "target_date": target.isoformat(),
        "applied": bool(do_apply),
        "updated": updated,
        "note": ("Dry-run — append &apply=1&code=NNNNNN to backdate."
                 if not do_apply else
                 "Reconstructed rows backdated to 2026-05-31. Re-run "
                 "/admin/unqualified-commissions or financial_sanity to confirm clear."),
    })


@app.get("/admin/secwatch-status")
def admin_secwatch_status(
    user: User = Depends(get_current_user),
    test: int = 0,
    db: Session = Depends(get_db),
):
    """
    Session-authed health check for the security watchdog (no CRON_SECRET
    needed). Shows whether the watchdog is keeping up with reality and whether
    the alert email channel works:
      - baseline (secwatch_last_withdrawal_id) vs current max Withdrawal id:
        if baseline < max, the watchdog has NOT processed the latest
        withdrawal (daemon not ticking, or last cycle failed to advance).
      - dry-run of run_security_watch: what events are currently pending.
      - ?test=1 fires a real test alert through _secwatch_send_alert to prove
        the email channel end-to-end.
    """
    _require_admin(user)
    baseline = int(_secwatch_get(db, "secwatch_last_withdrawal_id", "0") or "0")
    cur_max = int(db.query(func.max(Withdrawal.id)).scalar() or 0)
    # Heartbeat: how long since the daemon last completed a lock-held tick.
    import time as _time
    last_tick_raw = _secwatch_get(db, "secwatch_last_tick_ts", "")
    secs_since_tick = None
    if last_tick_raw:
        try:
            secs_since_tick = round(_time.time() - float(last_tick_raw), 1)
        except (ValueError, TypeError):
            secs_since_tick = None
    res = run_security_watch(db, dry=True)
    # Advisory-lock probe: is the daemon's coordination lock (1885347292)
    # currently held by ANY session? Held + stale heartbeat = a stuck lock
    # left by a killed process (the self-heal case). Not held + stale = the
    # daemon thread itself isn't running (a different fault).
    try:
        from sqlalchemy import text as _text
        lock_holders = db.execute(_text(
            "SELECT count(*) FROM pg_locks WHERE locktype='advisory' AND objid=:o"
        ), {"o": 1885347292}).scalar()
    except Exception:
        lock_holders = None
    out = {
        "baseline_last_withdrawal_id": baseline,
        "current_max_withdrawal_id": cur_max,
        "watchdog_behind": cur_max > baseline,
        "seconds_since_last_tick": secs_since_tick,
        "daemon_alive": (secs_since_tick is not None and secs_since_tick < 150),
        "advisory_lock_holders": lock_holders,
        "dry_run_pending_events": res.get("events"),
        "pending_detail": res.get("detail"),
        "treasury_read_ok": res.get("treasury_usdt") is not None,
        "treasury_usdt": res.get("treasury_usdt"),
        "inproc_enabled": os.environ.get("SECWATCH_INPROC_ENABLED", "true").lower() == "true",
    }
    if test:
        ok = _secwatch_send_alert([
            "<strong>TEST ALERT</strong> — manual /admin/secwatch-status?test=1 "
            "channel check. If you received this, watchdog email delivery works."
        ])
        out["test_email_sent_ok"] = bool(ok)
    return JSONResponse(out)
