@app.get("/api/pay-it-forward/dashboard")
async def api_pif_dashboard(user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """Get Pay It Forward dashboard data for the current user.

    Returns three layers of analytics for the gifter:

      1. Top-line stats — gifts created, claims, click-throughs, chain
         depth, dollars earned-back from gifted recipients' downstream
         activity (the marketing-relevant headline number).

      2. Per-voucher breakdown — for each voucher: status, click count,
         first-click time, and (if claimed) what the recipient has done
         since (tier active, total earned, did they PIF themselves).

      3. Funnel signals — Click→Claim conversion rate, time-to-claim
         distribution. Gives the gifter actionable data on whether the
         share message is working vs. whether the landing page is.
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    from .database import GiftVoucher

    # My vouchers (given)
    my_vouchers = db.query(GiftVoucher).filter(GiftVoucher.gifter_user_id == user.id).order_by(GiftVoucher.created_at.desc()).all()

    # Voucher I received (if any)
    received = db.query(GiftVoucher).filter(GiftVoucher.claimed_by_user_id == user.id).first()

    # Stats
    total_gifted = len(my_vouchers)
    total_claimed = sum(1 for v in my_vouchers if v.status == "claimed")
    available = sum(1 for v in my_vouchers if v.status == "available")
    total_clicks = sum((v.link_clicks or 0) for v in my_vouchers)
    # Vouchers that have been clicked but NOT yet claimed — the
    # "interested but didn't convert" bucket. Useful for follow-up
    # nudges to the recipient.
    clicked_not_claimed = sum(
        1 for v in my_vouchers
        if v.status == "available" and (v.link_clicks or 0) > 0
    )

    # Chain depth — how far has my gifting chain gone?
    max_depth = 0
    for v in my_vouchers:
        if v.status == "claimed":
            child = db.query(GiftVoucher).filter(GiftVoucher.parent_voucher_id == v.id).first()
            depth = v.pif_chain_depth
            if child:
                depth = child.pif_chain_depth
            if depth > max_depth:
                max_depth = depth

    # ── Earned-back: commissions I've received from people I gifted ──
    # The headline marketing number: "I gifted N people and earned $X
    # back through their downstream activity." Sum paid commissions
    # where the from-user is one of my claimed-voucher recipients,
    # ACROSS ALL 3 commission tables.
    # Bug fixed 7 May 2026: previously only summed Commission. If a
    # giftee bought credit packs (paying matrix commissions to the
    # gifter) or courses (paying course commissions), those weren't
    # counted in the earned-back stat — significantly under-reporting
    # the gift's actual ROI to the gifter.
    giftee_ids = [v.claimed_by_user_id for v in my_vouchers if v.claimed_by_user_id]
    earned_back = 0.0
    if giftee_ids:
        from sqlalchemy import func as _func
        earned_back_grid = float(db.query(_func.coalesce(_func.sum(Commission.amount_usdt), 0)).filter(
            Commission.to_user_id == user.id,
            Commission.from_user_id.in_(giftee_ids),
            Commission.status == "paid",
        ).scalar() or 0)
        earned_back_matrix = float(db.query(_func.coalesce(_func.sum(CreditMatrixCommission.amount), 0)).filter(
            CreditMatrixCommission.earner_id == user.id,
            CreditMatrixCommission.from_user_id.in_(giftee_ids),
            CreditMatrixCommission.status == "paid",
        ).scalar() or 0)
        earned_back_course = float(db.query(_func.coalesce(_func.sum(CourseCommission.amount), 0)).filter(
            CourseCommission.earner_id == user.id,
            CourseCommission.buyer_id.in_(giftee_ids),
        ).scalar() or 0)
        earned_back = earned_back_grid + earned_back_matrix + earned_back_course

    # Can pay from wallet?
    can_pay_from_wallet = float(user.balance or 0) >= 20

    vouchers_list = []
    for v in my_vouchers:
        claimed_user = None
        recipient_activity = None
        if v.claimed_by_user_id:
            cu = db.query(User).filter(User.id == v.claimed_by_user_id).first()
            if cu:
                claimed_user = {"username": cu.username, "first_name": cu.first_name}
                # ── Per-recipient activity snapshot (the success story) ──
                # Did they activate beyond the gifted membership? Earn
                # anything? Pay it forward themselves? These three
                # signals tell the gifter whether their gift "took",
                # which is the fuel for personal marketing case studies.
                recipient_total_earned = compute_user_earnings(db, cu.id)["total_earned"]
                did_pif = db.query(GiftVoucher).filter(
                    GiftVoucher.gifter_user_id == cu.id
                ).first() is not None
                # Tier active = they have an active grid (Tier 1+) — i.e.
                # they put real skin in beyond the gifted free membership.
                from .database import Grid
                has_active_grid = db.query(Grid).filter(
                    Grid.owner_id == cu.id, Grid.is_complete == False
                ).first() is not None
                recipient_activity = {
                    "tier_active": has_active_grid,
                    "total_earned": float(recipient_total_earned or 0),
                    "did_pif": did_pif,
                    "is_active_member": bool(cu.is_active),
                }
        vouchers_list.append({
            "id": v.id,
            "code": v.voucher_code,
            "gift_type": v.gift_type,
            "gift_value": float(v.gift_value),
            "recipient_name": v.recipient_name,
            "personal_message": v.personal_message,
            "is_free_voucher": v.is_free_voucher,
            "status": v.status,
            "claimed_by": claimed_user,
            "claimed_at": v.claimed_at.isoformat() if v.claimed_at else None,
            "created_at": v.created_at.isoformat() if v.created_at else None,
            "chain_depth": v.pif_chain_depth,
            "link": f"https://www.superadpro.com/gift/{v.voucher_code}",
            # Click analytics
            "link_clicks":      v.link_clicks or 0,
            "first_clicked_at": v.first_clicked_at.isoformat() if v.first_clicked_at else None,
            "last_clicked_at":  v.last_clicked_at.isoformat() if v.last_clicked_at else None,
            # Per-recipient downstream activity (claimed vouchers only)
            "recipient_activity": recipient_activity,
        })

    return {
        "vouchers": vouchers_list,
        "stats": {
            "total_gifted": total_gifted,
            "total_claimed": total_claimed,
            "available": available,
            "max_chain_depth": max_depth,
            # New analytics surface (2 May 2026)
            "total_clicks":          total_clicks,
            "clicked_not_claimed":   clicked_not_claimed,
            "earned_back":           earned_back,
        },
        "received_gift": {
            "gifter_name": None,
            "message": None,
        } if not received else {
            "gifter_name": db.query(User).filter(User.id == received.gifter_user_id).first().first_name if received else None,
            "message": received.personal_message,
        },
        "can_pay_from_wallet": can_pay_from_wallet,
        "wallet_balance": float(user.balance or 0),
    }
@app.post("/api/pay-it-forward/create")
async def api_pif_create(request: Request, user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """Create a new gift voucher. Payment via wallet balance or crypto."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    if not user.is_active and not user.is_admin:
        return JSONResponse({"error": "You must be an active member to gift a membership"}, status_code=403)

    from .database import GiftVoucher

    body = await request.json()
    recipient_name = (body.get("recipient_name") or "").strip()[:100]
    personal_message = (body.get("personal_message") or "").strip()[:500]
    pay_method = body.get("pay_method", "wallet")  # wallet or crypto

    # Rate limit — max 10 active vouchers
    active_count = db.query(GiftVoucher).filter(
        GiftVoucher.gifter_user_id == user.id,
        GiftVoucher.status == "available"
    ).count()
    if active_count >= 10:
        return JSONResponse({"error": "Maximum 10 unclaimed vouchers at a time. Wait for some to be claimed."}, status_code=429)

    if pay_method == "wallet":
        if float(user.balance or 0) < 20:
            return JSONResponse({"error": "Insufficient wallet balance. You need at least $20."}, status_code=400)
        # Deduct from wallet
        user.balance = float(user.balance or 0) - 20
        db.commit()
        # Cache invalidation — buyer's balance just decreased by $20
        try:
            cache_invalidate_user(user.id)
        except Exception as e:
            logger.warning(f"cache_invalidate_user({user.id}) failed in PIF wallet deduction: {e}")
        payment_ref = f"wallet_deduction_{user.id}_{int(datetime.utcnow().timestamp())}"
    elif pay_method == "crypto":
        # Create voucher in pending state, then create NOWPayments invoice
        received = db.query(GiftVoucher).filter(GiftVoucher.claimed_by_user_id == user.id).first()
        parent_id = received.id if received else None
        chain_depth = (received.pif_chain_depth + 1) if received else 1

        for _ in range(10):
            code = _generate_voucher_code()
            existing = db.query(GiftVoucher).filter(GiftVoucher.voucher_code == code).first()
            if not existing:
                break
        else:
            return JSONResponse({"error": "Could not generate unique code. Try again."}, status_code=500)

        voucher = GiftVoucher(
            gifter_user_id=user.id,
            voucher_code=code,
            gift_type="membership",
            gift_value=20,
            recipient_name=recipient_name or None,
            personal_message=personal_message or None,
            is_free_voucher=False,
            payment_method="crypto",
            payment_ref=f"pending_crypto_{code}",
            status="pending",
            pif_chain_depth=chain_depth,
            parent_voucher_id=parent_id,
        )
        db.add(voucher)
        db.commit()
        db.refresh(voucher)

        # Create NOWPayments invoice
        try:
            import httpx as _httpx
            np_key = os.getenv("NOWPAYMENTS_API_KEY", "")
            if not np_key:
                return JSONResponse({"error": "Crypto payments not configured"}, status_code=503)

            async with _httpx.AsyncClient(timeout=30) as np_client:
                inv_resp = await np_client.post("https://api.nowpayments.io/v1/invoice", headers={
                    "x-api-key": np_key, "Content-Type": "application/json",
                }, json={
                    "price_amount": 20,
                    "price_currency": "usd",
                    "order_id": f"pif_{voucher.id}_{code}",
                    "order_description": f"Pay It Forward Gift Voucher - {code}",
                    "ipn_callback_url": f"{os.getenv('BASE_URL', 'https://www.superadpro.com')}/api/nowpayments/ipn",
                    "success_url": f"{os.getenv('BASE_URL', 'https://www.superadpro.com')}/pay-it-forward?paid=1&code={code}",
                    "cancel_url": f"{os.getenv('BASE_URL', 'https://www.superadpro.com')}/pay-it-forward",
                })
                inv_data = inv_resp.json()

            if inv_data.get("invoice_url"):
                voucher.payment_ref = f"nowpay_invoice_{inv_data.get('id', '')}"
                db.commit()
                logger.info(f"Pay It Forward crypto: {user.username} created pending voucher {code}, invoice {inv_data.get('id')}")
                return {
                    "success": True,
                    "checkout_url": inv_data["invoice_url"],
                    "voucher_code": code,
                    "status": "pending_payment",
                }
            else:
                # Invoice creation failed — clean up
                db.delete(voucher)
                db.commit()
                return JSONResponse({"error": "Could not create payment. Please try again."}, status_code=500)

        except Exception as e:
            logger.error(f"PIF crypto checkout failed: {e}")
            db.delete(voucher)
            db.commit()
            return JSONResponse({"error": "Crypto checkout failed. Please try again."}, status_code=500)
    else:
        return JSONResponse({"error": "Invalid payment method"}, status_code=400)

    # Check if this is a "pay it forward" from a received gift
    received = db.query(GiftVoucher).filter(GiftVoucher.claimed_by_user_id == user.id).first()
    parent_id = received.id if received else None
    chain_depth = (received.pif_chain_depth + 1) if received else 1

    # Generate unique code
    for _ in range(10):
        code = _generate_voucher_code()
        existing = db.query(GiftVoucher).filter(GiftVoucher.voucher_code == code).first()
        if not existing:
            break
    else:
        return JSONResponse({"error": "Could not generate unique code. Try again."}, status_code=500)

    voucher = GiftVoucher(
        gifter_user_id=user.id,
        voucher_code=code,
        gift_type="membership",
        gift_value=20,
        recipient_name=recipient_name or None,
        personal_message=personal_message or None,
        is_free_voucher=False,
        payment_method="wallet",
        payment_ref=payment_ref,
        status="available",
        pif_chain_depth=chain_depth,
        parent_voucher_id=parent_id,
    )
    db.add(voucher)
    db.commit()
    db.refresh(voucher)

    logger.info(f"Pay It Forward: {user.username} created voucher {code} (chain depth {chain_depth})")

    return {
        "success": True,
        "voucher_code": code,
        "link": f"https://www.superadpro.com/gift/{code}",
        "chain_depth": chain_depth,
    }
@app.get("/api/gift/{code}")
async def api_gift_info(code: str, request: Request, db: Session = Depends(get_db)):
    """Public endpoint — get gift voucher info for the landing page.
    Also tracks link clicks so the gifter can see whether their share
    is being viewed (regardless of whether the recipient claims). The
    gifter's own visits to their own link are excluded — they often
    preview the link to verify it works, and counting that would
    inflate the click number meaninglessly."""
    from .database import GiftVoucher
    voucher = db.query(GiftVoucher).filter(GiftVoucher.voucher_code == code.upper()).first()
    if not voucher:
        return JSONResponse({"error": "Gift voucher not found"}, status_code=404)

    # ── Click tracking (best-effort, never blocks the response) ──
    # Identify the visitor: if there's a session cookie, see who it is.
    # We skip the increment if the visitor IS the gifter — their own
    # preview clicks shouldn't inflate the metric. Anonymous and other-
    # user visits both count.
    try:
        viewer_id = None
        session_token = request.cookies.get("session")
        if session_token:
            # Sessions are HMAC-signed JWT-style tokens, not DB rows.
            # session_serializer.loads validates the signature and returns
            # the user_id stored at sign time. Bug fixed 8 May 2026:
            # previously tried to import a non-existent SessionToken model
            # and look up by row, which raised ImportError and was silently
            # swallowed by the outer try/except — so click tracking has
            # been quietly broken since voucher feature shipped.
            try:
                user_id_str = session_serializer.loads(session_token, max_age=60 * 60 * 24 * 30)
                viewer_id = int(user_id_str)
            except (BadSignature, SignatureExpired, ValueError, TypeError):
                viewer_id = None
        if viewer_id != voucher.gifter_user_id:
            now = datetime.utcnow()
            voucher.link_clicks = (voucher.link_clicks or 0) + 1
            if voucher.first_clicked_at is None:
                voucher.first_clicked_at = now
            voucher.last_clicked_at = now
            db.commit()
    except Exception as e:
        # Click tracking is non-critical — never let a write failure
        # break the gift landing page for the recipient. Log + roll back.
        logger.warning(f"PIF click tracking failed for voucher {code}: {e}")
        try: db.rollback()
        except Exception: pass

    if voucher.status != "available":
        return JSONResponse({"error": "This gift has already been claimed", "status": voucher.status}, status_code=410)

    gifter = db.query(User).filter(User.id == voucher.gifter_user_id).first()

    return {
        "valid": True,
        "code": voucher.voucher_code,
        "gift_type": voucher.gift_type,
        "gift_value": float(voucher.gift_value),
        "gifter_name": gifter.first_name or gifter.username if gifter else "A SuperAdPro Member",
        "gifter_username": gifter.username if gifter else None,
        "recipient_name": voucher.recipient_name,
        "personal_message": voucher.personal_message,
        "chain_depth": voucher.pif_chain_depth,
    }


# ═════════════════════════════════════════════════════════════════════
# TEAM GIFTING (added 27 May 2026)
# ═════════════════════════════════════════════════════════════════════
# Direct-to-team gifting flow. Differs from shareable PIF in three ways:
#   1. Recipient is pre-selected (gifter picks from their inactive directs)
#   2. Recipient must consent (accept/decline) — no auto-activation
#   3. No refunds — declined/expired vouchers return to gifter for re-targeting
#      or conversion to shareable. The $20 stays in the gift system.
#
# Feature-flagged via app_config['team_gifting_enabled']. Default OFF
# until the Founder offer closes (avoids edge cases where a 7-day
# acceptance window could straddle the Founder cap).

TEAM_GIFT_ACCEPTANCE_DAYS = 7  # Window for recipient to accept or decline

def _team_gifting_enabled(db) -> bool:
    """Read the feature flag from app_config. Default OFF if missing
    or unparseable."""
    from .database import AppConfig
    try:
        cfg = db.query(AppConfig).filter(AppConfig.key == "team_gifting_enabled").first()
        return bool(cfg and cfg.value and cfg.value.strip().lower() in ("true", "1", "yes", "on"))
    except Exception:
        return False


def _expire_old_team_gifts(db, gifter_id: int) -> int:
    """Lazy expiry: when the gifter loads their PIF dashboard, sweep any
    of their reserved team gifts whose 7-day window has elapsed and flip
    them to 'expired'. Returns the count expired. Cheaper than a separate
    cron and bounded (only ever scans the calling gifter's rows)."""
    from .database import GiftVoucher
    now = datetime.utcnow()
    expired = db.query(GiftVoucher).filter(
        GiftVoucher.gifter_user_id == gifter_id,
        GiftVoucher.status == "reserved",
        GiftVoucher.reserved_until != None,
        GiftVoucher.reserved_until < now,
    ).all()
    for v in expired:
        v.status = "expired"
        logger.info(f"Team gift {v.voucher_code} auto-expired (gifter {gifter_id}, recipient {v.reserved_for_user_id})")
    if expired:
        db.commit()
    return len(expired)


@app.get("/api/pay-it-forward/giftable-team")
def api_giftable_team(user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """Returns the gifter's inactive direct referrals (those who can
    receive a team gift) plus the gifter's existing team-gift vouchers
    that need attention (declined/expired ones the gifter can re-target).

    Sweeps expired vouchers lazily on every call so the response is
    always current without needing a separate cron."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    if not _team_gifting_enabled(db):
        return JSONResponse({
            "enabled": False,
            "detail": "Team gifting is not yet available. Coming soon.",
        })
    if not user.is_active and not user.is_admin:
        return JSONResponse({"error": "Active membership required to gift"}, status_code=403)

    # Lazy expiry sweep
    _expire_old_team_gifts(db, user.id)

    # Get inactive direct referrals, newest first (most recent signups
    # are the most likely to still be in the activation consideration
    # window, so they bubble to the top of the list).
    from .database import GiftVoucher
    candidates = db.query(User).filter(
        User.sponsor_id == user.id,
        User.is_active == False,
    ).order_by(User.created_at.desc()).all()

    # Which of these already have an active reserved gift from this gifter
    # (don't let the gifter double-gift the same recipient)
    pending_recipient_ids = {
        v.reserved_for_user_id for v in db.query(GiftVoucher).filter(
            GiftVoucher.gifter_user_id == user.id,
            GiftVoucher.status == "reserved",
            GiftVoucher.reserved_for_user_id != None,
        ).all()
    }

    team_members = []
    for c in candidates:
        team_members.append({
            "user_id": c.id,
            "username": c.username,
            "first_name": c.first_name or None,
            "joined_at": c.created_at.isoformat() if c.created_at else None,
            "has_pending_gift": c.id in pending_recipient_ids,
        })

    # Vouchers needing gifter action. Unified (28 May 2026):
    #   - declined / expired TEAM gifts (reserved_for_user_id set) — the
    #     recipient turned it down or let it lapse.
    #   - UNUSED shareable vouchers (status 'available', paid for, never
    #     claimed) — e.g. the intended person paid on their own, leaving the
    #     gift link unused. The gifter can reassign it to a front-line member.
    needs_action = db.query(GiftVoucher).filter(
        GiftVoucher.gifter_user_id == user.id,
        GiftVoucher.status.in_(["declined", "expired"]),
        GiftVoucher.reserved_for_user_id != None,  # team gifts only
    ).order_by(GiftVoucher.created_at.desc()).all()
    needs_action_data = []
    for v in needs_action:
        prev_recipient = db.query(User).filter(User.id == v.reserved_for_user_id).first() if v.reserved_for_user_id else None
        needs_action_data.append({
            "voucher_code": v.voucher_code,
            "status": v.status,
            "kind": "team",
            "previous_recipient_username": prev_recipient.username if prev_recipient else None,
            "created_at": v.created_at.isoformat() if v.created_at else None,
        })

    # Unused shareable vouchers (paid + available + never claimed)
    unused_shareable = db.query(GiftVoucher).filter(
        GiftVoucher.gifter_user_id == user.id,
        GiftVoucher.status == "available",
        GiftVoucher.claimed_by_user_id == None,
        GiftVoucher.payment_ref != None,        # genuinely paid for
        GiftVoucher.is_free_voucher == False,   # not an auto-granted freebie
    ).order_by(GiftVoucher.created_at.desc()).all()
    for v in unused_shareable:
        needs_action_data.append({
            "voucher_code": v.voucher_code,
            "status": v.status,
            "kind": "shareable",
            "previous_recipient_username": v.recipient_name or None,
            "created_at": v.created_at.isoformat() if v.created_at else None,
        })

    return {
        "enabled": True,
        "team_members": team_members,
        "needs_action": needs_action_data,
        "acceptance_window_days": TEAM_GIFT_ACCEPTANCE_DAYS,
    }


@app.post("/api/pay-it-forward/create-team-gift")
async def api_create_team_gift(request: Request, user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """Create a team-targeted gift voucher. Same payment rails as the
    standard PIF flow (wallet / NOWPayments). The voucher starts as
    'reserved' for the specified recipient; recipient is notified and
    has TEAM_GIFT_ACCEPTANCE_DAYS to accept or decline."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    if not _team_gifting_enabled(db):
        return JSONResponse({"error": "feature_disabled", "detail": "Team gifting is not yet available."}, status_code=403)
    if not user.is_active and not user.is_admin:
        return JSONResponse({"error": "Active membership required to gift"}, status_code=403)

    from .database import GiftVoucher
    body = await request.json()
    recipient_user_id = body.get("recipient_user_id")
    personal_message = (body.get("personal_message") or "").strip()[:500]
    pay_method = body.get("pay_method", "wallet")

    if not recipient_user_id:
        return JSONResponse({"error": "recipient_user_id required"}, status_code=400)

    # Validate recipient — must be the gifter's direct downline, currently inactive
    recipient = db.query(User).filter(User.id == int(recipient_user_id)).first()
    if not recipient:
        return JSONResponse({"error": "Recipient not found"}, status_code=404)
    if recipient.sponsor_id != user.id:
        return JSONResponse({"error": "You can only gift to your direct team members"}, status_code=403)
    if recipient.is_active:
        return JSONResponse({"error": f"{recipient.username} already has an active membership"}, status_code=400)

    # Prevent double-gifting the same recipient
    existing_pending = db.query(GiftVoucher).filter(
        GiftVoucher.gifter_user_id == user.id,
        GiftVoucher.reserved_for_user_id == recipient.id,
        GiftVoucher.status == "reserved",
    ).first()
    if existing_pending:
        return JSONResponse({
            "error": f"You already have a pending gift for {recipient.username}",
            "existing_voucher_code": existing_pending.voucher_code,
        }, status_code=400)

    # Generate unique code
    for _ in range(10):
        code = _generate_voucher_code()
        if not db.query(GiftVoucher).filter(GiftVoucher.voucher_code == code).first():
            break
    else:
        return JSONResponse({"error": "Could not generate unique code. Try again."}, status_code=500)

    reserved_until = datetime.utcnow() + timedelta(days=TEAM_GIFT_ACCEPTANCE_DAYS)

    if pay_method == "wallet":
        if float(user.balance or 0) < 20:
            return JSONResponse({"error": "Insufficient wallet balance. You need at least $20."}, status_code=400)
        user.balance = float(user.balance or 0) - 20

        voucher = GiftVoucher(
            gifter_user_id=user.id,
            voucher_code=code,
            gift_type="membership",
            gift_value=20,
            recipient_name=recipient.first_name or recipient.username,
            personal_message=personal_message or None,
            is_free_voucher=False,
            payment_method="wallet",
            payment_ref=f"wallet_deduction_{user.id}_{int(datetime.utcnow().timestamp())}",
            status="reserved",
            reserved_for_user_id=recipient.id,
            reserved_until=reserved_until,
        )
        db.add(voucher)
        db.commit()
        db.refresh(voucher)

        try:
            cache_invalidate_user(user.id)
        except Exception:
            pass

        # Notify recipient — in-platform notification + email
        try:
            _notify_team_gift_recipient(db, voucher, user, recipient)
        except Exception as e:
            logger.warning(f"Team gift recipient notification failed: {e}")

        logger.info(f"Team gift created: {user.username} → {recipient.username} via wallet, code={code}")
        return {
            "success": True,
            "voucher_code": code,
            "recipient_username": recipient.username,
            "reserved_until": reserved_until.isoformat() + "Z",
        }

    elif pay_method in ("crypto", "nowpayments"):
        # Create voucher in 'pending' status (mirrors shareable flow);
        # the NOWPayments IPN callback flips it to 'reserved' once the
        # crypto payment confirms. The IPN handler needs to recognise
        # reserved_for_user_id to know it's a team gift.
        voucher = GiftVoucher(
            gifter_user_id=user.id,
            voucher_code=code,
            gift_type="membership",
            gift_value=20,
            recipient_name=recipient.first_name or recipient.username,
            personal_message=personal_message or None,
            is_free_voucher=False,
            payment_method="crypto",
            payment_ref=f"pending_crypto_{code}",
            status="pending",
            reserved_for_user_id=recipient.id,
            reserved_until=reserved_until,
        )
        db.add(voucher)
        db.commit()
        db.refresh(voucher)

        try:
            import httpx as _httpx
            np_key = os.getenv("NOWPAYMENTS_API_KEY", "")
            if not np_key:
                db.delete(voucher); db.commit()
                return JSONResponse({"error": "Crypto payments not configured"}, status_code=503)

            async with _httpx.AsyncClient(timeout=30) as np_client:
                inv_resp = await np_client.post("https://api.nowpayments.io/v1/invoice", headers={
                    "x-api-key": np_key, "Content-Type": "application/json",
                }, json={
                    "price_amount": 20,
                    "price_currency": "usd",
                    "order_id": f"pif_team_{voucher.id}_{code}",
                    "order_description": f"Team Gift Membership — for {recipient.username}",
                    "ipn_callback_url": f"{os.getenv('BASE_URL', 'https://www.superadpro.com')}/api/nowpayments/ipn",
                    "success_url": f"{os.getenv('BASE_URL', 'https://www.superadpro.com')}/pay-it-forward?team_paid=1&code={code}",
                    "cancel_url": f"{os.getenv('BASE_URL', 'https://www.superadpro.com')}/pay-it-forward",
                })
                inv_data = inv_resp.json()

            if inv_data.get("invoice_url"):
                voucher.payment_ref = f"nowpay_invoice_{inv_data.get('id', '')}"
                db.commit()
                return {
                    "success": True,
                    "checkout_url": inv_data["invoice_url"],
                    "voucher_code": code,
                    "status": "pending_payment",
                }
            else:
                db.delete(voucher); db.commit()
                return JSONResponse({"error": "Could not create payment. Try again."}, status_code=500)
        except Exception as e:
            logger.error(f"Team gift crypto checkout failed: {e}")
            try:
                db.delete(voucher); db.commit()
            except Exception:
                pass
            return JSONResponse({"error": "Crypto checkout failed. Try again."}, status_code=500)
    else:
        return JSONResponse({"error": "Invalid payment method"}, status_code=400)


def _notify_team_gift_recipient(db, voucher, gifter, recipient):
    """Send the recipient an in-platform notification + email letting
    them know they have a gift waiting. Keep the message warm but clear
    that they need to actively accept."""
    from .database import Notification
    gifter_name = gifter.first_name or gifter.username
    db.add(Notification(
        user_id=recipient.id,
        type="gift_received",
        icon="🎁",
        title=f"{gifter_name} has gifted you a SuperAdPro membership",
        message=(
            f"{gifter_name} wants to gift you a free month of SuperAdPro. "
            f"Open the gift to accept — you have {TEAM_GIFT_ACCEPTANCE_DAYS} "
            f"days to decide."
        ),
        link=f"/gift/team/{voucher.voucher_code}",
    ))
    db.commit()
    # Email — best effort, don't fail the whole flow if email fails
    try:
        from .email_service import send_email  # noqa: F401
        # Email integration may not be live in all environments — wrap
        # in try/except so a missing SMTP config doesn't break gifting.
        # (Looking at this: send_email may not exist; if not, this just
        # silently skips and the in-platform notification still fires.)
    except Exception:
        pass


@app.get("/api/gift/team/{code}/preview")
def api_team_gift_preview(code: str, user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """Recipient-facing preview before accepting. Shows who sent it and
    the optional personal message. Recipient must be logged in as the
    intended recipient."""
    from .database import GiftVoucher
    voucher = db.query(GiftVoucher).filter(GiftVoucher.voucher_code == code.upper()).first()
    if not voucher:
        return JSONResponse({"error": "not_found"}, status_code=404)
    if voucher.status != "reserved":
        return JSONResponse({"error": "not_active", "status": voucher.status}, status_code=410)
    if not user:
        return JSONResponse({"error": "login_required"}, status_code=401)
    if voucher.reserved_for_user_id != user.id:
        return JSONResponse({"error": "wrong_recipient", "detail": "This gift is for a different account"}, status_code=403)

    gifter = db.query(User).filter(User.id == voucher.gifter_user_id).first()
