@app.post("/admin/api/team-gifting-flag")
async def admin_team_gifting_flip(request: Request, user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """Flip the team gifting feature flag. POST {"enabled": true}."""
    if not user or not getattr(user, "is_admin", False):
        return JSONResponse({"error": "forbidden"}, status_code=403)
    body = await request.json()
    enabled = bool(body.get("enabled"))
    from .database import AppConfig
    cfg = db.query(AppConfig).filter(AppConfig.key == "team_gifting_enabled").first()
    if cfg:
        cfg.value = "true" if enabled else "false"
        cfg.updated_at = datetime.utcnow()
    else:
        db.add(AppConfig(key="team_gifting_enabled", value="true" if enabled else "false"))
    db.commit()
    logger.warning(f"Admin {user.username} set team_gifting_enabled = {enabled}")
    return JSONResponse({"success": True, "enabled": enabled})


@app.get("/admin/api/team-gifting-flip")
def admin_team_gifting_flip_get(
    on: str = "yes",
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Phone-friendly GET to flip the team gifting flag (28 May 2026).
      /admin/api/team-gifting-flip?on=yes   → enable (default)
      /admin/api/team-gifting-flip?on=no    → disable
    Mirrors the POST flip; reversible. Admin-only.
    """
    if not user or not getattr(user, "is_admin", False):
        return JSONResponse({"error": "forbidden"}, status_code=403)
    enabled = (on or "yes").lower() not in ("no", "false", "0", "off")
    from .database import AppConfig
    cfg = db.query(AppConfig).filter(AppConfig.key == "team_gifting_enabled").first()
    if cfg:
        cfg.value = "true" if enabled else "false"
        cfg.updated_at = datetime.utcnow()
    else:
        db.add(AppConfig(key="team_gifting_enabled", value="true" if enabled else "false"))
    db.commit()
    logger.warning(f"Admin {user.username} set team_gifting_enabled = {enabled} (via GET)")
    return JSONResponse({"success": True, "enabled": enabled})



@app.post("/api/gift/{code}/claim")
async def api_gift_claim(code: str, request: Request, db: Session = Depends(get_db)):
    """Claim a gift voucher — activates membership for the logged-in user."""
    from .database import GiftVoucher

    voucher = db.query(GiftVoucher).filter(GiftVoucher.voucher_code == code.upper()).first()
    if not voucher:
        return JSONResponse({"error": "Gift voucher not found"}, status_code=404)
    if voucher.status != "available":
        return JSONResponse({"error": "This gift has already been claimed"}, status_code=410)

    # Get current user from session cookie.
    # Bug fixed 8 May 2026: previously tried to look up a non-existent
    # SessionToken table, which crashed every claim attempt with
    # "cannot import name 'SessionToken'". Sessions are actually
    # HMAC-signed tokens — decode via session_serializer, same way
    # get_current_user() does it.
    user = None
    session_token = request.cookies.get("session")
    if session_token:
        try:
            user_id_str = session_serializer.loads(session_token, max_age=60 * 60 * 24 * 30)
            user = db.query(User).filter(User.id == int(user_id_str)).first()
        except (BadSignature, SignatureExpired, ValueError, TypeError):
            user = None

    if not user:
        return JSONResponse({"error": "Please create an account or log in first, then claim your gift"}, status_code=401)

    if user.is_active:
        return JSONResponse({"error": "Your membership is already active. This gift is for new or inactive members."}, status_code=400)

    # ── Founding partner spot allocation (25 May 2026) ─────────────────────
    # PIF gift recipients are paying members by transitivity — the gifter
    # paid for them, the company netted $10, the recipient activated. Under
    # the "first 100 paying members are Founders" policy they're eligible
    # for a Founder spot just like a Stripe or crypto signup.
    #
    # Prior to this fix the gift-claim handler activated recipients
    # directly as 'partner' with no spot check, no atomic claim, no
    # $15 price lock. Result: at least one recipient (cryptobase26 #54,
    # 21 May 2026) landed as Partner despite policy eligibility and had
    # to be manually promoted on 25 May.
    #
    # Mirrors the same pattern used in _activate_membership (line ~9267)
    # and the balance-activation path (line ~8195): pg_advisory_xact_lock
    # serialises concurrent claims, count check, claim if spots remain,
    # fall through to standard partner otherwise.
    founding_spot_claimed = None
    if not getattr(user, "is_founding_member", False):
        try:
            FOUNDING_TOTAL = 100
            FOUNDING_LOCK_KEY = 7423957  # must match _activate_membership
            db.execute(text("SELECT pg_advisory_xact_lock(:k)"),
                       {"k": FOUNDING_LOCK_KEY})
            current_count_row = db.execute(text(
                "SELECT COUNT(*) AS cnt FROM users WHERE is_founding_member = TRUE"
            )).fetchone()
            current_count = current_count_row.cnt if current_count_row else 0
            # Deadline check (added 27 May 2026) — see _founder_offer_still_open.
            deadline_open = _founder_offer_still_open(db)
            if current_count < FOUNDING_TOTAL and deadline_open:
                founding_spot_claimed = current_count + 1
                logger.info(
                    f"PIF gift claim: founding spot #{founding_spot_claimed} "
                    f"reserved for user {user.id} ({user.username}) — "
                    f"{FOUNDING_TOTAL - founding_spot_claimed} spots remaining"
                )
        except Exception as e:
            # If the founding claim fails for any reason, fall through to
            # standard partner activation. Better to give them a free month
            # at $20 lock than to fail the gift claim entirely.
            logger.error(
                f"PIF gift claim: founding spot check failed for user "
                f"{user.id}: {e} — proceeding with standard partner activation"
            )

    # Activate the membership
    user.is_active = True
    if founding_spot_claimed is not None:
        user.is_founding_member = True
        user.founding_spot_number = founding_spot_claimed
        user.membership_price_locked = decimal.Decimal("15.00")
        user.membership_tier = "founding"
        # Auto-enrol the new Founder into the rotator queue so they start
        # receiving distributed /start signups immediately. Idempotent.
        _enrol_user_to_rotator(db, user.id)
    else:
        user.membership_tier = "partner"
    # Set activated_at — this is what the dashboard's new-member toast
    # polling (/api/dashboard/new-members) filters on. Without this, gift
    # recipients silently activate but the gifter never sees the cha-ching
    # toast notification on their dashboard. (Bug caught 8 May 2026 during
    # test6 claim — test3 saw their wallet jump to $20 but no toast fired.)
    if not user.activated_at:
        user.activated_at = datetime.utcnow()
    # Gift = one month free membership. Set expiry so the renewal cron
    # knows when to charge them (or lapse them) at the end of the gift
    # window. Previously NULL because this handler skipped expiry-setting
    # entirely, leaving gift recipients with no defined renewal date.
    # (Carryover bug from earlier sessions: "membership_expires_at NULL
    # for some early Founders".)
    if not user.membership_expires_at:
        user.membership_expires_at = datetime.utcnow() + timedelta(days=31)

    # Skip onboarding for gift recipients — they're already qualified
    # members via the gift, and the onboarding wizard would otherwise
    # interrupt the celebratory welcome moment immediately after the
    # auto-redirect from the seamless claim flow. The dashboard's
    # gift-welcome banner serves as their onboarding entry point —
    # warm welcome + a "Pay it forward" CTA that introduces the
    # platform's core mechanic in context, not via a generic wizard.
    # (Steve's call 8 May 2026 after observing the wizard interrupting
    # the welcome banner during end-to-end testing.)
    user.onboarding_completed = True

    # Set the gifter as sponsor if user has no sponsor
    if not user.sponsor_id:
        user.sponsor_id = voucher.gifter_user_id

    # Mark voucher as claimed
    voucher.status = "claimed"
    voucher.claimed_by_user_id = user.id
    voucher.claimed_at = datetime.utcnow()

    # ── Pay gifter the membership sponsor commission ──
    # When test3 buys a $20 voucher, the company receives the full $20.
    # When the gift is claimed, the gifter receives the standard $10
    # membership-sponsor commission they would have received from a
    # normal direct signup. Net effect:
    #   - Gifter pays $20 (voucher) - $10 (commission back) = $10 net cost
    #   - Company nets $10 (same as a normal $20 membership sale)
    #   - Recipient receives a free month of membership
    # This aligns gift incentives with normal referral economics — without
    # the commission, gifters were economically punished for being
    # generous (a normal referral pays $10, a gift paid $0). That asymmetry
    # would have killed the viral mechanic over time.
    # (Steve's call 8 May 2026 after considering long-term community health
    # vs short-term marketing simplicity.)
    #
    # The commission_type is 'gift_membership_sponsor' to distinguish from
    # normal direct signups in analytics — this matters for the PIF
    # dashboard's "earned back" stat and any future audit work.
    gifter = db.query(User).filter(User.id == voucher.gifter_user_id).first()
    if gifter:
        from decimal import Decimal
        gift_commission = Decimal("10.00")
        gifter.balance = Decimal(str(gifter.balance or 0)) + gift_commission
        gifter.total_earned = Decimal(str(gifter.total_earned or 0)) + gift_commission
        # Atomic personal_referrals increment, same pattern as normal
        # membership_sponsor route. The gifter is now the recipient's
        # sponsor of record so this counts toward their referral total.
        from sqlalchemy import func as _sqlfunc
        db.query(User).filter(User.id == gifter.id).update({
            User.personal_referrals: _sqlfunc.coalesce(User.personal_referrals, 0) + 1,
        }, synchronize_session=False)

        comm = Commission(
            to_user_id=gifter.id,
            from_user_id=user.id,
            amount_usdt=gift_commission,
            commission_type="gift_membership_sponsor",
            package_tier=0,
            notes=f"Pay It Forward: {user.username} claimed gift voucher {voucher.voucher_code}",
            status="paid",
            paid_at=datetime.utcnow(),
        )
        db.add(comm)

        # Notification to gifter — they should see the claim AND the
        # commission in one message, not two separate notifications
        # arriving 30s apart.
        try:
            notif = Notification(
                user_id=gifter.id,
                title="🎁 Your gift was claimed!",
                message=f"{user.first_name or user.username} just activated their membership using your gift. You earned a $10 sponsor commission.",
                notification_type="gift_claimed",
                created_at=datetime.utcnow(),
            )
            db.add(notif)
        except Exception as e:
            # Notification failure must not block the claim itself.
            logger.warning(f"PIF gift-claim notification failed for gifter {gifter.id}: {e}")

    db.commit()
    # Cache invalidation — gifter received commission (balance/earnings
    # changed) AND the user just activated their membership (their
    # dashboard's 'active member' stats need to refresh too).
    try:
        cache_invalidate_user(user.id)
        if voucher.gifter_user_id:
            cache_invalidate_user(voucher.gifter_user_id)
    except Exception as e:
        logger.warning(f"cache_invalidate_user failed in PIF claim: {e}")

    logger.info(
        f"Pay It Forward: {user.username} claimed voucher {code} gifted by user {voucher.gifter_user_id} "
        f"(chain depth {voucher.pif_chain_depth}) — $10 sponsor commission paid to gifter"
    )

    return {
        "success": True,
        "message": "Your membership has been activated! Welcome to SuperAdPro.",
        "gifter_name": db.query(User).filter(User.id == voucher.gifter_user_id).first().first_name or "A member",
    }


@app.get("/admin/api/user-commissions/{username}")
def admin_user_commissions(
    username: str,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Read-only itemised commission history for a single user (the recipient).

    Returns every Commission row where to_user_id matches the target user,
    with WHO paid (from_user details), what commission_type, amount, status,
    timestamps. Plus a totals summary by type so admin can quickly answer
    'why does this user have $X balance?' questions.

    Built 27 May 2026 evening after Floyd / @ourfreedom asked Steve why
    his balance was $30 with only 2 referrals. The aggregate monitoring
    tools (commission_audit, commission_anomalies) confirm health but
    don't itemise per-user — this endpoint fills that gap.

    Returns:
      {
        "user": {id, username, balance, ...},
        "totals": {
          "by_type": {"membership_sponsor": {count, total}, ...},
          "by_status": {"paid": total, "pending": total},
          "grand_total": ...
        },
        "commissions": [
          {id, from_user_id, from_username, amount, type, status,
           created_at, paid_at, notes}, ...
        ]
      }

    Sorted newest-first.
    """
    _require_admin(user)
    from .database import Commission

    target = db.query(User).filter(User.username == username.lower()).first()
    if not target:
        return JSONResponse({"error": f"User '{username}' not found"}, status_code=404)

    rows = (
        db.query(Commission)
        .filter(Commission.to_user_id == target.id)
        .order_by(Commission.created_at.desc())
        .all()
    )

    # Build itemised list with from_user lookups (single query for all
    # source users to avoid N+1)
    from_user_ids = {r.from_user_id for r in rows if r.from_user_id}
    from_users = {
        u.id: u for u in db.query(User).filter(User.id.in_(from_user_ids)).all()
    } if from_user_ids else {}

    commissions = []
    for r in rows:
        src = from_users.get(r.from_user_id) if r.from_user_id else None
        commissions.append({
            "id": r.id,
            "from_user_id": r.from_user_id,
            "from_username": src.username if src else None,
            "from_display": (src.first_name or src.username) if src else "—",
            "amount_usd": float(r.amount_usdt) if r.amount_usdt is not None else 0.0,
            "commission_type": r.commission_type,
            "status": r.status,
            "tx_hash": r.tx_hash,
            "grid_id": r.grid_id,
            "package_tier": r.package_tier,
            "notes": r.notes,
            "created_at": r.created_at.isoformat() if r.created_at else None,
            "paid_at": r.paid_at.isoformat() if r.paid_at else None,
        })

    # Totals breakdown — by_type for "what's contributing what",
    # by_status for "paid vs still pending"
    by_type = {}
    by_status = {"paid": 0.0, "pending": 0.0, "failed": 0.0, "other": 0.0}
    grand_total_paid = 0.0
    for r in rows:
        amt = float(r.amount_usdt) if r.amount_usdt is not None else 0.0
        t = r.commission_type or "unknown"
        if t not in by_type:
            by_type[t] = {"count": 0, "total_usd": 0.0}
        by_type[t]["count"] += 1
        by_type[t]["total_usd"] += amt
        s = (r.status or "other").lower()
        if s in by_status:
            by_status[s] += amt
        else:
            by_status["other"] += amt
        if s == "paid":
            grand_total_paid += amt

    return JSONResponse({
        "user": {
            "id": target.id,
            "username": target.username,
            "first_name": target.first_name,
            "is_active": target.is_active,
            "balance_usd": float(target.balance or 0),
            "membership_tier": target.membership_tier,
            "is_founding_member": getattr(target, "is_founding_member", False),
        },
        "totals": {
            "row_count": len(rows),
            "grand_total_paid_usd": round(grand_total_paid, 2),
            "by_type": {k: {"count": v["count"], "total_usd": round(v["total_usd"], 2)} for k, v in by_type.items()},
            "by_status": {k: round(v, 2) for k, v in by_status.items() if v != 0.0},
        },
        "commissions": commissions,
    })


@app.get("/admin/api/audit-double-pays")
def admin_audit_double_pays(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Find duplicate membership_sponsor commissions paid because of the
    Stripe webhook race (checkout.session.completed + invoice.paid both
    firing on different replicas within ~350ms, both passing the
    is_active check before either commits).

    Detection rule: same (from_user_id, to_user_id, commission_type)
    with 2+ rows that have BOTH a 'stripe' AND a 'stripe-invoice-recovery'
    source in their notes, within a small time window. The duplicate
    is the LATER row.

    Returns the list of duplicate Commission IDs to be reversed. Does
    NOT mutate anything — read-only audit. Call /admin/api/reverse-commission/{id}
    to actually reverse one.

    Built 27 May 2026 late evening after Floyd / @ourfreedom's $30
    balance was traced to a duplicate sponsor commission on Dan
    (@dprose55420)'s signup. Race-condition root cause documented in
    the corresponding webhook-handler advisory lock fix in this commit.
    """
    _require_admin(user)
    from .database import Commission

    # Find all membership_sponsor rows for a single signup (same
    # from_user_id → to_user_id) where BOTH a 'stripe' source and a
    # 'stripe-invoice-recovery' source exist.
    candidates = (
        db.query(Commission)
        .filter(Commission.commission_type == "membership_sponsor")
        .filter(Commission.status == "paid")
        .order_by(Commission.from_user_id, Commission.to_user_id, Commission.created_at)
        .all()
    )

    # Group by (from_user_id, to_user_id) and look for stripe + stripe-invoice-recovery pairs
    from collections import defaultdict
    groups = defaultdict(list)
    for c in candidates:
        groups[(c.from_user_id, c.to_user_id)].append(c)

    duplicates = []
    for (from_id, to_id), commissions in groups.items():
        if len(commissions) < 2:
            continue
        has_stripe = any("(stripe)" in (c.notes or "") for c in commissions)
        has_recovery = any("(stripe-invoice-recovery)" in (c.notes or "") for c in commissions)
        if has_stripe and has_recovery:
            # The duplicate is the LATER row. Sort by created_at; the
            # first one is the "real" commission, the rest are duplicates.
            sorted_c = sorted(commissions, key=lambda c: c.created_at or datetime.utcnow())
            real = sorted_c[0]
            for dup in sorted_c[1:]:
                from_u = db.query(User).filter(User.id == from_id).first()
                to_u = db.query(User).filter(User.id == to_id).first()
                duplicates.append({
                    "duplicate_commission_id": dup.id,
                    "real_commission_id": real.id,
                    "from_user_id": from_id,
                    "from_username": from_u.username if from_u else None,
                    "to_user_id": to_id,
                    "to_username": to_u.username if to_u else None,
                    "amount_usd": float(dup.amount_usdt) if dup.amount_usdt else 0.0,
                    "real_notes": real.notes,
                    "duplicate_notes": dup.notes,
                    "ms_between": int(((dup.created_at - real.created_at).total_seconds() * 1000)) if (dup.created_at and real.created_at) else None,
                })

    return JSONResponse({
        "duplicate_count": len(duplicates),
        "total_amount_to_reverse_usd": round(sum(d["amount_usd"] for d in duplicates), 2),
        "duplicates": duplicates,
        "next_step": "Call POST /admin/api/reverse-commission/{duplicate_commission_id} for each one to reverse it",
    })


@app.post("/admin/api/reverse-commission/{commission_id}")
def admin_reverse_commission(
    commission_id: int,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Reverse a single Commission row: deduct from recipient's balance,
    mark the commission status as 'reversed', preserve the row for
    audit. Idempotent — calling twice on the same ID does nothing the
    second time.

    Built 27 May 2026 to clean up duplicate sponsor commissions from
    the Stripe webhook race. See /admin/api/audit-double-pays for how
    to identify candidates.

    Returns details of what was reversed.
    """
    _require_admin(user)
    from .database import Commission

    commission = db.query(Commission).filter(Commission.id == commission_id).first()
    if not commission:
        return JSONResponse({"error": f"Commission {commission_id} not found"}, status_code=404)

    if commission.status == "reversed":
        return JSONResponse({
            "already_reversed": True,
            "commission_id": commission_id,
            "notes": commission.notes,
        })

    amount = float(commission.amount_usdt) if commission.amount_usdt is not None else 0.0
    recipient = db.query(User).filter(User.id == commission.to_user_id).first()
    if not recipient:
        return JSONResponse({"error": f"Recipient user {commission.to_user_id} not found"}, status_code=404)

    # Deduct from recipient balance
    old_balance = float(recipient.balance or 0)
    new_balance = max(0.0, old_balance - amount)  # don't go negative
    recipient.balance = new_balance

    # Mark commission as reversed (preserve for audit)
    commission.status = "reversed"
    original_notes = commission.notes or ""
    commission.notes = (
        f"{original_notes}\n\n"
        f"[REVERSED on {datetime.utcnow().isoformat()}Z by admin "
        f"({user.username}) — duplicate caused by Stripe webhook race "
        f"(see commits 7c57426..). Deducted ${amount:.2f} from recipient "
        f"balance: ${old_balance:.2f} → ${new_balance:.2f}.]"
    )

    try:
        cache_invalidate_user(recipient.id)
    except Exception:
        pass

    db.commit()
    logger.warning(
        f"Commission {commission_id} REVERSED by admin {user.username}: "
        f"${amount} deducted from {recipient.username} (was ${old_balance}, "
        f"now ${new_balance})"
    )

    return JSONResponse({
        "success": True,
        "commission_id": commission_id,
        "recipient_username": recipient.username,
        "amount_reversed_usd": amount,
        "balance_before": old_balance,
        "balance_after": new_balance,
        "notes": commission.notes,
    })


@app.get("/admin/api/sweep-double-pays")
def admin_sweep_double_pays(
    confirm: str = "",
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """One-shot: audit + reverse all duplicate webhook-race commissions
    in a single call. Browser-bar friendly (GET, no POST required).

    SAFETY: requires ?confirm=yes in the URL. Without it, returns
    the audit list as a dry-run preview (same as audit-double-pays)
    but does NOT mutate anything. This protects against accidental
    full-sweep clicks.

    Workflow:
      1. GET /admin/api/sweep-double-pays  (preview — no mutations)
      2. Review the list
      3. GET /admin/api/sweep-double-pays?confirm=yes  (actually run)

    Built 27 May 2026 evening so Steve can clean up Floyd's case
    (and any others) from a phone browser without console access.
    """
    _require_admin(user)
    from .database import Commission
    from collections import defaultdict

    # Re-run the audit logic inline
    candidates = (
        db.query(Commission)
        .filter(Commission.commission_type == "membership_sponsor")
        .filter(Commission.status == "paid")
        .order_by(Commission.from_user_id, Commission.to_user_id, Commission.created_at)
        .all()
    )
    groups = defaultdict(list)
    for c in candidates:
        groups[(c.from_user_id, c.to_user_id)].append(c)

    duplicates = []
    for (from_id, to_id), commissions in groups.items():
        if len(commissions) < 2:
            continue
        has_stripe = any("(stripe)" in (c.notes or "") for c in commissions)
        has_recovery = any("(stripe-invoice-recovery)" in (c.notes or "") for c in commissions)
        if has_stripe and has_recovery:
            sorted_c = sorted(commissions, key=lambda c: c.created_at or datetime.utcnow())
            for dup in sorted_c[1:]:
                duplicates.append(dup)

    dry_run = (confirm.lower() != "yes")

    if dry_run:
        # Preview only
        from_users_cache = {}
        to_users_cache = {}
        preview = []
        for dup in duplicates:
            if dup.from_user_id not in from_users_cache:
                from_users_cache[dup.from_user_id] = db.query(User).filter(User.id == dup.from_user_id).first()
            if dup.to_user_id not in to_users_cache:
                to_users_cache[dup.to_user_id] = db.query(User).filter(User.id == dup.to_user_id).first()
            preview.append({
                "duplicate_commission_id": dup.id,
                "from_username": from_users_cache[dup.from_user_id].username if from_users_cache[dup.from_user_id] else None,
                "to_username": to_users_cache[dup.to_user_id].username if to_users_cache[dup.to_user_id] else None,
                "amount_usd": float(dup.amount_usdt) if dup.amount_usdt else 0.0,
                "notes": dup.notes,
                "created_at": dup.created_at.isoformat() if dup.created_at else None,
            })
        return JSONResponse({
            "dry_run": True,
            "would_reverse_count": len(duplicates),
            "would_reverse_total_usd": round(sum(float(d.amount_usdt or 0) for d in duplicates), 2),
            "duplicates": preview,
            "to_actually_run": "Append ?confirm=yes to this URL",
        })

    # Actually run the reversals
    reversed_list = []
    failed = []
    for dup in duplicates:
        try:
            amount = float(dup.amount_usdt) if dup.amount_usdt is not None else 0.0
            recipient = db.query(User).filter(User.id == dup.to_user_id).first()
            if not recipient:
                failed.append({"commission_id": dup.id, "reason": "recipient_not_found"})
                continue
            old_balance = float(recipient.balance or 0)
            new_balance = max(0.0, old_balance - amount)
            recipient.balance = new_balance
            dup.status = "reversed"
            original_notes = dup.notes or ""
            dup.notes = (
                f"{original_notes}\n\n"
                f"[REVERSED on {datetime.utcnow().isoformat()}Z via batch sweep by admin "
                f"({user.username}) — duplicate caused by Stripe webhook race. "
                f"Deducted ${amount:.2f} from {recipient.username}: "
                f"${old_balance:.2f} → ${new_balance:.2f}.]"
            )
            try:
                cache_invalidate_user(recipient.id)
            except Exception:
                pass
            reversed_list.append({
                "commission_id": dup.id,
                "recipient_username": recipient.username,
                "amount_reversed_usd": amount,
                "balance_before": old_balance,
                "balance_after": new_balance,
            })
            logger.warning(
                f"Sweep: Commission {dup.id} REVERSED — ${amount} deducted from "
                f"{recipient.username} (${old_balance} → ${new_balance})"
            )
        except Exception as e:
            failed.append({"commission_id": dup.id, "reason": str(e)})

    db.commit()
    return JSONResponse({
        "dry_run": False,
        "reversed_count": len(reversed_list),
        "failed_count": len(failed),
        "total_reversed_usd": round(sum(r["amount_reversed_usd"] for r in reversed_list), 2),
        "reversed": reversed_list,
        "failed": failed,
    })


@app.post("/admin/api/grant-founder/{username}")
@app.get("/admin/api/grant-founder/{username}")
def admin_grant_founder(
    username: str,
    code: str = "",
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Retroactively grant Founder status to an already-active member who
    SHOULD have been made a Founder but wasn't (e.g. the allocator-gap
    bug of 28 May 2026 that closed the offer 9 spots early and silently
    charged 4 members Partner pricing while spots were open).

    Assigns the lowest unused spot number <= 100, sets is_founding_member,
    membership_tier='founding', membership_price_locked=$15.00, and
    enrols them in the rotator. Idempotent — if already a founder, no-op.

    Race-safe via the same FOUNDING_LOCK_KEY advisory lock the live
    allocator uses, so concurrent grants (or a grant racing a live
    signup) can't collide on spot numbers.

    Does NOT refund the price difference — that's a separate manual
    decision per Steve (pay back the $5 only if the member asks).
    Does NOT notify the member — silent correction.
    """
    _require_admin_2fa(user, code)
    from decimal import Decimal as _Dec

    target = db.query(User).filter(User.username == username.lower()).first()
    if not target:
        return JSONResponse({"error": f"User '{username}' not found"}, status_code=404)

    if getattr(target, "is_founding_member", False):
        return JSONResponse({
            "already_founder": True,
            "username": target.username,
            "founding_spot_number": target.founding_spot_number,
        })

    FOUNDING_TOTAL = 100
    FOUNDING_LOCK_KEY = 7423957
    db.execute(text("SELECT pg_advisory_xact_lock(:k)"), {"k": FOUNDING_LOCK_KEY})

    current_count = db.execute(text(
        "SELECT COUNT(*) FROM users WHERE is_founding_member = TRUE"
    )).scalar() or 0
    if current_count >= FOUNDING_TOTAL:
        return JSONResponse({
            "error": "founder_cap_full",
            "current_count": current_count,
        }, status_code=409)

    gap_row = db.execute(text(
        "SELECT s.n AS spot FROM generate_series(1, :total) AS s(n) "
        "LEFT JOIN users u ON u.founding_spot_number = s.n "
        "WHERE u.id IS NULL ORDER BY s.n LIMIT 1"
    ), {"total": FOUNDING_TOTAL}).fetchone()
    if not gap_row:
        return JSONResponse({"error": "no_spot_available"}, status_code=409)

    next_spot = gap_row.spot
    old_tier = target.membership_tier
    target.is_founding_member = True
    target.founding_spot_number = next_spot
    target.membership_price_locked = _Dec("15.00")
    target.membership_tier = "founding"
    db.flush()
    try:
        _enrol_user_to_rotator(db, target.id)
    except Exception:
        pass
    try:
        cache_invalidate_user(target.id)
    except Exception:
        pass
    db.commit()

    logger.warning(
        f"ADMIN GRANT FOUNDER: {target.username} (id={target.id}) granted "
        f"founding spot #{next_spot} by admin {user.username}. Was tier="
        f"{old_tier}, now founding @ $15 locked. (Retroactive correction "
        f"for 28 May allocator-gap bug.)"
    )

    return JSONResponse({
        "success": True,
        "username": target.username,
        "founding_spot_number": next_spot,
        "previous_tier": old_tier,
        "price_locked": "15.00",
        "note": "Silent correction. No refund issued (pay $5 diff only if requested). No member notification sent.",
    })


@app.get("/admin/api/membership-state/{username}")
def admin_membership_state(
    username: str,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Read-only diagnostic for a member's full membership state.

    Returns everything needed to diagnose lapse/grace/renewal issues:
      - User row state (is_active, activated_at, membership_tier,
        membership_billing, membership_expires_at)
      - MembershipRenewal row (next_renewal_date, in_grace_period,
        grace_period_start, last_renewed_at, total_renewals,
        renewal_source) — or null if no row exists
      - Recent membership-type Payment rows (last 5)
      - Computed status: 'active' | 'in_grace' | 'lapsed' | 'never_paid'
      - For lapsed/grace cases, a `lapsed_explanation` field describes
        WHY the member is in this state (e.g. "next_renewal_date passed
        2026-04-30, balance $0 < $20 fee, grace period 5 days expired")

    Built 8 May 2026 to diagnose why test1 was showing as lapsed only
    12 days after activation. Read-only — never mutates anything.
    """
    _require_admin(user)
    from .database import MembershipRenewal

    target = db.query(User).filter(User.username == username.lower()).first()
    if not target:
        return JSONResponse({"error": f"User '{username}' not found"}, status_code=404)

    renewal = db.query(MembershipRenewal).filter(
        MembershipRenewal.user_id == target.id
    ).first()

    payments = (db.query(Payment)
                  .filter(Payment.from_user_id == target.id,
                          Payment.payment_type.like("membership%"))
                  .order_by(Payment.created_at.desc())
                  .limit(5).all())

    has_paid_membership = any(
        p.status in ("confirmed", "paid") for p in payments
    )

    # Determine computed status
    now = datetime.utcnow()
    if target.is_active:
        if renewal and renewal.in_grace_period:
            status = "in_grace"
        else:
            status = "active"
    else:
        status = "lapsed" if has_paid_membership else "never_paid"

    # Build a human-readable explanation for lapsed/grace cases
    lapsed_explanation = None
    if status in ("lapsed", "in_grace") and renewal:
        parts = []
        if renewal.next_renewal_date:
            days_since_renewal_due = (now - renewal.next_renewal_date).days
            if days_since_renewal_due > 0:
                parts.append(f"next_renewal_date was {renewal.next_renewal_date.strftime('%Y-%m-%d')} ({days_since_renewal_due} days ago)")
            else:
                parts.append(f"next_renewal_date is {renewal.next_renewal_date.strftime('%Y-%m-%d')} ({-days_since_renewal_due} days from now)")
        balance = float(target.balance or 0)
        parts.append(f"current balance ${balance:.2f}")
        if renewal.in_grace_period and renewal.grace_period_start:
            grace_days_in = (now - renewal.grace_period_start).days
            parts.append(f"in grace period since {renewal.grace_period_start.strftime('%Y-%m-%d')} ({grace_days_in} days, lapses at 5)")
        lapsed_explanation = "; ".join(parts)
    elif status == "lapsed" and not renewal:
        lapsed_explanation = "is_active=False but NO MembershipRenewal row exists — the renewal cron never had data to bill them, so the lapse came from somewhere else (manual admin action, GDPR deletion, or some other path that flipped is_active)"

    return {
        "user": {
            "id": target.id,
            "username": target.username,
            "first_name": target.first_name,
            "is_active": target.is_active,
            "is_admin": target.is_admin,
            "membership_tier": target.membership_tier,
            "membership_billing": getattr(target, "membership_billing", None),
            "activated_at": target.activated_at.isoformat() if target.activated_at else None,
            "membership_expires_at": target.membership_expires_at.isoformat() if getattr(target, "membership_expires_at", None) else None,
            "balance": float(target.balance or 0),
            "low_balance_warned": getattr(target, "low_balance_warned", False),
            "created_at": target.created_at.isoformat() if target.created_at else None,
        },
        "renewal": {
            "exists": renewal is not None,
            "activated_at": renewal.activated_at.isoformat() if renewal and renewal.activated_at else None,
            "next_renewal_date": renewal.next_renewal_date.isoformat() if renewal and renewal.next_renewal_date else None,
            "last_renewed_at": renewal.last_renewed_at.isoformat() if renewal and renewal.last_renewed_at else None,
            "in_grace_period": renewal.in_grace_period if renewal else None,
            "grace_period_start": renewal.grace_period_start.isoformat() if renewal and renewal.grace_period_start else None,
            "total_renewals": renewal.total_renewals if renewal else None,
            "renewal_source": renewal.renewal_source if renewal else None,
        } if renewal is not None else {"exists": False},
        "payments": [
            {
                "id": p.id,
                "amount": float(p.amount_usdt or 0),
                "type": p.payment_type,
                "status": p.status,
                "tx_hash": p.tx_hash,
                "created_at": p.created_at.isoformat() if p.created_at else None,
            } for p in payments
        ],
        "computed_status": status,
        "lapsed_explanation": lapsed_explanation,
    }


@app.get("/admin/api/audit-double-pays")
def admin_audit_double_pays(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Find historical sponsor commission overpayments from the upgrade-flag
    bug class fixed on 9 May 2026 (engine-level upgrade detection).

    Bug summary: prior to engine-level classification, three callsites had
    inconsistent is_upgrade detection. NOWPayments and WalletConnect rails
    incorrectly paid sponsor commission on:
      - Same-tier Monthly→Annual switches (via either rail)
      - Basic→Pro Annual upgrades (via WalletConnect rail only)
      - Basic→Pro Monthly upgrades (via WalletConnect rail only — pre-existing bug)

    NOWPayments Basic→Pro Monthly was correctly handled (line 7990 set
    is_upgrade=True via product_meta), so it's the only path that
    historically worked correctly for upgrades.

    This endpoint reads the Commission table and reports rows that look
    like overpayments based on the relationship between the
    commission_type and the user's eventual upgrade history. Read-only —
    does not reverse anything. Admin discretion required for cleanup.
    """
    if not user or not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)

    from .database import Commission, Payment

    # Find users who have BOTH:
    #   - A "membership" type sponsor commission paid (looks like fresh activation)
    #   - A subsequent or prior "membership_upgrade" or membership-annual Payment row
    # That combination strongly suggests the second activation should have
    # been classified as an upgrade/switch but paid commission anyway.
    suspect_users = db.query(User).filter(User.is_active == True).all()

    findings = []
    for u in suspect_users:
        # All sponsor commissions ever paid for this user's activations
        commissions = db.query(Commission).filter(
            Commission.from_user_id == u.id,
            Commission.commission_type == "membership",
        ).order_by(Commission.created_at).all()

        if len(commissions) <= 1:
            continue  # 0 or 1 commission — can't be a double-pay yet

        # 2+ membership-type commissions for the same user. That's
        # suspicious by definition: a member only "fresh activates"
        # once. Subsequent activations should be tier_upgrade or
        # cadence_switch, neither of which pays sponsor commission.
        # The first commission is legitimate; everything after the
        # first is a candidate overpayment.
        legit = commissions[0]
        suspect = commissions[1:]
        findings.append({
            "user_id": u.id,
            "username": u.username,
            "current_tier": u.membership_tier,
            "current_billing": getattr(u, "membership_billing", None),
            "legitimate_commission": {
                "id": legit.id,
                "to_user_id": legit.to_user_id,
                "amount_usdt": float(legit.amount_usdt or 0),
                "created_at": legit.created_at.isoformat() if legit.created_at else None,
            },
            "suspect_commissions": [
                {
                    "id": c.id,
                    "to_user_id": c.to_user_id,
                    "amount_usdt": float(c.amount_usdt or 0),
                    "created_at": c.created_at.isoformat() if c.created_at else None,
                    "notes": c.notes,
                }
                for c in suspect
            ],
            "suspect_total_usdt": float(sum((c.amount_usdt or 0) for c in suspect)),
        })

    return {
        "checked_active_users": len(suspect_users),
        "users_with_suspect_commissions": len(findings),
        "total_suspect_amount_usdt": float(sum(f["suspect_total_usdt"] for f in findings)),
        "findings": findings,
        "next_step": (
            "Review each user's commission history. If suspect commissions "
            "correspond to legitimate tier_upgrade or cadence_switch events, "
            "they should be reversed. Reversal endpoint: see admin tooling "
            "(write a one-shot endpoint with explicit user_id + commission_id "
            "list rather than a blanket reversal — keeps the cleanup auditable)."
        ),
    }


@app.get("/admin/api/stuck-lapsed-members")
def admin_find_stuck_lapsed_members(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Find all members who are showing as lapsed but shouldn't be.

    Stuck-lapsed = is_active=False AND has a MembershipRenewal row where
    next_renewal_date is still in the future AND not in grace period.
    There's no legitimate reason for these members to be inactive — the
    renewal cron hasn't been triggered against them yet, they have paid
    membership, and their renewal data is intact.

    The most likely cause is historical: admin actions, manual DB edits,
    or deleted code paths from earlier testing flipped their is_active
    flag without going through the proper lapse flow. This endpoint
    detects them so we can choose whether to reactivate.

    Read-only — never mutates anything. Pair with
    POST /admin/api/reactivate-stuck-lapsed to actually flip them back.

    Built 8 May 2026 after test1 was found in this state during
    end-to-end gift voucher testing.
    """
    _require_admin(user)
    from .database import MembershipRenewal

    now = datetime.utcnow()

    # Find all inactive users with intact renewal data
    candidates = (
        db.query(User, MembershipRenewal)
          .join(MembershipRenewal, MembershipRenewal.user_id == User.id)
          .filter(
              User.is_active == False,
              MembershipRenewal.next_renewal_date > now,
              MembershipRenewal.in_grace_period == False,
          )
          .all()
    )

    # Filter to only those with confirmed membership Payment — these are
    # the genuinely-paid members who shouldn't be lapsed. Members without
    # a paid Payment are 'never_paid', not 'stuck-lapsed', and shouldn't
    # be auto-reactivated.
    stuck = []
    for u, r in candidates:
        has_paid_payment = db.query(Payment).filter(
            Payment.from_user_id == u.id,
            Payment.payment_type.like("membership%"),
            Payment.status.in_(["confirmed", "paid"]),
        ).first()
        if not has_paid_payment:
            continue

        days_until_renewal = (r.next_renewal_date - now).days
        days_since_expires = None
        if u.membership_expires_at:
            days_since_expires = (u.membership_expires_at - now).days

        stuck.append({
            "user_id": u.id,
            "username": u.username,
            "first_name": u.first_name,
            "membership_tier": u.membership_tier,
            "activated_at": u.activated_at.isoformat() if u.activated_at else None,
            "next_renewal_date": r.next_renewal_date.isoformat(),
            "days_until_renewal_due": days_until_renewal,
            "membership_expires_at": u.membership_expires_at.isoformat() if u.membership_expires_at else None,
            "days_until_expiry": days_since_expires,
            "balance": float(u.balance or 0),
            "renewal_source": r.renewal_source,
            "total_renewals": r.total_renewals,
        })

    return {
        "count": len(stuck),
        "stuck_lapsed_members": stuck,
        "checked_at": now.isoformat(),
        "reactivation_endpoint": "POST /admin/api/reactivate-stuck-lapsed (with optional ?dry_run=1)",
    }


@app.get("/admin/api/matrix-landscape")
def admin_matrix_landscape(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Read-only snapshot of the credit-matrix landscape, to assess what a
    close-out would affect BEFORE doing it.

    Matrix per-position commissions are written status='paid' inline as
    positions fill — they are NOT held. The completion bonus was scrapped
    (COMPLETION_BONUS_RATE=0). So in theory close-out strips no owed money.
    This endpoint proves that against live data:

      - active_matrices: count + per-matrix owner/positions/earned
      - unpaid_commissions: any CreditMatrixCommission NOT status='paid'
        (would be money in-flight that close-out must not strip)
      - completion_bonus_exposure: sum of completion_bonus_paid and any
        matrix at/near 39 positions that might expect a bonus

    Read-only — mutates nothing. Built 30 May 2026 ahead of the matrix
    close-out for the flat-20% Nexus switch.
    """
    _require_admin(user)
    from .database import CreditMatrix as _CM, CreditMatrixCommission as _CMC

    active = db.query(_CM).filter(_CM.status == "active").all()
    completed = db.query(_CM).filter(_CM.status == "completed").count()

    active_summary = [{
        "matrix_id": m.id, "owner_id": m.owner_id, "pack_key": m.pack_key,
        "advance_number": m.advance_number, "positions_filled": m.positions_filled,
        "total_earned": float(m.total_earned or 0),
        "completion_bonus_paid": float(m.completion_bonus_paid or 0),
        "created_at": m.created_at.isoformat() if m.created_at else None,
    } for m in active]

    # Money-safety check 1: any commission NOT yet paid (in-flight)?
    unpaid = db.query(_CMC).filter(_CMC.status != "paid").all()
    unpaid_summary = [{
        "id": c.id, "earner_id": c.earner_id, "amount": float(c.amount or 0),
        "status": c.status, "commission_type": c.commission_type,
    } for c in unpaid]

    # Money-safety check 2: completion-bonus exposure
    total_completion_paid = float(
        db.query(func.coalesce(func.sum(_CM.completion_bonus_paid), 0)).scalar() or 0
    )
    near_complete = [m.id for m in active if (m.positions_filled or 0) >= 35]

    # Total paid matrix commissions (this is earned money — STAYS, not touched)
    total_paid_commissions = float(
        db.query(func.coalesce(func.sum(_CMC.amount), 0))
          .filter(_CMC.status == "paid").scalar() or 0
    )

    return {
        "active_matrix_count": len(active),
        "completed_matrix_count": completed,
        "active_matrices": active_summary,
        "unpaid_commissions_count": len(unpaid),
        "unpaid_commissions": unpaid_summary,
        "completion_bonus_total_ever_paid": total_completion_paid,
        "matrices_near_completion_35plus": near_complete,
        "total_paid_commissions_all_time": total_paid_commissions,
        "close_out_safety": (
            "SAFE — no unpaid commissions, no completion exposure"
            if not unpaid and not near_complete
            else "REVIEW — see unpaid_commissions / matrices_near_completion before closing out"
        ),
        "note": "Paid commissions are earned money and are NEVER touched by close-out. "
                "Close-out only marks active matrices inactive so they stop filling/displaying.",
    }


@app.get("/admin/api/expired-active-members")
def admin_find_expired_active_members(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """List members who are is_active=True but whose membership_expires_at
    has already passed.

    This is the counterpart to /admin/api/stuck-lapsed-members. The active
    member count is the is_active flag, which is intentionally decoupled
    from expiry: when a membership expires the member enters a 5-day grace
    period during which they correctly remain active. So an expired-but-
    active member is NORMAL if they're inside grace.

    Split into two buckets:
      - "in_grace": expired <= 5 days ago — correct, no action needed.
      - "past_grace": expired > 5 days ago but STILL active — the real bug
        (the lapse step in process_auto_renewals never flipped them). These
        are the ones that genuinely inflate the active count.

    Read-only — never mutates anything.

    Built 30 May 2026 to answer "who are the expired-but-active members?" —
    there was previously no endpoint listing this group, only the per-user
    /admin/api/membership-state/{username}.
    """
    _require_admin(user)
    now = datetime.utcnow()
    GRACE_DAYS = 5

    rows = (
        db.query(User)
          .filter(
              User.is_active == True,
              User.membership_expires_at.isnot(None),
              User.membership_expires_at < now,
          )
          .all()
    )

    in_grace = []
    past_grace = []
    for u in rows:
        days_since_expiry = (now - u.membership_expires_at).days
        rec = {
            "user_id": u.id,
            "username": u.username,
            "first_name": u.first_name or "",
            "membership_tier": u.membership_tier,
            "membership_expires_at": u.membership_expires_at.isoformat(),
            "days_since_expiry": days_since_expiry,
        }
        if days_since_expiry <= GRACE_DAYS:
            in_grace.append(rec)
        else:
            past_grace.append(rec)

    return {
        "total_expired_active": len(rows),
        "in_grace_count": len(in_grace),
        "past_grace_count": len(past_grace),
        "in_grace": sorted(in_grace, key=lambda r: r["days_since_expiry"], reverse=True),
        "past_grace": sorted(past_grace, key=lambda r: r["days_since_expiry"], reverse=True),
        "grace_window_days": GRACE_DAYS,
        "note": "in_grace = normal (correctly active during 5-day grace). past_grace = genuine bug: expired beyond grace but never lapsed.",
        "checked_at": now.isoformat(),
    }


@app.post("/admin/api/reactivate-stuck-lapsed")
def admin_reactivate_stuck_lapsed_members(
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    dry_run: bool = False,
):
    """Reactivate all members detected by /admin/api/stuck-lapsed-members.

    Same detection logic as that endpoint — only reactivates members who:
      - Have is_active=False
      - Have an intact MembershipRenewal with future next_renewal_date
      - Are NOT in grace period
      - Have at least one confirmed membership Payment

    Mutations per stuck member:
      - user.is_active = True
      - Adds a Notification ("Membership reactivated — administrative
        correction") so the member sees what happened on their next login

    NOT changed: balance, total_earned, membership_tier, activated_at,
    next_renewal_date — none of these need to change because the
    membership data was already correct, only the is_active flag was
    wrong.

    dry_run=True (or ?dry_run=1) returns the list of members that
    WOULD be reactivated without actually mutating anything. Always
    run dry_run first to confirm the affected set looks right.

    Idempotent — re-running after success is a no-op (no rows match
    the stuck-lapsed criteria once they're reactivated).

    Built 8 May 2026 alongside the detection endpoint after test1
    was found in this state.
    """
    _require_admin(user)
    from .database import MembershipRenewal

    now = datetime.utcnow()

    candidates = (
        db.query(User, MembershipRenewal)
          .join(MembershipRenewal, MembershipRenewal.user_id == User.id)
          .filter(
              User.is_active == False,
              MembershipRenewal.next_renewal_date > now,
              MembershipRenewal.in_grace_period == False,
          )
          .all()
    )

    reactivated = []
    skipped_no_payment = []

    for u, r in candidates:
        has_paid_payment = db.query(Payment).filter(
            Payment.from_user_id == u.id,
            Payment.payment_type.like("membership%"),
            Payment.status.in_(["confirmed", "paid"]),
        ).first()
        if not has_paid_payment:
            skipped_no_payment.append(u.username)
            continue

        if not dry_run:
            u.is_active = True
            u.stuck_lapsed_alerted_at = None  # eligible for re-alert if they ever re-stick
            try:
                notif = Notification(
                    user_id=u.id,
                    type="system",
                    icon="✅",
                    title="Membership reactivated",
                    message="An administrative correction has reactivated your membership. "
                            "Your renewal date and other details are unchanged.",
                    link="/dashboard",
                )
                db.add(notif)
            except Exception as e:
                logger.warning(f"Reactivation notification failed for user {u.id}: {e}")

        reactivated.append({
            "user_id": u.id,
            "username": u.username,
            "next_renewal_date": r.next_renewal_date.isoformat(),
        })

    if not dry_run:
        db.commit()
        logger.info(
            f"Admin reactivation: {len(reactivated)} stuck-lapsed members reactivated "
            f"by admin user {user.id} ({user.username}). "
            f"Skipped {len(skipped_no_payment)} candidates with no paid membership."
        )

    return {
        "dry_run": dry_run,
        "reactivated_count": len(reactivated),
        "reactivated": reactivated,
        "skipped_no_payment_count": len(skipped_no_payment),
        "skipped_no_payment": skipped_no_payment,
        "message": (
            "DRY RUN — no changes made. Re-run without ?dry_run=1 to apply."
            if dry_run else
            f"Reactivated {len(reactivated)} stuck-lapsed members."
        ),
    }


