@app.post("/admin/api/backfill-gift-commission/{voucher_code}")
def admin_backfill_gift_commission(
    voucher_code: str,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """One-off admin backfill: pay a gift commission that was missed
    because the claim happened BEFORE commit 744cb15c (which added the
    commission logic to the claim endpoint).

    Specifically built to handle test5's claim from 8 May 2026 which
    landed ~15 minutes before the deploy that added gift commission
    payment. Test3 should have received $10 but the old code path paid
    nothing.

    Idempotent — checks for an existing gift_membership_sponsor
    Commission row from the giftee to the gifter and exits cleanly if
    one already exists. Safe to call multiple times.

    Admin-only. The voucher_code path param identifies which historical
    claim to backfill. Returns the before/after state so the admin can
    verify the change.
    """
    _require_admin(user)
    from .database import GiftVoucher

    voucher = db.query(GiftVoucher).filter(
        GiftVoucher.voucher_code == voucher_code.upper()
    ).first()
    if not voucher:
        return JSONResponse({"error": f"Voucher {voucher_code} not found"}, status_code=404)
    if voucher.status != "claimed" or not voucher.claimed_by_user_id:
        return JSONResponse({
            "error": "Voucher must be in claimed state to backfill commission",
            "current_status": voucher.status,
        }, status_code=400)

    gifter = db.query(User).filter(User.id == voucher.gifter_user_id).first()
    recipient = db.query(User).filter(User.id == voucher.claimed_by_user_id).first()
    if not gifter or not recipient:
        return JSONResponse({"error": "Gifter or recipient user not found"}, status_code=404)

    # Idempotency check — has this commission already been paid?
    existing = db.query(Commission).filter(
        Commission.commission_type == "gift_membership_sponsor",
        Commission.to_user_id == gifter.id,
        Commission.from_user_id == recipient.id,
    ).first()
    if existing:
        return {
            "already_paid": True,
            "message": "Gift commission already exists — no changes made",
            "existing_commission_id": existing.id,
            "existing_amount": float(existing.amount_usdt or 0),
            "existing_paid_at": existing.paid_at.isoformat() if existing.paid_at else None,
        }

    # Capture before-state for the response
    before = {
        "gifter_balance": float(gifter.balance or 0),
        "gifter_total_earned": float(gifter.total_earned or 0),
        "gifter_personal_referrals": gifter.personal_referrals or 0,
    }

    # Apply the commission — exact same logic as the live claim endpoint,
    # except paid_at uses the original claim timestamp so analytics align.
    from decimal import Decimal
    gift_commission = Decimal("10.00")
    gifter.balance = Decimal(str(gifter.balance or 0)) + gift_commission
    gifter.total_earned = Decimal(str(gifter.total_earned or 0)) + gift_commission

    from sqlalchemy import func as _sqlfunc
    db.query(User).filter(User.id == gifter.id).update({
        User.personal_referrals: _sqlfunc.coalesce(User.personal_referrals, 0) + 1,
    }, synchronize_session=False)

    paid_at_ts = voucher.claimed_at or datetime.utcnow()
    comm = Commission(
        to_user_id=gifter.id,
        from_user_id=recipient.id,
        amount_usdt=gift_commission,
        commission_type="gift_membership_sponsor",
        package_tier=0,
        notes=f"Pay It Forward: {recipient.username} claimed gift voucher "
              f"{voucher.voucher_code} (admin backfill — claim predated commission logic)",
        status="paid",
        paid_at=paid_at_ts,
        created_at=paid_at_ts,
    )
    db.add(comm)

    try:
        notif = Notification(
            user_id=gifter.id,
            title="🎁 Your gift was claimed!",
            message=f"{recipient.first_name or recipient.username} just activated their "
                    f"membership using your gift. You earned a $10 sponsor commission.",
            notification_type="gift_claimed",
            created_at=datetime.utcnow(),
        )
        db.add(notif)
    except Exception as e:
        logger.warning(f"Backfill notification creation failed for gifter {gifter.id}: {e}")

    db.commit()
    db.refresh(gifter)
    # Cache invalidation — gifter just received a backfilled commission
    try:
        cache_invalidate_user(gifter.id)
    except Exception as e:
        logger.warning(f"cache_invalidate_user({gifter.id}) failed in admin backfill: {e}")

    logger.info(
        f"Admin backfill: ${gift_commission} gift commission paid to {gifter.username} "
        f"for voucher {voucher.voucher_code} (claimed by {recipient.username} at {paid_at_ts})"
    )

    return {
        "success": True,
        "voucher_code": voucher.voucher_code,
        "gifter": gifter.username,
        "recipient": recipient.username,
        "commission_paid": float(gift_commission),
        "before": before,
        "after": {
            "gifter_balance": float(gifter.balance or 0),
            "gifter_total_earned": float(gifter.total_earned or 0),
            "gifter_personal_referrals": gifter.personal_referrals or 0,
        },
    }
# ═══════════════════════════════════════════════════════════════
#  REACT SPA — Serve the built React frontend
# ═══════════════════════════════════════════════════════════════
import pathlib

_react_index = pathlib.Path("static/app/index.html")

# Read the React entry HTML once at module load, then serve from memory.
# Without this, every SPA route handler (106 of them) calls read_text() on
# every request — first hit is a fresh disk read (~1s on Railway containers),
# only after the OS file cache warms up does it drop to <50ms. By caching
# at startup we eliminate that variance: every TTFB is consistent.
# Cache invalidates when Railway restarts the process (which happens on
# every deploy), so frontend updates land naturally.
_react_index_html_cache = None
def _get_react_index_html():
    global _react_index_html_cache
    if _react_index_html_cache is None:
        try:
            _react_index_html_cache = _react_index.read_text()
        except Exception:
            return None
    return _react_index_html_cache

# Pre-warm at module import so the first request after a Railway restart
# doesn't pay the disk-read cost. Moves ~700ms from "first user's load"
# to "Railway startup time" which is invisible.
try:
    _get_react_index_html()
except Exception:
    pass

@app.get("/app/{full_path:path}")
async def serve_react_app(full_path: str):
    """Serve the React SPA for all /app/* routes."""
    html = _get_react_index_html()
    if html is not None:
        return HTMLResponse(html)
    return HTMLResponse("<h2>React app not built yet. Run: cd frontend && npm run build</h2>", status_code=503)
@app.post("/api/account/update")
async def api_account_update(request: Request, user: User = Depends(get_current_user),
                             db: Session = Depends(get_db)):
    """Update user profile fields."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    body = await request.json()
    if "first_name" in body:
        user.first_name = (body["first_name"] or "").strip()[:100]
    if "last_name" in body:
        user.last_name = (body["last_name"] or "").strip()[:100]
    if "email" in body:
        email = (body["email"] or "").strip()[:200]
        if email and "@" in email:
            user.email = email
    if "avatar_url" in body:
        user.avatar_url = body["avatar_url"]
    if "country" in body:
        user.country = (body["country"] or "").strip()[:100]
    if "interests" in body:
        # Comma-separated interest tags, sanitise each
        raw = (body["interests"] or "").strip()[:500]
        user.interests = ", ".join([t.strip()[:50] for t in raw.split(",") if t.strip()][:20])
    if "gender" in body:
        g = (body["gender"] or "").strip().lower()
        if g in ("male", "female", "other", ""):
            user.gender = g or None
    if "age_range" in body:
        ar = (body["age_range"] or "").strip()
        if ar in ("18-24", "25-34", "35-44", "45-54", "55+", ""):
            user.age_range = ar or None
    if "wallet_address" in body or "wallet_network" in body:
        # Wallet address and network must be saved together. If only one is
        # provided in the request body, fall back to the existing user value
        # for the other so we can still validate consistency. The validate
        # call runs against the COMBINED final state, not the partial input.
        wa = (body.get("wallet_address", user.wallet_address) or "").strip()
        wn_raw = body.get("wallet_network", user.wallet_network)
        wn = (wn_raw or "").strip().lower() if wn_raw is not None else None

        # Allow clearing both together (member wants to reset)
        if wa == "" and wn in (None, ""):
            user.wallet_address = None
            user.wallet_network = None
        else:
            # If saving a wallet, network MUST be specified — no silent
            # ambiguity. The dispatcher needs network to route correctly.
            if not wn or wn not in ("tron", "bsc"):
                return JSONResponse(
                    {"error": "Withdrawal network is required. Choose TRC-20 (Tron) or BEP-20 (BSC)."},
                    status_code=400,
                )
            # Validate wallet format against the chosen network
            if not validate_wallet(wa, network=wn):
                expected = "T-prefix base58 (34 chars) for Tron" if wn == "tron" else "0x-prefix hex (42 chars) for BSC"
                return JSONResponse(
                    {"error": f"Wallet address doesn't match the chosen network. Expected {expected}."},
                    status_code=400,
                )
            user.wallet_address = wa
            user.wallet_network = wn
    db.commit()
    return {"ok": True}
@app.post("/api/account/change-password")
async def api_change_password(request: Request, user: User = Depends(get_current_user),
                               db: Session = Depends(get_db)):
    """Change password via JSON API."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    import bcrypt
    body = await request.json()
    current = body.get("current_password", "")
    new_pw = body.get("new_password", "")
    confirm = body.get("confirm_password", "")

    if not bcrypt.checkpw(current.encode(), user.password.encode()):
        return JSONResponse({"error": "Current password is incorrect"}, status_code=400)
    if len(new_pw) < 8:
        return JSONResponse({"error": "New password must be at least 8 characters"}, status_code=400)
    if new_pw != confirm:
        return JSONResponse({"error": "New passwords do not match"}, status_code=400)

    user.password = bcrypt.hashpw(new_pw.encode(), bcrypt.gensalt()).decode()
    db.commit()
    return {"ok": True}
def api_courses_list(request: Request, db: Session = Depends(get_db)):
    """List platform courses for the course library."""
    from .database import Course, CourseChapter, CourseLesson
    courses = db.query(Course).order_by(Course.id).all()
    result = []
    for c in courses:
        chapters = db.query(CourseChapter).filter(CourseChapter.course_id == c.id).count()
        lessons = db.query(CourseLesson).filter(CourseLesson.course_id == c.id).count()
        total_dur = sum(l.duration_minutes or 0 for l in db.query(CourseLesson).filter(CourseLesson.course_id == c.id).all())
        result.append({
            "id": c.id, "title": c.title, "description": c.description or "",
            "price": float(c.price or 0), "thumbnail_url": c.thumbnail_url or "",
            "category": c.category or "course",
            "chapter_count": chapters, "lesson_count": lessons,
            "total_duration": total_dur,
        })
    return {"courses": result}
