@app.get("/api/leaderboard")
def api_leaderboard(db: Session = Depends(get_db)):
    """JSON leaderboard data with full user info + recent activity feed. Cached 5 min.

    Performance: this endpoint used to N+1-query — three separate
    queries per user (active grid, nexus team count, live referral
    count) inside user_data(), called for up to 20 users across 5
    boards = ~300 round-trips per cache miss. Plus another N queries
    in the activity feed for resolving commission earners.

    Refactored 5 May 2026 to bulk-load each per-user dimension once
    up front, then look up by user_id from a dict. Drops cache-miss
    cost from ~300 queries to ~10. The 5-minute cache hides this
    most of the time, but cold starts (every Railway replica restart,
    every cache TTL expiry under low traffic) felt sluggish to users
    — that's what triggered the rewrite.
    """
    from sqlalchemy import func

    # Check cache first (leaderboard is same for everyone)
    cache_key = "leaderboard:main"
    cached = cache_get(cache_key)
    if cached:
        return cached

    # ── Pull the user sets for each board ─────────────────────────────
    # Top referrers — by paid personal_referrals (active members only)
    ref_leaders = db.query(User).filter(
        User.is_active == True, User.personal_referrals > 0
    ).order_by(User.personal_referrals.desc()).limit(20).all()

    # Top sign-up sponsors — by total_team (anyone joined via your link,
    # paid or not). This board fills up faster than ref_leaders since it
    # doesn't require the downline to be on a paid plan.
    signup_users = db.query(User).filter(
        User.total_team > 0
    ).order_by(User.total_team.desc()).limit(20).all()

    # Top grid builders (by total team size)
    grid_users = db.query(User).filter(
        User.is_active == True, User.total_team > 0
    ).order_by(User.total_team.desc()).limit(20).all()

    # Top course sellers
    course_users = db.query(User).filter(
        User.is_active == True, User.course_sale_count > 0
    ).order_by(User.course_sale_count.desc()).limit(20).all()

    # Top Nexus builders — by unique users across all owned matrixes.
    # Computed via a subquery so we can ORDER BY the count.
    from sqlalchemy import func as sa_func
    nexus_team_subq = (
        db.query(
            CreditMatrix.owner_id.label("owner_id"),
            sa_func.count(sa_func.distinct(CreditMatrixPosition.user_id)).label("team_count"),
        )
        .join(CreditMatrixPosition, CreditMatrixPosition.matrix_id == CreditMatrix.id)
        .group_by(CreditMatrix.owner_id)
        .subquery()
    )
    nexus_users_q = (
        db.query(User)
        .join(nexus_team_subq, nexus_team_subq.c.owner_id == User.id)
        .filter(User.is_active == True, nexus_team_subq.c.team_count > 1)
        .order_by(nexus_team_subq.c.team_count.desc())
        .limit(20)
        .all()
    )

    # ── Bulk-load per-user dimensions in 3 queries (was 3 per user) ──
    # Collect every user_id appearing on any board so we only fetch what
    # we'll actually display. set() deduplicates across boards.
    all_user_ids = list({
        u.id
        for board in (ref_leaders, signup_users, grid_users, course_users, nexus_users_q)
        for u in board
    })

    # 1. Active grid per user — highest tier, not complete.
    # SQL: SELECT owner_id, MAX(package_tier), SUM(positions_filled)
    #      FROM grids WHERE owner_id IN (...) AND is_complete = false
    #      GROUP BY owner_id
    # We want the highest tier AND its positions_filled. MAX(tier) is
    # easy in SQL, but pairing it with positions_filled from THE SAME
    # row (rather than max positions across all tiers) needs a small
    # window-function trick OR a follow-up. Simpler: fetch the matching
    # rows, sort in Python (max 20 rows total — trivial).
    grid_by_owner = {}
    if all_user_ids:
        grid_rows = db.query(Grid).filter(
            Grid.owner_id.in_(all_user_ids),
            Grid.is_complete == False,
        ).all()
        for g in grid_rows:
            existing = grid_by_owner.get(g.owner_id)
            if existing is None or g.package_tier > existing.package_tier:
                grid_by_owner[g.owner_id] = g

    # 2. Nexus team size per user — distinct user count across all
    # matrixes they own, minus self. Single GROUP BY query.
    nexus_count_by_owner = {}
    if all_user_ids:
        nexus_rows = (
            db.query(
                CreditMatrix.owner_id,
                sa_func.count(sa_func.distinct(CreditMatrixPosition.user_id)).label("c"),
            )
            .join(CreditMatrixPosition, CreditMatrixPosition.matrix_id == CreditMatrix.id)
            .filter(CreditMatrix.owner_id.in_(all_user_ids))
            .group_by(CreditMatrix.owner_id)
            .all()
        )
        # Subtract self (CreditMatrix seeds owner at root)
        nexus_count_by_owner = {row.owner_id: max(0, row.c - 1) for row in nexus_rows}

    # 3. Live personal-referrals — count of current users sponsored by
    # each leaderboard user. Replaces the stored counter that doesn't
    # decrement on user deletion. Single GROUP BY query — no N+1.
    referrals_by_sponsor = {}
    if all_user_ids:
        ref_rows = (
            db.query(User.sponsor_id, sa_func.count(User.id).label("c"))
            .filter(User.sponsor_id.in_(all_user_ids))
            .group_by(User.sponsor_id)
            .all()
        )
        referrals_by_sponsor = {row.sponsor_id: row.c for row in ref_rows}

    def user_data(u):
        """Build per-user payload from pre-loaded dicts. No DB calls
        here — all dimensions were bulk-loaded above."""
        active_grid = grid_by_owner.get(u.id)
        grid_tier = active_grid.package_tier if active_grid else 0
        grid_count = active_grid.positions_filled if active_grid else 0
        nexus_team = nexus_count_by_owner.get(u.id, 0)
        live_refs = referrals_by_sponsor.get(u.id, 0)

        return {
            "id": u.id,
            "username": u.username,
            "first_name": u.first_name or u.username,
            "last_name": u.last_name or "",
            "avatar_url": u.avatar_url or None,
            "personal_referrals": live_refs,
            "total_team": u.total_team or 0,
            "total_earned": float(u.total_earned or 0),
            "course_sale_count": u.course_sale_count or 0,
            "grid_tier": grid_tier,
            "_grid_count": grid_count,
            "_course_count": u.course_sale_count or 0,
            "_nexus_count": nexus_team,
            "membership_tier": u.membership_tier or "free",
        }

    # ── Recent activity feed (last 20 events) ──
    from datetime import timedelta
    week_ago = datetime.utcnow() - timedelta(days=7)

    # Recent signups
    recent_joins = db.query(User).filter(
        User.created_at >= week_ago, User.is_active == True
    ).order_by(User.created_at.desc()).limit(10).all()

    # Recent commissions — across all 3 commission tables.
    # Only membership-related Commission rows are shown from the
    # Commission table (that was the original intent of this filter
    # — to surface "X earned" moments rather than internal grid plumbing).
    # CreditMatrixCommission + CourseCommission added 7 May 2026 so
    # Credit Nexus and Course earners also show up in the public feed.
    recent_comms = db.query(Commission).filter(
        Commission.created_at >= week_ago,
        Commission.status == "paid",
        Commission.commission_type.in_(["membership_sponsor", "membership_renewal", "gift_membership_sponsor"])
    ).order_by(Commission.created_at.desc()).limit(10).all()

    recent_matrix = db.query(CreditMatrixCommission).filter(
        CreditMatrixCommission.created_at >= week_ago,
        CreditMatrixCommission.status == "paid",
    ).order_by(CreditMatrixCommission.created_at.desc()).limit(10).all()

    recent_course = db.query(CourseCommission).filter(
        CourseCommission.created_at >= week_ago,
    ).order_by(CourseCommission.created_at.desc()).limit(10).all()

    # Bulk-load earners across all 3 sources in one query (was N+1).
    earner_by_id = {}
    earner_ids = list({
        *(c.to_user_id for c in recent_comms if c.to_user_id),
        *(c.earner_id for c in recent_matrix if c.earner_id),
        *(c.earner_id for c in recent_course if c.earner_id),
    })
    if earner_ids:
        earner_rows = db.query(User).filter(User.id.in_(earner_ids)).all()
        earner_by_id = {u.id: u for u in earner_rows}

    activity = []
    for u in recent_joins:
        activity.append({
            "type": "join",
            "icon": "👋",
            "text": f"{u.first_name or u.username} joined SuperAdPro",
            "time": u.created_at.isoformat() if u.created_at else None,
        })
    for c in recent_comms:
        earner = earner_by_id.get(c.to_user_id)
        if earner:
            activity.append({
                "type": "earning",
                "icon": "💰",
                "text": f"{earner.first_name or earner.username} earned a commission",
                "time": c.created_at.isoformat() if c.created_at else None,
            })
    for c in recent_matrix:
        earner = earner_by_id.get(c.earner_id)
        if earner:
            activity.append({
                "type": "earning",
                "icon": "💎",
                "text": f"{earner.first_name or earner.username} earned a Credit Nexus commission",
                "time": c.created_at.isoformat() if c.created_at else None,
            })
    for c in recent_course:
        earner = earner_by_id.get(c.earner_id)
        if earner:
            activity.append({
                "type": "earning",
                "icon": "🎓",
                "text": f"{earner.first_name or earner.username} earned a course commission",
                "time": c.created_at.isoformat() if c.created_at else None,
            })

    # Sort by time, newest first
    activity.sort(key=lambda x: x.get("time") or "", reverse=True)
    activity = activity[:20]

    # Platform stats — commissions paid OUT TO MEMBERS only.
    # Filter to_user_id IS NOT NULL (Commission table) excludes platform
    # fees and overflow-to-company commissions (where to_user_id is None).
    # Without this filter the headline "paid out to members" number is
    # inflated by company-routed revenue, which is misleading on a
    # leaderboard marketed as showing what members have earned.
    # (Fix 4 May 2026.)
    # Updated 7 May 2026 to sum across all 3 commission tables —
    # previously only counted Commission, undercounting Credit Nexus
    # + Course payouts.
    total_members = db.query(User).filter(User.is_active == True).count()
    total_earned_grid = float(db.query(func.sum(Commission.amount_usdt)).filter(
        Commission.status == "paid",
        Commission.to_user_id.isnot(None),
    ).scalar() or 0)
    total_earned_matrix = float(db.query(func.sum(CreditMatrixCommission.amount)).filter(
        CreditMatrixCommission.status == "paid",
    ).scalar() or 0)
    total_earned_course = float(db.query(func.sum(CourseCommission.amount)).scalar() or 0)
    total_earned = total_earned_grid + total_earned_matrix + total_earned_course

    result = {
        "ref_leaders": [user_data(u) for u in ref_leaders],
        "signup_users": [user_data(u) for u in signup_users],
        "grid_users": [user_data(u) for u in grid_users],
        "nexus_users": [user_data(u) for u in nexus_users_q],
        "course_users": [user_data(u) for u in course_users],
        "activity": activity,
        "stats": {
            "total_members": total_members,
            "total_earned": total_earned,
        }
    }

    # Cache for 5 minutes (same for all users)
    cache_set(cache_key, result, ttl=300)

    return result
@app.get("/api/campaign-tiers")
def api_campaign_tiers(request: Request, user: User = Depends(get_current_user),
                       db: Session = Depends(get_db)):
    """JSON campaign tier data with active status from both campaigns and grids."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    from .database import GRID_PACKAGES, GRID_TIER_NAMES, CAMPAIGN_VIEW_TARGETS, GRID_COMPLETION_BONUS

    # Check active video campaigns (qualification)
    active_campaigns = db.query(VideoCampaign).filter(
        VideoCampaign.user_id == user.id,
        VideoCampaign.status == "active",
        VideoCampaign.is_completed == False
    ).all()
    active_campaign_tiers = {c.campaign_tier for c in active_campaigns}

    # Per-tier campaign progress: sum views_delivered across active campaigns
    # at each tier. Used by the active-tier card's progress bar so the member
    # can see how close they are to campaign completion (which is also the
    # gate for repurchasing the tier per product rule).
    progress_by_tier = {}
    for c in active_campaigns:
        tier = (c.campaign_tier if c.campaign_tier is not None else -1)
        if tier < 0:
            continue
        agg = progress_by_tier.setdefault(tier, {"views_delivered": 0, "views_target": 0})
        agg["views_delivered"] += int(c.views_delivered or 0)
        agg["views_target"]    += int(c.views_target or 0)

    # Check grids. A tier is "active/owned" ONLY if the owner GENUINELY
    # purchased it (owner_purchased=True) — NOT merely because a grid row
    # exists. Spillover from a downline auto-creates a Grid via
    # get_or_create_active_grid with owner_purchased=False; those must not
    # show the owner as having bought the tier (fixed 30 May 2026 — members
    # were seeing tiers ACTIVE that they never paid for).
    active_grids = db.query(Grid).filter(
        Grid.owner_id == user.id,
        Grid.is_complete == False,
        Grid.owner_purchased == True,  # noqa: E712 — genuine purchase only
    ).all()
    completed_grids = db.query(Grid).filter(
        Grid.owner_id == user.id,
        Grid.is_complete == True,
        Grid.owner_purchased == True,  # noqa: E712
    ).all()
    grid_by_tier = {}
    completed_tier_set = {g.package_tier for g in completed_grids}
    for g in active_grids:
        grid_by_tier[g.package_tier] = {
            "filled": g.positions_filled or 0,
            "pct": round((g.positions_filled or 0) / g.total_seats * 100),
            "advance": g.advance_number or 1,
        }

    # Admin always active at all tiers
    is_admin = user.is_admin

    # Build tier data
    tiers = []
    for tier_num in range(0, 9):
        price = GRID_PACKAGES.get(tier_num, 0)
        direct_comm = round(price * 0.30, 2)
        uni_level_per_member = round(price * 0.0625, 2)
        bonus = completion_bonus_for(NEW_GRID_SEATS, price)
        views = CAMPAIGN_VIEW_TARGETS.get(tier_num, 0)
        is_active = is_admin or (tier_num in active_campaign_tiers) or (tier_num in grid_by_tier) or (tier_num in completed_tier_set)
        grid_info = grid_by_tier.get(tier_num)
        progress = progress_by_tier.get(tier_num)

        tiers.append({
            "tier": tier_num,
            "name": GRID_TIER_NAMES.get(tier_num, f"Tier {tier_num}"),
            "price": price,
            "views_target": views,
            "direct_commission": direct_comm,
            "uni_level_per_member": uni_level_per_member,
            "completion_bonus": bonus,
            "is_active": is_active,
            "grid": grid_info,
            # Campaign progress on the user's active campaigns at this tier
            # (used by the active-tier card's progress bar). None when the
            # user has no active campaign at this tier.
            "campaign_progress": progress,
        })

    return {
        "tiers": tiers,
        "active_tiers": [t["tier"] for t in tiers if t["is_active"]],
        "completed_count": len(completed_grids),
    }



# ═══════════════════════════════════════════════════════════════
#  SUPERMARKET / DIGITAL PRODUCT MARKETPLACE — RETIRED
# ═══════════════════════════════════════════════════════════════
# The SuperMarket digital product marketplace has been retired. All
# /api/supermarket/* endpoints (browse, product CRUD, upload, purchase,
# reviews, affiliate, admin review) have been removed. DigitalProduct,
# DigitalProductPurchase, DigitalProductReview, and DigitalProductAffiliate
# tables remain in the database for historical data integrity but are no
# longer written to.

@app.get("/api/watch")
@limiter.limit("30/minute")
def api_watch_data(request: Request, user: User = Depends(get_current_user),
                   db: Session = Depends(get_db)):
    """JSON watch-to-earn data — uses smart rotation from get_next_content()."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    # ── Tier gate (Apr 2026) ──
    # Watch-to-Earn is a product unlocked by buying a Campaign Tier.
    # Without an active tier there's no campaign in the system to earn from,
    # so basic-only members can't access this endpoint. Admin users bypass
    # via get_user_highest_tier returning 8 for is_admin=true.
    if get_user_highest_tier(db, user.id) < 0:
        return JSONResponse({
            "error": "tier_required",
            "message": "Watch-to-Earn unlocks when you activate a Campaign Tier. Visit /campaign-tiers to get started.",
            "redirect": "/campaign-tiers",
        }, status_code=403)
    try:
        quota = get_or_create_quota(db, user)
        db.commit()

        today_str = datetime.utcnow().strftime("%Y-%m-%d")
        watched_today = quota.today_watched or 0
        # daily_required can legitimately be 0 (admin/owner exemption).
        # Use a None check so 0 stays 0 rather than collapsing to a default.
        daily_limit = quota.daily_required if quota.daily_required is not None else 1
        is_exempt = (daily_limit == 0)
        # Exempt users are always "qualified" — never blocked from earning,
        # never asked to watch. They can still watch if they want.
        quota_reached = is_exempt or (watched_today >= daily_limit)

        # Get next content using the smart scoring/rotation algorithm
        # This handles: priority scoring, re-watches, own-campaign fallback,
        # geo/interest targeting, and ad board interleaving
        next_content = None
        next_video = None
        if not quota_reached:
            # ── Server-side anti-cheat: one-at-a-time enforcement ──
            # If the user has an existing started-but-not-complete VideoWatch
            # row from today, force them to finish THAT video first instead
            # of letting them get assigned a new one. Without this, an attacker
            # could pre-load N started rows in quick succession then wait 30s
            # and complete them all - bypassing the per-video timing intent.
            # This forces serial-watch: one video at a time, each timed.
            existing_started = db.query(VideoWatch).filter(
                VideoWatch.user_id == user.id,
                VideoWatch.watch_date == today_str,
                VideoWatch.is_complete == False,  # noqa: E712
            ).first()
            if existing_started:
                # Look up the campaign and serve that one (still active?)
                forced_c = db.query(VideoCampaign).filter(
                    VideoCampaign.id == existing_started.campaign_id,
                    VideoCampaign.status == "active",
                ).first()
                if forced_c:
                    # Compute seconds remaining server-side so the frontend
                    # timer can resume from the actual elapsed time, not
                    # always restart at 30. Without this, a user who walked
                    # away mid-watch and came back could be locked out: the
                    # server would accept their mark-complete (>=30s elapsed)
                    # but the frontend timer is showing 30s remaining and
                    # the button stays disabled.
                    elapsed = (datetime.utcnow() - existing_started.started_at).total_seconds() if existing_started.started_at else 0
                    seconds_remaining = max(0, int(WATCH_DURATION - elapsed))
                    next_video = {
                        "id": forced_c.id, "title": forced_c.title,
                        "platform": forced_c.platform or "youtube",
                        "category": forced_c.category or "General",
                        "embed_url": forced_c.embed_url,
                        "cta_url": forced_c.cta_url or None,
                        "is_watched": False,
                        "seconds_remaining": seconds_remaining,
                        "is_resumed": True,
                    }
                else:
                    # Campaign no longer active - clean up the orphan started
                    # row so the user can be assigned a different video
                    db.delete(existing_started)
                    db.commit()

            if not next_video:
                next_content = get_next_content(db, user.id)
                if next_content:
                    if next_content["type"] == "video":
                        c = next_content["data"]
                        next_video = {"id": c.id, "title": c.title, "platform": c.platform or "youtube",
                                      "category": c.category or "General", "embed_url": c.embed_url,
                                      "cta_url": c.cta_url or None, "is_watched": False,
                                      "seconds_remaining": WATCH_DURATION,
                                      "is_resumed": False}
                        # ── Server-side anti-cheat: record assignment timestamp ──
                        # When the rotation gives the user a video, create a
                        # VideoWatch row with started_at=now and is_complete=False.
                        # /api/watch/complete checks this row to verify >=30s have
                        # passed since assignment before accepting the completion.
                        # Without this row existing, the completion is rejected -
                        # blocking the curl-the-completion-endpoint exploit.
                        # If a started row already exists for this campaign today
                        # (user refreshed the page mid-watch), reuse it - don't
                        # reset the timer.
                        existing = db.query(VideoWatch).filter(
                            VideoWatch.user_id == user.id,
                            VideoWatch.campaign_id == c.id,
                            VideoWatch.watch_date == today_str,
                        ).first()
                        if not existing:
                            started_row = VideoWatch(
                                user_id=user.id,
                                campaign_id=c.id,
                                watch_date=today_str,
                                started_at=datetime.utcnow(),
                                duration_secs=0,
                                is_complete=False,
                            )
                            db.add(started_row)
                            db.commit()
                    elif next_content["type"] == "adboard":
                        a = next_content["data"]
                        next_video = {"id": a.id, "title": a.title, "platform": "adboard",
                                      "category": a.category or "Ad", "embed_url": "",
                                      "image_url": a.image_url or "", "link_url": a.link_url or "",
                                      "description": a.description or "", "is_watched": False, "type": "adboard"}

        # Build videos list: the next video to watch (if any)
        videos = [next_video] if next_video else []

        # Has-Campaign-Tier flag for the empty-state UI - lets us show
        # appropriate CTAs depending on whether the user is already a paying
        # campaign owner or needs to buy a tier first. get_user_highest_tier
        # returns 0 for unpaid users, 8 for admins.
        user_has_tier = get_user_highest_tier(db, user.id) >= 0

        return {
            "watched_today": watched_today,
            "daily_limit": daily_limit,
            "daily_required": daily_limit,
            "is_exempt": is_exempt,
            "quota_reached": quota_reached,
            "tier": (quota.package_tier if quota.package_tier is not None else 1),
            "has_campaign_tier": user_has_tier,
            "streak_days": getattr(quota, 'streak_days', 0) or 0,
            "total_watched": getattr(quota, 'total_watched', 0) or 0,
            "commissions_paused": getattr(quota, 'commissions_paused', False),
            "total_minutes": 0,
            "total_watch_earnings": 0,
            "videos": videos,
            "has_more": next_video is not None,
        }
    except Exception as e:
        import traceback
        traceback.print_exc()
        return JSONResponse({"error": str(e)}, status_code=500)
@app.get("/admin/replay-my-badge-toast")
async def admin_replay_my_badge_toast(
    request: Request,
    badge_id: str = "grid_bonus_paid",
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Re-mark ALL of the admin's achievement notifications as unread,
    so the dashboard toast fires on next load. Also returns full debug
    info so we can see exactly what the unseen endpoint will return.

    Idempotent (just flips is_read flags).

    Updated 26 May 2026 — earlier version used a fragile title-LIKE match
    that didn't reliably flip the flag for Steve's grid_bonus_paid notif.
    New approach: flip ALL achievement notifications for the user (3 are
    capped on the unseen feed anyway), then show what unseen would return.
    """
    from fastapi.responses import JSONResponse
    if not user or not user.is_admin:
        return JSONResponse({"error": "Admin only"}, status_code=403)
    from .database import Notification as _Notification, Achievement as _Achievement

    # Step 1: Inspect current state — what achievement notifications exist?
    all_ach_notifs = db.query(_Notification).filter(
        _Notification.user_id == user.id,
        _Notification.type == "achievement",
    ).order_by(_Notification.created_at.desc()).all()

    notif_summary = [{
        "id": n.id,
        "title": n.title,
        "is_read_before": bool(n.is_read),
        "created_at": n.created_at.isoformat() + "Z" if n.created_at else None,
    } for n in all_ach_notifs]

    # Step 2: Flip ALL of them to unread (bulletproof — no title matching)
    flipped = db.query(_Notification).filter(
        _Notification.user_id == user.id,
        _Notification.type == "achievement",
        _Notification.is_read == True,
    ).update({_Notification.is_read: False}, synchronize_session=False)
    db.commit()

    # Step 3: Confirm what /api/achievements/unseen would now return
    unseen_now = db.query(_Notification).filter(
        _Notification.user_id == user.id,
        _Notification.type == "achievement",
        _Notification.is_read == False,
    ).order_by(_Notification.created_at.desc()).limit(3).all()

    return {
        "ok": True,
        "user_id": user.id,
        "achievement_notifications_found": len(all_ach_notifs),
        "before_flip": notif_summary,
        "flipped_to_unread": int(flipped or 0),
        "now_unseen_count": len(unseen_now),
        "now_unseen_ids": [n.id for n in unseen_now],
        "instruction": (
            "Hit /api/achievements/unseen first to confirm rows are now returned, "
            "then refresh your dashboard (Ctrl+Shift+R for hard refresh) and the "
            "purple toast should slide out from top-right."
        ),
    }


@app.get("/api/achievements/unseen")
def api_achievements_unseen(request: Request, user: User = Depends(get_current_user),
                             db: Session = Depends(get_db)):
    """Returns achievement notifications that haven't been shown to the
    member as a toast yet. Dashboard polls this on load + every 60s; if
    any rows come back, it renders a slide-out toast for each one and
    then calls /api/achievements/mark-seen to flag them as shown.

    Why this is separate from /api/notifications: dashboard toasts are
    a different surface from the bell-icon notification list. A member
    might dismiss the toast (which marks as seen) but still want to find
    the notification later in their bell. We use Notification.is_read as
    the toast-seen flag — once toasted, is_read=True, and the bell will
    show it as already-read. Acceptable trade-off for now; if we want
    finer-grained control later we can add a separate toast_seen field.

    Added 26 May 2026 per Steve's request to surface the new grid bonus
    badge as a dashboard toast rather than relying on members navigating
    to /achievements to discover it.
    """
    from fastapi.responses import JSONResponse
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    from .database import Notification as _Notification, Achievement as _Achievement
    # Only achievement-type notifications, unread, most recent first.
    # Cap at 3 — if a member has more than 3 unseen achievements queued,
    # toasting them all would be overwhelming. Show the most recent 3
    # and let the rest accumulate quietly in the bell.
    rows = db.query(_Notification).filter(
        _Notification.user_id == user.id,
        _Notification.type == "achievement",
        _Notification.is_read == False,
    ).order_by(_Notification.created_at.desc()).limit(3).all()
    if not rows:
        return {"unseen": []}

    # Enrich with the actual Achievement metadata (so grid_bonus_paid
    # toasts can render the $72 amount + tier).
    out = []
    for n in rows:
        # Match the notification to its Achievement row by title (loose
        # but reliable — the badge title is unique and the notification
        # title is "Badge earned: <title>!"). For grid_bonus_paid pull
        # the metadata_json so the toast shows the amount + tier.
        ach = db.query(_Achievement).filter(
            _Achievement.user_id == user.id,
            _Achievement.title.in_([
                n.title.replace("Badge earned: ", "").rstrip("!"),
                n.title,
            ]),
        ).order_by(_Achievement.earned_at.desc()).first()
        meta = None
        badge_id = None
        if ach:
            badge_id = ach.badge_id
            if ach.metadata_json:
                try:
                    import json as _json_a
                    meta = _json_a.loads(ach.metadata_json)
                except Exception:
                    pass
        out.append({
            "notification_id": n.id,
            "title": n.title,
            "message": n.message,
            "icon": n.icon,
            "link": n.link,
            "created_at": n.created_at.isoformat() + "Z" if n.created_at else None,
            "badge_id": badge_id,
            "metadata": meta,
        })
    return {"unseen": out}


@app.post("/api/achievements/mark-seen")
async def api_achievements_mark_seen(request: Request, user: User = Depends(get_current_user),
                                      db: Session = Depends(get_db)):
    """Mark one or more achievement notifications as seen so they don't
    re-toast on next dashboard load. Body: {"notification_ids": [1, 2]}.
    """
    from fastapi.responses import JSONResponse
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    try:
        body = await request.json()
    except Exception:
        body = {}
    ids = body.get("notification_ids", []) if isinstance(body, dict) else []
    if not ids:
        return {"marked": 0}
    from .database import Notification as _Notification
    updated = db.query(_Notification).filter(
        _Notification.user_id == user.id,
        _Notification.id.in_(ids),
        _Notification.type == "achievement",
    ).update({_Notification.is_read: True}, synchronize_session=False)
    db.commit()
    return {"marked": int(updated or 0)}


@app.get("/api/achievements")
def api_achievements_data(request: Request, user: User = Depends(get_current_user),
                          db: Session = Depends(get_db)):
    """JSON achievements data."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    user_achievements = db.query(Achievement).filter(Achievement.user_id == user.id).all()
    earned_keys = {a.badge_id for a in user_achievements}
    earned = []
    available = []
    # Build a lookup of earned badges with their metadata so the API can
    # include per-instance data (e.g. grid_bonus_paid carries the bonus
    # amount earned). Added 26 May 2026.
    earned_meta = {a.badge_id: a for a in user_achievements}

    for key, badge in BADGES.items():
        # BADGES dict uses "desc" key (see app/database.py BADGES) — the
        # API previously called badge.get("description") which always
        # returned the default. Fixed 26 May 2026 alongside the new
        # grid_bonus_paid badge so every existing badge actually shows
        # its description on the achievements page.
        entry = {"key": key, "title": badge.get("title", key),
                 "description": badge.get("desc", ""),
                 "icon": badge.get("icon", "🏅")}
        if key in earned_keys:
            ach = earned_meta.get(key)
            if ach and ach.metadata_json:
                try:
                    import json as _json_ach
                    entry["metadata"] = _json_ach.loads(ach.metadata_json)
                except Exception:
                    pass
            if ach and ach.earned_at:
                entry["earned_at"] = ach.earned_at.isoformat()
            earned.append(entry)
        else:
            entry["progress"] = 0
            entry["target"] = badge.get("target", 1)
            available.append(entry)
    return {"earned": earned, "available": available}
@app.post("/api/support/ticket")
async def api_support_ticket(request: Request, user: User = Depends(get_current_user),
                             db: Session = Depends(get_db)):
    """Submit a support ticket.

    Two-channel notification:
      1. In-app notification on the admin's bell icon (existing)
      2. Email to SUPPORT_EMAIL (or DAILY_BRIEFING_EMAIL as fallback)
         so admin gets a real-time push regardless of whether they're
         logged in. Wired 11 May 2026 after launch revealed that in-app
         notifications alone meant overnight tickets sat unnoticed until
         the admin next signed in.
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    body = await request.json()
    subject = (body.get("subject") or "").strip()[:200]
    message = (body.get("message") or "").strip()[:5000]
    if not subject or not message:
        return JSONResponse({"error": "Subject and message required"}, status_code=400)
    # Notify admin in-app
    admin = db.query(User).filter(User.is_admin == True).first()
    if admin:
        notif = Notification(
            user_id=admin.id, type="support",
            icon="🎧", title=f"Support: {subject}",
            message=f"From {user.first_name or user.username}: {message[:200]}",
            link="/admin",
        )
        db.add(notif)
        db.commit()

    # ── Email the admin ──
    # Falls back to DAILY_BRIEFING_EMAIL if a dedicated SUPPORT_EMAIL
    # isn't configured, so this works out-of-the-box on Railway without
    # an extra env var (since DAILY_BRIEFING_EMAIL is already set).
    # Set SUPPORT_EMAIL separately later if you want tickets routed to
    # a different inbox (dedicated support address, VA, etc.).
    try:
        recipient = (
            os.environ.get("SUPPORT_EMAIL", "").strip()
            or os.environ.get("DAILY_BRIEFING_EMAIL", "").strip()
        )
        if recipient:
            from .brevo_service import send_email, wrap_email_html
            # Capture identifying info so we can reply or look the user up.
            user_label = (
                f"{user.first_name} {user.last_name}".strip()
                if (user.first_name or user.last_name)
                else user.username
            )
            sent_at = datetime.utcnow().strftime("%Y-%m-%d %H:%M UTC")
            # Escape user-supplied content so a malicious member can't
            # inject HTML into the admin's inbox. Brevo wraps the body in
            # standard email scaffolding, but the message itself is raw
            # user input — html.escape() is the right defence here.
            import html as _html
            safe_subject = _html.escape(subject)
            safe_message = _html.escape(message).replace("\n", "<br>")
            html_body = wrap_email_html(f"""
                <h2 style="font-family:Sora,sans-serif;color:#0f172a;margin:0 0 12px">
                    🎧 New support ticket
                </h2>
                <p style="color:#64748b;font-size:13px;margin:0 0 20px">
                    Submitted {sent_at}
                </p>
                <div style="background:#f8fafc;border-left:4px solid #2563eb;padding:14px 18px;border-radius:8px;margin-bottom:18px">
                    <div style="font-size:11px;font-weight:700;color:#64748b;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:4px">
                        From
                    </div>
                    <div style="font-size:15px;font-weight:700;color:#0f172a;margin-bottom:10px">
                        {_html.escape(user_label)} <span style="font-weight:500;color:#64748b">(@{_html.escape(user.username)})</span>
                    </div>
                    <div style="font-size:13px;color:#64748b">
                        {_html.escape(user.email or "no email on file")} · user_id {user.id}
                    </div>
                </div>
                <div style="background:#fff;border:1px solid #e2e8f0;border-radius:8px;padding:16px 18px;margin-bottom:18px">
                    <div style="font-size:11px;font-weight:700;color:#64748b;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:6px">
                        Subject
                    </div>
                    <div style="font-size:15px;font-weight:700;color:#0f172a;margin-bottom:14px">
                        {safe_subject}
                    </div>
                    <div style="font-size:11px;font-weight:700;color:#64748b;text-transform:uppercase;letter-spacing:0.5px;margin-bottom:6px">
                        Message
                    </div>
                    <div style="font-size:14px;color:#0f172a;line-height:1.55">
                        {safe_message}
                    </div>
                </div>
                <p style="color:#64748b;font-size:12px;margin:18px 0 0">
                    Reply directly to this email and the member will receive your response at {_html.escape(user.email or "(no email)")}.
                </p>
            """)
            await send_email(
                to_email=recipient,
                to_name="Steve",
                subject=f"[SuperAdPro Support] {subject}",
                html_content=html_body,
                # Reply-To so admin can hit Reply in their inbox and the
                # response goes back to the member directly.
                reply_to_email=user.email or None,
                reply_to_name=user_label if user_label else None,
            )
    except Exception as exc:
        # Email failure must not block ticket submission. The in-app
        # notification is already saved above, so the admin will still
        # see the ticket when they next sign in.
        logger.warning(f"[support] Email notification failed: {exc}")

    return {"ok": True}
@app.post("/api/watch/complete")
@limiter.limit("12/minute")
async def api_watch_complete(request: Request, user: User = Depends(get_current_user),
                             db: Session = Depends(get_db)):
    """Mark a video as watched, update quota, and return the next video via smart rotation."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    if get_user_highest_tier(db, user.id) < 0:
        return JSONResponse({"error": "tier_required", "redirect": "/campaign-tiers"}, status_code=403)
    try:
        from datetime import date
        body = await request.json()
        video_id = body.get("video_id")
        if not video_id:
            return JSONResponse({"error": "video_id required"}, status_code=400)

        campaign = db.query(VideoCampaign).filter(VideoCampaign.id == video_id).first()
        if not campaign:
            return JSONResponse({"error": "Video not found"}, status_code=404)

        # ── Anti-cheat: prevent self-watches (Apr 2026) ──
        # Without this, a campaign owner could call this endpoint with their
        # OWN video_id to inflate their view count and complete the campaign
        # without real audience. The rotation logic earlier excludes own
        # campaigns from being shown, but the API endpoint itself accepts
        # any video_id, so we need a server-side guard here too.
        if campaign.user_id == user.id and not user.is_admin:
            return JSONResponse({"error": "You can't watch your own campaign"}, status_code=403)

        today_str = str(date.today())

        # ── Server-side anti-cheat: assignment + 30-second timer check ──
        # The user must have been ASSIGNED this video by hitting /api/watch
        # first (which creates a VideoWatch row with started_at=now and
        # is_complete=False). If no started row exists, they're trying to
        # mark-complete a video they were never assigned (curl-the-API exploit).
        # If the started row is less than 30 seconds old, the timer hasn't
        # elapsed (script trying to bypass the watch duration). If the row
        # is already complete, this is a duplicate-day attempt.
        watch_row = db.query(VideoWatch).filter(
            VideoWatch.user_id == user.id,
            VideoWatch.campaign_id == video_id,
            VideoWatch.watch_date == today_str,
        ).first()

        if not watch_row:
            return JSONResponse(
                {"error": "Video not assigned to you. Get a video from the rotation first."},
                status_code=400
            )

        # Already-complete = duplicate-day attempt
        if watch_row.is_complete:
            return JSONResponse(
                {"error": "You've already watched this video today"},
                status_code=409
            )

        # 30-second timing check - admin bypasses for testing
        if not user.is_admin and watch_row.started_at:
            elapsed = (datetime.utcnow() - watch_row.started_at).total_seconds()
            if elapsed < WATCH_DURATION:
                remaining = int(WATCH_DURATION - elapsed)
                return JSONResponse(
                    {"error": f"Please watch for {remaining} more seconds to qualify"},
                    status_code=425  # 425 Too Early
                )

        # Use the proper quota system (handles day reset, tier sync, streak)
        quota = get_or_create_quota(db, user)

        # Check quota not already met
        if quota.today_watched >= quota.daily_required:
            return {"success": False, "error": "Daily quota already completed", "quota_met": True}

        # Mark the started row complete (don't create a new row - the
        # started row already exists from the assignment endpoint)
        watch_row.is_complete = True
        watch_row.watched_at = datetime.utcnow()
        watch_row.duration_secs = WATCH_DURATION

        # Update quota counter
        quota.today_watched += 1
        quota.total_watched = (quota.total_watched or 0) + 1
        if quota.today_watched >= quota.daily_required:
            quota.last_quota_met = today_str
            quota.consecutive_missed = 0
            quota.commissions_paused = False

        # Increment campaign views delivered
        campaign.views_delivered = (campaign.views_delivered or 0) + 1

        # ── FIX #4: Campaign completion check ──
        # When views_delivered reaches views_target, mark campaign as completed
        if campaign.views_target and campaign.views_delivered >= campaign.views_target and not campaign.is_completed:
            campaign.is_completed = True
            campaign.completed_at = datetime.utcnow()
            campaign.grace_expires_at = datetime.utcnow() + timedelta(days=14)
            campaign.status = "completed"
            logger.info(f"Campaign {campaign.id} completed: {campaign.views_delivered}/{campaign.views_target} views")

        db.commit()

        # Get next content using smart rotation
        quota_met = quota.today_watched >= quota.daily_required
        next_data = None
        if not quota_met:
            next_content = get_next_content(db, user.id)
            if next_content:
                if next_content["type"] == "video":
                    c = next_content["data"]
                    next_data = {"type": "video", "id": c.id, "title": c.title,
                                 "embed_url": c.embed_url, "platform": c.platform or "youtube",
                                 "category": c.category or "General"}
                elif next_content["type"] == "adboard":
                    a = next_content["data"]
                    next_data = {"type": "adboard", "id": a.id, "title": a.title,
                                 "description": a.description or "", "image_url": a.image_url or "",
                                 "link_url": a.link_url or "", "category": a.category or "Ad"}

        return {
            "success": True,
            "watched_today": quota.today_watched,
            "required": quota.daily_required,
            "quota_met": quota_met,
            "next_content": next_data,
            "next_campaign": next_data if next_data and next_data.get("type") == "video" else None,
            "has_more": next_data is not None,
        }
    except Exception as e:
        import traceback
        tb = traceback.format_exc()
        logger.error(f"Watch complete error: {e}\n{tb}")
        return JSONResponse({"error": str(e), "detail": tb}, status_code=500)
