@app.get("/api/team-pulse")
def api_team_pulse(user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """Dashboard Team Pulse card data — surfaces time-sensitive sponsor prompts.

    Returns a small, prioritised list of action items for the sponsor:
      - JUST_JOINED:   referrals registered in the last 24h (highest leverage —
                       activation window is open)
      - UNACTIVATED:   referrals 1-7d old who haven't activated yet (cooling
                       but still recoverable per the data: median time-to-
                       activation is <1h so older inactives are mostly lost)
      - JUST_ACTIVATED: referrals who activated in the last 24h (welcome +
                       show them what to do next)

    Capped at the top 5 most actionable items so the card stays focused and
    isn't a "12 things to do" overwhelm. Empty list = team is calm, render
    the empty state. Built 28 May 2026 to drive the 30% -> 40%+ activation
    lift identified in the activation-funnel diagnostic.

    Read-only, member-auth.
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    now = datetime.utcnow()
    team = db.query(User).filter(User.sponsor_id == user.id).all()

    # ── Adaptive dismissal (29 May 2026) ──
    # Once the sponsor has clicked Welcome / Say hi / Send nudge on a prompt,
    # the corresponding (target_user_id, prompt_kind) row exists in
    # team_pulse_actions. Exclude those from future loads so the card freshens
    # naturally as the sponsor works through it. Loaded once up-front as a
    # set to keep the inner loop O(1).
    from .database import TeamPulseAction as _TPA
    dismissed = {
        (row.target_user_id, row.prompt_kind)
        for row in db.query(_TPA).filter(_TPA.sponsor_user_id == user.id).all()
    }

    active_count = sum(1 for t in team if t.is_active)
    total = len(team)
    last_join = max((t.created_at for t in team if t.created_at), default=None)

    prompts = []
    for t in team:
        if not t.created_at:
            continue
        age_hours = (now - t.created_at).total_seconds() / 3600.0

        if t.is_active and t.activated_at:
            act_age_hours = (now - t.activated_at).total_seconds() / 3600.0
            if act_age_hours < 24:
                if (t.id, "just_activated") in dismissed:
                    continue
                prompts.append({
                    "kind": "just_activated",
                    "priority": 2,
                    "user_id": t.id,
                    "name": t.first_name or t.username,
                    "username": t.username,
                    "avatar": t.avatar_url,
                    "happened_at": t.activated_at.isoformat(),
                    "age_hours": round(act_age_hours, 1),
                    "tag": "JUST ACTIVATED",
                    "meta": f"Activated {_human_ago(act_age_hours)} — welcome them, show what to do next",
                    "action_label": "Welcome",
                    "welcome_template": _welcome_template(t.first_name or t.username, "just_activated"),
                })
            continue

        # Not active
        if age_hours < 24:
            if (t.id, "just_joined") in dismissed:
                continue
            prompts.append({
                "kind": "just_joined",
                "priority": 1,
                "user_id": t.id,
                "name": t.first_name or t.username,
                "username": t.username,
                "avatar": t.avatar_url,
                "happened_at": t.created_at.isoformat(),
                "age_hours": round(age_hours, 1),
                "tag": "JUST JOINED",
                "meta": f"Signed up {_human_ago(age_hours)} — still in the activation window",
                "action_label": "Say hi",
                "welcome_template": _welcome_template(t.first_name or t.username, "just_joined"),
            })
        elif age_hours < 24 * 7:
            if (t.id, "unactivated_warm") in dismissed:
                continue
            days = round(age_hours / 24, 1)
            prompts.append({
                "kind": "unactivated_warm",
                "priority": 3,
                "user_id": t.id,
                "name": t.first_name or t.username,
                "username": t.username,
                "avatar": t.avatar_url,
                "happened_at": t.created_at.isoformat(),
                "age_hours": round(age_hours, 1),
                "tag": f"UNACTIVATED · DAY {int(days)+1}",
                "meta": f"Joined {_human_ago(age_hours)}, hasn't activated yet — a quick nudge today can still bring them in",
                "action_label": "Send nudge",
                "welcome_template": _welcome_template(t.first_name or t.username, "unactivated_warm"),
            })
        # >7 days unactivated: don't surface (data says they're mostly lost)

    # Sort by priority (lower number = higher priority), then most recent
    prompts.sort(key=lambda p: (p["priority"], -p["age_hours"] if p["priority"] == 1 else p["age_hours"]))
    prompts = prompts[:5]  # cap for focus

    return JSONResponse({
        "prompts": prompts,
        "team": {
            "total": total,
            "active": active_count,
            "last_join_at": last_join.isoformat() if last_join else None,
            "last_join_age_hours": round((now - last_join).total_seconds() / 3600.0, 1) if last_join else None,
        },
    })


@app.post("/api/team-pulse/dismiss")
def api_team_pulse_dismiss(
    payload: dict = Body(...),
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Mark a Team Pulse prompt as actioned so it stops appearing on the card.

    Called from the dashboard when the sponsor clicks Welcome / Say hi /
    Send nudge. Records a (sponsor_user_id, target_user_id, prompt_kind)
    row in team_pulse_actions. Idempotent — re-clicking the same button
    is a no-op (ON CONFLICT DO NOTHING via the unique index).

    Body: {"target_user_id": int, "kind": "just_joined"|"just_activated"|"unactivated_warm"}

    The frontend fires this with fetch keepalive:true before navigating to
    TeamMessenger, so the write survives the page unload. When the sponsor
    returns to the dashboard, GET /api/team-pulse excludes this prompt.

    Built 29 May 2026 alongside the adaptive Team Pulse card. Member-auth.
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    try:
        target_user_id = int(payload.get("target_user_id") or 0)
    except (TypeError, ValueError):
        return JSONResponse({"error": "target_user_id must be an integer"}, status_code=400)

    kind = (payload.get("kind") or "").strip()
    VALID_KINDS = ("just_joined", "just_activated", "unactivated_warm")
    if not target_user_id or kind not in VALID_KINDS:
        return JSONResponse(
            {"error": f"target_user_id required, kind must be one of {VALID_KINDS}"},
            status_code=400,
        )

    # Sanity-guard: the target must actually be a downline of the sponsor.
    # Prevents someone calling this endpoint with arbitrary user_ids and
    # filling the action log with junk. The Team Pulse card itself only
    # surfaces direct referrals, so this is the same scope.
    target = db.query(User).filter(
        User.id == target_user_id, User.sponsor_id == user.id
    ).first()
    if not target:
        return JSONResponse(
            {"error": "Target user is not in your team"}, status_code=403
        )

    # Idempotent insert. The unique index (sponsor_user_id, target_user_id,
    # prompt_kind) means a duplicate raises IntegrityError — we catch and
    # treat as success. Cheaper than checking existence first.
    from .database import TeamPulseAction as _TPA
    from sqlalchemy.exc import IntegrityError

    try:
        action = _TPA(
            sponsor_user_id=user.id,
            target_user_id=target_user_id,
            prompt_kind=kind,
        )
        db.add(action)
        db.commit()
        return JSONResponse({"ok": True, "dismissed": True, "was_new": True})
    except IntegrityError:
        db.rollback()
        return JSONResponse({"ok": True, "dismissed": True, "was_new": False})


def _human_ago(hours: float) -> str:
    """Friendly relative time like '12 minutes ago' / '2 hours ago' / '3 days ago'."""
    if hours < 1:
        mins = max(1, int(hours * 60))
        return f"{mins} minute{'s' if mins != 1 else ''} ago"
    if hours < 24:
        h = int(round(hours))
        return f"{h} hour{'s' if h != 1 else ''} ago"
    days = int(hours / 24)
    return f"{days} day{'s' if days != 1 else ''} ago"


def _welcome_template(name: str, kind: str) -> str:
    """Tasteful pre-filled welcome messages — sponsor can edit before sending.
    Deliberately first-person, warm, low-pressure. Not auto-sent — the sponsor
    sees and approves every message. Templates are intentionally short so the
    sponsor adds the personal touch."""
    n = name.split()[0] if name else "there"
    if kind == "just_joined":
        return (f"Hey {n} — welcome to SuperAdPro! Saw you just signed up. "
                f"I'm here if you have any questions getting started. "
                f"What brought you in?")
    if kind == "unactivated_warm":
        return (f"Hey {n} — just checking in. You joined a couple of days ago "
                f"but haven't activated yet. Anything I can help with? "
                f"Happy to jump on a quick call if it's easier.")
    if kind == "just_activated":
        return (f"Welcome aboard {n}! Glad you've activated. "
                f"Quick tip — the first thing I'd do is check out the page builder "
                f"and set up your own SuperPage. Shout if you need a hand.")
    return f"Hey {n} — welcome to the team!"


@app.get("/api/team-messages")
def api_team_messages(request: Request, user: User = Depends(get_current_user),
                      db: Session = Depends(get_db)):
    """Get messages for the current user — sent and received."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    from .database import TeamMessage
    received = db.query(TeamMessage).filter(
        TeamMessage.to_user_id == user.id
    ).order_by(TeamMessage.created_at.desc()).limit(50).all()

    sent = db.query(TeamMessage).filter(
        TeamMessage.from_user_id == user.id
    ).order_by(TeamMessage.created_at.desc()).limit(50).all()

    def msg_to_dict(m, direction):
        other_id = m.from_user_id if direction == "received" else m.to_user_id
        other = db.query(User).filter(User.id == other_id).first()
        # Defensive: created_at can be NULL on older rows where the database
        # default didn't fire (manual inserts, very early platform data).
        # Without this guard, ONE bad row blows up the whole endpoint and
        # the contacts list never loads in the UI - members see "No team yet"
        # even when they have a full team. Found 27 Apr 2026.
        created_iso = m.created_at.isoformat() if m.created_at else ""
        return {
            "id": m.id, "direction": direction,
            "other_user": {"id": other.id, "name": other.first_name or other.username,
                           "username": other.username, "avatar": other.avatar_url} if other else None,
            "message": m.message, "is_read": m.is_read,
            "is_broadcast": bool(getattr(m, 'is_broadcast', False)),
            "created_at": created_iso,
        }

    messages = [msg_to_dict(m, "received") for m in received] + [msg_to_dict(m, "sent") for m in sent]
    # Sort key tolerates the empty-string fallback above (empty strings sort
    # to the bottom which is reasonable for messages with missing timestamps).
    messages.sort(key=lambda x: x["created_at"] or "", reverse=True)

    # Mark received as read
    for m in received:
        if not m.is_read:
            m.is_read = True
    db.commit()

    # Get team members (direct referrals) for the contact list — include all, not just active.
    # 28 May 2026: enriched with created_at, is_active, and last_message_at so the
    # dashboard Team Pulse card and TeamMessenger UI can identify time-sensitive
    # prompts (new joins in last 24h, unactivated members who need a nudge, etc).
    team = db.query(User).filter(User.sponsor_id == user.id).all()
    # Also include sponsor
    sponsor = db.query(User).filter(User.id == user.sponsor_id).first() if user.sponsor_id else None

    # Pre-fetch last-message timestamps per contact in a single query to avoid N+1.
    # Pair (least, greatest) used so a thread between A and B is symmetric regardless
    # of who sent the most recent message.
    contact_ids = [t.id for t in team] + ([sponsor.id] if sponsor else [])
    last_msg_by_contact = {}
    if contact_ids:
        # PostgreSQL LEAST/GREATEST canonicalises the user pair so each conversation
        # is a single row regardless of direction.
        last_msg_rows = db.execute(text("""
            SELECT
              CASE WHEN from_user_id = :me THEN to_user_id ELSE from_user_id END AS other_id,
              MAX(created_at) AS last_at
            FROM team_messages
            WHERE :me IN (from_user_id, to_user_id)
              AND CASE WHEN from_user_id = :me THEN to_user_id ELSE from_user_id END = ANY(:others)
            GROUP BY other_id
        """), {"me": user.id, "others": contact_ids}).fetchall()
        for r in last_msg_rows:
            last_msg_by_contact[r.other_id] = r.last_at

    contacts = []
    for t in team:
        contacts.append({
            "id": t.id, "name": t.first_name or t.username,
            "username": t.username, "avatar": t.avatar_url,
            "relationship": "referral", "tier": t.membership_tier or "free",
            "is_active": bool(t.is_active),
            "joined_at": t.created_at.isoformat() if t.created_at else None,
            "activated_at": t.activated_at.isoformat() if t.activated_at else None,
            "last_message_at": last_msg_by_contact[t.id].isoformat() if t.id in last_msg_by_contact and last_msg_by_contact[t.id] else None,
        })
    if sponsor:
        contacts.insert(0, {
            "id": sponsor.id, "name": sponsor.first_name or sponsor.username,
            "username": sponsor.username, "avatar": sponsor.avatar_url,
            "relationship": "sponsor", "tier": sponsor.membership_tier or "free",
            "is_active": bool(sponsor.is_active),
            "joined_at": sponsor.created_at.isoformat() if sponsor.created_at else None,
            "activated_at": sponsor.activated_at.isoformat() if sponsor.activated_at else None,
            "last_message_at": last_msg_by_contact[sponsor.id].isoformat() if sponsor.id in last_msg_by_contact and last_msg_by_contact[sponsor.id] else None,
        })

    # Unread count
    unread = db.query(TeamMessage).filter(
        TeamMessage.to_user_id == user.id, TeamMessage.is_read == False
    ).count()

    return {"messages": messages[:50], "contacts": contacts, "unread_count": unread}
@app.post("/api/team-messages/send")
async def api_send_team_message(request: Request, user: User = Depends(get_current_user),
                                 db: Session = Depends(get_db)):
    """Send a message to a team member (sponsor or direct referral)."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    from .database import TeamMessage
    body = await request.json()
    to_user_id = body.get("to_user_id")
    message_text = (body.get("message") or "").strip()[:2000]

    if not to_user_id or not message_text:
        return JSONResponse({"error": "Recipient and message required"}, status_code=400)

    # Verify relationship — can only message sponsor or direct referrals
    recipient = db.query(User).filter(User.id == to_user_id).first()
    if not recipient:
        return JSONResponse({"error": "User not found"}, status_code=404)

    is_sponsor = user.sponsor_id == to_user_id
    is_referral = recipient.sponsor_id == user.id
    is_admin = user.is_admin

    if not (is_sponsor or is_referral or is_admin):
        return JSONResponse({"error": "You can only message your sponsor or direct referrals"}, status_code=403)

    # Rate limit: max 20 messages per hour
    from datetime import timedelta
    hour_ago = datetime.utcnow() - timedelta(hours=1)
    recent_count = db.query(TeamMessage).filter(
        TeamMessage.from_user_id == user.id,
        TeamMessage.created_at >= hour_ago
    ).count()
    if recent_count >= 20 and not user.is_admin:
        return JSONResponse({"error": "Message limit reached (20/hour). Try again later."}, status_code=429)

    msg = TeamMessage(
        from_user_id=user.id,
        to_user_id=to_user_id,
        message=message_text,
        is_read=False,
    )
    db.add(msg)
    db.commit()

    # Send notification
    send_notification(db, to_user_id, "message", "💬",
        f"New message from {user.first_name or user.username}",
        message_text[:100])

    return {"success": True, "message_id": msg.id}


@app.post("/api/team-messages/broadcast")
async def api_broadcast_team_message(request: Request, user: User = Depends(get_current_user),
                                      db: Session = Depends(get_db)):
    """Broadcast the same message to ALL direct referrals (Apr 2026).

    Each recipient gets their own TeamMessage row marked is_broadcast=True so
    the UI can flag the message visually, but the row otherwise behaves like
    a normal 1-on-1 message: shows up in the recipients inbox thread, replies
    route back to the sender's thread as normal.

    Rate limited stricter than 1-on-1 sends (5 broadcasts/hour for non-admins)
    because a single broadcast already creates N messages and could be abused
    to flood the team. The leads broadcast endpoint at /api/leads/broadcast is
    a separate system (email autoresponder) — this is in-app messenger only.
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    from .database import TeamMessage
    body = await request.json()
    message_text = (body.get("message") or "").strip()[:2000]
    if not message_text:
        return JSONResponse({"error": "Message required"}, status_code=400)

    # Recipients = all direct referrals. Sponsor (upline) NOT included since a
    # broadcast is fundamentally a downline-team announcement, not a way to
    # spam your sponsor. If you want to message your sponsor, use the 1-on-1.
    recipients = db.query(User).filter(User.sponsor_id == user.id).all()
    if not recipients:
        return JSONResponse({"error": "You have no direct referrals to broadcast to"}, status_code=400)

    # Rate limit: 5 broadcasts/hour. Each broadcast can fan out to dozens of
    # recipients, so the cap is much tighter than the 20/hour single-send cap.
    from datetime import timedelta
    hour_ago = datetime.utcnow() - timedelta(hours=1)
    recent_broadcasts = db.query(TeamMessage).filter(
        TeamMessage.from_user_id == user.id,
        TeamMessage.is_broadcast == True,  # noqa: E712
        TeamMessage.created_at >= hour_ago
    ).count()
    if recent_broadcasts >= 5 and not user.is_admin:
        return JSONResponse({"error": "Broadcast limit reached (5/hour). Try again later."}, status_code=429)

    # Fan out — one row per recipient so each thread sees the broadcast naturally
    sent_count = 0
    for r in recipients:
        msg = TeamMessage(
            from_user_id=user.id,
            to_user_id=r.id,
            message=message_text,
            is_read=False,
            is_broadcast=True,
        )
        db.add(msg)
        sent_count += 1
    db.commit()

    # Notify all recipients
    for r in recipients:
        send_notification(db, r.id, "message", "📢",
            f"Broadcast from {user.first_name or user.username}",
            message_text[:100])

    return {"success": True, "sent_count": sent_count}


