@app.post("/api/voice-guide/ask")
async def voice_guide_ask(request: Request, user: User = Depends(get_current_user)):
    """Voice guide — answers questions about the platform using Gemini."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    body = await request.json()
    question = (body.get("question") or "").strip()
    if not question:
        return JSONResponse({"error": "No question provided"}, status_code=400)

    if len(question) > 500:
        question = question[:500]

    try:
        from .gemini_service import ai_generate
        answer = await ai_generate(
            prompt=question,
            max_tokens=300,
            system=VOICE_GUIDE_SYSTEM,
        )
        return {"success": True, "answer": answer.strip()}
    except Exception as e:
        logger.error(f"Voice guide failed: {e}")
        return JSONResponse({"error": "Could not generate answer. Please try again."}, status_code=500)
@app.post("/api/voice-guide/speak")
async def voice_guide_speak(request: Request, user: User = Depends(get_current_user)):
    """Convert text to natural speech using Edge TTS for the voice guide."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    import edge_tts
    import base64

    body = await request.json()
    text = (body.get("text") or "").strip()
    if not text:
        return JSONResponse({"error": "No text provided"}, status_code=400)

    # Strip markdown formatting so TTS doesn't read asterisks, hashes, etc.
    import re
    text = re.sub(r'\*\*(.+?)\*\*', r'\1', text)  # **bold** → bold
    text = re.sub(r'\*(.+?)\*', r'\1', text)       # *italic* → italic
    text = re.sub(r'#{1,6}\s*', '', text)           # ### heading → heading
    text = re.sub(r'`(.+?)`', r'\1', text)          # `code` → code
    text = re.sub(r'^\s*[-*+]\s+', '', text, flags=re.MULTILINE)  # bullet points
    text = re.sub(r'^\s*\d+\.\s+', '', text, flags=re.MULTILINE)  # numbered lists
    text = re.sub(r'\[(.+?)\]\(.+?\)', r'\1', text) # [link](url) → link
    text = text.strip()

    try:
        # Use Jenny — natural-sounding American female voice
        comm = edge_tts.Communicate(text, "en-GB-SoniaNeural", rate="+5%", pitch="+0Hz")
        audio_bytes = b""
        async for chunk in comm.stream():
            if chunk["type"] == "audio":
                audio_bytes += chunk["data"]

        if not audio_bytes:
            return JSONResponse({"error": "No audio generated"}, status_code=502)

        # Return as base64 for direct playback in browser
        b64 = base64.b64encode(audio_bytes).decode("utf-8")
        return {"success": True, "audio": b64}

    except Exception as e:
        logger.error(f"Voice guide TTS failed: {e}")
        return JSONResponse({"error": "Speech generation failed"}, status_code=500)
@app.get("/admin/recalculate-stats")
def admin_recalculate_stats(user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """Recalculate personal_referrals and total_team for all users."""
    _require_admin(user)

    users = db.query(User).all()
    updated = 0
    for u in users:
        actual_referrals = db.query(User).filter(User.sponsor_id == u.id, User.is_active == True).count()
        actual_team = db.query(User).filter(User.sponsor_id == u.id).count()
        if u.personal_referrals != actual_referrals or u.total_team != actual_team:
            u.personal_referrals = actual_referrals
            u.total_team = actual_team
            updated += 1

    db.commit()
    return {"success": True, "users_updated": updated}


@app.get("/admin/api/reassign-sponsor")
def admin_api_reassign_sponsor(
    user_id: int,
    new_sponsor_id: int,
    confirm: bool = False,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Admin tool: move a user under a different sponsor — correctly.

    A sponsor correction is NOT a one-field UPDATE. Two genealogy fields move
    together:
      - sponsor_id          → direct sponsor / display / future grid placement
      - pass_up_sponsor_id  → the SEPARATE permanent chain that course
                              commissions walk (course_engine.
                              find_qualified_passup_recipient). Leaving it on
                              the old sponsor's chain silently routes the user's
                              future course pass-up commissions to the wrong
                              upline.

    pass_up_sponsor_id is set to the NEW sponsor directly (kept-referral
    semantics). Rationale: the intent of a correction is "this user belongs to
    the new sponsor." Running the position-based assign_passup_sponsor logic
    could land them on a pass-up position and route their economics to the new
    sponsor's UPLINE instead — the opposite of the correction's intent. Safe to
    set directly because nothing has fired for a corrected user (no course
    pass-up commission has used the old chain).

    Counters (personal_referrals / total_team) are recomputed for BOTH the old
    and new sponsor using the canonical definitions from
    /admin/recalculate-stats (personal_referrals = active direct referrals;
    total_team = all direct referrals) — so the denormalised counters never
    drift on a move.

    Read-and-log, then write, then return before/after. Requires confirm=true;
    without it, returns a preview of what would change.
    Built 29 May 2026 (joyb521 registered under the wrong sponsor).
    """
    _require_admin(user)

    target = db.query(User).filter(User.id == user_id).first()
    if not target:
        return JSONResponse({"error": f"User {user_id} not found"}, status_code=404)
    new_sponsor = db.query(User).filter(User.id == new_sponsor_id).first()
    if not new_sponsor:
        return JSONResponse({"error": f"New sponsor {new_sponsor_id} not found"}, status_code=404)
    if user_id == new_sponsor_id:
        return JSONResponse({"error": "A user cannot be their own sponsor"}, status_code=400)

    # Cycle guard: the new sponsor must not sit inside the target's own
    # downline. Walk the new sponsor's sponsor_id chain upward; if we reach the
    # target, the move would create a loop.
    seen = set()
    cur = new_sponsor.sponsor_id
    while cur is not None and cur not in seen:
        if cur == user_id:
            return JSONResponse(
                {"error": f"Cycle blocked: user {new_sponsor_id} is in {user_id}'s downline"},
                status_code=400,
            )
        seen.add(cur)
        parent = db.query(User).filter(User.id == cur).first()
        cur = parent.sponsor_id if parent else None

    before = {
        "username": target.username,
        "sponsor_id": target.sponsor_id,
        "pass_up_sponsor_id": target.pass_up_sponsor_id,
    }

    if not confirm:
        return {
            "preview": True,
            "message": "Add &confirm=true to apply this move.",
            "target": before,
            "new_sponsor": {"id": new_sponsor.id, "username": new_sponsor.username},
            "would_set": {
                "sponsor_id": new_sponsor_id,
                "pass_up_sponsor_id": new_sponsor_id,
            },
        }

    old_sponsor_id = target.sponsor_id
    target.sponsor_id = new_sponsor_id
    target.pass_up_sponsor_id = new_sponsor_id
    db.flush()

    # Recompute denormalised counters for both affected sponsors using the
    # canonical definitions (matches /admin/recalculate-stats exactly).
    def _recompute(sid):
        if sid is None:
            return None
        s = db.query(User).filter(User.id == sid).first()
        if not s:
            return None
        s.personal_referrals = db.query(User).filter(
            User.sponsor_id == sid, User.is_active == True
        ).count()
        s.total_team = db.query(User).filter(User.sponsor_id == sid).count()
        return {
            "id": sid,
            "username": s.username,
            "personal_referrals": s.personal_referrals,
            "total_team": s.total_team,
        }

    old_counts = _recompute(old_sponsor_id)
    new_counts = _recompute(new_sponsor_id)
    db.commit()

    logger.info(
        f"[reassign-sponsor] user {user_id} ({target.username}) moved: "
        f"sponsor {old_sponsor_id}->{new_sponsor_id}, pass_up->{new_sponsor_id}, "
        f"by admin {user.username}"
    )

    return {
        "success": True,
        "user": {"id": target.id, "username": target.username},
        "before": before,
        "after": {
            "sponsor_id": target.sponsor_id,
            "pass_up_sponsor_id": target.pass_up_sponsor_id,
        },
        "counters_recomputed": {"old_sponsor": old_counts, "new_sponsor": new_counts},
    }


@app.post("/admin/diagnostic/cleanup-test-withdrawals/{user_id}")
def admin_diagnostic_cleanup_test_withdrawals(
    user_id: int,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """One-shot pre-launch cleanup: mark old test withdrawals on the
    SuperAdPro owner account as 'cancelled' so they drop out of the lifetime
    total_withdrawn. The on-chain Polygon transactions are real and went to
    Steve's own wallet — we're not erasing money, just relabelling our
    internal accounting so the wallet display stops including pre-launch
    test data.

    HARDCODED to user_id=1 only — explicitly refuses for any other user.
    This is NOT a general-purpose 'cancel a withdrawal' tool; that would be
    dangerous (could hide real customer withdrawals). Idempotent — re-running
    leaves already-cancelled rows alone."""
    _require_admin(user)

    # Hardcoded safety: this endpoint is ONLY for the SuperAdPro account.
    if user_id != 1:
        return JSONResponse({
            "error": "This endpoint only operates on user_id=1 (SuperAdPro). "
                     "It is a one-shot pre-launch cleanup, not a general-purpose tool."
        }, status_code=403)

    target = db.query(User).filter(User.id == user_id).first()
    if not target:
        return JSONResponse({"error": "user not found"}, status_code=404)

    # Find all paid withdrawals on this account
    withdrawals = db.query(Withdrawal).filter(
        Withdrawal.user_id == user_id,
        Withdrawal.status == "paid",
    ).all()

    rows_before = [
        {
            "id": w.id,
            "amount_usdt": float(w.amount_usdt or 0),
            "tx_hash": (w.tx_hash or "")[:80],
            "requested_at": w.requested_at.isoformat() if w.requested_at else None,
        }
        for w in withdrawals
    ]

    # Mark them cancelled
    cancelled_count = 0
    cancelled_total = 0.0
    for w in withdrawals:
        w.status = "cancelled"
        cancelled_count += 1
        cancelled_total += float(w.amount_usdt or 0)

    # Also reset the legacy total_withdrawn column on the user row for cleanliness
    target.total_withdrawn = 0

    # Invalidate the compute_total_withdrawn cache so the dashboard refreshes immediately
    try:
        cache_delete(f"withdrawn:{user_id}")
    except Exception:
        pass

    db.commit()

    logger.warning(
        f"CLEANUP_TEST_WITHDRAWALS user={user_id} ({target.username}) "
        f"cancelled={cancelled_count} total_usd={cancelled_total}"
    )

    return {
        "status": "completed",
        "user_id": user_id,
        "username": target.username,
        "withdrawals_cancelled": cancelled_count,
        "total_usd_cancelled": round(cancelled_total, 2),
        "rows_affected": rows_before,
        "note": "On-chain transactions remain real. Internal accounting now treats them as cancelled.",
    }


@app.get("/admin/diagnostic/inspect-ledgers/{user_id}")
def admin_diagnostic_inspect_ledgers(
    user_id: int,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Read-only ledger inspector. Dumps Withdrawal + Commission rows for a
    user so we can see exactly what the ledgers contain. No mutations. Used
    to diagnose when computed totals look wrong — e.g. 'earned X but withdrew
    more than X'."""
    _require_admin(user)

    target = db.query(User).filter(User.id == user_id).first()
    if not target:
        return JSONResponse({"error": "user not found"}, status_code=404)

    withdrawals = db.query(Withdrawal).filter(Withdrawal.user_id == user_id).order_by(Withdrawal.id).all()
    commissions = db.query(Commission).filter(Commission.to_user_id == user_id).order_by(Commission.id).all()

    return {
        "user_id": user_id,
        "username": target.username,
        "stored_columns": {
            "balance": float(target.balance or 0),
            "campaign_balance": float(target.campaign_balance or 0),
            "total_earned": float(target.total_earned or 0),
            "total_withdrawn": float(target.total_withdrawn or 0),
        },
        "withdrawals": [
            {
                "id": w.id,
                "amount_usdt": float(w.amount_usdt or 0),
                "status": w.status,
                "tx_hash": (w.tx_hash or "")[:80],
                "created_at": w.requested_at.isoformat() if w.requested_at else None,
                "processed_at": w.processed_at.isoformat() if w.processed_at else None,
                "wallet_address": (w.wallet_address or "")[:50],
            }
            for w in withdrawals
        ],
        "withdrawal_summary_by_status": {
            status: {
                "count": sum(1 for w in withdrawals if w.status == status),
                "total": round(sum(float(w.amount_usdt or 0) for w in withdrawals if w.status == status), 2),
            }
            for status in sorted({w.status for w in withdrawals})
        },
        "commissions_count": len(commissions),
        "commissions_by_type": {
            t: {
                "count": sum(1 for c in commissions if (c.commission_type or "") == t),
                "total": round(sum(float(c.amount_usdt or 0) for c in commissions if (c.commission_type or "") == t and c.status != "reversed"), 2),
                "reversed_count": sum(1 for c in commissions if (c.commission_type or "") == t and c.status == "reversed"),
            }
            for t in sorted({c.commission_type or "" for c in commissions})
        },
    }


@app.post("/admin/diagnostic/recompute-all-total-withdrawn")
def admin_diagnostic_recompute_total_withdrawn(user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """One-time defensive cleanup of the legacy user.total_withdrawn column.
    Sums Withdrawal.amount_usdt where status IN ('paid', 'completed') and
    overwrites the column. Dashboard reads have already been migrated to
    compute_total_withdrawn(), so this is purely defensive — making the
    column itself match the ledger in case any code path still reads it
    directly.

    Returns a per-user diff for users whose stored value differed from the
    computed truth, so we can see exactly how much drift had accumulated."""
    _require_admin(user)

    users = db.query(User).all()
    drifts = []
    updated = 0

    for u in users:
        actual = db.query(func.coalesce(func.sum(Withdrawal.amount_usdt), 0)).filter(
            Withdrawal.user_id == u.id,
            Withdrawal.status.in_(["paid", "completed"]),
        ).scalar() or 0
        actual = float(actual)
        stored = float(u.total_withdrawn or 0)

        # Only update if there's a real drift (use small epsilon for float compare)
        if abs(stored - actual) > 0.001:
            drifts.append({
                "user_id": u.id,
                "username": u.username,
                "stored": round(stored, 2),
                "actual": round(actual, 2),
                "drift": round(stored - actual, 2),
            })
            u.total_withdrawn = actual
            updated += 1

    db.commit()

    # Sort largest drift first so the worst offenders are visible
    drifts.sort(key=lambda d: abs(d["drift"]), reverse=True)

    return {
        "status": "completed",
        "users_scanned": len(users),
        "users_updated": updated,
        "drifts": drifts[:50],  # cap response size — top 50 offenders
        "total_drift_count": len(drifts),
    }


