@app.post("/api/superdeck/create")
async def api_superdeck_create(request: Request, user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)
    body = await request.json()
    title = (body.get("title") or "Untitled Presentation").strip()[:300]
    theme = (body.get("theme") or "midnight").strip()[:50]

    import json as _j
    # Default to white canvas with dark text
    bg = '#ffffff'
    tc = '#0f172a'
    default_slides = [{"id": "s1", "elements": [
        {"id": "h1", "type": "heading", "x": 200, "y": 180, "w": 600, "h": 80, "text": "Your Presentation Title", "fontSize": 42, "color": tc, "bold": True, "align": "center", "fontFamily": "Sora, sans-serif"},
        {"id": "t1", "type": "text", "x": 250, "y": 280, "w": 500, "h": 50, "text": "Click any element to edit. Add text, images, and shapes from the toolbar.", "fontSize": 18, "color": "#64748b", "align": "center", "fontFamily": "DM Sans, sans-serif"},
    ], "background": bg, "notes": ""}]

    try:
        deck = Presentation(
            user_id=user.id, title=title, theme=theme,
            slides_json=_j.dumps(default_slides), slide_count=1,
        )
        db.add(deck)
        db.commit()
        db.refresh(deck)
        return {"success": True, "id": deck.id}
    except Exception as e:
        db.rollback()
        logger.error(f"SuperDeck create failed: {e}")
        return JSONResponse({"error": f"Failed to create: {str(e)[:200]}"}, status_code=500)
