@app.post("/api/credit-matrix/purchase")
async def api_credit_matrix_purchase(request: Request, user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    """
    Purchase a credit pack with wallet balance.
    Awards credits + places buyer in sponsor's 3x3 matrix + pays commissions.
    """
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    body = await request.json()
    pack_key = body.get("pack_key", "").strip().lower()
    payment_method = body.get("payment_method", "wallet")  # wallet / crypto

    pack = CREDIT_PACKS.get(pack_key)
    if not pack:
        return JSONResponse({"error": f"Invalid pack: {pack_key}"}, status_code=400)

    # Purchase consent gate — see app/purchase_consent.py
    ok, err = require_fresh_consent(db, user.id, purpose=f"credit_matrix:{pack_key}")
    if not ok:
        return JSONResponse({"error": err}, status_code=403)

    price = pack["price"]

    if payment_method == "wallet":
        from decimal import Decimal
        balance = Decimal(str(user.balance or 0))
        pack_price = Decimal(str(price))
        if balance < pack_price:
            return JSONResponse({"error": f"Insufficient balance. Need ${price}, have ${float(balance):.2f}"}, status_code=400)

        # Deduct from wallet + spend in a single atomic block.
        # If purchase_credit_pack raises for any reason, we MUST rollback
        # the wallet deduction — otherwise member loses balance with
        # nothing to show for it (real money lost, no credits awarded).
        try:
            user.balance = balance - pack_price
            db.flush()
            result = purchase_credit_pack(
                db, user, pack_key,
                payment_ref=f"wallet_{user.id}_{pack_key}",
                payment_method="wallet",
            )
            if not result.get("success"):
                # Engine returned a soft failure — also rollback the deduction.
                db.rollback()
                logger.error(
                    f"Wallet credit-pack purchase soft-failed for user {user.id} "
                    f"(pack={pack_key}, price=${pack_price}): {result.get('error')}"
                )
                return JSONResponse(
                    {"error": result.get("error", "Purchase failed")},
                    status_code=400,
                )
            # Cache invalidation — buyer's balance decreased.
            # purchase_credit_pack itself invalidates the matrix earner(s)
            # via pay_matrix_commissions, so this covers the missing piece.
            try:
                cache_invalidate_user(user.id)
            except Exception as e:
                logger.warning(f"cache_invalidate_user({user.id}) failed in wallet credit-pack: {e}")
            return result
        except Exception as exc:
            db.rollback()
            logger.error(
                f"Wallet credit-pack purchase EXCEPTION for user {user.id} "
                f"(pack={pack_key}, price=${pack_price}): {exc}",
                exc_info=True,
            )
            return JSONResponse(
                {"error": "Purchase failed due to a system error. Your balance has not been charged. Please try again."},
                status_code=500,
            )

    elif payment_method == "crypto":
        # Create a NOWPayments invoice via the existing endpoint logic
        from . import nowpayments_service as nps
        from .database import NowPaymentsOrder
        import json as _json

        if not nps.is_configured():
            return JSONResponse({"error": "Crypto payments not configured"}, status_code=503)

        product_key_np = f"credit_matrix_{pack_key}"

        # Cancel existing pending orders for same product
        db.query(NowPaymentsOrder).filter(
            NowPaymentsOrder.user_id == user.id,
            NowPaymentsOrder.product_key == product_key_np,
            NowPaymentsOrder.status == "pending",
        ).update({"status": "cancelled"})
        db.flush()

        # Create local order record
        order = NowPaymentsOrder(
            user_id=user.id,
            product_type="credit_matrix",
            product_key=product_key_np,
            product_meta=_json.dumps({"pack_key": pack_key, "credits": pack["credits"]}),
            price_usd=price,
            status="pending",
        )
        db.add(order)
        db.flush()

        internal_order_id = f"SAP-{user.id}-{order.id}"
        order.internal_order_id = internal_order_id

        # Create NOWPayments invoice
        result = nps.create_invoice(
            product_key=product_key_np,
            user_id=user.id,
            order_id=order.id,
        )

        if not result["success"]:
            order.status = "failed"
            db.commit()
            return JSONResponse({"error": result.get("error", "Payment creation failed")}, status_code=500)

        order.np_invoice_id = result.get("np_id")
        db.commit()

        return {
            "success": True,
            "action": "crypto_checkout",
            "invoice_url": result.get("invoice_url"),
            "order_id": order.id,
            "pack_key": pack_key,
            "price": price,
            "credits": pack["credits"],
        }
    else:
        return JSONResponse({"error": "Invalid payment method"}, status_code=400)
