@app.post("/api/lead-finder/search")
async def api_lead_finder_search(request: Request,
                                  user: User = Depends(get_current_user),
                                  db: Session = Depends(get_db)):
    """Search for business leads by niche and location (maps mode) or keywords (web mode)."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    # Pro-only check
    tier = (user.membership_tier or "").lower()
    if tier not in ("pro", "admin") and not user.is_admin:
        return JSONResponse({"error": "Lead Finder is a Pro feature. Upgrade to access."}, status_code=403)

    data = await request.json()
    niche = (data.get("niche") or "").strip()
    location = (data.get("location") or "").strip()
    mode = (data.get("mode") or "maps").strip().lower()
    if mode not in ("maps", "web"):
        mode = "maps"

    if not niche:
        return JSONResponse({"error": "Please enter a search term."}, status_code=400)

    # For maps mode, location is required. For web mode, it's optional
    if mode == "maps" and not location:
        return JSONResponse({"error": "Please enter both a niche and location."}, status_code=400)

    if len(niche) > 200 or len(location) > 100:
        return JSONResponse({"error": "Search terms too long."}, status_code=400)

    from .lead_finder import _check_rate_limit, _increment_rate_limit, _get_cached, _set_cache, search_businesses, get_locale_for_country

    # Rate limit check
    allowed, remaining = _check_rate_limit(user.id)
    if not allowed:
        return JSONResponse({"error": "Daily search limit reached (10/day). Try again tomorrow.", "remaining": 0}, status_code=429)

    # Build query string for display
    query_display = f"{niche} in {location}" if (mode == "maps" and location) else niche

    # Check cache first
    cached = _get_cached(mode, niche, location)
    if cached is not None:
        return {"success": True, "results": cached, "count": len(cached),
                "cached": True, "remaining": remaining, "query": query_display, "mode": mode}

    # Run the scraper with user's locale
    _increment_rate_limit(user.id)
    remaining -= 1

    locale, lang = get_locale_for_country(user.country or "")

    try:
        results = await search_businesses(niche, location, locale=locale, lang=lang, mode=mode)
        _set_cache(mode, niche, location, results)
        return {"success": True, "results": results, "count": len(results),
                "cached": False, "remaining": remaining, "query": query_display, "mode": mode}
    except ValueError as e:
        # Known errors (API key, credits, 503s) — pass through message to user
        err_msg = str(e)
        logger.error(f"Lead Finder error: {err_msg}")
        return JSONResponse({"error": err_msg}, status_code=500)
    except Exception as e:
        logger.error(f"Lead Finder unexpected error: {type(e).__name__}: {e}")
        return JSONResponse({"error": f"Search failed: {type(e).__name__}. Please try again in a moment."}, status_code=500)
@app.post("/api/lead-finder/import")
async def api_lead_finder_import(request: Request,
                                  user: User = Depends(get_current_user),
                                  db: Session = Depends(get_db)):
    """Import scraped leads into the user's AutoResponder lead list."""
    if not user:
        return JSONResponse({"error": "Not authenticated"}, status_code=401)

    # Pro-only (AutoResponder is Pro feature)
    tier = (user.membership_tier or "").lower()
    if tier not in ("pro", "admin") and not user.is_admin:
        return JSONResponse({"error": "AutoResponder is a Pro feature. Upgrade to import leads."}, status_code=403)

    data = await request.json()
    leads = data.get("leads", [])
    list_name = data.get("list_name", "Imported Leads")

    if not leads:
        return JSONResponse({"error": "No leads to import."}, status_code=400)

    if len(leads) > 50:
        return JSONResponse({"error": "Maximum 50 leads per import."}, status_code=400)

    # Import the required models
    from .database import MemberLead, LeadList

    # Check lead limit
    current_count = db.query(MemberLead).filter(MemberLead.user_id == user.id).count()
    limit = _lead_limit(user)
    remaining = max(0, limit - current_count)

    if remaining == 0:
        return JSONResponse({
            "error": f"Lead limit reached ({limit}). Delete existing leads or upgrade your plan.",
            "limit": limit, "current": current_count
        }, status_code=400)

    # Create a new lead list
    lead_list = LeadList(
        user_id=user.id,
        name=list_name[:100],
        description=f"Imported from Lead Finder on {datetime.utcnow().strftime('%d %b %Y')}",
        color="#8b5cf6",  # purple to match Lead Finder branding
    )
    db.add(lead_list)
    db.flush()

    imported = 0
    skipped = 0
    for lead in leads[:remaining]:  # Respect lead limit
        email = (lead.get("email") or "").strip().lower()
        if not email or "@" not in email:
            skipped += 1
            continue

        # Check for duplicates
        existing = db.query(MemberLead).filter(
            MemberLead.user_id == user.id,
            MemberLead.email == email
        ).first()
        if existing:
            skipped += 1
            continue

        # Build name from business name (could be enhanced)
        lead_name = (lead.get("name") or "").strip()[:200]

        new_lead = MemberLead(
            user_id=user.id,
            email=email,
            name=lead_name,
            list_id=lead_list.id,
            source_url=f"Lead Finder: {lead.get('website', '') or lead.get('category', '') or 'imported'}"[:250],
            status="new",
        )
        db.add(new_lead)
        imported += 1

    # Update the lead_count on the list
    lead_list.lead_count = imported

    db.commit()

    # Sync to Brevo in background (non-blocking)
    if imported > 0:
        try:
            from .brevo_service import create_brevo_contact
            new_leads = db.query(MemberLead).filter(
                MemberLead.user_id == user.id,
                MemberLead.list_id == lead_list.id,
                MemberLead.brevo_contact_id == None,
            ).limit(imported).all()
            for nl in new_leads:
                try:
                    contact_id = await create_brevo_contact(nl.email, nl.name or "")
                    if contact_id:
                        nl.brevo_contact_id = str(contact_id)
                except Exception:
                    pass
            db.commit()
        except Exception as e:
            logger.warning(f"Brevo sync skipped: {e}")

    return {
        "success": True,
        "imported": imported,
        "skipped": skipped + (len(leads) - min(len(leads), remaining)),
        "list_id": lead_list.id,
        "list_name": lead_list.name,
    }


# ══════════════════════════════════════════════════════════════════════
# Admin Email Broadcast (added 11 May 2026)
# ══════════════════════════════════════════════════════════════════════
# Lets the platform owner send broadcast emails to all members directly
# from the admin panel — no Brevo dashboard, no list sync, no contacts to
# manage. The list is always live: emails are pulled from the users table
# at send time.
#
# Endpoints:
#   GET    /admin/api/members-emails              List members with email + filter
#   POST   /admin/api/broadcast/send              Send a broadcast (sync, batched)
#   GET    /admin/api/broadcast/history           List past broadcasts
#   GET    /admin/api/broadcast/{id}              Fetch single broadcast detail
#   GET    /unsubscribe?token=...                 One-click opt-out landing page
# ──────────────────────────────────────────────────────────────────────

import secrets as _secrets_broadcast

BROADCAST_BATCH_SIZE = 50          # send N then sleep
BROADCAST_BATCH_SLEEP = 1.0        # seconds between batches (SMTP-friendly)
BROADCAST_MAX_SUBJECT_LEN = 300
BROADCAST_MAX_BODY_BYTES = 200_000  # 200KB cap on body HTML


def _ensure_unsubscribe_token(db, user) -> str:
    """Lazily mint an opaque unsubscribe token for a user. Idempotent."""
    if user.email_unsubscribe_token:
        return user.email_unsubscribe_token
    user.email_unsubscribe_token = _secrets_broadcast.token_urlsafe(32)
    db.flush()
    return user.email_unsubscribe_token


def _build_broadcast_footer(unsubscribe_url: str) -> str:
    """Standard compliance footer appended to every broadcast email."""
    return (
        f'<div style="margin-top:32px;padding-top:20px;border-top:1px solid #e5e7eb;'
        f'font-size:12px;color:#94a3b8;text-align:center;line-height:1.6;font-family:Helvetica Neue,Arial,sans-serif;">'
        f'You\'re receiving this because you\'re a SuperAdPro member.<br>'
        f'<a href="{unsubscribe_url}" style="color:#94a3b8;text-decoration:underline;">Unsubscribe from broadcast emails</a> '
        f'(you\'ll still receive transactional emails like password resets and commission notifications).<br>'
        f'<span style="color:#cbd5e1;">SuperAdPro — AI Marketing & Advertising Platform</span>'
        f'</div>'
    )


# ─────────────────────────────────────────────────────────────────────
# Broadcast body normalisation (added 27 May 2026)
# ─────────────────────────────────────────────────────────────────────
# The /admin/api/broadcast/send endpoint takes a body_html field. The
# field accepts HTML, but admins routinely paste plain text with
# paragraph breaks. HTML collapses whitespace, so newlines disappear and
# the email renders as a wall of text — exactly what Steve hit on
# 27 May.
#
# Fix: detect whether input is already-HTML (contains block tags) or
# plain text. If plain, convert:
#   - Double newlines  → paragraph break (</p><p>)
#   - Single newlines  → soft break (<br>)
#   - Bare URLs        → clickable <a> links
#
# Wrap the whole thing in a single <div> with sensible typography so
# the email is readable on every client without needing the admin to
# remember to style anything.

import re as _re_broadcast

# Block-level HTML tags whose presence signals "this is already HTML".
# If ANY of these appear in the body, we leave it alone and trust the
# admin knows what they're doing.
_HTML_BLOCK_RE = _re_broadcast.compile(
    r'<\s*(p|div|br|h[1-6]|ul|ol|li|table|tr|td|blockquote|pre|hr|img|section|article)\b',
    _re_broadcast.IGNORECASE,
)
_URL_RE = _re_broadcast.compile(
    r'(?<!["\'>])(https?://[^\s<>"\']+)',
)


def _normalise_broadcast_body(body: str) -> str:
    """Convert plain-text body to safe HTML, or pass through if already
    HTML. Safe to call on any input — won't double-encode existing HTML.

    Returns a string that's always renderable HTML wrapped in a
    typographic <div>. Caller can append the footer and ship it.
    """
    if not body or not body.strip():
        return ""

    # Detect already-HTML. If the admin wrote <p>, <br>, <div>, etc.,
    # we trust them and only wrap with the typography div.
    is_html = bool(_HTML_BLOCK_RE.search(body))

    if is_html:
        inner = body
    else:
        # Plain-text path. Convert in order:
        #   1. Escape any stray HTML special chars (< > &) so we don't
        #      accidentally render markup the admin didn't intend.
        #      We then re-introduce our own controlled tags below.
        escaped = (body
                   .replace("&", "&amp;")
                   .replace("<", "&lt;")
                   .replace(">", "&gt;"))

        #   2. Linkify bare URLs. Done BEFORE paragraph processing so
        #      the URL regex doesn't have to deal with our injected tags.
        escaped = _URL_RE.sub(
            r'<a href="\1" style="color:#0ea5e9;text-decoration:underline;">\1</a>',
            escaped,
        )

        #   3. Split on blank lines into paragraphs. Each paragraph
        #      gets its own <p>. Within a paragraph, single newlines
        #      become <br> (preserves intentional line breaks like
        #      addresses or signatures).
        paragraphs = [p.strip() for p in _re_broadcast.split(r'\n\s*\n', escaped) if p.strip()]
        rendered_paragraphs = []
        for p in paragraphs:
            with_breaks = p.replace('\n', '<br>')
            rendered_paragraphs.append(
                f'<p style="margin:0 0 16px 0;line-height:1.6;">{with_breaks}</p>'
            )
        inner = ''.join(rendered_paragraphs)

    # Wrap with a single container that sets readable defaults. Email
    # clients honour inline styles much more reliably than <style> blocks,
    # so we keep everything inline.
    return (
        f'<div style="font-family:Helvetica Neue,Arial,sans-serif;'
        f'font-size:15px;color:#1f2937;line-height:1.6;'
        f'max-width:600px;margin:0 auto;padding:24px;background:#ffffff;">'
        f'{inner}'
        f'</div>'
    )


def _resolve_broadcast_recipients(db, audience_filter: dict):
    """Resolve the recipient list from an audience filter dict.
    
    Always excludes: admin users, opted-out users, users without an email.
    Filter keys:
        status   -- 'all' | 'active' | 'inactive'    (default 'all')
        country  -- 2-letter ISO code or None
        tier_min -- minimum campaign tier (1-8) or None
    Returns a list of User rows.
    """
    q = db.query(User).filter(
        User.email != None,                # noqa: E711
        User.email != "",
        User.email_opt_out == False,       # noqa: E712
        User.is_admin == False,            # noqa: E712  -- never email admins by accident
    )
    status = (audience_filter or {}).get("status", "all")
    if status == "active":
        q = q.filter(User.is_active == True)   # noqa: E712
    elif status == "inactive":
        q = q.filter(User.is_active == False)  # noqa: E712
    country = (audience_filter or {}).get("country")
    if country:
        q = q.filter(User.country == country)
    return q.order_by(User.id.asc()).all()


@app.get("/admin/api/members-emails")
def admin_api_members_emails(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    q: str = "",
    status: str = "all",
    country: str = "",
):
    """List members (with emails) for the broadcast composer.
    
    Returns counts + a sample of the resolved audience for preview.
    Excludes admin users, opted-out users, and accounts without an email.
    """
    _require_admin(user)
    audience = {"status": status}
    if country:
        audience["country"] = country
    recipients = _resolve_broadcast_recipients(db, audience)
    # Free-text search filters the preview list only — does not change the
    # recipient_count of an actual send, which always re-resolves the filter
    if q:
        ql = q.lower()
        filtered = [r for r in recipients if
                    ql in (r.email or "").lower()
                    or ql in (r.username or "").lower()
                    or ql in (r.first_name or "").lower()]
    else:
        filtered = recipients
    return {
        "recipient_count": len(recipients),
        "preview_count": len(filtered),
        "preview_limit": 5000,
        "preview_truncated": len(filtered) > 5000,
        "members": [
            {
                "id": m.id,
                "email": m.email,
                "username": m.username,
                "first_name": m.first_name or "",
                "country": m.country or "",
                "is_active": bool(m.is_active),
                "created_at": m.created_at.isoformat() if m.created_at else None,
            }
            for m in filtered[:5000]   # 5K rows — beyond this, add pagination
        ],
    }


# Advisory-lock id for the admin broadcast sender. Distinct from the BSC
# scanner (…291) and security watchdog (…292) locks so a running broadcast
# can't collide with those daemons. Held by the worker's own DB connection
# for the lifetime of one send; auto-released if the connection dies, so a
# crashed worker never leaves a stuck lock.
BROADCAST_LOCK_ID = 1885347293
BROADCAST_INFLIGHT_STALE_MIN = 30   # a 'sending' row older than this is treated as crashed, not in-flight


def _run_admin_broadcast(broadcast_id: int, recipient_ids, base_url: str):
    """Background worker: send one admin broadcast off the request thread.

    Runs in a daemon thread with its OWN DB session (the request session is
    long gone by the time this executes). A Postgres advisory lock guarantees
    only one broadcast send runs at a time platform-wide, so a duplicate
    trigger (double-click, retry after the instant 200) can't spawn a second
    concurrent loop and double-mail recipients. Progress is persisted to the
    AdminBroadcast row every batch, so /admin/api/broadcast/{id} reflects live
    sent/failed counts while this runs.
    """
    import time as _t
    from .database import SessionLocal, User as _User
    from .email_utils import send_email as _send
    db = SessionLocal()
    locked = False
    try:
        locked = bool(db.execute(
            text("SELECT pg_try_advisory_lock(:k)"), {"k": BROADCAST_LOCK_ID}
        ).scalar())
        b = db.query(AdminBroadcast).filter(AdminBroadcast.id == broadcast_id).first()
        if not b:
            logger.error(f"broadcast worker: row {broadcast_id} vanished before send")
            return
        if not locked:
            # Another broadcast is mid-flight. Fail closed rather than run a
            # second concurrent loop against the same audience.
            b.status = "failed"
            b.error_message = "Another broadcast was already sending; this one was not started to avoid double-mailing."
            b.completed_at = datetime.utcnow()
            db.commit()
            logger.warning(f"broadcast {broadcast_id}: lock held — refused concurrent send")
            return

        recipients = db.query(_User).filter(_User.id.in_(recipient_ids)).all() if recipient_ids else []
        sent = 0
        failed = 0
        try:
            for i, recipient in enumerate(recipients):
                try:
                    token = _ensure_unsubscribe_token(db, recipient)
                    unsub_url = f"{base_url}/unsubscribe?token={token}"
                    first = recipient.first_name or recipient.username or "there"
                    personalised_html = b.body_html.replace("{{first_name}}", first).replace("{{username}}", recipient.username or "")
                    personalised_text = (b.body_text or "").replace("{{first_name}}", first).replace("{{username}}", recipient.username or "")
                    full_html = personalised_html + _build_broadcast_footer(unsub_url)
                    ok = _send(
                        to_email=recipient.email,
                        subject=b.subject,
                        html_body=full_html,
                        text_body=personalised_text,
                    )
                    if ok:
                        sent += 1
                    else:
                        failed += 1
                except Exception as exc:
                    failed += 1
                    logger.warning(f"Broadcast {broadcast_id} send to {recipient.email} failed: {exc}")

                if (i + 1) % BROADCAST_BATCH_SIZE == 0:
                    b.sent_count = sent
                    b.failed_count = failed
                    db.commit()
                    _t.sleep(BROADCAST_BATCH_SLEEP)

            b.sent_count = sent
            b.failed_count = failed
            b.status = "completed"
            b.completed_at = datetime.utcnow()
            db.commit()
            logger.warning(f"ADMIN_BROADCAST: {broadcast_id} completed sent={sent} failed={failed}")
        except Exception as exc:
            b.status = "failed"
            b.error_message = str(exc)[:1000]
            b.sent_count = sent
            b.failed_count = failed
            b.completed_at = datetime.utcnow()
            db.commit()
            logger.error(f"Broadcast {broadcast_id} crashed mid-send: {exc}")
    except Exception:
        logger.exception(f"broadcast worker {broadcast_id}: fatal")
        try:
            db.rollback()
        except Exception:
            pass
    finally:
        if locked:
            try:
                db.execute(text("SELECT pg_advisory_unlock(:k)"), {"k": BROADCAST_LOCK_ID})
                db.commit()
            except Exception:
                pass
        db.close()


@app.post("/admin/api/broadcast/send")
async def admin_api_broadcast_send(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Send a broadcast email to filtered members.
    
    Body:
        subject         (required, <=300 chars)
        body_html       (required, <=200KB)
        body_text       (optional)
        audience        (optional, default {"status":"all"})
        test_only       (optional bool) — if true, only sends to the admin themselves
    
    Sends in batches with a small sleep between to be SMTP-friendly.
    Returns the AdminBroadcast row id and final counts.
    """
    _require_admin(user)
    body = await request.json()
    subject = (body.get("subject") or "").strip()[:BROADCAST_MAX_SUBJECT_LEN]
    body_html = body.get("body_html") or ""
    body_text = body.get("body_text") or ""
    audience = body.get("audience") or {"status": "all"}
    test_only = bool(body.get("test_only", False))

    if not subject:
        return JSONResponse({"error": "Subject is required"}, status_code=400)
    if not body_html:
        return JSONResponse({"error": "Body is required"}, status_code=400)
    if len(body_html.encode("utf-8")) > BROADCAST_MAX_BODY_BYTES:
        return JSONResponse({"error": "Body too large (max 200KB)"}, status_code=413)

    # Normalise body: if admin pasted plain text, convert to HTML with
    # proper paragraph breaks. If admin wrote HTML, pass through unchanged.
    # See _normalise_broadcast_body for the detection rule (looks for
    # block-level tags). Done ONCE up front before personalisation so the
    # per-recipient loop just does {{first_name}} substitution on the
    # already-rendered HTML.
    body_html = _normalise_broadcast_body(body_html)

    # Resolve audience now (fast User query) so we can return an accurate
    # recipient count instantly. The slow part — per-recipient Brevo sends —
    # runs off-thread in _run_admin_broadcast.
    if test_only:
        # Test send goes only to the admin (so they can preview deliverability)
        recipients = [user]
    else:
        recipients = _resolve_broadcast_recipients(db, audience)
    recipient_ids = [r.id for r in recipients]

    import json as _j_brc
    from datetime import timedelta as _td_brc

    # Concurrency guard: refuse to start a second broadcast while one is in
    # flight, so a double-click or a retry after the instant 200 can't spawn a
    # parallel send. Only a 'sending' row that STARTED within the staleness
    # window counts as in-flight — an older one is a crashed send and must not
    # block new broadcasts forever (the advisory lock is the hard race guard).
    cutoff = datetime.utcnow() - _td_brc(minutes=BROADCAST_INFLIGHT_STALE_MIN)
    inflight = db.query(AdminBroadcast).filter(
        AdminBroadcast.status == "sending",
        AdminBroadcast.started_at != None,  # noqa: E711
        AdminBroadcast.started_at >= cutoff,
    ).first()
    if inflight:
        return JSONResponse({
            "error": "A broadcast is already sending. Wait for it to finish before starting another.",
            "in_progress_broadcast_id": inflight.id,
            "poll_url": f"/admin/api/broadcast/{inflight.id}",
        }, status_code=409)

    # Create the tracking row up-front (status='sending') so it shows in
    # history immediately and the worker can update sent/failed as it goes.
    broadcast = AdminBroadcast(
        subject=subject,
        body_html=body_html,
        body_text=body_text,
        audience_filter=_j_brc.dumps(audience),
        recipient_count=len(recipients),
        sent_count=0,
        failed_count=0,
        status="sending",
        sent_by_user_id=user.id,
        started_at=datetime.utcnow(),
    )
    db.add(broadcast)
    db.commit()
    db.refresh(broadcast)

    # Hand the send to a background daemon thread and return instantly. This
    # is the fix for the Cloudflare ~100s edge timeout: large lists used to
    # block the request past the limit and surface a false 502 while the send
    # kept running server-side, tempting a resend that double-mailed everyone.
    base_url = (request.url.scheme + "://" + request.url.netloc).rstrip("/")
    import threading as _thr_brc
    _thr_brc.Thread(
        target=_run_admin_broadcast,
        args=(broadcast.id, recipient_ids, base_url),
        daemon=True,
        name=f"admin-broadcast-{broadcast.id}",
    ).start()

    return {
        "broadcast_id": broadcast.id,
        "status": "sending",
        "recipient_count": len(recipients),
        "test_only": test_only,
        "poll_url": f"/admin/api/broadcast/{broadcast.id}",
        "note": ("Sending started in the background — this response returns "
                 "immediately. Poll poll_url for live sent/failed counts. "
                 "Do NOT resend; a second send is blocked until this finishes."),
    }


@app.get("/admin/api/broadcast/history")
def admin_api_broadcast_history(
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
    limit: int = 50,
):
    """Return recent broadcasts, newest first."""
    _require_admin(user)
    rows = (
        db.query(AdminBroadcast)
          .order_by(AdminBroadcast.created_at.desc())
          .limit(max(1, min(limit, 200)))
          .all()
    )
    return {
        "broadcasts": [
            {
                "id": b.id,
                "subject": b.subject,
                "recipient_count": b.recipient_count,
                "sent_count": b.sent_count,
                "failed_count": b.failed_count,
                "status": b.status,
                "created_at": b.created_at.isoformat() if b.created_at else None,
                "completed_at": b.completed_at.isoformat() if b.completed_at else None,
                "sent_by_user_id": b.sent_by_user_id,
            }
            for b in rows
        ],
    }


@app.get("/admin/api/broadcast/{broadcast_id}")
def admin_api_broadcast_detail(
    broadcast_id: int,
    request: Request,
    user: User = Depends(get_current_user),
    db: Session = Depends(get_db),
):
    """Return the full content of one broadcast (for the History detail view)."""
    _require_admin(user)
    b = db.query(AdminBroadcast).filter(AdminBroadcast.id == broadcast_id).first()
    if not b:
        return JSONResponse({"error": "Broadcast not found"}, status_code=404)
    return {
        "id": b.id,
        "subject": b.subject,
        "body_html": b.body_html,
        "body_text": b.body_text,
        "audience_filter": b.audience_filter,
        "recipient_count": b.recipient_count,
        "sent_count": b.sent_count,
        "failed_count": b.failed_count,
        "status": b.status,
        "error_message": b.error_message,
        "created_at": b.created_at.isoformat() if b.created_at else None,
        "started_at": b.started_at.isoformat() if b.started_at else None,
        "completed_at": b.completed_at.isoformat() if b.completed_at else None,
    }


@app.get("/unsubscribe")
def unsubscribe_landing(request: Request, token: str = "", db: Session = Depends(get_db)):
    """One-click unsubscribe link from broadcast emails.
    
    Public route — no auth required, just a valid token. Idempotent: clicking
    twice keeps the user opted-out. Transactional emails ignore this flag.
    """
    if not token:
        return HTMLResponse(_unsub_page("Missing unsubscribe token", error=True), status_code=400)
    member = db.query(User).filter(User.email_unsubscribe_token == token).first()
    if not member:
        return HTMLResponse(_unsub_page("Invalid or expired unsubscribe link", error=True), status_code=404)
    if not member.email_opt_out:
        member.email_opt_out = True
        db.commit()
    return HTMLResponse(_unsub_page(
        f"You've been unsubscribed from SuperAdPro broadcast emails. "
        f"You'll still receive transactional emails (password resets, commission notifications). "
        f"Changed your mind? Log in and re-enable broadcasts in your account settings.",
        error=False
    ))


def _unsub_page(message: str, error: bool = False) -> str:
    """Plain styled landing page for the unsubscribe action."""
    color = "#dc2626" if error else "#16a34a"
    icon = "✗" if error else "✓"
    title = "Unsubscribe error" if error else "Unsubscribed"
    return f"""<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>{title} — SuperAdPro</title>
<meta name="viewport" content="width=device-width,initial-scale=1">
<style>
  body{{margin:0;background:#f8fafc;font-family:Helvetica Neue,Arial,sans-serif;color:#1e293b;min-height:100vh;display:flex;align-items:center;justify-content:center;padding:24px;}}
  .card{{max-width:460px;width:100%;background:#fff;border-radius:16px;padding:40px 32px;box-shadow:0 4px 24px rgba(0,0,0,0.06);text-align:center;}}
  .icon{{width:64px;height:64px;border-radius:50%;background:{color};color:#fff;font-size:32px;font-weight:700;display:flex;align-items:center;justify-content:center;margin:0 auto 20px;}}
  h1{{font-size:22px;font-weight:700;margin:0 0 12px;color:#0f172a;}}
  p{{font-size:15px;line-height:1.6;color:#475569;margin:0 0 24px;}}
  a.btn{{display:inline-block;padding:10px 22px;background:#0ea5e9;color:#fff;border-radius:8px;font-weight:600;text-decoration:none;font-size:14px;}}
</style>
</head>
<body>
<div class="card">
<div class="icon">{icon}</div>
<h1>{title}</h1>
<p>{message}</p>
<a href="/" class="btn">Back to SuperAdPro</a>
</div>
</body>
</html>"""


